      SUBROUTINE DPCIR2(X1,Y1,X2,Y2,   &
                        IFIG,   &
                        ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                        AREGBA,   &
                        IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
!     PURPOSE--DRAW A CIRCLE WITH ONE END OF THE DIAGONAL AT (X1,Y1)
!              AND THE OTHER END AT (X2,Y2).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1989. MODIFY CALLS TO DPDRPL (ALAN)
!     UPDATED         --JANUARY   1989. MODIFY CALL  TO DPFIRE (ALAN)
!     UPDATED         --FEBRAUARY 1993. USE EQUIVALENCE
!     UPDATED         --SEPTEMBER 2014. SET CIRCLE CORRECTION <ON/OFF>
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES-------------------------------------
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT2
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IPATT
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION PX(1000)
      DIMENSION PY(1000)
!CCCC DIMENSION PX3(1000)
!CCCC DIMENSION PY3(1000)
!CCCC FOLLOWING LINES ADDED FEBRUARY 1994
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(1),PX(1))
      EQUIVALENCE (GARBAG(1001),PY(1))
!CCCC END CHANGE
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLNZ,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRGZ,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRGZ,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRGZ,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CIR2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCIR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2
   53   FORMAT('X1,Y1,X2,Y2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4,IFIG
   59   FORMAT('IBUGG4,ISUBG4,IERRG4,IFIG = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',A4,2X,A4,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)PREBTH(1),AREGBA(1)
   62   FORMAT('PREBTH(1),AREGBA(1) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),IREBC2(1,1),IREBC2(1,2),   &
                       IREBC2(1,3)
   63   FORMAT('IREBLI(1),IREBCO(1),IREBC2(1,1),IREBC2(1,2),',   &
               'IREBC2(1,3) = ',2(A4,2X),3I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  DETERMINE THE COORDINATES  **
!               **  FOR THE CIRCLE             **
!               *********************************
!
      RATIHV=ANUMHP/ANUMVP
      IF(ICIRCR.EQ.'OFF')THEN
        RATIHV=1.0
      ENDIF
!
      DELX=X2-X1
      DELY=Y2-Y1
      DELX=ABS(DELX)
      DELY=ABS(DELY)
!
      ALEN=0.0
      TERM=DELX**2+DELY**2
      IF(TERM.GT.0.0)ALEN=SQRT(TERM)
      RADIUS=ALEN/2.0
!
      IF(ABS(DELX).GE.0.00001)THETA=ATAN(DELY/DELX)
      IF(ABS(DELX).LT.0.00001.AND.DELY.GE.0.0)THETA=3.1415926/2.0
      IF(ABS(DELX).LT.0.00001.AND.DELY.LT.0.0)THETA=-3.1415926/2.0
      THETA=0.0
!
      XCENT=(X1+X2)/2.0
      YCENT=(Y1+Y2)/2.0
      X3=XCENT-RADIUS
      Y3=YCENT
!
      K=0
!
      X=0.0
      Y=0.0
      Y=Y*RATIHV
      CALL TRANS(X,Y,X3,Y3,THETA,DELX,DELY,XP,YP,KXP,KYP)
      K=K+1
      PX(K)=XP
      PY(K)=YP
!
      DO 3010 I=181,541,5
        IREV=541-I+181
        PHI2=IREV-1
        PHI2=PHI2*(2.0*3.1415926)/360.0
        X=RADIUS*COS(PHI2)+RADIUS
        Y=RADIUS*SIN(PHI2)
        Y=Y*RATIHV
        CALL TRANS(X,Y,X3,Y3,THETA,DELX,DELY,XP,YP,KXP,KYP)
        K=K+1
        PX(K)=XP
        PY(K)=YP
 3010 CONTINUE
!
      NP=K
!
!               ***********************
!               **  STEP 2--         **
!               **  FILL THE FIGURE  **
!               **  (IF CALLED FOR)  **
!               ***********************
!
      IF(IREFSW(1).EQ.'ON')THEN
        IPATT=IREPTY(1)
        IPATT2='SOLI'
        PTHICK=PREPTH(1)
        PXGAP=PREPSP(1)
        PYGAP=PREPSP(1)
        ICOLF=IREFCO(1)
        ICOLFR=IREFC2(1,1)
        ICOLFG=IREFC2(1,2)
        ICOLFB=IREFC2(1,3)
        ICOLP=IREPCO(1)
        ICOLPR=IREPC2(1,1)
        ICOLPG=IREPC2(1,2)
        ICOLPB=IREPC2(1,3)
        CALL DPFIRE(PX,PY,NP,   &
                    IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                    ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                    ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                    IPATT2)
      ENDIF
!
!               ***************************
!               **  STEP 3--             **
!               **  DRAW OUT THE FIGURE  **
!               ***************************
!
      IPATT=ILINPA(1)
      PTHICK=PLINTH(1)
      ICOL=ILINCO(1)
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CIR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCIR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)DELX,DELY,NP
 9012   FORMAT('DELX,DELY,NP = ',2G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)XCENT,YCENT,RADIUS,THETA
 9013   FORMAT('XCENT,YCENT,RADIUS,THETA = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NP
          WRITE(ICOUT,9016)I,PX(I),PY(I)
 9016     FORMAT('I,PX(I),PY(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCIR2
      SUBROUTINE DPCIRC(IHARG,IARGT,ARG,NUMARG,   &
                        PXSTAR,PYSTAR,PXEND,PYEND,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                        IBACCO,IBACC2,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DRAW ONE OR MORE CIRCLES (DEPENDING ON HOW MANY NUMBERS ARE
!              PROVIDED).  THE COORDINATES ARE IN STANDARDIZED UNITS
!              OF 0 TO 100.
!     NOTE--THE INPUT COORDINATES DEFINE THE ENDS OF THE DIAMETER
!           OF THE CIRCLE.
!     NOTE-THE USUAL INPUT NUMBER OF COORDINATES IS 2
!          AND THEREFORE THE USUAL INPUT NUMBER OF NUMBERS IS 2*2 = 4.
!     NOTE--IF 2 NUMBERS ARE PROVIDED, THEN THE DRAWN CIRCLE WILL GO
!           FROM THE LAST CURSOR POSITION TO THE (X,Y) POINT (EITHER ABSOLUTE
!           OR RELATIVE) AS DEFINED BY THE 2 NUMBERS.
!     NOTE--IF 4 NUMBERS ARE PROVIDED, THEN THE DRAWN CIRCLE WILL GO
!           FROM THE ABSOLUTE (X,Y) POSITION AS DEFINED BY THE FIRST 2 NUMBERS
!           TO THE (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS DEFINED BY
!           THE THIRD AND FOURTH NUMBERS.
!     NOTE--IF 6 NUMBERS ARE PROVIDED, THEN THE DRAWN CIRCLE WILL GO
!           FROM THE (X,Y) POSITION AS RESULTING FROM THE THIRD AND FOURTH
!           NUMBERS TO THE (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE)
!           AS DEFINED BY THE FIFTH AND SIXTH NUMBERS.
!     NOTE--AND SO FORTH FOR 8, 10, 12, ... NUMBERS.
!     INPUT  ARGUMENTS--IHARG
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PXSTAR
!                     --PYSTAR
!     OUTPUT ARGUMENTS--PXEND
!                     --PYEND
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  1982.
!     UPDATED         --JANUARY   1989. CALL LIST FOR OFFSET VAR (ALAN)
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!     UPDATED         --JULY      1997. SUPPORT FOR "DATA" UNITS (ALAN)
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2020. SUPPORT FOR RGB COLORS
!
!-----NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
!CCCC ADD FOLLOWING LINE MARCH 1997.
      CHARACTER*4 IDFONT
!CCCC ADD FOLLOWING LINE JULY 1997.
      CHARACTER*4 UNITSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IFIG
      CHARACTER*4 IBELSW
      CHARACTER*4 IERASW
      CHARACTER*4 IBACCO
      CHARACTER*4 ICOPSW
      CHARACTER*4 ITYPEO
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
      DIMENSION PDSCAL(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
!CCCC ADD FOLLOWING LINE MARCH 1997.
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
!
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION IBACC2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IERRG4=IERROR
!
      ILOCFN=0
      NUMNUM=0
!
      X1=0.0
      Y1=0.0
      X2=0.0
      Y2=0.0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CIRC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCIRC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMARG,NUMDEV
   53   FORMAT('NUMARG,NUMDEV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56     FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,57)PXSTAR,PYSTAR,PXEND,PYEND
   57   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1)
   63   FORMAT('IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1) = ',   &
               2(A4,2X),2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,76)IGRASW,IDIASW
   76   FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77   FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78   FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NUMDEV
          WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82     FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
                 3(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83     FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',2(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84     FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,88)IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR
   88   FORMAT('IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFIG='CIRC'
      NUMPT=2
      NUMPT2=2*NUMPT
!
!               ********************************
!               **  STEP 0--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
      DO 8000 IDEVIC=1,NUMDEV
!
      IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NULL')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NONE')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'DISC')GO TO 8000
!
      IMANUF=IDMANU(IDEVIC)
      IMODEL=IDMODE(IDEVIC)
      IMODE2=IDMOD2(IDEVIC)
      IMODE3=IDMOD3(IDEVIC)
      IGCONT=IDCONT(IDEVIC)
      IGCOLO=IDCOLO(IDEVIC)
      IGFONT=IDFONT(IDEVIC)
      NUMVPP=IDNVPP(IDEVIC)
      NUMHPP=IDNHPP(IDEVIC)
      ANUMVP=NUMVPP
      ANUMHP=NUMHPP
      IOFFSV=IDNVOF(IDEVIC)
      IOFFSH=IDNHOF(IDEVIC)
      IGUNIT=IDUNIT(IDEVIC)
      PCHSCA=PDSCAL(IDEVIC)
!
!               ************************************
!               **  STEP 1--                      **
!               **  CARRY OUT OPENING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      CALL DPOPDE
!
      IBELSW='OFF'
      NUMRIN=0
      IERASW='OFF'
!
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  SEARCH FOR COMMAND SPECIFICATIONS  **
!               *****************************************
!
      IF(NUMARG.GE.2.AND.   &
      IARGT(1).EQ.'NUMB'.AND.IARGT(2).EQ.'NUMB')   &
      GO TO 1111
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ABSO'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1112
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'RELA'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1113
      GO TO 1130
!
 1111 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=1
      GO TO 1119
!
 1112 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=2
      GO TO 1119
!
 1113 CONTINUE
      ITYPEO='RELA'
      ILOCFN=2
      GO TO 1119
 1119 CONTINUE
!
      IF(ILOCFN.GT.NUMARG)GO TO 1129
      DO 1120 I=ILOCFN,NUMARG
      IF(IARGT(I).EQ.'NUMB')GO TO 1120
      GO TO 1129
 1120 CONTINUE
      IFOUND='YES'
      GO TO 1149
 1129 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,1131)
 1131 FORMAT('***** ERROR IN DPCIRC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      ILLEGAL FORM FOR CIRCLE ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      SUPPOSE IT IS DESIRED TO DRAW A CIRCLE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('      WITH ONE END OF A DIAGONAL AT 20 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1137)
 1137 FORMAT('      AND THE OTHER END OF THE DIAGONAL AT 40 60,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('      THEN ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      CIRCLE 20 20 40 60')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      CIRCLE ABSOLUTE 20 20 40 60')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1149 CONTINUE
!
!               ****************************
!               **  STEP 3--              **
!               **  DRAW OUT THE LINE(S)  **
!               ****************************
!
      NUMNUM=NUMARG-ILOCFN+1
      IF(NUMNUM.LT.NUMPT2)GO TO 1151
      GO TO 1152
!
 1151 CONTINUE
      J=ILOCFN-1
      X1=PXSTAR
      Y1=PYSTAR
      GO TO 1159
!
 1152 CONTINUE
      J=ILOCFN
      IF(J.GT.NUMARG)GO TO 1190
      X1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X1,X1,IBUGD2,ISUBRO,IERROR)
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y1,Y1,IBUGD2,ISUBRO,IERROR)
      GO TO 1159
!
 1159 CONTINUE
!
 1160 CONTINUE
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      X2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X2,X2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')X2=X1+X2
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y2,Y2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')Y2=Y1+Y2
!
      CALL DPCIR2(X1,Y1,X2,Y2,   &
                  IFIG,   &
                  ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                  AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
      X1=X2
      Y1=Y2
!
      GO TO 1160
 1190 CONTINUE
!
      PXEND=X2
      PYEND=Y2
!
!               ************************************
!               **  STEP 4--                      **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      ICOPSW='OFF'
      NUMCOP=0
      CALL DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
      CALL DPCLDE
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CIRC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCIRC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IFOUND,IFIG,ILOCFN,NUMNUM
 9012   FORMAT('IERROR,IFOUND,IFIG,ILOCFN,NUMNUM = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)X1,Y1,X2,Y2
 9013   FORMAT('X1,Y1,X2,Y2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)PXSTAR,PYSTAR,PXEND,PYEND
 9015   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCIRC
      SUBROUTINE DPCKEL(ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CHECK IF THE ARGUMENTS SPECIFIED ON THE COMMAND ARE
!              ALL VARIABLES OF EQUAL LENGTH.
!     EXAMPLE--LET IFLAG = CHECK EQUAL LENGTH S1 S2 S3
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015/03
!     ORIGINAL VERSION--MARCH     2015.
!     UPDATED         --FEBRUARY  2018. CHECK LENGTH OUTPUT
!                                             <FILLIBEN/DEFAULT>
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 NEWNAM
      CHARACTER*4 NEWCOL
      CHARACTER*4 ICASEL
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
!
      CHARACTER*4 IFOUND
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*8 ISTR
      CHARACTER*1 IQUOTE
!
      CHARACTER*4 ICASTO
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
      PARAMETER(MAXIND=100)
      CHARACTER*4 IVARN1(MAXIND)
      CHARACTER*4 IVARN2(MAXIND)
!
!---------------------------------------------------------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
      CHARACTER (LEN=MAXFNC) :: IMANAM(10)
      COMMON/IMAC/IMACNU,IMALEV,IMANAM
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCK'
      ISUBN2='EL  '
      IERROR='NO'
      ICASTO='OFF'
      IQUOTE="'"
      ILOC3=0
      ICOLL=0
      ILISTL=0
      NIOLD=0
      NSIZE=0
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CKEL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCKEL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NUMNAM,NUMCHF,MAXCHF
   52   FORMAT('IBUGA3,ISUBRO,NUMNAM,NUMCHF,MAXCHF = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMNAM
          WRITE(ICOUT,56)I,IHNAME(I),IHNAM2(I),IUSE(I),IVSTAR(I),   &
                         IVSTOP(I)
   56     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IVSTAR(I),',   &
                 'IVSTOP(I)=',I8,2X,A4,A4,2X,A4,I8,I8)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************************
!               **  STEP 1--                    **
!               **  INITIALIZE SOME VARIABLES.  **
!               **********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CKEL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NEWNAM='NO'
      NEWCOL='NO'
      ICASEL='UNKN'
!
!               ******************************************************
!               **  STEP 2--                                         *
!               **  EXAMINE THE LEFT-HAND SIDE--                     *
!               **  IF THIS IS A PREVIOUSLY DEFINED NAME, IT SHOULD  *
!               **  BE A PARAMETER (IF NOT, REPORT AN ERROR).        *
!               ******************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CKEL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHLEFT=IHARG(1)
      IHLEF2=IHARG2(1)
!
      DO 1910 I=1,4
        IF(IHLEFT(I:I).EQ.'(')THEN
          IHLEFT(I:4)=' '
          IHLEF2=' '
          ICASEL='ELEM'
          GO TO 1999
        ENDIF
 1910 CONTINUE
      DO 1920 I=1,4
        IF(IHLEF2(I:I).EQ.'(')THEN
          IHLEF2(I:4)=' '
          ICASEL='ELEM'
          GO TO 1999
        ENDIF
 1920 CONTINUE
 1999 CONTINUE
!
      DO 2000 I=1,NUMNAM
        I2=I
        IF(IHLEFT.EQ.IHNAME(I).AND.IHLEF2.EQ.IHNAM2(I))THEN
          IF(IUSE(I2).EQ.'P')THEN
            ICASEL='PARA'
            ILISTL=I2
            GO TO 2900
          ELSEIF(IUSE(I2).EQ.'V')THEN
            ICASEL='ELEM'
            ILISTL=I2
            ICOLL=IVALUE(ILISTL)
            NIOLD=IN(ILISTL)
            GO TO 2900
          ELSE
            WRITE(ICOUT,999)
  999       FORMAT(1X)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2001)
 2001       FORMAT('***** ERROR IN CHECK EQUAL NAME--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2003)IHLEFT,IHLEF2
 2003       FORMAT('      THE NAME ON THE LEFT HAND SIDE (',   &
                   A4,A4,')')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2005)
 2005       FORMAT('      ALREADY EXISTS, BUT NOT AS A PARAMETER.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
 2000 CONTINUE
!
      NEWNAM='YES'
      IF(ICASEL.EQ.'UNKN')ICASEL='PARA'
!
      ILISTL=NUMNAM+1
      IF(ILISTL.GT.MAXNAM)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2202)
 2202   FORMAT('      THE NUMBER OF VARIABLE, PARAMETER, AND ',   &
               'FUNCTION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2203)MAXNAM
 2203   FORMAT('      NAMES HAS JUST EXCEEDED THE ALLOWABLE ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2204)
 2204   FORMAT('      ENTER      STATUS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2205)
 2205   FORMAT('      TO FIND OUT THE FULL LIST OF USED NAMES, AND')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2206)
 2206   FORMAT('      THEN REDEFINE OR DELETE SOME OF THE ALREADY ',   &
               'USED NAMES.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 2900 CONTINUE
!
!               *****************************************************
!               **  STEP 3--                                       **
!               **  EXTRACT THE NAMES ON THE RIGHT HAND SIDE       **
!               *****************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CKEL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFRST=6
      IF(NUMARG.LT.IFRST)THEN
        IFLAG=-1
        GO TO 3900
      ENDIF
      IFLAG=1
!
      JMIN=IFRST
      JMAX=NUMARG
      CALL EXTVA3(IHARG,IHARG2,NUMARG,JMIN,JMAX,MAXIND,   &
                  IHNAME,IHNAM2,NUMNAM,   &
                  IVARN1,IVARN2,NUMIND,   &
                  IBUGA3,ISUBRO,IERROR)
      IERROR='NO'
!
      DO 3010 II=1,NUMIND
        IHRIGH=IVARN1(II)
        IHRIG2=IVARN2(II)
!
        DO 3020 I=1,NUMNAM
          I4=I
          IF(IHRIGH.EQ.IHNAME(I).AND.IHRIG2.EQ.IHNAM2(I))THEN
            IF(IUSE(I4).NE.'V')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2001)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3003)IHRIGH,IHRIG2
 3003         FORMAT('      THE NAME ON THE RIGHT HAND SIDE (',   &
                     A4,A4,')')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,3005)
 3005         FORMAT('      ALREADY EXISTS, BUT NOT AS A VARIABLE.')
              CALL DPWRST('XXX','BUG ')
              IFLAG=0
            ELSE
              IF(II.EQ.1)THEN
                NSIZE=IN(I4)
              ELSE
                NTEMP=IN(I4)
                IF(NTEMP.NE.NSIZE)THEN
                  IFLAG=0
                  WRITE(ICOUT,999)
                  CALL DPWRST('XXX','BUG ')
                  WRITE(ICOUT,2001)
                  CALL DPWRST('XXX','BUG ')
                  IF(ICHKLE.EQ.'DEFA')THEN
                    WRITE(ICOUT,3013)IVARN1(II),IVARN2(II),   &
                                     IVARN1(1),IVARN2(1)
 3013               FORMAT('      VARIABLE ',2A4,' IS NOT OF THE ',   &
                           'SAME LENGTH AS ',2A4)
                    CALL DPWRST('XXX','BUG ')
                  ELSE
!
!                   CHECK FOR "HTMLSW" PARAMETER
!                   CHECK FOR "IBATCH" PARAMETER
!
!                   IF THIS IS SET TO 1, JIM HAS SOME SPECIAL CODE
!                   FOR PYTHON BASED INTERFACE.  SO HERE, JUST SET
!                   IFLAG TO -1.
!
                    IHP='HTML'
                    IHP2='SW  '
                    IHWUSE='P'
                    MESSAG='NO'
                    CALL CHECKN(IHP,IHP2,IHWUSE,   &
                                IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                                NUMNAM,MAXNAM,   &
                                ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,   &
                                ILOCP,IERROR)
                    IHTML=0
                    IF(IERROR.EQ.'NO')IHTML=INT(VALUE(ILOCP)+0.5)
                    IF(IHTML.NE.1)IHTML=0
!
                    IHP='IBAT'
                    IHP2='CH  '
                    IHWUSE='P'
                    MESSAG='NO'
                    CALL CHECKN(IHP,IHP2,IHWUSE,   &
                                IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                                NUMNAM,MAXNAM,   &
                                ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,   &
                                ILOCP,IERROR)
                    IBATCH=0
                    IF(IERROR.EQ.'NO')IBATCH=INT(VALUE(ILOCP)+0.5)
                    IF(IBATCH.NE.1)IBATCH=0
                    IERROR='NO'
!
                    IF(IHTML.EQ.1)THEN
                      IFLAG=-1
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3026)
                      CALL DPWRST('XXX','BUG ')
!
                      IF(IMACNU.NE.5)THEN
                        WRITE(ICOUT,3031)IMANAM(IMALEV)
                        CALL DPWRST('XXX','BUG ')
                      ELSE
                        WRITE(ICOUT,3032)
                        CALL DPWRST('XXX','BUG ')
                      ENDIF
                      WRITE(ICOUT,3013)IVARN1(II),IVARN2(II),   &
                                       IVARN1(1),IVARN2(1)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3120)
 3120                 FORMAT('       1. Close this error-message ',   &
                             'window (via X-out)')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3122)
 3122                 FORMAT('       2. Terminate the Dataplot run ',   &
                             '(via Ctrl-C)')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3124)IQUOTE
 3124                 FORMAT('       3. Edit Dataplot',A1,   &
                             's main routine to correctly define ',   &
                             'the variable.')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3128)
 3128                 FORMAT('       4. Rerun Dataplot')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3026)
                      CALL DPWRST('XXX','BUG ')
                      CALL DPPAUS(IBUGA3,IFOUND,IERROR)
!
                    ELSE
!
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3026)
 3026                 FORMAT('===============================',   &
                             '=========')
                      CALL DPWRST('XXX','BUG ')
!
                      IF(IMACNU.NE.5)THEN
                        WRITE(ICOUT,3031)IMANAM(IMALEV)
 3031                   FORMAT('Error--Macro ',A80)
                        CALL DPWRST('XXX','BUG ')
                      ELSE
                        WRITE(ICOUT,3032)
 3032                   FORMAT('Error--From terminal')
                        CALL DPWRST('XXX','BUG ')
                      ENDIF
                      WRITE(ICOUT,3013)IVARN1(II),IVARN2(II),   &
                                      IVARN1(1),IVARN2(1)
                      CALL DPWRST('XXX','BUG ')
                    ENDIF
                    IF(IBATCH.EQ.0)THEN
                      WRITE(ICOUT,3058)
 3058                 FORMAT('        Click  Enter  to continue ...')
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,3026)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                      CALL DPPAUS(IBUGA3,IFOUND,IERROR)
                    ELSE
                      WRITE(ICOUT,3026)
                      CALL DPWRST('XXX','BUG ')
                      WRITE(ICOUT,999)
                      CALL DPWRST('XXX','BUG ')
                    ENDIF
                  ENDIF
                ENDIF
              ENDIF
            ENDIF
            GO TO 3029
          ENDIF
 3020   CONTINUE
!
        IFLAG=0
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3023)IHRIGH,IHRIG2
 3023   FORMAT('      NAME ',2A4,' WAS NOT FOUND IN THE CURRENT NAME ',   &
               'LIST.')
        CALL DPWRST('XXX','BUG ')
!
 3029   CONTINUE
 3010 CONTINUE
!
 3900 CONTINUE
!
!               *****************************************************
!               **  STEP 4--                                       **
!               **  SAVE PARAMETER                                 **
!               *****************************************************
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CKEL')THEN
        ISTEPN='4'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,4013)ICASEL
 4013   FORMAT('ICASEL = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ICASEL.EQ.'PARA')THEN
!
        ISTEPN='4A'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CKEL')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IHNAME(ILISTL)=IHLEFT
        IHNAM2(ILISTL)=IHLEF2
        IUSE(ILISTL)='P'
        VALUE(ILISTL)=REAL(IFLAG)
        IVALUE(ILISTL)=IFLAG
        IN(ILISTL)=1
        IF(NEWNAM.EQ.'YES')NUMNAM=NUMNAM+1
      ELSEIF(ICASEL.EQ.'ELEM')THEN
!
!       SEARCH IANS STRING FOR "(xx) =".  IF NO PARENTHESIS
!       FOUND BEFORE "=", THEN DO NOT KNOW WHAT ROW OF THE
!       VARIABLE TO SAVE.  TREAT THIS AS AN ERROR.
!
        NLEFT=-1
        NRIGHT=-1
        NEQUAL=-1
        DO 4201 I=1,IWIDTH
          IF(IANS(I)(1:1).EQ.'(' .AND. NLEFT.LT.0)THEN
            NLEFT=I
          ELSEIF(IANS(I)(1:1).EQ.')' .AND. NRIGHT.LT.0)THEN
            NRIGHT=I
          ELSEIF(IANS(I)(1:1).EQ.'=' .AND. NEQUAL.LT.0)THEN
            NEQUAL=I
          ENDIF
 4201   CONTINUE
!
!       NEED  NLEFT < NRIGHT < NEQUAL
!
        NSTRT=NLEFT+1
        NSTOP=NRIGHT-1
        NLEN=NSTOP-NSTRT+1
        IF(NLEFT.GT.NRIGHT .OR. NRIGHT.GT.NEQUAL .OR.   &
           NSTRT.GT.NSTOP .OR. NLEN.GT.8) THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4211)
 4211     FORMAT('      UNRECOGNIZED SYNTAX FOR VARIABLE ELEMENT ON ',   &
                 'LEFT HAND SIDE EQUAL SIGN.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSE
          ISTR=' '
          DO 4216 I=1,NLEN
            ISTR(I:I)=IANS(NSTRT+I-1)(1:1)
 4216     CONTINUE
          READ(ISTR,'(I8)',ERR=4218)IARGL
          GO TO 4219
!
 4218     CONTINUE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4211)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
!
 4219     CONTINUE
        ENDIF
!
        IF(IARGL.LT.1 .OR. IARGL.GT.MAXN)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2001)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4231)IARGL,ILEFT
 4231     FORMAT('      THE SPECIFIED ROW (',I8,') OF VARIABLE ',A4,A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4233)
 4233     FORMAT('      WAS LESS THAN 1 OR GREATER THAN THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4235)MAXN
 4235     FORMAT('      MAXIMUM ALLOWABLE ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IF(NEWNAM.EQ.'YES')THEN
          NIOLD=1
        ENDIF
        NINEW=NIOLD
        IF(IARGL.GT.NINEW)NINEW=IARGL
        NS2=1
!
        RIGHT=REAL(IFLAG)
        IJ=MAXN*(ICOLL-1)+IARGL
        IF(ICOLL.LE.MAXCOL)V(IJ)=RIGHT
        IF(ICOLL.EQ.MAXCP1)PRED(IARGL)=RIGHT
        IF(ICOLL.EQ.MAXCP2)RES(IARGL)=RIGHT
        IF(ICOLL.EQ.MAXCP3)YPLOT(IARGL)=RIGHT
        IF(ICOLL.EQ.MAXCP4)XPLOT(IARGL)=RIGHT
        IF(ICOLL.EQ.MAXCP5)X2PLOT(IARGL)=RIGHT
        IF(ICOLL.EQ.MAXCP6)TAGPLO(IARGL)=RIGHT
!
        IHNAME(ILISTL)=IHLEFT
        IHNAM2(ILISTL)=IHLEF2
        IUSE(ILISTL)='V'
        IVALUE(ILISTL)=ICOLL
        VALUE(ILISTL)=ICOLL
        IN(ILISTL)=NINEW
!
        IF(NEWNAM.EQ.'YES')THEN
          NUMNAM=NUMNAM+1
          NUMCOL=NUMCOL+1
        ENDIF
!
        DO 4290 J4=1,NUMNAM
          IF(IUSE(J4).EQ.'V'.AND.IVALUE(J4).EQ.ICOLL)THEN
            IUSE(J4)='V'
            IVALUE(J4)=ICOLL
            VALUE(J4)=ICOLL
            IN(J4)=NINEW
            GO TO 4299
          ENDIF
 4290   CONTINUE
 4299   CONTINUE
!
      ENDIF
!
      IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)IFLAG
 8011   FORMAT('THE STATUS FLAG FOR CHECK EQUAL LENGTH = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CKEL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCKEL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMNAM
 9013   FORMAT('NUMNAM,IVALUE = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NUMNAM
          WRITE(ICOUT,9016)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I)
 9016     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I)=',  &
                 I8,2X,2A4,2X,A4,2I8)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCKEL
      SUBROUTINE DPCLA2(X,NROW,NCOL,NCLUST,IVARN1,IVARN2,   &
                        DYS,DYSMA,DYSMB,BETER,   &
                        TTD,RADUS,RATT,   &
                        TTBES,RDBES,   &
                        RABES,TTNEW,RDNEW,   &
                        NR,NRX,NSEL,NBEST,   &
                        NREPR,NRNEW,NSNEW,   &
                        NPNEW,NS,NP,   &
                        NEW,   &
                        XSAVE,IC1,   &
                        ICAPSW,ICAPTY,IFORSW,MAXNXT,ISEED,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A K-MEDIODS CLUSTER ANALYSIS FOR > 100 ROWS USING
!              KAUFFMAN AND ROUSSEEUW "CLARA" ALGORITHM (FOR <= 100
!              ROWS, USE THE "PAM" ALGORITHM.
!     REFERENCES--KAUFMAN AND ROUSSEEUW (1990), "FINDING GROUPS IN DATA:
!                 AN INTRODUCTION TO CLUSTER ANALYSIS", WILEY.
!               --ROUSSEEUW (1987), "SILHOUETTES: A GRAPHICAL AID TO THE
!                 INTERPRETATION AND VALIDATION OF CLUSTER ANALYSIS",
!                 JOURNAL OF COMPUTATIONAL AND APPLIED MATHEMATICS,
!                 VOL. 20, PP. 53-65, NORTH HOLLAND.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION X(*)
      DIMENSION DYS(*)
      DIMENSION TTD(*)
      DIMENSION RADUS(*)
      DIMENSION RATT(*)
      DIMENSION TTBES(*)
      DIMENSION RDBES(*)
      DIMENSION RABES(*)
      DIMENSION DYSMA(*)
      DIMENSION DYSMB(*)
      DIMENSION BETER(*)
      DIMENSION TTNEW(*)
      DIMENSION RDNEW(*)
      DIMENSION XSAVE(NROW,NCOL)
!
      INTEGER NR(*)
      INTEGER NRX(*)
      INTEGER NSEL(*)
      INTEGER NBEST(*)
      INTEGER NREPR(*)
      INTEGER NRNEW(*)
      INTEGER NSNEW(*)
      INTEGER NPNEW(*)
      INTEGER NS(*)
      INTEGER NP(*)
      INTEGER NEW(*)
      INTEGER IC1(*)
!
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      REAL RAN(1)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IFLAG
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASPL
      CHARACTER*4 ITYP3
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCL'
      ISUBN2='A2  '
      IWRITE='OFF'
!
      ZBA=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CLA2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF DPCLA2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)NROW,NCOL,NCLUST,IKMDSC,IKMDDI
   72   FORMAT('NROW,NCOL,NCLUST,IKMDSC,IKMDDI = ',3I8,2(2X,A4))
        CALL DPWRST('XXX','BUG ')
        DO 75 I=1,NROW*NCOL
          WRITE(ICOUT,77)I,X(I)
   77     FORMAT('I,X(I) = ',I8,2X,G15.7)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
        WRITE(ICOUT,79)ICAPSW,ICAPTY,IFORSW
   79   FORMAT('ICAPSW,ICAPTY,IFORSW = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **   STEP 1--                 **
!               **   CHECK FOR MISSING VALUES **
!               ********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE THAT CLARA EXPECTS DATA TO BE IN "ROW ORDER", THAT IS
!     (ROW = OBSERVATION NUMBER, COLUMN = VARIABLE NUMBER):
!
!          X(1)       =  ROW 1, COLUMN 1
!          X(2)       =  ROW 1, COLUMN 2
!              ...
!          X(NCOL)    = ROW 1, COLUMN NCOL
!          X(NCOL+1)  = ROW 2, COLUMN 1
!               ...
!
!
!     THE X ARRAY ON INPUT IS IN COLUMN ORDER.  SO FIRST
!     STEP IS TO CONVERT TO ROW ORDER.
!
      DO 101 I=1,NROW*NCOL
        DYS(I)=-9999.0
 101  CONTINUE
!
      DO 102 IROW=1,NROW
        DO 103 ICOL=1,NCOL
          INDX1=(ICOL-1)*NROW + IROW
          INDX2=(IROW-1)*NCOL + ICOL
          DYS(INDX2)=X(INDX1)
  103   CONTINUE
  102 CONTINUE
!
      DO 104 I=1,NROW*NCOL
        X(I)=DYS(I)
 104  CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CLA2')THEN
        DO 105 I=1,NROW*NCOL
          WRITE(ICOUT,77)I,X(I)
          CALL DPWRST('XXX','BUG ')
  105   CONTINUE
      ENDIF
!
!     FIRST CHECK WHETHER ANY ROWS OR COLUMNS CONTAIN ONLY
!     MISSING DATA.  THIS WILL BE TREATED AS AN ERROR CONDITION.
!
!     CHECK ROWS FIRST
!
      DO 110 I=1,NROW
        DO 120 J=1,NCOL
          INDX=(I-1)*NCOL + J
          IF(X(INDX).NE.PSTAMV)GO TO 129
  120   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('****** ERROR IN CLARA CLUSTERING--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)I
  123   FORMAT('       ROW (OBSERVATION) ',I8,' CONTAINS ONLY ',   &
               'MISSING DATA.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
  129   CONTINUE
  110 CONTINUE
!
!     NOW CHECK COLUMNS
!
      NMISS=0
      NMAT=0
!
      DO 130 J=1,NCOL
        NMISSV=0
        DO 140 I=1,NROW
          INDX=(I-1)*NCOL + J
          IF(X(INDX).EQ.PSTAMV)THEN
            NMISSV=NMISSV + 1
          ENDIF
  140   CONTINUE
        IF(NMISSV.EQ.NROW)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,121)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,143)J
  143     FORMAT('       COLUMN (VARIABLE) ',I8,' CONTAINS ONLY ',   &
                 'MISSING DATA.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(NMISSV.EQ.0)THEN
          NMAT=1
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)IVARN1(J),IVARN2(J),NMISSV
  146     FORMAT('VARIABLE ',2A4,' CONTAINS ',I8,' MISSING VALUES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,143)J
        ENDIF
        NMISS=NMISS + NMISSV
  130 CONTINUE
!
      IF(NMISS.GT.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('THE TOTAL NUMBER OF MISSING VALUES IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(NMAT.EQ.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,165)
  165     FORMAT('****** WARNING IN CLARA CLUSTERING--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,167)
  167     FORMAT('       NO VARIABLES ARE DEFINED FOR ALL ',   &
                 'OBSERVATIONS.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               ******************************
!               **   STEP 2--               **
!               **   SCALE IF REQUESTED     **
!               ******************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,168)NMISS,PSTAMV
  168   FORMAT('NMISS,PSTAMV = ',I8,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      NSTAN=0
      IF(IKMDSC.EQ.'OFF')GO TO 299
!
      NSTAN=1
      DO 201 JJ=1,NCOL
        NROWT=0
        DO 203 II=1,NROW
          INDX=(II-1)*NCOL + JJ
          IF(X(INDX).NE.PSTAMV)THEN
            NROWT=NROWT+1
            DYS(NROWT)=X(INDX)
          ENDIF
  203   CONTINUE
        IF(ISTALO.EQ.'MEAN')THEN
          CALL MEAN(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'MEDI')THEN
          CALL MEDIAN(DYS,NROWT,IWRITE,DYSMB,MAXNXT,XMEAN,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'MIDM')THEN
          CALL MIDMEA(DYS,NROWT,IWRITE,DYSMB,MAXNXT,XMEAN,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'HARM')THEN
          CALL HARMEA(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'MINI')THEN
          CALL MINIM(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'GEOM')THEN
          CALL GEOMEA(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'BILO')THEN
          CALL BIWLOC(DYS,NROWT,IWRITE,DYSMA,DYSMB,MAXNXT,XMEAN,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'H15 ')THEN
          NCUT=0
          C=1.5
          CALL H15(DYS,NROWT,C,NCUT,XMEAN,XSC,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'H10 ')THEN
          NCUT=0
          C=1.0
          CALL H15(DYS,NROWT,C,NCUT,XMEAN,XSC,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'H12 ')THEN
          NCUT=0
          C=1.2
          CALL H15(DYS,NROWT,C,NCUT,XMEAN,XSC,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'H17 ')THEN
          NCUT=0
          C=1.7
          CALL H15(DYS,NROWT,C,NCUT,XMEAN,XSC,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTALO.EQ.'H20 ')THEN
          NCUT=0
          C=2.0
          CALL H15(DYS,NROWT,C,NCUT,XMEAN,XSC,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSE
          CALL MEAN(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ENDIF
!
        IF(ISTASC.EQ.'SD  ')THEN
          CALL SD(DYS,NROWT,IWRITE,XSD,IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'H15S')THEN
          NCUT=0
          C=1.5
          CALL H15(DYS,NROWT,C,NCUT,XLOC,XSD,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'H10S')THEN
          NCUT=0
          C=1.0
          CALL H15(DYS,NROWT,C,NCUT,XLOC,XSD,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'H12S')THEN
          NCUT=0
          C=1.2
          CALL H15(DYS,NROWT,C,NCUT,XLOC,XSD,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'H17S')THEN
          NCUT=0
          C=1.7
          CALL H15(DYS,NROWT,C,NCUT,XLOC,XSD,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'H20S')THEN
          NCUT=0
          C=2.0
          CALL H15(DYS,NROWT,C,NCUT,XLOC,XSD,DYSMA,DYSMB,MAXNXT,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'BISC')THEN
          CALL BIWSCA(DYS,NROWT,IWRITE,DYSMA,DYSMB,MAXNXT,XSD,   &
                      IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'MAD ')THEN
          CALL MAD(DYS,NROWT,IWRITE,DYSMA,DYSMB,MAXNXT,XSD,   &
                   IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'MADN')THEN
          CALL MAD(DYS,NROWT,IWRITE,DYSMA,DYSMB,MAXNXT,XSD,   &
                   IBUGA3,IERROR)
          XSD=XSD/0.67449
        ELSEIF(ISTASC.EQ.'AAD ')THEN
          CALL AAD(DYS,NROWT,IWRITE,DYSMA,MAXNXT,XSD,'MEAN',   &
                   IBUGA3,IERROR)
        ELSEIF(ISTASC.EQ.'IQRA')THEN
          CALL LOWQUA(DYS,NROWT,IWRITE,DYSMA,MAXNXT,RIGH1,   &
                      IBUGA3,IERROR)
          CALL UPPQUA(DYS,NROWT,IWRITE,DYSMA,MAXNXT,RIGH2,   &
                      IBUGA3,IERROR)
          XSD=RIGH2-RIGH1
        ELSEIF(ISTASC.EQ.'NIQR')THEN
          CALL LOWQUA(DYS,NROWT,IWRITE,DYSMA,MAXNXT,RIGH1,   &
                      IBUGA3,IERROR)
          CALL UPPQUA(DYS,NROWT,IWRITE,DYSMA,MAXNXT,RIGH2,   &
                      IBUGA3,IERROR)
          XSD=0.7413*(RIGH2-RIGH1)
        ELSEIF(ISTASC.EQ.'SNSC')THEN
          XSD=SN(DYS,NROWT,DYSMA,DYSMB,BETER)
        ELSEIF(ISTASC.EQ.'MAXI')THEN
          CALL MINIM(DYS,NROWT,IWRITE,XMIN,IBUGA3,IERROR)
          CALL MAXIM(DYS,NROWT,IWRITE,XMAX,IBUGA3,IERROR)
          XSD=XMAX - XMIN
        ELSE
          CALL SD(DYS,NROWT,IWRITE,XMEAN,IBUGA3,IERROR)
        ENDIF
!
        IF(XSD.LE.0.0)THEN
          WRITE(ICOUT,121)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,206)JJ
  206     FORMAT('       VARIABLE ',I4,' HAS ZERO STANDARD DEVIATION ',   &
                 'WHEN SCALING REQUESTED.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        DO 205 II=1,NROW
          INDX=(II-1)*NCOL + JJ
          IF(X(INDX).NE.PSTAMV)THEN
            AVAL=(X(INDX)-XMEAN)/XSD
            X(INDX)=AVAL
          ENDIF
  205   CONTINUE
  201 CONTINUE
!
  299 CONTINUE
!
!     SAVE X ARRAY IN ROW/COLUMN FORMAT FOR SILHOUEETE PLOT POINTS
!     (BUT ONLY IF NROW*NCOL <= 2*MAXNXT)
!
      IF(NROW*NCOL.LE.2*MAXNXT)THEN
        ICNT=0
        DO 211 II=1,NROW
          DO 213 JJ=1,NCOL
            ICNT=ICNT+1
            XSAVE(II,JJ)=X(ICNT)
            IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CLA2')THEN
              WRITE(ICOUT,215)II,JJ,XSAVE(II,JJ)
  215         FORMAT('II,JJ,XSAVE(II,JJ) = ',2I8,G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
  213     CONTINUE
  211   CONTINUE
      ENDIF
!
!     OPEN THE AUXILLARY FILES
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=1
      IFLG31=1
      IFLAG4=1
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ************************************
!               **   STEP 3--                     **
!               **   PERFORM THE CLUSTER ANALYSIS **
!               ************************************
!
!      THIS CODE IS A SOMEWHAT MODIFED VERSION OF CODE IN THE
!      CLARA MAIN ROUTINE.
!
!      IN THE DO 400 LOOP, RANDOM SUBSAMPLES ARE DRAWN AND PARTITIONED
!      INTO KK CLUSTERS
!
      KK=NCLUST
      IF(IKMDNS.GE.1 .AND. IKMDNS.LE.NROW)THEN
        NRAN=IKMDNS
      ELSE
        NRAN=5
      ENDIF
      NN=NROW
      JPP=NCOL
      RNN=REAL(NN)
      IF(IKMDSS.GE.10+2*KK .AND. IKMDSS.LE.NROW)THEN
        NSAM=IKMDSS
      ELSE
        NSAM=40 + 2*KK
      ENDIF
      NNEQ=0
      IF(NN.EQ.NSAM)NNEQ=1
      NHALF=NSAM*(NSAM-1)/2 + 1
      NSAMB=2*NSAM
      NNPP=NROW*NCOL
      IFLAG='CLAR'
      NDYST=2
      IF(IKMDDI.EQ.'EUCL')NDYST=1
!
      IF(IKMDPR.EQ.'ALL')THEN
        LARGE=2
      ELSEIF(IKMDPR.EQ.'FINA')THEN
        LARGE=1
      ELSEIF(IKMDPR.EQ.'MINI')THEN
        LARGE=0
      ELSE
        LARGE=2
      ENDIF
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,169)KK,NRAN,NSAM,NNPP,NDYST
  169   FORMAT('KK,NRAN,NSAM,NNPP,NDYST = ',5I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IPRINT.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
  301   FORMAT(10X,'**********************************************')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)
  302   FORMAT(10X,'*                                            *')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)
  303   FORMAT(10X,'*  ROUSSEEUW/KAUFFMAN K-MEDOID CLUSTERING    *')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,304)
  304   FORMAT(10X,'*  (USING THE CLARA ROUTINE).                *')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,401)
  401   FORMAT('**********************************************')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)
  402   FORMAT('*                                            *')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,403)KK
  403   FORMAT('*  NUMBER OF REPRESENTATIVE OBJECTS ',I5,4X,'*')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,402)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,401)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,406)NRAN,NSAM
  406   FORMAT(I4,' SAMPLES OF ',I5,' OBJECTS WILL NOW BE DRAWN.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      NUNFS=0
      LESS=NSAM
      IF(NN.LT.NSAMB)LESS=NN-NSAM
      KALL=0
      NRUN=0
!
      DO 400 JRAN=1,NRAN
!
         IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')THEN
           ISTEPN='3A'
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
           WRITE(ICOUT,29)JRAN
   29      FORMAT('JRAN = ',I6)
           CALL DPWRST('XXX','BUG ')
        ENDIF
!
        JHALT=0
        IF(NNEQ.EQ.2)GO TO 400
!
        IF(NNEQ.NE.0)THEN
          NNEQ=2
          DO 411 J=1,NSAM
            NSEL(J)=J
  411     CONTINUE
          WRITE(ICOUT,9255)
 9255     FORMAT('THE SIZE OF THE SAMPLE EQUALS THE NUMBER OF OBJECTS ',   &
                 'IN THE DATA SET.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9256)
 9256     FORMAT('IN THIS CASE THE ENTIRE DATA SET IS CLUSTERED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 330
        ENDIF
!
        IF(IPRINT.EQ.'ON' .AND. LARGE.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9265)JRAN
 9265     FORMAT('SAMPLE NUMBER ',I4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9266)
 9266     FORMAT('******************')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        NTT=0
        IF(JRAN.EQ.1 .OR. NUNFS.EQ.JRAN .OR. NN.LT.NSAMB)THEN
  180     CONTINUE
!NIST     CALL RANDM(NRUN,RAN)
          IF(IKMDRN.EQ.'DATA')THEN
            NTEMP=1
            CALL UNIRAN(NTEMP,ISEED,RAN)
          ELSE
            NRUN=NRUN*5761+999
            KTEMP=NRUN/65536
            NRUN=NRUN-KTEMP*65536
            RY=NRUN
            RAN(1)=RY/65536.0
          ENDIF
!
          KRAN=INT(RNN*RAN(1)+1.)
          IF(KRAN.GT.NN)KRAN=NN
          IF(JRAN.GT.1)THEN
            DO 190 JK=1,KK
              IF(KRAN.EQ.NRX(JK))GO TO 180
  190       CONTINUE
          ENDIF
          NTT=NTT+1
          NSEL(NTT)=KRAN
        ELSE
          DO 150 JK=1,KK
            NSEL(JK)=NRX(JK)
  150     CONTINUE
          KKM=KK-1
          DO 170 JK=1,KKM
            NSM=NSEL(JK)
            KKP=JK+1
            JSM=JK
            DO 160 JKK=KKP,KK
              IF(NSEL(JKK).GE.NSM)GO TO 160
              NSM=NSEL(JKK)
              JSM=JKK
  160       CONTINUE
            NSEL(JSM)=NSEL(JK)
            NSEL(JK)=NSM
  170     CONTINUE
          NTT=KK
        ENDIF
!
  210   CONTINUE
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')THEN
          ISTEPN='3B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,31)
   31     FORMAT('AT 210')
          CALL DPWRST('XXX','BUG ')
          DO 33 II=1,NTT
            WRITE(ICOUT,32)II,NSEL(II)
   32       FORMAT('II,NSEL(II) = ',2I8)
            CALL DPWRST('XXX','BUG ')
   33     CONTINUE
        ENDIF
!
!NIST   CALL RANDM(NRUN,RAN)
        IF(IKMDRN.EQ.'DATA')THEN
          NTEMP=1
          CALL UNIRAN(NTEMP,ISEED,RAN)
        ELSE
          NRUN=NRUN*5761+999
          KTEMP=NRUN/65536
          NRUN=NRUN-KTEMP*65536
          RY=NRUN
          RAN(1)=RY/65536.0
        ENDIF
        KRAN=INT(RNN*RAN(1)+1.)
        IF(KRAN.GT.NN)KRAN=NN
        IF(JRAN.GT.1 .AND. NN.LT.NSAMB)THEN
          DO 220 JK=1,KK
            IF(KRAN.EQ.NRX(JK))GO TO 210
  220     CONTINUE
        ENDIF
!
        DO 260 KANS=1,NTT
          IF(NSEL(KANS).LT.KRAN)GO TO 260
          IF(NSEL(KANS).EQ.KRAN)GO TO 210
          DO 280 NAD=KANS,NTT
            NADV=NTT-NAD+KANS
            NADVP=NADV+1
            NSEL(NADVP)=NSEL(NADV)
  280     CONTINUE
          NTT=NTT+1
          NSEL(KANS)=KRAN
          GO TO 290
  260   CONTINUE
        NTT=NTT+1
        NSEL(NTT)=KRAN
!
  290   CONTINUE
        IF(NTT.LT.LESS)GO TO 210
        IF(NN.LT.NSAMB)THEN
          NEXAP=1
          NEXBP=1
          JN=0
  300     CONTINUE
          JN=JN+1
          IF(NSEL(NEXAP).EQ.JN)THEN
            NEXAP=NEXAP+1
          ELSE
            NREPR(NEXBP)=JN
            NEXBP=NEXBP+1
          ENDIF
          IF(JN.LT.NN)GO TO 300
          DO 310 NSUB=1,NSAM
            NSEL(NSUB)=NREPR(NSUB)
  310     CONTINUE
        ENDIF
!
        IF(IPRINT.EQ.'ON' .AND. LARGE.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9270)
 9270     FORMAT('RANDOM SAMPLE =')
          CALL DPWRST('XXX','BUG ')
          ILINE=NSAM/10
          IREM=MOD(NSAM,10)
          IF(IREM.GE.1)ILINE=ILINE+1
          DO 9271 II=1,ILINE
            ISTRT=(II-1)*10 + 1
            ISTOP=II*10
            IF(ISTOP.GT.NSAM)ISTOP=NSAM
            WRITE(ICOUT,9280)(NSEL(JJ),JJ=ISTRT,ISTOP)
 9280       FORMAT(5X,10I7)
            CALL DPWRST('XXX','BUG ')
 9271     CONTINUE
        ENDIF
!
  330   CONTINUE
!
!       NDYST = 1 => EUCLIDEAN DISTANCES
!             = 2 => MANHATTAN DISTANCES
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')THEN
          ISTEPN='3C'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,9931)
 9931     FORMAT('BEFORE CALL DYSTA')
          CALL DPWRST('XXX','BUG ')
          DO 9933 II=1,NSAM
            WRITE(ICOUT,9932)II,NSEL(II),NREPR(II)
 9932       FORMAT('II,NSEL(II),NREPR(II) = ',3I8)
            CALL DPWRST('XXX','BUG ')
 9933     CONTINUE
        ENDIF
!
        CALL DYSTA(NSAM,NCOL,NSEL,X,DYS,NDYST,PSTAMV,JHALT,   &
                   ISUBRO,IBUGA3)
!
        ISTEPN='3D'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(JHALT.EQ.1)GO TO 400
        KALL=1
        S=0.0
        L=1
!
  340   CONTINUE
        L=L+1
        IF(DYS(L).GT.S)S=DYS(L)
        IF(L.LT.NHALF)GO TO 340
!
        ISTEPN='3E'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL BSWAP(KK,NSAM,NREPR,DYSMA,DYSMB,BETER,DYS,Z,S,IFLAG,   &
                   LARGE,ISUBRO,IBUGA3)
!
        ISTEPN='3F'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        RSAM=NSAM
        AZ=Z/RSAM
!
        IF(NNEQ.EQ.0)THEN
          IF(IPRINT.EQ.'ON' .AND. LARGE.EQ.2)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9320)
 9320       FORMAT('FINAL RESULT FOR THIS SAMPLE')
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NNEQ.GE.1)THEN
          IF(IPRINT.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9325)
 9325       FORMAT('FINAL RESULT')
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
        IF(IPRINT.EQ.'ON')THEN
          IF(LARGE.EQ.2 .OR. NNEQ.GE.1)THEN
            WRITE(ICOUT,9330)AZ
 9330       FORMAT('  AVERAGE DISTANCE  =   ',F12.3)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
!
        ISTEPN='3G'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        MDATA=0
        IF(NMISS.GE.1)MDATA=1
        CALL SELEC(KK,NN,JPP,NSTAN,NDYST,ZB,NSAM,MDATA,   &
                   PSTAMV,NREPR,NSEL,DYS,X,NR,NAFS,   &
                   TTD,RADUS,RATT,   &
                   TTNEW,RDNEW,   &
                   NRNEW,NSNEW,NPNEW,NS,NP,NEW,   &
                   LARGE,ISUBRO,IBUGA3)
!
        ISTEPN='3H'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        NUNFS=NUNFS+NAFS
        IF(NAFS.EQ.1)GO TO 400
        IF(JRAN.EQ.1)GO TO 350
        IF(ZB.GE.ZBA)GO TO 400
!
  350   CONTINUE
        ZBA=ZB
        DO 345 JJB=1,30
          TTBES(JJB)=TTD(JJB)
          RDBES(JJB)=RADUS(JJB)
          RABES(JJB)=RATT(JJB)
  345   CONTINUE
        DO 360 JK=1,KK
          NRX(JK)=NR(JK)
  360   CONTINUE
        DO 370 JS=1,NSAM
          NBEST(JS)=NSEL(JS)
  370   CONTINUE
        JRSKY=JRAN
                                                                                                                                  
  400 CONTINUE
!
      IF(NUNFS.GE.NRAN)THEN
        WRITE(ICOUT,9335)
        WRITE(ICOUT,9335)
 9335   FORMAT('FOR EACH SAMPLE AT LEAST ONE OBJECT WAS FOUND',   &
               ' WHICH COULD NOT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9336)
 9336   FORMAT('BE ASSIGNED TO A CLUSTER (BECAUSE OF',   &
               ' MISSING VALUES).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9337)
 9337   FORMAT(' NO CLUSTERING PERFORMED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!C
!C    FOR THE BEST SUBSAMPLE, THE OBJECTS OF THE ENTIRE DATA SET
!C    ARE ASSIGNED TO THEIR CLUSTERS
!C
      IF(KALL.NE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9340)NRAN
 9340   FORMAT('EACH OF THE ',I5,' RANDOM SAMPLES CONTAINS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9341)
 9341   FORMAT(' OBJECTS BETWEEN WHICH NO DISTANCE CAN BE COMPUTED.')
        CALL DPWRST('XXX','BUG ')
        GO TO 510
      ENDIF
!
      AZBA=ZBA/RNN
      IF(KK.EQ.1)THEN
        IF(IPRINT.EQ.'ON')THEN
          IF(NNEQ.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9350)JRSKY,NRX(1)
 9350       FORMAT('SAMPLE NUMBER',I4,' WAS SELECTED ITS MEDOID IS',   &
                   'OBJECT ',I7,' .')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(NNEQ.GE.1)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9355)NRX(1)
 9355       FORMAT('THE MEDOID IS OBJECT NUMBER ',I7,'.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9360)AZBA
 9360       FORMAT('   AVERAGE DISTANCE FOR THE ENTIRE DATA SET = ',   &
                   F12.3)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
        GO TO 500
      ENDIF
!
      IF(NNEQ.LT.1)THEN
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9370)
 9370     FORMAT('FINAL RESULTS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9371)
 9371     FORMAT(13('*'))
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9372)JRSKY
 9372     FORMAT('SAMPLE NUMBER ',I3,' WAS SELECTED, WITH OBJECTS =')
          CALL DPWRST('XXX','BUG ')
!
          ILOOP=NSAM/10
          IREM=MOD(NSAM,10)
          IF(IREM.GT.0)ILOOP=ILOOP+1
          DO 9283 II=1,ILOOP
            ISTRT=(II-1)*10+1
            ISTOP=II*10
            IF(ISTOP.GT.NSAM)ISTOP=NSAM
            WRITE(ICOUT,9281)(NBEST(JJ),JJ=ISTRT,ISTOP)
 9281       FORMAT(10I7)
            CALL DPWRST('XXX','BUG ')
 9283     CONTINUE
!
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9360)AZBA
          CALL DPWRST('XXX','BUG ')
!
        ENDIF
!
        CALL DYSTA(NSAM,NCOL,NBEST,X,DYS,NDYST,PSTAMV,JHALT,   &
                   ISUBRO,IBUGA3)
        CALL RESUL(KK,NN,NCOL,LARGE,NDYST,X,NRX,PSTAMV,IC1,IOUNI1)
!
        IF(IPRINT.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9400)
 9400     FORMAT('    AVERAGE DISTANCE TO EACH MEDOID')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9401)(TTBES(J),J=1,KK)
 9401     FORMAT(2X,5F12.3)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9410)
 9410     FORMAT('    MAXIMUM DISTANCE TO EACH MEDOID')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9411)(RDBES(J),J=1,KK)
 9411     FORMAT(2X,5F12.3)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9420)
 9420     FORMAT('    MAXIMUM DISTANCE TO A MEDOID DIVIDED BY MINIMUM')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9421)(RABES(J),J=1,KK)
 9421     FORMAT(2X,5F12.3)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
  500 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9450)
 9450   FORMAT('THIS RUN HAS BEEN SUCCESSFULLY COMPLETED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
  510 CONTINUE
!
!               *****************************************
!               **   STEP 4B--                         **
!               **   CREATE VALUES FOR SILHOUETTE PLOT **
!               *****************************************
!
      ISTEPN='4B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLA2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ONLY GENERATE SILHOUETTE PLOT POINTS IF NROW*NCOL <= 2*MAXNXT
!
      IF(NROW*NCOL.GT.2*MAXNXT)GO TO 8190
!
!     COMPUTE THE s(i) VALUE AS
!
!        s(i) = (b(i) - a(i))/max{a(i),b(i)}
!
!     WHERE
!
!        a(i)   = AVERAGE DISSIMILARITY OF THE i-TH POINT WITH
!                 ALL OTHER POINTS IN THE CLUSTER TO WHICH IT
!                 BELONGS
!
!        b(i)   = LOWEST AVERAGE DISSIMILARITY OF THE i-TH POINT
!                 WITH ALL OTHER CLUSTERS.
!
!     USE ONE-PASS MEAN ALGORITHMS TO KEEP TRACK OF AVERAGE
!     DISSIMILARITY OF ALL CLUSTERS.  THE ONE-PASS FORMULA IS
!
!         M(K)=X1                            K = 1
!             =M(K-1) + (X(K) - M(K-1))/K    K = 2, ...., N
!
      WRITE(IOUNI4,8001)
 8001 FORMAT(8X,'CLUSTER',5X,'SILHOUETTE',7X,'NEIGHBOR')
!
      DO 8110 II=1,NROW
        ICLUS1=IC1(II)
        DO 8112 JJ=1,NCOL
          DYSMA(JJ)=XSAVE(II,JJ)
 8112   CONTINUE
        ICASPL='VEDI'
        DO 8114 KK=1,NCLUST
          RDNEW(KK)=CPUMIN
          NEW(KK)=0
 8114   CONTINUE
!
        DO 8120 JJ=1,NROW
          IF(II.EQ.JJ)GO TO 8120
          ICLUS2=IC1(JJ)
          DO 8122 KK=1,NCOL
            DYSMB(KK)=XSAVE(JJ,KK)
 8122     CONTINUE
          CALL VECARI(DYSMA,DYSMB,NCOL,ICASPL,IWRITE,   &
                      BETER,N3,ADIST,ITYP3,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(ICLUS1.EQ.ICLUS2)THEN
            NEW(ICLUS1)=NEW(ICLUS1)+1
            IF(NEW(ICLUS1).EQ.1)THEN
              RDNEW(ICLUS1)=ADIST
            ELSE
              TERM1=(ADIST - RDNEW(ICLUS1))/REAL(NEW(ICLUS1))
              RDNEW(ICLUS1)=RDNEW(ICLUS1) + TERM1
            ENDIF
          ELSE
            NEW(ICLUS2)=NEW(ICLUS2)+1
            IF(NEW(ICLUS2).EQ.1)THEN
              RDNEW(ICLUS2)=ADIST
            ELSE
              TERM1=(ADIST - RDNEW(ICLUS2))/REAL(NEW(ICLUS2))
              RDNEW(ICLUS2)=RDNEW(ICLUS2) + TERM1
            ENDIF
          ENDIF
 8120   CONTINUE
!
        AI=RDNEW(ICLUS1)
        BI=CPUMAX
        NEIGH=-1
        DO 8130 JJ=1,NCLUST
          IF(JJ.EQ.ICLUS1)GO TO 8130
          IF(RDNEW(JJ).LT.BI)THEN
            BI=RDNEW(JJ)
            NEIGH=JJ
          ENDIF
 8130   CONTINUE
        SYL=(BI - AI)/MAX(AI,BI)
        WRITE(IOUNI4,'(3E15.7)')REAL(IC1(II)),SYL,REAL(NEIGH)
!
 8110 CONTINUE
 8190 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8091)
 8091   FORMAT('THE CLUSTER ID VALUES ARE WRITTEN TO dpst1f.dat')
        CALL DPWRST('XXX','BUG ')
!NIST   WRITE(ICOUT,8093)
!8093   FORMAT('THE WITHIN-CLUSTER SUM OF SQUARES AND ',
!NIST1         'THE NUMBER OF POINTS')
!NIST   CALL DPWRST('XXX','BUG ')
!NIST   WRITE(ICOUT,8095)
!8095   FORMAT('FOR EACH CLUSTER ARE WRITTEN TO dpst2f.dat')
!NIST   CALL DPWRST('XXX','BUG ')
!NIST   WRITE(ICOUT,8097)
!8097   FORMAT('THE CLUSTER CENTERS ARE WRITTEN TO dpst3f.dat')
!NIST   CALL DPWRST('XXX','BUG ')
        IF(NROW*NCOL.LE.2*MAXNXT)THEN
          WRITE(ICOUT,8099)
 8099     FORMAT('THE SILHOUETTE VALUES ARE WRITTEN TO dpst4f.dat')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CLA2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCLA2--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCLA2
      SUBROUTINE DPCLCH(PX,PY,NP,PX2,PY2,NP2,X3D2,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        ISORSW,   &
                        IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,   &
                        ANGLE,IFILL,ICOL,ICOLR,ICOLG,ICOLB,   &
                        PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                        IMPSW2,AMPSCH,AMPSCW,   &
                        ISYMBL,ISPAC)
!
!     PURPOSE--CARRY OUT CLIPPING (IF NECESSARY) AND DRAW THE
!              POLYMARKERS (OR SERIES OF CLIPPED TRACES)
!              BASED ON THE DATA IN (PX,PY).
!     DANGER--THE INPUT VARIABLES PX(.) AND PY(.) MAY BE
!             CHANGED IN THIS SUBROUTINE (SEE STEP 0 BELOW)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED       --DECEMBER  1999. SUPPORT FOR ROWID AND ROW LABEL
!                                     AS CHARACTERS.
!     UPDATED       --JANUARY   2000. USE ISUB TO GET CORRECT VALUE
!                                     FOR ROWID AND ROW LABEL
!     UPDATED       --JANUARY   2000. ADD X3D2 TO CALL LIST
!     UPDATED       --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISORSW
      CHARACTER*4 IFIG
      CHARACTER*24 IPATT
      CHARACTER*4 IFONT
      CHARACTER*4 ICASE
      CHARACTER*4 IJUST
      CHARACTER*4 IDIR
      CHARACTER*4 IFILL
      CHARACTER*4 ICOL
!
      CHARACTER*24 ISYMBL
      CHARACTER*4 ISPAC
      CHARACTER*4 IMPSW2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZI.INC'
      DIMENSION IROWID(MAXOBV)
      DIMENSION IJUNK(MAXOBV)
      DIMENSION IJUNK2(MAXOBV)
      EQUIVALENCE (IGARBG(IIGAR1),IROWID(1))
      EQUIVALENCE (IGARBG(IIGAR2),IJUNK(1))
      EQUIVALENCE (IGARBG(IIGAR3),IJUNK2(1))
!
      DIMENSION PX(*)
      DIMENSION PY(*)
      DIMENSION X3D2(*)
!
      DIMENSION PX2(*)
      DIMENSION PY2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCL'
      ISUBN2='CH  '
!
      XMIN=CPUMAX
      YMIN=CPUMAX
      XMAX=CPUMIN
      YMAX=CPUMIN
      J=(-999)
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCLCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)PXMIN,PXMAX,PYMIN,PYMAX
   53   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4F10.5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IBUGG4,ISUBG4,IERRG4,ISORSW,NP
   54   FORMAT('IBUGG4,ISUBG4,IERRG4,ISORSW,NP = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)ICOL,ICOLB,ICOLG,ICOLR
   57   FORMAT('ICOL,ICOLR,ICOLG,ICOLB = ',A4,2X,3I5)
        CALL DPWRST('XXX','BUG ')
        DO 62 I=1,NP
          DEL1=PX(I)-PXMIN
          DEL2=PX(I)-PXMAX
          DEL3=PY(I)-PYMIN
          DEL4=PY(I)-PYMAX
          WRITE(ICOUT,63)I,PX(I),PY(I)
   63     FORMAT('I,PX(I),PY(I)         = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,64)I,DEL1,DEL2,DEL3,DEL4
   64     FORMAT('I,DEL1,DEL2,DEL3,DEL4 = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   62   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 0B--                                        *
!               **  SET VALUES OF IJUNK TO VALUES OF ISUB = 1.       *
!               **  USED TO GET PROPER INDEX FOR ROWID               *
!               ******************************************************
!
      DO 81 I=1,MAXOBV
        IJUNK(I)=0
        IJUNK2(I)=0
        IROWID(I)=I
   81 CONTINUE
      J=0
      DO 83 I=1,MAXOBV
        IF(ISUB(I).EQ.1)THEN
          J=J+1
          IJUNK(J)=I
          IF(J.GE.NP)GO TO 89
        ENDIF
   83 CONTINUE
   89 CONTINUE
!
!               ********************************************************
!               **  STEP 0--                                           *
!               **  IF NECESSARY, ADJUST (= CHANGE) THE PX(.) AND      *
!               **  PY(.) VALUES TO ALLOW FOR POSSIBLE ROUNDOFF NEAR   *
!               **  THE LIMITS (PXMIN,PXMAX) AND (PYMIN,PYMAX) WHICH   *
!               **  WOULD SHOW UP AS A DATA POINT NOT BEING PLOTTED    *
!               **  WHEN IT SHOULD HAVE BEEN                           *
!               ********************************************************
!
      CALL DPSQUE(PX,PY,NP,PXMIN,PXMAX,PYMIN,PYMAX)
!
!               *************************************************
!               **  STEP 1--                                   **
!               **  DETERMINE THE FIRST AND LAST ELEMENTS OF   **
!               **  THE (PX,PY) VECTORS WHICH MUST BE SCANNED  **
!               **  BASED ON WHETHER PX(.) IS SORTED           **
!               **  OR NOT.                                    **
!               *************************************************
!
      ISTEPN='1'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISORSW.EQ.'ON')THEN
        DO 1110 I=1,NP
          I2=I
          IF(PX(I).GE.PXMIN)THEN
            IMIN=I2
            GO TO 1119
          ENDIF
 1110   CONTINUE
        IMIN=NP+1
 1119   CONTINUE
!
        DO 1120 I=1,NP
          IREV=NP-I+1
          IF(PX(IREV).LE.PXMAX)THEN
            IMAX=IREV
            GO TO 1129
          ENDIF
 1120   CONTINUE
        IMAX=0
 1129   CONTINUE
!
      ELSE
        IMIN=1
        IMAX=NP
      ENDIF
!
      IF(IMIN.GT.IMAX)GO TO 9000
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  COMPUTE THE HORIZONTAL AXIS VARIABLE MIN AND MAX  **
!               **  FOR THE DATA WITHIN THE SUBSET                    **
!               ********************************************************
!
      ISTEPN='2'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISORSW.EQ.'ON')THEN
        XMIN=PX(IMIN)
        XMAX=PX(IMAX)
      ELSE
        XMIN=CPUMAX
        XMAX=CPUMIN
        DO 1260 I=IMIN,IMAX
          IF(PX(I).LT.XMIN)XMIN=PX(I)
          IF(PX(I).GT.XMAX)XMAX=PX(I)
 1260   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  COMPUTE THE VERTICAL AXIS VARIABLE MIN AND MAX  **
!               **  FOR THE DATA WITHIN THE SUBSET                  **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      YMIN=CPUMAX
      YMAX=CPUMIN
      DO 1300 I=IMIN,IMAX
        IF(PY(I).LT.YMIN)YMIN=PY(I)
        IF(PY(I).GT.YMAX)YMAX=PY(I)
 1300 CONTINUE
!
!               *******************************************************
!               **  STEP 21--                                        **
!               **  TREAT THE MOST COMMON AND MOST IMPORTANT CASE--  **
!               **  ALL NP OBSERVATIONS ARE TO BE USED;              **
!               **  ALL X DATA ARE WITHIN THE FRAME;                 **
!               **  ALL Y DATA ARE WITHIN THE FRAME.                 **
!               *******************************************************
!
      IF(IMIN.EQ.1.AND.IMAX.EQ.NP.AND.   &
      XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX.AND.   &
      YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
        ISTEPN='21'
        DO 2101 I=1,NP
          IROWID(I)=IJUNK(I)
          IJUNK2(I)=1
 2101   CONTINUE
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPDRPM(PX,PY,NP,X3D2,IJUNK2,IROWID,IROWLB,   &
                    IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                    IMPSW2,AMPSCH,AMPSCW,   &
                    ISYMBL,ISPAC)
        NP2=0
        GO TO 9000
      ENDIF
!
!               *******************************************************
!               **  STEP 22--                                        **
!               **  TREAT THE NEXT MOST COMMON AND MOST IMPORTANT CASE--  **
!               **  A SUBSET OF THE NP OBSERVATIONS ARE TO BE USED;  **
!               **  ALL X DATA ARE WITHIN THE FRAME;                 **
!               **  ALL Y DATA ARE WITHIN THE FRAME.                 **
!               *******************************************************
!
      IF(XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX.AND.   &
      YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
        ISTEPN='22'
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        DO 2210 I=IMIN,IMAX
          J=J+1
          PX2(J)=PX(I)
          PY2(J)=PY(I)
          IROWID(J)=IJUNK(I)
          IJUNK2(I)=1
 2210   CONTINUE
        NP2=J
        IF(NP2.GE.1)   &
          CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                      IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                      ICOL,ICOLR,ICOLG,ICOLB,   &
                      PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                      IMPSW2,AMPSCH,AMPSCW,   &
                      ISYMBL,ISPAC)
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 23--                                     **
!               **  TREAT THE CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  ALL X'S ARE INSIDE THE FRAME,                 **
!               **  BUT SOME Y'S ARE OUTSIDE THE FRAME.           **
!               ****************************************************
!
      IF(XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX)THEN
!
        ISTEPN='23'
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        DO 2310 I=IMIN,IMAX
          IM1=I-1
          IF(PY(I).GE.PYMIN.AND.PY(I).LE.PYMAX)THEN
            J=J+1
            PX2(J)=PX(I)
            PY2(J)=PY(I)
            IROWID(J)=IJUNK(I)
            IJUNK2(I)=1
          ELSE
            NP2=J
            IF(NP2.GE.1)   &
              CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                          IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                          ICOL,ICOLR,ICOLG,ICOLB,   &
                          PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                          IMPSW2,AMPSCH,AMPSCW,   &
                          ISYMBL,ISPAC)
            J=0
          ENDIF
 2310   CONTINUE
!
        NP2=J
        IF(NP2.GE.1)   &
          CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                      IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                      ICOL,ICOLR,ICOLG,ICOLB,   &
                      PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                      IMPSW2,AMPSCH,AMPSCW,   &
                      ISYMBL,ISPAC)
        GO TO 9000
!
      ENDIF
!
!               ****************************************************
!               **  STEP 24--                                     **
!               **  TREAT THE CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  ALL Y'S ARE INSIDE THE FRAME,                 **
!               **  BUT SOME X'S ARE OUTSIDE THE FRAME            **
!               **  (AS IN THE CONSTRUCTION OF MAPS)              **
!               ****************************************************
!
      IF(YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
!
        ISTEPN='24'
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        DO 2410 I=IMIN,IMAX
          IM1=I-1
          IF(PX(I).GE.PXMIN.AND.PX(I).LE.PXMAX)THEN
            J=J+1
            PX2(J)=PX(I)
            PY2(J)=PY(I)
            IROWID(J)=IJUNK(I)
            IJUNK2(I)=1
          ELSE
            NP2=J
            IF(NP2.GE.1)   &
              CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                          IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                          ICOL,ICOLR,ICOLG,ICOLB,   &
                          PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                          IMPSW2,AMPSCH,AMPSCW,   &
                          ISYMBL,ISPAC)
            J=0
          ENDIF
!
 2410   CONTINUE
!
        NP2=J
        IF(NP2.GE.1)   &
          CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                      IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                      ICOL,ICOLR,ICOLG,ICOLB,   &
                      PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                      IMPSW2,AMPSCH,AMPSCW,   &
                      ISYMBL,ISPAC)
        GO TO 9000
!
      ENDIF
!
!               ****************************************************
!               **  STEP 25--                                     **
!               **  TREAT THE GENERAL CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  SOME  X'S MAY BE OUTSIDE THE FRAME, AND/OR    **
!               **  SOME  Y'S MAY BE OUTSIDE THE FRAME            **
!               **  (AS IN THE CONSTRUCTION OF MAPS)              **
!               ****************************************************
!
      ISTEPN='25'
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      J=0
      DO 2510 I=IMIN,IMAX
        IM1=I-1
        IF(PX(I).GE.PXMIN.AND.PX(I).LE.PXMAX.AND.   &
           PY(I).GE.PYMIN.AND.PY(I).LE.PYMAX)THEN
          J=J+1
          PX2(J)=PX(I)
          PY2(J)=PY(I)
          IROWID(J)=IJUNK(I)
          IJUNK2(I)=1
        ELSE
          NP2=J
          IF(NP2.GE.1)   &
            CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                        IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                        ICOL,ICOLR,ICOLG,ICOLB,   &
                        PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                        IMPSW2,AMPSCH,AMPSCW,   &
                        ISYMBL,ISPAC)
          J=0
        ENDIF
 2510 CONTINUE
!
      NP2=J
      IF(NP2.GE.1)   &
        CALL DPDRPM(PX2,PY2,NP2,X3D2,IJUNK2,IROWID,IROWLB,   &
                    IFIG,IPATT,IFONT,ICASE,IJUST,IDIR,ANGLE,IFILL,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    PHEIGH,PWIDTH,PVEGAP,PHOGAP,PTHICK,   &
                    IMPSW2,AMPSCH,AMPSCW,   &
                    ISYMBL,ISPAC)
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CLCH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCLCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)PXMIN,PXMAX,PYMIN,PYMAX
 9013   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4F10.5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)IMIN,IMAX,J,NP,NP2
 9017   FORMAT('IMIN,IMAX,J,NP,NP2 = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)XMIN,XMAX,YMIN,YMAX
 9018   FORMAT('XMIN,XMAX,YMIN,YMAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9022 I=1,NP
          DEL1=PX(I)-PXMIN
          DEL2=PX(I)-PXMAX
          DEL3=PY(I)-PYMIN
          DEL4=PY(I)-PYMAX
          WRITE(ICOUT,9023)I,PX(I),PY(I)
 9023     FORMAT('I,PX(I),PY(I)         = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9024)I,DEL1,DEL2,DEL3,DEL4
 9024     FORMAT('I,DEL1,DEL2,DEL3,DEL4 = ',I8,4E15.7)
          CALL DPWRST('XXX','BUG ')
 9022   CONTINUE
        IF(NP2.GT.0)THEN
          DO 9032 I=1,NP2
            WRITE(ICOUT,9033)I,PX2(I),PY2(I)
 9033       FORMAT('I,PX2(I),YP2(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9032     CONTINUE
        ENDIF
        WRITE(ICOUT,9039)IBUGG4,ISUBG4,IERRG4
 9039   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCLCH
      SUBROUTINE DPCLDE
!
!     PURPOSE--CLOSE A GRAPHICS DEVICE
!
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLDE')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCLDE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IMANUF,IMODEL,IMODE2,IMODE3
   52 FORMAT('IMANUF,IMODEL,IMODE2,IMODE3 = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IGUNIT,IGCODE
   53 FORMAT('IGUNIT,IGCODE = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ISOFT,ISOFT2,ISOFT3
   54 FORMAT('ISOFT,ISOFT2,ISOFT3 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IGBAUD
   55 FORMAT('IGBAUD = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)IBUGG4,ISUBG4,IERRG4
   56 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ******************************
!               **  STEP 1--                **
!               **  CLOSE GRAPHICS SOFTWARE **
!               ******************************
!
!CCCC CALL GRCLSO
!
!               *****************************
!               **  STEP 2--               **
!               **  CLOSE GRAPHICS DEVICES  **
!               *****************************
!
      CALL GRCLDE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLDE')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCLDE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IMANUF,IMODEL,IMODE2,IMODE3
 9012 FORMAT('IMANUF,IMODEL,IMODE2,IMODE3 = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IGUNIT,IGCODE
 9013 FORMAT('IGUNIT,IGCODE = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ISOFT,ISOFT2,ISOFT3
 9014 FORMAT('ISOFT,ISOFT2,ISOFT3 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IGBAUD
 9015 FORMAT('IGBAUD = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)IBUGG4,ISUBG4,IERRG4
 9016 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCLDE                 
      SUBROUTINE DPCLLO(IHARG,IARGT,ARG,NUMARG,   &
      CLLIMI,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LOWER BOUND OF THE LEFT-MOST CLASS
!              FOR HORIZONTAL VARIABLE OR VERTICAL VARIABLE OR BOTH
!              FOR DISTRIBUTIONAL PLOTS (E.G., HISTOGRAMS).
!              THE 2 LOWER LIMITS (ONE FOR THE X AXIS VARIABLE
!              AND ONE FOR THE Y AXIS VARIABLE)
!              ARE CONTAINED IN THE FIRST AND THIRD ELEMENTS OF THE
!              4-ELEMENT VECTOR CLLIMI(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--CLLIMI (A 4-ELEMENT FLOATING POINT VECTOR
!                              IN WHICH EACH ELEMENT IS AS FOLLOWS--
!                                 1) LOWER BOUND FOR HORIZONTAL VARIABLE
!                                 2) UPPER BOUND FOR HORIZONTAL VARIABLE
!                                    (NOT AFFECTED)
!                                 3) LOWER BOUND FOR VERTICAL   VARIABLE
!                                 4) UPPER BOUND FOR VERTICAL   VARIABLE
!                                    (NOT AFFECTED)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MAY       1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION CLLIMI(4)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE HORIZONTAL VARIABLE LOWER BOUND IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XLOW')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1110
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1120
      GO TO 1110
!
 1110 CONTINUE
      IFOUND='YES'
      CLLIMI(1)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1119
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1115)
 1115 FORMAT('THE HORIZONTAL AXIS VARIABLE LOWER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)
 1117 FORMAT('SO THAT IT WILL BE    XBAR - 6*XSD')
      CALL DPWRST('XXX','BUG ')
 1119 CONTINUE
      GO TO 1900
!
 1120 CONTINUE
      IFOUND='YES'
      CLLIMI(1)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('THE HORIZONTAL AXIS VARIABLE LOWER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)CLLIMI(1)
 1127 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1129 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE VERTICAL   VARIABLE LOWER BOUND IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YLOW')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1210
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1220
      GO TO 1210
!
 1210 CONTINUE
      IFOUND='YES'
      CLLIMI(3)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1219
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('THE VERTICAL AXIS VARIABLE LOWER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1217)
 1217 FORMAT('SO THAT IT WILL BE    YBAR - 6*YSD')
      CALL DPWRST('XXX','BUG ')
 1219 CONTINUE
      GO TO 1900
!
 1220 CONTINUE
      IFOUND='YES'
      CLLIMI(3)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1229
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)
 1225 FORMAT('THE VERTICAL AXIS VARIABLE LOWER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1226)
 1226 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1227)CLLIMI(3)
 1227 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1229 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE LOWER BOUNDS FOR BOTH VARIABLES ARE TO BE CHANGED **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XYLO')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YXLO')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'LOWE')GO TO 1300
      GO TO 1399
!
 1300 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1310
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1320
      GO TO 1310
!
 1310 CONTINUE
      IFOUND='YES'
      CLLIMI(1)=CPUMIN
      CLLIMI(3)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1315)
 1315 FORMAT('THE LOWER BOUNDS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1316)
 1316 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1317)
 1317 FORMAT('SO THAT THEY WILL BE    AVERAGE - 6*SD')
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      GO TO 1900
!
 1320 CONTINUE
      IFOUND='YES'
      CLLIMI(1)=ARG(NUMARG)
      CLLIMI(3)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1329
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1325)
 1325 FORMAT('THE LOWER BOUNDS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1326)
 1326 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1327)CLLIMI(1)
 1327 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1329 CONTINUE
      GO TO 1900
!
 1399 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPCLLO
      SUBROUTINE DPCLOS(IBUGA3,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--SUPPORTS THE FOLLOWING COMMAND:
!
!                 LET IFLAG = CLOSE <UNIT>
!                 LET IFLAG = CLOSE DELETE <UNIT>
!
!              WHERE IFLAG IS SET TO THE STATUS VALUE FROM THE CLOSE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016/06
!     ORIGINAL VERSION--JUNE      2016.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 NEWNAM
      CHARACTER*4 NEWCOL
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IEXIST
      CHARACTER*4 IFILSV
!
! ---------------------------------------------------------------------
!
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN0='CLOS'
      ISUBN1='DPCL'
      ISUBN2='OS  '
      IFOUND='YES'
      IERROR='NO'
      IEXIST='NO'
      IFILSV=IFILQU
      IFILQU='ON'
!
      IVAL=0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCLOS--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************
!               **  STEP 1--                                      **
!               **  CHECK FOR VALID COMMAND.                      **
!               ****************************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(2).NE.'=' .OR. IHARG(3).NE.'CLOS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN CLOSE COMMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      INVALID FORM FOR THE COMMAND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *********************************************************
!               **  STEP 2--                                            *
!               **  EXAMINE THE LEFT-HAND SIDE--                        *
!               **  IS THE PARAMETER NAME TO LEFT OF = SIGN             *
!               **  ALREADY IN THE NAME LIST?                           *
!               **  NOTE THAT     IHLEFT    IS THE NAME OF THE VARIABLE *
!               **  ON THE LEFT.                                        *
!               **  NOTE THAT     ILISTL    IS THE LINE IN THE TABLE    *
!               **  OF THE NAME ON THE LEFT.                            *
!               **  NOTE THAT     ICOLL    IS THE DATA COLUMN (1 TO 12) *
!               **  FOR THE NAME OF THE LEFT.                           *
!               *********************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NEWNAM='NO'
      NEWCOL='NO'
      IHLEFT=IHARG(1)
      IHLEF2=IHARG2(1)
      DO 200 I=1,NUMNAM
        I2=I
        IF(IHLEFT.EQ.IHNAME(I).AND.IHLEF2.EQ.IHNAM2(I))THEN
          IF(IUSE(I).EQ.'P')THEN
            ILISTL=I2
            GO TO 290
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,201)
  201       FORMAT('      THE NAME ON THE LEFT HAND SIDE WAS FOUND IN')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,202)
  202       FORMAT('      THE NAME TABLE, BUT NOT AS A PARAMETER.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
  200 CONTINUE
!
      ISTEPN='2B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NEWNAM='YES'
      ILISTL=NUMNAM+1
      IF(ILISTL.GT.MAXNAM)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,222)
  222   FORMAT('      THE NUMBER OF VARIABLE AND/OR PARAMETER NAMES ',   &
               'HAS JUST')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,223)MAXNAM
  223   FORMAT('      EXCEEDED THE MAX ALLOWABLE ',I8,'  .  ')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
  290 CONTINUE
!               ********************************************************
!               **  STEP 3--                                          **
!               **  EXTRACT THE UNIT NUMBER                           **
!               ********************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(4).EQ.'DELE')THEN
        IWORD=5
        IFLAG=1
      ELSE
        IWORD=4
        IFLAG=0
      ENDIF
!
      IF(IARGT(IWORD).EQ.'NUMB')THEN
        IUNIT=INT(ARG(IWORD)+0.1)
        IF(IUNIT.LT.1 .OR. IUNIT.GT.99)THEN
          IVAL=-1
        ELSE
          IF(IFLAG.EQ.1)THEN
            CLOSE(UNIT=IUNIT,STATUS='DELETE',IOSTAT=IVAL)
          ELSE
            CLOSE(UNIT=IUNIT,IOSTAT=IVAL)
          ENDIF
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
  301   FORMAT('      THE EXPECTED ARGUEMNT FOR THE UNIT NUMBER WAS ',   &
               'NOT A NUMERIC VALUE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)IHARG(IWORD),IHARG2(IWORD)
  303   FORMAT('      THE ARGUEMNT = ',A4,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **  STEP 4--                             **
!               **  UPDATE THE LHS PARAMETER             **
!               *******************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHNAME(ILISTL)=IHLEFT
      IHNAM2(ILISTL)=IHLEF2
      IUSE(ILISTL)='P'
      VALUE(ILISTL)=REAL(IVAL)
      IVALUE(ILISTL)=INT(VALUE(ILISTL)+0.5)
      IN(ILISTL)=1
      IF(NEWNAM.EQ.'YES')NUMNAM=NUMNAM+1
!
!
      IF(IPRINT.EQ.'ON' .AND. IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,601)IUNIT,IHLEFT,IHLEF2,IVALUE(ILISTL)
  601   FORMAT('UNIT ',I8,' WAS CLOSED, THE PARAMETER ',   &
                 A4,A4,' = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
!
      IFILQU=IFILSV
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CLOS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCLOS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR,IVAL
 9013   FORMAT('IFOUND,IERROR,IVAL = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCLOS
      SUBROUTINE DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
!     PURPOSE--CARRY OUT CLOSING OPERATIONS
!              SUBSEQUENT TO THE GENERATION OF A PLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 IFONT
!
      CHARACTER*4 IGRASW
      CHARACTER*4 ICOPSW
!
      CHARACTER*4 ICASE
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFONT=IMANUF
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLPL')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCLPL--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IMANUF,IMODEL,IMODE2,IMODE3
   52 FORMAT('IMANUF,IMODEL,IMODE2,IMODE3 = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IGUNIT,IGCODE
   53 FORMAT('IGUNIT,IGCODE = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ISOFT,ISOFT2,ISOFT3
   54 FORMAT('ISOFT,ISOFT2,ISOFT3 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)IGBAUD
   55 FORMAT('IGBAUD = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)IFONT
   56 FORMAT('IFONT = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)ICOPSW
   61 FORMAT('ICOPSW= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)NUMCOP
   62 FORMAT('NUMCOP= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)PGRAXF,PGRAYF
   63 FORMAT('PGRAXF,PGRAYF = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)IGRASW
   64 FORMAT('IGRASW= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,65)PDIAXC,PDIAYC,PDIAX2,PDIAY2
   65 FORMAT('PDIAXC,PDIAYC,PDIAX2,PDIAY2 = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,66)PDIAHE,PDIAWI
   66 FORMAT('PDIAHE,PDIAWI = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,67)PDIAVG,PDIAHG
   67 FORMAT('PDIAVG,PDIAHG = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)IBUGG4,ISUBG4,IERRG4
   69 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ************************
!               **  STEP 1--          **
!               **  COPY THE SCREEN,  **
!               **  IF CALLED FOR     **
!               ************************
!
      IF(ICOPSW.EQ.'OFF')GO TO 1190
      IF(NUMCOP.LE.0)GO TO 1190
      DO 1100 I=1,NUMCOP
      CALL GRCOSC
 1100 CONTINUE
 1190 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  MOVE THE BEAM TO THE BOTTOM LEFT VICINITY  **
!               **  OF THE GRAPHICS REGION.                    **
!               *************************************************
!
      CALL GRMOBE(PGRAXF,PGRAYF)
!
!               **********************************************
!               **  STEP 4--                                **
!               **  TRANSLATE THE CHARACTER REPRESENTATION  **
!               **  OF THE DIALOGUE MODE BEAM SIZE          **
!               **  INTO A NUMERIC REPRESENTATION           **
!               **  WHICH CAN BE UNDERSTOOD BY THE          **
!               **  GRAPHICS DEVICE.                        **
!               **********************************************
!
      ICASE='MARK'
!
      PHEIGH=PDIAHE
      PWIDTH=PDIAWI
      PVEGAP=PDIAVG
      PHOGAP=PDIAHG
      CALL GRTRSI(ICASE,IFONT,PHEIGH,PWIDTH,PVEGAP,PHOGAP,   &
      JSIZE,   &
      JHEIG2,JWIDT2,JVEGA2,JHOGA2,   &
      PHEIG2,PWIDT2,PVEGA2,PHOGA2)
!
!               ************************************
!               **  STEP 5--                      **
!               **  SET THE DIALOGUE MODE SIZE    **
!               **  ON THE GRAPHICS DEVICE.       **
!               ************************************
!
      CALL GRSESI(ICASE,IFONT,PHEIGH,PWIDTH,PVEGAP,PHOGAP,   &
      JSIZE,   &
      JHEIG2,JWIDT2,JVEGA2,JHOGA2,   &
      PHEIG2,PWIDT2,PVEGA2,PHOGA2)
!
!               *************************************************
!               **  STEP 6--                                   **
!               **  MOVE THE BEAM TO THE PROPER POINT          **
!               **  (USUALLY IN THE LOWER LEFT)                **
!               **  ON THE SCREEN.                             **
!               *************************************************
!
      CALL GRMOBE(PDIAX2,PDIAY2)
      PSUM=PDIAHE+PDIAVG
      PDIAY2=PDIAY2-PSUM
      IF(PDIAY2.LE.PSUM)PDIAY2=PDIAYC
      IF(PDIAY2.GE.100.0)PDIAY2=PDIAYC
!
!               ***********************************************************
!               **  STEP 11--                                            **
!               **  EXIT OUT OF GRAPHICS MODE AND                        **
!               **  AND MOVE TO DIALOGUE (= MONITOR) MODE.               **
!               **  THE DIALOGUE MODE ON VARIOUS TERMINALS               **
!               **  IS USUALLY OF 3 TYPES--                              **
!               **  1. FOR TERMINALS WITH NO FORMAL DIALOGUE REGION AND  **
!               **     NO BACKGROUND DIALOGUE PLANE                      **
!               **     (AND THUS SUCCEDING NON-GRAPHICS TEXT WILL        **
!               **     OVERWRITE THE GRAPHICS ON THE SCREEN),            **
!               **     THEN DO NOTHING.                                  **
!               **  2. FOR THOSE TERMINALS IN WHICH THE SCREEN           **
!               **     IS SHARED BETWEEN A GRAPHICS REGION AND           **
!               **     A MONITOR REGION (USUALLY AT THE BOTTOM),         **
!               **     THEN GO TO THE MONITOR REGION.                    **
!               **  3. FOR TERMINALS WITH A FULL-SCREEN BACKGROUND       **
!               **     DIALOGUE PLANE THAT THE USER CAN FLIP-FLOP TO     **
!               **     AND WHICH IS INDEPENDENT OF THE GRAPHICS PLANE,   **
!               **     THEN GO TO THE DIALOGUE PLANE.                    **
!               ***********************************************************
!
!     THE FOLLOWING WAS A SIGGRAPH PATCH FOR THE 4129 (DALLAS) AUG. 19, 1986
!CCCC IGRASW='OFF'
      IGRASW='OFF'
      CALL GRSEMO(IGRASW,PDIAXC,PDIAYC)
!
!               *********************
!               **  STEP 6--       **
!               **  REVIVE PROMPT  **
!               *********************
!
!CCCC CALL GRREPR
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLPL')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCLPL--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IMANUF,IMODEL,IMODE2,IMODE3
 9012 FORMAT('IMANUF,IMODEL,IMODE2,IMODE3 = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IGUNIT,IGCODE
 9013 FORMAT('IGUNIT,IGCODE = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ISOFT,ISOFT2,ISOFT3
 9014 FORMAT('ISOFT,ISOFT2,ISOFT3 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IGBAUD
 9015 FORMAT('IGBAUD = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)ICOPSW
 9021 FORMAT('ICOPSW= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)NUMCOP
 9022 FORMAT('NUMCOP= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)PGRAXF,PGRAYF
 9023 FORMAT('PGRAXF,PGRAYF = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9024)IGRASW
 9024 FORMAT('IGRASW= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9025)PDIAXC,PDIAYC,PDIAX2,PDIAY2
 9025 FORMAT('PDIAXC,PDIAYC,PDIAX2,PDIAY2 = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9026)PDIAHE,PDIAWI
 9026 FORMAT('PDIAHE,PDIAWI = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9027)PDIAVG,PDIAHG
 9027 FORMAT('PDIAVG,PDIAHG = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9029)IBUGG4,ISUBG4,IERRG4
 9029 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCLPL
      SUBROUTINE DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
      PXMIN,PXMAX,PYMIN,PYMAX,   &
      PXNEW,PYNEW)
!
!      PURPOSE--GIVEN THE 2 POINTS (PXOLD,PYOLD) AND (PXNEW,PYNEW)
!               (ONE OF WHICH IS DEFINITELY IN THE FRAME
!               DEFINED BY (PXMIN,PYMIN) AND (PXMAX,PYMAX)
!               AND THE OTHER OF WHICH IS OUTSIDE THAT FRAME,
!               COMPUTE THE POINT (PXNEW,PYNEW) WHICH
!               IS THAT VALUE ON THE FRAME IN WHICH THE LINE SEGMENT
!               INTERSECTS THE FRAME.
!               THIS ALLOWS THE SUBROUTINE DPCLIP
!               TO CARRY OUT CLIPPING.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCL'
      ISUBN2='P2  '
!
      PX1=PXOLD
      PY1=PYOLD
      PX2=PXCUR
      PY2=PYCUR
      PX3=PXCUR
      PY3=PYCUR
!
      SLOPE=0.0
      AINT=0.0
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLT2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCLT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)PXOLD,PYOLD
   52 FORMAT('PXOLD,PYOLD = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)PXCUR,PYCUR
   53 FORMAT('PXCUR,PYCUR = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)PXMIN,PYMIN,PXMAX,PYMAX
   54 FORMAT('PXMIN,PYMIN,PXMAX,PYMAX = ',4F10.5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4
   59 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ************************************************************
!               **  STEP 1--                                              **
!               **  EITHER (PXOLD,PYOLD) OR (PXCUR,PYCUR)                 **
!               **  MUST BE WITHIN THE FRAME.                             **
!               **  DETERMINE WHICH ONE IS.                               **
!               **  (PX1,PY1) WILL REFER TO THE POINT INSIDE  THE FRAME.  **
!               **  (PX2,PY2) WILL REFER TO THE POINT OUTSIDE THE FRAME.  **
!               ************************************************************
!
      ISTEPN='1'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(PXOLD.GE.PXMIN.AND.PXOLD.LE.PXMAX.AND.   &
         PYOLD.GE.PYMIN.AND.PYOLD.LE.PYMAX)GO TO 1110
      IF(PXCUR.GE.PXMIN.AND.PXCUR.LE.PXMAX.AND.   &
         PYCUR.GE.PYMIN.AND.PYCUR.LE.PYMAX)GO TO 1120
      GO TO 1130
!
 1110 CONTINUE
      PX1=PXOLD
      PY1=PYOLD
      PX2=PXCUR
      PY2=PYCUR
      GO TO 1190
!
 1120 CONTINUE
      PX1=PXCUR
      PY1=PYCUR
      PX2=PXOLD
      PY2=PYOLD
      GO TO 1190
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('***** INTERNAL ERROR IN DPCLT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      UPON INPUT TO THIS SUBROUTINE,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1133)
 1133 FORMAT('      AT LEAST ONE POINT MUST BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      WITHIN THE FRAME--BUT WAS NOT.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)PXMIN,PXMAX,PYMIN,PYMAX
 1135 FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)PXOLD,PYOLD,PXCUR,PYCUR
 1136 FORMAT('PXOLD,PYOLD,PXCUR,PYCUR = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!               **********************************
!               **  STEP 2--                    **
!               **  DETERMINE THE FRAME POINT.  **
!               **  THIS WILL BE (PX3,PY3).     **
!               **********************************
!
      ISTEPN='2'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(PX1.EQ.PX2)GO TO 1200
      GO TO 1250
!
!               **************************************
!               **  STEP 2.1--                      **
!               **  TREAT THE SUBCASE WHEN PX1 = PX2**
!               **************************************
!
 1200 CONTINUE
      ISTEPN='2.1'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      PX3=PX2
!
      PY3=PY2
      IF(PY2.LT.PYMIN)PY3=PYMIN
      IF(PY2.GT.PYMAX)PY3=PYMAX
!
      GO TO 1290
!
!               ***************************************************
!               **  STEP 2.2--                                   **
!               **  TREAT THE SUBCASE WHEN PX1 DOES NOT EQUAL PX2**
!               ***************************************************
!
 1250 CONTINUE
      ISTEPN='2.2'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      SLOPE=(PY2-PY1)/(PX2-PX1)
      AINT=PY2-SLOPE*PX2
!
      PX3=PX2
      IF(PX2.LT.PXMIN)PX3=PXMIN
      IF(PX2.GT.PXMAX)PX3=PXMAX
!
      PY3=SLOPE*PX3+AINT
      IF(PY3.LT.PYMIN)GO TO 1260
      IF(PY3.GT.PYMAX)GO TO 1270
      GO TO 1290
!
 1260 CONTINUE
      PY3=PYMIN
      PX3=0.0
      IF(SLOPE.NE.0.0)PX3=(PY3-AINT)/SLOPE
      GO TO 1290
!
 1270 CONTINUE
      PY3=PYMAX
      PX3=0.0
      IF(SLOPE.NE.0.0)PX3=(PY3-AINT)/SLOPE
      GO TO 1290
!
 1290 CONTINUE
      PXNEW=PX3
      PYNEW=PY3
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CLT2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCLT2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)PXOLD,PYOLD
 9012 FORMAT('PXOLD,PYOLD = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)PXCUR,PYCUR
 9013 FORMAT('PXCUR,PYCUR = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)PXMIN,PYMIN,PXMAX,PYMAX
 9014 FORMAT('PXMIN,PYMIN,PXMAX,PYMAX = ',4F10.5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)PX1,PY1
 9021 FORMAT('PX1,PY1 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)PX2,PY2
 9022 FORMAT('PX2,PY2 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)PX3,PY3
 9023 FORMAT('PX3,PY3 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9025)SLOPE,AINT
 9025 FORMAT('SLOPE,AINT = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9026)PXNEW,PYNEW
 9026 FORMAT('PXNEW,PYNEW = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9029)IBUGG4,ISUBG4,IERRG4
 9029 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCLT2
      SUBROUTINE DPCLTR(PX,PY,NP,PX2,PY2,NP2,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        ISORSW,   &
                        IFIG,IPATT,PTHICK,ICOL,ICOLR,ICOLG,ICOLB)
!
!     PURPOSE--CARRY OUT CLIPPING (IF NECESSARY) AND DRAW A TRACE (OR
!              SERIES OF CLIPPED TRACES) BASED ON THE DATA IN (PX,PY).
!     DANGER--THE INPUT VARIABLES PX(.) AND PY(.) MAY BE
!             CHANGED IN THIS SUBROUTINE (SEE STEP 0 BELOW)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --JANUARY   1989.  MODIFY CALLS TO DPDRPL (ALAN)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISORSW
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION PX(*)
      DIMENSION PY(*)
!
      DIMENSION PX2(*)
      DIMENSION PY2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCL'
      ISUBN2='PL  '
!
      XMIN=CPUMAX
      YMIN=CPUMAX
      XMAX=CPUMIN
      YMAX=CPUMIN
      J=(-999)
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CLTR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCLTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)PXMIN,PXMAX,PYMIN,PYMAX
   53   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)ISORSW,IFIG,IPATT,ICOL,PTHICK
   56   FORMAT('ISORSW,IFIG,IPATT,ICOL,PTHICK = ',4(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,58)NP,ICOLR,ICOLG,ICOLB
   58   FORMAT('NP,ICOLR,ICOLG,ICOLB = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 62 I=1,NP
          DEL1=PX(I)-PXMIN
          DEL2=PX(I)-PXMAX
          DEL3=PY(I)-PYMIN
          DEL4=PY(I)-PYMAX
          WRITE(ICOUT,63)I,PX(I),PY(I)
   63     FORMAT('I,PX(I),PY(I)         = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,64)I,DEL1,DEL2,DEL3,DEL4
   64     FORMAT('I,DEL1,DEL2,DEL3,DEL4 = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   62   CONTINUE
        WRITE(ICOUT,69)IBUGG4,ISUBG4,IERRG4
   69   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************************
!               **  STEP 0--                                                   *
!               **  IF NECESSARY,                                              *
!               **  ADJUST (= CHANGE) THE PX(.) AND PY(.) VALUES TO ALLOW FOR  *
!               **  POSSIBLE ROUNDOFF NEAR THE LIMITS (PXMIN,PXMAX)            *
!               **  AND (PYMIN,PYMAX) WHICH WOULD SHOW UP AS A DATA            *
!               **  POINT NOT BEING PLOTTED WHEN IT SHOULD HAVE BEEN           *
!               ****************************************************************
!
      CALL DPSQUE(PX,PY,NP,PXMIN,PXMAX,PYMIN,PYMAX)
!
!               *************************************************
!               **  STEP 1--                                   **
!               **  DETERMINE THE FIRST AND LAST ELEMENTS OF   **
!               **  THE (PX,PY) VECTORS WHICH MUST BE SCANNED  **
!               **  BASED ON WHETHER PX(.) IS SORTED           **
!               **  OR NOT.                                    **
!               *************************************************
!
      ISTEPN='1'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISORSW.EQ.'ON')THEN
        DO 1110 I=1,NP
          I2=I
          IF(PX(I).GE.PXMIN)THEN
            IMIN=I2
            GO TO 1119
          ENDIF
 1110   CONTINUE
        IMIN=NP+1
 1119   CONTINUE
!
        DO 1120 I=1,NP
          IREV=NP-I+1
          IF(PX(IREV).LE.PXMAX)THEN
            IMAX=IREV
            GO TO 1129
          ENDIF
 1120   CONTINUE
        IMAX=0
 1129 CONTINUE
!
      ELSE
        IMIN=1
        IMAX=NP
      ENDIF
!
      IF(IMIN.GT.IMAX)GO TO 9000
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  COMPUTE THE HORIZONTAL AXIS VARIABLE MIN AND MAX  **
!               **  FOR THE DATA WITHIN THE SUBSET                    **
!               ********************************************************
!
      ISTEPN='2'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISORSW.EQ.'ON')THEN
        XMIN=PX(IMIN)
        XMAX=PX(IMAX)
      ELSE
        XMIN=CPUMAX
        XMAX=CPUMIN
        DO 1260 I=IMIN,IMAX
          IF(PX(I).LT.XMIN)XMIN=PX(I)
          IF(PX(I).GT.XMAX)XMAX=PX(I)
 1260   CONTINUE
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  COMPUTE THE VERTICAL AXIS VARIABLE MIN AND MAX  **
!               **  FOR THE DATA WITHIN THE SUBSET                  **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      YMIN=CPUMAX
      YMAX=CPUMIN
      DO 1300 I=IMIN,IMAX
        IF(PY(I).LT.YMIN)YMIN=PY(I)
        IF(PY(I).GT.YMAX)YMAX=PY(I)
 1300 CONTINUE
!
!               *******************************************************
!               **  STEP 21--                                        **
!               **  TREAT THE MOST COMMON AND MOST IMPORTANT CASE--  **
!               **  ALL NP OBSERVATIONS ARE TO BE USED;              **
!               **  ALL X DATA ARE WITHIN THE FRAME;                 **
!               **  ALL Y DATA ARE WITHIN THE FRAME.                 **
!               *******************************************************
!
      IF(IMIN.EQ.1.AND.IMAX.EQ.NP.AND.   &
      XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX.AND.   &
      YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
!
        ISTEPN='21'
        IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IFLAG='ON'
        CALL DPDRPL(PX,PY,NP,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
        GO TO 9000
      ENDIF
!
!               ************************************************************
!               **  STEP 22--                                             **
!               **  TREAT THE NEXT MOST COMMON AND MOST IMPORTANT CASE--  **
!               **  A SUBSET OF THE NP OBSERVATIONS ARE TO BE USED;       **
!               **  ALL X DATA ARE WITHIN THE FRAME;                      **
!               **  ALL Y DATA ARE WITHIN THE FRAME.                      **
!               ************************************************************
!
      IF(XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX.AND.   &
      YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
!
        ISTEPN='22'
        IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        DO 2210 I=IMIN,IMAX
          J=J+1
          PX2(J)=PX(I)
          PY2(J)=PY(I)
 2210   CONTINUE
        NP2=J
        IFLAG='ON'
        CALL DPDRPL(PX2,PY2,NP2,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
         GO TO 9000
       ENDIF
!
!               ****************************************************
!               **  STEP 23--                                     **
!               **  TREAT THE CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  ALL X'S ARE INSIDE THE FRAME,                 **
!               **  BUT SOME Y'S ARE OUTSIDE THE FRAME.           **
!               ****************************************************
!
      IF(XMIN.GE.PXMIN.AND.XMAX.LE.PXMAX)THEN
!
        ISTEPN='23'
        IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        J=0
        DO 2310 I=IMIN,IMAX
          IM1=I-1
          IF(PY(I).GE.PYMIN.AND.PY(I).LE.PYMAX)GO TO 2320
          GO TO 2330
!
 2320     CONTINUE
          IF(IM1.LT.IMIN)GO TO 2325
          PXOLD=PX(IM1)
          PYOLD=PY(IM1)
          PXCUR=PX(I)
          PYCUR=PY(I)
          IF(PYOLD.GE.PYMIN.AND.PYOLD.LE.PYMAX)GO TO 2325
          CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                      PXMIN,PXMAX,PYMIN,PYMAX,   &
                      PXNEW,PYNEW)
          J=J+1
          PX2(J)=PXNEW
          PY2(J)=PYNEW
!
 2325    CONTINUE
         J=J+1
         PX2(J)=PX(I)
         PY2(J)=PY(I)
         GO TO 2310
!
 2330   CONTINUE
        IF(IM1.LT.IMIN)GO TO 2335
        PXOLD=PX(IM1)
        PYOLD=PY(IM1)
        PXCUR=PX(I)
        PYCUR=PY(I)
        IF(PYOLD.GE.PYMIN.AND.PYOLD.LE.PYMAX)GO TO 2333
        GO TO 2335
!
 2333   CONTINUE
        CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                    PXMIN,PXMAX,PYMIN,PYMAX,   &
                    PXNEW,PYNEW)
        J=J+1
        PX2(J)=PXNEW
        PY2(J)=PYNEW
        NP2=J
        IFLAG='ON'
        CALL DPDRPL(PX2,PY2,NP2,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
 2335   CONTINUE
        J=0
        GO TO 2310
!
 2310   CONTINUE
        NP2=J
        IFLAG='ON'
        IF(NP2.GE.1)   &
           CALL DPDRPL(PX2,PY2,NP2,   &
                       IFIG,IPATT,PTHICK,   &
                       ICOL,ICOLR,ICOLG,ICOLB,   &
                       JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
        GO TO 9000
!
      ENDIF
!
!               ****************************************************
!               **  STEP 24--                                     **
!               **  TREAT THE CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  ALL Y'S ARE INSIDE THE FRAME,                 **
!               **  BUT SOME X'S ARE OUTSIDE THE FRAME            **
!               **  (AS IN THE CONSTRUCTION OF MAPS)              **
!               ****************************************************
!
      IF(YMIN.GE.PYMIN.AND.YMAX.LE.PYMAX)THEN
!
        ISTEPN='24'
        IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        DO 2410 I=IMIN,IMAX
          IM1=I-1
          IF(PX(I).GE.PXMIN.AND.PX(I).LE.PXMAX)GO TO 2420
          GO TO 2430
!
 2420     CONTINUE
          IF(IM1.LT.IMIN)GO TO 2425
          PXOLD=PX(IM1)
          PYOLD=PY(IM1)
          PXCUR=PX(I)
          PYCUR=PY(I)
          IF(PXOLD.GE.PXMIN.AND.PXOLD.LE.PXMAX)GO TO 2425
          CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                      PXMIN,PXMAX,PYMIN,PYMAX,   &
                      PXNEW,PYNEW)
          J=J+1
          PX2(J)=PXNEW
          PY2(J)=PYNEW
 2425     CONTINUE
          J=J+1
          PX2(J)=PX(I)
          PY2(J)=PY(I)
          GO TO 2410
!
 2430     CONTINUE
          IF(IM1.LT.IMIN)GO TO 2435
          PXOLD=PX(IM1)
          PYOLD=PY(IM1)
          PXCUR=PX(I)
          PYCUR=PY(I)
          IF(PXOLD.GE.PXMIN.AND.PXOLD.LE.PXMAX)GO TO 2433
          GO TO 2435
 2433     CONTINUE
          CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                      PXMIN,PXMAX,PYMIN,PYMAX,   &
                      PXNEW,PYNEW)
          J=J+1
          PX2(J)=PXNEW
          PY2(J)=PYNEW
          NP2=J
          IFLAG='ON'
          CALL DPDRPL(PX2,PY2,NP2,   &
                      IFIG,IPATT,PTHICK,   &
                      ICOL,ICOLR,ICOLG,ICOLB,   &
                      JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
 2435     CONTINUE
          J=0
          GO TO 2410
!
 2410   CONTINUE
        NP2=J
        IFLAG='ON'
        IF(NP2.GE.1)   &
           CALL DPDRPL(PX2,PY2,NP2,   &
                       IFIG,IPATT,PTHICK,   &
                       ICOL,ICOLR,ICOLG,ICOLB,   &
                       JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
        GO TO 9000
!
      ENDIF
!
!               ************************************************************
!               **  STEP 25--                                             **
!               **  TREAT THE GENERAL CASE WHERE THE SUBSET IS SUCH THAT  **
!               **  SOME  X'S MAY BE OUTSIDE THE FRAME, AND/OR            **
!               **  SOME  Y'S MAY BE OUTSIDE THE FRAME                   **
!               **  (AS IN THE CONSTRUCTION OF MAPS)                     **
!               ***********************************************************
!
      ISTEPN='25'
      IF(IBUGG4.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      J=0
      DO 2510 I=IMIN,IMAX
        IM1=I-1
        IF(PX(I).GE.PXMIN.AND.PX(I).LE.PXMAX.AND.   &
           PY(I).GE.PYMIN.AND.PY(I).LE.PYMAX)GO TO 2520
        GO TO 2530
!
 2520   CONTINUE
        IF(IM1.LT.IMIN)GO TO 2525
        PXOLD=PX(IM1)
        PYOLD=PY(IM1)
        PXCUR=PX(I)
        PYCUR=PY(I)
        IF(PXOLD.GE.PXMIN.AND.PXOLD.LE.PXMAX.AND.   &
           PYOLD.GE.PYMIN.AND.PYOLD.LE.PYMAX)GO TO 2525
        CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                    PXMIN,PXMAX,PYMIN,PYMAX,   &
                    PXNEW,PYNEW)
        J=J+1
        PX2(J)=PXNEW
        PY2(J)=PYNEW
 2525   CONTINUE
        J=J+1
        PX2(J)=PX(I)
        PY2(J)=PY(I)
        GO TO 2510
!
 2530   CONTINUE
        IF(IM1.LT.IMIN)GO TO 2535
        PXOLD=PX(IM1)
        PYOLD=PY(IM1)
        PXCUR=PX(I)
        PYCUR=PY(I)
        IF(PXOLD.GE.PXMIN.AND.PXOLD.LE.PXMAX.AND.   &
           PYOLD.GE.PYMIN.AND.PYOLD.LE.PYMAX)GO TO 2533
        GO TO 2535
 2533   CONTINUE
        CALL DPCLT2(PXOLD,PYOLD,PXCUR,PYCUR,   &
                    PXMIN,PXMAX,PYMIN,PYMAX,   &
                    PXNEW,PYNEW)
        J=J+1
        PX2(J)=PXNEW
        PY2(J)=PYNEW
        NP2=J
        IFLAG='ON'
        CALL DPDRPL(PX2,PY2,NP2,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
 2535   CONTINUE
        J=0
        GO TO 2510
!
 2510 CONTINUE
      NP2=J
      IFLAG='ON'
      IF(NP2.GE.1)   &
         CALL DPDRPL(PX2,PY2,NP2,   &
                     IFIG,IPATT,PTHICK,   &
                     ICOL,ICOLR,ICOLG,ICOLB,   &
                     JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CLTR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCLTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)PXMIN,PXMAX,PYMIN,PYMAX
 9013   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)IMIN,IMAX,J,NP,NP2
 9017   FORMAT('IMIN,IMAX,J,NP,NP2 = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)XMIN,XMAX,YMIN,YMAX
 9018   FORMAT('XMIN,XMAX,YMIN,YMAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9022 I=1,NP
          DEL1=PX(I)-PXMIN
          DEL2=PX(I)-PXMAX
          DEL3=PY(I)-PYMIN
          DEL4=PY(I)-PYMAX
          WRITE(ICOUT,9023)I,PX(I),PY(I)
 9023     FORMAT('I,PX(I),PY(I)         = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,9024)I,DEL1,DEL2,DEL3,DEL4
 9024     FORMAT('I,DEL1,DEL2,DEL3,DEL4 = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9022   CONTINUE
        DO 9032 I=1,NP
          WRITE(ICOUT,9033)I,PX2(I),PY2(I)
 9033     FORMAT('I,PX2(I),YP2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9032   CONTINUE
        WRITE(ICOUT,9039)IERRG4
 9039   FORMAT('IERRG4 = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCLTR
      SUBROUTINE DPCLUP(IHARG,IARGT,ARG,NUMARG,   &
      CLLIMI,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE UPPER BOUND OF THE LEFT-MOST CLASS
!              FOR HORIZONTAL VARIABLE OR VERTICAL VARIABLE OR BOTH
!              FOR DISTRIBUTIONAL PLOTS (E.G., HISTOGRAMS).
!              THE 2 UPPER LIMITS (ONE FOR THE X AXIS VARIABLE
!              AND ONE FOR THE Y AXIS VARIABLE)
!              ARE CONTAINED IN THE SECOND AND FOURTH ELEMENTS OF THE
!              4-ELEMENT VECTOR CLLIMI(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--CLLIMI (A 4-ELEMENT FLOATING POINT VECTOR
!                              IN WHICH EACH ELEMENT IS AS FOLLOWS--
!                                 1) LOWER BOUND FOR HORIZONTAL VARIABLE
!                                    (NOT AFFECTED)
!                                 2) UPPER BOUND FOR HORIZONTAL VARIABLE
!                                 3) LOWER BOUND FOR VERTICAL   VARIABLE
!                                    (NOT AFFECTED)
!                                 4) UPPER BOUND FOR VERTICAL   VARIABLE
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MAY       1981.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION CLLIMI(4)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE HORIZONTAL VARIABLE UPPER BOUND IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XUPP')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1110
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1120
      GO TO 1110
!
 1110 CONTINUE
      IFOUND='YES'
      CLLIMI(2)=CPUMAX
!
      IF(IFEEDB.EQ.'OFF')GO TO 1119
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1115)
 1115 FORMAT('THE HORIZONTAL AXIS VARIABLE UPPER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)
 1117 FORMAT('SO THAT IT WILL BE    XBAR + 6*XSD')
      CALL DPWRST('XXX','BUG ')
 1119 CONTINUE
      GO TO 1900
!
 1120 CONTINUE
      IFOUND='YES'
      CLLIMI(2)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('THE HORIZONTAL AXIS VARIABLE UPPER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)CLLIMI(1)
 1127 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1129 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE VERTICAL   VARIABLE UPPER BOUND IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YUPP')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1210
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1220
      GO TO 1210
!
 1210 CONTINUE
      IFOUND='YES'
      CLLIMI(4)=CPUMAX
!
      IF(IFEEDB.EQ.'OFF')GO TO 1219
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('THE VERTICAL AXIS VARIABLE UPPER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1217)
 1217 FORMAT('SO THAT IT WILL BE    YBAR + 6*YSD')
      CALL DPWRST('XXX','BUG ')
 1219 CONTINUE
      GO TO 1900
!
 1220 CONTINUE
      IFOUND='YES'
      CLLIMI(4)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1229
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)
 1225 FORMAT('THE VERTICAL AXIS VARIABLE UPPER BOUND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1226)
 1226 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1227)CLLIMI(4)
 1227 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1229 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE UPPER BOUNDS FOR BOTH VARIABLES ARE TO BE CHANGED **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XYUP')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YXUP')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'UPPE')GO TO 1300
      GO TO 1399
!
 1300 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1310
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1320
      GO TO 1310
!
 1310 CONTINUE
      IFOUND='YES'
      CLLIMI(2)=CPUMAX
      CLLIMI(4)=CPUMAX
!
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1315)
 1315 FORMAT('THE UPPER BOUNDS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1316)
 1316 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1317)
 1317 FORMAT('SO THAT THEY WILL BE    AVERAGE + 6*SD')
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      GO TO 1900
!
 1320 CONTINUE
      IFOUND='YES'
      CLLIMI(2)=ARG(NUMARG)
      CLLIMI(4)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1329
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1325)
 1325 FORMAT('THE UPPER BOUNDS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1326)
 1326 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1327)CLLIMI(2)
 1327 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1329 CONTINUE
      GO TO 1900
!
 1399 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPCLUP
      SUBROUTINE DPCLWI(IHARG,IARGT,ARG,NUMARG,   &
      CLWIDT,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE CLASS WIDTH
!              FOR HORIZONTAL VARIABLE OR VERTICAL VARIABLE OR BOTH
!              FOR DISTRIBUTIONAL PLOTS (E.G., HISTOGRAMS).
!              THE 2 CLASS WIDTHS (ONE FOR THE X AXIS VARIABLE
!              AND ONE FOR THE Y AXIS VARIABLE)
!              ARE CONTAINED IN THE FIRST AND SECOND ELEMENTS OF THE
!              2-ELEMENT VECTOR CLWIDT(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--CLWIDT (A 2-ELEMENT FLOATING POINT VECTOR
!                              IN WHICH EACH ELEMENT IS AS FOLLOWS--
!                                 1) CLASS WIDTH FOR HORIZONTAL VARIABLE
!                                 2) CLASS WIDTH FOR VERTICAL VARIABLE
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MAY       1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION CLWIDT(2)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE HORIZONTAL VARIABLE CLASS WIDTH IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XWID')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1110
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1120
      GO TO 1110
!
 1110 CONTINUE
      IFOUND='YES'
      CLWIDT(1)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1119
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1115)
 1115 FORMAT('THE HORIZONTAL AXIS VARIABLE CLASS WIDTH ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)
 1117 FORMAT('SO THAT IT WILL BE    0.3*XSD')
      CALL DPWRST('XXX','BUG ')
 1119 CONTINUE
      GO TO 1900
!
 1120 CONTINUE
      IFOUND='YES'
      CLWIDT(1)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('THE HORIZONTAL AXIS VARIABLE CLASS WIDTH ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)CLWIDT(1)
 1127 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1129 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE VERTICAL   VARIABLE CLASS WIDTH IS TO BE CHANGED  **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YWID')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1210
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1220
      GO TO 1210
!
 1210 CONTINUE
      IFOUND='YES'
      CLWIDT(2)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1219
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('THE VERTICAL AXIS VARIABLE CLASS WIDTH ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1217)
 1217 FORMAT('SO THAT IT WILL BE    0.3*YSD')
      CALL DPWRST('XXX','BUG ')
 1219 CONTINUE
      GO TO 1900
!
 1220 CONTINUE
      IFOUND='YES'
      CLWIDT(2)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1229
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)
 1225 FORMAT('THE VERTICAL AXIS VARIABLE CLASS WIDTH ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1226)
 1226 FORMAT('(FOR DISTRIBUTIONAL PLOTS) HAS JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1227)CLWIDT(2)
 1227 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1229 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
!               ************************************************************
!               **  TREAT THE CASE WHEN                                   **
!               **  THE CLASS WIDTHS FOR BOTH VARIABLES ARE TO BE CHANGED **
!               ************************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'XYWI')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'YXWI')GO TO 1300
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'WIDT')GO TO 1300
      GO TO 1399
!
 1300 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1310
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1320
      GO TO 1310
!
 1310 CONTINUE
      IFOUND='YES'
      CLWIDT(1)=CPUMIN
      CLWIDT(2)=CPUMIN
!
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1315)
 1315 FORMAT('THE CLASS WIDTHS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1316)
 1316 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1317)
 1317 FORMAT('SO THAT THEY WILL BE    0.3*SD')
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      GO TO 1900
!
 1320 CONTINUE
      IFOUND='YES'
      CLWIDT(1)=ARG(NUMARG)
      CLWIDT(2)=ARG(NUMARG)
!
      IF(IFEEDB.EQ.'OFF')GO TO 1329
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1325)
 1325 FORMAT('THE CLASS WIDTHS (FOR DISTRIBUTIONAL PLOTS) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1326)
 1326 FORMAT('FOR BOTH VARIABLES HAVE JUST BEEN SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1327)CLWIDT(1)
 1327 FORMAT('TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1329 CONTINUE
      GO TO 1900
!
 1399 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPCLWI
      SUBROUTINE DPCMGP(Y,N,   &
                        GAMMA,A,GAMMSD,THRESH,   &
                        TEMP1,TEMP2,TEMP3,ITEMP1,   &
                        ALIKE,AIC,AICC,BIC,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE CME
!              ESTIMATES FOR THE GENERALIZED PARETO DISTRIBUTION.
!              THIS IS USED IN EXTREME VALUE APPLICATIONS.
!     EXAMPLE--CME Y
!     REFERENCE: GROSS, HECKERT, LECHNER, AND SIMIU (1995).  "EXTREME
!                WIND ESTIMATES BY THE CONDITIONAL MEAN EXCEEDANCE
!                PROCEDURE", NISTIT 5531.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!     UPDATED         --JUNE      2004. SUPPORT FOR IGEPDF
!     UPDATED         --APRIL     2005. A NUMBER OF ENHANCEMENTS
!     UPDATED         --OCTOBER   2010. SLIGHT TWEAK TO ALGORITHM
!                                       IN REGARD TO THE THRESHOLD
!     UPDATED         --OCTOBER   2010. CALL GEPLI1 TO OBTAIN
!                                       LIKELIHOOD, AIC VALUES
!     UPDATED         --OCTOBER   2010. USE DPDTA1 TO PRINT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
      CHARACTER*8 ISIGN1
      CHARACTER*8 ISIGN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION ITEMP1(*)
!
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      EXTERNAL DGAMMA
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFIRST
      LOGICAL ILAST
!
      CHARACTER*40 IDIST
!
      DIMENSION QP(1)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI / 3.1415926535/
      DATA MINSIZ /5/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCM'
      ISUBN2='GP  '
      IERROR='NO'
!
      GAMMA=CPUMIN
      GAMMSD=CPUMIN
      A=CPUMIN
      SCALE=-99.0
      GAMMA2=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CMGP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCMGP--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)IBUGA3,ISUBRO,MAXNXT
   53   FORMAT('IBUGA3,ISUBRO,MAXNXT = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,MINSIZ,PPOTTO,THRESH
   55   FORMAT('N,MINSIZ,PPOTTO,THRESH = ',2I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
       ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CMGP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NPERC=0
      NTEMP=MINSIZ-1
      CALL CKDIST(Y,N,NTEMP,QP,NPERC,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IDIST='GENERALIZED PARETO (CME)'
      IFLAG=0
!
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR CME    ESTIMATE                   **
!               **  SORT THE DATA                         **
!               **  AND IDENTIFY POINTS ABOVE THE THRESHOLD*
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CMGP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE 10/2010: DEFINE THRESHOLD AS MINIMUM VALUE, NOT
!     MINIMUM MINUS EPSILON.
!
      CALL SORT(Y,N,Y)
      EPS=0.0001
!CCCC IF(THRESH.LE.0.0)THRESH=Y(1)-EPS
      IF(THRESH.LE.0.0)THRESH=Y(1)
      DO 2110 I=1,N
        IF(Y(I).GT.THRESH)THEN
          IFRST=I
          GO TO 2119
        ENDIF
 2110 CONTINUE
      IFRST=N+1
 2119 CONTINUE
!
      NUSE=N-IFRST+1
      IF(NUSE.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('****** ERROR IN GENERALIZED PARETO CME ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2121)
 2121   FORMAT('      NO POINTS ARE ABOVE THE THRESHOLD.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2123)THRESH
 2123   FORMAT('      THRESHOLD          = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2125)Y(N)
 2125   FORMAT('      MAXIMUM DATA POINT = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(Y(IFRST).LT.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('      NEGATIVE VALUES ENCOUNTERED IN THE INPUT DATA.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL CMESUB(Y(IFRST),NUSE,THRESH,SLOPE,R1,   &
                  TEMP1,TEMP2,TEMP3,ITEMP1,GAMMSD)
      IF(SLOPE.EQ.CPUMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2141)
 2141   FORMAT('      UNABLE TO COMPUTE CME ESTIMATES.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      GAMMA=SLOPE/(1.0+SLOPE)
      A=R1*(1.0-GAMMA)
!
      IWRITE='OFF'
      CALL MEAN(Y(IFRST),NUSE,IWRITE,ZMEAN,IBUGA3,IERROR)
      CALL VAR(Y(IFRST),NUSE,IWRITE,ZVAR,IBUGA3,IERROR)
      ZSD=SQRT(ZVAR)
      IF(ABS(GAMMA).LE.PPOTTO)THEN
        SCALE=ZSD*SQRT(6.0)/PI
        ALOC=ZMEAN - 0.57722*SCALE
      ELSEIF(GAMMA.LT.0.0)THEN
        GAMMA2=-1.0/GAMMA
        DA=DGAMMA(DBLE((GAMMA2+1.0)/GAMMA2))
        DB=DGAMMA(DBLE((GAMMA2+2.0)/GAMMA2)) - DA*DA
        IF(DB.GT.0.0D0)THEN
          SCALE=ZSD/REAL(DSQRT(DB))
          ALOC=ZMEAN + SCALE*REAL(DA)
        ELSE
          SCALE=0.0
          ALOC=0.0
        ENDIF
      ELSE
      ENDIF
!
!  DEPENDING ON WHAT DEFINITION OF GENERALIZED PARETO PREFERRED,
!  REVERSE SIGN OF GAMMA.
!
      IF(IGEPDF.EQ.'SIMI')THEN
        GAMMSV=GAMMA
        ISIGN1='negative'
        ISIGN2='positive'
      ELSE
        GAMMSV=-GAMMA
        ISIGN1='positive'
        ISIGN2='negative'
      ENDIF
!
!     NOTE THAT LIKELIHOOD IS NOT ALWAYS DEFINED (CAN GET LOG OF
!     NEGATIVE NUMBER).  SO PRINTING IS CONDITIONAL ON THESE VALUES
!     ACTUALLY BEING COMPUTED.
!
      ALIKE=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
      MINMXZ=2
      CALL GEPLI1(Y(IFRST),NUSE,MINMXZ,IGEPDF,   &
                  ALOC,A,GAMMSV,   &
                  ALIKE,AIC,AICC,BIC,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *********************************
!               **   STEP 42--                 **
!               **   WRITE OUT EVERYTHING      **
!               **   FOR CME         ESTIMATE  **
!               *********************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CMGP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Generalized Pareto Parameter Estimation (CME)'
      NCTITL=45
      ITITLZ='(Maximum Case)'
      NCTITZ=14
      ICNT=1
      ITEXT(ICNT)='Summary Statistics (Full Data Set):'
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=XMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=XSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Minimum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMIN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Maximum:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=XMAX
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Observations Above Threshold:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Threshold:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=THRESH
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations Above Threshold:'
      NCTEXT(ICNT)=39
      AVALUE(ICNT)=REAL(NUSE)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=ZMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=ZSD
      IDIGIT(ICNT)=NUMDIG
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='CME Parameter Estimates:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Location Parameter:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=THRESH
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Scale Parameter:'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=A
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Shape Parameter (Gamma):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=GAMMSV
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Deviation of Gamma:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=GAMMSD
      IDIGIT(ICNT)=NUMDIG
      IF(ALIKE.NE.CPUMIN)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Log-likelihood:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=ALIKE
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='AIC:'
        NCTEXT(ICNT)=4
        AVALUE(ICNT)=AIC
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='AICc:'
        NCTEXT(ICNT)=5
        AVALUE(ICNT)=AICC
        IDIGIT(ICNT)=-7
        ICNT=ICNT+1
        ITEXT(ICNT)='BIC:'
        NCTEXT(ICNT)=4
        AVALUE(ICNT)=BIC
        IDIGIT(ICNT)=-7
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(GAMMA.LT.-PPOTTO)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)(1:4)='For '
        WRITE(ITEXT(ICNT)(5:12),'(A8)')ISIGN1
        ITEXT(ICNT)(13:42)=' Gamma, the generalized Pareto'
        NCTEXT(ICNT)=42
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:34)='is equivalent to a reverse Weibull'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:22)='(SET MINMAX MAX) with:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Shape Parameter (Gamma):'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=GAMMA2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Location Parameter:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=ALOC
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Scale Parameter:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=SCALE
        IDIGIT(ICNT)=NUMDIG
      ELSEIF(ABS(GAMMA).LE.PPOTTO)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)(1:40)='For Gamma = zero, the generalized Pareto'
        NCTEXT(ICNT)=40
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:40)='is equivalent to an extreme value type I'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:14)='(Gumbel) with:'
        NCTEXT(ICNT)=14
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Location Parameter:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=ALOC
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Scale Parameter:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=SCALE
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)(1:4)='For '
        WRITE(ITEXT(ICNT)(5:12),'(A8)')ISIGN2
        ITEXT(ICNT)(13:42)=' Gamma, the generalized Pareto'
        NCTEXT(ICNT)=42
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:28)='is equivalent to a (maximum)'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)(1:31)='extreme value type II (Frechet)'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Shape Parameter (Gamma):'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=GAMMA2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Location Parameter:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=ALOC
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Scale Parameter:'
        NCTEXT(ICNT)=16
        AVALUE(ICNT)=SCALE
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 2320 I=1,NUMROW
        NTOT(I)=15
 2320 CONTINUE
!
      IFIRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFIRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(ICAPSW.EQ.'OFF' .AND. ICAPTY.EQ.'TEXT')THEN
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4941)
 4941   FORMAT('GAMMA, SDGAMMA, AND A WILL BE SAVED AS INTERNAL ',   &
               'PARAMETERS.')
        CALL DPWRST('XXX','BUG ')
        IF(GAMMA.LT.-PPOTTO)THEN
          WRITE(ICOUT,4951)
 4951     FORMAT('THE REVERSE WEIBULL PARAMETERS WILL BE SAVED AS')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4953)
 4953     FORMAT('THE INTERNAL PARAMETERS GAMMA2, LOC, AND SCALE, ',   &
                 ' RESPECTIVELY.')
          CALL DPWRST('XXX','WRIT')
        ELSEIF(ABS(GAMMA).LT.PPOTTO)THEN
          WRITE(ICOUT,4961)
 4961     FORMAT('THE GUMBEL PARAMETERS WILL BE SAVED AS THE ',   &
                 'INTERNAL PARAMETERS LOC AND SCALE, RESPECTIVELY.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      ENDIF
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CMGP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCMGP--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCMGP
      SUBROUTINE DPCME(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                       IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE ONE OF THE FOLLOWING 4
!              CONDITIONAL EXCEEDANCE PLOTS--
!                 CONDITIONAL EXCEEDANCE PLOT Y
!                 CONDITIONAL MEAN EXCEEDANCE PLOT Y (= CME PLOT Y)
!                 CONDITIONAL MEDIAN EXCEEDANCE PLOT Y
!                 CONDITIONAL MIDMEAN EXCEEDANCE PLOT Y
!     NOTE--THERE ARE MANY SYNONYMS FOR THE CME PLOT--
!              YANG PLOT
!              MEAN RESIDUAL LIFE PLOT
!              LIFE EXPECTANCY PLOT
!              MEAN LIFE EXPECTANCY PLOT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER  1993.
!     UPDATED         --DECEMBER  1993. LINFIT ARGS: PROTECT RESSD/DF
!     UPDATED         --JANUARY   2012. USE DPPARS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),XTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB4),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB5),XTEMP4(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPCM'
      ISUBN2='E   '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               **************************************************
!               **  TREAT THE COND. ... EXCEEDANCE    PLOT CASE **
!               **************************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCME--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2,MAXCOL
   52   FORMAT('ICASPL,IAND1,IAND2,MAXCOL = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASPL='CME'
!
      IF(ICOM.EQ.'CME')THEN
         IF(NUMARG.GE.1)THEN
            IF(IHARG(1).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=1
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'COND')THEN
         IF(NUMARG.GE.2)THEN
            IF(IHARG(1).EQ.'EXCE'.AND.IHARG(2).EQ.'PLOT')THEN
               ICASPL='SCAT'
               ILASTC=2
               GO TO 111
            ENDIF
         ENDIF
!
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'SCAT'.AND.IHARG(2).EQ.'EXCE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='SCAT'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'MEAN'.AND.IHARG(2).EQ.'EXCE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'MEDI'.AND.IHARG(2).EQ.'EXCE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='MEDI'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'MIDM'.AND.IHARG(2).EQ.'EXCE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='MIDM'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'YANG')THEN
         IF(NUMARG.GE.1)THEN
            IF(IHARG(1).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=1
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'LIFE')THEN
         IF(NUMARG.GE.2)THEN
            IF(IHARG(1).EQ.'EXPE'.AND.IHARG(2).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=2
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'MEAN')THEN
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'LIFE'.AND.IHARG(2).EQ.'EXPE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      IF(ICOM.EQ.'MEAN')THEN
         IF(NUMARG.GE.3)THEN
            IF(IHARG(1).EQ.'RESI'.AND.IHARG(2).EQ.'LIFE'.AND.   &
            IHARG(3).EQ.'PLOT')THEN
               ICASPL='MEAN'
               ILASTC=3
               GO TO 111
            ENDIF
         ENDIF
      ENDIF
!
      GO TO 9000
!
  111 CONTINUE
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CME PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=1
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *****************************************************
!               **  STEP 9--                                       **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!               **  RESET THE VECTOR D(.) TO ALL ONES.             **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!               *****************************************************
!
      ISTEPN='9'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y1,Y1,NLOCAL,NLOCAL,NLOCAL,ICASE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CALL DPCME2(Y1,NLOCAL,ICASPL,XTEMP1,XTEMP2,   &
                  XTEMP3,XTEMP4,   &
                  Y,X,D,NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               ****************************************
!               **  STEP 10--                         **
!               **  COMPUTE SLOPE ESTIMATES OF THE    **
!               **  RESULTING TRACE                   **
!               ****************************************
!
      IWRITE='OFF'
      ISUBN0='DPPP'
      CALL LINFIT(Y,X,NPLOTP,   &
      ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,CCALBE,   &
      ISUBRO,IBUGG3,IERROR)
!
      IH='CMEC'
      IH2='C   '
      VALUE0=CCXY
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='CMEA'
      IH2='0   '
      VALUE0=ALPHA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='CMEA'
      IH2='1   '
      VALUE0=BETA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SDCM'
      IH2='EA0 '
      VALUE0=SDALPH
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SDCM'
      IH2='EA1 '
      VALUE0=SDBETA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='CMER'
      IH2='ESSD'
      VALUE0=XRESSD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='CMER'
      IH2='ESDF'
      VALUE0=XRESDF
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CME')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCME--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GT.0)THEN
          DO 9020 I=1,NPLOTP
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCME
      SUBROUTINE DPCME2(Y,N,ICASPL,XTEMP1,XTEMP2,   &
                        Z,ZITEMS,   &
                        Y2,X2,D2,N2,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE ONE OF THE FOLLOWING 4
!              CONDITIONAL EXCEEDANCE PLOTS--
!                 CONDITIONAL EXCEEDANCE PLOT Y
!                 CONDITIONAL MEAN EXCEEDANCE PLOT Y (= CME PLOT Y)
!                 CONDITIONAL MEDIAN EXCEEDANCE PLOT Y
!                 CONDITIONAL MIDMEAN EXCEEDANCE PLOT Y
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER   1993.
!     UPDATED         --FEBRUARY   1994. HANDLE TIES CORRECTLY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
!CCCC FEBRUARY 1994.  ADD FOLLOWING 2 LINES
      DIMENSION Z(*)
      DIMENSION ZITEMS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCM'
      ISUBN2='E2  '
      IERROR='NO'
!
      J=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CME2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPCME2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,N,NPLOTV
   72   FORMAT('ICASPL,N,NPLOTV = ',A4,2X,I8,I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GT.0)THEN
          DO 85 I=1,N
            WRITE(ICOUT,86)I,Y(I)
   86       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   85     CONTINUE
        ENDIF
      ENDIF
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN CME PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)N
  114   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!CCCC FOLLOWING ALGORITHM UPDATED TO HANDLE TIES CORRECTLY.
!CCCC FIRST,, DETERMINE IF TIES EXIST AND BRANCH TO DISTINCT SECTION
!CCCC IF THEY DO.  FEBRUARY 1994.
!
!               ****************************************
!               **  STEP 1A--                         **
!               **  DETERMINE IF TIES EXIST.          **
!               ****************************************
!
      DO 99 I=1,N
      ZITEMS(I)=0.0
 99   CONTINUE
      NZ=0
      DO 100 I=1,N
        IF(I.EQ.1)GO TO 130
        DO 120 J=1,NZ
          IF(Y(I).EQ.Z(J))THEN
            ZITEMS(J)=ZITEMS(J)+1.0
            GO TO 100
          ENDIF
 120   CONTINUE
 130   CONTINUE
       NZ=NZ+1
       Z(NZ)=Y(I)
       ZITEMS(J)=1.0
 100  CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CME2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)
  171   FORMAT('***** AFTER CHECKING FOR TIES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)N,NZ
  172   FORMAT('N,NZ = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NZ.GT.0)THEN
          DO 185 I=1,NZ
            WRITE(ICOUT,186)I,Z(I)
  186       FORMAT('I,Z(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
      IF(NZ.LT.N)GO TO 2000
!
!               ****************************************
!               **  CASE WITH NO TIES                 **
!               ****************************************
!
!               ****************************************
!               **  STEP 1--                          **
!               **  DETERMINE PLOT COORDINATES        **
!               ****************************************
!
      CALL SORT(Y,N,Y)
!
      IWRITE='OFF'
      J=0
      NM1=N-1
      DO 1100 I=1,NM1
         Y0=Y(I)
         IP1=I+1
!
         NTEMP1=0
         DO 1200 K=IP1,N
            NTEMP1=NTEMP1+1
            XTEMP1(NTEMP1)=Y(K)-Y0
 1200    CONTINUE
!
         IF(ICASPL.EQ.'SCAT')THEN
            DO 1210 L=1,NTEMP1
               J=J+1
               Y2(J)=XTEMP1(L)
               X2(J)=Y0
               D2(J)=I
 1210    CONTINUE
!
         ELSEIF(ICASPL.EQ.'MEAN')THEN
            CALL MEAN(XTEMP1,NTEMP1,IWRITE,XMEAN,IBUGG3,IERROR)
            J=J+1
            Y2(J)=XMEAN
            X2(J)=Y0
            D2(J)=1.0
!
         ELSEIF(ICASPL.EQ.'MEDI')THEN
            CALL MEDIAN(XTEMP1,NTEMP1,IWRITE,XTEMP2,MAXNT2,XMED,   &
                        IBUGG3,IERROR)
            J=J+1
            Y2(J)=XMED
            X2(J)=Y0
            D2(J)=1.0
!
         ELSEIF(ICASPL.EQ.'MIDM')THEN
            IF(NTEMP1.EQ.1)THEN
              XMIDM=XTEMP1(1)
            ELSE
              CALL MIDMEA(XTEMP1,NTEMP1,IWRITE,XTEMP2,MAXNT2,XMIDM,   &
                        IBUGG3,IERROR)
            ENDIF
            J=J+1
            Y2(J)=XMIDM
            X2(J)=Y0
            D2(J)=1.0
         ENDIF
!
 1100 CONTINUE
      N2=J
      NPLOTV=2
      GO TO 9000
!
 2000 CONTINUE
!
!               ****************************************
!               **  CASE WITH TIES                    **
!               ****************************************
!
!               ****************************************
!               **  STEP 1--                          **
!               **  DETERMINE PLOT COORDINATES        **
!               ****************************************
!
      CALL SORTC(Z,ZITEMS,NZ,Z,ZITEMS)
!
      IWRITE='OFF'
      J=0
      NM1=NZ-1
      DO 2100 I=1,NM1
         Z0=Z(I)
         IP1=I+1
!
         NTEMP1=0
         IF(ICASPL.EQ.'SCAT')THEN
           DO 2200 K=IP1,NZ
             NTEMP1=NTEMP1+1
             XTEMP1(NTEMP1)=Z(K)-Z0
 2200      CONTINUE
         ELSEIF(ICASPL.EQ.'MEAN')THEN
           ATEMP=0.0
           DO 2210 K=IP1,NZ
             NTEMP1=NTEMP1+1
             XTEMP1(NTEMP1)=Z(K)-Z0
             XTEMP2(NTEMP1)=ZITEMS(K)
 2210      CONTINUE
         ELSEIF(ICASPL.EQ.'MEDI'.OR.ICASPL.EQ.'MIDM')THEN
           DO 2220 K=IP1,NZ
             NITEMS=INT(ZITEMS(K)+0.5)
             DO 2225 KK=1,NITEMS
               NTEMP1=NTEMP1+1
               XTEMP1(NTEMP1)=Z(K)-Z0
 2225        CONTINUE
 2220      CONTINUE
         ENDIF
!
         IF(ICASPL.EQ.'SCAT')THEN
            DO 2310 L=1,NTEMP1
               J=J+1
               Y2(J)=XTEMP1(L)
               X2(J)=Z0
               D2(J)=I
 2310      CONTINUE
!
         ELSEIF(ICASPL.EQ.'MEAN')THEN
            IF(NTEMP1.EQ.1)THEN
              XMEAN=XTEMP1(1)
            ELSE
              CALL WEMEAN(XTEMP1,XTEMP2,NTEMP1,IWRITE,XMEAN,   &
                        IBUGG3,IERROR)
            ENDIF
            J=J+1
            Y2(J)=XMEAN
            X2(J)=Z0
            D2(J)=1.0
!
         ELSEIF(ICASPL.EQ.'MEDI')THEN
            CALL MEDIAN(XTEMP1,NTEMP1,IWRITE,XTEMP2,MAXNT2,XMED,   &
                        IBUGG3,IERROR)
            J=J+1
            Y2(J)=XMED
            X2(J)=Z0
            D2(J)=1.0
!
         ELSEIF(ICASPL.EQ.'MIDM')THEN
            IF(NTEMP1.EQ.1)THEN
              XMIDM=XTEMP1(1)
            ELSE
              CALL MIDMEA(XTEMP1,NTEMP1,IWRITE,XTEMP2,MAXNT2,XMIDM,   &
                        IBUGG3,IERROR)
            ENDIF
            J=J+1
            Y2(J)=XMIDM
            X2(J)=Z0
            D2(J)=1.0
         ENDIF
!
 2100 CONTINUE
      N2=J
      NPLOTV=2
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CME2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCME2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,N,N2,NPLOTV
 9012   FORMAT('ICASPL,IERROR,N,N2,NPLOTV = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N2
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCME2
      SUBROUTINE DPCMPL(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        ICAPSW,ICAPTY,   &
                        IFORSW,ISEED,IBOOSS,   &
                        ISUBRO,IBUGG2,IBUGG3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A CONSENSUS MEAN PLOT--
!              THE COMMAND HAS THE FOLLOWING FORMAT:
!                  CONSENSUS MEAN PLOT Y X LABID
!              OR
!                  CONSENSUS MEAN PLOT YMEAN YSD NI LABID
!              THIS PLOT DISPLAYS THE RESULTS OF A CONSENSUS MEAN ANALYSIS.
!              IT IS USEFUL FOR PROVIDING A COMPARISON OF THE VARIOUS
!              METHODS OF COMPUTING CONSENSUS MEANS.
!     EXAMPLE--CONSENSUS MEAN PLOT Y X
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/8
!     ORIGINAL VERSION--AUGUST    2001.
!     UPDATED         --OCTOBER   2002. ADD ICAPSW, ICAPTY TO CALL
!                                       LIST (PASS TO DPCMP2)
!     UPDATED         --MARCH     2006. ADD IFORSW TO CALL LIST
!     UPDATED         --MAY       2010. UPDATE LIST OF SUPPORTED
!                                       METHODS
!     UPDATED         --MAY       2010. USE DPPARS
!     UPDATED         --OCTOBER   2011. ADD LAB DATA TO PLOT
!     UPDATED         --OCTOBER   2011. OPTION TO SORT METHODS BASED
!                                       ON INTERVAL WIDTH
!     UPDATED         --JUNE      2012. ADD "IBOOSS" TO CALL LIST (FOR
!                                       BOOTSTRAP COMPUTATIONS)
!     UPDATED         --OCTOBER   2014. FOR SUMMARY DATA, OPTION TO
!                                       INPUT MEAN AND UNCERTAINTY
!                                       (I.E., S/SQRT(N) INSTEAD OF
!                                       S AND N).  IN SOME CASES, DATA
!                                       IS AVAILABLE IN THIS FORM.
!     UPDATED         --NOVEMBER  2016. OPTION TO OMIT ONE OR MORE LABS
!                                       FROM THE PLOT (BUT NOT THE
!                                       ANALYSIS), USEFUL FOR INCREASING
!                                       VISUAL RESOLUTION OF BULK OF
!                                       LABS
!     UPDATED         --APRIL     2017. ADD ICMPM1, ICMPM2, ICMPM3 TO
!                                       CALL LIST TO DPCMP2
!     UPDATED         --JULY      2019. TWEAK SCRATCH STORAGE
!     UPDATED         --APRIL     2023. LINEAR POOL METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
      DOUBLE PRECISION SEBOK1
      DOUBLE PRECISION SEBOK2
!
      DOUBLE PRECISION YDL
      DOUBLE PRECISION DLOWD2
      DOUBLE PRECISION DHIGD2
      DOUBLE PRECISION DLOWD3
      DOUBLE PRECISION DHIGD3
      DOUBLE PRECISION DLOWD4
      DOUBLE PRECISION DHIGD4
      DOUBLE PRECISION DLOWD5
      DOUBLE PRECISION DHIGD5
      DOUBLE PRECISION DLOWD6
      DOUBLE PRECISION DHIGD6
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
      INCLUDE 'DPCOZI.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
!
      DIMENSION Z1(MAXOBV)
      DIMENSION Z6(MAXOBV)
      DIMENSION Z7(MAXOBV)
      DIMENSION Z8(MAXOBV)
      DIMENSION Z9(MAXOBV)
      DIMENSION PLABID(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XPLOTZ(MAXOBV)
      DIMENSION YPLOTZ(MAXOBV)
      DIMENSION WTS(MAXOBV)
!
      INTEGER IZ(MAXOBV)
      INTEGER IZ2(MAXOBV)
      INTEGER ITEMP1(MAXOBV)
      INTEGER IZFULL(MAXOBV)
!
      DOUBLE PRECISION Z2(MAXOBV)
      DOUBLE PRECISION Z3(MAXOBV)
      DOUBLE PRECISION Z4(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y3(1))
      EQUIVALENCE (GARBAG(IGARB4),Z1(1))
      EQUIVALENCE (GARBAG(IGARB5),Z6(1))
      EQUIVALENCE (GARBAG(IGARB6),Z7(1))
      EQUIVALENCE (GARBAG(IGARB7),Z8(1))
      EQUIVALENCE (GARBAG(IGARB8),Z9(1))
      EQUIVALENCE (GARBAG(IGARB9),PLABID(1))
      EQUIVALENCE (GARBAG(IGAR10),XTEMP1(1))
      EQUIVALENCE (GARBAG(JGAR11),XTEMP2(1))
      EQUIVALENCE (GARBAG(JGAR12),XTEMP3(1))
      EQUIVALENCE (GARBAG(JGAR13),XTEMP4(1))
      EQUIVALENCE (GARBAG(JGAR14),XPLOTZ(1))
      EQUIVALENCE (GARBAG(JGAR15),YPLOTZ(1))
      EQUIVALENCE (GARBAG(JGAR16),WTS(1))
!
      EQUIVALENCE (DGARBG(IDGAR1),Z2(1))
      EQUIVALENCE (DGARBG(IDGAR2),Z3(1))
      EQUIVALENCE (DGARBG(IDGAR3),Z4(1))
      EQUIVALENCE (DGARBG(IDGAR4),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR5),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR6),DTEMP3(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),IZ(1))
      EQUIVALENCE (IGARBG(IIGAR2),IZ2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR4),IZFULL(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IFOUND='NO'
      ISUBN1='DPCM'
      ISUBN2='PL  '
      ICASPL='CMPL'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *******************************************
!               **  TREAT THE CONSENSUS MEAN PLOT CASE   **
!               *******************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCMPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   52   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,MAXN
   53   FORMAT('ICASPL,IAND1,IAND2,MAXN = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='11'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.2.AND.ICOM.EQ.'CONS'.AND.IHARG(1).EQ.'MEAN'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
         ILASTC=2
         CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
         IFOUND='YES'
      ELSEIF(NUMARG.GE.3.AND.ICOM.EQ.'SUMM'.AND.IHARG(1).EQ.'CONS'.AND.   &
         IHARG(2).EQ.'MEAN'.AND.IHARG(3).EQ.'PLOT')THEN
         ILASTC=3
         CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
         IFOUND='YES'
      ELSE
         IFOUND='NO'
         GO TO 9000
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CONSENSUS MEAN PLOT'
      MINNA=2
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=2
      MAXNVA=4
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ****************************************
!               **  STEP 3--                          **
!               **  EXTRACT THE DATA                  **
!               ****************************************
!
!     THE FOLLOWING CASES ARE SUPPORTED:
!
!       1) NUMVAR = 2
!
!          RAW DATA CASE, THE "X" VARIABLE IS ALSO THE LAB-ID
!
!       2) NUMVAR = 3
!
!          SUMMARY DATA CASE, NO LAB-ID VARIABLE GIVEN
!
!       2) NUMVAR = 4
!
!          SUMMARY DATA CASE, LAB-ID VARIABLE GIVEN
!
      ICOL=1
      CALL DPPAR5(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,Y3,PLABID,Z9,Z9,Z9,NLOCAL,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NS=NLOCAL
      IF(NUMVAR.EQ.3)THEN
        DO 310 I=1,NS
          PLABID(I)=REAL(I)
  310   CONTINUE
      ENDIF
!
!               *******************************************************
!               **  STEP 8--                                         **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS            **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.               **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).    **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).    **
!               *******************************************************
!
      ISTEPN='5'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,5001)NLOCAL,ICASPL
 5001   FORMAT('NLOCAL,ICASPL=',I5,1X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IH='SIGM'
      IH2='AH  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        SIGMAH=0.0
      ELSE
        SIGMAH=VALUE(ILOCP)
        IF(SIGMAH.LT.0.0)SIGMAH=0.0
      ENDIF
      IH='DFH '
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IDFH=1
      ELSE
        IDFH=INT(VALUE(ILOCP)+ 0.5)
      ENDIF
      IF(IDFH.LE.0)IDFH=1
!
!     2023/04: LINEAR POOL METHOD SUPPORTS A WEIGHTS VARIABLE
!              FOR THE LABS
!
      DO 410 II=1,MAXOBV
        WTS(II)=0.0
  410 CONTINUE
!
      IF(ILIPCM.EQ.'ON' .AND. ILIPWT.NE.'OFF ')THEN
        IH=ILIPWT(1:4)
        IH2=ILIPWT(5:8)
        IHWUSE='V'
        MESSAG='NO'
        CALL CHECKN(IH,IH2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
!
        IF(IERROR.EQ.'NO')THEN
          ICOLQP=IVALUE(ILOCV)
          NTEMP=IN(ILOCV)
          ICNT=0
          DO 418 I=1,NTEMP
            IJ=MAXN*(ICOLQP-1)+I
            ICNT=ICNT+1
            IF(ICOLQP.LE.MAXCOL)WTS(ICNT)=V(IJ)
            IF(ICOLQP.EQ.MAXCP1)WTS(ICNT)=PRED(I)
            IF(ICOLQP.EQ.MAXCP2)WTS(ICNT)=RES(I)
            IF(ICOLQP.EQ.MAXCP3)WTS(ICNT)=YPLOT(I)
            IF(ICOLQP.EQ.MAXCP4)WTS(ICNT)=XPLOT(I)
            IF(ICOLQP.EQ.MAXCP5)WTS(ICNT)=X2PLOT(I)
            IF(ICOLQP.EQ.MAXCP6)WTS(ICNT)=TAGPLO(I)
  418     CONTINUE
        ENDIF
      ENDIF
!
!     MARCH 2006.  ADD IFORSW TO CALL LIST.
!
      MAXNXT=MAXOBV
      CALL DPCMP2(Y1,Y2,Y3,PLABID,NLOCAL,ICASPL,NUMVAR,MAXNXT,   &
                  Z1,Z2,Z3,Z4,   &
                  Z6,Z7,IZ,   &
                  Z8,Z9,IZFULL,   &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  XPLOTZ,YPLOTZ,WTS,NPLOT,   &
                  IVARN1(1),IVARN2(1),IVARN1(2),IVARN2(2),   &
                  IVARN1(3),IVARN2(3),   &
                  SIGMAH,IDFH,   &
                  XGRAND,S2WPOO,SW,ASD2,ASD3,   &
                  SET1,SET2,   &
                  XMPS,S2BMPS,SEMP,   &
                  XMMPS,S2BMMP,SEMMP,   &
                  XMLS,S2BMLS,SEML,   &
                  XSE,XSES2,ABIAS,ISEDF,   &
                  ASM,ASB,AKU,   &
                  XGD,XGDS2,   &
                  XGCI,XDL,XDLS2,YDL,SEDLK1,SEHDK1,SERUK1,   &
                  XDLK2,XDLK3,DLOWD2,DHIGD2,DLOWD3,DHIGD3,   &
                  SEBOK1,SEBOK2,DLOWD4,DHIGD4,   &
                  DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
                  SEGCI,XFW,SEFWK1,SEFWK2,   &
                  XBCP,XBCPSE,XBCPK1,XBCPK2,XMEDME,SEMEK1,   &
                  XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,   &
                  XLP,XLIPSE,ALOWLP,AUPPLP,   &
                  Y,X,D,   &
                  ICAPSW,ICAPTY,IFORSW,ISEED,IBOOSS,   &
                  ICMPSO,ICMPDA,ICMPER,ICMPLL,ICMPNL,   &
                  ICMPM1,ICMPM2,ICMPM3,   &
                  NPLOTP,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!               ***************************************
!               **  STEP 10--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='10'
      IF(IBUGG2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IH='XGRA'
      IH2='ND  '
      VALUE0=XGRAND
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='S2PO'
      IH2='OOL '
      VALUE0=S2WPOO
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='YBAR'
      IH2='SD1 '
      VALUE0=ASD2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='YBAR'
      IH2='SD2 '
      VALUE0=ASD3
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='T1ST'
      IH2='DERR'
      VALUE0=SET1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='T2ST'
      IH2='DERR'
      VALUE0=SET2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MEAM'
      IH2='EASE'
      VALUE0=SET2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SEME'
      IH2='AN  '
      VALUE0=XSE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SES2'
      IH2='    '
      VALUE0=XSES2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BIAS'
      IH2='ALLO'
      VALUE0=ABIAS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SEDF'
      IH2='    '
      VALUE0=REAL(ISEDF)
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MPME'
      IH2='AN  '
      VALUE0=XMPS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MPS2'
      IH2='    '
      VALUE0=S2BMPS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SEMP'
      IH2='    '
      VALUE0=SEMP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MPSE'
      IH2='    '
      VALUE0=SEMP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MMPM'
      IH2='EAN '
      VALUE0=XMMPS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MMPS'
      IH2='2   '
      VALUE0=S2BMMP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SEMM'
      IH2='P   '
      VALUE0=SEMMP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MLME'
      IH2='AN  '
      VALUE0=XMLS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MLS2'
      IH2='    '
      VALUE0=S2BMLS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SEML'
      IH2='    '
      VALUE0=SEML
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BOBM'
      IH2='EAN '
      VALUE0=ASM
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MEAO'
      IH2='FMEA'
      VALUE0=ASM
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BOBS'
      IH2='2   '
      VALUE0=ASB
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BOBS'
      IH2='2W  '
      VALUE0=SW
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BOBK'
      IH2='U   '
      VALUE0=AKU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='GDME'
      IH2='AN  '
      VALUE0=XGD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='GDS2'
      IH2='    '
      VALUE0=XGDS2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='GCIM'
      IH2='EAN '
      VALUE0=XGCI
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='GCIS'
      IH2='E   '
      VALUE0=SEGCI
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='MEAN'
      VALUE0=XDL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='YDL '
      IH2='    '
      VALUE0=YDL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='VARI'
      VALUE0=XDLS2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='SE  '
      VALUE0=SEDLK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='SEHD'
      VALUE0=SEHDK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='95LL'
      VALUE0=DLOWD2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='95UL'
      VALUE0=DHIGD2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DHHD'
      IH2='95LL'
      VALUE0=DLOWD3
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DHHD'
      IH2='95UL'
      VALUE0=DHIGD3
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='SERU'
      VALUE0=SERUK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='SEBS'
      VALUE0=SEBOK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='BOK2'
      VALUE0=XDLK2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='DERS'
      IH2='BOK3'
      VALUE0=XDLK3
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='FAIR'
      IH2='MEAN'
      VALUE0=XFW
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='FAIR'
      IH2='SE  '
      VALUE0=SEFWK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BCPM'
      IH2='EAN '
      VALUE0=XBCP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='BCPS'
      IH2='E   '
      VALUE0=XBCPSE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MEDO'
      IH2='FMEA'
      VALUE0=XMEDME
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='MEDM'
      IH2='EASE'
      VALUE0=SEMEK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='H15O'
      IH2='FMEA'
      VALUE0=XH15
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='H15M'
      IH2='EASE'
      VALUE0=SEHMK1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='LINP'
      IH2='MEAN'
      VALUE0=XLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='LINP'
      IH2='SE  '
      VALUE0=XLIPSE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='LINP'
      IH2='95LL'
      VALUE0=ALOWLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='LINP'
      IH2='95UL'
      VALUE0=AUPPLP
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
!               *****************
!               **  STEP 9--   **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CMPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCMPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGG2,IBUGG3,IBUGQ,ISUBRO
 9012   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR,NLOCAL,NPLOTP
 9013   FORMAT('IFOUND,IERROR,NLOCAL,NPLOTP = ',A4,2X,A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NPLOTV,NPLOTP,NLOCAL,ICASPL,IAND1,IAND2
 9014   FORMAT('NPLOTV,NPLOTP,NLOCAL,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GT.0)THEN
          DO 9052 I=1,NPLOTP
            WRITE(ICOUT,9053)I,Y(I),X(I),D(I)
 9053       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9052     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCMPL
      SUBROUTINE DPCMP2(Y1,Y2,Y3,PLABID,NZ,ICASPL,NUMV2,MAXNXT,   &
                        DAT,DX,T,W,   &
                        AMEAN,ASD,N,   &
                        AMEANF,ASDF,NFULL,   &
                        XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        XPLOT,YPLOT,WTS,NPLOT,   &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,IHRI21,IHRI22,   &
                        SIGMAH,IDFH,   &
                        XGRAND,S2WPOO,SW,ASD2,ASD3,   &
                        SET1,SET2,   &
                        XMPS,S2BMPS,SEMP,   &
                        XMMPS,S2BMMP,SEMMP,   &
                        XMLS,S2BMLS,SEML,   &
                        XSE,XSES2,ABIAS,ISEDF,   &
                        ASM,ASB,AKU,   &
                        XGD,XGDS2,   &
                        XGCI,XDL,XDLS2,YDL,SEDLK1,SEHDK1,SERUK1,   &
                        XDLK2,XDLK3,DLOWD2,DHIGD2,DLOWD3,DHIGD3,   &
                        SEBOK1,SEBOK2,DLOWD4,DHIGD4,   &
                        DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
                        SEGCI,XFW,SEFWK1,SEFWK2,   &
                        XBCP,XBCPSE,XBCPK1,XBCPK2,XMEDME,SEMEK1,   &
                        XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,   &
                        XLP,XLIPSE,ALOWLP,AUPPLP,   &
                        Y,X,D,   &
                        ICAPSW,ICAPTY,IFORSW,ISEED,IBOOSS,   &
                        ICMPSO,ICMPDA,ICMPER,ICMPLL,ICMPNL,   &
                        ICMPM1,ICMPM2,ICMPM3,   &
                        N2,NPLOTV,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE A
!              CONSENSUS MEAN PLOT
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/8
!     ORIGINAL VERSION--AUGUST    2001.
!     UPDATED  VERSION--APRIL     2002. PRINT OUT ORDER OF METHODS ON
!                                       PLOT
!     UPDATED  VERSION--OCTOBER   2002. ADD ICAPSW, ICAPTY TO CALL
!                                       LIST (PASS TO DPMAN2)
!     UPDATED  VERSION--MAY       2010. UPDATE LIST OF METHODS
!     UPDATED  VERSION--OCTOBER   2011. LABID VARIABLE (PLABID)
!     UPDATED  VERSION--OCTOBER   2011. ADD LABS TO THE PLOT
!     UPDATED  VERSION--NOVEMBER  2016. OPTION TO OMIT LABS FROM PLOT
!                                       (BUT NOT FROM THE ANALYSIS)
!     UPDATED  VERSION--FEBRUARY  2017. FIX BUG FOR SAMPLE SIZE = 0
!     UPDATED  VERSION--MAY       2019. OPTION TO PUT DATA ON LEFT
!                                       AND CONSENSUS OPTIONS ON
!                                       RIGHT
!     UPDATED  VERSION--APRIL     2023. LINEAR POOL METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASPL
      CHARACTER*4 IFORSW
      CHARACTER*4 ICMPDA
      CHARACTER*4 ICMPSO
      CHARACTER*4 ICMPER
      CHARACTER*4 ICMPM1
      CHARACTER*4 ICMPM2
      CHARACTER*4 ICMPM3
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IHRI21
      CHARACTER*4 IHRI22
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DOUBLE PRECISION YDL
      DOUBLE PRECISION DLOWD2
      DOUBLE PRECISION DHIGD2
      DOUBLE PRECISION DLOWD3
      DOUBLE PRECISION DHIGD3
      DOUBLE PRECISION DLOWD4
      DOUBLE PRECISION DHIGD4
      DOUBLE PRECISION DLOWD5
      DOUBLE PRECISION DHIGD5
      DOUBLE PRECISION DLOWD6
      DOUBLE PRECISION DHIGD6
      DOUBLE PRECISION SEBOK1
      DOUBLE PRECISION SEBOK2
!
!---------------------------------------------------------------------
!
      DIMENSION XMID(20)
      DOUBLE PRECISION DXLOW(20)
      DOUBLE PRECISION DXHIGH(20)
      CHARACTER*30 ILAB(20)
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION PLABID(*)
      DIMENSION AMEAN(*)
      DIMENSION ASD(*)
      DIMENSION AMEANF(*)
      DIMENSION ASDF(*)
      DIMENSION DAT(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP4(*)
      DIMENSION XPLOT(*)
      DIMENSION YPLOT(*)
      DIMENSION WTS(*)
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
!
      DOUBLE PRECISION DX(*)
      DOUBLE PRECISION T(*)
      DOUBLE PRECISION W(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      INTEGER N(*)
      INTEGER NFULL(*)
      INTEGER ITEMP1(*)
      INTEGER ICMPLL(*)
!
      INTEGER METHIN(20)
!
      CHARACTER*4 IOP
      CHARACTER*15 IA
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCM'
      ISUBN2='P2  '
      IERROR='NO'
      ISUBN0='CMP2'
!
      DO 10 I=1,20
        METHIN(I)=1
   10 CONTINUE
      ICNT3=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CMP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPCMP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,NZ,N2,NPLOTV,NUMV2
   72   FORMAT('ICASPL,NZ,N2,NPLOTV,NUMV2 = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        IF(NZ.GT.0)THEN
          DO 81 I=1,NZ
            WRITE(ICOUT,82)I,Y1(I),Y2(I),Y3(I),PLABID(I)
   82       FORMAT('I,Y1(I),Y2(I),Y3(I),PLABID(I) = ',I8,4G15.7)
   81     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NZ.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN CONSENSUS MEAN PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST TWO;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)NZ
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************
!               **  STEP 1--                          **
!               **  CALL DPMAN2 TO OBTAIN CONSENSUS   **
!               **  MEAN ESTIMATES.                   **
!               ****************************************
!
      IWRITE='OFF'
!CCCC IWRITE='ON'
      CALL DPMAN2(Y1,Y2,Y3,PLABID,NZ,NUMV2,MAXNXT,   &
                  DAT,DX,T,W,   &
                  AMEAN,ASD,N,   &
                  AMEANF,ASDF,NFULL,   &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  XPLOT,YPLOT,WTS,NPLOT,   &
                  IHLEFT,IHLEF2,IHRIGH,IHRIG2,IHRI21,IHRI22,   &
                  SIGMAH,IDFH,   &
                  XGRAND,S2WPOO,SW,ASD2,ASD3,   &
                  SET1,SET2,   &
                  XMPS,S2BMPS,SEMP,   &
                  XMMPS,S2BMMP,SEMMP,   &
                  XMLS,S2BMLS,SEML,   &
                  XSE,XSES2,ABIAS,ISEDF,   &
                  ASM,ASB,AKU,   &
                  XGD,XGDS2,   &
                  XGCI,XDL,XDLS2,YDL,SEDLK1,SEHDK1,SERUK1,   &
                  XDLK2,XDLK3,DLOWD2,DHIGD2,DLOWD3,DHIGD3,   &
                  SEBOK1,SEBOK2,DLOWD4,DHIGD4,   &
                  DLOWD5,DHIGD5,DLOWD6,DHIGD6,   &
                  SEGCI,XFW,SEFWK1,SEFWK2,   &
                  XBCP,XBCPSE,XBCPK1,XBCPK2,XMEDME,SEMEK1,   &
                  XH15,SEHMK1,SEHMK2,H15LCL,H15UCL,   &
                  XLP,XLIPSE,ALOWLP,AUPPLP,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,IFORSW,ISEED,IBOOSS,   &
                  ISUBRO,IBUGG3,IERROR)
!
!               ****************************************
!               **  STEP 2--                          **
!               **  READ VALUES BACK FROM FILE        **
!               ****************************************
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=1
      IFLAG3=1
      IFLAG4=1
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DO I=1,20
         ILAB(I)=' '
      ENDDO
      IROW=0
      DO 200 I=1,20
        IF(ICMPER.EQ.'CONF')THEN
          READ(IOUNI2,'(3E15.7,15X,A30)',END=209,ERR=205)   &
              XMID(I),DXLOW(I),DXHIGH(I),ILAB(I)
        ELSE
          READ(IOUNI3,'(3E15.7,15X,A30)',END=209,ERR=205)   &
               XMID(I),AJUNK2,AJUNK3,ILAB(I)
          IF(ICMPER.EQ.'1SE')THEN
            DXLOW(I)=XMID(I) - AJUNK2
            DXHIGH(I)=XMID(I) + AJUNK2
          ELSEIF(ICMPER.EQ.'2SE')THEN
            DXLOW(I) =XMID(I) - 2.0*AJUNK2
            DXHIGH(I)=XMID(I) + 2.0*AJUNK2
          ENDIF
        ENDIF
        IROW=IROW+1
  200 CONTINUE
      GO TO 209
!
  205 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,206)
  206 FORMAT('      UNABLE TO READ VALUES FROM DPST2F.DAT FILE.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
  209 CONTINUE
      NMETH=IROW
!
!     CHECK TO SEE IF ANY METHODS WILL BE SUPPRESSED ON THE PLOT
!
      IF(ICMPM1.NE.'NULL')THEN
        REWIND(IOUNI4)
        DO 211 II=1,NMETH
          READ(IOUNI4,'(60X,A15)')IA(1:15)
          IF(ICMPM1.EQ.'MP  '.AND.IA(1:12).EQ.'Mandel-Paule')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'MMP '.AND.IA(1:15).EQ.'Modified Mandel')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'VR  '.AND.IA(1:13).EQ.'Vangel-Rukhin')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'DSL '.AND.IA(1:15).EQ.'DerSionian-Lair')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'GRAY'.AND.IA(1:13).EQ.'Graybill-Deal')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'FAIR'.AND.IA(1:11).EQ.'Fairweather')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'GCI '.AND.IA(1:14).EQ.'Generalized CI')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'GMEA'.AND.IA(1:10).EQ.'Grand Mean')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'MOM '.AND.IA(1:13).EQ.'Mean of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'MEDM'.AND.IA(1:15).EQ.'Median of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'BOB '.AND.IA(1:3).EQ.'Bob')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'SE  '.AND.IA(1:7).EQ.'Schiller')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'BCP '.AND.IA(1:3).EQ.'BCP')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'HUBE'.AND.IA(1:5).EQ.'Huber')THEN
            METHIN(II)=0
          ELSEIF(ICMPM1.EQ.'LPOO'.AND.IA(1:5).EQ.'Linea')THEN
            METHIN(II)=0
          ENDIF
  211   CONTINUE
        REWIND(IOUNI4)
      ENDIF
!
      IF(ICMPM2.NE.'NULL')THEN
        REWIND(IOUNI4)
        DO 213 II=1,NMETH
          READ(IOUNI4,'(60X,A15)')IA(1:15)
          IF(ICMPM2.EQ.'MP  '.AND.IA(1:12).EQ.'Mandel-Paule')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'MMP '.AND.IA(1:15).EQ.'Modified Mandel')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'VR  '.AND.IA(1:13).EQ.'Vangel-Rukhin')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'DSL '.AND.IA(1:15).EQ.'DerSionian-Lair')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'GRAY'.AND.IA(1:13).EQ.'Graybill-Deal')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'FAIR'.AND.IA(1:11).EQ.'Fairweather')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'GCI '.AND.IA(1:14).EQ.'Generalized CI')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'GMEA'.AND.IA(1:10).EQ.'Grand Mean')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'MOM '.AND.IA(1:13).EQ.'Mean of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'MEDM'.AND.IA(1:15).EQ.'Median of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'BOB '.AND.IA(1:3).EQ.'Bob')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'SE  '.AND.IA(1:7).EQ.'Schiller')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'BCP '.AND.IA(1:3).EQ.'BCP')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'HUBE'.AND.IA(1:5).EQ.'Huber')THEN
            METHIN(II)=0
          ELSEIF(ICMPM2.EQ.'LPOO'.AND.IA(1:5).EQ.'Linea')THEN
            METHIN(II)=0
          ENDIF
  213   CONTINUE
        REWIND(IOUNI4)
      ENDIF
!
      IF(ICMPM3.NE.'NULL')THEN
        REWIND(IOUNI4)
        DO 215 II=1,NMETH
          READ(IOUNI4,'(60X,A15)')IA(1:15)
          IF(ICMPM3.EQ.'MP  '.AND.IA(1:12).EQ.'Mandel-Paule')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'MMP '.AND.IA(1:15).EQ.'Modified Mandel')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'VR  '.AND.IA(1:13).EQ.'Vangel-Rukhin')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'DSL '.AND.IA(1:15).EQ.'DerSionian-Lair')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'GRAY'.AND.IA(1:13).EQ.'Graybill-Deal')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'FAIR'.AND.IA(1:11).EQ.'Fairweather')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'GCI '.AND.IA(1:14).EQ.'Generalized CI')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'GMEA'.AND.IA(1:10).EQ.'Grand Mean')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'MOM '.AND.IA(1:13).EQ.'Mean of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'MEDM'.AND.IA(1:15).EQ.'Median of Means')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'BOB '.AND.IA(1:3).EQ.'Bob')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'SE  '.AND.IA(1:7).EQ.'Schiller')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'BCP '.AND.IA(1:3).EQ.'BCP')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'HUBE'.AND.IA(1:5).EQ.'Huber')THEN
            METHIN(II)=0
          ELSEIF(ICMPM3.EQ.'LPOO'.AND.IA(1:5).EQ.'Linea')THEN
            METHIN(II)=0
          ENDIF
  215   CONTINUE
        REWIND(IOUNI4)
      ENDIF
!
!     IF SORT OPTION REQUESTED, SORT BY WIDTH OF INTERVAL
!
!     AFTER SORTC, Y3 WILL CONTAIN THE INDEX
!
      IF(ICMPSO.EQ.'ON')THEN
        DO 220 I=1,NMETH
          Y1(I)=DXHIGH(I) - DXLOW(I)
          Y2(I)=REAL(I)
  220   CONTINUE
        CALL SORTC(Y1,Y2,NMETH,Y1,Y3)
      ENDIF
!
      IROW=0
      DO 250 I=1,1000
        READ(IOUNI1,'(F6.0,F8.0,2X,3E15.7)',END=259,ERR=255)   &
            PLABID(I),AMEANF(I),AMEAN(I),AJUNK,ASD(I)
        IROW=IROW+1
  250 CONTINUE
      GO TO 259
!
  255 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,256)
  256 FORMAT('      UNABLE TO READ VALUES FROM DPST1F.DAT FILE.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
  259 CONTINUE
      NLABID=IROW
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IOP='OPEN'
      IFLAG1=0
      IFLAG2=0
      IFLAG3=1
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ****************************************
!               **  STEP 3--                          **
!               **  CREATE THE X, Y, D ARRAYS FOR     **
!               **  PLOTTING                          **
!               ****************************************
!
!CCCC IBOB=1
!CCCC IF(IROW.LT.8)IBOB=0
!
      N2=0
!
      IF(ICMPDA.NE.'LEFT')THEN
        DO 300 I=1,NMETH
          IINDX=I
          IF(ICMPSO.EQ.'ON')IINDX=INT(Y3(I)+0.5)
          IF(METHIN(IINDX).EQ.0)GO TO 300
          N2=N2+1
          X(N2)=REAL(I)
          Y(N2)=XMID(IINDX)
          D(N2)=1.0
  300   CONTINUE
      ENDIF
!
      IF(ICMPDA.EQ.'ON' .OR. ICMPDA.EQ.'LEFT')THEN
        IF(ICMPNL.GT.0)THEN
          DO 303 IINDX=1,NLABID
            DO 304 JJ=1,ICMPNL
              IF(PLABID(IINDX).EQ.ICMPLL(JJ))GO TO 303
  304       CONTINUE
            N2=N2+1
            IF(ICMPDA.EQ.'ON')THEN
              ICNT3=NMETH+INT(PLABID(IINDX)+0.5)
            ELSEIF(ICMPDA.EQ.'LEFT')THEN
              ICNT3=INT(PLABID(IINDX)+0.5)
            ENDIF
            X(N2)=REAL(ICNT3)
            Y(N2)=AMEAN(IINDX)
            D(N2)=1.0
  303     CONTINUE
        ELSE
          DO 305 IINDX=1,NLABID
            N2=N2+1
            IF(ICMPDA.EQ.'ON')THEN
              ICNT3=NMETH+INT(PLABID(IINDX)+0.5)
            ELSEIF(ICMPDA.EQ.'LEFT')THEN
              ICNT3=INT(PLABID(IINDX)+0.5)
            ENDIF
            X(N2)=REAL(ICNT3)
            Y(N2)=AMEAN(IINDX)
            D(N2)=1.0
  305     CONTINUE
        ENDIF
      ENDIF
!
      IF(ICMPDA.EQ.'LEFT')THEN
        DO 307 I=1,NMETH
          IINDX=I
          IF(ICMPSO.EQ.'ON')IINDX=INT(Y3(I)+0.5)
          IF(METHIN(IINDX).EQ.0)GO TO 307
          N2=N2+1
          X(N2)=REAL(I+NLABID)
          Y(N2)=XMID(IINDX)
          D(N2)=1.0
  307   CONTINUE
      ENDIF
!
      ICNT2=1
      IF(ICMPDA.NE.'LEFT')THEN
        DO 310 I=1,NMETH
          IINDX=I
          IF(ICMPSO.EQ.'ON')IINDX=INT(Y3(I)+0.5)
          IF(METHIN(IINDX).EQ.0)GO TO 310
          N2=N2+1
          ICNT2=ICNT2+1
          X(N2)=REAL(I)
          Y(N2)=DXLOW(IINDX)
          D(N2)=REAL(ICNT2)
!
          N2=N2+1
          X(N2)=REAL(I)
          Y(N2)=DXHIGH(IINDX)
          D(N2)=REAL(ICNT2)
  310   CONTINUE
      ENDIF
!
!     2015/01: IF DATA REPORTED AS AN UNCERTAINTY (I.E.,
!              N(I) < 0), THEN ASD IS ACTUALLY INTERPRETED
!              AS   S(i)/SQRT(N(i)) WHERE N(i) IS THE EFFECTIVE
!              DEGREES OF FREEDOM.  SO FOR +/- 2*S(i), DO NOT
!              DIVIDE BY SQRT(N(i)) AS THIS IS ALREADY INCORPORATED
!              IN ASD.
!
!              ALSO, IF N(I) = 0, THEN ASD INTERPRETED AS
!              S(i)/SQRT(N(i)).
!
      IF(ICMPDA.EQ.'ON' .OR. ICMPDA.EQ.'LEFT')THEN
        AFACT=2.0
        IF(ICMPER.EQ.'1SE ')AFACT=1.0
        IF(ICMPNL.GT.0)THEN
          DO 325 IINDX=1,NLABID
            DO 328 JJ=1,ICMPNL
              IF(PLABID(IINDX).EQ.ICMPLL(JJ))GO TO 325
  328       CONTINUE
            ICNT2=ICNT2+1
            IF(ICMPDA.EQ.'ON')THEN
              ICNT3=NMETH+INT(PLABID(IINDX)+0.5)
            ELSEIF(ICMPDA.EQ.'LEFT')THEN
              ICNT3=INT(PLABID(IINDX)+0.5)
            ENDIF
!
            N2=N2+1
            X(N2)=REAL(ICNT3)
            IF(AMEANF(IINDX).LE.0.0)THEN
              ALOWT=AMEAN(IINDX) - AFACT*ASD(IINDX)
            ELSE
              ALOWT=AMEAN(IINDX) - AFACT*ASD(IINDX)/SQRT(AMEANF(IINDX))
            ENDIF
            Y(N2)=ALOWT
            D(N2)=REAL(ICNT2)
!
            N2=N2+1
            IF(AMEANF(IINDX).LE.0.0)THEN
              AHIGT=AMEAN(IINDX) + AFACT*ASD(IINDX)
            ELSE
              AHIGT=AMEAN(IINDX) + AFACT*ASD(IINDX)/SQRT(AMEANF(IINDX))
            ENDIF
            IF(ICMPDA.EQ.'ON')THEN
              ICNT3=NMETH+INT(PLABID(IINDX)+0.5)
            ELSEIF(ICMPDA.EQ.'LEFT')THEN
              ICNT3=INT(PLABID(IINDX)+0.5)
            ENDIF
            X(N2)=REAL(ICNT3)
            Y(N2)=AHIGT
            D(N2)=REAL(ICNT2)
  325     CONTINUE
        ELSE
          DO 315 IINDX=1,NLABID
            ICNT2=ICNT2+1
            IF(ICMPDA.EQ.'ON')THEN
              ICNT3=NMETH+INT(PLABID(IINDX)+0.5)
            ELSEIF(ICMPDA.EQ.'LEFT')THEN
              ICNT3=INT(PLABID(IINDX)+0.5)
            ENDIF
!
            N2=N2+1
            X(N2)=REAL(ICNT3)
            IF(AMEANF(IINDX).LE.0.0)THEN
              ALOWT=AMEAN(IINDX) - AFACT*ASD(IINDX)
            ELSE
              ALOWT=AMEAN(IINDX) - AFACT*ASD(IINDX)/SQRT(AMEANF(IINDX))
            ENDIF
            Y(N2)=ALOWT
            D(N2)=REAL(ICNT2)
!
            N2=N2+1
            IF(AMEANF(IINDX).LE.0.0)THEN
              AHIGT=AMEAN(IINDX) + AFACT*ASD(IINDX)
            ELSE
              AHIGT=AMEAN(IINDX) + AFACT*ASD(IINDX)/SQRT(AMEANF(IINDX))
            ENDIF
            X(N2)=REAL(ICNT3)
            Y(N2)=AHIGT
            D(N2)=REAL(ICNT2)
  315     CONTINUE
        ENDIF
      ENDIF
!
      IF(ICMPDA.EQ.'LEFT')THEN
        DO 330 I=1,NMETH
          IINDX=I
          IF(ICMPSO.EQ.'ON')IINDX=INT(Y3(I)+0.5)
          IF(METHIN(IINDX).EQ.0)GO TO 330
          N2=N2+1
          ICNT2=ICNT2+1
          X(N2)=REAL(I+NLABID)
          Y(N2)=DXLOW(IINDX)
          D(N2)=REAL(ICNT2)
!
          N2=N2+1
          X(N2)=REAL(I+NLABID)
          Y(N2)=DXHIGH(IINDX)
          D(N2)=REAL(ICNT2)
  330   CONTINUE
      ENDIF
!
      NPLOTV=3
      DO 8010 I=1,NMETH
        IINDX=I
        IF(ICMPSO.EQ.'ON')IINDX=INT(Y3(I)+0.5)
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,8011)I,ILAB(IINDX)
 8011     FORMAT(I2,'. ',A30)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(IOUNI3,'(I5)')IINDX
 8010 CONTINUE
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8001)
 8001   FORMAT('The accompying plot has the consensus value and ',   &
               'confidence limits.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8003)
 8003   FORMAT('The ordering of methods on the accompaning consensus ',   &
               'mean plot is:')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CMP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCMP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,NZ,N2,NPLOTV,IERROR
 9012   FORMAT('ICASPL,NZ,N2,NPLOTV,IERROR = ',A4,3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9035 I=1,N2
          WRITE(ICOUT,9036)I,Y(I),X(I),D(I)
 9036     FORMAT('I,Y(I),X(I),D(I) = ',I8,2E15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCMP2
      SUBROUTINE DPCNF2(Y,N,X,N2,   &
                        PID,IVARID,IVARI2,NREPL,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICASAN,ICASAT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE GENERATES CONFIDENCE LIMITS
!              FOR THE MEAN
!              FOR THE DATA IN THE INPUT VECTOR Y.
!     NOTE--ASSUMPTION--MODEL IS   RESPONSE = CONSTANT + ERROR.
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR
!                                OF EQUALLY-SPACED OBSERVATIONS
!                                TO BE SMOOTHED.
!                       N      = THE INTEGER NUMBER OF
!                                OBSERVATIONS IN THE VECTOR Y.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1994. DPWRST: 'BUG ' => 'WRIT'
!     UPDATED         --FEBRUARY  1994. E FORMAT => G FORMAT
!     UPDATED         --MARCH     1999. DIFFERENCE OF MEANS CASE
!     UPDATED         --FEBRUARY  2003. SUPPORT FOR CUTL..,CUTH..
!     UPDATED         --OCTOBER   2003. SUPPORT FOR HTML, LATEX OUTPUT
!     UPDATED         --AUGUST    2005. FOR DIFF OF MEANS CASE:
!                                       A) HTML PRINTED OUT WRONG
!                                          VALUES FOR SECOND VARIABLE
!                                       B) ADDED AN ELSE STATEMENT TO
!                                          ACTIVATE THE ASCII OUTPUT
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!     UPDATED         --MARCH     2010. USE DPDTA2 AND DPDTA4 TO
!                                       GENERATE OUTPUT (ADDS RTF
!                                       SUPPORT)
!     UPDATED         --MARCH     2010. SOME MODIFICATIONS TO THE
!                                       OUTPUT (AESTHETIC, NOT
!                                       SUBSTANTIVE)
!     UPDATED         --APRIL     2013. SUPPORT FOR ONE-SIDED INTERVALS
!     UPDATED         --AUGUST    2017. SUPPORT FOR LOGNORMAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASAT
      CHARACTER*4 ICASA2
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION PID(*)
!
      PARAMETER (NUMALP=8)
!
      DIMENSION CONF(NUMALP)
      DIMENSION T(NUMALP)
      DIMENSION TSDM(NUMALP)
      DIMENSION ALOWER(NUMALP)
      DIMENSION AUPPER(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCN'
      ISUBN2='F2  '
!
      IERROR='NO'
      IWRITE='OFF'
      ICASA2='CONF'
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      CONF(1)=50.0
      CONF(2)=75.0
      CONF(3)=90.0
      CONF(4)=95.0
      CONF(5)=99.0
      CONF(6)=99.9
      CONF(7)=99.99
      CONF(8)=99.999
!
      CUTL90=CPUMIN
      CUTU90=CPUMIN
      CUTL95=CPUMIN
      CUTU95=CPUMIN
      CUTL99=CPUMIN
      CUTU99=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CNF2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCNF2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)N,MAXNXT,IBUGA3
   52   FORMAT('N,IBUGA3 = ',I8,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,3E15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
        WRITE(ICOUT,58)ICASAN
   58   FORMAT('ICASAN   = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(ICASAN.EQ.'TWOV')GO TO 2000
      IF(ICASAN.EQ.'LOGN')GO TO 3000
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN CONFIDENCE LIMITS FOR THE MEAN--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)N
  105   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
  131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
      IERROR='YES'
  139 CONTINUE
!
!               ***************************************************
!               **  STEP 3--                                     **
!               **  COMPUTE THE MEAN.                            **
!               **  COMPUTE THE STANDARD DEVIATION.              **
!               **  COMPUTE THE STANDARD DEVIATION OF THE MEAN.  **
!               ***************************************************
!
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y,N,IWRITE,YMEAN,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,YSD,IBUGA3,IERROR)
      AN=N
      YSDMEA=YSD/SQRT(AN)
!
!               ***************************************
!               **  STEP 4--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1400 I=1,8
        PCONF=CONF(I)/100.0
        CDF=PCONF
        IF(ICASAT.EQ.'TWOS')CDF=0.5+PCONF/2.0
        NM1=N-1
        CALL TPPF(CDF,REAL(NM1),T(I))
        TSDM(I)=T(I)*YSDMEA
        IF(ICASAT.EQ.'TWOS')THEN
          ALOWER(I)=YMEAN-TSDM(I)
          AUPPER(I)=YMEAN+TSDM(I)
        ELSEIF(ICASAT.EQ.'LOWE')THEN
          ALOWER(I)=YMEAN-TSDM(I)
          AUPPER(I)=CPUMIN
        ELSEIF(ICASAT.EQ.'UPPE')THEN
          ALOWER(I)=CPUMIN
          AUPPER(I)=YMEAN+TSDM(I)
        ENDIF
 1400 CONTINUE
      CUTL90=ALOWER(3)
      CUTU90=AUPPER(3)
      CUTL95=ALOWER(4)
      CUTU95=AUPPER(4)
      CUTL99=ALOWER(5)
      CUTU99=AUPPER(5)
      CTL999=ALOWER(6)
      CTU999=AUPPER(6)
!
!     ADD A FUDGE FACTOR SO THAT CONFIDENCE LEVEL WILL
!     BE PRINTED CORRECTLY TO 3 DECIMAL PLACES.
!
      CONF(1)=50.0001
      CONF(2)=75.0001
      CONF(3)=90.0001
      CONF(4)=95.0001
      CONF(5)=99.0001
      CONF(6)=99.9001
      CONF(7)=99.9901
      CONF(8)=99.9991
!
!               ****************************
!               **  STEP 5--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE='Confidence Limits for the Mean'
      NCTITL=30
      IF(ICASAT.EQ.'TWOS')THEN
        ITITLZ='(Two-Sided)'
        NCTITZ=11
      ELSEIF(ICASAT.EQ.'LOWE')THEN
        ITITLZ='(Lower One-Sided)'
        NCTITZ=17
      ELSEIF(ICASAT.EQ.'UPPE')THEN
        ITITLZ='(Upper One-Sided)'
        NCTITZ=17
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        NRESP=1
        DO 4101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+NRESP
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 4101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation of the Mean:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=YSDMEA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='5A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='5B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDT11(CONF,T,TSDM,ALOWER,AUPPER,   &
                  ICASA2,ICAPSW,ICAPTY,NUMDIG,  &
                  ISUBRO,IBUGA3,IERROR)
!
      GO TO 9000
!
 2000 CONTINUE
!
!               ********************************************
!               **  STEP 6--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1.OR.N2.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2111)
 2111   FORMAT('***** ERROR IN DIIFERENCE OF MEANS CONFIDENCE LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2112)
 2112   FORMAT('      BOTH VARIABLES MUST HAVE AT LEAST TWO ',   &
               'OBSERVATIONS.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2113)IVARID(1),IVARI2(1),N
 2113   FORMAT('      SAMPLE SIZE FOR ',A4,A4,' = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2114)IVARID(2),IVARI2(2),N2
 2114   FORMAT('      SAMPLE SIZE FOR ',A4,A4,' = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 7--                                     **
!               **  COMPUTE THE MEAN.                            **
!               **  COMPUTE THE STANDARD DEVIATION.              **
!               **  COMPUTE THE STANDARD DEVIATION OF THE MEAN.  **
!               ***************************************************
!
!
      ISTEPN='7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y,N,IWRITE,YMEAN1,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,YSD1,IBUGA3,IERROR)
      AN1=N
      YTEMP1=YSD1**2/AN1
!
      CALL MEAN(X,N2,IWRITE,YMEAN2,IBUGA3,IERROR)
      CALL SD(X,N2,IWRITE,YSD2,IBUGA3,IERROR)
      AN2=N2
      YTEMP2=YSD2**2/AN2
!
      YDIFF=YMEAN1-YMEAN2
      YSTERR=SQRT(YTEMP1 + YTEMP2)
      TERM1=(YTEMP1 + YTEMP2)**2
      TERM2=YTEMP1*YTEMP1/(AN1-1.0) + YTEMP2*YTEMP2/(AN2-1.0)
      V=TERM1/TERM2
      IV=INT(V+0.5)
!
!               ***************************************
!               **  STEP 8--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 2400 I=1,8
        PCONF=CONF(I)/100.0
        CDF=PCONF
        IF(ICASAT.EQ.'TWOS')CDF=0.5+PCONF/2.0
        CALL TPPF(CDF,REAL(IV),T(I))
        TSDM(I)=T(I)*YSTERR
        IF(ICASAT.EQ.'TWOS')THEN
          ALOWER(I)=YDIFF-TSDM(I)
          AUPPER(I)=YDIFF+TSDM(I)
        ELSEIF(ICASAT.EQ.'LOWE')THEN
          ALOWER(I)=YDIFF-TSDM(I)
          AUPPER(I)=CPUMIN
        ELSEIF(ICASAT.EQ.'UPPE')THEN
          ALOWER(I)=CPUMIN
          AUPPER(I)=YDIFF+TSDM(I)
        ENDIF
 2400 CONTINUE
      CUTL90=ALOWER(3)
      CUTU90=AUPPER(3)
      CUTL95=ALOWER(4)
      CUTU95=AUPPER(4)
      CUTL99=ALOWER(5)
      CUTU99=AUPPER(5)
      CTL999=ALOWER(6)
      CTU999=AUPPER(6)
!
!               ****************************
!               **  STEP 9--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='9'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE='Welch-Satterthwaite Confidence Limits for the Difference'
      NCTITL=56
      IF(ICASAT.EQ.'TWOS')THEN
        ITITLZ='Between Means (Two-Sided)'
        NCTITZ=25
      ELSEIF(ICASAT.EQ.'LOWE')THEN
        ITITLZ='Between Means (Lower One-Sided)'
        NCTITZ=31
      ELSEIF(ICASAT.EQ.'UPPE')THEN
        ITITLZ='Between Means (Upper One-Sided)'
        NCTITZ=31
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable 1: '
      WRITE(ITEXT(ICNT)(22:25),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable 2: '
      WRITE(ITEXT(ICNT)(22:25),'(A4)')IVARID(2)(1:4)
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARI2(2)(1:4)
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        NRESP=2
        DO 5101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+NRESP
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 5101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Variable 1:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Variable 2:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Difference Between Sample Means:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=YDIFF
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Standard Error:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=YSTERR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Degrees of Freedom:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=REAL(IV)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 5210 I=1,NUMROW
        NTOT(I)=15
 5210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='9A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='9B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASA2='CON2'
      CALL DPDT11(CONF,T,TSDM,ALOWER,AUPPER,   &
                  ICASA2,ICAPSW,ICAPTY,NUMDIG, &
                  ISUBRO,IBUGA3,IERROR)
!
      GO TO 9000
!
!               ********************************************
!               **  STEP 10--                             **
!               **  LOGNORMAL CONFIDENCE LIMITS CASE      **
!               ********************************************
!
 3000 CONTINUE
!
      ISTEPN='10'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3001)
 3001   FORMAT('***** ERROR IN LOGNORMAL CONFIDENCE LIMITS FOR ',   &
               'THE MEAN--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)N
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 3005 I=2,N
        IF(Y(I).NE.HOLD)GO TO 3009
 3005 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,3001)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
      IERROR='YES'
 3009 CONTINUE
!
!               ***************************************************
!               **  STEP 11--                                    **
!               **  TAKE THE LOGS OF THE DATA.                   **
!               **  COMPUTE THE MEAN.                            **
!               **  COMPUTE THE STANDARD DEVIATION.              **
!               **  COMPUTE THE STANDARD DEVIATION OF THE MEAN.  **
!               ***************************************************
!
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y,N,IWRITE,YMEAN,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,YSD,IBUGA3,IERROR)
!
      DO 3010 I=1,N
        IF(Y(I).GT.0.0)THEN
          Y(I)=LOG(Y(I))
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,3001)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,3013)I
 3013     FORMAT('     ROW ',I8,' HAS A NON-POSITIVE VALUE.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,3015)Y(I)
 3015     FORMAT('     THE VALUE IS ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
 3010 CONTINUE
!
      AN=N
      CALL MEAN(Y,N,IWRITE,YMNLOG,IBUGA3,IERROR)
      CALL SD(Y,N,IWRITE,YSDLOG,IBUGA3,IERROR)
      S2=YSDLOG**2
      TERM1=S2/2.0
      YSDMEA=SQRT((S2/AN) + (S2**2/(2.0*(AN-1.0))))
!
!               ***************************************
!               **  STEP 4--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      YMEANC=YMNLOG + TERM1
      DO 3400 I=1,8
        PCONF=CONF(I)/100.0
        CDF=PCONF
        IF(ICASAT.EQ.'TWOS')CDF=0.5+PCONF/2.0
        NM1=N-1
        CALL TPPF(CDF,REAL(NM1),T(I))
        TSDM(I)=T(I)*YSDMEA
        IF(ICASAT.EQ.'TWOS')THEN
          ALOWER(I)=EXP(YMEANC-TSDM(I))
          AUPPER(I)=EXP(YMEANC+TSDM(I))
        ELSEIF(ICASAT.EQ.'LOWE')THEN
          ALOWER(I)=EXP(YMEANC-TSDM(I))
          AUPPER(I)=CPUMIN
        ELSEIF(ICASAT.EQ.'UPPE')THEN
          ALOWER(I)=CPUMIN
          AUPPER(I)=EXP(YMEANC+TSDM(I))
        ENDIF
 3400 CONTINUE
      CUTL90=ALOWER(3)
      CUTU90=AUPPER(3)
      CUTL95=ALOWER(4)
      CUTU95=AUPPER(4)
      CUTL99=ALOWER(5)
      CUTU99=AUPPER(5)
      CTL999=ALOWER(6)
      CTU999=AUPPER(6)
!
!     ADD A FUDGE FACTOR SO THAT CONFIDENCE LEVEL WILL
!     BE PRINTED CORRECTLY TO 3 DECIMAL PLACES.
!
      CONF(1)=50.0001
      CONF(2)=75.0001
      CONF(3)=90.0001
      CONF(4)=95.0001
      CONF(5)=99.0001
      CONF(6)=99.9001
      CONF(7)=99.9901
      CONF(8)=99.9991
!
!               ****************************
!               **  STEP 5--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      IF(ICASAT.EQ.'TWOS')THEN
        ITITLE='Two-Sided Confidence Limits for the Mean'
        NCTITL=40
        ITITLZ='(Log-Normal, Modified Cox Method)'
        NCTITZ=33
      ELSEIF(ICASAT.EQ.'LOWE')THEN
        ITITLE='Lower One-Sided Confidence Limits for the Mean'
        NCTITL=46
        ITITLZ='(Log-Normal, Modified Cox Method)'
        NCTITZ=33
      ELSEIF(ICASAT.EQ.'UPPE')THEN
        ITITLE='Upper One-Sided Confidence Limits for the Mean'
        NCTITL=46
        ITITLZ='(Log-Normal, Modified Cox Method)'
        NCTITZ=33
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        NRESP=1
        DO 3491 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+NRESP
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 3491   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean (Raw Data):'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=YMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation (Raw Data):'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=YSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean (Log Data):'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=YMNLOG
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Correction Term (s*2/2):'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=TERM1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation (Log Data):'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=YSDLOG
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation of the Mean:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=YSDMEA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 3493 I=1,NUMROW
        NTOT(I)=15
 3493 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='5A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='5B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDT11(CONF,T,TSDM,ALOWER,AUPPER,   &
                  ICASA2,ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGA3,IERROR)
!
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CNF2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCNF2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,N2,IBUGA3,IERROR
 9012   FORMAT('N,N2,IBUGA3,IERROR = ',2I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 9016 I=1,N
          WRITE(ICOUT,9017)I,Y(I)
 9017     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
 9016   CONTINUE
        IF(ICASAN.EQ.'TWOV')THEN
          DO 9026 I=1,N2
            WRITE(ICOUT,9027)I,X(I)
 9027       FORMAT('I,Y2(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
 9026     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCNF2
      SUBROUTINE DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASPL,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPCONF.  THIS ROUTINE
!              UPDATES THE PARAMETERS "CUTLOW90", CUTUPP90",
!              "CUTLOW95", CUTUPP95", "CUTLOW99", AND "CUTUPP99"
!              AFTER COMPUTING THE CONFIDENCE LIMITS FOR THE MEAN
!              (OR FOR THE DIFFERENCE OF THE MEANS).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/03
!     ORIGINAL VERSION--MARCH     2010.
!     UPDATED         --AUGUST    2019. ADD CTL999, CTU999
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      SAVE IOUNI1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CNF3')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCNF3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)CUTL90,CUTL95,CUTL99
   54   FORMAT('CUTL90,CUTL95,CUTL99 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)CUTU90,CUTU95,CUTU99
   56   FORMAT('CUTU90,CUTU95,CUTU99 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,58)ICASPL
   58   FORMAT('ICASPL = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CNF3')THEN
            ISTEPN='2A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,201)IOUNI1
  201       FORMAT('AFTER CALL DPOPFI, IOUNI1 = ',I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,295)
  295     FORMAT(7X,'CUTLOW90',7X,'CUTUPP90',7X,'CUTLOW95',   &
                 7X,'CUTUPP95',7X,'CUTLOW99',7X,'CUTUPP99')
        ENDIF
        WRITE(IOUNI1,299)CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                         CTL999,CTU999
  299   FORMAT(9E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
!
        IF(CUTL90.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW90'
          VALUE0=CUTL90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU90.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP90'
          VALUE0=CUTU90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL95.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW95'
          VALUE0=CUTL95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU95.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP95'
          VALUE0=CUTU95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL99.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW99'
          VALUE0=CUTL99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU99.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP99'
          VALUE0=CUTU99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CTL999.NE.CPUMIN)THEN
          IH='CTLO'
          IH2='W999'
          VALUE0=CTL999
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CTU999.NE.CPUMIN)THEN
          IH='CTUP'
          IH2='P999'
          VALUE0=CTU999
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CNF3')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IOUNI1
  301       FORMAT('AFTER CALL DPCLFI, IOUNI1 = ',I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CNF3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPCNF3--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCNF3
      SUBROUTINE DPCOCH(MAXNXT,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT COCHRAN TEST ANALYSIS OF A RANDOMIZED COMPLETE
!              BLOCK DESIGN WHERE THE OUTCOME CAN BE EITHER "SUCCESS" OR
!              "FAILURE" (OR ANY TWO MUTUALLY EXCLUSIVE OUTCOMES).
!              THESE ARE CODED AS ZERO AND ONE.  IN DATAPLOT, THE COLUMNS
!              REPRESENT TREATMENTS AND THE ROWS REPRESENT SUBJECTS.
!     EXAMPLE--COCHRAN TEST Y X1 X2
!     REFERENCE--W. J. CONOVER, 1999, "PRACTICAL NONPARAMETRIC
!                STATISTICS", THIRD EDITION, WILEY, PP. 251-256.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER   2004.
!     UPDATED         --DECEMBER  2005. RECODE TO USE
!                                         COCHRAN TEST Y X1 X2
!                                       INSTEAD OF
!                                         COCHRAN TEST Y X1 ... XK
!                                       IN ORDER TO BE CONSISTENT
!                                       WITH OTHER DATAPLOT COMMANDS.
!     UPDATED         --APRIL     2011. USE DPPARS AND DPPAR3
!     UPDATED         --JULY      2019. TWEAK USE OF SCRATCH SPACE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      LOGICAL IFRST
      LOGICAL ILAST
      CHARACTER*4 IFLAGU
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      PARAMETER(MAXCOC=20)
!
      DIMENSION Z(MAXOBV,MAXCOC)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
!
      EQUIVALENCE(GARBAG(IGARB1),XTEMP1(1))
      EQUIVALENCE(GARBAG(IGARB2),XTEMP2(1))
      EQUIVALENCE(GARBAG(IGARB3),XTEMP3(1))
      EQUIVALENCE(GARBAG(IGARB4),XTEMP4(1))
      EQUIVALENCE(GARBAG(IGARB5),XTEMP5(1))
      EQUIVALENCE(GARBAG(IGARB6),Z(1,1))
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='CH  '
      IFOUND='YES'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ******************************************
!               **  TREAT THE COCHRAN TEST CASE         **
!               ******************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'COCH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUBQ,ISUBRO,MAXNXT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICAPSW,ICAPTY,IFORSW
   53   FORMAT('ICAPSW,ICAPTY,IFORSW = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'COCH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COCHRAN TEST'
      MINNA=3
      MAXNA=100
      MINNVA=3
      MAXNVA=3
      IFLAGE=1
      IFLAGM=0
      MINN2=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'COCH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               **********************************
!               **  STEP 52--                   **
!               **  CARRY OUT THE DURBIN TEST   **
!               **********************************
!
      ISTEPN='52'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'DURB')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      NUMVA2=3
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y,X,XTEMP2,NS1,NS1,NS1,ICASE,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'COCH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5211)
 5211   FORMAT('***** FROM DPDURB, AS WE ARE ABOUT TO CALL DPCOC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5212)NS1
 5212   FORMAT('NS1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 5215 I=1,NS1
          WRITE(ICOUT,5216)I,Y(I),X(I),XTEMP2(I)
 5216     FORMAT('I,Y(I),X(I),XTEMP2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 5215   CONTINUE
      ENDIF
!
      CALL DPCOC2(Y,X,XTEMP2,NS1,IVARN1,IVARN2,   &
                  Z,XTEMP1,XTEMP3,XTEMP4,XTEMP5,   &
                  MAXNXT,MAXCOC,   &
                  STATVA,STATCD,PVAL,   &
                  CUT0,CUT50,CUT75,CUT90,CUT95,CUT975,   &
                  CUT99,CUT999,   &
                  ICAPSW,ICAPTY,IFORSW,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IFLAGU='ON'
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPFRT5(STATVA,STATCD,PVAL,   &
                  CUT0,CUT50,CUT75,CUT90,CUT95,   &
                  CUT975,CUT99,CUT999,   &
                  IFLAGU,IFRST,ILAST,   &
                  IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'COCH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOCH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOCH
      SUBROUTINE DPCOC2(Y,BLOCK,TREAT,N,IVARID,IVARI2,   &
                        Z,C,R,TEMP1,TEMP2,   &
                        MAXNXT,MAXCOC,   &
                        STATVA,STATCD,PVAL,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,CUT975,   &
                        CUT99,CUT999,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT COCHRAN'S TEST
!              ANALYSIS OF A RANDOMIZED COMPLETE BLOCK DESIGN
!              WHERE THE OUTCOME CAN BE EITHER "SUCCESS" OR
!              "FAILURE" (OR ANY TWO MUTUALLY EXCLUSIVE OUTCOMES).
!              THESE ARE CODED AS ZERO AND ONE.
!              IN DATAPLOT, THE COLUMNS REPRESENT TREATMENTS AND
!              THE ROWS REPRESENT SUBJECTS.
!
!              THE TEST STATISTIC IS:
!
!                 T = c*(c-1)*SUM[J=1 to c][(C(j) - N/c)**2]/
!                     SUM[i=1 to r][R(i)*(c - R(i))]
!
!              WITH c, r, C(j), R(i) AND N denoting the
!              NUMBER OF COLUMNS, NUMBER OF ROWS, COLUMN TOTALS,
!              ROW TOTALS, AND GRAND TOTAL RESPECTIVELY.
!
!              THE CRITICAL VALUE IS:
!
!                 CHSPPF(c-1,ALPHA)
!
!     EXAMPLE--COCHRAN TEST Y X1 X2
!     REFERENCE--W. J., CONOVER, 1999, "PRACTICAL NON-PARAMETRIC
!                STATSTICS", THIRD EDITION, WILEY, PP. 251-256.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER   2004.
!     UPDATED         --DECEMBER  2005. RECODE TO USE
!                                         COCHRAN TEST Y X1 X2
!                                       INSTEAD OF
!                                         COCHRAN TEST Y X1 ... XK
!                                       IN ORDER TO BE CONSISTENT
!                                       WITH OTHER DATAPLOT COMMANDS.
!     UPDATED         --APRIL     2011. USE DPDTA1 AND DPDTA4 TO PRINT
!                                       TABLES.  THIS ADDS RTF SUPPORT
!                                       AND SPECIFICATION OF THE NUMBER
!                                       OF DIGITS.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION BLOCK(*)
      DIMENSION TREAT(*)
      DIMENSION C(*)
      DIMENSION R(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION Z(MAXNXT,MAXCOC)
!
      PARAMETER (NUMALP=8)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=6)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA/   &
       0.0, 50.0, 75.0, 90.0, 95.0, 97.5, 99.0, 99.9/
!
      ISUBN1='DPCO'
      ISUBN2='C2  '
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCOC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),BLOCK(I),TREAT(I)
   57     FORMAT('I,Y(I),BLOCK(I),TREAT(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'COC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ALOW=Y(1)
      AHIGH=CPUMAX
      IDIST=1
!
      DO 110 I=1,N
        ATEMP=Y(I)
        IF(IDIST.EQ.1)THEN
          IF(ATEMP.EQ.ALOW)THEN
            GO TO 110
          ELSE
            IDIST=IDIST+1
            AHIGH=ATEMP
            GO TO 110
          ENDIF
        ELSEIF(IDIST.EQ.2)THEN
          IF(ATEMP.EQ.ALOW .OR. ATEMP.EQ.AHIGH)THEN
            GO TO 110
          ELSE
            IDIST=IDIST+1
            GO TO 129
          ENDIF
        ELSE
          GO TO 129
        ENDIF
  110 CONTINUE
!
  129 CONTINUE
!
      IF(IDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM COCHRAN TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,163)
  163   FORMAT('      MORE THAN TWO DISTINCT VALUES DETECTED IN')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,165)
  165   FORMAT('      INPUT DATA.  THE COCHRAN TEST IS FOR')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,167)
  167   FORMAT('      DICHOTOMOUS DATA.  NOTHING DONE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ALOW.GT.AHIGH)THEN
        ATEMP=ALOW
        ALOW=AHIGH
        AHIGH=ATEMP
      ENDIF
!
      DO 220 I=1,N
        IF(Y(I).EQ.ALOW)Y(I)=0.0
        IF(Y(I).EQ.AHIGH)Y(I)=1.0
  220 CONTINUE
!
!               ******************************************
!               **  STEP 31--                          **
!               **  COMPUTE DISTINCT ROWS AND COLUMNS. **
!               **  INITIALIZE Z MATRIX TO -99 SO WE   **
!               **  CAN DETECT EMPTY CELLS (COCHRAN    **
!               **  TEST ASSUMES COMPLETE BLOCKS)      **
!               *****************************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'COC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL CODE(BLOCK,N,IWRITE,TEMP1,TEMP2,MAXNXT,IBUGA3,IERROR)
      DO 301 I=1,N
        BLOCK(I)=TEMP1(I)
  301 CONTINUE
      CALL MAXIM(BLOCK,N,IWRITE,XMAX,IBUGA3,IERROR)
      NROW=INT(XMAX+0.5)
!
      CALL CODE(TREAT,N,IWRITE,TEMP1,TEMP2,MAXNXT,IBUGA3,IERROR)
      DO 303 I=1,N
        TREAT(I)=TEMP1(I)
  303 CONTINUE
      CALL MAXIM(TREAT,N,IWRITE,XMAX,IBUGA3,IERROR)
      NCOL=INT(XMAX+0.5)
!
      DO 310 J=1,NCOL
        DO 320 I=1,NROW
          Z(I,J)=-99.0
  320   CONTINUE
  310 CONTINUE
!
      DO 330 I=1,N
        IROW=INT(BLOCK(I)+0.5)
        ICOL=INT(TREAT(I)+0.5)
        Z(IROW,ICOL)=Y(I)
  330 CONTINUE
!
      DO 340 J=1,NCOL
        DO 350 I=1,NROW
          IF(Z(I,J).LT.-0.5)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,161)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,363)
  363       FORMAT('      AN INCOMPLETE BLOCK DESIGN WAS DETECTED.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,365)IROW,ICOL
  365       FORMAT('      ROW ',I8,' AND COLUMM ',I8,' WAS EMPTY.')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
  350   CONTINUE
  340 CONTINUE
      IF(NROW*NCOL.NE.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,161)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,363)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,367)NROW,NCOL
  367   FORMAT('      THE NUMBER OF ROWS (',I8,') TIMES THE ',   &
               'NUMBER OF COLUMMS ( ',I8,')')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,369)N
  369   FORMAT('      DOES NOT EQUAL THE SAMPLE SIZE (',I8,').')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               ******************************
!               **  STEP 41--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR COCHRAN TEST        **
!               ******************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'COC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
!  STEP 1: COMPUTE ROW AND COLUMN TOTALS
!
      AN=0.0
      DO 410 J=1,NCOL
        SUM1=0.0
        DO 420 I=1,NROW
          SUM1=SUM1 + Z(I,J)
  420   CONTINUE
        C(J)=SUM1
        AN=AN + SUM1
  410 CONTINUE
!
      DO 460 I=1,NROW
        SUM1=0.0
        DO 470 J=1,NCOL
          SUM1=SUM1 + Z(I,J)
  470   CONTINUE
        R(I)=SUM1
  460 CONTINUE
!
!  STEP 2: COMPUTE TEST STATISTIC
!
      ANCOL=REAL(NCOL)
      ANROW=REAL(NROW)
!
      ANUM=0.0
      DO 510 J=1,NCOL
        ANUM=ANUM + (C(J) - AN/ANCOL)**2
  510 CONTINUE
!
      ADEN=0.0
      DO 520 I=1,NROW
        ADEN=ADEN + R(I)*(ANCOL - R(I))
  520 CONTINUE
!
      STATVA=ANCOL*(ANCOL-1.0)*ANUM/ADEN
                                                                                                                                  
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COC2')THEN
        WRITE(ICOUT,531)ANUM,ADEN,STATVA
  531   FORMAT('ANUM,ADEN,STATVA = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 541 J=1,NCOL
          WRITE(ICOUT,543)J,C(J)
  543     FORMAT('J,C(J) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
  541   CONTINUE
        DO 551 I=1,NROW
          WRITE(ICOUT,553)I,R(I)
  553     FORMAT('I,R(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
  551   CONTINUE
      ENDIF
!
      NUMDF1=NCOL-1
      CALL CHSCDF(STATVA,NUMDF1,STATCD)
      PVAL=1.0 - STATCD
!
      CUT0=0.0
      CALL CHSPPF(.50,NUMDF1,CUT50)
      CALL CHSPPF(.75,NUMDF1,CUT75)
      CALL CHSPPF(.90,NUMDF1,CUT90)
      CALL CHSPPF(.95,NUMDF1,CUT95)
      CALL CHSPPF(.975,NUMDF1,CUT975)
      CALL CHSPPF(.99,NUMDF1,CUT99)
      CALL CHSPPF(.999,NUMDF1,CUT999)
!
!               ******************************
!               **   STEP 43--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR COCHRAN  TEST      **
!               ******************************
!
      ISTEPN='43'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE=   &
       'Cochran Test for Two-Way Randomized Complete Block Designs'
      NCTITL=58
      ITITLZ='(Dichotomous Data)'
      NCTITZ=28
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='First Group-ID Variable: '
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(2)(1:4)
      WRITE(ITEXT(ICNT)(30:33),'(A4)')IVARI2(2)(1:4)
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Group-ID Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARID(3)(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI2(3)(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Treatments Have Identical Effects'
      NCTEXT(ICNT)=37
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Treatments Do Not Have Identical Effects'
      NCTEXT(ICNT)=44
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Blocks:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NROW)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Treatments:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=REAL(NCOL)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Cochran Test Statistic:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=PVAL
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DUR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITLE=' '
      NCTITL=0
      ITITL9=' '
      NCTIT9=0
      ITITLE='Percent Points of the Chi-Square Reference Distribution'
      NCTITL=55
      NUMLIN=1
      NUMROW=8
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      IDIGIT(3)=3
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=RND(CUT0,IDIGIT(J))
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=RND(CUT50,IDIGIT(J))
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=RND(CUT75,IDIGIT(J))
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=RND(CUT90,IDIGIT(J))
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=RND(CUT95,IDIGIT(J))
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=RND(CUT975,IDIGIT(J))
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=RND(CUT99,IDIGIT(J))
            ELSEIF(I.EQ.8)THEN
              AMAT(I,J)=RND(CUT999,IDIGIT(J))
            ENDIF
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DUR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CDF1=CUT90
      CDF2=CUT95
      CDF3=CUT975
      CDF4=CUT99
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper 1-Tailed Test)'
      NCTITL=33
      NUMLIN=1
      NUMROW=4
      NUMCOL=4
      ITITL2(1,1)='Alpha'
      ITITL2(1,2)='CDF'
      ITITL2(1,3)='Critical Value'
      ITITL2(1,4)='Conclusion'
      NCTIT2(1,1)=5
      NCTIT2(1,2)=3
      NCTIT2(1,3)=14
      NCTIT2(1,4)=10
!
      NMAX=0
      DO 4321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
        IF(I.EQ.3)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=3
        ITYPCO(I)='ALPH'
 4321 CONTINUE
      ITYPCO(3)='NUME'
      IDIGIT(1)=0
      IDIGIT(2)=0
      DO 4323 I=1,NUMROW
        DO 4325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 4325   CONTINUE
 4323 CONTINUE
      IVALUE(1,1)='10%'
      IVALUE(2,1)='5%'
      IVALUE(3,1)='2.5%'
      IVALUE(4,1)='1%'
      IVALUE(1,2)='90%'
      IVALUE(2,2)='95%'
      IVALUE(3,2)='97.5%'
      IVALUE(4,2)='99%'
      NCVALU(1,1)=3
      NCVALU(2,1)=2
      NCVALU(3,1)=4
      NCVALU(4,1)=2
      NCVALU(1,2)=3
      NCVALU(2,2)=3
      NCVALU(3,2)=5
      NCVALU(4,2)=3
      IVALUE(1,4)='Accept H0'
      IVALUE(2,4)='Accept H0'
      IVALUE(3,4)='Accept H0'
      IVALUE(4,4)='Accept H0'
      NCVALU(1,4)=9
      NCVALU(2,4)=9
      NCVALU(3,4)=9
      NCVALU(4,4)=9
      IF(STATVA.GT.CUT90)IVALUE(1,4)='Reject H0'
      IF(STATVA.GT.CUT95)IVALUE(2,4)='Reject H0'
      IF(STATVA.GT.CUT975)IVALUE(3,4)='Reject H0'
      IF(STATVA.GT.CUT99)IVALUE(4,4)='Reject H0'
      AMAT(1,3)=RND(CUT90,IDIGIT(3))
      AMAT(2,3)=RND(CUT95,IDIGIT(3))
      AMAT(3,3)=RND(CUT975,IDIGIT(3))
      AMAT(4,3)=RND(CUT99,IDIGIT(3))
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=1500
      IWRTF(2)=IWRTF(1)+1500
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='42E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'COC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'COC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)NROW,NCOL,IBUGA3,IERROR
 9012   FORMAT('NROW,NCOL,IBUGA3,IERROR = ',2I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)STATVA,STATCD,PVAL
 9014   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOC2
