      SUBROUTINE DPCODS(ICASE,D,P,IBUGD2,ISUBRO,IERROR)
!
!     PURPOSE--CONVERT AN INPUT X OR Y VALUE (IN DATA UNITS)
!              (RELATIVE TO THE LAST PLOT THAT APPEARED)
!              INTO ABSOLUTE (0. TO 100.) X OR Y SCREEN UNITS.
!     NOTE--CHARACTER*1 ICASE WILL BE EITHER 'X' OR 'Y'
!     ORIGINAL VERSION--NOVEMBER 1992
!     UPDATED         --MARCH    2001 SUPPORT FOR LOG SCALES (BUT NOT
!                                     WEIBULL AND NORMAL)
!     UPDATED         --APRIL    2010 USE "FX1MAX" AND "FY1MAX" INSTEAD
!                                     OF "FX2MAX" AND "FY2MAX".  BUG
!                                     IF "X1TIC MARK OFFSET" USED
!                                     INSTEAD OF "XTIC MARK OFFSET
!                                     (UPPER LIMIT WILL NOT INCORPORATE
!                                     THE OFFSET).
!
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*1 ICASE
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOPC.INC'
!
!-----COMMON VARIABLES (GENERAL)-----------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGD2.NE.'ON'.AND.ISUBRO.NE.'CODS')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCODS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IBUGD2,ISUBRO,IERROR
   53 FORMAT('IBUGD2,ISUBRO,IERROR = ',2(A4,2X),A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ICASE,D,P
   54 FORMAT('ICASE,D,P = ',A1,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)PXMIN,PXMAX,PYMIN,PYMAX
   61 FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)FX1MIN,FX1MAX,FY1MIN,FY2MAX
   62 FORMAT('FX1MIN,FX2MAX,FY1MIN,FY2MAX = ',4G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)GX1MIN,GX2MAX,GY1MIN,GY2MAX
   63 FORMAT('GX1MIN,GX2MAX,GY1MIN,GY2MAX = ',4G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)IX1TSC,IY1TSC
   64 FORMAT('IX1TSC,IY1TSC = ',2(A4,2X))
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      IF(ICASE.EQ.'X')THEN
        IF(IX1TSC.EQ.'LOG')THEN
          IF(FX1MIN.LE.0.0 .OR. D.LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,121)
  121 FORMAT('***** FROM DPCODS: NEGATIVE NUMBER ENCOUNTERED FOR')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,123)
  123 FORMAT('      EITHER THE AXIS MINIMUM OR THE X COORDINATE')
            CALL DPWRST('XXX','BUG ')
            XFRACT=(D-FX1MIN)/(FX1MAX-FX1MIN)
            P=PXMIN+XFRACT*(PXMAX-PXMIN)
            GO TO 299
          ENDIF
          ARG1=LOG10(FX1MIN)
          ARG2=LOG10(FX1MAX)
          ARG3=LOG10(D)
          XFRACT=(ARG3-ARG1)/(ARG2-ARG1)
          P=PXMIN+XFRACT*(PXMAX-PXMIN)
        ELSEIF(IX1TSC.EQ.'WEIB')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
  111 FORMAT('***** FROM DPCODS: WEIBULL SCALE NOT SUPPORTED FOR ',   &
             'X AXIS')
          XFRACT=(D-FX1MIN)/(FX1MAX-FX1MIN)
          P=PXMIN+XFRACT*(PXMAX-PXMIN)
        ELSEIF(IX1TSC.EQ.'NORM')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101 FORMAT('***** FROM DPCODS: NORMAL SCALE NOT SUPPORTED FOR ',   &
             'X AXIS')
          CALL DPWRST('XXX','BUG ')
          XFRACT=(D-FX1MIN)/(FX1MAX-FX1MIN)
          P=PXMIN+XFRACT*(PXMAX-PXMIN)
        ELSE
          XFRACT=(D-FX1MIN)/(FX1MAX-FX1MIN)
          P=PXMIN+XFRACT*(PXMAX-PXMIN)
        ENDIF
      ELSE
        IF(IY1TSC.EQ.'LOG')THEN
          IF(FY1MIN.LE.0.0 .OR. D.LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,221)
  221 FORMAT('***** FROM DPCODS: NEGATIVE NUMBER ENCOUNTERED FOR')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,223)
  223 FORMAT('      EITHER THE AXIS MINIMUM OR THE Y COORDINATE')
            CALL DPWRST('XXX','BUG ')
            YFRACT=(D-FY1MIN)/(FY1MAX-FY1MIN)
            P=PYMIN+YFRACT*(PYMAX-PYMIN)
            GO TO 299
          ENDIF
          ARG1=LOG10(FY1MIN)
          ARG2=LOG10(FY1MAX)
          ARG3=LOG10(D)
          YFRACT=(ARG3-ARG1)/(ARG2-ARG1)
          P=PYMIN+YFRACT*(PYMAX-PYMIN)
        ELSEIF(IY1TSC.EQ.'WEIB')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211 FORMAT('***** FROM DPCODS: WEIBULL SCALE NOT SUPPORTED FOR ',   &
             'Y AXIS')
          YFRACT=(D-FY1MIN)/(FY1MAX-FY1MIN)
          P=PYMIN+YFRACT*(PYMAX-PYMIN)
        ELSEIF(IY1TSC.EQ.'NORM')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,201)
  201 FORMAT('***** FROM DPCODS: NORMAL SCALE NOT SUPPORTED FOR ',   &
             'Y AXIS')
          YFRACT=(D-FY1MIN)/(FY1MAX-FY1MIN)
          P=PYMIN+YFRACT*(PYMAX-PYMIN)
        ELSE
          YFRACT=(D-FY1MIN)/(FY1MAX-FY1MIN)
          P=PYMIN+YFRACT*(PYMAX-PYMIN)
        ENDIF
      ENDIF
  299 CONTINUE
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
      IF(IBUGD2.NE.'ON'.AND.ISUBRO.NE.'CODS')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE BEGINNING OF DPCODS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IBUGD2,ISUBRO,IERROR
 9013 FORMAT('IBUGD2,ISUBRO,IERROR = ',2(A4,2X),A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ICASE,D,P
 9014 FORMAT('ICASE,D,P = ',A1,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)PXMIN,PXMAX,PYMIN,PYMAX
 9021 FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)FX1MIN,FX2MAX,FY1MIN,FY2MAX
 9022 FORMAT('FX1MIN,FX2MAX,FY1MIN,FY2MAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCODS
      SUBROUTINE DPCOFH(IL1,IL2,IFUNC,NUMCHF,IH,NH,IBUGD2,IERROR)
!
!     PURPOSE--COPY OVER THE FUNCTION STRING IN LOCATIONS
!              IL1 TO IL2 OF IFUNC(.) AND PLACE IT IN
!              LOCATIONS 1 TO NH (= ILOC2-ILOC1+1)
!              OF THE ARRAY IH(.)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/7
!     ORIGINAL VERSION--JUNE  1986.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFUNC
      CHARACTER*4 IH
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
!
      DIMENSION IFUNC(*)
      DIMENSION IH(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='FH  '
      IERROR='NO'
!
      IF(IBUGD2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOFH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IL1,IL2,NUMCHF
   52   FORMAT('IL1,IL2,NUMCHF = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)(IFUNC(I),I=1,MIN(100,NUMCHF))
   55   FORMAT('IFUNC(.) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 11--                  **
!               **  COPY OVER THE STRING       **
!               *********************************
      J=0
      IF(IL1.GT.IL2)GO TO 1150
      DO 1100 I=IL1,IL2
        J=J+1
        IH(J)=IFUNC(I)
 1100 CONTINUE
 1150 CONTINUE
      NH=J
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGD2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOFH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9024)NH
 9024   FORMAT('NH = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9025)(IH(I),I=1,MIN(100,NH))
 9025   FORMAT('IH(.) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOFH
      SUBROUTINE DPCOFI(ICOM,IANSLC,IWIDTH,IHARG,IHARG2,NUMARG,   &
                        IBUGS2,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--COPY AN INPUT FILE TO AN OUTPUT FILE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/1
!     ORIGINAL VERSION--MAY       1994.
!     UPDATED  VERSION--NOVEMBER  2014. COPY CLIPBOARD TO FILE
!     UPDATED  VERSION--DECEMBER  2014. COPY FILE TO CLIPBOARD
!     UPDATED  VERSION--MARCH     2019. COPY SYSTEM TO USE OPERATING
!                                       SYSTEM DEPENDENT COPY
!     UPDATED  VERSION--DECEMBER  2019. INCREASE MAX NUMBER OF
!                                       CHARACTERS TO 255
!     UPDATED  VERSION--FEBRUARY  2020. FOR "CLIPBOARD", CHECK TO SEE
!                                       IF ARGUMENT IS ACTUALLY A FILE
!                                       NAME
!     UPDATED  VERSION--JUNE      2020. FOR "CLIPBOARD" UNDER LINUX,
!                                       USE "xclip" (IF AVAILABLE)
!     UPDATED  VERSION--AUGUST    2023. SUPPORT CLIPBOARD FOR CYGWIN
!                                       AND MACOS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IANSLC
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IBUGS2
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE1
      CHARACTER (LEN=MAXFNC) :: IFILE1
      CHARACTER*12 ISTAT1
      CHARACTER*12 IFORM1
      CHARACTER*12 IACCE1
      CHARACTER*12 IPROT1
      CHARACTER*12 ICURS1
!
!CCCC CHARACTER*80 IFILE2
      CHARACTER (LEN=MAXFNC) :: IFILE2
      CHARACTER*12 ISTAT2
      CHARACTER*12 IFORM2
      CHARACTER*12 IACCE2
      CHARACTER*12 IPROT2
      CHARACTER*12 ICURS2
!
      CHARACTER*4 IENDFI
      CHARACTER*4 IREWIN
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
#ifdef HAVE_XCLIP
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
      CHARACTER*4 ISSAV3
      CHARACTER*4 ISSAV4
#elif defined(CYGWIN)
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
      CHARACTER*4 ISSAV3
      CHARACTER*4 ISSAV4
#elif defined(MACOSX)
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
      CHARACTER*4 ISSAV3
      CHARACTER*4 ISSAV4
#endif
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
      CHARACTER*4 ICASE2
      CHARACTER*4 ITYPE
      CHARACTER*4 IOFILE
      CHARACTER*4 ICASEQ
      CHARACTER*9 ICLIZZ
      CHARACTER*10 IFORMT
!
      CHARACTER*4 IANSI
      CHARACTER (LEN=MAXSTR) :: ICANS
      CHARACTER (LEN=MAXSTR) :: ISTRIN
!
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOZC.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOHO.INC'
!
      CHARACTER*2000000 ISTR
      EQUIVALENCE (CGARBG(1),ISTR)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='FI  '
      IFOUND='YES'
      IERROR='NO'
      ICASE='FILE'
!
      ICASE2='FILE'
      IF(IHARG(1).EQ.'SYST' .AND. IHARG2(1).EQ.'EM  ')THEN
        ICASE2='SYST'
      ENDIF
!
      MINN2=1
      NCSTRI=(-999)
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICOM,IBUGS2,ISUBRO,IERROR,ICASE2
   53   FORMAT('ICOM,IBUGS2,ISUBRO,IERROR,ICASE2 = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IWIDTH,ILISNU,ICONNU,IDIRNU
   54   FORMAT('IWIDTH,ILISNU,ICONNU,IDIRNU = ',5I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,55)(IANSLC(I),I=1,MIN(80,IWIDTH))
   55     FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,61)IHARG(1),IHARG2(1),IHARG(2),IHARG2(2),   &
                       IHARG(3),IHARG2(3)
   61   FORMAT('IHARG(1),IHARG2(1),IHARG(2),IHARG2(2),',   &
               'IHARG(3),IHARG2(3) = ',3(2A4,2X))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)ILISNA
   62   FORMAT('ILISNA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)ILISST,ILISFO,ILISAC,ILISFO,ILISCS
   63   FORMAT('ILISST,ILISFO,ILISAC,ILISFO,ILISCS = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICONNA
   72   FORMAT('ICONNA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)ICONST,ICONFO,ICONAC,ICONFO,ICONCS
   73   FORMAT('ICONST,ICONFO,ICONAC,ICONFO,ICONCS = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,82)IDIRNA
   82   FORMAT('IDIRNA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,83)IDIRST,IDIRFO,IDIRAC,IDIRFO,IDIRCS
   83   FORMAT('IDIRST,IDIRFO,IDIRAC,IDIRFO,IDIRCS = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************
!               **  STEP 11--           **
!               **  COPY OVER VARIABLES **
!               **************************
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNI1=ILISNU
      IFILE1=ILISNA
      ISTAT1=ILISST
      IFORM1=ILISFO
      IACCE1=ILISAC
      IPROT1=ILISPR
      ICURS1=ILISCS
!
      IOUNI2=IWRINU
      IFILE2=IWRINA
      ISTAT2=IWRIST
      IFORM2=IWRIFO
      IACCE2=IWRIAC
      IPROT2=IWRIPR
      ICURS2=IWRICS
!
      ISUBN0='COFI'
      IERRFI='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,1181)IOUNI1
 1181   FORMAT('IOUNI1 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1182)IFILE1
 1182   FORMAT('IFILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1183)ISTAT2,IFORM2,IACCE2,IPROT2,ICURS2
 1183   FORMAT('ISTAT2,IFORM2,IACCE2,IPROT2,ICURS2 = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
!
        WRITE(ICOUT,1191)IOUNI2
 1191   FORMAT('IOUNI2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1192)IFILE2
 1192   FORMAT('IFILE2 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1193)ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1
 1193   FORMAT('ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1 = ',   &
               4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
!
        WRITE(ICOUT,1198)ISUBN0,IERRFI
 1198   FORMAT('ISUBN0,IERRFI = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  CHECK TO SEE IF THE COPY FILE MAY EXIST  **
!               ***********************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISTAT1.EQ.'NONE' .AND. ICASE.EQ.'FILE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
 1211   FORMAT('***** ERROR IN COPY FILE (DPCOFI)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1212)
 1212   FORMAT('      THE DESIRED COPYING CANNOT BE CARRIED OUT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1214)
 1214   FORMAT('      BECAUSE THE INTERNAL VARIABLE    ILISST ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1215)
 1215   FORMAT('      WHICH ALLOWS SUCH LISTING HAS BEEN SET TO ',   &
               '  NONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1217)ISTAT1,ILISST
 1217   FORMAT('ISTAT1,ILISST = ',A12,2X,A12)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***************************************
!               **  STEP 13--                        **
!               **  EXTRACT THE INPUT  FILE NAME.    **
!               ***************************************
!
      ISTEPN='13'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1310 I=1,MAXSTR
        IANSI=IANSLC(I)
        ICANS(I:I)=IANSI(1:1)
 1310 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=2
      IF(ICASE2.EQ.'SYST')IWORD=3
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,IFILE1,NCFIL1,   &
                  IBUGS2,ISUBRO,IERROR)
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,1321)NCFIL1,IFILE1
 1321   FORMAT('NCFIL1,IFILE1 = ',I8,2X,A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NCFIL1.EQ.9)THEN
        CALL DPUPPE(IFILE1,NCFIL1,ICLIZZ,IBUGS2,IERROR)
        IF(ICLIZZ(1:9).EQ.'CLIPBOARD')THEN
!
!         CHECK IF ARGUMENT IS A FILE NAME STARTING WITH
!         "CLIPBOARD.
!
          IWORD=2
          IF(ICASE2.EQ.'SYST')IWORD=3
          IOFILE='NO'
          CALL DPFILE(IANSLC,IWIDTH,IWORD,IOFILE,IBUGS2,ISUBRO,IERROR)
          IF(IOFILE.EQ.'NO')ICASE='CLIP'
        ENDIF
      ENDIF
!
      IF(NCFIL1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1372)
 1372   FORMAT('      TWO FILE NAMES--AN INPUT AND AN OUTPUT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1373)
 1373   FORMAT('      ARE REQUIRED IN THE COPY COMMAND')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1374)
 1374   FORMAT('      (FOR EXAMPLE,    COPY BOXSPRIN.DAT TEMP.)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1375)
 1375   FORMAT('      BUT TWO NAMES WERE NOT GIVEN HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1382)
 1382   FORMAT('   INPUT  FILE--')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=IWORD+1
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,IFILE2,NCFIL2,   &
                  IBUGS2,ISUBRO,IERROR)
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,1323)NCFIL2,IFILE2
 1323   FORMAT('NCFIL2,IFILE2 = ',I8,2X,A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NCFIL2.EQ.9)THEN
        CALL DPUPPE(IFILE2,NCFIL2,ICLIZZ,IBUGS2,IERROR)
        IF(ICLIZZ(1:9).EQ.'CLIPBOARD')THEN
!
!         CHECK IF ARGUMENT IS A FILE NAME STARTING WITH
!         "CLIPBOARD.
!
          IWORD=3
          IF(ICASE2.EQ.'SYST')IWORD=4
          IOFILE='NO'
          CALL DPFILE(IANSLC,IWIDTH,IWORD,IOFILE,IBUGS2,ISUBRO,IERROR)
          IF(IOFILE.EQ.'NO')ICASE='CLI2'
        ENDIF
      ENDIF
!
      IF(NCFIL2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1372)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1373)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1374)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1375)
        CALL DPWRST('XXX','BUG ')
!
        IF(NCFIL1.GE.1 .AND. ICASE.NE.'CLIP')THEN
           WRITE(ICOUT,1381)(IFILE1(I:I),I=1,NCFIL1)
 1381      FORMAT('   INPUT  FILE--',80A1)
           CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(NCFIL2.GE.1)THEN
          WRITE(ICOUT,1383)(IFILE2(I:I),I=1,NCFIL2)
 1383     FORMAT('   OUTPUT FILE--',80A1)
          CALL DPWRST('XXX','BUG ')
        ELSE
           WRITE(ICOUT,1384)
 1384      FORMAT('   OUTPUT FILE--')
           CALL DPWRST('XXX','BUG ')
        ENDIF
!
        WRITE(ICOUT,1386)
 1386   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,1387)(IANSLC(I),I=1,MIN(80,IWIDTH))
 1387     FORMAT('      ',80A1)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               *****************************************
!               **  STEP 20--                          **
!               **  IMPLEMENT OPERATING SYSTEM COPY    **
!               **  IF REQUESTED.                      **
!               *****************************************
!
      ISTEPN='20'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASE2.EQ.'SYST')THEN
        CALL COPYFI(IFILE1,IFILE2,IBUGS2,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
      ICASEQ='FULL'
!
!               *****************************************
!               **  STEP 21--                          **
!               **  CHECK TO SEE THE TYPE CASE--       **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='21'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 2190
      DO 2100 J=1,NUMARG
        J1=J
        IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ') GO TO 2110
        IF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ') GO TO 2110
        IF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ') GO TO 2120
 2100 CONTINUE
      GO TO 2190
 2110 CONTINUE
      ICASEQ='SUBS'
      ILOCQ=J1
      GO TO 2190
 2120 CONTINUE
      ICASEQ='FOR'
      ILOCQ=J1
      GO TO 2190
 2190 CONTINUE
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,2191)NUMARG,ILOCQ
 2191   FORMAT('NUMARG,ILOCQ = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************
!               **  STEP 22--                              **
!               **  BRANCH    TO THE APPROPRIATE SUBCASE   **
!               **  (FULL, SUBSET, OR FOR).                **
!               *********************************************
!
      ISTEPN='22'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASE.EQ.'CLIP')THEN
!
!       COPY CLIPBOARD TO FILE
!
        ISTEPN='22A'
        IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IFILE2.NE.ICONNA)THEN
          IREWIN='ON'
          CALL DPOPFI(IOUNI2,IFILE2,ISTAT2,IFORM2,IACCE2,   &
                      IPROT2,ICURS2,   &
                      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
          IF(IERRFI.EQ.'YES')GO TO 9000
        ENDIF
        IF(IOPSY1.EQ.'UNIX' .OR. IOPSY1.EQ.'LINU')THEN
#ifdef HAVE_XCLIP
!
!       FOR XCLIP, ISSUE THE COMMAND:
!
!          xclip -o -selection <clipboard/primary/secondary>  > IFILE2
!
          ISTRIN=' '
          IF(IX11SE.EQ.'CLIP')THEN
            ISTRIN='xclip -o -selection clipboard'
            NCSTR=29
          ELSEIF(IX11SE.EQ.'PRIM')THEN
            ISTRIN='xclip -o -selection primary'
            NCSTR=27
          ELSE
            ISTRIN='xclip -o -selection secondary'
            NCSTR=29
          ENDIF
!
          NCSTR=NCSTR+1
          ISTRIN(NCSTR:NCSTR+2)=' > '
          NCSTR=NCSTR+2
          DO 2206 II=1,NCFIL2
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE2(II:II)
 2206     CONTINUE
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#elif defined(CYGWIN)
!
!       FOR CYGWIN, ISSUE THE COMMAND:
!
!          cat /dev/clipboard > IFILE2
!
          ISTRIN=' '
          ISTRIN='cat /dev/clipboard'
          NCSTR=29
!
          NCSTR=NCSTR+1
          ISTRIN(NCSTR:NCSTR+2)=' > '
          NCSTR=NCSTR+2
          DO 2206 II=1,NCFIL2
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE2(II:II)
 2206     CONTINUE
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#elif defined(MACOSX)
!
!       FOR MACOS, ISSUE THE COMMAND:
!
!          pbpaste > IFILE2
!
          ISTRIN=' '
          ISTRIN='pbpaste'
          NCSTR=7
!
          NCSTR=NCSTR+1
          ISTRIN(NCSTR:NCSTR+2)=' > '
          NCSTR=NCSTR+2
          DO 2206 II=1,NCFIL2
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE2(II:II)
 2206     CONTINUE
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#else
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1211)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2201)
 2201     FORMAT('      THE xclip COMMAND IS NOT AVAILABLE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2203)
 2203     FORMAT('      THE CONTENTS OF THE CLIPBOARD WILL NOT BE ',   &
                 'COPIED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
#endif
        ELSE
          ITYPE='COPY'
          IHELMX=-99
          CALL DPCLI2(ITYPE,IOUNI2,IHELMX,ILINRD,IBUGS2,ISUBRO,IERROR)
        ENDIF
!
        IENDFI='OFF'
        IREWIN='ON'
        CALL DPCLFI(IOUNI2,IFILE2,ISTAT2,IFORM2,IACCE2,IPROT2,ICURS2,   &
                    IENDFI,IREWIN,ISUBN0,   &
                    IERRFI,IBUGS2,ISUBRO,IERROR)
!
        GO TO 9000
      ELSEIF(ICASE.EQ.'CLI2')THEN
!
        ISTEPN='22B'
        IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IFILE1.NE.ICONNA)THEN
          IREWIN='ON'
          CALL DPOPFI(IOUNI1,IFILE1,ISTAT1,IFORM1,IACCE1,   &
                      IPROT1,ICURS1,   &
                      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
          IF(IERRFI.EQ.'YES')GO TO 9000
        ENDIF
        IF(IOPSY1.EQ.'UNIX' .OR. IOPSY1.EQ.'LINU')THEN
#ifdef HAVE_XCLIP
!
!       FOR XCLIP, ISSUE THE COMMAND:
!
!          xclip -i -selection <clipboard/primary/secondary>  < IFILE1
!
          ISTRIN=' '
          IF(IX11SE.EQ.'CLIP')THEN
            ISTRIN='xclip -i -selection clipboard'
            NCSTR=29
          ELSEIF(IX11SE.EQ.'PRIM')THEN
            ISTRIN='xclip -i -selection primary'
            NCSTR=27
          ELSE
            ISTRIN='xclip -i -selection secondary'
            NCSTR=29
          ENDIF
!
          NCSTR=NCSTR+1
          ISTRIN(NCSTR:NCSTR+2)=' < '
          NCSTR=NCSTR+2
          DO 2306 II=1,NCFIL1
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE1(II:II)
 2306     CONTINUE
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#elif defined(CYGWIN)
!
!       FOR CYGWIN, ISSUE THE COMMAND:
!
!          cat IFILE1 > /dev/clipboard
!
          ISTRIN=' '
          ISTRIN='cat '
          NCSTR=4
!
          DO 2306 II=1,NCFIL1
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE1(II:II)
 2306     CONTINUE
!
          NCSTR=NCSTR+1
          ISTRIN(NCSTR:NCSTR+16)=' > /dev/clipboard'
          NCSTR=NCSTR+16
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#elif defined(MACOSX)
!
!       FOR MACOS, ISSUE THE COMMAND:
!
!          pbcopy IFILE1
!
          ISTRIN=' '
          ISTRIN='pbcopy '
          NCSTR=7
!
          DO 2306 II=1,NCFIL1
            NCSTR=NCSTR+1
            ISTRIN(NCSTR:NCSTR)=IFILE1(II:II)
 2306     CONTINUE
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISSAV3=ICLEWT
          ISSAV4=ILINSY
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
          CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
          ICLEWT=ISSAV3
          ILINSY=ISSAV4
          GO TO 9000
#else
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1211)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2301)
 2301     FORMAT('      THE xclip COMMAND IS NOT AVAILABLE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2303)
 2303     FORMAT('      THE CONTENTS OF THE FILE WILL NOT BE ',   &
                 'COPIED TO THE CLIPBOARD.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
#endif
        ELSE
          MAXCHR=2000000
          CALL DPCLI6(IOUNI1,ISTR,MAXCHR,IBUGS2,ISUBRO,IERROR)
        ENDIF
!
        IENDFI='OFF'
        IREWIN='ON'
        CALL DPCLFI(IOUNI1,IFILE1,ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1,   &
                    IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
        GO TO 9000
      ENDIF
!
      IF(ICASEQ.EQ.'FULL')GO TO 2210
      IF(ICASEQ.EQ.'SUBS')GO TO 2220
      IF(ICASEQ.EQ.'FOR')GO TO 2230
!
 2210 CONTINUE
      DO 2215 I=1,MAXN
      ISUB(I)=1
 2215 CONTINUE
      NQ=MAXN
      GO TO 2270
!
 2220 CONTINUE
      NIOLD=MAXN
      CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
      NQ=NIOLD
      GO TO 2270
!
 2230 CONTINUE
      NIOLD=MAXN
      CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
      NLOCAL,ILOCS,NS,IBUGQ,IERROR)
      NQ=NFOR
      NMXFOR=IROWN
      GO TO 2270
!
 2270 CONTINUE
      IF(NQ.LT.MINN2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2272)
 2272   FORMAT('      AFTER THE APPROPRIATE SUBSET HAS BEEN ',   &
               'EXTRACTED,')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2273)
 2273   FORMAT('      THE NUMBER OF SPECIFIED FILE LINES TO BE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2276)MINN2
 2276   FORMAT('      LISTED MUST BE ',I8,' OR LARGER;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2277)
 2277   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1386)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,1387)(IANSLC(I),I=1,MIN(80,IWIDTH))
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
      ENDIF
!
      NS=NQ
!
!               ****************************************
!               **  STEP 51--                         **
!               **  OPEN  THE INPUT AND OUTPUT FILES  **
!               **  (UNLESS ITS THE                   **
!               **  CONCLUSIONS FILE).                **
!               ****************************************
!
      ISTEPN='31'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,3111)IFILE1
 3111   FORMAT('IFILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3112)IFILE2
 3112   FORMAT('IFILE2 = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFILE2.NE.ICONNA)THEN
        IREWIN='ON'
        CALL DPOPFI(IOUNI1,IFILE1,ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1,   &
                    IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
        IF(IERRFI.EQ.'YES')GO TO 9000
        CALL DPOPFI(IOUNI2,IFILE2,ISTAT2,IFORM2,IACCE2,IPROT2,ICURS2,   &
                    IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
        IF(IERRFI.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***********************************
!               **  STEP 41--                    **
!               **  READ IN THE INPUT FILE.      **
!               **  WRITE OUT THE OUTPUT FILE.   **
!               ***********************************
!
      ISTEPN='41'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMAX=1000000
      IF(ICASEQ.EQ.'SUBS')IMAX=MAXN
      IF(ICASEQ.EQ.'FOR')IMAX=IROWN
!
      NMAX=512
      IFORMT=' '
      IFORMT='(   A1)'
      WRITE(IFORMT(2:4),'(I3)')NMAX
      DO 4110 I=1,IMAX
!
        READ(IOUNI1,IFORMT,END=4190)(ISTRIN(J:J),J=1,NMAX)
!
        IF(ISUB(I).EQ.1)THEN
          CALL DPDB80(ISTRIN,JMAX,NMAX,IBUGS2,ISUBRO,IERROR)
          NCSTRI=JMAX
          WRITE(IOUNI2,IFORMT)(ISTRIN(J:J),J=1,NCSTRI)
        ENDIF
!
 4110 CONTINUE
 4190 CONTINUE
!
!               **************************
!               **  STEP 51--           **
!               **  CLOSE THE 2 FILES   **
!               **  (UNLESS ITS THE     **
!               **  CONCLUSIONS FILE).  **
!               **************************
!
      ISTEPN='51'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IFILE2.EQ.ICONNA)GO TO 5190
!
      IENDFI='OFF'
      IREWIN='ON'
      CALL DPCLFI(IOUNI1,IFILE1,ISTAT1,IFORM1,IACCE1,IPROT1,ICURS1,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      CALL DPCLFI(IOUNI2,IFILE2,ISTAT2,IFORM2,IACCE2,IPROT2,ICURS2,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
 5190 CONTINUE
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'COFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9041)ICASEQ,NQ,NS,JMAX,NCSTRI
 9041   FORMAT('ICASEQ,NQ,NS,JMAX,NCSTRI = ',A4,4I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOFI
      SUBROUTINE DPCOHI(ISTART,ISTOP,IANS2,N2,IVALID,VALCON,IVALCO,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--DETERMINE IF THE STRING DEFINED
!              IN LOCATIONS ISTART THROUGH ISTOP (INCLUSIVE) IN IANS2(.).
!              IS A VALID NUMBER REPRESENTATION
!              AND IF SO, COMPUTE THE VALUE OF THE NUMBER.
!     NOTE--THIS SUBROUTINE IS IDENTICAL TO DPHOCO EXCEPT
!           FOR THE FACT THAT DPHOCO HAS THE INPUT STRING
!           IN LOCATIONS 1 THROUGH N2 OF IANS2(.)
!           WHEREAS DPCOHI HAS THE INPUT STRING
!           IN LOCATIONS ISTART THROUGH ISTOP OF IANS(.).
!
!     ORIGINAL VERSION--JANUARY   1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --NOVEMBER  1989.  ITYPE2='NUMBER' BUG
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IANS2
      CHARACTER*4 IVALID
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ITYPE2
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION IANS2(*)
!
!-----COMMON VARIABLES (GENERAL)-----------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='HI  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)
   81   FORMAT('***** AT THE BEGINNING OF DPCOHI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,82)N2,ISTART,ISTOP
   82   FORMAT('N2,ISTART,ISTOP = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,83)(IANS2(I),I=1,MIN(N2,115))
   83   FORMAT('IANS2(.) = ',115A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **********************************
!               **  STEP 1--                    **
!               **  INITIALIZE SOME VARIABLES.  **
!               **********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IVALID='NO'
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  CONVERT (IF POSSIBLE) THE STRING INTO A FLOATING  **
!               **  POINT ARGUMENT.                                   **
!               **  OUTPUT THIS FLOATING POINT VALUE IN FLOAT.        **
!               ********************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      AMIN=-1000000.
      AMAX=+1000000.
      IERROR='NO'
      IVALID='YES'
      ITYPE2='NUMB'
      VALCON=-999.0
      IVALCO=-999
!
      ISTAR2=ISTART
      ISTOP2=ISTOP
!
      ILOC=0
      IDECPT=0
      DO 3060 I=ISTAR2,ISTOP2
        IF(IANS2(I).EQ.'.')ILOC=I
        IF(IANS2(I).EQ.'.')IDECPT=IDECPT+1
 3060 CONTINUE
      IF(IDECPT.GE.2)GO TO 3900
      IF(IDECPT.EQ.1)GO TO 3150
      DO 3100 I=ISTAR2,ISTOP2
        IREV=ISTOP2-(I-ISTAR2)
        IF(IANS2(IREV).EQ.' ')GO TO 3100
        IF(IANS2(IREV).EQ.'0')GO TO 3110
        IF(IANS2(IREV).EQ.'1')GO TO 3110
        IF(IANS2(IREV).EQ.'2')GO TO 3110
        IF(IANS2(IREV).EQ.'3')GO TO 3110
        IF(IANS2(IREV).EQ.'4')GO TO 3110
        IF(IANS2(IREV).EQ.'5')GO TO 3110
        IF(IANS2(IREV).EQ.'6')GO TO 3110
        IF(IANS2(IREV).EQ.'7')GO TO 3110
        IF(IANS2(IREV).EQ.'8')GO TO 3110
        IF(IANS2(IREV).EQ.'9')GO TO 3110
        IERROR='YES'
        IF(IANS2(IREV).EQ.'+')GO TO 3900
        IF(IANS2(IREV).EQ.'-')GO TO 3900
        GO TO 3900
 3100 CONTINUE
      IERROR='YES'
      GO TO 3900
 3110 CONTINUE
      ILOC=IREV+1
 3150 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,3111)ILOC,IDECPT
 3111   FORMAT('ILOC = ',I8,'    IDECPT = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     SECONDLY, COMPUTE THE INTEGER PART OF THE VALUE
!
      SIGN=1.0
      IDIGI=0
      ISIGN=0
      SUMI=0
      ILOCM1=ILOC-1
      IF(ILOCM1.LT.ISTAR2)GO TO 3250
      DO 3200 I=ISTAR2,ILOCM1
        IREV=ILOCM1-(I-ISTAR2)
        IF(IANS2(IREV).EQ.' ')GO TO 3200
        IF(IANS2(IREV).EQ.'0')THEN
          ITERM=0
        ELSEIF(IANS2(IREV).EQ.'1')THEN
          ITERM=1
        ELSEIF(IANS2(IREV).EQ.'2')THEN
          ITERM=2
        ELSEIF(IANS2(IREV).EQ.'3')THEN
          ITERM=3
        ELSEIF(IANS2(IREV).EQ.'4')THEN
          ITERM=4
        ELSEIF(IANS2(IREV).EQ.'5')THEN
          ITERM=5
        ELSEIF(IANS2(IREV).EQ.'6')THEN
          ITERM=6
        ELSEIF(IANS2(IREV).EQ.'7')THEN
          ITERM=7
        ELSEIF(IANS2(IREV).EQ.'8')THEN
          ITERM=8
        ELSEIF(IANS2(IREV).EQ.'9')THEN
          ITERM=9
        ELSEIF(IANS2(IREV).EQ.'+')THEN
          ISIGN=ISIGN+1
          GO TO 3200
        ELSEIF(IANS2(IREV).EQ.'-')THEN
          ISIGN=ISIGN+1
          SIGN=-SIGN
          GO TO 3200
        ELSE
          IERROR='YES'
          GO TO 3900
        ENDIF
!
        IDIGI=IDIGI+1
        TERM=ITERM
        IEXP=IDIGI-1
        SUMI=SUMI+TERM*(10.0**IEXP)
 3200 CONTINUE
 3250 CONTINUE
      IF(ISIGN.GE.2)GO TO 3900
!
      IF(IBUGA3.EQ.'ON')THEN
         WRITE(ICOUT,3255)IDIGI,SUMI
 3255    FORMAT('IDIGI = ',I8,'    SUMI = ',E15.7)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     THIRDLY, COMPUTE THE DECIMAL PART OF THE VALUE
!
      IDIGD=0
      SUMD=0.0
      ILOCP1=ILOC+1
      IF(ILOCP1.GT.ISTOP2)GO TO 3350
      DO 3300 I=ILOCP1,ISTOP2
        IF(IANS2(I).EQ.' ')GO TO 3300
        IF(IANS2(I).EQ.'0')THEN
          ITERM=0
        ELSEIF(IANS2(I).EQ.'1')THEN
          ITERM=1
        ELSEIF(IANS2(I).EQ.'2')THEN
          ITERM=2
        ELSEIF(IANS2(I).EQ.'3')THEN
          ITERM=3
        ELSEIF(IANS2(I).EQ.'4')THEN
          ITERM=4
        ELSEIF(IANS2(I).EQ.'5')THEN
          ITERM=5
        ELSEIF(IANS2(I).EQ.'6')THEN
          ITERM=6
        ELSEIF(IANS2(I).EQ.'7')THEN
          ITERM=7
        ELSEIF(IANS2(I).EQ.'8')THEN
          ITERM=8
        ELSEIF(IANS2(I).EQ.'9')THEN
          ITERM=9
        ELSE
          IERROR='YES'
          GO TO 3900
        ENDIF
        IDIGD=IDIGD+1
        TERM=ITERM
        SUMD=SUMD+TERM/(10.0**IDIGD)
 3300 CONTINUE
 3350 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,3355)IDIGD,SUMD
 3355   FORMAT('IDIGD = ',I8,'    SUMD = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IDIGT=IDIGI+IDIGD
      IF(IDIGT.LE.0)GO TO 3900
      VALCON=SUMI+SUMD
      IVALCO=INT(VALCON+0.00001)
      IF(SIGN.LT.0.0)VALCON=-VALCON
      IF(SIGN.LT.0.0)IVALCO=-IVALCO
      IF(AMIN.LE.VALCON.AND.VALCON.LE.AMAX)GO TO 3000
      GO TO 3900
!
 3900 CONTINUE
      IF(IERROR.EQ.'YES')ITYPE2='WORD'
 3000 CONTINUE
      GO TO 9000
!
 9000 CONTINUE
!
      ISTEPN='8'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IERROR.EQ.'YES')IVALID='NO'
      IF(IERROR.EQ.'NO')IVALID='YES'
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9001)
 9001   FORMAT('***** AT THE END       OF DPCOHI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9002)VALCON,IVALCO
 9002   FORMAT('VALCON,IVALCO = ',G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9005)IVALID,IERROR
 9005   FORMAT('IVALID,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOHI
      SUBROUTINE DPCOIH(IVAL,IHOUT,NOUT,IVALID,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CONVERT AN INTEGER VARIABLE
!              TO A 1-CHARACTER-PER-WORD HOLLARITH STRING.
!
!     ORIGINAL VERSION--JANUARY  1979.
!     UPDATED         --MAY      1986.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHOUT
      CHARACTER*4 IVALID
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISIGN
      CHARACTER*4 IHDIG
!
      DIMENSION IHOUT(*)
!
!-----COMMON VARIABLES (GENERAL)-----------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     MAXDIG IS THE MAXIMUM NUMBER OF DIGITS
!     FOR AN INTEGER VARIABLE.
!     THIS WILL VARY FROM ONE COMPUTER TO THE NEXT
!     DEPENDING ON THE NUMBER OF BITS FOR A WORD.
!     THE FOLLOWING DEFINED VALUE (= 10)
!     HAS BEEN SET FOR THE VAX 11/780.
!
!CCCC MAXDIG=11
      MAXDIG=9
      NUMDIG=(-999)
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'COIH')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOIH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ISUBRO,IERROR
   52 FORMAT('IBUGA3,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IVAL
   53 FORMAT('IVAL = ',I11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMDIG
   54 FORMAT('NUMDIG = ',I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **********************************
!               **  STEP 1--                    **
!               **  INITIALIZE SOME VARIABLES.  **
!               **********************************
!
      IERROR='NO'
      IVALID='YES'
      IVAL2=IVAL
!
!               ***********************
!               **  STEP 2--         **
!               **  DETERMINE SIGN.  **
!               ***********************
!
      ISIGN='+'
      IF(IVAL2.LT.0)ISIGN='-'
      IVAL2=IABS(IVAL2)
!
!               ***********************************
!               **  STEP 3--                     **
!               **  DETERMINE NUMBER OF DIGITS.  **
!               ***********************************
!
      IMIN=1
      IMAX=MAXDIG
      DO 300 I=IMIN,IMAX
      IREV=IMAX-I+IMIN
      IDIV=INT(10.0**(IREV-1) + 0.01)
      IDIG=IVAL2/IDIV
      IF(IDIG.NE.0)GO TO 350
  300 CONTINUE
      NUMDIG=1
      GO TO 390
  350 CONTINUE
      NUMDIG=IREV
  390 CONTINUE
!
!               ***************************************
!               **  STEP 4--                         **
!               **  IF NEGATIVE,                     **
!               **  INSERT SIGN INTO OUTPUT VECTOR.  **
!               ***************************************
!
      J=0
      IF(ISIGN.EQ.'-')J=J+1
      IF(ISIGN.EQ.'-')IHOUT(J)='-'
!
!               **************************
!               **  STEP 5--            **
!               **  INSERT DIGITS INTO  **
!               **  OUTPUT VECTOR.      **
!               **************************
!
      IMIN=1
      IMAX=NUMDIG
      DO 500 I=IMIN,IMAX
      IREV=IMAX-I+IMIN
      IDIV=INT(10.0**(IREV-1) + 0.01)
      IDIG=IVAL2/IDIV
!
      IF(IDIG.EQ.0)GO TO 510
      IF(IDIG.EQ.1)GO TO 511
      IF(IDIG.EQ.2)GO TO 512
      IF(IDIG.EQ.3)GO TO 513
      IF(IDIG.EQ.4)GO TO 514
      IF(IDIG.EQ.5)GO TO 515
      IF(IDIG.EQ.6)GO TO 516
      IF(IDIG.EQ.7)GO TO 517
      IF(IDIG.EQ.8)GO TO 518
      IF(IDIG.EQ.9)GO TO 519
  510 CONTINUE
      IHDIG='0'
      GO TO 529
  511 CONTINUE
      IHDIG='1'
      GO TO 529
  512 CONTINUE
      IHDIG='2'
      GO TO 529
  513 CONTINUE
      IHDIG='3'
      GO TO 529
  514 CONTINUE
      IHDIG='4'
      GO TO 529
  515 CONTINUE
      IHDIG='5'
      GO TO 529
  516 CONTINUE
      IHDIG='6'
      GO TO 529
  517 CONTINUE
      IHDIG='7'
      GO TO 529
  518 CONTINUE
      IHDIG='8'
      GO TO 529
  519 CONTINUE
      IHDIG='9'
      GO TO 529
  529 CONTINUE
!
      J=J+1
      IHOUT(J)=IHDIG
      IVAL2=IVAL2-IDIG*IDIV
  500 CONTINUE
      NOUT=J
!
!               ****************
!               **  STEP 6--  **
!               **  EXIT.     **
!               ****************
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'COIH')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCOIH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ISUBRO,IERROR
 9012 FORMAT('IBUGA3,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IVAL
 9013 FORMAT('IVAL = ',I11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)NOUT
 9014 FORMAT('NOUT = ',I11)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)(IHOUT(I),I=1,NOUT)
 9015 FORMAT('IHOUT(.) = ',80A1)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCOIH
      SUBROUTINE DPCOIP(XP,YP,XC,YC,SLOPE,ABSSLO,SLOEPS,   &
      XHORIZ,AUPPER,ALOWER,NHORP,IPHORI,ICHORI,   &
      ISTART,ICASHO,ICASIN,   &
      XMIN,XMAX,   &
      XTEMP2,YTEMP2,ITHORI,   &
      IBUGU2,ISUBRO,IERROR)
!
!     PURPOSE--GIVEN THAT THE DATA LINE (XP,YP) TO (XC,YC)
!              IS SUCH THAT (XP,YP) IS TO THE
!              IMMEDIATE LEFT OF THE ISTART-TH ELEMENT
!              OF THE HORIZON TABLE,
!              DETERMINE THE INTERSECTION POINT
!              (XTEMP2,YTEMP2) WHERE THE DATA LINE
!              INTERSECTS THE HORIZON LINE.
!     ORIGINAL VERSION--SEPTEMBER 1988
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASHO
      CHARACTER*4 ICASIN
!
      CHARACTER*4 IBUGU2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION XHORIZ(*)
      DIMENSION AUPPER(*)
      DIMENSION ALOWER(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='IP  '
!
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'COIP')GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOIP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGU2,ISUBRO,IERROR
   52 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)XP,YP,XC,YC
   53 FORMAT('XP,YP,XC,YC = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)SLOPE,ABSSLO,SLOEPS
   54 FORMAT('SLOPE,ABSSLO,SLOEPS = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)NHORP,IPHORI,ICHORI
   61 FORMAT('NHORP,IPHORI,ICHORI = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 63 I=IPHORI,ICHORI
      WRITE(ICOUT,64)I,XHORIZ(I),AUPPER(I),ALOWER(I)
   64 FORMAT('I,XHORIZ(I),AUPPER(I),ALOWER(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   63 CONTINUE
      DO 65 I=IPHORI,ICHORI
      WRITE(ICOUT,66)I,AUPPER(I),ALOWER(I),XHORIZ(I)
   66 FORMAT('I,AUPPER(I),ALOWER(I),XHORIZ(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
      WRITE(ICOUT,67)ISTART,ICASHO,ICASIN
   67 FORMAT('ISTART,ICASHO,ICASIN = ',I8,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,68)XMIN,XMAX
   68 FORMAT('XMIN,XMAX = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,72)ITHORI
   72 FORMAT('ITHORI = ',I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      I=ISTART-1
      IF(I.LE.0)I=1
      XTEMPO=XHORIZ(I)
      YTEMPO=YP+(XTEMPO-XP)*SLOPE
      YCUTOL=ALOWER(I)
      IF(ICASHO.EQ.'UPPE')YCUTOL=AUPPER(I)
!
      DO 1100 I=ISTART,ICHORI
      I2=I
      XTEMP=XHORIZ(I)
      YTEMP=YP+(XTEMP-XP)*SLOPE
      YCUT=ALOWER(I)
      IF(ICASHO.EQ.'UPPE')YCUT=AUPPER(I)
      IF(ICASIN.EQ.'LE'.AND.YTEMP.LE.YCUT)GO TO 1150
      IF(ICASIN.EQ.'GE'.AND.YTEMP.GE.YCUT)GO TO 1150
      XTEMPO=XTEMP
      YTEMPO=YTEMP
      YCUTOL=YCUT
 1100 CONTINUE
!
      XTEMP2=XC
      YTEMP2=YC
      ITHORI=ICHORI
      GO TO 1190
!
 1150 CONTINUE
      IF(ABSSLO.LE.SLOEPS)GO TO 1160
      GO TO 1170
!
 1160 CONTINUE
      XTEMP2=XTEMP
      YTEMP2=YCUT
      ITHORI=I2
      GO TO 1190
!
 1170 CONTINUE
      CALL DPCOI2(XTEMPO,YTEMPO,YCUTOL,XTEMP,YTEMP,YCUT,   &
      XTEMP2,YTEMP2,IBUGU2,ISUBRO,IERROR)
      CALL HORIND(XTEMP2,XMIN,XMAX,1,NHORP,ITHORI,IBUGU2,ISUBRO,IERROR)
      GO TO 1190
!
 1190 CONTINUE
      IF(ICASHO.EQ.'LOWE'.AND.YCUT.LT.ALOWER(ITHORI))ALOWER(ITHORI)=YCUT
      IF(ICASHO.EQ.'UPPE'.AND.YCUT.GT.AUPPER(ITHORI))AUPPER(ITHORI)=YCUT
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'COIP')GO TO 9010
      GO TO 9090
 9010 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END        OF DPCOIP--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGU2,ISUBRO,IERROR
 9012 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)XP,YP,XC,YC
 9013 FORMAT('XP,YP,XC,YC = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)SLOPE,ABSSLO,SLOEPS
 9014 FORMAT('SLOPE,ABSSLO,SLOEPS = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)NHORP,IPHORI,ICHORI
 9021 FORMAT('NHORP,IPHORI,ICHORI = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 9023 I=IPHORI,ICHORI
      WRITE(ICOUT,9024)I,XHORIZ(I),AUPPER(I),ALOWER(I)
 9024 FORMAT('I,XHORIZ(I),AUPPER(I),ALOWER(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 9023 CONTINUE
      WRITE(ICOUT,9027)ISTART,ICASHO,ICASIN
 9027 FORMAT('ISTART,ICASHO,ICASIN = ',I8,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9028)XMIN,XMAX
 9028 FORMAT('XMIN,XMAX = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)XTEMP2,YTEMP2
 9031 FORMAT('XTEMP2,YTEMP2 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)ITHORI
 9032 FORMAT('ITHORI = ',I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCOIP
      SUBROUTINE DPCOI2(X1,Y11,Y12,X2,Y21,Y22,   &
      X3,Y3,IBUGU2,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE INTERSECTION POINT (X3,Y3) OF 2 LINES
!              FOR THE SPECIAL CASE WHEN ONLY HAVE
!              2 DISTINCT X VALUES  (RATHER THAN 4)
!              FOR THE 4 Y VALUES.
!              THUS ONE X VALUE HAS 2 Y VALUES,
!              AND THE OTHER X VALUE HAS 2 Y VALUES.
!     ASSUMPTION--THE 2 LINES DO IN FACT INTERSECT.
!     METHOD--FOR THIS SPECIAL CASE WHEN HAVE A COMMON
!             X VALUE FOR THE LEFT DATA AND ANOTHER COMMON
!             X VALUE FOR THE RIGHT DATA, THEN THE
!             SOLUTION FOR THE INTERSECTION POINT
!             IS GEOMETRICALLY QUITE SIMPLE--THE X VALUE IS
!             A CERTAIN PROPORTION P ACROSS AND
!             THE Y VALUE IS THE SAME PROPORTION P
!             BETWEEN THE Y VALUES ON A GIVEN LINE.
!             THAT PROPORTION IS
!                P = DEL1 /(DEL1 + DEL2)
!             WHERE DEL1 = DIFFERENCE OF Y VALUES ON LEFT,
!             AND   DEL2 = DIFFERENCE OF Y VALUES ON RIGHT.
!     ORIGINAL VERSION--SEPTEMBER 1988
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGU2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='I2  '
!
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'COI2')GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGU2,ISUBRO,IERROR
   52 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)X1,Y11,Y12
   53 FORMAT('X1,Y11,Y12 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)X2,Y21,Y22
   54 FORMAT('X2,Y21,Y22 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************************************
!               **  STEP 10--                                   **
!               **  COMPUTE THE INTERSECTION POINT              **
!               **************************************************
!
      YDEL1=Y12-Y11
      YDEL2=Y22-Y21
      YDEL2=(-YDEL2)
      YDEL12=YDEL1+YDEL2
      P=YDEL1/YDEL12
      X3=X1+P*(X2-X1)
      Y3=Y11+P*(Y21-Y11)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGU2.EQ.'ON'.OR.ISUBRO.EQ.'COI2')GO TO 9010
      GO TO 9090
 9010 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCOI2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGU2,ISUBRO,IERROR
 9012 FORMAT('IBUGU2,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)X1,Y11,Y12
 9013 FORMAT('X1,Y11,Y12 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)X2,Y21,Y22
 9014 FORMAT('X2,Y21,Y22 = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)YDEL1,YDEL2,YDEL12,P
 9021 FORMAT('YDEL1,YDEL2,YDEL12,P = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9022)X3,Y3
 9022 FORMAT('X3,Y3 = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
      RETURN
      END SUBROUTINE DPCOI2
      SUBROUTINE DPCOLL(IDEFC1,IDEFC2,IFCOL1,IFCOL2,NUMRCM,   &
      IFCOLL,IFCOLU,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE COLUMN LIMITS
!              WHICH WILL DEFINE THE EXTREME
!              COLUMNS (WITHIN A FILE) TO BE SCANNED IN CARRYING
!              OUT THE READ AND SERIAL READ COMMANDS.
!              THE 2 LIMITS ARE CONTAINED IN THE
!              2 ARGUMENTS IFCOL1 AND IFCOL2, RESPECTIVELY.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --IARG   (AN INTEGER VECTOR)
!                     --NUMARG
!                     --IDEFC1
!                     --IDEFC2
!     OUTPUT ARGUMENTS--IFCOL1 (AN INTEGER VARIABLE
!                       CONTAINING THE MINIMUM COLUMN
!                       IN THE DATA FILE TO BE SCANNED
!                       DURING A    READ    OR A    SERIAL READ.
!                     --IFCOL2 (AN INTEGER VARIABLE
!                       CONTAINING THE MAXIMUM COLUMN
!                       IN THE DATA FILE TO BE SCANNED
!                       DURING A    READ    OR A    SERIAL READ.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  2003. TEST AGAINST MAXIMUM RECORD
!                                       LENGTH FOR DATA FILE (NUMRCM)
!     UPDATED         --JANUARY   2004. IFCOLL, IFCOLU FOR ARRAYS OF
!                                       COLUMN LIMITS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 IH11
      CHARACTER*4 IH12
      CHARACTER*4 MESSAG
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      INTEGER IFCOL3(50)
      INTEGER AINDEX(50)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOM2.INC'
!
      DIMENSION IFCOLL(*)
      DIMENSION IFCOLU(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IHOLD1=0
      IHOLD2=0
!
!               ****************************************************
!               **  TREAT THE CASE WHEN                           **
!               **  THE COLUMN LIMITS ARE TO BE CHANGED           **
!               ****************************************************
!
      IF(NUMARG.LE.0)GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'LIMI')GO TO 1110
      GO TO 1190
!
 1110 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1120
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1120
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1120
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1120
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1120
      IF(IHARG(NUMARG).EQ.'?')GO TO 8100
      IF(NUMARG.GE.3.AND.IARGT(2).EQ.'NUMB'.AND.   &
      IARGT(3).EQ.'NUMB')GO TO 1130
      IF(NUMARG.GE.3.AND.IARGT(2).EQ.'WORD'.AND.   &
      IARGT(3).EQ.'WORD')GO TO 3140
      GO TO 1190
!
 1120 CONTINUE
      I1=IDEFC1
      I2=IDEFC2
      IF(I1.LE.I2)IHOLD1=I1
      IF(I1.LE.I2)IHOLD2=I2
      IF(I1.GT.I2)IHOLD1=I2
      IF(I1.GT.I2)IHOLD2=I1
      DO 1122 I=1,50
        IFCOLL(I)=0
        IFCOLU(I)=0
 1122 CONTINUE
      GO TO 1180
!
 1130 CONTINUE
      I1=IARG(2)
      I2=IARG(3)
      IF(I1.LE.I2)IHOLD1=I1
      IF(I1.LE.I2)IHOLD2=I2
      IF(I1.GT.I2)IHOLD1=I2
      IF(I1.GT.I2)IHOLD2=I1
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      IFCOL1=IHOLD1
      IFCOL2=IHOLD2
!
!CCCC FEBRAURY 2003: CHECK AGAINST MAXIMUM RECORD LENGTH
!
      IF(IFCOL2.GT.NUMRCM)IFCOL2=NUMRCM
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1185)
 1185   FORMAT('THE COLUMN LIMITS (FOR READ AND SERIAL READ)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1186)IFCOL1,IFCOL2
 1186   FORMAT('HAVE JUST BEEN SET TO ',I8,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 1190 CONTINUE
!
!               ****************************************************
!               **  TREAT THE CASE WHEN                           **
!               **  THE COLUMN MINIMUM IS TO BE CHANGED           **
!               ****************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'MINI')GO TO 1210
      GO TO 1290
!
 1210 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1220
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1220
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1220
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1220
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1220
      IF(NUMARG.GE.2.AND.IARGT(2).EQ.'NUMB')GO TO 1230
      GO TO 1290
!
 1220 CONTINUE
      IHOLD1=IDEFC1
      DO 1222 I=1,50
        IFCOLL(I)=0
        IFCOLU(I)=0
 1222 CONTINUE
      GO TO 1280
!
 1230 CONTINUE
      IHOLD1=IARG(2)
      GO TO 1280
!
 1280 CONTINUE
      IFOUND='YES'
      IFCOL1=IHOLD1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1285)
 1285 FORMAT('THE COLUMN MINIMUM (FOR READ AND SERIAL READ)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1286)IFCOL1
 1286 FORMAT('HAS JUST BEEN SET TO ',I8)
      CALL DPWRST('XXX','BUG ')
 1289 CONTINUE
      GO TO 9000
!
 1290 CONTINUE
!
!               ****************************************************
!               **  TREAT THE CASE WHEN                           **
!               **  THE COLUMN MAXIMUM IS TO BE CHANGED           **
!               ****************************************************
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'MAXI')GO TO 1310
      GO TO 1390
!
 1310 CONTINUE
      IF(NUMARG.EQ.1)GO TO 1320
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1320
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1320
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1320
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1320
      IF(NUMARG.GE.2.AND.IARGT(2).EQ.'NUMB')GO TO 1330
      GO TO 1390
!
 1320 CONTINUE
      IHOLD2=IDEFC2
      DO 1322 I=1,50
        IFCOLL(I)=0
        IFCOLU(I)=0
 1322 CONTINUE
      GO TO 1380
!
 1330 CONTINUE
      IHOLD2=IARG(2)
      GO TO 1380
!
 1380 CONTINUE
      IFOUND='YES'
      IFCOL2=IHOLD2
!
!CCCC FEBRAURY 2003: CHECK AGAINST MAXIMUM RECORD LENGTH
!
      IF(IFCOL2.GT.NUMRCM)IFCOL2=NUMRCM
!
      IF(IFEEDB.EQ.'OFF')GO TO 1389
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1385)
 1385 FORMAT('THE COLUMN MAXIMUM (FOR READ AND SERIAL READ)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1386)IFCOL1
 1386 FORMAT('HAS JUST BEEN SET TO ',I8)
      CALL DPWRST('XXX','BUG ')
 1389 CONTINUE
      GO TO 9000
!
 1390 CONTINUE
!
!               ********************************************
!               **  STEP 81--                             **
!               **  TREAT THE    ?    CASE--              **
!               **  DUMP OUT CURRENT AND DEFAULT VALUES.  **
!               ********************************************
!
 8100 CONTINUE
      IFOUND='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8111)IFCOL1,IFCOL2
 8111 FORMAT('THE CURRENT COLUMN LIMITS ARE ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8112)IDEFC1,IDEFC2
 8112 FORMAT('THE DEFAULT COLUMN LIMITS ARE ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 3140 CONTINUE
!
      IH11=IHARG(2)
      IH12=IHARG2(2)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IH11,IH12,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ICOL1=IVALUE(ILOCV)
        N1=IN(ILOCV)
      ELSE
        GO TO 9000
      ENDIF
!
      IH11=IHARG(3)
      IH12=IHARG2(3)
      IHWUSE='V'
      MESSAG='YES'
      CALL CHECKN(IH11,IH12,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ICOL2=IVALUE(ILOCV)
        N2=IN(ILOCV)
      ELSE
        GO TO 9000
      ENDIF
!
      IF(N1.NE.N2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3411)
 3411   FORMAT('***** ERROR: FOR THE VECTOR FORM OF THE COLUMN LIMITS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3413)
 3413   FORMAT('      COMMAND, THE NUMBER OF COLUMNS IS NOT EQUAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3415)IHARG(2),IHARG2(2),N1
 3415   FORMAT('      VARIABLE ',A4,A4,' HAS ',I8,' ELEMENTS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3415)IHARG(3),IHARG2(3),N2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
      J=0
      IMAX=MIN(50,N1)
      DO 3160 I=1,50
        J=J+1
        IFCOLL(J)=0
        IFCOLU(J)=0
        IF(I.GT.IMAX)GO TO 3160
!
        IJ=MAXN*(ICOL1-1)+I
        IF(ICOL1.LE.MAXCOL)IFCOLL(J)=INT(V(IJ) + 0.5)
        IF(ICOL1.EQ.MAXCP1)IFCOLL(J)=INT(PRED(I) + 0.5)
        IF(ICOL1.EQ.MAXCP2)IFCOLL(J)=INT(RES(I) + 0.5)
        IF(ICOL1.EQ.MAXCP3)IFCOLL(J)=INT(YPLOT(I) + 0.5)
        IF(ICOL1.EQ.MAXCP4)IFCOLL(J)=INT(XPLOT(I) + 0.5)
        IF(ICOL1.EQ.MAXCP5)IFCOLL(J)=INT(X2PLOT(I) + 0.5)
        IF(ICOL1.EQ.MAXCP6)IFCOLL(J)=INT(TAGPLO(I) + 0.5)
!
        IJ=MAXN*(ICOL2-1)+I
        IF(ICOL2.LE.MAXCOL)IFCOLU(J)=INT(V(IJ) + 0.5)
        IF(ICOL2.EQ.MAXCP1)IFCOLU(J)=INT(PRED(I) + 0.5)
        IF(ICOL2.EQ.MAXCP2)IFCOLU(J)=INT(RES(I) + 0.5)
        IF(ICOL2.EQ.MAXCP3)IFCOLU(J)=INT(YPLOT(I) + 0.5)
        IF(ICOL2.EQ.MAXCP4)IFCOLU(J)=INT(XPLOT(I) + 0.5)
        IF(ICOL2.EQ.MAXCP5)IFCOLU(J)=INT(X2PLOT(I) + 0.5)
        IF(ICOL2.EQ.MAXCP6)IFCOLU(J)=INT(TAGPLO(I) + 0.5)
!
 3160 CONTINUE
!
      DO 3180 I=1,IMAX
        IF(IFCOLL(I).GT.IFCOLU(I))THEN
          ITEMP=IFCOLL(I)
          IFCOLL(I)=IFCOLU(I)
          IFCOLU(I)=ITEMP
        ENDIF
 3180 CONTINUE
!
!  SORT THE COLUMNS (FROM SMALLEST TO LARGEST VALUE OF IFCOLL)
!
      CALL SORTII(IFCOLL,IMAX,IFCOL3,AINDEX)
      DO 3187 I=1,IMAX
        IFCOLL(I)=IFCOL3(I)
 3187 CONTINUE
!
      DO 3188 I=1,IMAX
        J=AINDEX(I)
        IFCOL3(I)=IFCOLU(J)
 3188 CONTINUE
!
      DO 3189 I=1,IMAX
        IFCOLU(I)=IFCOL3(I)
 3189 CONTINUE
!
      IFCOL1=IFCOLL(1)
      IFCOL2=IFCOLU(IMAX)
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3191)
 3191 FORMAT('THE FOLLOWING COLUMN LIMITS HAVE BEEN SET:')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3193)
 3193 FORMAT('VARIABLE         LOWER LIMIT      UPPER LIMIT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3195)
 3195 FORMAT('---------------------------------------------')
      CALL DPWRST('XXX','BUG ')
      DO 3199 I=1,IMAX
        WRITE(ICOUT,3197)I,IFCOLL(I),IFCOLU(I)
        CALL DPWRST('XXX','BUG ')
 3199 CONTINUE
 3197 FORMAT(I8,12X,I8,9X,I8)
!
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPCOLL
      SUBROUTINE DPCOLO(IHARG,NUMARG,   &
      IDEFCO,   &
      ITEXCO,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE COLOR FOR THE LINES
!              IN TEXT AND FIGURES.
!              THE COLOR WILL BE PLACED
!              IN THE CHARACTER VARIABLE ITEXCO.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEFCO
!     OUTPUT ARGUMENTS--ITEXCO
!                     --IBUGD2
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1982.
!     UPDATED         --OCTOBER   2011. SUPPORT FOR "?"
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCO
      CHARACTER*4 ITEXCO
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGD2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOLO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IDEFCO,NUMARG
   53   FORMAT('IDEFCO,NUMARG = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I)
   56     FORMAT('I,IHARG(I) = ',I8,2X,A4)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!     THE FOLLOWING LINES HAVE BEEN COMMENTED OUT (NOV. 1983)
!     DUE TO CONFLICTS WITH THE DPDECL SUBROUTINE
!     WHICH SPECIFIES WHETHER OR NOT THE TERMINAL
!     IS A COLOR DEVICE OR NOT.
!
!CCCC IF(NUMARG.EQ.0)GO TO 1160
!CCCC IF(IHARG(NUMARG).EQ.'ON')GO TO 1160
!CCCC IF(IHARG(NUMARG).EQ.'OFF')GO TO 1160
      IF(NUMARG.EQ.0)GO TO 9000
      IF(IHARG(NUMARG).EQ.'ON')GO TO 9000
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 9000
      IF(IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA')THEN
        ITEXCO=IDEFCO
      ELSEIF(IHARG(NUMARG).EQ.'?')THEN
        IFOUND='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1191)ITEXCO
 1191   FORMAT('THE CURRENT COLOR IS ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1193)IDEFCO
 1193   FORMAT('THE DEFAULT COLOR IS ',A4)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSE
        ITEXCO=IHARG(NUMARG)
      ENDIF
!
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1181)
 1181   FORMAT('THE COLOR FOR TEXT AND FIGURES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1182)ITEXCO
 1182   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      IF(IBUGD2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOLO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGD2,ISUBRO,IFOUND,IERROR
 9012   FORMAT('IBUGD2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IDEFCO,ITEXCO
 9013   FORMAT('IDEFCO,ITEXCO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOLO
      SUBROUTINE DPCOMB(Y,X,N,MINSIZ,   &
      Y2,XLOW,XUPP,N2,IBUGA3,IERROR)
!
!     PURPOSE--FOR THE CHI-SQUARE GOODNESS OF FIT, IT IS RECOMMENDED
!              THAT CLASSES WITH LESS THAN 5 OBSERVATIONS BE COMBINED
!              IN ORDER FOR THE CHI-SQUARE GOODNESS OF FIT TES TO BE
!              VALID.  THE COMMAND IS:
!
!                 LET Y2 XLOW XHIGH = COMBINE FREQUENCY TABLE YCOUNT XMID
!
!              IT IS ASSUMED THAT THE INPUT CLASSES HAVE EQUAL WIDTH
!              AND THERE ARE NO MISSING CLASSES.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER   2004.
!     UPDATED         --FEBRUARY  2006. MODIFY ALGORITHM.
!                                       ORIGINAL ALGORITHM JUST WENT
!                                       FROM LEFT TO RIGHT.  REVISE
!                                       TO GO FROM LEFT TO CENTER
!                                       AND THEN FROM RIGHT TO
!                                       CENTER.  DO THIS SINCE WE
!                                       TYPICALLY WANT TO COMBINE
!                                       BINS WITH SMALL COUNTS IN
!                                       THE TAILS.
!     UPDATED         --JANUARY   2010. CASE WHERE THERE ARE MANY
!                                       EMPTY BINS CAN CAUSE PROBLEMS.
!                                       TO DEAL WITH THIS, REMOVE
!                                       EMPTY BINS FIRST (BUT COMPUTE
!                                       BIN WIDTH FIRST)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Y2(*)
      DIMENSION XLOW(*)
      DIMENSION XUPP(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='MB  '
      IERROR='NO'
!
      ASUM=0.0
!
      CALL SORTC(X,Y,N,X,Y)
!
      N2=0
      IFLAG=0
      ISTRT=1
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN COMBINE FREQUENCY TABLE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF INPUT CLASSES IS LESS THAN TWO.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF INPUT CLASSES HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 60 I=1,N
        IF(Y(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,62)
   62     FORMAT('      A NEGATIVE FREQUENCY WAS ENCOUNTERED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,63)I,Y(I)
   63     FORMAT('      ROW ',I8,' = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
   60 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPCOMB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)N,MINSIZ
   72   FORMAT('N,MINSIZ = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,X(I),Y(I)
   74     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               **********************************************
!               **  STEP 2--                                **
!               **  COMBINE CLASSES WITH A FREQUECNY LESS   **
!               **  THAN MINSIZ.                            **
!               **********************************************
!
      DELTA=X(2) - X(1)
      DO 100 I=2,N
        ATEMP=X(I) - X(I-1)
        IF(ATEMP.LT.DELTA)DELTA=ATEMP
  100 CONTINUE
      AINC=DELTA/2.0
!
      ICNT=0
      DO 105 I=1,N
        IF(Y(I).GT.0.5)THEN
          ICNT=ICNT+1
          Y(ICNT)=Y(I)
          X(ICNT)=X(I)
        ENDIF
  105 CONTINUE
      N=ICNT
!
      AMINSZ=REAL(MINSIZ)
      IFLAG=0
      ICNT=0
      ISTRT=-1
      EPS=1.0E-10
!
!  FEBRUARY 2006:  SINCE SMALL FREQUENCIES TEND TO OCCUR IN THE
!                  TAILS, MODIFY THE ALGORITHM TO WORK FROM THE
!                  LEFT TAIL TO THE CENTER AND THEN THE RIGHT
!                  TAIL TO THE CENTER (ORIGINAL IMPLEMENTATION
!                  WENT FROM LEFT TAIL TO RIGHT TAIL).
!
!CCCC DO200I=1,N
!CCCC   AMID=X(I)
!CCCC   ATEMP=REAL(INT(Y(I)+0.5))
!CCCC   IF(IFLAG.EQ.0)THEN
!CCCC     IF(ATEMP+EPS.GE.AMINSZ)THEN
!CCCC       ICNT=ICNT+1
!CCCC       XLOW(ICNT)=AMID - AINC
!CCCC       XUPP(ICNT)=AMID + AINC
!CCCC       Y2(ICNT)=ATEMP
!CCCC     ELSE
!CCCC       IFLAG=1
!CCCC       ASUM=ATEMP
!CCCC       ISTRT=I
!CCCC     ENDIF
!CCCC   ELSE
!CCCC     ASUM=ASUM + ATEMP
!CCCC     IF(ASUM+EPS.GE.AMINSZ)THEN
!CCCC       ICNT=ICNT + 1
!CCCC       XLOW(ICNT)=X(ISTRT) - AINC
!CCCC       XUPP(ICNT)=AMID + AINC
!CCCC       Y2(ICNT)=ASUM
!CCCC       ISTRT=-1
!CCCC       IFLAG=0
!CCCC     ENDIF
!CCCC   ENDIF
!C200 CONTINUE
!
!CCCC IF(IFLAG.EQ.1 .AND. ASUM.GT.0.0)THEN
!CCCC   XUPP(ICNT)=X(N) + AINC
!CCCC   Y2(ICNT)=Y2(ICNT) + ASUM
!CCCC ENDIF
!CCCC N2=ICNT
!
       IMID=N/2
!
!  LEFT TAIL TO CENTER
!
      DO 200 I=1,IMID
        AMID=X(I)
        ATEMP=REAL(INT(Y(I)+0.5))
        IF(IFLAG.EQ.0)THEN
          IF(ATEMP+EPS.GE.AMINSZ)THEN
            ICNT=ICNT+1
            XLOW(ICNT)=AMID - AINC
            XUPP(ICNT)=AMID + AINC
            Y2(ICNT)=ATEMP
          ELSE
            IFLAG=1
            ASUM=ATEMP
            ISTRT=I
          ENDIF
        ELSE
          ASUM=ASUM + ATEMP
          IF(ASUM+EPS.GE.AMINSZ)THEN
            ICNT=ICNT + 1
            XLOW(ICNT)=X(ISTRT) - AINC
            XUPP(ICNT)=AMID + AINC
            Y2(ICNT)=ASUM
            ISTRT=-1
            IFLAG=0
          ENDIF
        ENDIF
  200 CONTINUE
!
      IF(IFLAG.EQ.1 .AND. ASUM.GT.0.0)THEN
        XUPP(ICNT)=X(IMID) + AINC
        Y2(ICNT)=Y2(ICNT) + ASUM
      ENDIF
      IFLAG=0
      N2LEFT=ICNT
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,270)
  270   FORMAT('***** DPCOMB--AFTER LEFT TAIL FREQUENCIES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,272)IMID,ICNT
  272   FORMAT('IMID,ICNT = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 273 I=1,ICNT
          WRITE(ICOUT,274)I,XLOW(I),XUPP(I),Y2(I)
  274     FORMAT('I,XLOW(I),XUPP(I),Y2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
  273   CONTINUE
      ENDIF
!
!
!  RIGHT TAIL TO CENTER.  TEMPORARILY STORE IN UPPER PART OF
!  XLOW, XUPP, AND Y2 ARRARYS, WILL THEN FLIP THE SORT AT THE
!  END.
!
      ICNT2=N
      IMID2=IMID+1
      IF(IMID2.GT.N)THEN
        N2=ICNT
        GO TO 9000
      ENDIF
!
      DO 300 I=N,IMID2,-1
        AMID=X(I)
        ATEMP=REAL(INT(Y(I)+0.5))
        IF(IFLAG.EQ.0)THEN
          IF(ATEMP+EPS.GE.AMINSZ)THEN
            ICNT2=ICNT2+1
            XLOW(ICNT2)=AMID - AINC
            XUPP(ICNT2)=AMID + AINC
            Y2(ICNT2)=ATEMP
          ELSE
            IFLAG=1
            ASUM=ATEMP
            ISTOP=I
          ENDIF
        ELSE
          ASUM=ASUM + ATEMP
          IF(ASUM+EPS.GE.AMINSZ)THEN
            ICNT2=ICNT2 + 1
            XLOW(ICNT2)=AMID - AINC
            XUPP(ICNT2)=X(ISTOP) + AINC
            Y2(ICNT2)=ASUM
            ISTOP=-1
            IFLAG=0
          ENDIF
        ENDIF
  300 CONTINUE
!
      IF(IFLAG.EQ.1 .AND. ASUM.GT.0.0)THEN
        XLOW(ICNT2)=X(IMID2) - AINC
        Y2(ICNT2)=Y2(ICNT2) + ASUM
      ENDIF
      N2RGHT=ICNT2
!
!  NOW COPY REVERSE ORDER RIGHT TAIL ENTRIES
!
      DO 400 I=ICNT2,N+1,-1
        ICNT=ICNT+1
        Y2(ICNT)=Y2(I)
        XLOW(ICNT)=XLOW(I)
        XUPP(ICNT)=XUPP(I)
  400 CONTINUE
      N2=ICNT
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPCOMB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,N2
 9012   FORMAT('IERROR,N2 = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N2
          WRITE(ICOUT,9016)I,Y2(I),XLOW(I),XUPP(I)
 9016     FORMAT('I,Y2(I),XLOW(I),XUPP(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOMB
      SUBROUTINE DPCOMM(IHARG,NUMARG,   &
      IDEFCZ,   &
      ICOMCH,   &
      ICOMFL,   &
      IBUGS2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE COMMENT CHARACTOR (DEFAULT IS ".").
!              ALSO CHECK FOR "COMMENT CHECK ON/OFF" COMMAND).
!
!              THE COMMENT CHARACTER IS STORED IN 4 CHARACTERS,
!              BUT ONLY THE FIRST CHARACTER IS USED.
!
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG (AN INTEGER VARIABLE)
!                     --IDEFCZ (A  CHARACTER VARIABLE)
!                     --IBUGS2 (A  CHARACTER VARIABLE)
!     OUTPUT ARGUMENTS--ICOMCH (A CHARACTER VARIABLE)
!                     --ICOMFL (A CHARACTER VARIABLE)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MAY      1990.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCZ
      CHARACTER*4 ICOMCH
      CHARACTER*4 ICOMFL
      CHARACTER*4 IBUGS2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGS2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOMM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDEFCZ
   53 FORMAT('IDEFCZ = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I)
   56 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.1.OR.NUMARG.GE.3)GO TO 9000
      GO TO 1110
!
 1110 CONTINUE
      IF(IHARG(1).EQ.'CHAR')GO TO 1120
      IF(IHARG(1).EQ.'CHEC')GO TO 2120
      GO TO 2120
!
 1120 CONTINUE
      IF(IHARG(2).EQ.'AUTO')GO TO 1150
      IF(IHARG(2).EQ.'DEFA')GO TO 1150
      GO TO 1160
!
 1150 CONTINUE
      IHOLD=IDEFCZ
      GO TO 1180
!
 1160 CONTINUE
      IHOLD=IHARG(2)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ICOMCH=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)ICOMCH(1:1)
 1181 FORMAT('THE COMMENT CHARACTER HAS JUST BEEN SET TO ',   &
      A1)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
 2120 CONTINUE
      IF(IHARG(2).EQ.'ON')GO TO 2150
      IF(IHARG(2).EQ.'OFF')GO TO 2160
      IF(IHARG(2).EQ.'AUTO')GO TO 2150
      IF(IHARG(2).EQ.'DEFA')GO TO 2150
      GO TO 2160
!
 2150 CONTINUE
      IHOLD='ON'
      GO TO 2180
!
 2160 CONTINUE
      IHOLD='OFF'
      GO TO 2180
!
 2180 CONTINUE
      IFOUND='YES'
      ICOMFL=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 2189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IF(ICOMFL.EQ.'ON')WRITE(ICOUT,2181)
 2181 FORMAT('THE FIRST CHARACTER OF DATA FILES WILL BE CHECKED ',   &
      'FOR THE COMMENT CHARACTER.')
      IF(ICOMFL.EQ.'ON')CALL DPWRST('XXX','BUG ')
      IF(ICOMFL.EQ.'OFF')WRITE(ICOUT,2182)
 2182 FORMAT('THE FIRST CHARACTER OF DATA FILES WILL NOT BE ',   &
      'CHECKED FOR THE COMMENT CHARACTER.')
      IF(ICOMFL.EQ.'OFF')CALL DPWRST('XXX','BUG ')
 2189 CONTINUE
      GO TO 9000
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCOMM-')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGS2,IFOUND,IERROR
 9012 FORMAT('IBUGS2,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDEFCZ,ICOMCH
 9013 FORMAT('IDEFCZ,ICOMCH = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCOMM
      SUBROUTINE DPCON2(IVAL,VAL,IH,NH,NMDID0,IBUGD2,IERROR)
!
!     NOTE--EXCEPT FOR THE NMDID0 ARGUMENT
!           (AND SOME BUG WRITE STATEMENTS),
!           THIS SUBROUTINE IS IDENTICAL TO DPCONH.
!           IT HAS BEEN DUPLICATED AND PLACED
!           ON THIS BRANCH OF THE OVERLAY/SEGMENTATION
!           TREE STRUCTURE IN ORDER TO ACHIEVE
!           FASTER EXECUTION TIME.
!
!     NOTE--UPON INPUT, IVALUE IS USUALLY INT(VALUE+0.5), BUT
!           FOR NEGATIVE VALUE, IVALUE SHOULD BE INT(VALUE-0.5)
!
!     NOTE--NMDID0 = THE NUMBER OF DECIMAL
!           PLACES DESIRED A PRIORI.
!           IF NMDID0 IS NEGATIVE, THEN THIS IMPLIES
!           THAT THE ACTUAL NUMBER OF DECIMAL PLACES
!           DESIRED IS NOT SET A PRIORI AND SO SHOULD
!           FLOAT WITH THE DATA VALUE.
!
!     PURPOSE--CONVERT NUMERIC VALUE INTO CORRESPONDING
!              CHARACTER STRING.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MARCH     1983.
!     UPDATED         --FEBRUARY  2011. FIX TO EXTEND THE PRECISION
!                                       A FEW EXTRA PLACES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IH
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHREM
      CHARACTER*4 IHNUM
      CHARACTER*4 IHTEMI
      CHARACTER*4 IHTEMD
!
      DIMENSION IH(*)
      DIMENSION IHTEMI(10)
      DIMENSION IHTEMD(10)
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT---------------------------------------------------------
!
      AINUM=0.0
      FRACT=0.0
      NUMDID=0
      IMAX=0
!
!CCCC IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2')GO TO 90
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2'.AND.IBUGD2.EQ.'OFF')   &
      GO TO 90
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCON2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IVAL,VAL
   52 FORMAT('IVAL,VAL = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NMDID0
   53 FORMAT('NMDID0 = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4
   59 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      ABSVAL=ABS(VAL)
!
      AIVAL=IVAL
      DEL=AIVAL-VAL
      ABSDEL=ABS(DEL)
!
      ABSRAT=ABSDEL
      IF(ABSVAL.GE.1.0)ABSRAT=ABSDEL/ABSVAL
!
!CCCC CUTDEL=10.0**(-16)
!
      CUTDEL=10.0**(-6)
      CUTRAT=10.0**(-6)
!
!CCCC IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2')GO TO 919
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2'.AND.IBUGD2.EQ.'OFF')   &
      GO TO 919
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,911)
  911 FORMAT('***** FROM THE MIDDLE OF DPCON2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,912)ABSVAL
  912 FORMAT('ABSVAL = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,913)VAL,IVAL,AIVAL,DEL,ABSDEL
  913 FORMAT('VAL,IVAL,AIVAL,DEL,ABSDEL = ',E15.7,I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,914)ABSDEL,CUTDEL
  914 FORMAT('ABSDEL,CUTDEL = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,915)ABSRAT,CUTRAT
  915 FORMAT('ABSRAT,CUTRAT = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
  919 CONTINUE
!
      IF(ABSVAL.LT.1.0.AND.ABSDEL.LE.CUTDEL)GO TO 1000
      IF(ABSVAL.GE.1.0.AND.ABSRAT.LE.CUTRAT)GO TO 1000
      GO TO 2000
!
!               ******************************
!               **  STEP XX--               **
!               **  TREAT THE INTEGER CASE  **
!               ******************************
!
 1000 CONTINUE
!
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')WRITE(ICOUT,1005)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')CALL DPWRST('XXX','BUG ')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      WRITE(ICOUT,1005)
 1005 FORMAT('*****INTEGER CASE*****')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      CALL DPWRST('XXX','BUG ')
!
      INUM=IABS(IVAL)
      NUMDII=0
      IF(INUM.EQ.0)NUMDII=NUMDII+1
      IF(INUM.EQ.0)IHTEMI(NUMDII)='0'
      IF(INUM.EQ.0)GO TO 1190
!
      DO 1100 I=1,10
      IF(INUM.LE.0)GO TO 1190
      IRATIO=INUM/10
      IREM=INUM-10*IRATIO
      INUM=IRATIO
      NUMDII=NUMDII+1
      CALL DPCOD2(IREM,IHREM,IBUGD2,IERROR)
      IHTEMI(NUMDII)=IHREM
 1100 CONTINUE
 1190 CONTINUE
      IF(IVAL.LT.0)NUMDII=NUMDII+1
      IF(IVAL.LT.0)IHTEMI(NUMDII)='-'
!
      NH=NUMDII
      IF(NUMDII.LE.0)GO TO 1290
      DO 1200 I=1,NUMDII
      IREV=NUMDII-I+1
      IH(I)=IHTEMI(IREV)
 1200 CONTINUE
 1290 CONTINUE
!
      IF(NMDID0.GE.1)GO TO 2500
      GO TO 9000
!
!               **********************************
!               **  STEP XX--                   **
!               **  TREAT THE NON-INTEGER CASE  **
!               **********************************
!
 2000 CONTINUE
!
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')WRITE(ICOUT,2005)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')CALL DPWRST('XXX','BUG ')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      WRITE(ICOUT,2005)
 2005 FORMAT('*****NON-INTEGER CASE*****')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      CALL DPWRST('XXX','BUG ')
!
      INUM=INT(ABSVAL)
      AINUM=REAL(INUM)
      FRACT=ABSVAL-AINUM
!
      NUMDII=0
      IF(INUM.EQ.0)NUMDII=NUMDII+1
      IF(INUM.EQ.0)IHTEMI(NUMDII)='0'
      IF(INUM.EQ.0)GO TO 2190
!
      DO 2100 I=1,10
        IF(INUM.LE.0)GO TO 2190
        IRATIO=INUM/10
        IREM=INUM-10*IRATIO
        INUM=IRATIO
        NUMDII=NUMDII+1
        CALL DPCOD2(IREM,IHREM,IBUGD2,IERROR)
        IHTEMI(NUMDII)=IHREM
 2100 CONTINUE
 2190 CONTINUE
      IF(VAL.LT.0)NUMDII=NUMDII+1
      IF(VAL.LT.0)IHTEMI(NUMDII)='-'
!
      NUMDID=0
      IF(FRACT.EQ.0.0)NUMDID=0
      IF(FRACT.EQ.0.0)GO TO 2390
!
      ANUM=FRACT
!CCCC NOTE 2011/2: LOSING ACCURACY AT ABOUT 6 DECIMAL PLACES.
!CCCC              INCREASE VALUE OF NLOOP SO THAT WE OBTAIN
!CCCC              A FEW EXTRA DIGITS OF ACCURACY.
!CCCC NLOOP=8-NUMDII
      NLOOP=12-NUMDII
!CCCC CUTOF2=10.0**(-NLOOP+1)
!CCCC CUTOF3=1.0-CUTOF2
      IF(NLOOP.LE.0)GO TO 2390
      DO 2300 I=1,NLOOP
      CUTOF2=10.0**(-NLOOP+I+1)
      CUTOF3=1.0-CUTOF2
      ANUM=ANUM*10.0
      INUM=INT(ANUM)
      AINUM=REAL(INUM)
      DEL3=ANUM-AINUM
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')WRITE(ICOUT,2311)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')CALL DPWRST('XXX','BUG ')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      WRITE(ICOUT,2311)   &
      NLOOP,I,CUTOF3,CUTOF2
 2311 FORMAT('NLOOP,I,CUTOF3,CUTOF2 = ',I8,I8,2E15.7)
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      CALL DPWRST('XXX','BUG ')
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')WRITE(ICOUT,2312)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')CALL DPWRST('XXX','BUG ')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      WRITE(ICOUT,2312)   &
      ANUM,AINUM,DEL3,CUTOF3
 2312 FORMAT('ANUM,AINUM,DEL3,CUTOF3 = ',4E15.7)
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      CALL DPWRST('XXX','BUG ')
      IF(DEL3.GE.CUTOF3)INUM=INUM+1
      IF(DEL3.GE.CUTOF3)ANUM=INUM
      NUMDID=NUMDID+1
      CALL DPCOD2(INUM,IHNUM,IBUGD2,IERROR)
      IHTEMD(NUMDID)=IHNUM
      AINUM=INUM
      DEL2=ANUM-AINUM
      ANUM=DEL2
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')WRITE(ICOUT,2313)
!CCCC IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2')CALL DPWRST('XXX','BUG ')
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      WRITE(ICOUT,2313)   &
      ANUM,AINUM,DEL2,CUTOF2
 2313 FORMAT('ANUM,AINUM,DEL2,CUTOF2 = ',4E15.7)
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CON2'.OR.IBUGD2.EQ.'ON')   &
      CALL DPWRST('XXX','BUG ')
      IF(DEL2.LE.CUTOF2)GO TO 2390
 2300 CONTINUE
 2390 CONTINUE
!
      NH=0
      IF(NUMDII.LE.0)GO TO 2490
      DO 2400 I=1,NUMDII
      NH=NH+1
      IREV=NUMDII-I+1
      IH(NH)=IHTEMI(IREV)
 2400 CONTINUE
 2490 CONTINUE
!
 2500 CONTINUE
      NH=NH+1
      IH(NH)='.'
!
      IMAX=NMDID0
      IF(NMDID0.LT.0)IMAX=NUMDID
!
      IF(IMAX.LE.0)GO TO 2690
      DO 2600 I=1,IMAX
      NH=NH+1
      IF(NMDID0.LT.0)IH(NH)=IHTEMD(I)
      IF(NMDID0.GE.0.AND.I.LE.NUMDID)IH(NH)=IHTEMD(I)
      IF(NMDID0.GE.0.AND.I.GT.NUMDID)IH(NH)='0'
 2600 CONTINUE
 2690 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!CCCC IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2')GO TO 9090
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'CON2'.AND.IBUGD2.EQ.'OFF')   &
      GO TO 9090
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCON2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IVAL,VAL
 9012 FORMAT('IVAL,VAL = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)AIVAL,VAL,DEL,ABSDEL,CUTDEL
 9013 FORMAT('AIVAL,VAL,DEL,ABSDEL,CUTDEL = ',5E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ABSVAL,INUM,AINUM,FRACT
 9014 FORMAT('ABSVAL,INUM,AINUM,FRACT = ',E15.7,2X,I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)NUMDII
 9015 FORMAT('NUMDII = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)(IHTEMI(I),I=1,NUMDII)
 9016 FORMAT('(IHTEMI(I),I=1,NUMDII) = ',20A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9025)NMDID0,NUMDID,IMAX
 9025 FORMAT('NMDID0,NUMDID,IMAX = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9026)(IHTEMD(I),I=1,NUMDID)
 9026 FORMAT('(IHTEMD(I),I=1,NUMDID) = ',20A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9031)NH
 9031 FORMAT('NH = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9032)(IH(I),I=1,NH)
 9032 FORMAT('(IH(I),I=1,NH) = ',20A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9039)IBUGG4,ISUBG4,IERRG4
 9039 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCON2
      SUBROUTINE DPCOND(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IANGLU,MAXNPP,   &
                        CLLIMI,CLWIDT,   &
                        ICONT,NUMHPP,NUMVPP,IMANUF,   &
                        XMATN,YMATN,XMITN,YMITN,   &
                        ISQUAR,   &
                        IVGMSW,IHGMSW,   &
                        IMPSW,IMPNR,IMPNC,IMPCO,   &
                        PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                        MAXNXT,   &
                        ALOWFR,ALOWDG,   &
                        IFORSW,   &
                        ANOPL1,ANOPL2,ISEED,IBOOSS,BARHEF,BARWEF,   &
                        ICAPSW,   &
                        IBUGG2,IBUGG3,IBUGCO,IBUGEV,IBUGQ,   &
                        IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                        IFOUND,IERROR)
!
!     PURPOSE--GENERATE A CONDITIONING PLOT (COPLOT)
!            --ALLOWABLE SYNTAXES:
!                CONDITIONING PLOT Y COND
!                CONDITIONING PLOT Y X COND
!                CONDITIONING PLOT Y X COND TAG
!                CONDITIONING PLOT Y X COND1 COND2
!                CONDITIONING PLOT Y X COND1 COND2 TAG
!                CONDITIONING PLOT Y1 ... YK X COND TAG
!             --THAT IS, THERE ARE:
!               1) ONE OR MORE RESPONSE VARIABLES (DETERMINED BY
!                  SET COND PLOT RESPONSE VARIABLES <VALUE>
!               2) AN OPTIONAL INDEPENDENT VARIABLE.  THIS IS
!                  DETERMINED BT THE PLOT TYPE.
!                  NOTE: 3D PLOT TYPES WILL HAVE EITHER 2 OR 3
!                  INDEPENDENT VARIABLES.
!               3) EITHER ONE OR TWO CONDITIONING VARIABLES (DETERMINED
!                  BY: SET COND PLOT CONDITION VARIABLES <1/2>)
!               4) AN OPTIONAL TAG VARIABLE (DETERMINED BY
!                  SET COND PLOT TAG <ON/OFF>)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/9
!     ORIGINAL VERSION --SEPTEMBER 1999.
!     UPDATED          --APRIL     2007. ADD ROSE PLOT
!     UPDATED          --AUGUST    2007. CALL LIST TO MAINGR
!     UPDATED          --JUNE      2014. WRITE YPLOT, XPLOT, TAGPLOT TO
!                                        DPST5F.DAT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES---------------
!
      REAL CLLIMI(*)
      REAL CLWIDT(*)
!
      INCLUDE 'DPCOPA.INC'
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICONT
      CHARACTER*4 IPOWE
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IANGLU
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGUG
      CHARACTER*4 IBUGU2
      CHARACTER*4 IBUGU3
      CHARACTER*4 IBUGU4
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISQUAR
      CHARACTER*4 IVGMSW
      CHARACTER*4 IHGMSW
      CHARACTER*4 IREPCH
      CHARACTER*4 IMPSW
!
      CHARACTER*4 ICPLLD
      CHARACTER*4 ICPLDI
      CHARACTER*4 IEMPTY
      CHARACTER*4 IFEED9
      CHARACTER*4 ICPLFZ
      CHARACTER*4 ICPLPZ
      CHARACTER*4 ICPLLZ
      CHARACTER*4 ICPLTZ
      CHARACTER*4 ICPLL2
      CHARACTER*4 ICPLXZ
      CHARACTER*4 ICPLYZ
      CHARACTER*4 ICPLDZ
      CHARACTER*4 ICPLZT
      CHARACTER*4 ICPLZ2
      CHARACTER*4 ICPLZ3
      CHARACTER*4 ICPLZ4
      CHARACTER*4 ILFLAX
      CHARACTER*4 ILFLAY
!
      CHARACTER*4 IMANUF
      CHARACTER*4 IPLTTY
      CHARACTER*4 IPLOTT
      CHARACTER*4 IFLGIN
      CHARACTER*4 IFLGX
      CHARACTER*4 IFLGY
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBSZ
!
      CHARACTER*4 IFITA2
      CHARACTER*4 IOP
!
      CHARACTER*4 ICT
      CHARACTER*4 IC2T
      CHARACTER*4 IHT(25)
      CHARACTER*4 IH2T(25)
      CHARACTER*4 IARGTT(25)
      REAL ARGT(25)
!
!  MAXY IS THE MAXIMUM NUMBER OF VARIABLES TO USE IN CREATING THE
!  CONDITIONING PLOT   CURVE
!
      PARAMETER(MAXY=50)
      CHARACTER*40 INAME
      CHARACTER*4 IVARN1(MAXY)
      CHARACTER*4 IVARN2(MAXY)
      CHARACTER*4 IVARTY(MAXY)
      DIMENSION ILIS(MAXY)
      DIMENSION PVAR(MAXY)
      DIMENSION NRIGHT(MAXY)
      DIMENSION ICOLL(MAXY)
!
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION TEMP(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
!
!-----COMMON------------------------------------------------------
!
      DIMENSION ADIST1(MAXY)
      DIMENSION ADIST2(MAXY)
!
      INCLUDE 'DPCOZ3.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOSP.INC'
!
      EQUIVALENCE (G3RBAG(KGARB1),TEMP(1))
      EQUIVALENCE (G3RBAG(KGARB2),TEMP2(1))
      EQUIVALENCE (G3RBAG(KGARB3),TEMP3(1))
      EQUIVALENCE (G3RBAG(KGARB4),XTEMP1(1))
      EQUIVALENCE (G3RBAG(KGARB5),XTEMP2(1))
!
!
!-----COMMON VARIABLES (GENERAL)----------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-------------------------------------------------
!
      IFOUND='YES'
      IERROR='NO'
      ISUBN1='DPCO'
      ISUBN2='ND  '
      ICASPL='COND'
      ICPLLD='ON'
      ICPLDI='BLAN'
!
      IXC2=0
      IXC3=0
      NPOS2=0
!
      IPLTTY='BIVA'
      IF(ICPLPT.EQ.'HIST')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'RUNS')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'PERC')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'AUTO')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'LAG ')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'PROB')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'PPCC')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'DENS')IPLTTY='UNIV'
      IF(ICPLPT.EQ.'ROSE')IPLTTY='UNIV'
      ICPLXV=1
      IF(IPLTTY.EQ.'UNIV')ICPLXV=0
      IF(ICPLPT.EQ.'YACU')ICPLXV=3
      IF(ICPLPT.EQ.'3DPL')ICPLXV=2
!
      ICPLRV=INT(PCPLRV+0.5)
      IF(ICPLRV.LT.1)ICPLRV=1
      ITAG=0
      IF(ICPLTA.EQ.'ON'.AND.ICPLPT.EQ.'PLOT')ITAG=1
      ICPLTV=INT(PCPLTV+0.5)
      IF(ICPLTV.LT.1)ICPLTV=1
      IF(ICPLTV.GT.2)ICPLTV=2
!
      IFLAGV=ICPLRV+ICPLXV+ICPLTV+ITAG
!
      IRC1=1
      IRC2=ICPLRV
      ICOL=IRC2
      IF(ICPLXV.GE.1)ICOL=ICOL+1
      IXC1=ICOL
      IF(ICPLXV.GE.2)THEN
        ICOL=ICOL+1
        IXC2=ICOL
      ENDIF
      IF(ICPLXV.GE.3)THEN
        ICOL=ICOL+1
        IXC3=ICOL
      ENDIF
      ICOL=ICOL+1
      ICC1=ICOL
      IF(ICPLTV.EQ.2)ICOL=ICOL+1
      ICC2=ICOL
      IF(ITAG.GT.0)ICOL=ICOL+1
      ITC1=ICOL
!
!     WRITE XPLOT, YPLOT, TAGPLOT TO "dpst5f.dat"
!
      IOP='OPEN'
      IFLG11=0
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=1
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG2,ISUBRO,IERROR)
      ICNTPL=0
      IFITA2=IFITAU
      IFITAU='OFF'
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  TREAT THE CONDITIONING PLOT   CASE **
!               *****************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2,NUMARG
   52   FORMAT('ICASPL,IAND1,IAND2,NUMARG = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GT.0)THEN
          DO 61 I=1,NUMARG
            WRITE(ICOUT,62)I,IHARG(I),IARGT(I)
   62       FORMAT('I,IHARG(I),IARGT(I) = ',I8,2X,A4,2X,A4)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
        WRITE(ICOUT,71)ICPLLA,ICPLTA,ICPLPT,ICPLFI,ICPLFR
   71   FORMAT('ICPLLA,ICPLTA,ICPLPT,ICPLFI,ICPLFR = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,73)CLLIMI(1),CLLIMI(2),CLWIDT(1),CLWIDT(2)
   73   FORMAT('CLLIMI(1),CLLIMI(2),CLWIDT(1),CLWIDT(2) = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  SHIFT COMMAND LINE ARGMENTS                     **
!               ******************************************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'PLOT')THEN
        ISHIFT=1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
      ICOM='PLOT'
      ICOM2='    '
      IFOUND='YES'
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  CHECK FOR THE PROPER NUMBER OF INPUT ARGUMENTS.  **
!               *******************************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CONDITION PLOT'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IF(IFPLPT.EQ.'HIST')IFLAGE=0
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=MAXY
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXY,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLL,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLL(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLL(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               **************************************************
!               **  STEP 12B-                                   **
!               **  NUMBER OF VARIABLES MUST EQUAL IFLAGV       **
!               **************************************************
!
      ISTEPN='12B'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMVAR.NE.IFLAGV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1291)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1293)ICPLRV
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1294)ICPLXV
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1295)ICPLTV
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1296)ITAG
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1297)NUMVAR
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1328)
 1328   FORMAT('THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,1329)(IANS(J),J=1,MIN(IWIDTH,100))
 1329     FORMAT('    ',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IERROR='YES'
        GO TO 9000
      ENDIF
 1291 FORMAT('***** ERROR IN DPCOND--EXPECTED')
 1293 FORMAT('         ',I8,'RESPONSE VARIABLES')
 1294 FORMAT('         ',I8,'INDEPENDENT VARIABLES')
 1295 FORMAT('         ',I8,'CONDITIONING VARIABLES')
 1296 FORMAT('         ',I8,'TAG VARIABLES')
 1297 FORMAT('      DETECTED ',I8,' VARIABLES.')
!
!               ***************************************
!               **  STEP 13--                        **
!               **  CHECK THE VALIDITY OF EACH       **
!               **  OF THE VARIABLES.                **
!               **  ALSO CHECK TO ASSURE THAT EACH   **
!               **  OF THE VARIABLES HAS AT LEAST    **
!               **  2 OBSERVATIONS.                  **
!               ***************************************
!
      ISTEPN='13'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFLAG=0
      IFLAG2=0
      DO 1300 I=1,NUMVAR
!
        IF(I.EQ.ICC1)THEN
          ICOL=ICOLL(I)
          J=0
          DO 1261 ITEMP=1,NRIGHT(I)
            J=J+1
            NIN=J
            IJ=MAXN*(ICOL-1)+ITEMP
            IF(ICOL.LE.MAXCOL)TEMP(J)=V(IJ)
            IF(ICOL.EQ.MAXCP1)TEMP(J)=PRED(ITEMP)
            IF(ICOL.EQ.MAXCP2)TEMP(J)=RES(ITEMP)
            IF(ICOL.EQ.MAXCP3)TEMP(J)=YPLOT(ITEMP)
            IF(ICOL.EQ.MAXCP4)TEMP(J)=XPLOT(ITEMP)
            IF(ICOL.EQ.MAXCP5)TEMP(J)=X2PLOT(ITEMP)
            IF(ICOL.EQ.MAXCP6)TEMP(J)=TAGPLO(ITEMP)
 1261     CONTINUE
          IWRITE='OFF'
          CALL DISTIN(TEMP,NIN,IWRITE,XTEMP1,NOUT,IBUGG3,IERROR)
          IF(NOUT.GT.MAXY)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1266)
 1266       FORMAT('***** ERROR IN CONDITIONING PLOT--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1267)NOUT
 1267       FORMAT('      NUMBER OF DISTINCT SUBSETS, ',I8,   &
                   ' EXCEEDS THE ')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1268)MAXY
 1268       FORMAT('      MAXIMUM ALLOWABLE OF ',I8)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            DO 1269 KK=1,NOUT
              ADIST1(KK)=XTEMP1(KK)
 1269       CONTINUE
          ENDIF
        ENDIF
!
        IF(ICPLTV.EQ.2.AND.I.EQ.ICC2)THEN
          ICOL=ICOLL(I)
          J=0
          DO 1271 ITEMP=1,NRIGHT(I)
            J=J+1
            NIN2=J
            IJ=MAXN*(ICOL-1)+ITEMP
            IF(ICOL.LE.MAXCOL)TEMP2(J)=V(IJ)
            IF(ICOL.EQ.MAXCP1)TEMP2(J)=PRED(ITEMP)
            IF(ICOL.EQ.MAXCP2)TEMP2(J)=RES(ITEMP)
            IF(ICOL.EQ.MAXCP3)TEMP2(J)=YPLOT(ITEMP)
            IF(ICOL.EQ.MAXCP4)TEMP2(J)=XPLOT(ITEMP)
            IF(ICOL.EQ.MAXCP5)TEMP2(J)=X2PLOT(ITEMP)
            IF(ICOL.EQ.MAXCP6)TEMP2(J)=TAGPLO(ITEMP)
 1271     CONTINUE
          IWRITE='OFF'
          CALL DISTIN(TEMP2,NIN2,IWRITE,XTEMP1,NOUT2,IBUGG3,IERROR)
          IF(NOUT2.GT.MAXY)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1276)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1277)NOUT2
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1278)MAXY
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            DO 1279 KK=1,NOUT
              ADIST2(KK)=XTEMP1(KK)
 1279       CONTINUE
          ENDIF
        ENDIF
 1276 FORMAT('***** ERROR IN CONDITIONING PLOT--')
 1277 FORMAT('      NUMBER OF DISTINCT SUBSETS, ',I8,' EXCEEDS THE ')
 1278 FORMAT('      MAXIMUM ALLOWABLE OF ',I8)
!
 1300 CONTINUE
!
!               **************************************************
!               **   STEP 1--                                   **
!               **   SAVE INITIAL SETTINGS                      **
!               **************************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COND')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFLAG=1
      CALL DPSPM5(IFLAG,IMPSW,IMPCO,IMPNR,IMPNC,   &
                  IBUGG2,ISUBRO,IFOUND,IERROR)
!
      ICPLFZ=ICPLFR
      ICPLL2=ICPLLA
      IF(ICPLFR.EQ.'CONN')ICPLFR='DEFA'
      IF(ICPLFR.EQ.'USER'.AND.ICPLLA.EQ.'BOX')ICPLLA='ON'
      IF(ICPLLA.EQ.'BOX ')THEN
        ICPLLD='ON'
      ENDIF
      ICPLTZ=ICPLTA
      ICPLPZ=ICPLPT
      ICPLLZ=ICPLLD
      ICPLZT=ICPLST
      ICPLZ2=ICPLS2
      ICPLZ3=ICPLS3
      ICPLZ4=ICPLS4
      ICPLXZ=ICPLXA
      ICPLYZ=ICPLYA
      ICPLDZ=ICPLDI
!
      ILFLAX='OFF'
      ILFLAY='OFF'
      IF(IY1MIN.EQ.'FIXE'.AND.IY1MAX.EQ.'FIXE')THEN
        ILFLAY='ON'
      ENDIF
      IF(IX1MIN.EQ.'FIXE'.AND.IX2MAX.EQ.'FIXE')THEN
        ILFLAX='ON'
      ENDIF
!
      IFEED9=IFEEDB
      IFLGIN='OFF'
      IFLGY='OFF'
      IFLGX='OFF'
!
      IF(ICPLTA.EQ.'ON'.AND.ICPLPT.EQ.'PLOT')THEN
        ISHIFT=ILOCQ-1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        ISHIFT=NUMVAR-1
        CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        DO 1509 I=1,ISHIFT
          IHARG(I)=IVARN1(I)
          IHARG2(I)=IVARN2(I)
 1509   CONTINUE
        NUMVAR=NUMVAR-1
        IF(IPLTTY.EQ.'UNIV')THEN
          IF(NUMVAR.LT.1)GO TO 9000
        ELSEIF(IPLTTY.EQ.'BIVA')THEN
          IF(NUMVAR.LT.2)GO TO 9000
        ENDIF
        ILOCQ=ISHIFT+1
      ENDIF
!
      IMPSW3=IMPSW
      IMPCO2=IMPCO
      IMPNR2=IMPNR
      IMPNC2=IMPNC
      IMPSW='ON'
      IMPCO=1
      IMPCO9=IMPCO
!
!  DETERMINE NUMBER OF ROWS AND COLUMNS FOR PLOT.  BASED ON
!  BOTH THE NUMBER OF RESPONSE VARIABLES AND NUMBER OF DISTINCT
!  VALUES IN THE CONDITIONING VARIABLES.
!
      IF(ICPLRV.EQ.1)THEN
        IF(ICPLTV.EQ.1)THEN
          NPLOTS=NOUT
          IF(IMPNR*IMPNC.LT.NPLOTS)THEN
            IMPNC=INT(SQRT(REAL(NPLOTS-1)))+1
            IMPNR=1
            IF(NPLOTS.GE.11)THEN
              IMPNR=INT(NPLOTS/IMPNC)+1
            ELSEIF(NPLOTS.GE.7)THEN
              IMPNR=3
            ELSEIF(NPLOTS.GE.3)THEN
              IMPNR=2
            ENDIF
          ENDIF
          IFACTV=NPLOTS
        ELSE
          NPLOTS=NOUT*NOUT2
          IMPNR=NOUT
          IMPNC=NOUT2
          IFACTV=NPLOTS
        ENDIF
      ELSE
        IF(ICPLTV.EQ.1)THEN
          IMPNR=ICPLRV
          IMPNC=NOUT
          NPLOTS=IMPNR*IMPNC
          IFACTV=NOUT
        ELSE
          IMPNR=ICPLRV*NOUT
          IMPNC=NOUT2
          NPLOTS=IMPNR*IMPNC
          IFACTV=NOUT*NOUT2
        ENDIF
      ENDIF
!
      IROWT=ICPLRV
      ICOLT=IFACTV
      IF(ICPLLA.EQ.'BOX')THEN
        IMPNR=IMPNR+1
        IMPNC=IMPNC+1
        IROWT=ICPLRV+1
        ICOLT=IFACTV+1
      ENDIF
!
      IXAXIS=0
      IYAXIS=0
!
!  2-VARIABLE PLOTS
!
      IF(ICPLPT.EQ.'PLOT')THEN
        ICT='PLOT'
        IC2T='    '
        NCCOMM=0
        IPLOTT='PLOT'
        IFLGIN='NO'
        IF((IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA').OR.   &
           (IX1MIN.EQ.'FLOA'.AND.IX1MAX.EQ.'FLOA'))THEN
          IF((PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN).OR.   &
             (PCPXLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN))THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='ON'
          ENDIF
        ENDIF
        GO TO 6999
      ENDIF
      IF(ICPLPT.EQ.'STAT')THEN
        ICT=ICPLST
        IC2T=ICPLS2
        NCCOMM=0
        IF(ICPLS3.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLS3
          IH2T(NCCOMM)=ICPLS4
        ENDIF
        NCCOMM=NCCOMM+1
        IHT(NCCOMM)='PLOT'
        IH2T(NCCOMM)='    '
        IPLOTT='STAT'
        IFLGIN='NO'
        GO TO 6999
      ENDIF
      IF(ICPLPT.EQ.'BIHI')THEN
        ICT='RELA'
        IC2T='TIVE'
        IHT(1)='BIHI'
        IH2T(1)='STOG'
        NCCOMM=1
        IPLOTT='BIHI'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            IRHSTG='PERC'
            GY1MIN=-0.6
            GY1MAX=0.6
            GY2MIN=-0.6
            GY2MAX=0.6
            IY1MIN='FIXE'
            IY1MAX='FIXE'
            IY2MIN='FIXE'
            IY2MAX='FIXE'
            IYAXIS=1
          ENDIF
        ENDIF
        GO TO 6999
      ENDIF
!
      IF(ICPLPT.EQ.'BOXC')THEN
        ICT='BOX '
        IC2T='    '
        IHT(1)='COX '
        IH2T(1)='    '
        IHT(2)='LINE'
        IH2T(2)='ARIT'
        IHT(3)='PLOT'
        IH2T(3)='    '
        NCCOMM=3
        IPLOTT='CBXC'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            GY1MIN=-1.0
            GY1MAX=1.0
            GY2MIN=-1.0
            GY2MAX=1.0
            IY1MIN='FIXE'
            IY1MAX='FIXE'
            IY2MIN='FIXE'
            IY2MAX='FIXE'
            IYAXIS=1
          ENDIF
        ENDIF
        GO TO 6999
      ENDIF
      IF(ICPLPT.EQ.'QQPL')THEN
        ICT='QUAN'
        IC2T='TILE'
        IHT(1)='QUAN'
        IH2T(1)='TILE'
        IHT(2)='PLOT'
        IH2T(2)='    '
        NCCOMM=2
        IPLOTT='QQSP'
        IFLGIN='NO'
        IF((IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA').OR.   &
           (IX1MIN.EQ.'FLOA'.AND.IX1MAX.EQ.'FLOA'))THEN
          IF((PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN).OR.   &
             (PCPXLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN))THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='ON'
          ENDIF
        ENDIF
        GO TO 6999
      ENDIF
      IF(ICPLPT.EQ.'ROS2')THEN
        ICT='ROSE'
        IC2T='    '
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='ROSE'
        IFLGIN='NO'
        IFLGY='OFF'
        IFLGX='OFF'
        GO TO 6999
      ENDIF
!CCCC IF(ICPLPT.EQ.'CROS')THEN
!CCCC   GO TO 7999
!CCCC ENDIF
!
! 3-D PLOTS
!
      IF(ICPLPT.EQ.'YACU')THEN
        ICT='YATE'
        IC2T='S   '
        IHT(1)='CUBE'
        IH2T(1)='    '
        IHT(2)='PLOT'
        IH2T(2)='    '
        NCCOMM=2
        IPLOTT='YACU'
        IFLGIN='NO'
        GO TO 7499
      ENDIF
      IF(ICPLPT.EQ.'3DPL')THEN
        ICT='3D  '
        IC2T='    '
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='3DPL'
        IFLGIN='NO'
        GO TO 7499
      ENDIF
!
!
!  1-VARIABLE PLOTS
!
      IF(ICPLPT.EQ.'HIST')THEN
        ICT='RELA'
        IC2T='TIVE'
        IHT(1)='HIST'
        IH2T(1)='OGRA'
        NCCOMM=1
        IPLOTT='HIST'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            IRHSTG='PERC'
            GY1MIN=0.0
            GY1MAX=0.6
            GY2MIN=0.0
            GY2MAX=0.6
            IY1MIN='FIXE'
            IY1MAX='FIXE'
            IY2MIN='FIXE'
            IY2MAX='FIXE'
            IYAXIS=1
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'DENS')THEN
        ICT='KERN'
        IC2T='EL  '
        IHT(1)='DENS'
        IH2T(1)='ITY '
        IHT(2)='PLOT'
        IH2T(2)='    '
        NCCOMM=2
        IPLOTT='CDEN'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            IRHSTG='PERC'
            GY1MIN=0.0
            GY1MAX=0.6
            GY2MIN=0.0
            GY2MAX=0.6
            IY1MIN='FIXE'
            IY1MAX='FIXE'
            IY2MIN='FIXE'
            IY2MAX='FIXE'
            IYAXIS=1
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'RUNS')THEN
        ICT='RUN '
        IC2T='    '
        IHT(1)='SEQU'
        IH2T(1)='ENCE'
        IHT(2)='PLOT'
        IH2T(2)='    '
        NCCOMM=2
        IPLOTT='CRUN'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='OFF'
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'PERC')THEN
        ICT='PERC'
        IC2T='ENT '
        IHT(1)='POIN'
        IH2T(1)='T   '
        IHT(2)='PLOT'
        IH2T(2)='    '
        NCCOMM=2
        IPLOTT='CPER'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='OFF'
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'AUTO')THEN
        ICT='AUTO'
        IC2T='CORR'
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='CRUN'
        IFLGIN='NO'
        IF(IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA')THEN
          IF(PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN)THEN
            GY1MIN=-1.0
            GY1MAX=1.0
            GY2MIN=-1.0
            GY2MAX=1.0
            IY1MIN='FIXE'
            IY1MAX='FIXE'
            IY2MIN='FIXE'
            IY2MAX='FIXE'
            IYAXIS=1
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'SPEC')THEN
        ICT='SPEC'
        IC2T='TRAL'
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='SPEC'
        IFLGIN='NO'
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'ROSE')THEN
        ICT='ROSE'
        IC2T='    '
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='ROSE'
        IFLGIN='NO'
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'LAG ')THEN
        ICT='LAG '
        IC2T='    '
        IHT(1)='PLOT'
        IH2T(1)='    '
        NCCOMM=1
        IPLOTT='LAG '
        IFLGIN='NO'
        IF((IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA').OR.   &
           (IX1MIN.EQ.'FLOA'.AND.IX1MAX.EQ.'FLOA'))THEN
          IF((PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN).OR.   &
             (PCPXLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN))THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='ON'
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'PROB')THEN
        ICT=ICPLP1
        IC2T='    '
        NCCOMM=0
        IF(ICPLP2.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLP2
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLP3.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLP3
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLP4.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLP4
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLP5.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLP5
          IH2T(NCCOMM)='    '
        ENDIF
        NCCOMM=NCCOMM+1
        IHT(NCCOMM)='PROB'
        IH2T(NCCOMM)='ABIL'
        NCCOMM=NCCOMM+1
        IHT(NCCOMM)='PLOT'
        IH2T(NCCOMM)='    '
        IPLOTT='PROB'
        IFLGIN='NO'
        IF((IY1MIN.EQ.'FLOA'.AND.IY1MAX.EQ.'FLOA').OR.   &
           (IX1MIN.EQ.'FLOA'.AND.IX1MAX.EQ.'FLOA'))THEN
          IF((PCPYLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN).OR.   &
             (PCPXLL(1).EQ.CPUMIN.AND.PCPYUL(1).EQ.CPUMIN))THEN
            IFLGIN='YES'
            IFLGY='ON'
            IFLGX='ON'
          ENDIF
        ENDIF
        GO TO 5999
      ENDIF
      IF(ICPLPT.EQ.'PPCC')THEN
        ICT=ICPLC1
        IC2T='    '
        NCCOMM=0
        IF(ICPLC2.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLC2
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLC3.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLC3
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLC4.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLC4
          IH2T(NCCOMM)='    '
        ENDIF
        IF(ICPLC5.NE.'    ')THEN
          NCCOMM=NCCOMM+1
          IHT(NCCOMM)=ICPLC5
          IH2T(NCCOMM)='    '
        ENDIF
        NCCOMM=NCCOMM+1
        IHT(NCCOMM)='PPCC'
        IH2T(NCCOMM)='    '
        NCCOMM=NCCOMM+1
        IHT(NCCOMM)='PLOT'
        IH2T(NCCOMM)='    '
        IPLOTT='PPCC'
        IFLGIN='NO'
        GO TO 5999
      ENDIF
      GO TO 8000
!
!               *******************************************
!               **   STEP 21--                           **
!               **   GENERATE THE RUN SEQUENCE    PLOTS  **
!               **   GENERATE THE HISTOGRAM       PLOTS  **
!               **   GENERATE THE PERCENTILE      PLOTS  **
!               **   GENERATE THE AUTOCORRELATION PLOTS  **
!               **   GENERATE THE SPECTRAL        PLOTS  **
!               **   GENERATE THE LAG             PLOTS  **
!               **   GENERATE THE PROBABILITY     PLOTS  **
!               **   GENERATE THE PPCC            PLOTS  **
!               **   GENERATE THE KERNEL DENSITY  PLOTS  **
!               *******************************************
!
 5999 CONTINUE
!
!  IF NO PRIOR LIMITS SET FOR Y AXIS, USE 0 TO 0.6 (THIS MAY NOT
!  BE OPTIMAL, BUT IT WILL ALWAYS SHOW ALL THE DATA).
!
      IF(NPLOTS.LT.1)GO TO 8000
!
      ISHIFT=ILOCQ-1
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
      IBUGG2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8000
!
!  CREATE BASIC COMMAND LINE, FOR EXAMPLE:
!    RELATIVE HISTOGRAM Y SUBSET COND1 = <VAL> SUBSET COND2 = <VAL>
!  WHERE COND2 IS OPTIONAL
!
!  FOR SOME PLOT TYPES, NEED TO DO AN INITIAL PLOT TO SET PLOT LIMITS
!
      ISHIFT=NCCOMM+1
      IF(ICPLTV.GE.1)ISHIFT=ISHIFT+4
      IF(ICPLTV.GE.2)ISHIFT=ISHIFT+4
      CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGG2,IERROR)
      ICOM=ICT
      ICOM2=IC2T
      DO 6006 II=1,NCCOMM
        IHARG(II)=IHT(II)
        IHARG2(II)=IH2T(II)
        IARGT(II)='WORD'
 6006 CONTINUE
      NWORD=NCCOMM+1
      NPOS=NWORD
      IHARG(NWORD)=IVARN1(1)
      IHARG2(NWORD)=IVARN2(1)
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='SUBS'
      IHARG2(NWORD)='ET  '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)=IVARN1(ICC1)
      IHARG2(NWORD)=IVARN2(ICC1)
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='=   '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='0  '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='NUMB'
      NPOS1=NWORD
!
      IF(ICPLTV.EQ.2)THEN
        NWORD=NWORD+1
        IHARG(NWORD)='SUBS'
        IHARG2(NWORD)='ET  '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)=IVARN1(ICC2)
        IHARG2(NWORD)=IVARN2(ICC2)
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='=   '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='0  '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='NUMB'
        NPOS2=NWORD
      ENDIF
      NARGT=NUMARG
!
      DO 6020 I=1,NARGT
        IHT(I)=IHARG(I)
        IH2T(I)=IHARG2(I)
        IARGTT(I)=IARGT(I)
        ARGT(I)=ARG(I)
 6020 CONTINUE
!
      IPLOT=0
      DO 6200 IRES=1,IROWT
!
!  CREATE INITIAL PLOT TO DETERMINE SCALE
!
      IF(IFLGIN.EQ.'YES')THEN
        ISHIFT=NWORD
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        ISHIFT=NCCOMM+1
        CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        ICOM=ICT
        ICOM2=IC2T
        DO 6210 II=1,NCCOMM
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)='WORD'
 6210   CONTINUE
        NTEMP=NCCOMM+1
        IHARG(NTEMP)=IVARN1(IRES)
        IHARG2(NTEMP)=IVARN2(IRES)
        IARGT(NTEMP)='WORD'
!
!  GENERATE THE DUMMY PLOT
!
        ICHAPA(1)='BLAN'
        ILINPA(1)='BLAN'
        IBARSW(1)='OFF'
        ISPISW(1)='OFF'
!
        GY1MIN=CPUMIN
        GY1MAX=CPUMAX
        GY2MIN=CPUMIN
        GY2MAX=CPUMAX
        GX1MIN=CPUMIN
        GX1MAX=CPUMAX
        GX2MIN=CPUMIN
        GX2MAX=CPUMAX
        IY1MIN='FLOA'
        IY1MAX='FLOA'
        IY2MIN='FLOA'
        IY2MAX='FLOA'
        IX1MIN='FLOA'
        IX1MAX='FLOA'
        IX2MIN='FLOA'
        IX2MAX='FLOA'
        CALL MAINGR(ANOPL1,ANOPL2,NPLOTV,NPLOTP,NS,ICASPL,   &
                    MAXNPP,ISEED,IBOOSS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    BARHEF,BARWEF,   &
                    IRHSTG,IHSTCW,IHSTEB,IHSTOU,IASHWT,IHSTMC,IHSTOP,   &
                    ICAPSW,IFORSW,   &
                    IGUIFL,IERRFA,IFRALI,   &
                    IAND1,IAND2,ICONT,NUMHPP,NUMVPP,   &
                    MAXNXT,   &
                    ISUBRO,IFOUND,IERROR)
!
        IX1TSW='OFF'
        IX1ZSW='OFF'
        IX2TSW='OFF'
        IX2ZSW='OFF'
        IY1TSW='OFF'
        IY1ZSW='OFF'
        IY2TSW='OFF'
        IY2ZSW='OFF'
        IX1FSW='OFF'
        IX2FSW='OFF'
        IY1FSW='OFF'
        IY2FSW='OFF'
        IERASW='ON'
        DO 6250 I=1,MAXCH
          IX1LTE(I)='    '
          IX2LTE(I)='    '
          IY1LTE(I)='    '
          IY2LTE(I)='    '
 6250   CONTINUE
        NCX1LA=0
        NCX2LA=0
        NCY1LA=0
        NCY2LA=0
        NCTITL=0
        ICONT=IDCONT(1)
        NUMHPP=IDNHPP(1)
        IPOWE=IDPOWE(1)
        IMPARG=2
        CALL DPGRAP(Y,X,X3D,D,N,NPLOTP,ICASPL,ICONT,IPOWE,NUMHPP,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,   &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                    YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IMPARG,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    MAXCOL,   &
                    DSIZE,DSYMB,DCOLOR,DFILL,   &
                    ICAPSW,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                    IERROR)
!
        ICNTPL=ICNTPL+1
        IF(NPLOTP.GT.0)THEN
          DO 3115 II=1,NPLOTP
            WRITE(IOUNI5,3118)ICNTPL,Y(II),X(II),D(II)
 3115     CONTINUE
 3118     FORMAT(I12,3E15.7)
        ENDIF
!
        IF(IERROR.EQ.'NO')IAND1=IAND2
        IMPCO=IMPCO-1
        IF(IFLGY.EQ.'ON')THEN
          GY1MIN=FY1MNZ
          GY1MAX=FY1MXZ
          GY2MIN=FY2MNZ
          GY2MAX=FY2MXZ
          IY1MIN='FIXE'
          IY1MAX='FIXE'
          IY2MIN='FIXE'
          IY2MAX='FIXE'
        ELSE
          GY1MIN=GY1MNS
          GY1MAX=GY1MXS
          GY2MIN=GY2MNS
          GY2MAX=GY2MXS
          IY1MIN=IY1MNS
          IY1MAX=IY1MXS
          IY2MIN=IY2MNS
          IY2MAX=IY2MXS
        ENDIF
        IF(IFLGX.EQ.'ON')THEN
          GX1MIN=FX1MNZ
          GX1MAX=FX1MXZ
          GX2MIN=FX2MNZ
          GX2MAX=FX2MXZ
          IX1MIN='FIXE'
          IX1MAX='FIXE'
          IX2MIN='FIXE'
          IX2MAX='FIXE'
        ELSE
          GX1MIN=GX1MNS
          GX1MAX=GX1MXS
          GX2MIN=GX2MNS
          GX2MAX=GX2MXS
          IX1MIN=IX1MNS
          IX1MAX=IX1MXS
          IX2MIN=IX2MNS
          IX2MAX=IX2MXS
        ENDIF
!
        IX1TSW=IX1TSV
        IX1ZSW=IX1ZSV
        IX2TSW=IX2TSV
        IX2ZSW=IX2ZSV
        IY1TSW=IY1TSV
        IY1ZSW=IY1ZSV
        IY2TSW=IY2TSV
        IY2ZSW=IY2ZSV
        IX1FSW=IX1FSV
        IX2FSW=IX2FSV
        IY1FSW=IY1FSV
        IY2FSW=IY2FSV
        IERASW='OFF'
!
!  RESTORE COMMAND LINE
!
        ISHIFT=NARGT-NUMARG
        IF(ISHIFT.GT.0)THEN
          CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ELSEIF(ISHIFT.LT.0)THEN
          ISHIFT=-ISHIFT
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ENDIF
        DO 6220 II=1,NARGT
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)=IARGTT(II)
          ARG(II)=ARGT(II)
 6220   CONTINUE
      ENDIF
!
      DO 6100 IFAC=1,ICOLT
!
        IPLOT=IPLOT+1
        IX=IXC1
        IXLIST=1
        IROW=INT(IPLOT/IMPNC)+1
        IF(MOD(IPLOT,IMPNC).EQ.0)IROW=IROW-1
        ICOL=MOD(IPLOT,IMPNC)
        IF(ICOL.EQ.0)ICOL=IMPNC
!
        IHARG(NPOS)=IVARN1(IRES)
        IHARG2(NPOS)=IVARN2(IRES)
!
        IEMPTY='NO'
        IF(ICPLLA.EQ.'BOX')THEN
          ICOL=ICOL-1
          IF(ICOL.EQ.0)IEMPTY='YES'
          IF(IROW.EQ.IMPNR)IEMPTY='YES'
        ENDIF
!
        IF(ICPLRV.EQ.1)THEN
          IF(ICPLTV.EQ.1)THEN
            ARG(NPOS1)=ADIST1(IFAC)
          ELSE
            ARG(NPOS1)=ADIST1(IROW)
            ARG(NPOS2)=ADIST2(ICOL)
          ENDIF
        ELSE
          IF(ICPLTV.EQ.1)THEN
            ARG(NPOS1)=ADIST1(IFAC)
          ELSE
            ARG(NPOS1)=ADIST1(MOD(IROW-1,ICPLRV)+1)
            ARG(NPOS2)=ADIST2(ICOL)
          ENDIF
        ENDIF
!
        IF(IEMPTY.EQ.'YES')THEN
          DO 6104 I=1,MAXSUB
            ISU2SW(I)=ISUBSW(I)
            ISUBSW(I)='OFF'
 6104     CONTINUE
        ENDIF
        ICASPL='COND'
        IOPTN=3
        IDY=IRES
        IDX=1
        CALL DPSPM4(ICASPL,IOPTN,IDX,IDY,   &
                    ISUBNU,ISUBSW,   &
                    ASUBXL,ASUBXU,ASUBYL,ASUBYU,   &
                    ISUBN9,ISUBSZ,   &
                    ASBXL2,ASBXU2,ASBYL2,ASBYU2,   &
                    PCPXSL,PCPXSU,PCPYSL,PCPYSU,   &
                    IBUGG2,ISUBRO,IERROR)
!
        CALL DPSPM1(ICASPL,IVARN1,IVARN2,ICOLL,   &
                    IMPNR,IMPNC,IROW,ICOL,IRES,IX,IPLOT,   &
                    NPLOTS,NUMVAR,   &
                    ICHAP2,ILINP2,   &
                    GY1MNS,GY1MXS,GY2MNS,GY2MXS,   &
                    GX1MNS,GX1MXS,GX2MNS,GX2MXS,   &
                    IY1MNS,IY1MXS,IY2MNS,IY2MXS,   &
                    IX1MNS,IX1MXS,IX2MNS,IX2MXS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    PX1LD2,PX2LD2,   &
                    IY1LJ2,IY1LD2,PY1LD2,PY1LA2,   &
                    IX1LT2,IX2LT2,IY1LT2,IY2LT2,   &
                    NCX1L2,NCX2L2,NCY1L2,NCY2L2,   &
                    PCPXLL,PCPXUL,PCPYLL,PCPYUL,IXLIST,   &
                    ICPLLA,ISPMLD,IPLOTT,ICPLFR,ICPLXA,ICPLYA,   &
                    ISPMDI,ISPX1L,   &
                    ISPMXT,ISPMXL,ISPMYT,ISPMYL,   &
                    ICPLTD,PCPLTD,IVNMEX,   &
                    IBUGG2,ISUBRO)
!
!CCCC   ITITTE(1)='S'
!CCCC   ITITTE(2)='U'
!CCCC   ITITTE(3)='B'
!CCCC   ITITTE(4)='S'
!CCCC   ITITTE(5)='E'
!CCCC   ITITTE(6)='T'
!CCCC   ITITTE(7)=' '
!CCCC   NCTEMP=7
        NCTEMP=0
        DO 6161 I=1,4
          IF(IVARN1(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC1)(I:I)
          ENDIF
 6161   CONTINUE
        DO 6163 I=1,4
          IF(IVARN2(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC1)(I:I)
          ENDIF
 6163   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS1)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
        IF(ICPLTV.EQ.1)GO TO 6189
        DO 6169 I=1,15
          NCTEMP=NCTEMP+1
          ITITTE(NCTEMP)=' '
 6169   CONTINUE
        DO 6171 I=1,4
          IF(IVARN1(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC2)(I:I)
          ENDIF
 6171   CONTINUE
        DO 6173 I=1,4
          IF(IVARN2(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC2)(I:I)
          ENDIF
 6173   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS2)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
 6189   CONTINUE
        NCTITL=NCTEMP
        IF(ICPLFR.EQ.'DEFA')THEN
          PTITDS=-ABS(PTITDZ)
        ENDIF
!
        CALL MAINGR(ANOPL1,ANOPL2,NPLOTV,NPLOTP,NS,ICASPL,   &
                    MAXNPP,ISEED,IBOOSS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    BARHEF,BARWEF,   &
                    IRHSTG,IHSTCW,IHSTEB,IHSTOU,IASHWT,IHSTMC,IHSTOP,   &
                    ICAPSW,IFORSW,   &
                    IGUIFL,IERRFA,IFRALI,   &
                    IAND1,IAND2,ICONT,NUMHPP,NUMVPP,   &
                    MAXNXT,   &
                    ISUBRO,IFOUND,IERROR)
        IF(IEMPTY.EQ.'NO')THEN
          CALL DPSPM3(ICASPL,IOUNI5,   &
                      IROW,ICOL,   &
                      PX2LD2,NPLOTP,   &
                      IFORSW,   &
                      IFPX2L,ISPX2P,ISPX2S,   &
                      IHRIGH,IHRIG2,IHWUSE,   &
                      ISUBN1,ISUBN2,MESSAG,   &
                      IBUGG2,ISUBRO,IERROR)
        ENDIF
!
        ICONT=IDCONT(1)
        IPOWE=IDPOWE(1)
        NUMHPP=IDNHPP(1)
        IMPARG=2
        CALL DPGRAP(Y,X,X3D,D,N,NPLOTP,ICASPL,ICONT,IPOWE,NUMHPP,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,   &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                    YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IMPARG,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    MAXCOL,   &
                    DSIZE,DSYMB,DCOLOR,DFILL,   &
                    ICAPSW,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                    IERROR)
!
        ICNTPL=ICNTPL+1
        IF(NPLOTP.GT.0)THEN
          DO 3315 II=1,NPLOTP
            WRITE(IOUNI5,3118)ICNTPL,Y(II),X(II),D(II)
 3315     CONTINUE
        ENDIF
!
        IF(IERROR.EQ.'NO')IAND1=IAND2
        IF(IERROR.EQ.'YES')GO TO 6199
!
        IF(ICPLPT.NE.'PLOT')GO TO 6199
        IF(ICPLFI.EQ.'NONE')GO TO 6199
        IF(IEMPTY.EQ.'YES')GO TO 6199
!
        IMPCO=IMPCO-1
        IF(IMPCO.LE.1)IERASW='OFF'
!
!  NOTE: NO FITTING DONE SINCE ONLY ONE VARIABLE PLOTTED
!        HERE.
!
 6199   CONTINUE
        ISHIFT=NARGT-NUMARG
        IF(ISHIFT.GT.0)THEN
          CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ELSEIF(ISHIFT.LT.0)THEN
          ISHIFT=-ISHIFT
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ENDIF
        ICOM=ICT
        ICOM2=IC2T
        DO 6101 II=1,NARGT
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)=IARGTT(II)
          ARG(II)=ARGT(II)
 6101   CONTINUE
!
        PX1LDS=PX1LD2
        IF(IYAXIS.EQ.0.AND.IFLGIN.EQ.'NO')THEN
          GY1MIN=GY1MNS
          GY1MAX=GY1MXS
          GY2MIN=GY2MNS
          GY2MAX=GY2MXS
          IY1MIN=IY1MNS
          IY1MAX=IY1MXS
          IY2MIN=IY2MNS
          IY2MAX=IY2MXS
        ENDIF
        IF(IXAXIS.EQ.0.AND.IFLGIN.EQ.'NO')THEN
          GX1MIN=GX1MNS
          GX1MAX=GX1MXS
          GX2MIN=GX2MNS
          GX2MAX=GX2MXS
          IX1MIN=IX1MNS
          IX1MAX=IX1MXS
          IX2MIN=IX2MNS
          IX2MAX=IX2MXS
        ENDIF
        PX1ZDS=PX1ZD2
        PX2ZDS=PX2ZD2
        PY1ZDS=PY1ZD2
        PY2ZDS=PY2ZD2
        IF(IEMPTY.EQ.'YES')THEN
          DO 6107 I=1,MAXSUB
            ISUBSW(I)=ISU2SW(I)
 6107     CONTINUE
        ENDIF
        DO 6108 I=1,100
            ICHAPA(I)=ICHAP2(I)
            ILINPA(I)=ILINP2(I)
            ISPISW(I)=ISPIS2(I)
            IBARSW(I)=IBARS2(I)
 6108     CONTINUE
!
 6100 CONTINUE
 6200 CONTINUE
      IF(IYAXIS.EQ.1)THEN
        GY1MIN=GY1MNS
        GY1MAX=GY1MXS
        GY2MIN=GY2MNS
        GY2MAX=GY2MXS
        IY1MIN=IY1MNS
        IY1MAX=IY1MXS
        IY2MIN=IY2MNS
        IY2MAX=IY2MXS
      ENDIF
      IF(IXAXIS.EQ.1)THEN
        GX1MIN=GX1MNS
        GX1MAX=GX1MXS
        GX2MIN=GX2MNS
        GX2MAX=GX2MXS
        IX1MIN=IX1MNS
        IX1MAX=IX1MXS
        IX2MIN=IX2MNS
        IX2MAX=IX2MXS
      ENDIF
      GO TO 8000
!
!               **********************************************
!               **   STEP 21--                              **
!               **   GENERATE THE PLOT               PLOTS  **
!               **   GENERATE THE BIHISTOGRAM        PLOTS  **
!               **   GENERATE THE QUANTILE-QUANTILE  PLOTS  **
!               **   GENERATE THE BOX-COX LINEARITY  PLOTS  **
!               **   GENERATE THE STATISTIC       PLOTS     **
!               **   GENERATE THE CROSS-TABULATE  PLOTS     **
!               **   GENERATE THE ROSE            PLOTS     **
!               **********************************************
!
 6999 CONTINUE
!
!  IF NO PRIOR LIMITS SET FOR Y AXIS, USE 0 TO 0.6 (THIS MAY NOT
!  BE OPTIMAL, BUT IT WILL ALWAYS SHOW ALL THE DATA).
!
      IF(NPLOTS.LT.1)GO TO 8000
!
      ISHIFT=ILOCQ-1
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
      IBUGG2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8000
!
!  CREATE BASIC COMMAND LINE, FOR EXAMPLE:
!    RELATIVE BIHISTOGRAM Y1 Y2 SUBSET COND1 = <VAL> SUBSET COND2 = <VAL>
!  WHERE COND2 IS OPTIONAL
!
!  FOR SOME PLOT TYPES, NEED TO DO AN INITIAL PLOT TO SET PLOT LIMITS
!
      ISHIFT=NCCOMM+2
      IF(ICPLTV.GE.1)ISHIFT=ISHIFT+4
      IF(ICPLTV.GE.2)ISHIFT=ISHIFT+4
      CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGG2,IERROR)
      ICOM=ICT
      ICOM2=IC2T
      DO 7006 II=1,NCCOMM
        IHARG(II)=IHT(II)
        IHARG2(II)=IH2T(II)
        IARGT(II)='WORD'
 7006 CONTINUE
      NWORD=NCCOMM+1
      NPOSA=NWORD
      IHARG(NWORD)=IVARN1(1)
      IHARG2(NWORD)=IVARN2(1)
      IARGT(NWORD)='WORD'
      NWORD=NCCOMM+2
      NPOSB=NWORD
      IHARG(NWORD)=IVARN1(IXC1)
      IHARG2(NWORD)=IVARN2(IXC1)
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='SUBS'
      IHARG2(NWORD)='ET  '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)=IVARN1(ICC1)
      IHARG2(NWORD)=IVARN2(ICC1)
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='=   '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='0  '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='NUMB'
      NPOS1=NWORD
!
      IF(ICPLTV.EQ.2)THEN
        NWORD=NWORD+1
        IHARG(NWORD)='SUBS'
        IHARG2(NWORD)='ET  '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)=IVARN1(ICC2)
        IHARG2(NWORD)=IVARN2(ICC2)
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='=   '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='0  '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='NUMB'
        NPOS2=NWORD
      ENDIF
      NARGT=NUMARG
!
      DO 7020 I=1,NARGT
        IHT(I)=IHARG(I)
        IH2T(I)=IHARG2(I)
        IARGTT(I)=IARGT(I)
        ARGT(I)=ARG(I)
 7020 CONTINUE
!
      IPLOT=0
      DO 7200 IRES=1,IROWT
!
!  CREATE INITIAL PLOT TO DETERMINE SCALE
!
      IF(IFLGIN.EQ.'YES')THEN
        ISHIFT=NWORD
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        ISHIFT=NCCOMM+2
        CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGG2,IERROR)
        ICOM=ICT
        ICOM2=IC2T
        DO 7210 II=1,NCCOMM+2
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)='WORD'
 7210   CONTINUE
        NTEMP=NCCOMM+1
        IHARG(NTEMP)=IVARN1(IRES)
        IHARG2(NTEMP)=IVARN2(IRES)
        IARGT(NTEMP)='WORD'
!
!  GENERATE THE DUMMY PLOT
!
        ICHAPA(1)='BLAN'
        ILINPA(1)='BLAN'
        IBARSW(1)='OFF'
        ISPISW(1)='OFF'
        GY1MIN=CPUMIN
        GY1MAX=CPUMAX
        GY2MIN=CPUMIN
        GY2MAX=CPUMAX
        GX1MIN=CPUMIN
        GX1MAX=CPUMAX
        GX2MIN=CPUMIN
        GX2MAX=CPUMAX
        IY1MIN='FLOA'
        IY1MAX='FLOA'
        IY2MIN='FLOA'
        IY2MAX='FLOA'
        IX1MIN='FLOA'
        IX1MAX='FLOA'
        IX2MIN='FLOA'
        IX2MAX='FLOA'
        CALL MAINGR(ANOPL1,ANOPL2,NPLOTV,NPLOTP,NS,ICASPL,   &
                    MAXNPP,ISEED,IBOOSS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    BARHEF,BARWEF,   &
                    IRHSTG,IHSTCW,IHSTEB,IHSTOU,IASHWT,IHSTMC,IHSTOP,   &
                    ICAPSW,IFORSW,   &
                    IGUIFL,IERRFA,IFRALI,   &
                    IAND1,IAND2,ICONT,NUMHPP,NUMVPP,   &
                    MAXNXT,   &
                    ISUBRO,IFOUND,IERROR)
!
        IX1TSW='OFF'
        IX1ZSW='OFF'
        IX2TSW='OFF'
        IX2ZSW='OFF'
        IY1TSW='OFF'
        IY1ZSW='OFF'
        IY2TSW='OFF'
        IY2ZSW='OFF'
        IX1FSW='OFF'
        IX2FSW='OFF'
        IY1FSW='OFF'
        IY2FSW='OFF'
        IERASW='ON'
        DO 7250 I=1,MAXCH
          IX1LTE(I)='    '
          IX2LTE(I)='    '
          IY1LTE(I)='    '
          IY2LTE(I)='    '
 7250   CONTINUE
        NCX1LA=0
        NCX2LA=0
        NCY1LA=0
        NCY2LA=0
        NCTITL=0
        ICONT=IDCONT(1)
        IPOWE=IDPOWE(1)
        NUMHPP=IDNHPP(1)
        IMPARG=2
        CALL DPGRAP(Y,X,X3D,D,N,NPLOTP,ICASPL,ICONT,IPOWE,NUMHPP,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,   &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                    YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IMPARG,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    MAXCOL,   &
                    DSIZE,DSYMB,DCOLOR,DFILL,   &
                    ICAPSW,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                    IERROR)
!
        ICNTPL=ICNTPL+1
        IF(NPLOTP.GT.0)THEN
          DO 3415 II=1,NPLOTP
            WRITE(IOUNI5,3118)ICNTPL,Y(II),X(II),D(II)
 3415     CONTINUE
        ENDIF
!
        IF(IERROR.EQ.'NO')IAND1=IAND2
        IMPCO=IMPCO-1
        IF(IFLGY.EQ.'ON')THEN
          GY1MIN=FY1MNZ
          GY1MAX=FY1MXZ
          GY2MIN=FY2MNZ
          GY2MAX=FY2MXZ
          IY1MIN='FIXE'
          IY1MAX='FIXE'
          IY2MIN='FIXE'
          IY2MAX='FIXE'
        ELSE
          GY1MIN=GY1MNS
          GY1MAX=GY1MXS
          GY2MIN=GY2MNS
          GY2MAX=GY2MXS
          IY1MIN=IY1MNS
          IY1MAX=IY1MXS
          IY2MIN=IY2MNS
          IY2MAX=IY2MXS
        ENDIF
        IF(IFLGX.EQ.'ON')THEN
          GX1MIN=FX1MNZ
          GX1MAX=FX1MXZ
          GX2MIN=FX2MNZ
          GX2MAX=FX2MXZ
          IX1MIN='FIXE'
          IX1MAX='FIXE'
          IX2MIN='FIXE'
          IX2MAX='FIXE'
        ELSE
          GX1MIN=GX1MNS
          GX1MAX=GX1MXS
          GX2MIN=GX2MNS
          GX2MAX=GX2MXS
          IX1MIN=IX1MNS
          IX1MAX=IX1MXS
          IX2MIN=IX2MNS
          IX2MAX=IX2MXS
        ENDIF
!
        IX1TSW=IX1TSV
        IX1ZSW=IX1ZSV
        IX2TSW=IX2TSV
        IX2ZSW=IX2ZSV
        IY1TSW=IY1TSV
        IY1ZSW=IY1ZSV
        IY2TSW=IY2TSV
        IY2ZSW=IY2ZSV
        IX1FSW=IX1FSV
        IX2FSW=IX2FSV
        IY1FSW=IY1FSV
        IY2FSW=IY2FSV
        IERASW='OFF'
!
!  RESTORE COMMAND LINE
!
        ISHIFT=NARGT-NUMARG
        IF(ISHIFT.GT.0)THEN
          CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ELSEIF(ISHIFT.LT.0)THEN
          ISHIFT=-ISHIFT
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ENDIF
        DO 7220 II=1,NARGT
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)=IARGTT(II)
          ARG(II)=ARGT(II)
 7220   CONTINUE
      ENDIF
!
      DO 7100 IFAC=1,ICOLT
!
        IPLOT=IPLOT+1
        IX=IXC1
        IXLIST=1
        IROW=INT(IPLOT/IMPNC)+1
        IF(MOD(IPLOT,IMPNC).EQ.0)IROW=IROW-1
        ICOL=MOD(IPLOT,IMPNC)
        IF(ICOL.EQ.0)ICOL=IMPNC
!
        IHARG(NPOSA)=IVARN1(IRES)
        IHARG2(NPOSA)=IVARN2(IRES)
!
        IEMPTY='NO'
        ITEMP=IFAC
        IF(ICPLLA.EQ.'BOX')THEN
          ICOL=ICOL-1
          ITEMP=IFAC-1
          IF(ITEMP.EQ.0)IEMPTY='YES'
          IF(IROW.EQ.IMPNR)IEMPTY='YES'
        ENDIF
!
        IF(ICPLRV.EQ.1)THEN
          IF(ICPLTV.EQ.1)THEN
            IF(ITEMP.GT.0)THEN
              ARG(NPOS1)=ADIST1(ITEMP)
            ELSE
              ARG(NPOS1)=ADIST1(1)
            ENDIF
          ELSE
            IJUNK=IROW
            IF(IJUNK.GT.NOUT)IJUNK=NOUT
            IF(IJUNK.LT.1)IJUNK=1
            ARG(NPOS1)=ADIST1(IJUNK)
            IJUNK=ICOL
            IF(IJUNK.GT.NOUT2)IJUNK=NOUT2
            IF(IJUNK.LT.1)IJUNK=1
            ARG(NPOS2)=ADIST2(IJUNK)
          ENDIF
        ELSE
          IF(ICPLTV.EQ.1)THEN
            IJUNK=ITEMP
            IF(IJUNK.LT.1)IJUNK=1
            IF(IJUNK.GT.NOUT)IJUNK=NOUT
            ARG(NPOS1)=ADIST1(IJUNK)
          ELSE
            IJUNK=MOD(IROW-1,ICPLRV)+1
            IF(IJUNK.LT.1)IJUNK=1
            IF(IJUNK.GT.NOUT)IJUNK=NOUT
            ARG(NPOS1)=ADIST1(IJUNK)
            IJUNK=ITEMP
            IF(IJUNK.GT.NOUT2)IJUNK=NOUT2
            IF(IJUNK.LT.1)IJUNK=1
            ARG(NPOS2)=ADIST2(IJUNK)
          ENDIF
        ENDIF
!
        IF(IEMPTY.EQ.'YES')THEN
          DO 7104 I=1,MAXSUB
            ISU2SW(I)=ISUBSW(I)
            ISUBSW(I)='OFF'
 7104     CONTINUE
        ENDIF
        ICASPL='COND'
        IOPTN=3
        IDY=IRES
        IDX=1
        CALL DPSPM4(ICASPL,IOPTN,IDX,IDY,   &
                    ISUBNU,ISUBSW,   &
                    ASUBXL,ASUBXU,ASUBYL,ASUBYU,   &
                    ISUBN9,ISUBSZ,   &
                    ASBXL2,ASBXU2,ASBYL2,ASBYU2,   &
                    PCPXSL,PCPXSU,PCPYSL,PCPYSU,   &
                    IBUGG2,ISUBRO,IERROR)
!
        CALL DPSPM1(ICASPL,IVARN1,IVARN2,ICOLL,   &
                    IMPNR,IMPNC,IROW,ICOL,IRES,IX,IPLOT,   &
                    NPLOTS,NUMVAR,   &
                    ICHAP2,ILINP2,   &
                    GY1MNS,GY1MXS,GY2MNS,GY2MXS,   &
                    GX1MNS,GX1MXS,GX2MNS,GX2MXS,   &
                    IY1MNS,IY1MXS,IY2MNS,IY2MXS,   &
                    IX1MNS,IX1MXS,IX2MNS,IX2MXS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    PX1LD2,PX2LD2,   &
                    IY1LJ2,IY1LD2,PY1LD2,PY1LA2,   &
                    IX1LT2,IX2LT2,IY1LT2,IY2LT2,   &
                    NCX1L2,NCX2L2,NCY1L2,NCY2L2,   &
                    PCPXLL,PCPXUL,PCPYLL,PCPYUL,IXLIST,   &
                    ICPLLA,ISPMLD,IPLOTT,ICPLFR,ICPLXA,ICPLYA,   &
                    ISPMDI,ISPX1L,   &
                    ISPMXT,ISPMXL,ISPMYT,ISPMYL,   &
                    ICPLTD,PCPLTD,IVNMEX,   &
                    IBUGG2,ISUBRO)
!
!CCCC   ITITTE(1)='S'
!CCCC   ITITTE(2)='U'
!CCCC   ITITTE(3)='B'
!CCCC   ITITTE(4)='S'
!CCCC   ITITTE(5)='E'
!CCCC   ITITTE(6)='T'
!CCCC   ITITTE(7)=' '
!CCCC   NCTEMP=7
        NCTEMP=0
        DO 7161 I=1,4
          IF(IVARN1(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC1)(I:I)
          ENDIF
 7161   CONTINUE
        DO 7163 I=1,4
          IF(IVARN2(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC1)(I:I)
          ENDIF
 7163   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS1)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
        IF(ICPLTV.EQ.1)GO TO 7189
        DO 7169 I=1,15
          NCTEMP=NCTEMP+1
          ITITTE(NCTEMP)=' '
 7169   CONTINUE
        DO 7171 I=1,4
          IF(IVARN1(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC2)(I:I)
          ENDIF
 7171   CONTINUE
        DO 7173 I=1,4
          IF(IVARN2(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC2)(I:I)
          ENDIF
 7173   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS2)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
 7189   CONTINUE
        NCTITL=NCTEMP
        IF(ICPLFR.EQ.'DEFA')THEN
          PTITDS=-ABS(PTITDZ)
        ENDIF
        IF(IEMPTY.EQ.'YES')THEN
          DO 5306 I=1,100
            ICHAPA(I)='BLAN'
            ILINPA(I)='BLAN'
            ISPISW(I)='OFF'
            IBARSW(I)='OFF'
 5306     CONTINUE
          NCTITL=0
        ENDIF
!
        IF(ICPLPT.EQ.'ROSE' .OR. ICPLPT.EQ.'ROS2')THEN
          NCTITL=0
        ENDIF
!
        CALL MAINGR(ANOPL1,ANOPL2,NPLOTV,NPLOTP,NS,ICASPL,   &
                    MAXNPP,ISEED,IBOOSS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    BARHEF,BARWEF,   &
                    IRHSTG,IHSTCW,IHSTEB,IHSTOU,IASHWT,IHSTMC,IHSTOP,   &
                    ICAPSW,IFORSW,   &
                    IGUIFL,IERRFA,IFRALI,   &
                    IAND1,IAND2,ICONT,NUMHPP,NUMVPP,   &
                    MAXNXT,   &
                    ISUBRO,IFOUND,IERROR)
        IF(IEMPTY.EQ.'NO' .AND. ICPLPT.NE.'ROS2')THEN
          CALL DPSPM3(ICASPL,IOUNI5,   &
                      IROW,ICOL,   &
                      PX2LD2,NPLOTP,   &
                      IFORSW,   &
                      IFPX2L,ISPX2P,ISPX2S,   &
                      IHRIGH,IHRIG2,IHWUSE,   &
                      ISUBN1,ISUBN2,MESSAG,   &
                      IBUGG2,ISUBRO,IERROR)
        ENDIF
!
        ICONT=IDCONT(1)
        IPOWE=IDPOWE(1)
        NUMHPP=IDNHPP(1)
        IMPARG=2
        CALL DPGRAP(Y,X,X3D,D,N,NPLOTP,ICASPL,ICONT,IPOWE,NUMHPP,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,   &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                    YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IMPARG,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    MAXCOL,   &
                    DSIZE,DSYMB,DCOLOR,DFILL,   &
                    ICAPSW,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                    IERROR)
!
        ICNTPL=ICNTPL+1
        IF(NPLOTP.GT.0)THEN
          DO 3515 II=1,NPLOTP
            WRITE(IOUNI5,3118)ICNTPL,Y(II),X(II),D(II)
 3515     CONTINUE
        ENDIF
!
        IF(IERROR.EQ.'NO')IAND1=IAND2
        IF(IERROR.EQ.'YES')GO TO 7199
!
        IF(ICPLPT.NE.'PLOT')GO TO 7199
        IF(ICPLFI.EQ.'NONE')GO TO 7199
        IF(IEMPTY.EQ.'YES')GO TO 7199
!
        IMPCO=IMPCO-1
        IF(IMPCO.LE.1)IERASW='OFF'
!
        ICNTPL=0
        IOUNI5=-99
        CALL DPSPM2(ICASPL,IVARN1,IVARN2,ICOLL,NUMVAR,NPLOTP,   &
                    IRES,IX,   &
                    TEMP,TEMP2,TEMP3,XTEMP1,XTEMP2,MAXNXT,   &
                    ALOWFR,ALOWDG,   &
                    IANGLU,MAXNPP,IAND1,IAND2,   &
                    ICPLFI,ICPLTA,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IREPCH,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    ICNTPL,IOUNI5,   &
                    IBUGG2,IBUGG3,IBUGCO,IBUGEV,IBUGQ,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,   &
                    ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 7199
!
 7199   CONTINUE
        ISHIFT=NARGT-NUMARG
        IF(ISHIFT.GT.0)THEN
          CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ELSEIF(ISHIFT.LT.0)THEN
          ISHIFT=-ISHIFT
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ENDIF
        ICOM=ICT
        ICOM2=IC2T
        DO 7101 II=1,NARGT
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)=IARGTT(II)
          ARG(II)=ARGT(II)
 7101   CONTINUE
!
        PX1LDS=PX1LD2
        IF(IYAXIS.EQ.0.AND.IFLGIN.EQ.'NO')THEN
          GY1MNS=GY1MIN
          GY1MXS=GY1MAX
          GY2MNS=GY2MIN
          GY2MXS=GY2MAX
          IY1MNS=IY1MIN
          IY1MXS=IY1MAX
          IY2MNS=IY2MIN
          IY2MXS=IY2MAX
        ENDIF
        IF(IXAXIS.EQ.0.AND.IFLGIN.EQ.'NO')THEN
          GX1MNS=GX1MIN
          GX1MXS=GX1MAX
          GX2MNS=GX2MIN
          GX2MXS=GX2MAX
          IX1MNS=IX1MIN
          IX1MXS=IX1MAX
          IX2MNS=IX2MIN
          IX2MXS=IX2MAX
        ENDIF
        PX1ZDS=PX1ZD2
        PX2ZDS=PX2ZD2
        PY1ZDS=PY1ZD2
        PY2ZDS=PY2ZD2
        IF(IEMPTY.EQ.'YES')THEN
          DO 7107 I=1,MAXSUB
            ISUBSW(I)=ISU2SW(I)
 7107     CONTINUE
        ENDIF
        DO 7108 I=1,100
            ICHAPA(I)=ICHAP2(I)
            ILINPA(I)=ILINP2(I)
            ISPISW(I)=ISPIS2(I)
            IBARSW(I)=IBARS2(I)
 7108     CONTINUE
!
 7100 CONTINUE
 7200 CONTINUE
      IF(IYAXIS.EQ.1)THEN
        GY1MIN=GY1MNS
        GY1MAX=GY1MXS
        GY2MIN=GY2MNS
        GY2MAX=GY2MXS
        IY1MIN=IY1MNS
        IY1MAX=IY1MXS
        IY2MIN=IY2MNS
        IY2MAX=IY2MXS
      ENDIF
      IF(IXAXIS.EQ.1)THEN
        GX1MIN=GX1MNS
        GX1MAX=GX1MXS
        GX2MIN=GX2MNS
        GX2MAX=GX2MXS
        IX1MIN=IX1MNS
        IX1MAX=IX1MXS
        IX2MIN=IX2MNS
        IX2MAX=IX2MXS
      ENDIF
      GO TO 8000
!
!               **********************************************
!               **   STEP 21--                              **
!               **   GENERATE THE 3D                 PLOTS  **
!               **   GENERATE THE YATES CUBE         PLOTS  **
!               **********************************************
!
 7499 CONTINUE
!
      IF(NPLOTS.LT.1)GO TO 8000
!
      ISHIFT=ILOCQ-1
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
      IBUGG2,IERROR)
      IF(IERROR.EQ.'YES')GO TO 8000
!
!  CREATE BASIC COMMAND LINE, FOR EXAMPLE:
!    YATES CUBE PLOT Y X1 X2 X3 SUBSET COND1 = <VAL> SUBSET COND2 = <VAL>
!  WHERE COND2 IS OPTIONAL
!
      ISHIFT=NCCOMM+4
      IF(ICPLTV.GE.1)ISHIFT=ISHIFT+4
      IF(ICPLTV.GE.2)ISHIFT=ISHIFT+4
      CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGG2,IERROR)
      ICOM=ICT
      ICOM2=IC2T
      DO 7506 II=1,NCCOMM
        IHARG(II)=IHT(II)
        IHARG2(II)=IH2T(II)
        IARGT(II)='WORD'
 7506 CONTINUE
      NWORD=NCCOMM+1
      NPOSA=NWORD
      IHARG(NWORD)=IVARN1(1)
      IHARG2(NWORD)=IVARN2(1)
      IARGT(NWORD)='WORD'
      NWORD=NCCOMM+2
      NPOSB=NWORD
      IHARG(NWORD)=IVARN1(IXC1)
      IHARG2(NWORD)=IVARN2(IXC1)
      IARGT(NWORD)='WORD'
!
      IF(ICPLXV.GE.2)THEN
        NWORD=NWORD+1
        IHARG(NWORD)=IVARN1(IXC2)
        IHARG2(NWORD)=IVARN2(IXC2)
        IARGT(NWORD)='WORD'
      ENDIF
!
      IF(ICPLXV.GE.3)THEN
        NWORD=NWORD+1
        IHARG(NWORD)=IVARN1(IXC3)
        IHARG2(NWORD)=IVARN2(IXC3)
        IARGT(NWORD)='WORD'
      ENDIF
!
      NWORD=NWORD+1
      IHARG(NWORD)='SUBS'
      IHARG2(NWORD)='ET  '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)=IVARN1(ICC1)
      IHARG2(NWORD)=IVARN2(ICC1)
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='=   '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='WORD'
!
      NWORD=NWORD+1
      IHARG(NWORD)='0  '
      IHARG2(NWORD)='    '
      IARGT(NWORD)='NUMB'
      NPOS1=NWORD
!
      IF(ICPLTV.EQ.2)THEN
        NWORD=NWORD+1
        IHARG(NWORD)='SUBS'
        IHARG2(NWORD)='ET  '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)=IVARN1(ICC2)
        IHARG2(NWORD)=IVARN2(ICC2)
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='=   '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='WORD'
!
        NWORD=NWORD+1
        IHARG(NWORD)='0  '
        IHARG2(NWORD)='    '
        IARGT(NWORD)='NUMB'
        NPOS2=NWORD
      ENDIF
      NARGT=NUMARG
!
      DO 7520 I=1,NARGT
        IHT(I)=IHARG(I)
        IH2T(I)=IHARG2(I)
        IARGTT(I)=IARGT(I)
        ARGT(I)=ARG(I)
 7520 CONTINUE
!
      IPLOT=0
      IEMPTY='NO'
      DO 7700 IRES=1,IROWT
      DO 7600 IFAC=1,ICOLT
!
        IPLOT=IPLOT+1
        IX=IXC1
        IXLIST=1
        IROW=INT(IPLOT/IMPNC)+1
        IF(MOD(IPLOT,IMPNC).EQ.0)IROW=IROW-1
        ICOL=MOD(IPLOT,IMPNC)
        IF(ICOL.EQ.0)ICOL=IMPNC
!
        IHARG(NPOSA)=IVARN1(IRES)
        IHARG2(NPOSA)=IVARN2(IRES)
!
        IEMPTY='NO'
        ITEMP=IFAC
!
        IF(ICPLTV.EQ.1)THEN
          IF(ITEMP.GT.0)THEN
            ARG(NPOS1)=ADIST1(ITEMP)
          ELSE
            ARG(NPOS1)=ADIST1(1)
          ENDIF
        ELSE
          IJUNK=IROW
          IF(IJUNK.GT.NOUT)IJUNK=NOUT
          IF(IJUNK.LT.1)IJUNK=1
          ARG(NPOS1)=ADIST1(IJUNK)
          IJUNK=ICOL
          IF(IJUNK.GT.NOUT2)IJUNK=NOUT2
          IF(IJUNK.LT.1)IJUNK=1
          ARG(NPOS2)=ADIST2(IJUNK)
        ENDIF
!
        ICASPL='COND'
        NCTEMP=0
        DO 7661 I=1,4
          IF(IVARN1(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC1)(I:I)
          ENDIF
 7661   CONTINUE
        DO 7663 I=1,4
          IF(IVARN2(ICC1)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC1)(I:I)
          ENDIF
 7663   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS1)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
        IF(ICPLTV.EQ.1)GO TO 7689
        DO 7669 I=1,15
          NCTEMP=NCTEMP+1
          ITITTE(NCTEMP)=' '
 7669   CONTINUE
        DO 7671 I=1,4
          IF(IVARN1(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN1(ICC2)(I:I)
          ENDIF
 7671   CONTINUE
        DO 7673 I=1,4
          IF(IVARN2(ICC2)(I:I).NE.' ')THEN
            NCTEMP=NCTEMP+1
            ITITTE(NCTEMP)=IVARN2(ICC2)(I:I)
          ENDIF
 7673   CONTINUE
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)='='
        NCTEMP=NCTEMP+1
        ITITTE(NCTEMP)=' '
        NCTEMP=NCTEMP+1
        VAL=ARG(NPOS2)
        IVAL=INT(VAL+0.5)
        IF(VAL.LT.0.0)IVAL=INT(VAL-0.5)
        CALL DPCONH(IVAL,VAL,ITITTE(NCTEMP),NH,IBUGG2,IERROR)
        NCTEMP=NCTEMP+NH-1
 7689   CONTINUE
        NCTITL=NCTEMP
        IF(ICPLFR.EQ.'DEFA')THEN
          PTITDS=-ABS(PTITDZ)
        ENDIF
!
        CALL MAINGR(ANOPL1,ANOPL2,NPLOTV,NPLOTP,NS,ICASPL,   &
                    MAXNPP,ISEED,IBOOSS,   &
                    IX1TSV,IX2TSV,IY1TSV,IY2TSV,   &
                    IX1ZSV,IX2ZSV,IY1ZSV,IY2ZSV,   &
                    BARHEF,BARWEF,   &
                    IRHSTG,IHSTCW,IHSTEB,IHSTOU,IASHWT,IHSTMC,IHSTOP,   &
                    ICAPSW,IFORSW,   &
                    IGUIFL,IERRFA,IFRALI,   &
                    IAND1,IAND2,ICONT,NUMHPP,NUMVPP,   &
                    MAXNXT,   &
                    ISUBRO,IFOUND,IERROR)
!
        ICONT=IDCONT(1)
        IPOWE=IDPOWE(1)
        NUMHPP=IDNHPP(1)
        IMPARG=2
        CALL DPGRAP(Y,X,X3D,D,N,NPLOTP,ICASPL,ICONT,IPOWE,NUMHPP,   &
                    XMATN,YMATN,XMITN,YMITN,   &
                    ISQUAR,   &
                    IVGMSW,IHGMSW,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,   &
                    IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                    YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    IMPSW,IMPNR,IMPNC,IMPCO,IMPCO9,   &
                    IMPARG,   &
                    PMXMIN,PMXMAX,PMYMIN,PMYMAX,   &
                    MAXCOL,   &
                    DSIZE,DSYMB,DCOLOR,DFILL,   &
                    ICAPSW,   &
                    IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                    IERROR)
!
        ICNTPL=ICNTPL+1
        IF(NPLOTP.GT.0)THEN
          DO 3615 II=1,NPLOTP
            WRITE(IOUNI5,3118)ICNTPL,Y(II),X(II),D(II)
 3615     CONTINUE
        ENDIF
!
        IF(IERROR.EQ.'NO')IAND1=IAND2
        IF(IERROR.EQ.'YES')GO TO 7699
!
 7699   CONTINUE
        ISHIFT=NARGT-NUMARG
        IF(ISHIFT.GT.0)THEN
          CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ELSEIF(ISHIFT.LT.0)THEN
          ISHIFT=-ISHIFT
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGG2,IERROR)
        ENDIF
        ICOM=ICT
        ICOM2=IC2T
        DO 7601 II=1,NARGT
          IHARG(II)=IHT(II)
          IHARG2(II)=IH2T(II)
          IARGT(II)=IARGTT(II)
          ARG(II)=ARGT(II)
 7601   CONTINUE
!
 7600 CONTINUE
 7700 CONTINUE
      GO TO 8000
!
!               **************************************************
!               **   STEP 28--                                  **
!               **   REINSTATE INITIAL SETTINGS                 **
!               **************************************************
!
 8000 CONTINUE
!
      ISTEPN='28'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COND')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,8807)IMANUF,NUMDEV,IDMANU(1)
 8807   FORMAT('IMANUF,NUMDEV,IDMANU(1) = ',A4,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFLAG=2
      CALL DPSPM5(IFLAG,IMPSW,IMPCO,IMPNR,IMPNC,   &
                  IBUGG2,ISUBRO,IFOUND,IERROR)
      ICPLFR=ICPLFZ
      IFEEDB=IFEED9
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG2,ISUBRO,IERROR)
      IFITAU=IFITA2
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'COND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',31I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOND
      SUBROUTINE DPCONF(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,IMULT,IREPL,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE (SYMMETRIC) CONFIDENCE LIMITS FOR THE MEAN
!              FOR PROBABILITY VALUE P = .90, .95, .99, .999, AND .9999.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JULY      1984.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --MARCH     1999. IF 2 VARIABLES SPECIFIED,
!                                       COMPUTE CONFIDENCE INTERVAL
!                                       FOR DIFFERENCE BETWEEN MEANS
!     UPDATED         --MARCH     2003. SAVE CONFIDENCE BOUNDS AS
!                                       INTERNAL PARAMETERS
!     UPDATED         --OCTOBER   2003. SUPPORT FOR HTML, LATEX OUTPUT
!     UPDATED         --MARCH     2010. USE DPPARS
!     UPDATED         --MARCH     2010. USE DPDTA1, DPDTA4 TO GENERATE
!                                       HTML, LATEX, RTF FORMAT
!     UPDATED         --MARCH     2010. SUPPORT FOR MULTIPLE RESPONSE
!                                       VARIABLES AND FOR GROUP-ID
!                                       VARIABLES (I.E., REPLICATION
!                                       CASE)
!     UPDATED         --MARCH     2010. USE DPPAR3 TO EXTRACT EITHER A
!                                       RESPONSE VARIABLE OR A MATRIX
!                                       NAME
!     UPDATED         --APRIL     2013. SUPPORT <LOWER/UPPER> OPTION
!     UPDATED         --AUGUST    2017. SUPPORT FOR LOGNORMAL OPTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICTMP0
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICTMP5
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFLAGU
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(MAXSPN)
      CHARACTER*4 IVARI2(MAXSPN)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
!
      DIMENSION XDESGN(MAXOBV,6)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB2),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB3),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTE4(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE5(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE6(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB9),XDESGN(1,1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='NF  '
      IFOUND='YES'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ****************************************
!               **  TREAT THE CONFIDENCE LIMITS CASE  **
!               ****************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCONF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,ICASAN,MAXV2
   55   FORMAT('MAXNXT,ICASAN,MAXV2 = ',I8,2X,A4,2X,I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE COMMAND        **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     THE FOLLOWING COMMANDS ARE ACCEPTED:
!
!         CONFIDENCE LIMITS Y               (TWO SIDED)
!         LOWER CONFIDENCE LIMITS Y         (ONE SIDED)
!         UPPER CONFIDENCE LIMITS Y         (ONE SIDED)
!
!         DIFFERENCE OF MEAN CONFIDENCE LIMITS Y1 Y2   (TWO SIDED)
!         DIFFERENCE OF MEAN LOWER CONFIDENCE LIMITS Y (ONE SIDED)
!         DIFFERENCE OF MEAN UPPER PREDICTION LIMITS Y (ONE SIDED)
!
!     IN ADDITION, CHECK FOR THE
!
!         1. "MULTIPLE"
!         2. "REPLICATION"
!         3. "LOGNORMAL"
!         4. "BOX COX"
!
!     OPTIONS.
!
      ILASTZ=9999
      IFOUND='NO'
      ICASAN='ONEV'
      ICASA2='TWOS'
      ICASA3='NORM'
!
      DO 100 I=0,NUMARG-1
!
        ICTMP0='XXXX'
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
          ICTMP5=IHARG(I+4)
        ELSE
          IF(I.GE.2)ICTMP0=IHARG(I-1)
          ICTMP1=IHARG(I)
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
          ICTMP5=IHARG(I+4)
        ENDIF
!
        IF(ICTMP1.EQ.'=   ')GO TO 9000
        IF(ICTMP1.EQ.'SD  ')GO TO 9000
        IF(ICTMP1.EQ.'MEDI')GO TO 9000
        IF(ICTMP1.EQ.'PROP')GO TO 9000
        IF(ICTMP1.EQ.'STAN' .AND. ICTMP2.EQ.'DEVI')GO TO 9000
        IF(ICTMP1.EQ.'TRIM' .AND. ICTMP2.EQ.'MEAN')GO TO 9000
        IF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
           ICTMP3.EQ.'DEVI')GO TO 9000
        IF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
           ICTMP3.EQ.'DISP')GO TO 9000
        IF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
           ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'DISP')GO TO 9000
        IF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
           ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'VARI')GO TO 9000
        IF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
           ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'DISP')GO TO 9000
        IF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
           ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'VARI')GO TO 9000
!
        IF(ICTMP1.EQ.'DIFF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'MEAN' .AND. ICTMP4.EQ.'CONF' .AND.   &
               (ICTMP5.EQ.'LIMI' .OR. ICTMP5.EQ.'INTE'))THEN
          IFOUND='YES'
          ILASTZ=I+4
          ICASAN='TWOV'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'CONF' .AND. ICTMP2.EQ.'INTE' .AND.   &
           ICTMP0.NE.'SD  ' .AND. ICTMP0.NE.'DEVI' .AND.   &
           ICASAN.NE.'TWOV')THEN
          IFOUND='YES'
          ILASTZ=I+1
          ICASAN='ONEV'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'CONF' .AND. ICTMP2.EQ.'LIMI' .AND.   &
           ICTMP0.NE.'SD  ' .AND. ICTMP0.NE.'DEVI' .AND.   &
           ICTMP0.NE.'PROP' .AND. ICASAN.NE.'TWOV' .AND.   &
           ICTMP0.NE.'MEDI' .AND. ICTMP0.NE.'TRIM' .AND.   &
           ICTMP0.NE.'VARI')THEN
          IFOUND='YES'
          ILASTZ=I+1
          ICASAN='ONEV'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'LOWE')THEN
          ICASA2='LOWE'
        ELSEIF(ICTMP1.EQ.'UPPE')THEN
          ICASA2='UPPE'
        ELSEIF(ICTMP1.EQ.'REPL')THEN
          IREPL='ON'
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
        ELSEIF(ICTMP1.EQ.'LOGN')THEN
          ICASA3='LOGN'
        ENDIF
  100 CONTINUE
  109 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
        WRITE(ICOUT,111)ICASAN,ICASA2,ICASA3,IREPL
  111   FORMAT('ICASAN,ICASA2,ICASA3,IREPL=',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(ICASA3.EQ.'LOGN')ICASAN='LOGN'
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN CONFIDENCE LIMITS--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THE CONFIDENCE LIMITS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MINNA=1
      MAXNA=100
      MINNVA=1
      MAXNVA=100
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINN2=2
!
      IF(ICASAN.EQ.'TWOV')THEN
        INAME='DIFFERENCE OF THE MEANS CONFIDENCE LIMIT'
        IFLAGE=0
        IFLAGM=1
        MINNA=2
        MINNVA=2
        MAXNVA=30
        IF(IREPL.EQ.'ON')THEN
          MAXNVA=8
          IFLAGE=1
          IFLAGM=0
        ENDIF
      ELSEIF(ICASAN.EQ.'LOGN')THEN
        INAME='LOGNORMAL CONFIDENCE LIMITS FOR THE MEAN'
        MINNVA=1
        MAXNVA=30
        IFLAGE=0
        IFLAGM=1
        IF(IREPL.EQ.'ON')THEN
          MINNVA=2
          MAXNVA=7
          IFLAGE=0
          IFLAGM=0
        ENDIF
      ELSE
        INAME='CONFIDENCE LIMITS FOR THE MEAN'
        MINNVA=1
        MAXNVA=30
        IFLAGE=0
        IFLAGM=1
        IF(IREPL.EQ.'ON')THEN
          MINNVA=2
          MAXNVA=7
          IFLAGE=0
          IFLAGM=0
        ENDIF
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT,IREPL,ICASAN
  182   FORMAT('NQ,NUMVAR,IMULT,IREPL,ICASAN = ',2I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=NUMVAR
      NREPL=0
!
      IF(IREPL.EQ.'ON')THEN
        NRESP=1
        IF(ICASAN.EQ.'TWOV')NRESP=2
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,213)NREPL
  213     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')THEN
        WRITE(ICOUT,221)NRESP,NREPL
  221   FORMAT('NRESP,NREPL = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **  STEP 3--                             **
!               **  CASE 1: NO REPLICATION CASE.         **
!               *******************************************
!
      IF(IREPL.EQ.'OFF' .AND.   &
         (ICASAN.EQ.'ONEV' .OR. ICASAN.EQ.'LOGN'))THEN
!
        ISTEPN='3'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NCURVE=0
        DO 310 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,311)IRESP,NCURVE
  311       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         *****************************************************
!         **  STEP 3B--                                      **
!         *****************************************************
!
          ISTEPN='3B'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,322)
  322       FORMAT('***** FROM THE MIDDLE  OF DPCONF--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,323)ICASAN,NUMVAR,NLOCAL,IRESP
  323       FORMAT('ICASAN,NUMVAR,NLOCAL,IRESP = ',A4,3I8)
            CALL DPWRST('XXX','BUG ')
            IF(NLOCAL.GE.1)THEN
              DO 325 I=1,NLOCAL
                WRITE(ICOUT,326)I,Y(I)
  326           FORMAT('I,Y(I) = ',I8,F12.5)
                CALL DPWRST('XXX','BUG ')
  325         CONTINUE
            ENDIF
          ENDIF
!
          CALL DPCNF2(Y,NLOCAL,X,NLOCA2,                           &
                      PID,IVARID,IVARI2,NREPL,                     &
                      CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      CTL999,CTU999,                               &
                      ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,          &
                      ISUBRO,IBUGA3,IERROR)
!
          IFLAGU='FILE'
          IF(NRESP.EQ.1)IFLAGU='ON'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      CTL999,CTU999,   &
                      IFLAGU,IFRST,ILAST,ICASAN,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
  310   CONTINUE
!
!               ****************************************************
!               **  STEP 5A--                                     **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.    **
!               **          FOR THIS CASE, ALL VARIABLES MUST     **
!               **          HAVE THE SAME LENGTH.                 **
!               ****************************************************
!
      ELSEIF(IREPL.EQ.'OFF' .AND. ICASAN.EQ.'TWOV')THEN
!
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        NUMVA2=1
        DO 410 I=1,NUMVAR
          DO 420 J=I+1,NUMVAR
            ICOL=I
            CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        Y,Y,Y,NS1,NLOCA2,NLOCA3,ICASE,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
            ICOL=J
            CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        X,X,X,NS2,NLOCA2,NLOCA3,ICASE,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 4B--                          **
!               **  PERFORM DIFFERENCE OF MEANS        **
!               **          CONFIDENCE LIMITS          **
!               *****************************************
!
            ISTEPN='52'
            IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
              CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,411)
 411          FORMAT('***** FROM DPCONF, BEFORE CALL DPCNF2--')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,412)I,J,NS1,NS2,MAXN
 412          FORMAT('I,J,NS1,NS2,MAXN = ',5I8)
              CALL DPWRST('XXX','BUG ')
              DO 415 II=1,MAX(NS1,NS2)
                WRITE(ICOUT,416)II,Y(II),X(II)
 416            FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
                CALL DPWRST('XXX','BUG ')
 415          CONTINUE
            ENDIF
!
            IVARID(1)=IVARN1(I)
            IVARI2(1)=IVARN2(I)
            IVARID(2)=IVARN1(J)
            IVARI2(2)=IVARN2(J)
            CALL DPCNF2(Y,NS1,X,NS2,   &
                        PID,IVARID,IVARI2,NREPL,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
            ISTEPN='8C'
            IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
              CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
            IF(NUMVAR.GT.2)THEN
              IFLAGU='FILE'
            ELSE
              IFLAGU='ON'
            ENDIF
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(I.EQ.1 .AND. J.EQ.2)IFRST=.TRUE.
            IF(I.EQ.NUMVAR .AND. J.EQ.NUMVAR)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 420        CONTINUE
 410      CONTINUE
!
      ELSEIF(IREPL.EQ.'ON')THEN
        ISTEPN='5A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 510 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 510
          J=J+1
!
!         RESPONSE VARIABLE IN Y
!
          ICOLC=1
          IJ=MAXN*(ICOLR(ICOLC)-1)+I
          IF(ICOLR(ICOLC).LE.MAXCOL)Y(J)=V(IJ)
          IF(ICOLR(ICOLC).EQ.MAXCP1)Y(J)=PRED(I)
          IF(ICOLR(ICOLC).EQ.MAXCP2)Y(J)=RES(I)
          IF(ICOLR(ICOLC).EQ.MAXCP3)Y(J)=YPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP4)Y(J)=XPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP5)Y(J)=X2PLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
!         SECOND RESPONSE VARIABLE FOR DIFFERENCE OF MEANS CASE
!
          IF(ICASAN.EQ.'TWOV')THEN
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)X(J)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)X(J)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)X(J)=RES(I)
            IF(ICOLT.EQ.MAXCP3)X(J)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)X(J)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)X(J)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)X(J)=TAGPLO(I)
          ELSE
            X(J)=0.0
          ENDIF
!
          IF(NREPL.GE.1)THEN
            DO 520 IR=1,MIN(NREPL,6)
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  520       CONTINUE
          ENDIF
!
  510   CONTINUE
        NLOCAL=J
!
        ISTEPN='5B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        PID(1)=CPUMIN
        IVARID(1)=IVARN1(1)
        IVARI2(1)=IVARN2(1)
        IADD=1
        IF(ICASAN.EQ.'TWOV')THEN
          IADD=2
          PID(2)=CPUMIN
          IVARID(2)=IVARN1(2)
          IVARI2(2)=IVARN2(2)
        ENDIF
        DO 540 II=1,NREPL
          IVARID(II+IADD)=IVARN1(II+IADD)
          IVARI2(II+IADD)=IVARN2(II+IADD)
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')THEN
            WRITE(ICOUT,532)IADD,II,IVARID(II+IADD),IVARN1(II+IADD)
  532       FORMAT('IADD,II,IVARID(II+IADD),IVARN1(II+IADD) = ',   &
                   2I8,A4,2X,A4)
          CALL DPWRST('XXX','BUG ')
          ENDIF
  540   CONTINUE
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='5C'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CONF')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,541)
  541     FORMAT('***** FROM THE MIDDLE  OF DPCONF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,542)ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL
  542     FORMAT('ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL = ',A4,2X,4I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 545 I=1,NLOCAL
              WRITE(ICOUT,546)I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2)
  546         FORMAT('I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2) = ',   &
                     I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  545       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,XTEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 5D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(IADD+1)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            PID(6+IADD)=XIDTE6(ISET4)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCNF2(TEMP1,NTEMP,TEMP2,NTEMP,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,ICASA2,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CONF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCONF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NRIGHT(1),NRIGHT(2)
 9014   FORMAT('NRIGHT(1),NRIGHT(2) = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCONF
      SUBROUTINE DPCONH(IVAL,VAL,IH,NH,IBUGD2,IERROR)
!
!     NOTE--THIS SUBROUTINE IS IDENTICAL TO DPCON2.
!           IT HAS BEEN DUPLICATED AND PLACED
!           ON THIS BRANCH OF THE OVERLAY/SEGMENTATION
!           TREE STRUCTURE IN ORDER TO ACHIEVE
!           FASTER EXECUTION TIME.
!
!     NOTE--UPON INPUT, IVALUE IS USUALLY INT(VALUE+0.5), BUT
!       FOR NEGATIVE VALUE, IVALUE SHOULD BE INT(VALUE-0.5)
!
!     PURPOSE--CONVERT NUMERIC VALUE INTO CORRESPONDING
!              CHARACTER STRING.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MARCH   1983.
!     UPDATED         --JANUARY  2000. SUPPORT FOR EXPONENTIAL
!                                      EXPANSION (THIS IS PRIMARILY
!                                      FOR USE WITH THE FIT COMMAND)
!     UPDATED         --FEBRUARY 2005. SUPPORT FOR "SET PARAMETER
!                                      EXPAND DIGITS"
!     UPDATED         --FEBRUARY 2011. FIX TO EXTEND THE PRECISION
!                                      A FEW EXTRA PLACES
!     UPDATED         --MAY      2016. FIX TO EXTEND THE PRECISION
!                                      A FEW EXTRA PLACES (UP TO 9
!                                      DIGITS BY DEFAULT)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IH
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHREM
      CHARACTER*4 IHNUM
      CHARACTER*4 IHTEMI
      CHARACTER*4 IHTEMD
!
      CHARACTER*25 IJUNK
      CHARACTER*10 IFORMT
!
      DIMENSION IH(*)
      DIMENSION IHTEMI(10)
      DIMENSION IHTEMD(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT---------------------------------------------------------
!
      AINUM=0.0
      FRACT=0.0
      NUMDID=0
      IPOS=0
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCONH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IVAL,VAL
   52   FORMAT('IVAL,VAL = ',I8,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4
   59   FORMAT('IBUGG4,ISUBG4,IERRG4 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IEXPPA.EQ.'EXPO')THEN
        IJUNK=' '
        WRITE(IJUNK,'(D20.12)')DBLE(VAL)
        NH=1
        IH(1)='('
        DO 1010 I=1,20
          IF(IJUNK(I:I).EQ.'D' .OR. IJUNK(I:I).EQ.'E')THEN
            DO 1020 J=1,MAX(1,I-1)
              IF(IJUNK(J:J).EQ.' ')GO TO 1020
              NH=NH+1
              IH(NH)=IJUNK(J:J)
 1020       CONTINUE
            IPOS=I+1
            GO TO 1019
          ENDIF
 1010   CONTINUE
 1019   CONTINUE
!
        NH=NH+1
        IH(NH)='*'
        NH=NH+1
        IH(NH)='1'
        NH=NH+1
        IH(NH)='0'
        NH=NH+1
        IH(NH)='*'
        NH=NH+1
        IH(NH)='*'
        NH=NH+1
        IH(NH)='('
        DO 1040 I=IPOS,20
          IF(IJUNK(I:I).EQ.' ')GO TO 1040
          NH=NH+1
          IH(NH)=IJUNK(I:I)
 1040   CONTINUE
!
        NH=NH+1
        IH(NH)=')'
        NH=NH+1
        IH(NH)=')'
        GO TO 9000
      ELSEIF(IEXPDI.GT.0)THEN
!
        IJUNK=' '
        IFORMT=' '
        IFORMT(1:8)='(F  .  )'
        NJUNK=IEXPDI
        IF(NJUNK.GT.15)NJUNK=15
        WRITE(IFORMT(6:7),'(I2)')NJUNK
        NJUNK=NJUNK+8
        WRITE(IFORMT(3:4),'(I2)')NJUNK
        WRITE(IJUNK,IFORMT)VAL
!
        NH=0
        DO 1050 I=1,NJUNK
          IF(NH.EQ.0 .AND. IJUNK(I:I).EQ.' ')GO TO 1050
          NH=NH+1
          IH(NH)=IJUNK(I:I)
 1050   CONTINUE
        GO TO 9000
      ELSEIF(IEXPDI.EQ.0)THEN
!
        IJUNK=' '
        IFORMT=' '
        IFORMT(1:5)='(I15)'
        WRITE(IJUNK,IFORMT)INT(VAL+0.5)
!
        NH=0
        DO 1060 I=1,15
          IF(NH.EQ.0 .AND. IJUNK(I:I).EQ.' ')GO TO 1060
          NH=NH+1
          IH(NH)=IJUNK(I:I)
 1060   CONTINUE
        GO TO 9000
      ENDIF
!
      ABSVAL=ABS(VAL)
!
      AIVAL=IVAL
      DEL=AIVAL-VAL
      ABSDEL=ABS(DEL)
!
      ABSRAT=ABSDEL
      IF(ABSVAL.GE.1.0)ABSRAT=ABSDEL/ABSVAL
!
!CCCC CUTDEL=10.0**(-16)
!CCCC CUTDEL=10.0**(-6)
!CCCC CUTRAT=10.0**(-6)
      CUTDEL=10.0**(-10)
      CUTRAT=10.0**(-10)
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,911)
  911   FORMAT('***** FROM THE MIDDLE OF DPCONH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,913)ABSVAL,VAL,IVAL,AIVAL,DEL,ABSDEL
  913   FORMAT('ABSVAL,VAL,IVAL,AIVAL,DEL,ABSDEL = ',2G15.7,I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,914)ABSDEL,CUTDEL,ABSRAT,CUTRAT
  914   FORMAT('ABSDEL,CUTDEL,ABSRAT,CUTRAT = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ABSVAL.LT.1.0.AND.ABSDEL.LE.CUTDEL)GO TO 1000
      IF(ABSVAL.GE.1.0.AND.ABSRAT.LE.CUTRAT)GO TO 1000
      GO TO 2000
!
!               ******************************
!               **  STEP XX--               **
!               **  TREAT THE INTEGER CASE  **
!               ******************************
!
 1000 CONTINUE
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
        WRITE(ICOUT,1005)
 1005   FORMAT('*****INTEGER CASE*****')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      INUM=IABS(IVAL)
      NUMDII=0
      IF(INUM.EQ.0)NUMDII=NUMDII+1
      IF(INUM.EQ.0)IHTEMI(NUMDII)='0'
      IF(INUM.EQ.0)GO TO 1190
!
      DO 1100 I=1,10
        IF(INUM.LE.0)GO TO 1190
        IRATIO=INUM/10
        IREM=INUM-10*IRATIO
        INUM=IRATIO
        NUMDII=NUMDII+1
        CALL DPCODH(IREM,IHREM,IBUGD2,IERROR)
        IHTEMI(NUMDII)=IHREM
 1100 CONTINUE
 1190 CONTINUE
      IF(IVAL.LT.0)NUMDII=NUMDII+1
      IF(IVAL.LT.0)IHTEMI(NUMDII)='-'
!
      NH=NUMDII
      IF(NUMDII.GT.0)THEN
        DO 1200 I=1,NUMDII
          IREV=NUMDII-I+1
          IH(I)=IHTEMI(IREV)
 1200   CONTINUE
      ENDIF
!
      GO TO 9000
!
!               **********************************
!               **  STEP XX--                   **
!               **  TREAT THE NON-INTEGER CASE  **
!               **********************************
!
 2000 CONTINUE
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
        WRITE(ICOUT,2005)
 2005   FORMAT('*****NON-INTEGER CASE*****')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      INUM=INT(ABSVAL)
      AINUM=REAL(INUM)
      FRACT=ABSVAL-AINUM
!
      NUMDII=0
      IF(INUM.EQ.0)NUMDII=NUMDII+1
      IF(INUM.EQ.0)IHTEMI(NUMDII)='0'
      IF(INUM.EQ.0)GO TO 2190
!
      DO 2100 I=1,10
        IF(INUM.LE.0)GO TO 2190
        IRATIO=INUM/10
        IREM=INUM-10*IRATIO
        INUM=IRATIO
        NUMDII=NUMDII+1
        CALL DPCODH(IREM,IHREM,IBUGD2,IERROR)
        IHTEMI(NUMDII)=IHREM
 2100 CONTINUE
 2190 CONTINUE
      IF(VAL.LT.0)NUMDII=NUMDII+1
      IF(VAL.LT.0)IHTEMI(NUMDII)='-'
!
      NUMDID=0
      IF(FRACT.EQ.0.0)NUMDID=0
      IF(FRACT.EQ.0.0)GO TO 2390
!
      ANUM=FRACT
!CCCC NOTE 2011/2: ADD A FEW EXTRA DIGITS OF PRECISION
!CCCC NLOOP=8-NUMDII
!CCCC NLOOP=12-NUMDII
      NLOOP=14-NUMDII
!CCCC CUTOF2=10.0**(-NLOOP+1)
!CCCC CUTOF3=1.0-CUTOF2
      IF(NLOOP.LE.0)GO TO 2390
      DO 2300 I=1,NLOOP
        CUTOF2=10.0**(-NLOOP+I+1)
        CUTOF3=1.0-CUTOF2
        ANUM=ANUM*10.0
        INUM=INT(ANUM)
        AINUM=REAL(INUM)
        DEL3=ANUM-AINUM
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
          WRITE(ICOUT,2311)NLOOP,I,CUTOF3,CUTOF2
 2311     FORMAT('NLOOP,I,CUTOF3,CUTOF2 = ',I8,I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2312)ANUM,AINUM,DEL3,CUTOF3
 2312     FORMAT('ANUM,AINUM,DEL3,CUTOF3 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!CCCC   IF(CUTOF3.GT.0.0000001)THEN
        IF(CUTOF3.GT.0.000000001)THEN
          IF(DEL3.GE.CUTOF3)INUM=INUM+1
          IF(DEL3.GE.CUTOF3)ANUM=INUM
        ELSE
          IF(DEL3.GE.0.5)INUM=INUM+1
          IF(DEL3.GE.0.5)ANUM=INUM
        ENDIF
        NUMDID=NUMDID+1
        CALL DPCODH(INUM,IHNUM,IBUGD2,IERROR)
        IHTEMD(NUMDID)=IHNUM
        AINUM=INUM
        DEL2=ANUM-AINUM
        ANUM=DEL2
!
        IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
          WRITE(ICOUT,2313)ANUM,AINUM,DEL2,CUTOF2
 2313     FORMAT('ANUM,AINUM,DEL2,CUTOF2 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(DEL2.LE.CUTOF2)GO TO 2390
 2300 CONTINUE
 2390 CONTINUE
!
      NH=0
      IF(NUMDII.GT.0)THEN
        DO 2400 I=1,NUMDII
        NH=NH+1
        IREV=NUMDII-I+1
        IH(NH)=IHTEMI(IREV)
 2400   CONTINUE
      ENDIF
!
      NH=NH+1
      IH(NH)='.'
!
      IF(NUMDID.GT.0)THEN
        DO 2500 I=1,NUMDID
          NH=NH+1
          IH(NH)=IHTEMD(I)
 2500   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CONH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCONH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)NUMDII,NUMDID,NH,IVAL,VAL
 9012   FORMAT('NUMDII,NUMDID,NH,IVAL,VAL = ',4I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)AIVAL,VAL,DEL,ABSDEL,CUTDEL
 9013   FORMAT('AIVAL,VAL,DEL,ABSDEL,CUTDEL = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ABSVAL,INUM,AINUM,FRACT
 9014   FORMAT('ABSVAL,INUM,AINUM,FRACT = ',G15.7,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)(IHTEMI(I),I=1,NUMDII)
 9016   FORMAT('(IHTEMI(I),I=1,NUMDII) = ',20A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9026)(IHTEMD(I),I=1,NUMDID)
 9026   FORMAT('(IHTEMD(I),I=1,NUMDID) = ',20A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)(IH(I),I=1,NH)
 9032   FORMAT('(IH(I),I=1,NH) = ',20A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCONH
