      SUBROUTINE DPCOOR(ICASPL,ICASP2,Y,N,   &
                        PX1COO,X1COOR,NX1COO,   &
                        PX2COO,X2COOR,NX2COO,   &
                        PY1COO,Y1COOR,NY1COO,   &
                        PY2COO,Y2COOR,NY2COO,   &
                        IBUGG4,ISUBRO,IERROR)
!
!     PURPOSE--SAVE THE CURRENT SETTINGS OF THE Y (OR X) TIC MARK
!              LABEL COORDINATES.  THIS CAN OCCASSIONALLY BE USEFUL IF
!              YOU NEED TO ADD SOME ADDITIONAL TEXT TO THE TIC LABELS.
!              NOTE THAT THE COORDINATES CAN BE RETURNED IN EITHER
!              SCREEN (PX1COO, PX2COO, PY1COO, PY2COO) OR DATA
!              (X1COOR, X2COOR, Y1COOR, Y2COOR) UNITS.
!     EXAMPLES--LET YOUT = Y1TIC SCREEN COORDINATES
!               LET YOUT = Y1TIC DATA   COORDINATES
!               LET YOUT = YTIC  SCREEN COORDINATES
!               LET XOUT = XTIC  SCREEN COORDINATES
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018.10
!     ORIGINAL VERSION--OCTOBER   2018.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-----------------------------------
!
      DIMENSION Y(*)
      DIMENSION PX1COO(*)
      DIMENSION X1COOR(*)
      DIMENSION PX2COO(*)
      DIMENSION X2COOR(*)
      DIMENSION PY1COO(*)
      DIMENSION Y1COOR(*)
      DIMENSION PY2COO(*)
      DIMENSION Y2COOR(*)
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IBUGG4
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'COOR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOOR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)ICASPL,ICASP2,NX1COO,NX2COO,NY1COO,NY2COO
   54   FORMAT('ICASPL,ICASP2,NX1COO,NX2COO,NY1COO,NY2COO = ',   &
               2(A4,2X),4I5)
        CALL DPWRST('XXX','BUG ')
        IF(NX1COO.GE.1)THEN
          DO 61 I=1,NX1COO
            WRITE(ICOUT,62)I,X1COOR(I),PX1COO(I)
   62       FORMAT('I,X1COOR(I),PX1COO(I) = ',I5,2G15.7)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
        IF(NX2COO.GE.1)THEN
          DO 66 I=1,NX2COO
            WRITE(ICOUT,67)I,X2COOR(I),PX2COO(I)
   67       FORMAT('I,X2COOR(I),PX2COO(I) = ',I5,2G15.7)
            CALL DPWRST('XXX','BUG ')
   66     CONTINUE
        ENDIF
        IF(NY1COO.GE.1)THEN
          DO 71 I=1,NY1COO
            WRITE(ICOUT,72)I,Y1COOR(I),PY1COO(I)
   72       FORMAT('I,Y1COOR(I),PY1COO(I) = ',I5,2G15.7)
            CALL DPWRST('XXX','BUG ')
   71     CONTINUE
        ENDIF
        IF(NY2COO.GE.1)THEN
          DO 76 I=1,NY2COO
            WRITE(ICOUT,77)I,Y2COOR(I),PY2COO(I)
   77       FORMAT('I,Y2COOR(I),PY2COO(I) = ',I5,2G15.7)
            CALL DPWRST('XXX','BUG ')
   76     CONTINUE
        ENDIF
      ENDIF
!
      IERROR='YES'
!
!               *******************************************************
!               **  STEP 1--                                         **
!               **  EXTRACT THE REQUESTED TIC MARK COORDINATES.      **
!               *******************************************************
!
      IF(ICASPL.EQ.'Y1  ' .OR. ICASPL.EQ.'Y   ')THEN
        IF(NY1COO.LT.1)THEN
          N=0
          GO TO 9000
        ELSE
          N=NY1COO
        ENDIF
        IF(ICASP2.EQ.'SCRE')THEN
          DO 110 I=1,NY1COO
            Y(I)=PY1COO(I)
  110     CONTINUE
        ELSE
          DO 120 I=1,NY1COO
            Y(I)=Y1COOR(I)
  120     CONTINUE
        ENDIF
      ELSEIF(ICASPL.EQ.'Y2  ')THEN
        IF(NY2COO.LT.1)THEN
          N=0
          GO TO 9000
        ELSE
          N=NY2COO
        ENDIF
        IF(ICASP2.EQ.'SCRE')THEN
          DO 210 I=1,NY2COO
            Y(I)=PY2COO(I)
  210     CONTINUE
        ELSE
          DO 220 I=1,NY2COO
            Y(I)=Y2COOR(I)
  220     CONTINUE
        ENDIF
      ELSEIF(ICASPL.EQ.'X1  ' .OR. ICASPL.EQ.'X   ')THEN
        IF(NX1COO.LT.1)THEN
          N=0
          GO TO 9000
        ELSE
          N=NX1COO
        ENDIF
        IF(ICASP2.EQ.'SCRE')THEN
          DO 310 I=1,NX1COO
            Y(I)=PX1COO(I)
  310     CONTINUE
        ELSE
          DO 320 I=1,NX1COO
            Y(I)=X1COOR(I)
  320     CONTINUE
        ENDIF
      ELSEIF(ICASPL.EQ.'X2  ')THEN
        IF(NX2COO.LT.1)THEN
          N=0
          GO TO 9000
        ELSE
          N=NX2COO
        ENDIF
        IF(ICASP2.EQ.'SCRE')THEN
          DO 410 I=1,NX2COO
            Y(I)=PX2COO(I)
  410     CONTINUE
        ELSE
          DO 420 I=1,NX2COO
            Y(I)=X2COOR(I)
  420     CONTINUE
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON'.OR.ISUBRO.EQ.'COOR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOOR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9052)N
 9052   FORMAT('N = ',I6)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 9060 I=1,N
            WRITE(ICOUT,9062)I,Y(I)
 9062       FORMAT('I,Y(I) = ',I6,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9060     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOOR
      SUBROUTINE DPCOR2(Y1,Y2,N,NCURVE,ICASPL,NUMLAG,MAXN,   &
                        IAUTCP,IAUTL0,TEMP1,TEMP2,   &
                        Y,X,D,TOP,BOTTOM,PCC,NPLOTP,NPLOTV,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE
!                   1) AN AUTOCORRELATION PLOT
!                   2) A CROSS-CORRELATION PLOT
!                   3) A PARTIAL AUTOCORRELATION PLOT
!                   4) AN AUTOCOMOVEMENT PLOT
!                   5) A CROSS-COMOVEMENT PLOT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --MARCH     1979.
!     UPDATED         --APRIL     1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       1992. REWRITE AUTOCORR. FOR SMALL N
!     UPDATED         --FEBRUARY  1993. PARTIAL AUTOCORRELATION PLOT
!     UPDATED         --DECEMBER  1994. FIX XLIMITS /REF. LINES PROBLEM
!     UPDATED         --JULY      1999. SUPPORT FIXED OR MOVING ERROR
!                                       LIMITS.
!     UPDATED         --FEBRUARY  2003. SUPPORT OPTION TO OMIT LAG 0 ON
!                                       AUTOCORRELATION AND PARTIAL
!                                       AUTOCORRELATION PLOT (IAUTL0)
!     UPDATED         --JANUARY   2012. FOLD IN COMOVEMENT PLOTS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC ADD FOLLOWING LINE JULY 1999
      CHARACTER*4 IAUTCP
!CCCC ADD FOLLOWING LINE FEBRUARY 2003
      CHARACTER*4 IAUTL0
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFOUND
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
!
!CCCC TO DO--THE FOLLOWING DIMENSIONS MUST BE GENERALIZED BEYOND 1000
!CCCC 2/93
!CCCC MOVE FOLLOWING DIMENSIONS TO DPCORR.   OCTOBER 1997
!CCCC DIMENSION TOP(1000)
!CCCC DIMENSION BOTTOM(1000)
!CCCC DIMENSION PCC(1000)
      DIMENSION TOP(*)
      DIMENSION BOTTOM(*)
      DIMENSION PCC(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='R2  '
      IERROR='NO'
      IWRITE='OFF'
!
      J=(-999)
      KMAX=(-999)
      IFACT=1
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPCOR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)ICASPL,N,NUMLAG,MAXN
   71   FORMAT('ICASPL,N,NUMLAG,MAXN = ',A4,2X,3I8)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y1(I),Y2(I)
   74     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.3)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN ...CORRELATION/COMOVEMENT PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y1(1)
      DO 60 I=1,N
        IF(Y1(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)HOLD
   62 FORMAT('      ALL ELEMENTS IN Y1 ARE IDENTICALLY EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!               *******************************
!               **  STEP 2--                 **
!               **  IF NECESSARY,            **
!               **  COMPUTE THE MAXIMUM LAG  **
!               *******************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      MAXLAG=MAXN
      IF(NUMLAG.GE.1)KMAX=NUMLAG
      IF(NUMLAG.LE.0)KMAX=N/4
      IF(NUMLAG.LE.0.AND.N.LE.32)KMAX=N/2
      IF(NUMLAG.LE.0.AND.N.LE.16)KMAX=N
      IF(KMAX.GT.MAXLAG)KMAX=MAXLAG
      NM1=N-1
      IF(KMAX.GT.NM1)KMAX=NM1
!CCCC THE FOLLOWING 4 LINES WERE ADDED MAY 1992 (JJF)
      IF(N.LE.16)THEN
         NM2=N-2
         IF(KMAX.GT.NM2)KMAX=NM2
      ENDIF
      KMAXM1=KMAX-1
      AKMAXM=KMAXM1
      AN=N
!
!               **************************************
!               **  STEP 4--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **  AND DETERMINE PLOT COORDINATES  **
!               **************************************
!
      ISTEPN='4'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
      IF(ICASPL.EQ.'AUCO')THEN
!
!        ******************************************************
!        **  STEP 4.1--                                      **
!        **  COMPUTE THE AUTOCORRELATIONS FOR THE X  DATA    **
!        **  DO SO IN 3 STEPS--                              **
!        **     1) COMPUTE THE SAMPLE MEAN;                  **
!        **     2) COMPUTE THE SAMPLE VARIANCE;              **
!        **     3) COMPUTE THE AUTOCORRELATIONS;             **
!        **  REFERENCE--JENKINS AND WATTS, PAGE 382 (9.3.1)  **
!        ******************************************************
!
        ISTEPN='4.1'
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')   &
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(N.LE.16)THEN
!
!         COMPUTE AUTOCORRELATIONS FOR N <= 16
!
          DO 1110 K=1,KMAXM1
            NMK=N-K
            ANMK=NMK
            SUM1=0.0
            SUM2=0.0
            DO 1120 I=1,NMK
              J=I+K
              SUM1=SUM1+Y1(I)
              SUM2=SUM2+Y1(J)
 1120       CONTINUE
            Y1BAR=SUM1/ANMK
            Y2BAR=SUM2/ANMK
!
            SUM1=0.0
            SUM2=0.0
            DO 1130 I=1,NMK
              J=I+K
              SUM1=SUM1+(Y1(I)-Y1BAR)**2
              SUM2=SUM2+(Y1(J)-Y2BAR)**2
 1130       CONTINUE
            SSQ1=SUM1
            SSQ2=SUM2
!
            SUM1=0.0
            DO 1140 I=1,NMK
              J=I+K
              SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(J)-Y2BAR)
 1140       CONTINUE
            ANUM=SUM1
!
            SQRT1=0.0
            IF(SSQ1.GT.0.0)SQRT1=SQRT(SSQ1)
            SQRT2=0.0
            IF(SSQ2.GT.0.0)SQRT2=SQRT(SSQ2)
            DENOM=SQRT1*SQRT2
            AC=0.0
            IF(DENOM.GT.0.0)AC=ANUM/DENOM
            TEMP1(K)=AC
 1110     CONTINUE
        ELSE
!
!         COMPUTE AUTOCORRELATIONS FOR N >= 17
!
          SUM1=0.0
          DO 1210 I=1,N
            SUM1=SUM1+Y1(I)
 1210     CONTINUE
          Y1BAR=SUM1/AN
!
          SUM1=0.0
          DO 1220 I=1,N
            SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(I)-Y1BAR)
 1220     CONTINUE
          VARB1=SUM1/AN
          VAR1=SUM1/(AN-1.0)
!
          DO 1230 K=1,KMAXM1
            SUM1=0.0
            NMK=N-K
            DO 1240 I=1,NMK
              J=I+K
              SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(J)-Y1BAR)
 1240       CONTINUE
            TEMP1(K)=SUM1/AN
            TEMP1(K)=TEMP1(K)/VARB1
 1230     CONTINUE
        ENDIF
!
!       FORM OUTPUT VECTORS FOR BOTH AUTOCORRELATION CASES
!
        YMID=0.0
        SDR=1.0/SQRT(AN)
        YUPP95=1.96*SDR
        YLOW95=(-YUPP95)
        YUPP99=2.576*SDR
        YLOW99=(-YUPP99)
        IOUT=0
        IFACT=6
        AFACT=1.0/AN
        YSUM1=0.0
        YSUM2=0.0
        YSUM3=0.0
        YSUM4=0.0
!
        J=0
        IF(IAUTL0.EQ.'ON')THEN
          J=J+1
          Y(J+NPLOTP)=1.0
          X(J+NPLOTP)=0.0
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          IF(IAUTCP.EQ.'BOXJ')THEN
            J=J+1
            Y(J+NPLOTP)=YMID
            X(J+NPLOTP)=0.0
            D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YMID
            X(J+NPLOTP)=0.0
            D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YMID
            X(J+NPLOTP)=0.0
            D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YMID
            X(J+NPLOTP)=0.0
            D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
          ENDIF
        ENDIF
!
        DO 1310 K=1,KMAXM1
          J=J+1
          Y(J+NPLOTP)=TEMP1(K)
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          IF(Y(J).GT.YUPP95)IOUT=IOUT+1
          IF(Y(J).LT.YLOW95)IOUT=IOUT+1
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
!CCCC     SUPPORT FIXED CONFIDENCE BANDS FOR TESTING FOR WHITE NOISE.
!CCCC     MOVING BANDS FOR BOX-JENKINS MODELING.
          IF(IAUTCP.NE.'BOXJ')THEN
            J=J+1
            Y(J+NPLOTP)=YUPP95
            X(J+NPLOTP)=REAL(K)
            D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YLOW95
            X(J+NPLOTP)=REAL(K)
            D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YUPP99
            X(J+NPLOTP)=REAL(K)
            D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
            J=J+1
            Y(J+NPLOTP)=YLOW99
            X(J+NPLOTP)=REAL(K)
            D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
          ELSE
!
            IF(K.EQ.1)THEN
              J=J+1
              YSUM1=YSUM1 + TEMP1(K)**2
              Y(J+NPLOTP)=YUPP95
              X(J+NPLOTP)=1.0
              D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
              YSUM2=YSUM2 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=YLOW95
              X(J+NPLOTP)=1.0
              D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
              YSUM3=YSUM3 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=YUPP99
              X(J+NPLOTP)=1.0
              D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
              YSUM4=YSUM4 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=YLOW99
              X(J+NPLOTP)=1
              D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
            ELSE
              YSUM1=YSUM1 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=1.96*SQRT(AFACT*(1.0+2.0*YSUM1))
              X(J+NPLOTP)=REAL(K)
              D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
              YSUM2=YSUM2 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=YLOW95
              Y(J+NPLOTP)=-1.96*SQRT(AFACT*(1.0+2.0*YSUM2))
              X(J+NPLOTP)=REAL(K)
              D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
              YSUM3=YSUM3 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=2.576*SQRT(AFACT*(1.0+2.0*YSUM3))
              X(J+NPLOTP)=REAL(K)
              D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
              YSUM4=YSUM4 + TEMP1(K)**2
              J=J+1
              Y(J+NPLOTP)=-2.576*SQRT(AFACT*(1.0+2.0*YSUM4))
              X(J+NPLOTP)=REAL(K)
              D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
            ENDIF
!
          ENDIF
!
 1310   CONTINUE
        AIOUT=IOUT
        AKMAXM=KMAXM1
        PEROUT=100.0*(AIOUT/AKMAXM)
!
        NPLOTP=NPLOTP+J
        NPLOTV=3
!
        CALL DPWCCP(ICASPL,   &
                    YLOW95,YUPP95,IOUT,KMAXM1,PEROUT,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
!
      ELSEIF(ICASPL.EQ.'CRCO')THEN
!
!           **********************************************************
!           **  STEP 4.2--                                          **
!           **  COMPUTE CROSS-CORRELATIONS FOR THE X AND Y  DATA    **
!           **  DO SO IN 3 STEPS--                                  **
!           **     1) COMPUTE THE SAMPLE MEAN;                      **
!           **     2) COMPUTE THE SAMPLE VARIANCE;                  **
!           **     3) COMPUTE THE AUTOCORRELATIONS;                 **
!           **  REFERENCE--JENKINS AND WATTS, PAGE 382 (9.3.1)      **
!           **********************************************************
!
        ISTEPN='4.2'
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        SUM1=0.0
        SUM2=0.0
        DO 2110 I=1,N
          SUM1=SUM1+Y1(I)
          SUM2=SUM2+Y2(I)
 2110   CONTINUE
        Y1BAR=SUM1/AN
        Y2BAR=SUM2/AN
!
        SUM1=0.0
        SUM2=0.0
        DO 2120 I=1,N
          SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(I)-Y1BAR)
          SUM2=SUM2+(Y2(I)-Y2BAR)*(Y2(I)-Y2BAR)
 2120   CONTINUE
        VARB1=SUM1/AN
        VARB2=SUM2/AN
        VAR1=SUM1/(AN-1.0)
        VAR2=SUM2/(AN-1.0)
        DENOM=0.0
        PROD=VAR1*VAR2
        IF(PROD.GT.0.0)DENOM=SQRT(PROD)
!
        INDEX=0
!
        DO 2130 K=1,KMAXM1
          INDEX=INDEX+1
          KREV=KMAXM1-K+1
          SUM12=0.0
          NMKREV=N-KREV
          DO 2132 I=1,NMKREV
            J=I+KREV
            SUM12=SUM12+(Y1(J)-Y1BAR)*(Y2(I)-Y2BAR)
 2132     CONTINUE
          TEMP1(INDEX)=SUM12/AN
 2130   CONTINUE
!
        K=0
        INDEX=INDEX+1
        SUM12=0.0
        DO 2134 I=1,N
          J=I
          SUM12=SUM12+(Y1(I)-Y1BAR)*(Y2(J)-Y2BAR)
 2134   CONTINUE
        TEMP1(INDEX)=SUM12/AN
!
        DO 2136 K=1,KMAXM1
          INDEX=INDEX+1
          SUM12=0.0
          NMK=N-K
          DO 2138 I=1,NMK
            J=I+K
            SUM12=SUM12+(Y1(I)-Y1BAR)*(Y2(J)-Y2BAR)
 2138     CONTINUE
          TEMP1(INDEX)=SUM12/AN
 2136   CONTINUE
!
        YMID=0.0
        SDR=1.0/SQRT(AN)
        YUPP95=1.96*SDR
        YLOW95=(-YUPP95)
        YUPP99=2.576*SDR
        YLOW99=(-YUPP99)
        IFACT=6
!
        L=(-KMAXM1-1)
        J=0
        DO 2150 J2=1,INDEX
          J=J+1
          L=L+1
          Y(J+NPLOTP)=1.0
          IF(DENOM.GT.0.0)Y(J+NPLOTP)=TEMP1(J2)/DENOM
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
!
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YUPP95
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YLOW95
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
          J=J+1
          Y(J)=YUPP99
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
          J=J+1
          Y(J)=YLOW99
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
 2150   CONTINUE
!
        NPLOTP=NPLOTP+J
        NPLOTV=3
!
      ELSEIF(ICASPL.EQ.'PACO')THEN
!
!CCCC   THE FOLLOWING ENTIRE SECTION WAS ADDED FEBRUARY 1993
!           ******************************************************
!           **  STEP 4.3--                                      **
!           **  COMPUTE THE PARTIAL AUTOCORRELATIONS FOR THE X  **
!           **  DATA.   DO SO IN 4 STEPS--                      **
!           **     1) COMPUTE THE SAMPLE MEAN;                  **
!           **     2) COMPUTE THE SAMPLE VARIANCE;              **
!           **     3) COMPUTE THE AUTOCORRELATIONS;             **
!           **     4) COMPUTE THE PARTIAL AUTOCORRELATIONS;     **
!           **  REFERENCE--JENKINS AND WATTS, PAGE 382 (9.3.1)  **
!           **  REFERENCE--WEISS, COMMUNICATIONS IN STATISTICS, **
!           **             PAGE 382 (9.3.1)                     **
!           ******************************************************
!
        ISTEPN='4.3'
        IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
!       IF N <= 16, COMPUTE (SIMPLE) AUTOCORRELATIONS
!
        IF(N.LE.16)THEN
          AN=N
!
          DO 3110 K=1,KMAXM1
            NMK=N-K
            ANMK=NMK
            SUM1=0.0
            SUM2=0.0
            DO 3120 I=1,NMK
               J=I+K
               SUM1=SUM1+Y1(I)
               SUM2=SUM2+Y1(J)
 3120       CONTINUE
            Y1BAR=SUM1/ANMK
            Y2BAR=SUM2/ANMK
!
            SUM1=0.0
            SUM2=0.0
            DO 3130 I=1,NMK
               J=I+K
               SUM1=SUM1+(Y1(I)-Y1BAR)**2
               SUM2=SUM2+(Y1(J)-Y2BAR)**2
 3130       CONTINUE
            SSQ1=SUM1
            SSQ2=SUM2
!
            SUM1=0.0
            DO 3140 I=1,NMK
               J=I+K
               SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(J)-Y2BAR)
 3140       CONTINUE
            ANUM=SUM1
!
            SQRT1=0.0
            IF(SSQ1.GT.0.0)SQRT1=SQRT(SSQ1)
            SQRT2=0.0
            IF(SSQ2.GT.0.0)SQRT2=SQRT(SSQ2)
            DENOM=SQRT1*SQRT2
            AC=0.0
            IF(DENOM.GT.0.0)AC=ANUM/DENOM
            TEMP1(K)=AC
 3110     CONTINUE
!
!         IF N >= 17, COMPUTE (SIMPLE) AUTOCORRELATIONS
!
        ELSEIF(N.GE.17)THEN
          AN=N
!
          SUM1=0.0
          DO 3210 I=1,N
            SUM1=SUM1+Y1(I)
 3210     CONTINUE
          Y1BAR=SUM1/AN
!
          SUM1=0.0
          DO 3220 I=1,N
            SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(I)-Y1BAR)
 3220     CONTINUE
          VARB1=SUM1/AN
          VAR1=SUM1/(AN-1.0)
!
          DO 3230 K=1,KMAXM1
            SUM1=0.0
            NMK=N-K
            DO 3240 I=1,NMK
              J=I+K
              SUM1=SUM1+(Y1(I)-Y1BAR)*(Y1(J)-Y1BAR)
 3240       CONTINUE
            TEMP1(K)=SUM1/AN
            TEMP1(K)=TEMP1(K)/VARB1
 3230     CONTINUE
        ENDIF
!
!       FORM PARTIAL AUTOCORRELATIONS FROM SIMPLE AUTOCORRELATIONS
!       REFERENCE--WEISS, COMMUN. OF STAT., 1984, P. 541-542.
!
        K=KMAXM1
        I=0
        I2=I+1
        TOP(I2)=1.0
        BOTTOM(I2)=1.0
        DO 3310 I=1,K
          I2=I+1
          TOP(I2)=TEMP1(I)
          BOTTOM(I2)=TEMP1(I)
 3310   CONTINUE
!
        PCC(1)=1.0
        DO 3320 J=1,K
          J2=J+1
          PCC(J2)=TOP(1+1)/BOTTOM(0+1)
!
          IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'COR2')THEN
            WRITE(ICOUT,3321)J,J2,PCC(J2)
 3321       FORMAT('J,J2,PCC(J2) = ',2I8,F10.5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          KMJ=K-J
          DO 3330 I=1,KMJ
            I2=I+1
            BOTTOM(I2-1)=BOTTOM(I2-1)-TOP(I2)*PCC(J2)
            TOP(I2)=TOP(I2+1)-BOTTOM(I2)*PCC(J2)
 3330     CONTINUE
 3320   CONTINUE
!
!       FORM OUTPUT VECTORS
!
        YMID=0.0
        SDR=1.0/SQRT(AN)
        YUPP95=1.96*SDR
        YLOW95=(-YUPP95)
        YUPP99=2.576*SDR
        YLOW99=(-YUPP99)
        IOUT=0
!
        J=0
        IF(IAUTL0.EQ.'ON')THEN
          J=J+1
          Y(J+NPLOTP)=PCC(1)
          X(J+NPLOTP)=0.0
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
        ENDIF
!
        DO 3410 K=1,KMAXM1
          J=J+1
          Y(J+NPLOTP)=PCC(K+1)
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          IF(Y(J+NPLOTP).GT.YUPP95)IOUT=IOUT+1
          IF(Y(J+NPLOTP).LT.YLOW95)IOUT=IOUT+1
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YUPP95
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(3 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YLOW95
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(4 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YUPP99
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(5 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YLOW99
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(6 + IFACT*(NCURVE-1))
 3410   CONTINUE
        AIOUT=IOUT
        AKMAXM=KMAXM1
        PEROUT=100.0*(AIOUT/AKMAXM)
!
        NPLOTP=NPLOTP+J
        NPLOTV=3
!
        CALL DPWCCP(ICASPL,   &
                    YLOW95,YUPP95,IOUT,KMAXM1,PEROUT,   &
                    IBUGG3,ISUBRO,IFOUND,IERROR)
!
!           ******************************************************
!           **  STEP 4.4--                                      **
!           **  COMPUTE THE AUTOCOMOVEMENT FOR THE X DATA.      **
!           ******************************************************
!
      ELSEIF(ICASPL.EQ.'AUCM')THEN
        IFACT=2
        YMID=0.0
        J=1
        X(J+NPLOTP)=0.0
        Y(J+NPLOTP)=1.0
        D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
!
        DO 4110 K=1,KMAXM1
          NMK=N-K
          ANMK=NMK
          DO 4120 I=1,NMK
            JJ=I+K
            TEMP1(I)=Y1(I)
            TEMP2(I)=Y1(JJ)
 4120     CONTINUE
          CALL COMOVE(TEMP1,TEMP2,NMK,IWRITE,XYCOMO,IBUGG3,IERROR)
          J=J+1
          X(J+NPLOTP)=REAL(K)
          Y(J+NPLOTP)=XYCOMO
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
 4110   CONTINUE
!
        NPLOTP=NPLOTP+J
        NPLOTV=3
!
      ELSEIF(ICASPL.EQ.'CRCM')THEN
!
!       **********************************************************
!       **  STEP 5.2--                                          **
!       **  COMPUTE CROSS-COMOVEMENTS  FOR THE X AND Y  DATA    **
!       **********************************************************
!
        IFACT=2
        YMID=0.0
        J=0
        L=(-KMAXM1-1)
        DO 5110 K=1,KMAXM1
          KREV=KMAXM1-K+1
          NMK=N-KREV
          ANMK=NMK
          DO 5120 I=1,NMK
            JJ=I+KREV
            TEMP1(I)=Y1(JJ)
            TEMP2(I)=Y2(I)
 5120     CONTINUE
          CALL COMOVE(TEMP1,TEMP2,NMK,IWRITE,XYCOMO,IBUGG3,IERROR)
          J=J+1
          L=L+1
          X(J+NPLOTP)=REAL(L)
          Y(J+NPLOTP)=XYCOMO
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(L)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
 5110   CONTINUE
!
        J=J+1
        X(J+NPLOTP)=0.0
        Y(J+NPLOTP)=1.0
        D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
        J=J+1
        X(J+NPLOTP)=0.0
        Y(J+NPLOTP)=0.0
        D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
!
        DO 5210 K=1,KMAXM1
          NMK=N-K
          ANMK=NMK
          DO 5220 I=1,NMK
            JJ=I+K
            TEMP1(I)=Y1(I)
            TEMP2(I)=Y2(JJ)
 5220     CONTINUE
          CALL COMOVE(TEMP1,TEMP2,NMK,IWRITE,XYCOMO,IBUGG3,IERROR)
          J=J+1
          X(J+NPLOTP)=REAL(K)
          Y(J+NPLOTP)=XYCOMO
          D(J+NPLOTP)=REAL(1 + IFACT*(NCURVE-1))
          J=J+1
          Y(J+NPLOTP)=YMID
          X(J+NPLOTP)=REAL(K)
          D(J+NPLOTP)=REAL(2 + IFACT*(NCURVE-1))
 5210   CONTINUE
!
        NPLOTP=NPLOTP+J
        NPLOTV=3
!
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      ICASPL SHOULD BE ONE OF')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1013)
 1013   FORMAT('      AUCO, CRCO, PACO, AUCM, OR CRCM, BUT IS NOT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1014)ICASPL
 1014   FORMAT('      ICASPL = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'COR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOR2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,NUMLAG,N,KMAX,NPLOTP,IERROR
 9012   FORMAT('ICASPL,NUMLAG,N,KMAX,NPLOTP,IERROR = ',A4,4I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NPLOTP
          WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016     FORMAT('I,Y(I),X(I),D(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,10
          WRITE(ICOUT,9021)I,D(I),TOP(I),BOTTOM(I),PCC(I)
 9021     FORMAT('I,D(I),TOP(I),BOTTOM(I),PCC(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOR2
      SUBROUTINE DPCORE(XMAT,K,N,MAXROM,MAXK,   &
                        CORE,ICTAG,NROW,NUMCOR,   &
                        IVLIST,TEMP1,TEMP2,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     IMPLEMENT THE FOLLOWING COMMAND
!
!         LET COREFAC = DEX CORE X1 ... XK
!
!     COREFAC WILL BE A MATRIX WITH 5 COLUMNS.
!
!     THIS COMMAND IMPLEMENTS THE "CORE.DP" MACRO IN FORTRAN FOR
!     PERFORMANCE REASONS.  THIS COMMAND DETERMINES THE CORE VECTORS
!     SPANNING THE (N-1) SPACE (OR A LARGE PART OF IT) FOR EFFECT
!     ESTIMATION CALCULATIONS BY THE EST.DP MACRO IN THE 10-STEP
!     SERIES OF MACROS.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/01
!     ORIGINAL VERSION--JANUARY   2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      PARAMETER (MAXNOC=100)
!
      DIMENSION XMAT(MAXROM,K)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION CORE(MAXROM,5)
      INTEGER IVLIST(NROW,5)
      INTEGER ICTAG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='RE  '
      IERROR='NO'
      IWRITE='OFF'
!
      KM1=0
      KM2=0
      KM3=0
      NUMFAC=K
      NINP=N
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,K,NROW,MAXK,MAXROM
   52   FORMAT('N,K,NROW,MAXK,MAXROM = ',5I8)
        CALL DPWRST('XXX','BUG ')
        DO 61 I=1,N
          WRITE(ICOUT,63)I,(XMAT(I,J),J=1,MIN(K,10))
   63     FORMAT('I,XMAT(I,J) = ',I8,10G15.7)
          CALL DPWRST('XXX','BUG ')
   61   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 0.5--                                  **
!               **   CHECK FOR VALID VALUES OF K                **
!               **************************************************
!
      ISTEPN='0.5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'FIT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(K.LT.1 .OR. K.GT.MAXK)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,91)
   91   FORMAT('***** ERROR IN DEX CORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,93)MAXK
   93   FORMAT('      THE NUMBER OF DESIGN FACTORS IS LESS THAN ',   &
               '1 OR GREATER THAN ',I3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,95)K
   95   FORMAT('      THE NUMBER OF DESIGN FACTORS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     REMOVE CENTER POINTS (I.E., = 0) AND CHECK THAT ALL REMAINING
!     POINTS ARE EITHER -1 OR +1.
!
      DO 70 J=1,NUMFAC
        ICNT=0
        DO 80 I=1,NINP
          AVAL=XMAT(I,J)
          IF(AVAL.EQ.0.0)THEN
            GO TO 80
          ELSEIF(AVAL.NE.-1.0 .AND. AVAL.NE.1.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,91)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,85)I,J
   85       FORMAT('     ROW ',I8,' OF FACTOR ',I5,' DOES NOT EQUAL ',   &
                   '-1 OR +1')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,87)AVAL
  87        FORMAT('     THE VALUE IS ',G15.7)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            ICNT=ICNT+1
            XMAT(ICNT,J)=XMAT(I,J)
          ENDIF
   80   CONTINUE
   70 CONTINUE
      NINP=ICNT
!
      DO 101 J=1,5
        DO 103 I=1,NROW
          CORE(I,J)=-999.
          IVLIST(I,J)=-999
  103   CONTINUE
  101 CONTINUE
!
      DO 105 I=1,NROW
        ICTAG(I)=1
  105 CONTINUE
!
      NUMCOR=0
      DO 110 J=1,K
        NUMCOR=NUMCOR+1
        IVLIST(NUMCOR,1)=J
  110 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,112)NUMCOR
  112   FORMAT('AFTER K = 1, NUMCOR = ',I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(K.GE.2)THEN
        KM1=K-1
        DO 120 J1=1,KM1
          J1P1=J1+1
          DO 125 J2=J1P1,K
            NUMCOR=NUMCOR+1
            IVLIST(NUMCOR,1)=J1
            IVLIST(NUMCOR,2)=J2
  125     CONTINUE
  120     CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,122)NUMCOR
  122   FORMAT('AFTER K = 2, NUMCOR = ',I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NUMCOR.LE.MAXNOC .AND. K.GE.3)THEN
        KM2=K-2
        DO 130 J1=1,KM2
          J1P1=J1+1
          DO 135 J2=J1P1,KM1
            J2P1=J2+1
            DO 138 J3=J2P1,K
              NUMCOR=NUMCOR+1
              IVLIST(NUMCOR,1)=J1
              IVLIST(NUMCOR,2)=J2
              IVLIST(NUMCOR,3)=J3
  138       CONTINUE
  135     CONTINUE
  130     CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,132)NUMCOR
  132   FORMAT('AFTER K = 3, NUMCOR = ',I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NUMCOR.LE.MAXNOC .AND. K.GE.4)THEN
        KM3=K-3
        DO 140 J1=1,KM3
          J1P1=J1+1
          DO 143 J2=J1P1,KM2
            J2P1=J2+1
            DO 145 J3=J2P1,KM1
              J3P1=J3+1
              DO 148 J4=J3P1,K
                NUMCOR=NUMCOR+1
                IVLIST(NUMCOR,1)=J1
                IVLIST(NUMCOR,2)=J2
                IVLIST(NUMCOR,3)=J3
                IVLIST(NUMCOR,4)=J4
  148         CONTINUE
  145       CONTINUE
  143     CONTINUE
  140   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,142)NUMCOR
  142   FORMAT('AFTER K = 4, NUMCOR = ',I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NUMCOR.LE.MAXNOC .AND. K.GE.5)THEN
        KM4=K-4
        DO 150 J1=1,KM4
          J1P1=J1+1
          DO 151 J2=J1P1,KM3
            J2P1=J2+1
            DO 153 J3=J2P1,KM2
              J3P1=J3+1
              DO 155 J4=J3P1,KM1
                J4P1=J4+1
                DO 158 J5=J4P1,K
                  NUMCOR=NUMCOR+1
                  IVLIST(NUMCOR,1)=J1
                  IVLIST(NUMCOR,2)=J2
                  IVLIST(NUMCOR,3)=J3
                  IVLIST(NUMCOR,4)=J4
                  IVLIST(NUMCOR,5)=J5
  158           CONTINUE
  155         CONTINUE
  153       CONTINUE
  151     CONTINUE
  150   CONTINUE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,152)NUMCOR
  152   FORMAT('AFTER K = 5, NUMCOR = ',I5)
        CALL DPWRST('XXX','BUG ')
        DO 161 I=1,NUMCOR
          WRITE(ICOUT,162)I,(IVLIST(I,J),J=1,5)
  162     FORMAT('I,IVLIST(I,J=1,5) = ',6I8)
          CALL DPWRST('XXX','BUG ')
 161    CONTINUE
      ENDIF
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  SEQUENTIALLY COMPARE THE TENTATIVE CORE        **
!               **  ELEMENTS WITH ALL PREVIOUS ELEMENTS.  IF       **
!               **  ORTHOGONAL, TAG CORE ELEMENT AS ACCEPTABLE,    **
!               **  OTHERWISE TAG AS UNACCEPTABLE.                 **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 210 J1=2,NUMCOR
!
!       INITIALIZE THE TWO VECTORS
!
        ISTEPN='21'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,201)J1
  201     FORMAT('LOOP 210: J1 = ',I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        DO 211 I=1,N
          TEMP1(I)=1.0
  211   CONTINUE
!
!       NOW LOOP THROUGH THE COLUMNS
!
        DO 213 L=1,5
          ICOL=IVLIST(J1,L)
          IF(ICOL.GT.0)THEN
            DO 215 I=1,N
              TEMP1(I)=TEMP1(I)*XMAT(I,ICOL)
  215       CONTINUE
          ENDIF
  213   CONTINUE
!
!       NOW EXTRACT THE SECOND VECTOR
!
        J1M1=J1-1
        EPS=0.001
        DO 220 J2=1,J1M1
          DO 221 I=1,N
            TEMP2(I)=1.0
  221     CONTINUE
          DO 223 L=1,5
            ICOL=IVLIST(J2,L)
            IF(ICOL.GT.0)THEN
              DO 225 I=1,N
                TEMP2(I)=TEMP2(I)*XMAT(I,ICOL)
  225         CONTINUE
            ENDIF
  223     CONTINUE
!
          CALL CORR(TEMP1,TEMP2,N,IWRITE,CZ,IBUGA3,IERROR)
          CZABS=ABS(CZ)
          IF(ABS(CZABS-1.0).LE.EPS)ICTAG(J1)=0
          IF(J1.EQ.1)ICTAG(J1)=1
  220   CONTINUE
  210 CONTINUE
!
!               *****************************************************
!               **  STEP 3--                                       **
!               **  ONLY KEEP ROWS WHERE ICTAG IS 1.               **
!               *****************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICNT2=0
      DO 310 J=1,NUMCOR
        IF(ICTAG(J).EQ.1)THEN
          ICNT2=ICNT2+1
          CORE(ICNT2,1)=REAL(IVLIST(J,1))
          CORE(ICNT2,2)=REAL(IVLIST(J,2))
          CORE(ICNT2,3)=REAL(IVLIST(J,3))
          CORE(ICNT2,4)=REAL(IVLIST(J,4))
          CORE(ICNT2,5)=REAL(IVLIST(J,5))
         ENDIF
  310  CONTINUE
       NUMCOR=ICNT2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NUMCOR
 9012   FORMAT('IERROR,NUMCOR = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NUMCOR
          WRITE(ICOUT,9022)I,(CORE(I,J),J=1,5)
 9022     FORMAT('I,(CORE(I,J),J=1,5) = ',I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCORE
      SUBROUTINE DPCORR(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--FORM
!              1) AUTOCORRELATION PLOT
!              2) CROSS-CORRELATION PLOT
!              3) PARTIAL AUTOCORRELATION PLOT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1990.  TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --FEBRUARY  1990.  PARTIAL AUTOECORRELATION PLOT
!     UPDATED         --OCTOBER   1997.  MOVE SOME DIMENSIONS TO DPCORR
!     UPDATED         --JULY      1999.  ADD IAUTCP PARAMETER
!     UPDATED         --FEBRUARY  2003.  ADD IAUTL0 PARAMETER
!     UPDATED         --JANAURY   2012.  USE DPPARS
!     UPDATED         --JANAURY   2012.  FOLD IN COMOVEMENT PLOT
!     UPDATED         --JANAURY   2012.  SUPPORT FOR "MULTIPLE" AND
!                                        "REPLICATION" OPTIONS
!     UPDATED         --APRIL     2015.  FIX BUG IN CHECKING FOR
!                                        PARTIAL AUTOCORRELATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION TOP(MAXOBV)
      DIMENSION BOTTOM(MAXOBV)
      DIMENSION PCC(MAXOBV)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION ZY1(MAXOBV)
      DIMENSION ZY2(MAXOBV)
      DIMENSION XDESGN(MAXOBV,2)
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),TOP(1))
      EQUIVALENCE (GARBAG(IGARB4),BOTTOM(1))
      EQUIVALENCE (GARBAG(IGARB5),PCC(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB9),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGAR10),XIDTE2(1))
      EQUIVALENCE (GARBAG(JGAR11),XIDTE3(1))
      EQUIVALENCE (GARBAG(JGAR12),ZY1(1))
      EQUIVALENCE (GARBAG(JGAR13),ZY2(1))
      EQUIVALENCE (GARBAG(JGAR14),XDESGN(1,1))
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!CCCC ADD FOLLOWING LINE JULY 1999
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IMULT='OFF'
      IREPL='OFF'
!
      ISUBN1='DPCO'
      ISUBN2='RR  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               **************************************************
!               **  TREAT THE FOLLOWING CASES--                  *
!               **        1) AUTOCORRELATION                     *
!               **        2) CROSS-CORRELATION;                  *
!               **        3) PARTIAL AUTO-CORRELATION;           *
!               **************************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCORR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ***************************************
!               **  STEP 1.1--                       **
!               **  SEARCH FOR AUTOCORRELATION PLOT, **
!               **  PARTIAL CORRELATION, OR          **
!               **  CROSS-CORRELATION.  ALSO LOOK    **
!               **  MULTIPLE OR REPLICATION.         **
!               ***************************************
!
      IF(ICOM.EQ.'MULT')IMULT='ON'
      IF(ICOM.EQ.'REPL')IREPL='ON'
!
      IF(NUMARG.GE.2 .AND.   &
         ICOM.EQ.'AUTO'.AND.IHARG(1).EQ.'CORR'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='AUCO'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND.   &
         ICOM.EQ.'AUTO'.AND.ICOM2.EQ.'CORR'.AND.   &
         IHARG(1).EQ.'PLOT')THEN
        ICASPL='AUCO'
        ILASTC=1
      ELSEIF(NUMARG.GE.3 .AND.ICOM.NE.'PART'.AND.   &
         IHARG(1).EQ.'AUTO'.AND.IHARG(2).EQ.'CORR'.AND.   &
         IHARG(3).EQ.'PLOT')THEN
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
         ICOM.NE.'PART'.AND.   &
         IHARG(1).EQ.'AUTO'.AND.IHARG2(1).EQ.'CORR'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='AUCO'
        ILASTC=2
      ELSEIF(NUMARG.GE.3 .AND.   &
         ICOM.NE.'PART'.AND.   &
         IHARG(1).EQ.'AUTO'.AND.IHARG(2).EQ.'CORR'.AND.   &
         IHARG(3).EQ.'PLOT')THEN
        ICASPL='AUCO'
        ILASTC=3
      ELSEIF(NUMARG.GE.3 .AND.   &
         ICOM.EQ.'PART'.AND.IHARG(1).EQ.'AUTO'.AND.   &
         IHARG(2).EQ.'CORR'.AND.IHARG(3).EQ.'PLOT')THEN
        ICASPL='PACO'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
         ICOM.EQ.'PART'.AND.IHARG(1).EQ.'AUTO'.AND.   &
         IHARG2(1).EQ.'CORR'.AND.IHARG(2).EQ.'PLOT')THEN
        ICASPL='PACO'
        ILASTC=2
      ELSEIF(NUMARG.GE.4 .AND.   &
         IHARG(1).EQ.'PART'.AND.IHARG(2).EQ.'AUTO'.AND.   &
         IHARG(3).EQ.'CORR'.AND.IHARG(4).EQ.'PLOT')THEN
        ICASPL='PACO'
        ILASTC=4
      ELSEIF(NUMARG.GE.3 .AND.   &
         IHARG(1).EQ.'PART'.AND.IHARG(2).EQ.'AUTO'.AND.   &
         IHARG2(2).EQ.'CORR'.AND.IHARG(3).EQ.'PLOT')THEN
        ICASPL='PACO'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
         ICOM.EQ.'CROS'.AND.IHARG(1).EQ.'CORR'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='CRCO'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND.   &
         ICOM.EQ.'CROS'.AND.ICOM2.EQ.'SCOR'.AND.   &
         IHARG(1).EQ.'PLOT')THEN
        ICASPL='CRCO'
        ILASTC=1
      ELSEIF(NUMARG.GE.3 .AND.   &
         IHARG(1).EQ.'CROS'.AND.IHARG(2).EQ.'CORR'.AND.   &
         IHARG(3).EQ.'PLOT')THEN
        ICASPL='CRCO'
        ILASTC=3
      ELSEIF(NUMARG.GE.1 .AND.   &
         IHARG(1).EQ.'CROS'.AND.IHARG2(1).EQ.'SCOR'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='CRCO'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND.   &
         ICOM.EQ.'AUTO'.AND.IHARG(1).EQ.'COMO'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='AUCM'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND.   &
         ICOM.EQ.'AUTO'.AND.ICOM2.EQ.'COMO'.AND.   &
         IHARG(1).EQ.'PLOT')THEN
        ICASPL='AUCM'
        ILASTC=1
      ELSEIF(NUMARG.GE.2 .AND.   &
         IHARG(1).EQ.'AUTO'.AND.IHARG2(1).EQ.'COMO'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='AUCM'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND.   &
         ICOM.EQ.'CROS'.AND.IHARG(1).EQ.'COMO'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='CRCM'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND.   &
         ICOM.EQ.'CROS'.AND.ICOM2.EQ.'SCOM'.AND.   &
         IHARG(1).EQ.'PLOT')THEN
        ICASPL='CRCM'
        ILASTC=1
      ELSEIF(NUMARG.GE.3 .AND.   &
         IHARG(1).EQ.'CROS'.AND.IHARG(2).EQ.'COMO'.AND.   &
         IHARG(3).EQ.'PLOT')THEN
        ICASPL='CRCM'
        ILASTC=3
      ELSEIF(NUMARG.GE.1 .AND.   &
         IHARG(1).EQ.'CROS'.AND.IHARG2(1).EQ.'SCOM'.AND.   &
         IHARG(2).EQ.'PLOT')THEN
        ICASPL='CRCM'
        ILASTC=2
      ELSE
        ICASPL='    '
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN ...CORRELATION/COMOVEMENT PLOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THIS PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ICASPL.NE.'AUCO' .AND. ICASPL.NE.'AUCM')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,107)
  107     FORMAT('      THE "MULTIPLE" OPTION IS ONLY SUPPORTED FOR')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,109)
  109     FORMAT('      AUTOCORRELATION PLOT.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='AUTOCORRELATION PLOT'
      IF(ICASPL.EQ.'PACO')INAME='PARTIAL AUTOCORRELATION PLOT'
      IF(ICASPL.EQ.'CRCO')INAME='CROSS-CORRELATION PLOT'
      IF(ICASPL.EQ.'AUCM')INAME='AUTOCOMOVEMENT PLOT'
      IF(ICASPL.EQ.'CRCM')INAME='CROSS-COMOVEMENT PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      IF(ICASPL.EQ.'AUCO' .OR. ICASPL.EQ.'AUCM' .OR.   &
         ICASPL.EQ.'PACO')THEN
        MINNVA=1
        MAXNVA=1
      ELSE
        MINNVA=2
        MAXNVA=2
      ENDIF
      IF(IREPL.EQ.'ON')THEN
        MINNVA=MINNVA+1
        MAXNVA=MAXNVA+2
      ELSEIF(IMULT.EQ.'ON')THEN
        MINNVA=1
        MAXNVA=MAXSPN
        IFLAGE=0
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      NRESP=0
      NREPL=0
      IF(ICASPL.NE.'AUCO' .OR. ICASPL.EQ.'AUCM' .OR.   &
         ICASPL.EQ.'PACO')THEN
        IF(IREPL.EQ.'OFF' .AND. NUMVAR.GT.1)IMULT='ON'
      ENDIF
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN 1 AND 2;  SUCH WAS NOT THE ',   &
                 'CASE HERE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=1
      ENDIF
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'CORR')THEN
        WRITE(ICOUT,112)ICASPL,IMULT,IREPL
  112   FORMAT('ICASPL,IMULT,IREPL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **********************************************************
!               **  STEP 8--                                            **
!               **  DETERMINE IF THE ANALYST                            **
!               **  HAS SPECIFIED THE NUMBER OF LAGS DESIRED            **
!               **  FOR THE CROSS-CORRELATION PLOT.                     **
!               **  THE LAG SETTING IS DONE BY SEARCHING THE            **
!               **  INTERNAL TABLE FOR THE PARAMETER NAMES              **
!               **  LAGS, LAG, OR NUMLAG                                **
!               **  (WITH THE SEARCH CONDUCTED IN THAT ORDER            **
!               **  AND WITH THE FIRST FIND TERMINATING                 **
!               **  THE SEARCH.)                                        **
!               **  IF FOUND, USE THE SPECIFIED VALUE                   **
!               **  (WHICH MUST BE BETWEEN 1 AND 1000, INCLUSIVE);      **
!               **  IF NOT FOUND, USE THE DEFAULT VALUE                 **
!               **  (USUALLY NS/4) WHICH WILL BE DEFINED                **
!               **  IN THE SUBROUTINE DPCOR2.                           **
!               **********************************************************
!
      ISTEPN='8'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMLAG=0
!
      IH='LAGS'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        GO TO 790
      ENDIF
!
      IH='LAG '
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        IF(IERROR.EQ.'NO')GO TO 790
      ENDIF
!
      IH='NUML'
      IH2='AG  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        NUMLAG=INT(VALUE(ILOCV)+0.5)
        IF(IERROR.EQ.'NO')GO TO 790
      ENDIF
!
  790 CONTINUE
!
!               ********************************************
!               **  STEP 6--                              **
!               **  GENERATE THE CORRELATION    PLOTS FOR **
!               **  THE VARIOUS CASES.                    **
!               ********************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
        ISTEPN='6'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,601)NRESP,NREPL
  601   FORMAT('NRESP,NREPL = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NREPL.EQ.0)THEN
        ISTEPN='8A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NPLOTP=0
        ISKIP=2
        IF(ICASPL.EQ.'AUCO' .OR. ICASPL.EQ.'AUCM' .OR.   &
           ICASPL.EQ.'PACO')ISKIP=1
        DO 810 IRESP=1,NRESP,ISKIP
          NCURVE=IRESP
!
          IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=2
          IF(ICASPL.EQ.'AUCO' .OR. ICASPL.EQ.'AUCM' .OR.   &
             ICASPL.EQ.'PACO')NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,Y2,Y2,NS,NS,NS,ICASE,   &
                      IBUGG3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************************
!               **  STEP 8B--                                      **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!               *****************************************************
!
         CALL DPCOR2(Y1,Y2,NS,NCURVE,ICASPL,NUMLAG,MAXN,   &
                     IAUTCP,IAUTL0,TEMP1,TEMP2,   &
                     Y,X,D,TOP,BOTTOM,PCC,NPLOTP,NPLOTV,   &
                     IBUGG3,ISUBRO,IERROR)
!
  810   CONTINUE
!
!               *****************************************************
!               **  STEP 9A--                                      **
!               **  CASE 3: ONE OR TWO  REPLICATION VARIABLES.     **
!               **          FOR THIS CASE, THE NUMBER OF RESPONSE  **
!               **          VARIABLES MUST BE EXACTLY 1.           **
!               *****************************************************
!
      ELSEIF(NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y1
!
          IJ=MAXN*(ICOLR(1)-1)+I
          IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
          ICOLC=1
!
!         SECOND RESPONSE VARIABLE IN Y2
!
          IF(ICASPL.NE.'AUCO' .AND. ICASPL.NE.'AUCM' .AND.   &
             ICASPL.NE.'PACO')THEN
            IJ=MAXN*(ICOLR(2)-1)+I
            IF(ICOLR(2).LE.MAXCOL)Y2(J)=V(IJ)
            IF(ICOLR(2).EQ.MAXCP1)Y2(J)=PRED(I)
            IF(ICOLR(2).EQ.MAXCP2)Y2(J)=RES(I)
            IF(ICOLR(2).EQ.MAXCP3)Y2(J)=YPLOT(I)
            IF(ICOLR(2).EQ.MAXCP4)Y2(J)=XPLOT(I)
            IF(ICOLR(2).EQ.MAXCP5)Y2(J)=X2PLOT(I)
            IF(ICOLR(2).EQ.MAXCP6)Y2(J)=TAGPLO(I)
            ICOLC=2
          ENDIF
!
          DO 920 IR=1,MIN(NREPL,2)
            ICOLC=ICOLC+1
            ICOLT=ICOLR(ICOLC)
            IJ=MAXN*(ICOLT-1)+I
            IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
            IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
            IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
            IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
            IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
            IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
            IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920     CONTINUE
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='9B'
        IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,931)
  931     FORMAT('***** FROM THE MIDDLE  OF DPCORR--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,932)ICASPL,NUMVAR,NLOCAL
  932     FORMAT('ICASPL,NUMVAR,NLOCAL = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 935 I=1,NLOCAL
              WRITE(ICOUT,936)I,Y1(I),XDESGN(I,1),XDESGN(I,2)
  936         FORMAT('I,Y1(I),XDESGN(I,1),XDESGN(I,2) = ',I8,3F12.5)
              CALL DPWRST('XXX','BUG ')
  935       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPFRE5(XDESGN(1,1),XDESGN(1,2),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,   &
                   TEMP1,TEMP2,   &
                   NUMSE1,NUMSE2,   &
                   IBUGG3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                ZY1(K)=Y1(I)
                ZY2(K)=Y2(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCOR2(ZY1,ZY2,NTEMP,NCURVE,ICASPL,NUMLAG,MAXN,   &
                          IAUTCP,IAUTL0,TEMP1,TEMP2,   &
                          Y,X,D,TOP,BOTTOM,PCC,NPLOTP,NPLOTV,   &
                          IBUGG3,ISUBRO,IERROR)
            ENDIF
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                ZY1(K)=Y1(I)
                ZY2(K)=Y2(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCOR2(ZY1,ZY2,NTEMP,NCURVE,ICASPL,NUMLAG,MAXN,   &
                          IAUTCP,IAUTL0,TEMP1,TEMP2,   &
                          Y,X,D,TOP,BOTTOM,PCC,NPLOTP,NPLOTV,   &
                          IBUGG3,ISUBRO,IERROR)
            ENDIF
 1220     CONTINUE
 1210     CONTINUE
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CORR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCORR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,NUMLAG,MAXN
 9012   FORMAT('IFOUND,IERROR,NUMLAG,MAXN = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',3I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.LE.0)THEN
          DO 9015 I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016       FORMAT('I,Y(I),X(I),D(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCORR
      SUBROUTINE DPCPLO(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        ICAPSW,ICAPTY,IFORSW,                  &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              A COMMUTABILITY PLOT.  THERE ARE TWO PAIRED MEASUREMENT
!              PROCESSES.  THE MEASUREMENTS ARE MADE ON BOTH CLINICAL
!              SAMPLES AND ON REFERENCE MATERIALS.
!
!              FOR THE CLINICAL SAMPLES, PLOT Y(I) - X(I) VERSUS
!              (Y(I) + X(I))/2 (ESSENTIALLY A BLAND-ALTMAN PLOT).
!              THE AVERAGE OF THE REPLICATES FOR THE CLINICAL SAMPLES
!              ARE USED.
!
!              FOR THE REFERENCE SAMPLES, ...
!
!     REFERENCES--NILSSON, et. al. (2018), "IFCC Working Group Recommendations
!                 for Assessing Commutability Part 2: Using the
!                 Difference in Bias Between a Reference Material and
!                 Clinical Samples," Clinical Chemistry, 64(3),
!                 pp. 455-464.
!     EXAMPLE--COMMUTABILITY PLOT XCS YCS CSID XRM YRM RMID POSID
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2025/04
!     ORIGINAL VERSION--APRIL     2025 .
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN0
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=20)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      DIMENSION CSX(MAXOBV)
      DIMENSION CSY(MAXOBV)
      DIMENSION CSID(MAXOBV)
      DIMENSION CSIDSORT(MAXOBV)
      DIMENSION RMX(MAXOBV)
      DIMENSION RMY(MAXOBV)
      DIMENSION RMID(MAXOBV)
      DIMENSION POSID(MAXOBV)
      DIMENSION B(MAXOBV)
      DIMENSION BAVE(MAXOBV)
      DIMENSION BRM(MAXOBV)
      DIMENSION BRMAVG(MAXOBV)
      DIMENSION DRM(MAXOBV)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION RMDIST(MAXOBV)
      DIMENSION POSDIST(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION TEMP5(MAXOBV)
      DIMENSION TEMP6(MAXOBV)
      DIMENSION TEMP7(MAXOBV)
      DIMENSION TEMP8(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),CSX(1))
      EQUIVALENCE (GARBAG(IGARB2),CSY(1))
      EQUIVALENCE (GARBAG(IGARB3),CSID(1))
      EQUIVALENCE (GARBAG(IGARB4),RMX(1))
      EQUIVALENCE (GARBAG(IGARB5),RMY(1))
      EQUIVALENCE (GARBAG(IGARB6),RMID(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB9),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGAR10),B(1))
      EQUIVALENCE (GARBAG(JGAR11),BAVE(1))
      EQUIVALENCE (GARBAG(JGAR12),TEMP3(1))
      EQUIVALENCE (GARBAG(JGAR13),TEMP4(1))
      EQUIVALENCE (GARBAG(JGAR14),POSID(1))
      EQUIVALENCE (GARBAG(JGAR15),TEMP5(1))
      EQUIVALENCE (GARBAG(JGAR16),TEMP6(1))
      EQUIVALENCE (GARBAG(JGAR17),TEMP7(1))
      EQUIVALENCE (GARBAG(JGAR18),BRM(1))
      EQUIVALENCE (GARBAG(JGAR19),DRM(1))
      EQUIVALENCE (GARBAG(JGAR20),CSIDSORT(1))
      EQUIVALENCE (GARBAG(IGAR11),BRMAVG(1))
      EQUIVALENCE (GARBAG(IGAR12),RMDIST(1))
      EQUIVALENCE (GARBAG(IGAR13),POSDIST(1))
      EQUIVALENCE (GARBAG(IGAR14),TEMP8(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCP'
      ISUBN2='LO  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCPLO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS,MAXN,MAXNPP
   52   FORMAT('NPLOTV,NPLOTP,NS,MAXN,MAXNPP = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2,IFOUND,IERROR
   53   FORMAT('ICASPL,IAND1,IAND2,IFOUND,IERROR = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IANGLU,IBUGG2,IBUGG3,IBUGQ,ISUBRO
   54   FORMAT('IANGLU,IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************
!               **  TREAT THE COMMUTABILITY PLOT    CASE **
!               *******************************************
!
!               ***************************
!               **  STEP 11--            **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='11'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'COMM' .AND. IHARG(1).EQ.'PLOT')THEN
        ICASPL='CPLO'
        ILASTC=1
      ELSEIF(ICOM.EQ.'COMM' .AND. IHARG(1).EQ.'DIFF' .AND.     &
             IHARG(2).EQ.'PLOT')THEN
        ICASPL='CDPL'
        ILASTC=2
      ELSE
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COMMUTABILITY PLOT'
      MAXNA=100
      MINN2=2
      IFLAGE=19
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNA=7
      MINNVA=7
      MAXNVA=7
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,                                   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,       &
                  IVARN1,IVARN2,IVARTY,PVAR,                   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,      &
                  MINNVA,MAXNVA,                               &
                  IFLAGM,IFLAGP,                               &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',         &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      NUMVA2=3
      ICOL=1
      ICASE='VARI'
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,         &
                  INAME,IVARN1,IVARN2,IVARTY,                &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,          &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,               &
                  MAXCP4,MAXCP5,MAXCP6,                      &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,      &
                  CSX,CSY,CSID,NCS,NTEMP,NTEMP,ICASE,        &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NUMVA2=3
      ICOL=4
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,         &
                  INAME,IVARN1,IVARN2,IVARTY,                &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,          &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,               &
                  MAXCP4,MAXCP5,MAXCP6,                      &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,      &
                  RMX,RMY,RMID,NREF,NTEMP,NTEMP,ICASE,       &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      NUMVA2=1
      ICOL=7
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,         &
                  INAME,IVARN1,IVARN2,IVARTY,                &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,          &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,               &
                  MAXCP4,MAXCP5,MAXCP6,                      &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,      &
                  POSID,POSID,POSID,NTEMP,NTEMP,NTEMP,ICASE, &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ****************************************************
!               **  STEP 41--                                      *
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS          *
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR    *
!               **   THE PLOT.                                     *
!               **  FORM THE CURVE DESIGNATION VARIABLE D(.)  .    *
!               **  THIS WILL BE BOTH ONES FOR BOTH CASES          *
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  *
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  *
!               ****************************************************
!
      ISTEPN='41'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCPL2(CSX,CSY,CSID,NCS,RMX,RMY,RMID,POSID,NREF,     &
                  XIDTEM,TEMP1,TEMP2,TEMP3,TEMP4,               &
                  TEMP5,TEMP6,TEMP7,TEMP8,                      &
                  CSIDSORT,RMDIST,POSDIST,                      &
                  B,BAVE,BCS,SB,BRM,BRMAVG,UBRM,DRM,UDRM,       &
                  ICAPSW,ICAPTY,IFORSW,IVARN1,IVARN2,           &
                  Y,X,D,NPLOTP,NPLOTV,                          &
                  ICASPL,IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO To 9000
!
      IH='BCS '
      IH2='    '
      VALUE0=BCS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,                     &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='SB  '
      IH2='    '
      VALUE0=SB
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,                     &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='UBRM'
      IH2='    '
      VALUE0=UBRM
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,                     &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGG3,IERROR)
!
      IH='UDRM'
      IH2='    '
      VALUE0=UDRM
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,                     &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGG3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CPLO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCPLO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NUMVAR,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NUMVAR,NS,ICASPL,IAND1,IAND2 = ',   &
               4I8,2X,2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ICASPL,MAXN,NUMVAR
 9014   FORMAT('ICASPL,MAXN,NUMVAR = ',A4,I8,I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9020 I=1,NPLOTP
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCPLO
      SUBROUTINE DPCPL2(CSX,CSY,CSID,NCS,RMX,RMY,RMID,POSID,NREF,     &
                        XIDTEM,TEMP1,TEMP2,TEMP3,TEMP4,               &
                        TEMP5,TEMP6,TEMP7,TEMP8,                      &
                        CSIDSORT,RMDIST,POSDIST,                      &
                        B,BAVE,BCS,SB,BRM,BRMAVG,UBRM,DRM,UDRM,       &
                        ICAPSW,ICAPTY,IFORSW,IVARN1,IVARN2,           &
                        Y2,X2,D2,NPLOTP,NPLOTV,                       &
                        ICASPL,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              A COMMUTABILITY PLOT.  THERE ARE TWO PAIRED MEASUREMENT
!              PROCESSES.  THE MEASUREMENTS ARE MADE ON BOTH CLINICAL
!              SAMPLES AND ON REFERENCE MATERIALS.
!
!              FOR THE CLINICAL SAMPLES, PLOT Y(I) - X(I) VERSUS
!              (Y(I) + X(I))/2 (ESSENTIALLY A BLAND-ALTMAN PLOT).
!              THE AVERAGE OF THE REPLICATES FOR THE CLINICAL SAMPLES
!              ARE USED.
!
!              FOR THE REFERENCE SAMPLES, ...
!
!     REFERENCES--NILSSON, et. al. (2018), "IFCC Working Group Recommendations
!                 for Assessing Commutability Part 2: Using the
!                 Difference in Bias Between a Reference Material and
!                 Clinical Samples," Clinical Chemistry, 64(3),
!                 pp. 455-464.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/07
!     ORIGINAL VERSION--JULY      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARN1(*)
      CHARACTER*4 IVARN2(*)
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IWRITE
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      DIMENSION CSX(*)
      DIMENSION CSY(*)
      DIMENSION CSID(*)
      DIMENSION CSIDSORT(*)
      DIMENSION RMX(*)
      DIMENSION RMY(*)
      DIMENSION RMID(*)
      DIMENSION RMDIST(*)
      DIMENSION POSID(*)
      DIMENSION POSDIST(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION TEMP6(*)
      DIMENSION TEMP7(*)
      DIMENSION TEMP8(*)
      DIMENSION B(*)
      DIMENSION BAVE(*)
      DIMENSION BRM(*)
      DIMENSION BRMAVG(*)
      DIMENSION DRM(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER(MAXLIN=3)
      PARAMETER(MAXROW=50)
      PARAMETER(MAXCOL=5)
      CHARACTER*4  ALIGN(MAXCOL)
      CHARACTER*4  VALIGN(MAXCOL)
      INTEGER      IDIGIT(MAXCOL)
      INTEGER      NTOT(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      CHARACTER*55 ITEXT(MAXROW)
      CHARACTER*60 ITITL9
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITLE
      CHARACTER*40 ITITL2(MAXLIN,MAXCOL)
      CHARACTER*15 IVALUE(MAXROW,MAXCOL)
      CHARACTER*4  ITYPCO(MAXCOL)
      INTEGER      NCVALU(MAXROW,MAXCOL)
      INTEGER      ROWSEP(MAXROW)
      INTEGER      NCTIT2(MAXLIN,MAXCOL)
      INTEGER      IWHTML(MAXCOL)
      INTEGER      IWRTF(MAXCOL)
      REAL         AMAT(MAXROW,MAXCOL)
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      REAL QCV01(21)
      REAL QCV1(21)
      REAL QCV5(21)
!
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      INCLUDE 'DPCOP2.INC'
!
      DATA QCV01  /-99.0, -99.0, -99.0,                  &
                    0.295, 0.208, 0.182, 0.185, 0.202,    &
                    0.221, 0.241, 0.260, 0.278, 0.295,    &
                    0.311, 0.327, 0.341, 0.355, 0.368,    &
                    0.381, 0.393, 0.393/
      DATA  QCV1   /-99.0, -99.0, -99.0,                  &
                    0.313, 0.269, 0.281, 0.307, 0.331,    &
                    0.354, 0.376, 0.396, 0.414, 0.431,    &
                    0.447, 0.461, 0.475, 0.487, 0.499,    &
                    0.510, 0.520, 0.520/
      DATA  QCV5   /-99.0, -99.0, -99.0,                  &
                    0.390, 0.410, 0.445, 0.468, 0.491,    &
                    0.512, 0.531, 0.548, 0.564, 0.578,    &
                    0.591, 0.603, 0.614, 0.624, 0.633,    &
                    0.642, 0.650, 0.658/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCP'
      ISUBN2='L2  '
      IERROR='NO'
      IWRITE='OFF'
!
      NCSDIST=0
      NRDIST=0
      NPLOTP=0
      IDFCS=0
      IDFRM=0
      SUM1=0.0
      SUM2=0.0
      SUM3=0.0
      SUM4=0.0
      SUM5=0.0
      PVALX=CPUMIN
      PVALX=CPUMIN
      SDPOSX=0.0
      SDPOSY=0.0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCPL2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG3,ISUBRO,ICAPSW,ICAPTY,IFORSW,NCS,NREF,PSTAMV
   52   FORMAT('IBUGG3,ISUBRO,ICAPSW,ICAPTY,IFORSW,NCS,NREF,PSTAMV = ', &
               5(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO I=1,NCS
           WRITE(ICOUT,72)I,CSX(I),CSY(I),CSID(I)
   72      FORMAT('I,CSX(I),CSY(I),CSID(I) = ',I8,3G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
        DO I=1,NREF
           WRITE(ICOUT,82)I,RMX(I),RMY(I),RMID(I),POSID(I)
   82      FORMAT('I,RMX(I),RMY(I),RMID(I),POSID(I) = ',I8,4G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      NUMDIG=4
      IF(IFORSW.EQ.'1')NUMDIG=2
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=7
      IF(IFORSW.EQ.'9')NUMDIG=7
      IF(IFORSW.EQ.'0')NUMDIG=7
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NCS.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN COMMUTABILITY PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1112)
 1112   FORMAT('      THE NUMBER OF CLINICAL SAMPLE MEAUREMENTS MUST ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1113)
 1113   FORMAT('      BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1114)NCS
 1114   FORMAT('      THE NUMBER OF CLINICAL SAMPLE MEASUREMENTS = ',I6)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(ICPLLN.EQ.'ON')THEN
        DO II=1,NCS
           IF(CSX(II).LE.0.0 .AND. CSX(II).NE.PSTAMV)THEN
             WRITE(ICOUT,1111)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1122)II
 1122        FORMAT('      ROW ',I8,' OF THE CLINICAL SAMPLE FOR THE')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1124)II
 1124        FORMAT('      FIRST MEASUREMENT PROCESS IS NON-POSITIVE.')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1126)CSX(II)
 1126        FORMAT('      IT HAS THE VALUE:   ',G15.7)
             CALL DPWRST('XXX','BUG ')
             IERROR='YES'
             GO TO 9000
           ENDIF
           IF(CSY(II).LE.0.0 .AND. CSY(II).NE.PSTAMV)THEN
             WRITE(ICOUT,1111)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1122)II
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1136)
 1136        FORMAT('      SECOND MEASUREMENT PROCESS IS NON-POSITIVE.')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1126)CSY(II)
             CALL DPWRST('XXX','BUG ')
             IERROR='YES'
             GO TO 9000
           ENDIF
        ENDDO
!
        DO II=1,NREF
           IF(RMX(II).LE.0.0 .AND. RMX(II).NE.PSTAMV)THEN
             WRITE(ICOUT,1111)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1142)II
 1142        FORMAT('      ROW ',I8,' OF THE REFERENCE SAMPLE FOR THE')
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1124)II
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1146)RMX(II)
 1146        FORMAT('      IT HAS THE VALUE:   ',G15.7)
             CALL DPWRST('XXX','BUG ')
             IERROR='YES'
             GO TO 9000
           ENDIF
           IF(RMY(II).LE.0.0 .AND. RMY(II).NE.PSTAMV)THEN
             WRITE(ICOUT,1111)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1142)II
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1136)
             CALL DPWRST('XXX','BUG ')
             WRITE(ICOUT,1146)RMY(II)
             CALL DPWRST('XXX','BUG ')
             IERROR='YES'
             GO TO 9000
           ENDIF
        ENDDO
      ENDIF
!
!               ****************************************************
!               **  STEP 21--COMPUTE THE DIFFERENCES AND THE MEAN **
!               **           FOR THE CLINICAL SAMPLES, BUT BASE   **
!               **           ON THE MEAN OF EACH CLINICAL SAMPLE. **
!               ****************************************************
!
      ISTEPN='21'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(CSID,NCS,IWRITE,XIDTEM,NCSDIST,IBUGG3,IERROR)
      IF(IERROR.EQ.'YES') GO TO 9000
      CALL SORT(XIDTEM,NCSDIST,XIDTEM)
      CALL DISTIN(POSID,NREF,IWRITE,POSDIST,NPOSDIST,IBUGG3,IERROR)
      IF(IERROR.EQ.'YES') GO TO 9000
      CALL SORT(POSDIST,NPOSDIST,POSDIST)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,1151)NCSDIST,NPOSDIST
 1151   FORMAT('NCSDIST,NPOSDIST = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO II=1,NCSDIST
           WRITE(ICOUT,1153)II,XIDTEM(II)
 1153      FORMAT('II,XIDTEM(II) = ',I8,G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
        DO II=1,NPOSDIST
           WRITE(ICOUT,1155)II,POSDIST(II)
 1155      FORMAT('II,POSDIST(II) = ',I8,G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      NMAX=0
      SUM1=0.0
      SUM2=0.0
      SUM3=0.0
      SUM4=0.0
      IDFX=0
      IDFY=0
      AVEMIN=CPUMAX
      AVEMAX=CPUMIN
      DO JJ=1,NCSDIST
         HOLD=XIDTEM(JJ)
         IF(ICPLMV.EQ.'ON')THEN
           KX=0
           KY=0
           DO II=1,NCS
              IF(CSID(II).EQ.HOLD)THEN
                IF(CSX(II).NE.PSTAMV)THEN
                  KX=KX+1
                  TEMP1(KX)=CSX(II)
                  IF(ICPLLN.EQ.'ON')TEMP3(KX)=LOG(CSX(II))
                ENDIF
                IF(CSY(II).NE.PSTAMV)THEN
                  KY=KY+1
                  TEMP2(KY)=CSY(II)
                  IF(ICPLLN.EQ.'ON')TEMP4(KY)=LOG(CSY(II))
                ENDIF
              ENDIF
           ENDDO
         ELSE
           K=0
           DO II=1,NCS
              IF(CSID(II).EQ.HOLD)THEN
                K=K+1
                TEMP1(K)=CSX(II)
                TEMP2(K)=CSY(II)
                IF(ICPLLN.EQ.'ON')THEN
                  TEMP3(K)=LOG(CSX(II))
                  TEMP4(K)=LOG(CSY(II))
                ENDIF
              ENDIF
           ENDDO
           KX=K
           KY=K
         ENDIF
!
         IF(KX.GT.NMAX)NMAX=KX
         IF(KY.GT.NMAX)NMAX=KY
         IDFX=IDFX + KX - 1
         IDFY=IDFY + KY - 1
!
         CALL MEAN(TEMP1,KX,IWRITE,XIRAW,IBUGG3,IERROR)
         CALL MEAN(TEMP2,KY,IWRITE,YIRAW,IBUGG3,IERROR)
         IF(ICPLLN.EQ.'ON')THEN
           CALL MEAN(TEMP3,KX,IWRITE,XI,IBUGG3,IERROR)
           CALL MEAN(TEMP4,KY,IWRITE,YI,IBUGG3,IERROR)
           CALL SD(TEMP3,KX,IWRITE,SDXI,IBUGG3,IERROR)
           CALL SD(TEMP4,KY,IWRITE,SDYI,IBUGG3,IERROR)
         ELSE
           XI=XIRAW
           YI=YIRAW
           CALL SD(TEMP1,KX,IWRITE,SDXI,IBUGG3,IERROR)
           CALL SD(TEMP2,KY,IWRITE,SDYI,IBUGG3,IERROR)
         ENDIF
         DIFF=YI-XI
!
         IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
           WRITE(ICOUT,2003)JJ,KX,KY,NMAX,IDFX,IDFY
 2003      FORMAT('JJ,KX,KY,NMAX,IDFX,IDFY = ',6I8)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,2004)XI,SDXI,YI,SDYI,DIFF
 2004      FORMAT('XI,SDXI,YI,SDYI,DIFF = ',5G15.7)
           CALL DPWRST('XXX','BUG ')
         ENDIF
!
         IF(ICPLRM.EQ.'ON')THEN
           IF(ICPLLN.EQ.'ON')THEN
             AVE=XIRAW
           ELSE
             AVE=XI
           ENDIF
         ELSE
           IF(ICPLLN.EQ.'ON')THEN
             AVE=(XIRAW+YIRAW)/2.0
           ELSE
             AVE=(XI+YI)/2.0
           ENDIF
         ENDIF
         B(JJ)=DIFF
         BAVE(JJ)=AVE
         IF(AVE.LT.AVEMIN)AVEMIN=AVE
         IF(AVE.GT.AVEMAX)AVEMAX=AVE
         IF(ICASPL.EQ.'CDPL')THEN
           NPLOTP=NPLOTP+1
           Y2(NPLOTP)=DIFF
           X2(NPLOTP)=AVE
           D2(NPLOTP)=1.0
         ENDIF
         SUM1=SUM1+DIFF
         SUM2=SUM2+SDXI**2
         SUM3=SUM3+SDYI**2
!
         IDFCS=NCSDIST
      ENDDO
      BCS=SUM1/REAL(NCSDIST)
!
      NDIFF=NCSDIST
      CALL SORTC(BAVE,B,NCSDIST,TEMP1,TEMP2)
      DO II=1,NCSDIST
         B(II)=TEMP2(II)
      ENDDO
      CALL SORTC(BAVE,CSID,NCSDIST,TEMP1,CSIDSORT)
      DO II=1,NCSDIST
         BAVE(II)=TEMP1(II)
      ENDDO
      CALL SD(B,NCSDIST,IWRITE,SB,IBUGG3,IERROR)
      SUM1=0.0
      DO KK=1,NCSDIST-1
         AVAL1=B(KK+1)
         AVAL2=B(KK)
         SUM1=SUM1 + (AVAL1 - AVAL2)**2
      ENDDO
      AVAL3=1.0/(2.0*REAL(NCSDIST-1))
      SMSSD=SQRT(AVAL3*SUM1)
      STATNO=0.0
      IF(SB.GT.0.0)STATNO=(SMSSD/SB)**2
      IFLAGN=0
      IF(NCSDIST.GE.22)THEN
        ALOC=1.0
        ANDIFF=REAL(NCSDIST)
        TERM1=1.0/(ANDIFF+1.0)
        TERM2=1.0 - (1.0/(ANDIFF-1.0))
        ASCALE=SQRT(TERM1*TERM2)
        CALL NORPPF(0.05,APPF)
        ACVNO5=ALOC + ASCALE*APPF
        CALL NORPPF(0.01,APPF)
        ACVNO1=ALOC + ASCALE*APPF
        CALL NORPPF(0.01,APPF)
        ACVNO1=ALOC + ASCALE*APPF
        CALL NORPPF(0.001,APPF)
        ACVNO01=ALOC + ASCALE*APPF
        IF(STATNO.LT.ACVNO5)IFLAGN=1
        ARG1=(STATNO-ALOC)/ASCALE
        CALL NORCDF(ARG1,ACDF)
        PVALUT=1.0-ACDF
      ELSE
        ALOC=0.0
        ASCALE=1.0
        ACVNO5=QCV5(NCSDIST)
        ACVNO1=QCV1(NCSDIST)
        ACVNO01=QCV01(NCSDIST)
        IF(STATNO.LT.ACVNO5)IFLAGN=1
        ACDF=-99.0
        PVALUT=-99.0
      ENDIF
!
      SDXCS=SQRT(SUM2/REAL(NCSDIST))
      SDYCS=SQRT(SUM3/REAL(NCSDIST))
      IF(ICASPL.EQ.'CDPL')THEN
        NPLOTP=NPLOTP+1
        Y2(NPLOTP)=BCS
        X2(NPLOTP)=AVEMIN
        D2(NPLOTP)=2.0
        NPLOTP=NPLOTP+1
        Y2(NPLOTP)=BCS
        X2(NPLOTP)=AVEMAX
        D2(NPLOTP)=2.0
      ENDIF
      ITAG=2
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,2101)SMSSD,BCS,SDXCS,SDYCS,AVEMIN,AVEMAX
 2101   FORMAT('SMSSD,BCS,SDXCS,SDYCS,AVEMIN,AVEMAX = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2103)ALOC,ASCALE,ANDIFF,ACDF,PVAL2T
 2103   FORMAT('ALOC,ASCALE,ANDIFF,ACDF,PVAL2T = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        DO II=1,NCSDIST
          WRITE(ICOUT,2105)II,B(II),BAVE(II)
 2105     FORMAT('II,B(II),BAVE(II) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      ISTEPN='2.2'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=1
      IFLG31=1
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,       &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      WRITE(IOUNI1,2001)
      WRITE(IOUNI1,2002)
      WRITE(IOUNI2,2006)
      WRITE(IOUNI2,2007)
      WRITE(IOUNI3,2008)ICPLQV
      WRITE(IOUNI3,2009)
 2001 FORMAT('REFERENCE MATERIAL DIFFERENCES')
 2002 FORMAT('   REFERENCE ID      DIFFERENCE')
 2006 FORMAT('BRM (BIAS OF THE REFERENCE MATERIAL) BY POSITION')
 2007 FORMAT('   RM ID ',' REFERENCE MEAN',12X,'BRM',12X,'DRM')
 2008 FORMAT('BIAS AND MOVING AVERAGE OF THE BIAS (q = ',I5,')')
 2009 FORMAT('CLINICAL SAMPLE ',8X,'BAVE(I)',11X,'B(I)',' MOVING AVERAGE')
!
      NBIAS=0
      DO JJ=1,NREF
         IF(ICPLLN.EQ.'ON')THEN
           IF(RMY(JJ).NE.PSTAMV .AND. RMX(JJ).NE.PSTAMV)THEN
             NBIAS=NBIAS+1
             AVAL=LOG(RMY(JJ)) - LOG(RMX(JJ))
             WRITE(IOUNI1,'(I15,E15.7)')INT(RMID(JJ)+0.1),AVAL
           ENDIF
         ELSE
           IF(RMY(JJ).NE.PSTAMV .AND. RMX(JJ).NE.PSTAMV)THEN
             NBIAS=NBIAS+1
             AVAL=RMY(JJ) - RMX(JJ)
             WRITE(IOUNI1,'(I15,E15.7)')INT(RMID(JJ)+0.1),AVAL
           ENDIF
         ENDIF
         IF(ICPLRM.EQ.'ON')THEN
           AVET=RMX(JJ)
         ELSE
           AVET=(RMY(JJ)+RMX(JJ))/2.0
         ENDIF
         IF(AVET.LT.AVEMIN)AVEMIN=AVET
         IF(AVET.GT.AVEMAX)AVEMAX=AVET
      ENDDO
!
      IVAL1=MOD(ICPLQV,2)
      IF(IVAL1.EQ.1)THEN
        IBEFORE=ICPLQV/2
        IAFTER=IBEFORE
      ELSE
        IBEFORE=ICPLQV/2
        IAFTER=IBEFORE-1
      ENDIF
!
      DO JJ=1,NCSDIST
         IF(ICPLQV.LE.1)THEN
           AMOVAVG=B(JJ)
         ELSE
!
           IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
             WRITE(ICOUT,2018)JJ,IBEFORE,IAFTER
 2018        FORMAT('JJ,IBEFORE,IAFTER = ',3I8)
             CALL DPWRST('XXX','BUG ')
           ENDIF
!
           IF(JJ.LE.IBEFORE .OR. JJ.GE.(NCSDIST-IAFTER))THEN
             AMOVAVG=PSTAMV
           ELSE
              ISTART=JJ-IBEFORE+1
              ISTOP=JJ+IAFTER
              AMOVAVG=SUM(B(ISTART:ISTOP))/REAL(ICPLQV)
!
              IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
                WRITE(ICOUT,2019)ISTART,ISTOP,AMOVAVG
 2019           FORMAT('ISTART,ISTOP,AMOVAVG = ',2I8,G15.7)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
           ENDIF
         ENDIF
         WRITE(IOUNI3,'(I15,3E15.7)')INT(CSIDSORT(JJ)),BAVE(JJ),B(JJ),AMOVAVG
      ENDDO
!
      ISTEPN='2.1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,2011)SUM1,SUM2,SUM3,IDFX,IDFY
 2011   FORMAT('SUM1,SUM2,SUM3,IDFX,IDFY = ',3G15.7,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2012)IBEFORE,IAFTER
 2012   FORMAT('IBEFORE,IAFTER = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2013)
 2013   FORMAT('BEFORE SORT DIFFERENCES')
        CALL DPWRST('XXX','BUG ')
        DO II=1,NCSDIST
           WRITE(ICOUT,2015)II,B(II),BAVE(II)
 2015      FORMAT('II,B(II),BAVE(II) = ',I8,2G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      IF(NREF.GE.1)THEN
         CALL DISTIN(RMID,NREF,IWRITE,RMDIST,NRDIST,IBUGG3,IERROR)
         IF(IERROR.EQ.'YES') GO TO 9000
         CALL SORT(RMDIST,NRDIST,RMDIST)
!
         ITAG=ITAG+1
         SUM4=0.0
         SUM5=0.0
         SUM6=0.0
         SUM7=0.0
         SUM9=0.0
         SUM10=0.0
         DO JJ=1,NRDIST
            HOLD=RMDIST(JJ)
            KX=0
            KY=0
            K=0
            IF(ICPLMV.EQ.'ON')THEN
              DO II=1,NREF
                 IF(RMID(II).EQ.HOLD)THEN
                   IF(RMX(II).NE.PSTAMV)THEN
                     KX=KX+1
                     TEMP1(KX)=RMX(II)
                     IF(ICPLLN.EQ.'ON')TEMP3(KX)=LOG(RMX(II))
                     TEMP7(KX)=POSID(II)
                   ENDIF
                   IF(RMY(II).NE.PSTAMV)THEN
                     KY=KY+1
                     TEMP2(KY)=RMY(II)
                     IF(ICPLLN.EQ.'ON')TEMP4(KY)=LOG(RMY(II))
                     TEMP8(KY)=POSID(II)
                   ENDIF
                 ENDIF
              ENDDO
            ELSE
              DO II=1,NREF
                 IF(RMID(II).EQ.HOLD)THEN
                   K=K+1
                   TEMP1(K)=RMX(II)
                   TEMP2(K)=RMY(II)
                   TEMP7(K)=POSID(II)
                   TEMP8(K)=POSID(II)
                   IF(ICPLLN.EQ.'ON')THEN
                     TEMP3(K)=LOG(RMX(II))
                     TEMP4(K)=LOG(RMY(II))
                   ENDIF
                 ENDIF
              ENDDO
              KX=K
              KY=K
            ENDIF
!
            IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
              WRITE(ICOUT,2176)JJ,KX,KY
 2176         FORMAT('JJ,KX,KY = ',3I6)
              CALL DPWRST('XXX','BUG ')
              DO LL=1,MAX(KX,KY)
                WRITE(ICOUT,2178)LL,TEMP1(LL),TEMP2(LL),TEMP3(LL),     &
                                 TEMP4(LL),TEMP7(LL)
 2178           FORMAT('LL,TEMP1(LL),TEMP2(LL),TEMP3(LL),TEMP4(LL),',  &
                       'TEMP7(LL) = ',I6,5G15.7)
                CALL DPWRST('XXX','BUG ')
              ENDDO
            ENDIF
!
!           COMPUTE S(pos-mean(x)) and S(pos-mean(y))
!
            ICNT3=0
            ICNT4=0
            DO LL=1,NPOSDIST
               HOLD2=POSDIST(LL)
               ICNT2=0
               SUM8=0.0
               DO II=1,KX
                  IF(TEMP7(II).EQ.HOLD2)THEN
                    ICNT2=ICNT2+1
                    IF(ICPLLN.EQ.'ON')THEN
                      SUM8=SUM8+TEMP3(II)
                    ELSE
                      SUM8=SUM8+TEMP1(II)
                    ENDIF
                 ENDIF
               ENDDO
               IF(ICNT2.GE.1)THEN
                 ICNT3=ICNT3+1
                 TEMP6(ICNT3)=SUM8/REAL(ICNT2)
               ENDIF
!
              IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
                WRITE(ICOUT,2196)LL,HOLD2,ICNT2,ICNT3,SUM8,TEMP6(ICNT3)
 2196           FORMAT(6X,'LL,HOLD2,ICNT2,ICNT3,SUM8,TEMP6(ICNT3) = ',  &
                       I6,G15.7,2I6,2G15.7)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
            ENDDO
            DO LL=1,NPOSDIST
               HOLD2=POSDIST(LL)
               ICNT2=0
               SUM8=0.0
               DO II=1,KY
                  IF(TEMP8(II).EQ.HOLD2)THEN
                    ICNT2=ICNT2+1
                    IF(ICPLLN.EQ.'ON')THEN
                      SUM8=SUM8+TEMP4(II)
                    ELSE
                      SUM8=SUM8+TEMP2(II)
                    ENDIF
                 ENDIF
               ENDDO
               IF(ICNT2.GE.1)THEN
                 ICNT4=ICNT4+1
                 TEMP5(ICNT4)=SUM8/REAL(ICNT2)
               ENDIF
!
              IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
                WRITE(ICOUT,2197)LL,HOLD2,ICNT2,ICNT4,SUM8,TEMP5(ICNT4)
 2197           FORMAT(6X,'LL,HOLD2,ICNT2,ICNT4,SUM8,TEMP5(ICNT4) = ',I6,G15.7,2I6,2G15.7)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
            ENDDO
            CALL MEAN(TEMP1,KX,IWRITE,XIRAW,IBUGG3,IERROR)
            CALL MEAN(TEMP2,KY,IWRITE,YIRAW,IBUGG3,IERROR)
            IF(ICPLLN.EQ.'ON')THEN
              CALL MEAN(TEMP3,KX,IWRITE,XI,IBUGG3,IERROR)
              CALL MEAN(TEMP4,KY,IWRITE,YI,IBUGG3,IERROR)
              CALL SD(TEMP3,KX,IWRITE,SDXI,IBUGG3,IERROR)
              CALL SD(TEMP4,KY,IWRITE,SDYI,IBUGG3,IERROR)
            ELSE
              XI=XIRAW
              YI=YIRAW
              CALL SD(TEMP1,KX,IWRITE,SDXI,IBUGG3,IERROR)
              CALL SD(TEMP2,KY,IWRITE,SDYI,IBUGG3,IERROR)
            ENDIF
            CALL SD(TEMP6,ICNT3,IWRITE,SPOSX,IBUGG3,IERROR)
            CALL SD(TEMP5,ICNT4,IWRITE,SPOSY,IBUGG3,IERROR)
            SUM9=SUM9 + SPOSX**2
            SUM10=SUM10 + SPOSY**2
            SUM4=SUM4 + SDXI
            SUM5=SUM5 + SDYI
            DIFF=YI - XI
            IF(ICPLRM.EQ.'OFF')THEN
              BRMAVG(JJ)=(YIRAW+XIRAW)/2.0
            ELSE
              BRMAVG(JJ)=XIRAW
            ENDIF
            BRM(JJ)=DIFF
            DRM(JJ)=BRM(JJ)-BCS
!
            IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
              WRITE(ICOUT,2191)JJ,KX,KY,HOLD
 2191         FORMAT('JJ,KX,KY,HOLD = ',3I5,G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2193)XIRAW,YIRAW,XI,YI,DIFF
 2193         FORMAT(6X,'XIRAW,YIRAW,XI,YI,DIFF,AVG = ',6G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2194)SPOSX,SPOSY
 2194         FORMAT(6X,'SPOSX,SPOSY = ',2G15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2195)BRMAVG(JJ),BRM(JJ),DRM(JJ)
 2195         FORMAT(6X,'BRMAVG(JJ),BRM(JJ),DRM(JJ) = ',3G15.7)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            IF(ICPLRM.EQ.'ON')THEN
              AVE=XIRAW
            ELSE
              AVE=(XIRAW+YIRAW)/2.0
            ENDIF
            IF(ICASPL.EQ.'CDPL')THEN
              ITAG=3
              NPLOTP=NPLOTP+1
              Y2(NPLOTP)=DIFF
              X2(NPLOTP)=AVE
              D2(NPLOTP)=REAL(ITAG)
            ENDIF
         ENDDO
         SDXRM=SQRT(SUM4/REAL(NRDIST))
         SDYRM=SQRT(SUM5/REAL(NRDIST))
         IDFRM=NRDIST
         SPOSMNX=SQRT(SUM9/REAL(NPOSDIST))
         SPOSMNY=SQRT(SUM10/REAL(NPOSDIST))
!
      ELSE
         SDXRM=CPUMIN
         SDYRM=CPUMIN
         SPOSMNX=0.0
         SPOSMNY=0.0
      ENDIF
!
      IF(PCPLCL.NE.CPUMIN)THEN
        IF(ICASPL.EQ.'CPLO')THEN
          ITAG=4
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLCL
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLCL
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
          ITAG=5
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=-PCPLCL
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=-PCPLCL
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
        ELSEIF(ICASPL.EQ.'CDPL')THEN
          ITAG=4
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLCL + BCS
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLCL + BCS
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
          ITAG=5
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=-PCPLCL + BCS
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=-PCPLCL + BCS
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
         ENDIF
      ELSEIF(PCPLLL.NE.CPUMIN .AND. PCPLUL.NE.CPUMIN)THEN
        IF(ICASPL.EQ.'CPLO')THEN
          ITAG=4
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLLL
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLLL
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
          ITAG=5
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
        ELSEIF(ICASPL.EQ.'CDPL')THEN
          ITAG=4
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL + BCS
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL + BCS
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
          ITAG=5
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL + BCS
          X2(NPLOTP)=AVEMIN
          D2(NPLOTP)=REAL(ITAG)
          NPLOTP=NPLOTP+1
          Y2(NPLOTP)=PCPLUL + BCS
          X2(NPLOTP)=AVEMAX
          D2(NPLOTP)=REAL(ITAG)
        ENDIF
      ELSE
        ITAG=ITAG+2
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,2201)SDXRM,SDYRM,SPOSMNX,SPOSMNY
 2201   FORMAT('SDXRM,SDYRM,SPOSMNX,SPOSMNY = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISTEPN='2.4'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     F-TEST FOR EQUAL STANDARD DEVIATION FOR CLINICAL SAMPLES
!     AND REFERENCE SAMPLES
!
      IDFSDX=-1
      IDFSDY=-1
      IFLAG_FTEST=1
      IF(SDXRM.GT.0.0 .AND. SDYRM.GT.0.0)THEN
        IF(SDXCS.GE.SDXRM)THEN
          FSTATX=SDXCS/SDXRM
          IDF1X=IDFCS
          IDF2X=IDFRM
        ELSE
          FSTATX=SDXRM/SDXCS
          IDF1X=IDFRM
          IDF2X=IDFCS
        ENDIF
        IF(SDYCS.GE.SDYRM)THEN
          FSTATY=SDYCS/SDYRM
          IDF1Y=IDFCS
          IDF2Y=IDFRM
        ELSE
          FSTATY=SDYRM/SDYCS
          IDF1Y=IDFRM
          IDF2Y=IDFCS
        ENDIF
        CALL FCDF(FSTATX,IDF1X,IDF2X,FCDFX)
        PVALX=1.0-FCDFX
        CALL FCDF(FSTATY,IDF1Y,IDF2Y,FCDFY)
        PVALY=1.0-FCDFY
        IF(FCDFX.LT.0.95)THEN
          SDX=SQRT((SUM2+SUM4)/REAL(NRDIST+NCSDIST))
          IDFSDX=NRDIST+NCSDIST
        ELSE
          SDX=SDXCS
          IDFSDX=NCSDIST
        ENDIF
        IF(FCDFY.LT.0.95)THEN
          SDY=SQRT((SUM3+SUM5)/REAL(NRDIST+NCSDIST))
          IDFSDY=NRDIST+NCSDIST
        ELSE
          SDY=SDYCS
          IDFSDY=NCSDIST
        ENDIF
      ELSE
        SDX=SDXCS
        SDY=SDYCS
        IFLAG_FTEST=0
      ENDIF
      IDFSD=MIN(IDFSDX-1,IDFSDY-1)
!
!     F-TEST FOR SAMPLE SPECIFIC EFFECTS
!
      ANUM=REAL(NMAX)*SMSSD**2
      DENOM=SDX**2 + SDY**2
      FSTATRE=ANUM/DENOM
      IF(MOD(NCSDIST,2).EQ.0)THEN
        IDFNUM=NCSDIST/2
      ELSE
        IDFNUM=(NCSDIST-1)/2
      ENDIF
      IDFDEN=MIN(IDFX,IDFY)
      CALL FCDF(FSTATRE,IDFNUM,IDFDEN,FCDFRE)
      PVALRE=1.0 - FCDFRE
      AVAL1=SMSSD**2 - (SDX**2 + SDY**2)/REAL(NMAX)
      SDD=0.0
      IF(AVAL1.GT.0.0)SDD=SQRT(AVAL1)
      SDDSB=0.0
      AVAL3=SB**2 - (SDX**2 + SDY**2)/REAL(NMAX)
      IF(AVAL3.GT.0.0)SDDSB=SQRT(AVAL3)
      NUMREPL=NMAX
      IF(ICPLLN.EQ.'ON')THEN
        DO JJ=1,NREF
           TEMP5(JJ)=LOG(RMX(JJ))
           TEMP6(JJ)=LOG(RMY(JJ))
        ENDDO
      ELSE
        DO JJ=1,NREF
           TEMP5(JJ)=RMX(JJ)
           TEMP6(JJ)=RMY(JJ)
        ENDDO
      ENDIF
      SDDCORR=0.0
      AVAL2=SMSSD**2 - (SDX**2 + SDY**2)/REAL(NMAX) -        &
            SDPOSX**2 - SDPOSY**2
      IF(AVAL2.GT.0.0)SDDCORR=SQRT(AVAL2)
      SE=SQRT((SDX**2 + SDY**2)/REAL(NMAX))
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,2203)SDX,SDY,PVALX,PVALY,IFLAG_FTEST
 2203   FORMAT('SDX,SDY,PVALX,PVALY,IFLAG_FTEST = ',4G15.7,I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2205)ANUM,DENOM,FSTATRE,FCDFRE,PVALRE,SDD
 2205   FORMAT('ANUM,DENOM,FSTATRE,FCDFRE,PVALRE,SDD = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2206)SMSSD,SE,SPOSMNX,SPOSMNY,SDPOSX,SDPOSY,AVAL2
 2206   FORMAT('SMSSD,SE,SPOSMNX,SPOSMNY,SDPOSX,SDPOSY,AVAL2 = ',7G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2207)SDD,SDDCORR,IDFNUM,IDFDEN
 2207   FORMAT('SDD,SDDCORR,IDFNUM,IDFDEN = ',2G15.7,2I6)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISTEPN='2.3'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO I=1,MAXROW
         NCTEXT(I)=0
         ITEXT(I)=' '
         ROWSEP(I)=0
         DO J=1,MAXCOL
            AMAT(I,J)=-99.0
            NCVALU(I,J)=0
            IVALUE(I,J)=' '
         ENDDO
      ENDDO
!
      UBRM=SQRT((SPOSMNX**2 + SPOSMNY**2)/REAL(NPOSDIST))
      UBCS=SB/SQRT(REAL(NCSDIST))
      AVAL1=(SPOSMNX**2 + SPOSMNY**2)/REAL(NPOSDIST)
      AVAL2=SB**2/REAL(NCSDIST)
      UDRM=SQRT(AVAL1+AVAL2)
!
      ACOV=PCPLCV
      ITAG=5
      DO II=1,NRDIST
         IF(ICASPL.EQ.'CPLO')THEN
           NPLOTP=NPLOTP + 1
           X2(NPLOTP)=BRMAVG(II)
           Y2(NPLOTP)=DRM(II)
           D2(NPLOTP)=3.0
         ENDIF
         ITAG=ITAG+1
         IF(ICASPL.EQ.'CDPL')THEN
           UPPLIM=BRM(II) + ACOV*UDRM
           ALOWLIM=BRM(II) - ACOV*UDRM
           NPLOTP=NPLOTP + 1
           X2(NPLOTP)=BRMAVG(II)
           Y2(NPLOTP)=ALOWLIM
           D2(NPLOTP)=REAL(ITAG)
           NPLOTP=NPLOTP + 1
           X2(NPLOTP)=BRMAVG(II)
           Y2(NPLOTP)=UPPLIM
           D2(NPLOTP)=REAL(ITAG)
         ELSE
           UPPLIM=DRM(II) + ACOV*UDRM
           ALOWLIM=DRM(II) - ACOV*UDRM
           NPLOTP=NPLOTP + 1
           X2(NPLOTP)=BRMAVG(II)
           Y2(NPLOTP)=ALOWLIM
           D2(NPLOTP)=REAL(ITAG)
           NPLOTP=NPLOTP + 1
           X2(NPLOTP)=BRMAVG(II)
           Y2(NPLOTP)=UPPLIM
           D2(NPLOTP)=REAL(ITAG)
         ENDIF
      ENDDO
!
      DO JJ=1,NRDIST
         WRITE(IOUNI2,'(I5,5X,3E15.7)')INT(RMDIST(JJ)),BRMAVG(JJ),BRM(JJ),DRM(JJ)
      ENDDO
      WRITE(IOUNI2,2230)
      WRITE(IOUNI2,2230)
      WRITE(IOUNI2,2231)SPOSMNX
      WRITE(IOUNI2,2232)SPOSMNY
      WRITE(IOUNI2,2233)UBRM
      WRITE(IOUNI2,2234)BCS
      WRITE(IOUNI2,2235)SB
      WRITE(IOUNI2,2236)UBCS
      WRITE(IOUNI2,2237)UDRM
 2230 FORMAT(' ')
 2231 FORMAT('s(pos-mean-x):   ',E15.7)
 2232 FORMAT('s(pos-mean-y):   ',E15.7)
 2233 FORMAT('u(Brm):          ',E15.7)
 2234 FORMAT('Bcs:             ',E15.7)
 2235 FORMAT('SB:              ',E15.7)
 2236 FORMAT('u(Bcs):          ',E15.7)
 2237 FORMAT('u(DRM):          ',E15.7)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,2211)UBRM,UBCS,AVAL1,AVAL2,UDRM
 2211   FORMAT('UBRM,UBCS,AVAL1,AVAL2,UDRM = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     CALL POSITION SPECIFIC TEST
!
      IF(ICASPL.EQ.'CPLO')THEN
        CALL DPPET2(RMX,POSID,RMID,NREF,XIDTEM,TEMP1,           &
                    TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,        &
                    IVARN1(4),IVARN2(4),IVARN1(6),IVARN2(6),    &
                    IVARN1(7),IVARN2(7),                        &
                    IWRITE,IFORSW,ICAPSW,ICAPTY,                &
                    ISUBRO,IBUGG3,IERROR)
        CALL DPPET2(RMY,POSID,RMID,NREF,XIDTEM,TEMP1,           &
                    TEMP2,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,        &
                    IVARN1(5),IVARN2(5),IVARN1(6),IVARN2(6),    &
                    IVARN1(7),IVARN2(7),                        &
                    IWRITE,IFORSW,ICAPSW,ICAPTY,                &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,       &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(IPRINT.EQ.'ON' .AND. ICASPL.EQ.'CPLO')THEN
!
!       F-TEST FOR EQUAL STANDARD DEVIATIONS FOR CLINICAL SAMPLES
!       AND REFERENCE MATERIALS
!
        IF(IFLAG_FTEST.EQ.0)GO TO 2399
!
        ITITLE(1:22)='Commutability Analysis'
        NCTITL=22
        ITITLZ=''
        NCTITZ=0
        ICNT=1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='First Clinical Sample Variable:    '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(1)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(1)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Second Clinical Sample Variable:   '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(2)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(2)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Clinical Sample ID Variable:       '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(3)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(3)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='First Reference Sample Variable:   '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(4)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(4)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Second Reference Sample Variable:  '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(5)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(5)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Reference Sample ID Variable:      '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(6)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(6)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Reference Position ID Variable:    '
        WRITE(ITEXT(ICNT)(36:39),'(A4)')IVARN1(7)
        WRITE(ITEXT(ICNT)(40:43),'(A4)')IVARN2(7)
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        NUMROW=ICNT
        DO I=1,NUMROW
           NTOT(I)=15
        ENDDO
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,                              &
                    NTOT,NUMROW,                                &
                    ICAPSW,ICAPTY,ILAST,IFRST,                  &
                    ISUBRO,IBUGG3,IERROR)
!
!       HEADER FOR EQUAL STANDARD DEVIATIONS TEST
!
        ITITLE(1:47)='Test for Equal Standard Deviations for Clinical'
        NCTITL=47
        ITITLZ(1:44)='Samples and Reference Materials (X Variable)'
        NCTITZ=44
        ICNT=1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='F Test for Equal Standard Deviations:'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Pooled SD for Clinical Samples:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=SDXCS
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Ref Materials Between Replicate SD:'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=SDXRM
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Numerator Degrees of Freedom:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=REAL(IDF1X)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Denominator Degrees of Freedom:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REAL(IDF2X)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Test F Statistic:'
        NCTEXT(ICNT)=17
        AVALUE(ICNT)=FSTATX
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test CDF Value:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=FCDFX
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test P-Value:'
        NCTEXT(ICNT)=13
        AVALUE(ICNT)=PVALX
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        NUMROW=ICNT
        DO I=1,NUMROW
           NTOT(I)=15
        ENDDO
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,   &
                    NTOT,NUMROW,   &
                    ICAPSW,ICAPTY,ILAST,IFRST,   &
                    ISUBRO,IBUGG3,IERROR)
!
!       PRINT F CRITICAL VALUES TABLE
!
        ITITLE='Conclusions (Upper 1-Tailed Test)'
        NCTITL=33
        ITITL9='H0: Equal SD for X Variable'
        NCTIT9=27
        NUMCL2=4
        NUMALZ=3
!
        DO J=1,NUMCL2
           DO I=1,3
              ITITL2(I,J)=' '
              NCTIT2(I,J)=0
           ENDDO
        ENDDO
!
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Region (>=)'
        NCTIT2(3,3)=11
        ICNT2=4
        ITITL2(1,ICNT2)='Null'
        NCTIT2(1,ICNT2)=4
        ITITL2(2,ICNT2)='Hypothesis'
        NCTIT2(2,ICNT2)=10
        ITITL2(3,ICNT2)='Conclusion'
        NCTIT2(3,ICNT2)=10
!
        NMAX=0
        NUMCOL=NUMCL2
        DO I=1,NUMCOL
           VALIGN(I)='b'
           ALIGN(I)='r'
           NTOT(I)=15
           NMAX=NMAX+NTOT(I)
           ITYPCO(I)='NUME'
           IDIGIT(I)=NUMDIG
           IF(I.EQ.1)ITYPCO(I)='ALPH'
           IF(I.EQ.4)ITYPCO(I)='ALPH'
        ENDDO
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
!
        DO J=1,3
!
           AMAT(J,2)=FSTATX
           NCVALU(J,4)=6
           IF(J.EQ.1)THEN
             IVALUE(J,1)='90%'
             NCVALU(J,1)=4
             CALL FPPF(0.90,IDF1X,IDF2X,CUTU90)
             AMAT(J,3)=CUTU90
             IVALUE(J,4)='ACCEPT'
             IF(FSTATX.GT.CUTU90)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.2)THEN
             IVALUE(J,1)='95%'
             NCVALU(J,1)=4
             CALL FPPF(0.95,IDF1X,IDF2X,CUTU95)
             AMAT(J,3)=CUTU95
             IVALUE(J,4)='ACCEPT'
             IF(FSTATX.GT.CUTU95)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.3)THEN
             IVALUE(J,1)='99%'
             NCVALU(J,1)=4
             CALL FPPF(0.99,IDF1X,IDF2X,CUTU99)
             AMAT(J,3)=CUTU99
             IVALUE(J,4)='ACCEPT'
             IF(FSTATX.GT.CUTU99)IVALUE(J,4)='REJECT'
           ENDIF
        ENDDO
!
        ICNT=3
        NUMLIN=3
        NUMCLI=MAXCOL
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,                                &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,                  &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,                  &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,        &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,                    &
                    IFLAGS,IFLAGE,                                &
                    ISUBRO,IBUGG3,IERROR)
!
        ITITLE(1:47)='Test for Equal Standard Deviations for Clinical'
        NCTITL=47
        ITITLZ(1:44)='Samples and Reference Materials (Y Variable)'
        NCTITZ=44
        ICNT=1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='F Test for Equal Standard Deviations:'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Pooled SD for Clinical Samples:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=SDYCS
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Ref Materials Between Replicate SD:'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=SDYRM
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Numerator Degrees of Freedom:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=REAL(IDF1Y)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Denominator Degrees of Freedom:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REAL(IDF2Y)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Test F Statistic:'
        NCTEXT(ICNT)=17
        AVALUE(ICNT)=FSTATY
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test CDF Value:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=FCDFY
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test P-Value:'
        NCTEXT(ICNT)=13
        AVALUE(ICNT)=PVALY
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        NUMROW=ICNT
        DO II=1,NUMROW
           NTOT(II)=15
        ENDDO
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,                              &
                    NTOT,NUMROW,                                &
                    ICAPSW,ICAPTY,ILAST,IFRST,                  &
                    ISUBRO,IBUGG3,IERROR)
!
!       PRINT F CRITICAL VALUES TABLE
!
        ITITLE='Conclusions (Upper 1-Tailed Test)'
        NCTITL=33
        ITITL9='H0: Equal SD for Y Variable'
        NCTIT9=27
        NUMCL2=4
        NUMALZ=3
!
        DO J=1,NUMCL2
           DO I=1,3
              ITITL2(I,J)=' '
              NCTIT2(I,J)=0
           ENDDO
        ENDDO
!
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Region (>=)'
        NCTIT2(3,3)=11
        ICNT2=4
        ITITL2(1,ICNT2)='Null'
        NCTIT2(1,ICNT2)=4
        ITITL2(2,ICNT2)='Hypothesis'
        NCTIT2(2,ICNT2)=10
        ITITL2(3,ICNT2)='Conclusion'
        NCTIT2(3,ICNT2)=10
!
        NMAX=0
        NUMCOL=NUMCL2
        DO I=1,NUMCOL
           VALIGN(I)='b'
           ALIGN(I)='r'
           NTOT(I)=15
           NMAX=NMAX+NTOT(I)
           ITYPCO(I)='NUME'
           IDIGIT(I)=NUMDIG
           IF(I.EQ.1)ITYPCO(I)='ALPH'
           IF(I.EQ.4)ITYPCO(I)='ALPH'
        ENDDO
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
!
        DO J=1,3
!
           AMAT(J,2)=FSTATY
           NCVALU(J,4)=6
           IF(J.EQ.1)THEN
             IVALUE(J,1)='90%'
             NCVALU(J,1)=4
             CALL FPPF(0.90,IDF1Y,IDF2Y,CUTU90)
             AMAT(J,3)=CUTU90
             IVALUE(J,4)='ACCEPT'
             IF(FSTATY.GT.CUTU90)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.2)THEN
             IVALUE(J,1)='95%'
             NCVALU(J,1)=4
             CALL FPPF(0.95,IDF1Y,IDF2Y,CUTU95)
             AMAT(J,3)=CUTU95
             IVALUE(J,4)='ACCEPT'
             IF(FSTATY.GT.CUTU95)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.3)THEN
             IVALUE(J,1)='99%'
             NCVALU(J,1)=4
             CALL FPPF(0.99,IDF1Y,IDF2Y,CUTU99)
             AMAT(J,3)=CUTU99
             IVALUE(J,4)='ACCEPT'
             IF(FSTATY.GT.CUTU99)IVALUE(J,4)='REJECT'
           ENDIF
        ENDDO
!
        ICNT=3
        NUMLIN=3
        NUMCLI=MAXCOL
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,                                &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,                  &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,                  &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,        &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,                    &
                    IFLAGS,IFLAGE,                                &
                    ISUBRO,IBUGG3,IERROR)
!
 2399 CONTINUE
!
!       TEST FOR TREND IN BIAS
!
        ITITLE(1:28)='Test for a Trend in the Bias'
        NCTITL=28
        ITITLZ=' '
        NCTITZ=0
        ICNT=1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        IF(NCSDIST.GE.22)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Normal Test for Bias Trend:'
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ELSE
          ICNT=ICNT+1
          ITEXT(ICNT)='Test for Bias Trend:'
          NCTEXT(ICNT)=20
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ENDIF
!
        ICNT=ICNT+1
        ITEXT(ICNT)='s(MSSD) (Mean Square Successive Difference SD):'
        NCTEXT(ICNT)=48
        AVALUE(ICNT)=SMSSD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='s(B) (SD of Bias Values):'
        NCTEXT(ICNT)=25
        AVALUE(ICNT)=SB
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Differences:'
        NCTEXT(ICNT)=22
        AVALUE(ICNT)=ANDIFF
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test Statistic ((s(MSSD)/s(B))**2):'
        NCTEXT(ICNT)=35
        AVAL=(SMSSD/SB)**2
        AVALUE(ICNT)=AVAL
        IDIGIT(ICNT)=NUMDIG
        IF(NCSDIST.GE.22)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Location for Test Statistic:'
          NCTEXT(ICNT)=28
          AVALUE(ICNT)=ALOC
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Scale for Test Statistic:'
          NCTEXT(ICNT)=25
          AVALUE(ICNT)=ASCALE
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Test CDF Value:'
          NCTEXT(ICNT)=15
          AVALUE(ICNT)=ACDF
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Test P-Value:'
          NCTEXT(ICNT)=13
          AVALUE(ICNT)=PVALUT
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        NUMROW=ICNT
        DO II=1,NUMROW
           NTOT(II)=15
        ENDDO
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,                              &
                    NTOT,NUMROW,                                &
                    ICAPSW,ICAPTY,ILAST,IFRST,                  &
                    ISUBRO,IBUGG3,IERROR)
!
!       PRINT NORMAL CRITICAL VALUES TABLE
!
        ITITLE='Conclusions (Lower Tailed Test)'
        NCTITL=31
        ITITL9='H0: No Trend in Bias'
        NCTIT9=20
        NUMCL2=4
        NUMALZ=3
!
        DO J=1,NUMCL2
           DO I=1,NUMALZ
              ITITL2(I,J)=' '
              NCTIT2(I,J)=0
           ENDDO
        ENDDO
!
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
        ITITL2(2,3)='Lower Critical'
        NCTIT2(2,3)=14
        ITITL2(3,3)='Region (<=)'
        NCTIT2(3,3)=11
        ICNT2=4
        ITITL2(1,ICNT2)='Null'
        NCTIT2(1,ICNT2)=4
        ITITL2(2,ICNT2)='Hypothesis'
        NCTIT2(2,ICNT2)=10
        ITITL2(3,ICNT2)='Conclusion'
        NCTIT2(3,ICNT2)=10
!
        NMAX=0
        NUMCOL=NUMCL2
        DO I=1,NUMCOL
           VALIGN(I)='b'
           ALIGN(I)='r'
           NTOT(I)=15
           NMAX=NMAX+NTOT(I)
           ITYPCO(I)='NUME'
           IDIGIT(I)=NUMDIG
           IF(I.EQ.1)ITYPCO(I)='ALPH'
           IF(I.EQ.4)ITYPCO(I)='ALPH'
        ENDDO
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IWHTML(5)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
        IWRTF(5)=IWRTF(4)+IINC
!
        DO J=1,NUMALZ
!
           AMAT(J,2)=STATNO
           NCVALU(J,4)=6
           IF(J.EQ.1)THEN
             IVALUE(J,1)='95%'
             NCVALU(J,1)=3
             IF(NCSDIST.GE.22)THEN
               CALL NORPPF(0.05,CUTL10)
               CUTL5= ALOC + ASCALE*CUTL10
             ELSE
               CUTL5= QCV5(NCSDIST)
             ENDIF
             AMAT(J,3)=CUTL5
             IVALUE(J,4)='ACCEPT'
             IF(STATNO.LT.CUTL5)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.2)THEN
             IVALUE(J,1)='99%'
             NCVALU(J,1)=3
             IF(NCSDIST.GE.22)THEN
               CALL NORPPF(0.01,CUTL1)
               CUTL1= ALOC + ASCALE*CUTL1
             ELSE
               CUTL5= QCV1(NCSDIST)
             ENDIF
             AMAT(J,3)=CUTL1
             IVALUE(J,4)='ACCEPT'
             IF(STATNO.LT.CUTL1)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.3)THEN
             IVALUE(J,1)='99.9%'
             NCVALU(J,1)=5
             IF(NCSDIST.GE.22)THEN
               CALL NORPPF(0.001,CUTL01)
               CUTL01= ALOC + ASCALE*CUTL01
             ELSE
               CUTL01= QCV01(NCSDIST)
             ENDIF
             AMAT(J,3)=CUTL01
             IVALUE(J,4)='ACCEPT'
             IF(STATNO.LT.CUTL01)IVALUE(J,4)='REJECT'
           ENDIF
        ENDDO
!
        ICNT=3
        NUMLIN=3
        NUMCLI=MAXCOL
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,                                &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,                  &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,                  &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,        &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,                    &
                    IFLAGS,IFLAGE,                                &
                    ISUBRO,IBUGG3,IERROR)
!
!       F-TEST FOR SAMPLE SPECIFIC DIFFERENCES
!
!       HEADER
!
        ITITLE(1:32)='Test for Sample Specific Effects'
        NCTITL=32
        ITITLZ=' '
        NCTITZ=0
        ICNT=1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='F Test for Sample Specific Effects:'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='SD of Mean Square Successive Differences (s(MSSD)):'
        NCTEXT(ICNT)=51
        AVALUE(ICNT)=SMSSD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='SE:'
        NCTEXT(ICNT)=3
        AVALUE(ICNT)=SE
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Replicates:'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=REAL(NUMREPL)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Pooled SD Between Replicates (Sx):'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=SDX
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Pooled SD Between Replicates (Sy):'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=SDY
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='SD of Sample Specific Differences (s(MSSD):'
        NCTEXT(ICNT)=43
        AVALUE(ICNT)=SDD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Corrected SD of Sample Specific Differences:'
        NCTEXT(ICNT)=44
        AVALUE(ICNT)=SDDCORR
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='SD of Sample Specific Differences (s(B)):'
        NCTEXT(ICNT)=41
        AVALUE(ICNT)=SB
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Numerator Degrees of Freedom:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=REAL(IDFNUM)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Denominator Degrees of Freedom:'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=REAL(IDFDEN)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Test F Statistic:'
        NCTEXT(ICNT)=17
        AVALUE(ICNT)=FSTATRE
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test CDF Value:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=FCDFRE
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test P-Value:'
        NCTEXT(ICNT)=13
        AVALUE(ICNT)=PVALRE
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        NUMROW=ICNT
        DO I=1,NUMROW
           NTOT(I)=15
        ENDDO
!
        IFRST=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,                              &
                    NTOT,NUMROW,                                &
                    ICAPSW,ICAPTY,ILAST,IFRST,                  &
                    ISUBRO,IBUGG3,IERROR)
!
!       PRINT F CRITICAL VALUES TABLE
!
        ITITLE='Conclusions (Upper 1-Tailed Test)'
        NCTITL=33
        ITITL9='H0: No Sample-Specific Effects'
        NCTIT9=30
        NUMCL2=4
        NUMALZ=3
!
        DO J=1,NUMCL2
           DO I=1,3
              ITITL2(I,J)=' '
              NCTIT2(I,J)=0
           ENDDO
        ENDDO
!
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Region (>=)'
        NCTIT2(3,3)=11
        ICNT2=4
        ITITL2(1,ICNT2)='Null'
        NCTIT2(1,ICNT2)=4
        ITITL2(2,ICNT2)='Hypothesis'
        NCTIT2(2,ICNT2)=10
        ITITL2(3,ICNT2)='Conclusion'
        NCTIT2(3,ICNT2)=10
!
        NMAX=0
        NUMCOL=NUMCL2
        DO I=1,NUMCOL
           VALIGN(I)='b'
           ALIGN(I)='r'
           NTOT(I)=15
           NMAX=NMAX+NTOT(I)
           ITYPCO(I)='NUME'
           IDIGIT(I)=NUMDIG
           IF(I.EQ.1)ITYPCO(I)='ALPH'
           IF(I.EQ.4)ITYPCO(I)='ALPH'
        ENDDO
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
!
        DO J=1,3
!
           AMAT(J,2)=FSTATRE
           NCVALU(J,4)=6
           IF(J.EQ.1)THEN
             IVALUE(J,1)='90%'
             NCVALU(J,1)=4
             CALL FPPF(0.90,IDFNUM,IDFDEN,CUTU90)
             AMAT(J,3)=CUTU90
             IVALUE(J,4)='ACCEPT'
             IF(FSTATRE.GT.CUTU90)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.2)THEN
             IVALUE(J,1)='95%'
             NCVALU(J,1)=4
             CALL FPPF(0.95,IDFNUM,IDFDEN,CUTU95)
             AMAT(J,3)=CUTU95
             IVALUE(J,4)='ACCEPT'
             IF(FSTATRE.GT.CUTU95)IVALUE(J,4)='REJECT'
           ELSEIF(J.EQ.3)THEN
             IVALUE(J,1)='99%'
             NCVALU(J,1)=4
             CALL FPPF(0.99,IDFNUM,IDFDEN,CUTU99)
             AMAT(J,3)=CUTU99
             IVALUE(J,4)='ACCEPT'
             IF(FSTATRE.GT.CUTU99)IVALUE(J,4)='REJECT'
           ENDIF
        ENDDO
!
        ICNT=3
        NUMLIN=3
        NUMCLI=MAXCOL
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,                                &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,                  &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,                  &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,        &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,                    &
                    IFLAGS,IFLAGE,                                &
                    ISUBRO,IBUGG3,IERROR)
!
      ENDIF
!
      NPLOTV=3
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CPL2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCPL2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,BCS
 9012   FORMAT('IERROR,BCS = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO I=1,NPLOTP
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2G15.7,F9.1)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      RETURN
      END SUBROUTINE DPCPL2
      SUBROUTINE DPCPU(ICOM,IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                       ATIME,   &
                       IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--RETURN THE AMOUNT OF CPU TIME CURRENTLY USED AND SAVE
!              IN THE INTERNAL PARAMETER   CPUTIME  .
!              THERE IS A FORTRAN 90 STANDARD, BUT NOT A FORTRAN 77
!              STANDARD, SO CALL DPCPUT (IN THE DP1.FOR
!              MACHINE DEPENDENT CODE FILE).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 STATISTICAL ENGINEEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.5
!     ORIGINAL VERSION--MAY        2009.
!
!-----NON-COMMON VARIABLES (GRAPHICS)---------------------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION IARGT(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      J2=0
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PCPU')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCPU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)IBUGS2,ISUBRO,IFOUND,IERROR
   81   FORMAT('IBUGS2,ISUBRO,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 85 I=1,NUMARG
          WRITE(ICOUT,87)I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I)
   87     FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I) = ',   &
                 I8,2X,3(A4,2X),I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   85   CONTINUE
      ENDIF
!
!               *****************************************************
!               **  STEP 1--                                       **
!               **  CHECK FOR THE COMMAND                          **
!               *****************************************************
!
      IF(ICOM.EQ.'CPU ')THEN
        IFOUND='YES'
        CALL DPCPUT(ATIME,IBUGS2,ISUBRO,IFOUND,IERROR)
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,1001)ATIME
 1001     FORMAT('THE CURRENT CPU USAGE IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PCPU')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCPU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9031)IBUGS2,ISUBRO
 9031   FORMAT('IBUGS2,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)IFOUND,IERROR
 9032   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9033)ATIME
 9033   FORMAT('ATIME = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCPU
      SUBROUTINE DPCQD3(Y,N,ICASA2,ICASA4,ISEED,MAXNXT,IQUAME,   &
                        TEMP1,ALPHA,NALPHA,ALOWLM,AUPPLM,   &
                        CQV,Q1,Q3,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES CONFIDENCE LIMITS FOR THE
!              COEFFIENT OF QUARTILE DISPERSION.  THE COEFFICIENT OF
!              QUARTILE DISPERSION IS AN ALTERNATIVE TO THE COEFFICIENT
!              OF VARIATION FOR NON-NORMAL DATA.  IT IS PARTICULARLY
!              RECOMMENDED FOR HIGHLY SKEWED OR HIGHLY NON-NORMAL DATA
!              (FOR MODERATELY NON-NORMAL DATA, THE COEFFICIENT OF
!              DISPERSION IS RECOMMENDED).
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!                 LET A = LOWER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMIT Y
!                 LET A = UPPER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMIT Y
!
!              THE DATA CONSISTS OF N OBSERVATIONS IN Y.
!
!              THIS ALGORITHM IS FROM THE BONETT PAPER.
!
!              THE COEFFICIENT OF QUARTILE DISPERSION IS DEFINED AS:
!
!                  CQV = (Q3 - Q1)/(Q3 - Q1)
!
!              WHERE Q1 AND Q3 ARE THE 25-TH AND 75-TH PERCENTILES OF
!              THE DATA, RESPECTIVELY.
!
!     INPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR Y.
!                    --ALPHA  = THE SINGLE PRECISION VECTOR OF CONFIDENCE
!                               LEVELS
!                      NALPHA = THE INTEGER NUMBER OF ALPHA VALUES
!     OUTPUT ARGUMENTS-ALOWLM = THE SINGLE PRECISION VECTOR OF LOWER
!                               CONFIDENCE LIMIT VALUES
!                     -AUPPLM = THE SINGLE PRECISION VECTOR OF UPPER
!                               CONFIDENCE LIMIT VALUES
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEDIAN, MEAN, VAR, AAD, SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--BONETT (2006), "CONFIDENCE INTERVAL FOR A
!                 COEFFICIENT OF QUARTILE VARIATIOIN", COMPUTATIONAL
!                 STATISTICS AND DATA ANALYSIS, VOL. 50, PP. 2953-2957.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     ORIGINAL VERSION--DECEMBER  2017.
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION ALOWLM(*)
      DIMENSION AUPPLM(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA4
      CHARACTER*4 IQUAME
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CQD3'
      ISUBN2='    '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CQD3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCQD3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASA2,ICASA4
   52   FORMAT('IBUGA3,ISUBRO,ICASA2,ICASA4 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,NALPHA,ISEED,ALPHA(1)
   53   FORMAT('N,NALPHA,ISEED,ALPHA(1) = ',3I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
        DO 76 I=1,NALPHA
          WRITE(ICOUT,77)I,ALPHA(I)
   77     FORMAT('I,ALPHA(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   76   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CQD3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 110 I=1,NALPHA
        ALOWLM(I)=CPUMIN
        AUPPLM(I)=CPUMIN
  110 CONTINUE
!
      IF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COEFFICIENT OF QUARTILE DISPERSION ',   &
               'CONFIDENCE LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF ORIGINAL OBSERVATIONS  IS LESS ',   &
               'THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CARRY OUT CALCULATIONS FOR CONFIDENCE **
!               **  LIMITS.                               **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.AND.ISUBRO.EQ.'CQD3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ICASA2:  LOWE     => LOWER LIMIT
!              UPPE     => UPPER LIMIT
!     ICASA4:  ONES     => ONE-SIDED LIMIT
!              TWOS     => TWO-SIDED LIMIT
!
!     COMPUTE LOWER AND UPPER QUARTILES
!
      AN=REAL(N)
      CALL SORT(Y,N,Y)
      QNT=0.25
      CALL QUANT(QNT,Y,N,IWRITE,TEMP1,MAXNXT,IQUAME,Q1,IBUGA3,IERROR)
      QNT=0.75
      CALL QUANT(QNT,Y,N,IWRITE,TEMP1,MAXNXT,IQUAME,Q3,IBUGA3,IERROR)
!
      D=Q3 - Q1
      S=Q3 + Q1
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CQD3')THEN
        WRITE(ICOUT,201)Q1,Q3,D,S
  201   FORMAT('Q1,Q3,D,S = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(S.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,207)
  207   FORMAT('      THE DIFFERENCE BETWEEN THE UPPER AND LOWER ',   &
               'QUARTILES IS ZERO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,209)
  209   FORMAT('      THE COEFFICIENT OF QUARTILE DISPERSION ',   &
               'CONFIDENCE LIMIT IS NOT COMPUTED IN THIS CASE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CQV=D/S
!
      TERM1=AN/4.0
      TERM2=SQRT(3.0*AN/16.0)
      TERM3=1.0/(16.0*AN)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CQD3')THEN
        WRITE(ICOUT,223)CQV,TERM1,TERM2,TERM3
  223   FORMAT('CQV,TERM1,TERM2,TERM3 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      DO 300 I=1,NALPHA
!
!       GET NORMAL CRITICAL VALUE
!
        ALP=ALPHA(I)
        IF(ALP.GE.1.0 .AND. ALP.LE.100.)ALP=ALP/100.
        IF(ALP.LE.0.0 .OR. ALP.GE.1.0)THEN
          IF(ICASA4.EQ.'ONES')THEN
            Z=1.645
          ELSE
            Z=1.96
          ENDIF
        ELSE
          IF(ALP.LT.0.5)THEN
            ALP=1.0-ALP
          ENDIF
          ALP=1.0 - ALP
          IF(ICASA4.EQ.'ONES')THEN
            P1=ALP
            P2=1.0-ALP
            CALL NORPPF(P2,Z)
          ELSE
            P1=ALP/2.0
            P2=1.0-(ALP/2.0)
            CALL NORPPF(P2,Z)
          ENDIF
        ENDIF
!
!       FIND IA, IB, IC, AND ID
!
!       ROUND IA AND IB UP TO NEAREST INTEGER
!
        A=TERM1 - Z*TERM2
        IA=INT(A+0.999)
        IF(IA.LE.0)IA=1
        B=TERM1 + Z*TERM2
        IB=INT(B+0.999)
        IF(IB.GE.N)IB=N
        IC=N+1-IB
        ID=N+1-IA
!
        IF(N.LE.100)THEN
          PTEMP=0.25
          CALL BINCDF(DBLE(IB-1),DBLE(PTEMP),N,DCDF1)
          CALL BINCDF(DBLE(IA-1),DBLE(PTEMP),N,DCDF2)
          ALPSTR=DCDF1 - DCDF2
          P9=(1.0 - ALPSTR)/2.0
          CALL NORPPF(P9,Z2)
          Z2=-Z2
        ELSE
          P9=0.975
          Z2=Z
        ENDIF
!
        F1SQ=3.0*Z2**2/(4.0*AN*(Y(IB) - Y(IA))**2)
        F3SQ=3.0*Z2**2/(4.0*AN*(Y(ID) - Y(IC))**2)
        F1=SQRT(F1SQ)
        F3=SQRT(F3SQ)
!
        TERM4=(3.0/F1SQ) + (3.0/F3SQ) - (2.0/(F1*F3))
        TERM4B=(3.0/F1SQ) + (3.0/F3SQ) + (2.0/(F1*F3))
        TERM5=2.0*((3.0/F3SQ) - (3.0/F1SQ))
        TERM6=(TERM4/D**2) + (TERM4B/S**2) - (TERM5/(D*S))
        V=TERM3*TERM6
        CENT=AN/(AN-1.0)
!
        ALOWLM(I)=EXP(LOG(D/S)*CENT - Z*SQRT(V))
        AUPPLM(I)=EXP(LOG(D/S)*CENT + Z*SQRT(V))
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CQD3')THEN
          WRITE(ICOUT,311)I,IA,IB,IC,ID,Z
  311     FORMAT('I,IA,IB,IC,ID,Z = ',5I8,G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,312)ALPSTR,P9,Z2
  312     FORMAT('ALPSTR,P9,Z2 = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,313)F1SQ,F3SQ,F1,F3,TERM4,TERM5,TERM6
  313     FORMAT('F1SQ,F3SQ,F1,F3,TERM4,TERM5,TERM6 = ',7G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,315)V,ALOWLM(I),AUPPLM(I)
  315     FORMAT('V,ALOWLM(I),AUPPLM(I) = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
  300 CONTINUE
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CQD3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9051)
 9051   FORMAT('**** AT THE END OF DPCQD3--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCQD3
      SUBROUTINE DPCR(IHARG,NUMARG,   &
      IDEFCR,   &
      ITEXCR,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE CARRIAGE RETURN SWITCH (ON OR OFF) FOR
!              TEXT SCRIPT.
!              THE CARRIAGE RETURN SWITCH WILL BE PLACED
!              IN THE CHARACTER VARIABLE ITEXCR.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEFCR
!                     --IBUGD2
!     OUTPUT ARGUMENTS--ITEXCR
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCR
      CHARACTER*4 ITEXCR
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGD2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDEFCR
   53 FORMAT('IDEFCR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I)
   56 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  TREAT THE CARRIAGE RETURN CASE  **
!               **************************************
!
      IF(NUMARG.LE.0)GO TO 1161
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'RETU')GO TO 1161
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1161
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1162
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1161
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1165
      GO TO 1170
!
 1161 CONTINUE
      ITEXCR='ON'
      GO TO 1180
!
 1162 CONTINUE
      ITEXCR='OFF'
      GO TO 1180
!
 1165 CONTINUE
      ITEXCR=IDEFCR
      GO TO 1180
!
 1170 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,1171)
 1171 FORMAT('***** ERROR IN DPCR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1172)
 1172 FORMAT('      ILLEGAL ENTRY FOR CARRIAGE RETURN ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1173)
 1173 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1174)
 1174 FORMAT('      SUPPOSE THE THE ANALYST WISHES ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1175)
 1175 FORMAT('      TO HAVE A CARRIAGE RETURN AFTER THE TEXT ',   &
      'COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1177)
 1177 FORMAT('      THEN ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1178)
 1178 FORMAT('           CARRIAGE RETURN ON     (OR   CR ON) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1179)
 1179 FORMAT('           CARRIAGE RETURN        (OR   CR) ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE CARRIAGE RETURN (AFTER TEXT) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)ITEXCR
 1182 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGD2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCR')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGD2,ISUBRO,IFOUND,IERROR
 9012 FORMAT('IBUGD2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDEFCR,ITEXCR
 9013 FORMAT('IDEFCR,ITEXCR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCR
      SUBROUTINE DPCRCI(MAXNXT,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE CONFIDENCE LIMITS FOR THE CORRELATION
!              COEFFICIENT
!     EXAMPLE--CORRELATION CONFIDENCE LIMTIS Y1 Y2
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/6
!     ORIGINAL VERSION--JUNE      2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='CI  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='YES'
      IERROR='NO'
!
!               *******************************************************
!               **  TREAT THE CORRELATION CONFIDENCE LIMITS CASE     **
!               *******************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRCI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCRCI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRCI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CORRELATION CONFIDENCE LIMITS'
      MINNA=1
      MAXNA=100
      MINN2=4
      IFLAGE=1
      IFLAGM=1
      MINNVA=2
      MAXNVA=MAXSPN
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRCI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRCI')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=1
      DO 5210 I=1,NUMVAR
        DO 5220 J=I+1,NUMVAR
          ICOL=I
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y,Y,Y,NS1,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          ICOL=J
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      X,X,X,NS1,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***********************************************
!               **  STEP 52--                                **
!               **  GENERATE CORRELATION CONFIDENCE LIMITS   **
!               ***********************************************
!
          ISTEPN='52'
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRCI')THEN
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5211)
 5211       FORMAT('***** FROM DPCRCI, BEFORE CALL DPCRC2--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,5212)I,J,NS1,MAXN
 5212       FORMAT('I,J,NS1,MAXN = ',4I8)
            CALL DPWRST('XXX','BUG ')
            DO 5215 II=1,NS1
              WRITE(ICOUT,5216)II,Y(II),X(II)
 5216         FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
 5215       CONTINUE
          ENDIF
!
          IVARID=IVARN1(I)
          IVARI2=IVARN2(I)
          IVARI3=IVARN1(J)
          IVARI4=IVARN2(J)
          CALL DPCRC2(Y,X,NS1,   &
                      ICAPSW,ICAPTY,IFORSW,   &
                      IVARID,IVARI2,IVARI3,IVARI4,   &
                      CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRCI')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(NUMVAR.GT.2)THEN
            IFLAGU='FILE'
          ELSE
            IFLAGU='ON'
          ENDIF
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(I.EQ.1 .AND. J.EQ.2)IFRST=.TRUE.
          IF(I.EQ.NUMVAR .AND. J.EQ.NUMVAR)ILAST=.TRUE.
          CALL DPCRC5(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 5220   CONTINUE
 5210 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRCI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRCI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRCI
      SUBROUTINE DPCRC2(Y1,Y2,N,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IVARID,IVARI2,IVARI3,IVARI4,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE GENERATES A CONFIDENCE LIMITS FOR THE
!              CORRELATION COEFFICIENT BASED ON FISHER'S NORMAL
!              APPROXIMATION.
!
!                LCL = TANH(Z - NORPPF(1 - ALPHA/2)/SQRT(N-3))
!                UCL = TANH(Z + NORPPF(1 - ALPHA/2)/SQRT(N-3))
!
!              WHERE
!
!                Z = TANH**(-1)(R)
!                  = LOG[(1+R)/(1-R)]/2
!
!     EXAMPLE--CORRELATION COEFICIENT Y1 Y2
!              SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N OBSERVATIONS).
!              SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N OBSERVATIONS).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/6
!     ORIGINAL VERSION--JUNE      2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 ICASA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
      PARAMETER (NUMALP=7)
      REAL ALPHA(NUMALP)
      REAL ALPHSV(NUMALP)
      REAL LOWLIM(NUMALP)
      REAL UPPLIM(NUMALP)
      REAL NORVAL(NUMALP)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/0.50, 0.75, 0.80, 0.90, 0.95, 0.99, 0.999/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='C2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCRC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y1(I),Y2(I)
   57     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************
!               **  STEP 1--                **
!               **  ERROR CHECK             **
!               ******************************
!
      IF(N.LT.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('****** ERROR IN CORRELATION CONFIDENCE LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)
  113   FORMAT('     THE NUMBER OF OBSERVATIONS IS LESS THAN FOUR.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,115)N
  115   FORMAT('     THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               *****************************************
!               **  STEP 2--                           **
!               **  CARRY OUT CALCULATIONS             **
!               **  FOR CORRELATION CONFIDENCE LIMITS  **
!               *****************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL CORR(Y1,Y2,N,IWRITE,ACORR,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL MEAN(Y1,N,IWRITE,YMEAN1,IBUGA3,IERROR)
      CALL SD(Y1,N,IWRITE,YSD1,IBUGA3,IERROR)
      CALL MEAN(Y2,N,IWRITE,YMEAN2,IBUGA3,IERROR)
      CALL SD(Y2,N,IWRITE,YSD2,IBUGA3,IERROR)
!
      DO 200 I=1,NUMALP
        ALPHT=ALPHA(I)
        CALL DPCRC3(ACORR,N,ALPHT,U,Z,   &
                    ALOWLM,AUPPLM,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        LOWLIM(I)=ALOWLM
        UPPLIM(I)=AUPPLM
        NORVAL(I)=U
  200 CONTINUE
!
      CUTL90=LOWLIM(5)
      CUTL95=LOWLIM(6)
      CUTL99=LOWLIM(7)
      CUTU90=UPPLIM(5)
      CUTU95=UPPLIM(6)
      CUTU99=UPPLIM(7)
!
!               ******************************
!               **   STEP 3-                **
!               **   WRITE OUT EVERYTHING   **
!               ******************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Confidence Limits for the Correlation Coefficient'
      NCTITL=49
      ITITLZ='(Based on Fisher Normal Approximation)'
      NCTITZ=38
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable 1: '
      WRITE(ITEXT(ICNT)(22:25),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable 2: '
      WRITE(ITEXT(ICNT)(22:25),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Variable 1:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Variable 2:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Correlation Coefficient (r):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=ACORR
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='atanh(r):'
      NCTEXT(ICNT)=9
      AVALUE(ICNT)=Z
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 5210 I=1,NUMROW
        NTOT(I)=15
 5210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='9A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='9B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CNF2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASA2='CORR'
      DO 4210 I=1,NUMALP
        ALPHSV(I)=100.*ALPHA(I)
 4210 CONTINUE
      CALL DPDT11(ALPHSV,NORVAL,NORVAL,LOWLIM,UPPLIM,   &
                  ICASA2,ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGA3,IERROR)
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRC2
      SUBROUTINE DPCRC3(R,N,ALPHA,U,Z,   &
                        ALOWLM,AUPPLM,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE GENERATES A CONFIDENCE LIMITS FOR THE
!              CORRELATION COEFFICIENT BASED ON FISHER'S NORMAL
!              APPROXIMATION.
!
!                LCL = TANH(Z - NORPPF(1 - ALPHA/2)/SQRT(N-3))
!                UCL = TANH(Z + NORPPF(1 - ALPHA/2)/SQRT(N-3))
!
!              WHERE
!
!                Z = TANH**(-1)(R)
!                  = LOG[(1+R)/(1-R)]/2
!
!     EXAMPLE--CORRELATION COEFICIENT Y1 Y2
!              SAMPLE 1 IS IN INPUT VECTOR Y1 (WITH N OBSERVATIONS).
!              SAMPLE 2 IS IN INPUT VECTOR Y2 (WITH N OBSERVATIONS).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/6
!     ORIGINAL VERSION--JUNE      2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='C3  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRC3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCRC3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,R,ALPHA
   52   FORMAT('IBUGA3,ISUBRO,N,R,ALPHA = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               **************************************
!               **  STEP 21--                       **
!               **  COMPUTE THE CONFIDENCE  LIMITS  **
!               **  FOR GIVEN VALUES OF R AND ALPHA **
!               **************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ALOWLM=CPUMIN
      AUPPLM=CPUMIN
!
      IF(R.LT.-1.0 .OR. R.GT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('**** ERROR IN CORRELATION CONFIDENCE INTERVAL--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('     THE VALUE OF R IS OUTSIDE THE (-1,1) INTERVAL.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)R
  105   FORMAT('     THE VALUE OF R = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.LT.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)
  113   FORMAT('     THE NUMBER OF OBSERVATIONS IS LESS THAN FOUR.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,115)N
  115   FORMAT('     THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ALPHSV=ALPHA
      IF(ALPHA.GT.1.0 .AND. ALPHA.LE.100.0)ALPHA=ALPHA/100.0
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)
  172   FORMAT('      THE VALUE OF ALPHA IS OUTSIDE THE (0,1) ',   &
               'INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,177)ALPHA
  177   FORMAT('      THE VALUE OF ALPHA = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ALP=ALPHA
      IF(ALP.LT.0.5)THEN
        P2=1.0-(ALP/2.0)
      ELSE
        ALP=1.0 - ALPHA
        P2=1.0-(ALP/2.0)
      ENDIF
      CALL NORPPF(P2,U)
!
      AVAL2=(1.0 + R)/(1.0 - R)
      Z=LOG(AVAL2)/2.0
!
      AN=REAL(N)
      AVAL=Z - U/SQRT(AN-3.0)
      IF(AVAL.GT.40.0)THEN
        ALOWLM=1.0
      ELSEIF(AVAL.LT.-40.0)THEN
        ALOWLM=(-1.0)
      ELSE
        ALOWLM=(EXP(AVAL) - EXP(-AVAL))/(EXP(AVAL) + EXP(-AVAL))
      ENDIF
      IF(ALOWLM.LT.-1.0)ALOWLM=-1.0
!
      AVAL=Z + U/SQRT(REAL(N)-3.0)
      IF(AVAL.GT.40.0)THEN
        AUPPLM=1.0
      ELSEIF(AVAL.LT.-40.0)THEN
        AUPPLM=(-1.0)
      ELSE
        AUPPLM=(EXP(AVAL) - EXP(-AVAL))/(EXP(AVAL) + EXP(-AVAL))
      ENDIF
      IF(AUPPLM.GT.1.0)AUPPLM=1.0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRC3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR,ALOWLM,AUPPLM,U
 9012   FORMAT('IERROR,ALOWLM,AUPPLM,U = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)AVAL2,Z,AVAL
 9014   FORMAT('AVAL2,Z,AVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRC3
      SUBROUTINE DPCRC5(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPCRCI.  THIS ROUTINE UPDATES THE
!              VARIOUS CUTOFF POINTS AFTER A CORRELATION CONFIDENCE
!              INTERVAL.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012/6
!     ORIGINAL VERSION--JUNE      2012.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      SAVE IOUNI1
!
!---------------------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRC5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCRC5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99
   54   FORMAT('CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99 = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,295)
  295     FORMAT(   &
                 7X,'CUTLOW90',7X,'CUTUPP90',7X,'CUTLOW95',   &
                 7X,'CUTUPP95',7X,'CUTLOW99',7X,'CUTUPP99')
        ENDIF
        WRITE(IOUNI1,299)CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99
  299   FORMAT(6E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
!
        IF(CUTU90.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP90'
          VALUE0=CUTU90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU95.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP95'
          VALUE0=CUTU95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU99.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP99'
          VALUE0=CUTU99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL90.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW90'
          VALUE0=CUTL90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL95.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW95'
          VALUE0=CUTL95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL99.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW99'
          VALUE0=CUTL99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRC5')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI, IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRC5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPCRC5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRC5
      SUBROUTINE DPCRLF(IHARG,NUMARG,   &
                        IDEFCR,IDEFLF,ITEXCR,ITEXLF,   &
                        IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE CARRIAGE RETURN AND LINE FEED SWITCHES
!              (ON OR OFF) FOR
!              TEXT SCRIPT.
!              THE CARRIAGE RETURN AND LINE FEED SWITCHES WILL BE PLACED
!              IN THE CHARACTER VARIABLES ITEXCR AND ITEXLF.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEFCR
!                     --IDEFLF
!                     --IBUGD2
!     OUTPUT ARGUMENTS--ITEXCR
!                     --ITEXLF
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCR
      CHARACTER*4 IDEFLF
      CHARACTER*4 ITEXCR
      CHARACTER*4 ITEXLF
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGD2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDEFCR,IDEFLF
   53 FORMAT('IDEFCR,IDEFLF = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I)
   56 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **************************************
!               **  TREAT THE CARRIAGE RETURN CASE  **
!               **************************************
!
      IF(NUMARG.LE.0)GO TO 1161
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1161
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1162
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1161
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1165
      GO TO 1170
!
 1161 CONTINUE
      ITEXCR='ON'
      ITEXLF='ON'
      GO TO 1180
!
 1162 CONTINUE
      ITEXCR='OFF'
      ITEXLF='OFF'
      GO TO 1180
!
 1165 CONTINUE
      ITEXCR=IDEFCR
      ITEXLF=IDEFLF
      GO TO 1180
!
 1170 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,1171)
 1171 FORMAT('***** ERROR IN DPCR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1172)
 1172 FORMAT('      ILLEGAL ENTRY FOR CARRIAGE RETURN ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1173)
 1173 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1174)
 1174 FORMAT('      SUPPOSE THE THE ANALYST WISHES ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1175)
 1175 FORMAT('      TO HAVE A CARRIAGE RETURN/LINE FEED ',   &
      'AFTER THE TEXT COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1177)
 1177 FORMAT('      THEN ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1178)
 1178 FORMAT('           CRLF ON')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1179)
 1179 FORMAT('           CRLF')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE CARRIAGE RETURN/LINE FEED (AFTER TEXT) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)ITEXCR
 1182 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGD2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCR')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGD2,ISUBRO,IFOUND,IERROR
 9012 FORMAT('IBUGD2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDEFCR,ITEXCR
 9013 FORMAT('IDEFCR,ITEXCR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IDEFLF,ITEXLF
 9014 FORMAT('IDEFLF,ITEXLF = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCRLF
      SUBROUTINE DPCROS(ICOM,IHARG,IHARG2,IARGT,ARG,NUMARG,   &
                        IANS,IWIDTH,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,   &
                        IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,PDSCAL,   &
                        PXMIN,PXMAX,PYMIN,PYMAX,   &
                        FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                        IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--READ THE COORDINATES OF THE CROSS-HAIR.  SUCH COORDINATES WILL
!              BE IN STANDARDIZED (0.0 TO 100.0) UNITS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED         --JANUARY   1989. CALL LIST FOR OFFSET VAR (ALAN)
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!     UPDATED         --FEBRUARY  1998. SUPPORT FORM OF COMMAND FOR GUI
!     UPDATED         --NOVEMBER  2018. RECODE FOR BETTER READABILITY
!     UPDATED         --NOVEMBER  2018. RESTRICT TO DEVICE 1 (I.E., THE
!                                       SCREEN DEVICE)
!     UPDATED         --NOVEMBER  2018. ADD "SQUARE" OPTION TO ALLOW A
!                                       RECTANGULAR REGION TO BE READ
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!
!-----NON-COMMON VARIABLES------------------------------------------------------
!
      CHARACTER*4 ICOM
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
      CHARACTER*4 IANS
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
      CHARACTER*4 IDFONT
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICOPSJ
      CHARACTER*4 IFLAGU
      CHARACTER*4 IFLAGS
!
      CHARACTER*4 IHWORD
      CHARACTER*4 IHWOR2
      CHARACTER*4 IOP
      CHARACTER*4 MESSAG
      CHARACTER*4 IFOUNN
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION IANS(*)
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IN(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION PDSCAL(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IBUGG4=IBUGD2
      ISUBG4=ISUBRO
!
      PXRATI=(-999.0)
      PYRATI=(-999.0)
      PXRANG=(-999.0)
      PYRANG=(-999.0)
      FXRANG=(-999.0)
      FYRANG=(-999.0)
      ILOCP3=(-999)
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CROS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCROS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IWIDTH,NUMARG,NUMNAM,MAXNAM,NUMDEV
   53   FORMAT('IWIDTH,NUMARG,NUMNAM,MAXNAM,NUMDEV = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)(IANS(I),I=1,MIN(25,IWIDTH))
   54   FORMAT('(IANS(I),I=1,IWIDTH) = ',25A4)
        CALL DPWRST('XXX','BUG ')
        DO 62 I=1,NUMARG
          WRITE(ICOUT,63)I,IHARG(I),IHARG2(I),IARGT(I),ARG(I)
   63     FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),ARG(I) = ',   &
                 I8,3(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
   62   CONTINUE
        DO 72 I=1,NUMNAM
          WRITE(ICOUT,73)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
                         VALUE(I)
   73     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),',   &
                 'VALUE(I) = ',I8,3(2X,A4),2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   72   CONTINUE
        WRITE(ICOUT,76)IGRASW,IDIASW
   76   FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77   FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78   FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NUMDEV
          WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82     FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
                 3(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83     FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',2(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84     FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,85)PXMIN,PXMAX,PYMIN,PYMAX
   85   FORMAT('PXMIN,PXMAX,PYMIN,PYMAX = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,86)FX1MIN,FX1MAX,FY1MIN,FY1MAX
   86   FORMAT('FX1MIN,FX1MAX,FY1MIN,FY1MAX = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,88)IBUGD2,IBUGG4,ISUBG4,IERRG4
   88   FORMAT('IBUGD2,IBUGG4,ISUBG4,IERRG4 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,89)IFOUND,IERROR
   89   FORMAT('IFOUND,IERROR= ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************************
!               **  STEP 1--                                          **
!               **  EXTRACT NEEDED INFORMATION FROM THE COMMAND LINE  **
!               ********************************************************
!
      ILOC=0
      IF(ICOM.EQ.'CH')THEN
        IF(IHARG(1).EQ.'ON' .OR. IHARG(1).EQ.'AUTO')THEN
          ILOC=1
          GO TO 1190
        ELSEIF(IHARG(1).EQ.'DEFA' .OR. IHARG(1).EQ.'OFF')THEN
          GO TO 1190
        ELSEIF(NUMARG.GE.0)THEN
          ILOC=0
          GO TO 1190
        ENDIF
!
      ELSEIF(IHARG(1).EQ.'CH' .OR. IHARG(1).EQ.'HAIR')THEN
        IF(IHARG(2).EQ.'ON' .OR. IHARG(2).EQ.'AUTO')THEN
          ILOC=2
          GO TO 1190
        ELSEIF(IHARG(2).EQ.'DEFA' .OR. IHARG(2).EQ.'OFF')THEN
          GO TO 1190
        ELSEIF(NUMARG.GE.1)THEN
          ILOC=1
          GO TO 1190
        ENDIF
!
      ELSEIF(IHARG(1).EQ.'CROS'.AND.IHARG(2).EQ.'HAIR')THEN
        IF(IHARG(3).EQ.'ON' .OR. IHARG(3).EQ.'AUTO')THEN
          ILOC=3
          GO TO 1190
        ELSEIF(IHARG(3).EQ.'OFF' .OR. IHARG(3).EQ.'DEFA')THEN
          GO TO 1190
        ELSEIF(NUMARG.GE.2)THEN
          ILOC=2
          GO TO 1190
        ENDIF
      ENDIF
!
      GO TO 9000
!
 1190 CONTINUE
!
!     NOVEMBER 2018: CHECK FOR FOLLOWING OPTIONS--
!
!                    DATA     - SPECIFY DATA UNITS
!                    SCREEN   - SPECIFY SCREEN UNITS
!                    SQUARE   - EXTRACT TWO POINTS TO DEFINE A SQUARE
!                               REGION
      IFLAGU='SCRE'
      IFLAGS='POIN'
      IF(NUMARG.GT.ILOC)THEN
        IF(IHARG(ILOC+1).EQ.'DATA')THEN
          IFLAGU='DATA'
          DO 110 II=ILOC+1,NUMARG-1
            IHARG(II)=IHARG(II+1)
            IHARG2(II)=IHARG2(II+1)
            IARGT(II)=IARGT(II+1)
            ARG(II)=ARG(II+1)
  110     CONTINUE
          IHARG(NUMARG)='    '
          IHARG2(NUMARG)='    '
          NUMARG=NUMARG-1
        ELSEIF(IHARG(ILOC+1).EQ.'SCRE')THEN
          IFLAGU='SCRE'
          DO 120 II=ILOC+1,NUMARG-1
            IHARG(II)=IHARG(II+1)
            IHARG2(II)=IHARG2(II+1)
            IARGT(II)=IARGT(II+1)
            ARG(II)=ARG(II+1)
  120     CONTINUE
          IHARG(NUMARG)='    '
          IHARG2(NUMARG)='    '
          NUMARG=NUMARG-1
        ENDIF
        IF(IHARG(ILOC+1).EQ.'SQUA')THEN
          IFLAGS='SQUA'
          DO 130 II=ILOC+1,NUMARG-1
            IHARG(II)=IHARG(II+1)
            IHARG2(II)=IHARG2(II+1)
            IARGT(II)=IARGT(II+1)
            ARG(II)=ARG(II+1)
  130     CONTINUE
          IHARG(NUMARG)='    '
          IHARG2(NUMARG)='    '
          NUMARG=NUMARG-1
        ENDIF
      ENDIF
!
!     COMPUTE SOME VALUES NEEDED TO CONVERT TO DATA UNITS
!
      PXRANG=PXMAX-PXMIN
      PYRANG=PYMAX-PYMIN
!
      FXRANG=PXRANG
      IF(FX1MIN.NE.CPUMIN.AND.FX1MIN.NE.CPUMAX.AND.   &
         FX1MAX.NE.CPUMIN.AND.FX1MAX.NE.CPUMAX)   &
         FXRANG=FX1MAX-FX1MIN
!
      FYRANG=PYRANG
      IF(FY1MIN.NE.CPUMIN.AND.FY1MIN.NE.CPUMAX.AND.   &
         FY1MAX.NE.CPUMIN.AND.FY1MAX.NE.CPUMAX)   &
         FYRANG=FY1MAX-FY1MIN
!
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CROS')THEN
        WRITE(ICOUT,2170)PXRANG,PYRANG,FXRANG,FYRANG
 2170   FORMAT('PXRANG,PYRANG,FXRANG,FYRANG = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
!CCCC FEBRUARY 1998: SUPPORT FORM OF COMMAND--
!CCCC
!CCCC                    CROSS-HAIR 22.1  34.6
!CCCC
!CCCC                FOR GUI.  THIS FORM WILL PRINT THE COORDINATES IN
!CCCC                THE MOST RECENT PLOT UNITS.
!
      IF(NUMARG.EQ.2..AND.IARGT(1).EQ.'NUMB'.AND.   &
         IARGT(2).EQ.'NUMB')THEN
        PXCOOR=ARG(1)
        PYCOOR=ARG(2)
!
        PXRATI=(-999.0)
        IF(PXRANG.GT.0.0)PXRATI=(PXCOOR-PXMIN)/PXRANG
        XCOOR=PXCOOR
        IF(FX1MIN.NE.CPUMIN.AND.FX1MIN.NE.CPUMAX.AND.   &
           FX1MAX.NE.CPUMIN.AND.FX1MAX.NE.CPUMAX)   &
           XCOOR=FX1MIN+PXRATI*FXRANG
        IF(PYRANG.LE.0.0)PYRATI=(-999.0)
        IF(PYRANG.GT.0.0)PYRATI=(PYCOOR-PYMIN)/PYRANG
        YCOOR=PYCOOR
        IF(FY1MIN.NE.CPUMIN.AND.FY1MIN.NE.CPUMAX.AND.   &
           FY1MAX.NE.CPUMIN.AND.FY1MAX.NE.CPUMAX)   &
           YCOOR=FY1MIN+PYRATI*FYRANG
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2182)XCOOR
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2183)YCOOR
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2188)
        CALL DPWRST('XXX','BUG ')
        IFOUND='YES'
        GO TO 9000
      ENDIF
!
!               ********************************
!               **  STEP 2--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
!CCCC IUPPER=NUMDEV
      IUPPER=1
      DO 8000 IDEVIC=1,IUPPER
!
        IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
        IF(IDMANU(IDEVIC).EQ.'OFF')GO TO 8000
        IF(IDMANU(IDEVIC).EQ.'NULL')GO TO 8000
        IF(IDMANU(IDEVIC).EQ.'NONE')GO TO 8000
        IF(IDMANU(IDEVIC).EQ.'DISC')GO TO 8000
!
        IMANUF=IDMANU(IDEVIC)
        IMODEL=IDMODE(IDEVIC)
        IMODE2=IDMOD2(IDEVIC)
        IMODE3=IDMOD3(IDEVIC)
        IGCONT=IDCONT(IDEVIC)
        IGCOLO=IDCOLO(IDEVIC)
        IGFONT=IDFONT(IDEVIC)
        NUMVPP=IDNVPP(IDEVIC)
        NUMHPP=IDNHPP(IDEVIC)
        ANUMVP=NUMVPP
        ANUMHP=NUMHPP
        IOFFSV=IDNVOF(IDEVIC)
        IOFFSH=IDNHOF(IDEVIC)
        IGUNIT=IDUNIT(IDEVIC)
        PCHSCA=PDSCAL(IDEVIC)
!
!               ***********************************
!               **  STEP 3--                     **
!               **  READ THE SCREEN COORDINATES  **
!               ***********************************
!
        CALL GRRESC(PXCOOR,PYCOOR)
!
!       DEFINE:
!
!           PXCOOR   - X-COORDINATE OF FIRST POINT, SCREEN UNITS
!           PYCOOR   - Y-COORDINATE OF FIRST POINT, SCREEN UNITS
!           XCOOR    - X-COORDINATE OF FIRST POINT, DATA UNITS
!           YCOOR    - Y-COORDINATE OF FIRST POINT, DATA UNITS
!           PXCOO2   - X-COORDINATE OF SECOND POINT, SCREEN UNITS
!           PYCOO2   - Y-COORDINATE OF SECOND POINT, SCREEN UNITS
!           XCOOR2   - X-COORDINATE OF SECOND POINT, DATA UNITS
!           YCOOR2   - Y-COORDINATE OF SECOND POINT, DATA UNITS
!
        IF(PXRANG.GT.0.0)PXRATI=(PXCOOR-PXMIN)/PXRANG
        XCOOR=PXCOOR
        IF(FX1MIN.NE.CPUMIN.AND.FX1MIN.NE.CPUMAX.AND.   &
           FX1MAX.NE.CPUMIN.AND.FX1MAX.NE.CPUMAX)   &
           XCOOR=FX1MIN+PXRATI*FXRANG
        IF(PYRANG.LE.0.0)PYRATI=(-999.0)
        IF(PYRANG.GT.0.0)PYRATI=(PYCOOR-PYMIN)/PYRANG
        YCOOR=PYCOOR
        IF(FY1MIN.NE.CPUMIN.AND.FY1MIN.NE.CPUMAX.AND.   &
           FY1MAX.NE.CPUMIN.AND.FY1MAX.NE.CPUMAX)   &
           YCOOR=FY1MIN+PYRATI*FYRANG
!
        PXCOO2=CPUMIN
        PYCOO2=CPUMIN
        XCOO2=CPUMIN
        YCOO2=CPUMIN
        IF(IFLAGS.EQ.'SQUA')THEN
          CALL GRRESC(PXCOO2,PYCOO2)
          IF(PXRANG.GT.0.0)PXRATI=(PXCOO2-PXMIN)/PXRANG
          XCOOR2=PXCOO2
          IF(FX1MIN.NE.CPUMIN.AND.FX1MIN.NE.CPUMAX.AND.   &
             FX1MAX.NE.CPUMIN.AND.FX1MAX.NE.CPUMAX)   &
             XCOOR2=FX1MIN+PXRATI*FXRANG
          IF(PYRANG.LE.0.0)PYRATI=(-999.0)
          IF(PYRANG.GT.0.0)PYRATI=(PYCOO2-PYMIN)/PYRANG
          YCOOR2=PYCOO2
          IF(FY1MIN.NE.CPUMIN.AND.FY1MIN.NE.CPUMAX.AND.   &
             FY1MAX.NE.CPUMIN.AND.FY1MAX.NE.CPUMAX)   &
             YCOOR2=FY1MIN+PYRATI*FYRANG
!
        ENDIF
!
!               ************************************
!               **  STEP 3.5--                    **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
        ICOPSJ='OFF'
        NUMCOJ=0
        CALL DPCLPL(ICOPSJ,NUMCOJ,   &
                    PGRAXF,PGRAYF,   &
                    IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                    PDIAHE,PDIAWI,PDIAVG,PDIAHG)
        CALL DPCLDE
!
!               ***************************************
!               **  STEP 4--                         **
!               **  UPDATE INTERNAL DATAPLOT ARRAYS  **
!               ***************************************
!
!
        IF(IFLAGU.EQ.'SCRE')THEN
          ILOCP1=ILOC+1
          IF(ILOCP1.GT.NUMARG)GO TO 2180
          IHWORD=IHARG(ILOCP1)
          IHWOR2=IHARG2(ILOCP1)
          IOP='CHAD'
          MESSAG='NO'
          CALL UPDATP(IHWORD,IHWOR2,PXCOOR,IOP,MESSAG,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          ILOCP2=ILOC+2
          IF(ILOCP2.GT.NUMARG)GO TO 2180
          IHWORD=IHARG(ILOCP2)
          IHWOR2=IHARG2(ILOCP2)
          IOP='CHAD'
          MESSAG='NO'
          CALL UPDATP(IHWORD,IHWOR2,PYCOOR,IOP,MESSAG,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         IF "SQUARE" OPTION GIVEN, THEN RETURN SECOND POINT IN SCREEN
!         UNITS.  OTHERWISE, RETURN THE FIRST POINT IN DATA UNITS.
!
          IF(IFLAGS.EQ.'POIN')THEN
            ILOCP3=ILOC+3
            IF(ILOCP3.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP3)
            IHWOR2=IHARG2(ILOCP3)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,XCOOR,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
            ILOCP4=ILOC+4
            IF(ILOCP4.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP4)
            IHWOR2=IHARG2(ILOCP4)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,YCOOR,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IFLAGS.EQ.'SQUA')THEN
            ILOCP3=ILOC+3
            IF(ILOCP3.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP3)
            IHWOR2=IHARG2(ILOCP3)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,PXCOO2,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
            ILOCP4=ILOC+4
            IF(ILOCP4.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP4)
            IHWOR2=IHARG2(ILOCP4)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,PYCOO2,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
          ENDIF
!
        ELSEIF(IFLAGU.EQ.'DATA')THEN
          ILOCP1=ILOC+1
          IF(ILOCP1.GT.NUMARG)GO TO 2180
          IHWORD=IHARG(ILOCP1)
          IHWOR2=IHARG2(ILOCP1)
          IOP='CHAD'
          MESSAG='NO'
          CALL UPDATP(IHWORD,IHWOR2,XCOOR,IOP,MESSAG,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          ILOCP2=ILOC+2
          IF(ILOCP2.GT.NUMARG)GO TO 2180
          IHWORD=IHARG(ILOCP2)
          IHWOR2=IHARG2(ILOCP2)
          IOP='CHAD'
          MESSAG='NO'
          CALL UPDATP(IHWORD,IHWOR2,YCOOR,IOP,MESSAG,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         IF "SQUARE" OPTION GIVEN, THEN RETURN SECOND POINT IN DATA
!         UNITS.  OTHERWISE, RETURN THE FIRST POINT IN SCREEN UNITS.
!
          IF(IFLAGS.EQ.'POIN')THEN
            ILOCP3=ILOC+3
            IF(ILOCP3.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP3)
            IHWOR2=IHARG2(ILOCP3)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,PXCOOR,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
            ILOCP4=ILOC+4
            IF(ILOCP4.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP4)
            IHWOR2=IHARG2(ILOCP4)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,PYCOOR,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IFLAGS.EQ.'SQUA')THEN
            ILOCP3=ILOC+3
            IF(ILOCP3.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP3)
            IHWOR2=IHARG2(ILOCP3)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,XCOOR2,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
            ILOCP4=ILOC+4
            IF(ILOCP4.GT.NUMARG)GO TO 2180
            IHWORD=IHARG(ILOCP4)
            IHWOR2=IHARG2(ILOCP4)
            IOP='CHAD'
            MESSAG='NO'
            CALL UPDATP(IHWORD,IHWOR2,YCOOR2,IOP,MESSAG,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        IANS,IWIDTH,IBUGD2,ILOCN,IFOUNN,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
          ENDIF
!
        ENDIF
!
 2180   CONTINUE
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          IF(IFLAGU.EQ.'SCRE')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2182)PXCOOR
 2182       FORMAT('X COORDINATE = ',E15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2183)PYCOOR
 2183       FORMAT('Y COORDINATE = ',E15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2184)
 2184       FORMAT('(IN 0 TO 100 UNITS)')
            CALL DPWRST('XXX','BUG ')
!
            IF(IFLAGS.EQ.'POIN')THEN
!
              IF(ILOCP3.GT.NUMARG)GO TO 2189
              IF(ICOM.EQ.'CH'.AND.NUMARG.LE.0)GO TO 2189
              IF(IHARG(1).EQ.'CH'.AND.NUMARG.LE.1)GO TO 2189
              IF(IHARG(1).EQ.'CROS'.AND.IHARG(2).EQ.'HAIR'.AND.   &
                 NUMARG.LE.2)GO TO 2189
!
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2182)XCOOR
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2183)YCOOR
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2188)
 2188         FORMAT('(IN UNITS OF THE DATA)')
              CALL DPWRST('XXX','BUG ')
            ELSEIF(IFLAGS.EQ.'SQUA')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2192)PXCOO2
 2192         FORMAT('X COORDINATE OF SECOND POINT = ',E15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2193)PYCOO2
 2193         FORMAT('Y COORDINATE OF SECOND POINT = ',E15.7)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2184)
              CALL DPWRST('XXX','BUG ')
            ENDIF
          ELSEIF(IFLAGU.EQ.'DATA')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2182)XCOOR
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2183)YCOOR
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2188)
            CALL DPWRST('XXX','BUG ')
!
            IF(IFLAGS.EQ.'POIN')THEN
!
              IF(ILOCP3.GT.NUMARG)GO TO 2189
              IF(ICOM.EQ.'CH'.AND.NUMARG.LE.0)GO TO 2189
              IF(IHARG(1).EQ.'CH'.AND.NUMARG.LE.1)GO TO 2189
              IF(IHARG(1).EQ.'CROS'.AND.IHARG(2).EQ.'HAIR'.AND.   &
                 NUMARG.LE.2)GO TO 2189
!
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2182)PXCOOR
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2183)PYCOOR
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2184)
              CALL DPWRST('XXX','BUG ')
            ELSEIF(IFLAGS.EQ.'SQUA')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2192)XCOOR2
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2193)YCOOR2
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,2188)
              CALL DPWRST('XXX','BUG ')
            ENDIF
          ENDIF
!
 2189   CONTINUE
!
      ENDIF
      GO TO 9000
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IERROR=IERRG4
      IF(IBUGG4.EQ.'ON'.OR.ISUBG4.EQ.'CROS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCROS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)PXCOOR,PYCOOR,PXCOO2,PYCOO2
 9012   FORMAT('PXCOOR,PYCOOR,PXCOO2,PYCOO2 = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ILOC,NUMNAM,MAXNAM,IFOUND
 9013   FORMAT('ILOC,NUMNAM,MAXNAM,IFOUND = ',3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9032 I=1,NUMNAM
          WRITE(ICOUT,9033)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),   &
                           IVALUE(I),VALUE(I)
 9033     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),',   &
                 'IVALUE(I),VALUE(I) = ',I8,3(2X,A4),2I8,I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9032   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCROS
      SUBROUTINE DPCRPL(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        MAXNXT,ISEED,ICONT,   &
                        ISUBRO,IBUGG2,IBUGG3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A CROSS TABULATION PLOT FOR ONE OF
!              DATAPLOT'S SUPPORTED STATISTICS
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/11
!     ORIGINAL VERSION--NOVEMBER  1999.
!     UPDATED         --APRIL     2001. ARGUMENT LIST FOR CP, CPK, CPM
!                                       ADD CPL AND CPU PLOTS
!     UPDATED         --OCTOBER   2001. HARMONIC MEAN, IQ RANGE
!     UPDATED         --NOVEMBER  2001. BIWEIGHT LOCATION
!     UPDATED         --NOVEMBER  2001. BIWEIGHT SCALE
!     UPDATED         --JULY      2002. WINSORIZED VARIANCE
!     UPDATED         --JULY      2002. WINSORIZED SD
!     UPDATED         --JULY      2002. ADD WINSORIZED COVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD WINSORIZED CORRELATION PLOT
!     UPDATED         --JULY      2002. ADD BIWEIGHT MIDVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD BIWEIGHT MIDCOVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD BIWEIGHT MIDCORRELATION PLOT
!     UPDATED         --JULY      2002. ADD PERCENTAGE BEND MIDVARIANCE
!                                           PLOT
!     UPDATED         --JULY      2002. ADD HODGES LEHMAN PLOT
!     UPDATED         --JULY      2002. ADD QUANTILE PLOT
!     UPDATED         --JULY      2002. ADD QUANTILE STANDARD ERROR PLOT
!     UPDATED         --JULY      2002. ADD TRIMMED MEAN STANDARD ERROR
!                                       PLOT
!     UPDATED         --MARCH     2003. ADD 35 "DIFFERENCE OF" STATISTICS
!     UPDATED         --MARCH     2003. ADD WEIGHTED MEAN, WEIGHTED SD,
!                                       WEIGHTED VARIANCE
!     UPDATED         --APRIL     2003. ADD SN AND QN (AND DIFFERENCE
!                                       OF).  REQUIRED ADDITION OF
!                                       ADDITIONAL SCRATCH VARIABLES.
!     UPDATED         --MAY       2003. WEIGHTED TRIMMED MEAN
!     UPDATED         --OCTOBER   2004. KENDELLS TAU
!     UPDATED         --SEPTEMBER 2005. RATIO
!     UPDATED         --MARCH     2007. RELATIVE RISK
!     UPDATED         --MARCH     2007. CRAMER CONINGENCY COEFFICIENT
!     UPDATED         --MARCH     2007. PEARSON CONINGENCY COEFFICIENT
!     UPDATED         --MARCH     2007. FALSE POSITIVE
!     UPDATED         --MARCH     2007. FALSE NEGATIVE
!     UPDATED         --MARCH     2007. TRUE POSITIVE
!     UPDATED         --MARCH     2007. TRUE NEGATIVE
!     UPDATED         --MARCH     2007. TEST SENSITIVITY
!     UPDATED         --MARCH     2007. TEST SPECIFICITY
!     UPDATED         --APRIL     2007. POSITIVE PREDICTIVE VALUE
!     UPDATED         --APRIL     2007. NEGATIVE PREDICTIVE VALUE
!     UPDATED         --APRIL     2007. LOG ODDS RATIO
!     UPDATED         --APRIL     2007. LOG ODDS RATIO STANDARD ERROR
!     UPDATED         --MAY       2007. TRIMMED STANDARD DEVIATION
!     UPDATED         --AUGUST    2007. MOVE STORAGE OF TEMPORARY
!                                       VARIABLES TO COMMON BLOCKS
!     UPDATED         --NOVEMBER  2007. LP LOCATION
!     UPDATED         --NOVEMBER  2007. DOUBLE PRECISION TEMPORARY
!                                       ARRAYS FOR CMPSTA
!     UPDATED         --NOVEMBER  2007. LP LOCATION
!     UPDATED         --NOVEMBER  2007. VARIANCE OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. SD OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF VARI OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF SD OF LP LOCATION
!     UPDATED         --SEPTEMBER 2008. BINOMIAL PROBABILITY
!     UPDATED         --SEPTEMBER 2008. DIFFERENCE OF BINOMIAL
!                                       PROBABILITY
!     UPDATED         --FEBRUARY  2009. INDEX MINIMUM
!     UPDATED         --FEBRUARY  2009. INDEX MAXIMUM
!     UPDATED         --FEBRUARY  2009. INDEX EXTREME
!     UPDATED         --FEBRUARY  2009. GRUBB
!                                       GRUBB CDF
!                                       GRUBB DIRECTION
!                                       GRUBB INDEX
!     UPDATED         --FEBRUARY  2009. ONE SAMPLE T TEST
!                                       ONE SAMPLE T TEST CDF
!     UPDATED         --FEBRUARY  2009. CHI-SQUARE SD TEST
!                                       CHI-SQUARE SD TEST CDF
!     UPDATED         --FEBRUARY  2009. FREQUENCY TEST
!                                       FREQUENCY TEST CDF
!     UPDATED         --FEBRUARY  2009. FREQUENCY WITHIN A BLOCK TEST
!                                       FREQUENCY WITHIN A BLOCK TEST CDF
!     UPDATED         --MARCH     2009. EXTRACT STATISTIC WITH "EXTSTA"
!     UPDATED         --JUNE      2010. PARSE WITH "DPPARS"
!     UPDATED         --JUNE      2010. ACCOMODATE 3 RESPONSE VARIABLES
!                                       (CMPSTA UPDATED)
!     UPDATED         --AUGUST    2023. CALL LIST TO EXTSTA, CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 ICONT
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4  ISTADF
      CHARACTER*4  ISTARA
      CHARACTER*60 ISTANM
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
!     AUGUST 2007: MOVE STORAGE OF FOLLOWING ARRAYS TO
!                  COMMON BLOCKS
!
!CCCC DIMENSION TEMP(*)
!CCCC DIMENSION TEMP2(*)
!CCCC DIMENSION TEMP3(*)
!CCCC DIMENSION XTEMP1(*)
!CCCC DIMENSION XTEMP2(*)
      DIMENSION TEMP(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
!
      INTEGER ITEMP1(MAXOBV)
      INTEGER ITEMP2(MAXOBV)
      INTEGER ITEMP3(MAXOBV)
      INTEGER ITEMP4(MAXOBV)
      INTEGER ITEMP5(MAXOBV)
      INTEGER ITEMP6(MAXOBV)
!
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      DIMENSION X1(MAXOBV)
      DIMENSION X2(MAXOBV)
      DIMENSION Y1(MAXOBV)
      DIMENSION Z1(MAXOBV)
      DIMENSION Z2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
      DIMENSION XTEMP6(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZD.INC'
!
      EQUIVALENCE (GARBAG(IGARB1),X1(1))
      EQUIVALENCE (GARBAG(IGARB2),X2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y1(1))
      EQUIVALENCE (GARBAG(IGARB4),Z1(1))
      EQUIVALENCE (GARBAG(IGARB5),Z2(1))
      EQUIVALENCE (GARBAG(IGARB6),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB7),XTEMP4(1))
      EQUIVALENCE (GARBAG(IGARB9),TEMP(1))
      EQUIVALENCE (GARBAG(IGAR10),TEMP2(1))
      EQUIVALENCE (GARBAG(JGAR11),TEMP3(1))
      EQUIVALENCE (GARBAG(JGAR12),TEMP4(1))
      EQUIVALENCE (GARBAG(JGAR13),XTEMP1(1))
      EQUIVALENCE (GARBAG(JGAR14),XTEMP2(1))
      EQUIVALENCE (GARBAG(JGAR15),XTEMP5(1))
      EQUIVALENCE (GARBAG(JGAR16),XTEMP6(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR2),ITEMP2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP3(1))
      EQUIVALENCE (IGARBG(IIGAR4),ITEMP4(1))
      EQUIVALENCE (IGARBG(IIGAR5),ITEMP5(1))
      EQUIVALENCE (IGARBG(IIGAR6),ITEMP6(1))
!
      EQUIVALENCE (DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR2),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR3),DTEMP3(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBN1='CRPL'
      ISUBN2='    '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MAXV2=2
      MINN2=2
!
      IXVAR='OFF'
      IX2VAR='OFF'
      IYVAR='ON'
!
!               ******************************************
!               **  TREAT THE CROSS TABULATE PLOT CASE  **
!               ******************************************
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCRPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICONT,ISUBRO,IBUGG2,IBUGG3,IBUGQ
   52   FORMAT('ICONT,ISUBRO,IBUGG2,IBUGG3,IBUGQ  = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2
   53   FORMAT('ICASPL,IAND1,IAND2 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************
!               **  STEP 1--                       **
!               **  EXTRACT THE COMMAND            **
!               **  COMMAND SYNTAX IS:             **
!               **  CROSS TABULATE <STAT> PLOT     **
!               *************************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.2)GO TO 9000
      IF(ICOM.NE.'CROS')GO TO 9000
      IF(IHARG(1).NE.'TABU')GO TO 9000
!
!CCCC MARCH 2009: USE "EXTSTA" TO PARSE.  NOTE THAT IF NO
!CCCC             STATISTIC IS GIVEN, WE ASSUME THE "COUNTS"
!CCCC             CASE.
!
      JMIN=2
      JMAX=MIN(NUMARG,JMIN+6)
      DO 200 I=JMIN,JMAX
        IF(IHARG(I).EQ.'PLOT')THEN
          JMAX=I-1
          ILASTC=I
          GO TO 209
        ENDIF
  200 CONTINUE
      IFOUND='NO'
      GO TO 9000
  209 CONTINUE
!
      CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                  ICASPL,ISTANM,ISTANR,ISTADF,ISTARA,IFOUND,ILOCV,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IFOUND.EQ.'YES')THEN
        IF(ISTANR.GE.2)IXVAR='ON'
        IF(ISTANR.GE.3)IX2VAR='ON'
        IF(ICASPL.EQ.'NUMB')IYVAR='OFF'
      ELSE
        ICASPL='NUMB'
        IYVAR='OFF'
        IXVAR='OFF'
        ILOCV=2
        IFOUND='YES'
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      INAME='CROSS TABULATE PLOT'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=-99
      MAXNVA=-99
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!     NEED FOLLOWING VARIABLES:
!     1) TWO GROUP-ID VARIABLE
!     2) ONE RESPONSE VARIABLE FOR STATISTICS THAT REQUIRE ONE VARIABLE
!     3) TWO RESPONSE VARIABLES FOR STATISTICS THAT REQUIRE TWO VARIABLES
!     4) THREE RESPONSE VARIABLES FOR STATISTICS THAT REQUIRE THREE
!        VARIABLES
!
      IF(ICASPL.EQ.'NUMB')ISTANR=0
      MINVAR=2+ISTANR
      IF(NUMVAR.NE.MINVAR)THEN
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,211)ISTANA
  211   FORMAT('***** ERROR IN CROSS TABULATE PLOT COMMAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,212)MINVAR
  212   FORMAT('      EXACTLY ',I5,' VARIABLES REQUIRED, BUT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)NUMVAR
  213   FORMAT('      ',I8,' VARIABLES WERE GIVEN.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,215)
  215   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,216)(IANS(J),J=1,MIN(80,IWIDTH))
  216     FORMAT('      ',80A1)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               ********************************
!               **  STEP 3--                  **
!               **  EXTRACT THE DATA          **
!               ********************************
!
      ISTEPN='3'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      J=0
      IMAX=NRIGHT(1)
      IF(NQ.LT.IMAX)IMAX=NQ
      DO 2660 I=1,IMAX
        IF(ISUB(I).EQ.0)GO TO 2660
        J=J+1
!
        IF(IYVAR.EQ.'OFF')THEN
          Y1(J)=0.0
        ELSE
          ICOLL=ICOLR(1)
          IJ=MAXN*(ICOLL-1)+I
          IF(ICOLL.LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLL.EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLL.EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLL.EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLL.EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLL.EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLL.EQ.MAXCP6)Y1(J)=TAGPLO(I)
        ENDIF
        ICNT=1
!
        IF(IXVAR.EQ.'OFF')THEN
          Z1(J)=0.0
        ELSE
          ICNT=ICNT+1
          ICOLX=ICOLR(ICNT)
          IJ=MAXN*(ICOLX-1)+I
          IF(ICOLX.LE.MAXCOL)Z1(J)=V(IJ)
          IF(ICOLX.EQ.MAXCP1)Z1(J)=PRED(I)
          IF(ICOLX.EQ.MAXCP2)Z1(J)=RES(I)
          IF(ICOLX.EQ.MAXCP3)Z1(J)=YPLOT(I)
          IF(ICOLX.EQ.MAXCP4)Z1(J)=XPLOT(I)
          IF(ICOLX.EQ.MAXCP5)Z1(J)=X2PLOT(I)
          IF(ICOLX.EQ.MAXCP6)Z1(J)=TAGPLO(I)
        ENDIF
!
        IF(IX2VAR.EQ.'OFF')THEN
          Z2(J)=0.0
        ELSE
          ICNT=ICNT+1
          ICOLX=ICOLR(ICNT)
          IJ=MAXN*(ICOLX-1)+I
          IF(ICOLX.LE.MAXCOL)Z2(J)=V(IJ)
          IF(ICOLX.EQ.MAXCP1)Z2(J)=PRED(I)
          IF(ICOLX.EQ.MAXCP2)Z2(J)=RES(I)
          IF(ICOLX.EQ.MAXCP3)Z2(J)=YPLOT(I)
          IF(ICOLX.EQ.MAXCP4)Z2(J)=XPLOT(I)
          IF(ICOLX.EQ.MAXCP5)Z2(J)=X2PLOT(I)
          IF(ICOLX.EQ.MAXCP6)Z2(J)=TAGPLO(I)
        ENDIF
!
        ICNT=ICNT+1
        ICOLH=ICOLR(ICNT)
        IJ=MAXN*(ICOLH-1)+I
        IF(ICOLH.LE.MAXCOL)X1(J)=V(IJ)
        IF(ICOLH.EQ.MAXCP1)X1(J)=PRED(I)
        IF(ICOLH.EQ.MAXCP2)X1(J)=RES(I)
        IF(ICOLH.EQ.MAXCP3)X1(J)=YPLOT(I)
        IF(ICOLH.EQ.MAXCP4)X1(J)=XPLOT(I)
        IF(ICOLH.EQ.MAXCP5)X1(J)=X2PLOT(I)
        IF(ICOLH.EQ.MAXCP6)X1(J)=TAGPLO(I)
!
        ICNT=ICNT+1
        ICOLH2=ICOLR(ICNT)
        IJ=MAXN*(ICOLH2-1)+I
        IF(ICOLH2.LE.MAXCOL)X2(J)=V(IJ)
        IF(ICOLH2.EQ.MAXCP1)X2(J)=PRED(I)
        IF(ICOLH2.EQ.MAXCP2)X2(J)=RES(I)
        IF(ICOLH2.EQ.MAXCP3)X2(J)=YPLOT(I)
        IF(ICOLH2.EQ.MAXCP4)X2(J)=XPLOT(I)
        IF(ICOLH2.EQ.MAXCP5)X2(J)=X2PLOT(I)
        IF(ICOLH2.EQ.MAXCP6)X2(J)=TAGPLO(I)
!
 2660 CONTINUE
      NLOCAL=J
!
!               ******************************************************
!               **  STEP 28--                                       **
!               **  COMPUTE THE APPROPRIATE STATISTIC PLOT STATISTIC--
!               **  (MEAN, STANDARD DEVIATION, RANGE, OR CUSUM).    **
!               **  COMPUTE CONFIDENCE LINES.                       **
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS           **
!               **  VALUES Y(.) AND X(.) FOR THE PLOT.              **
!               **  DEFINE THE VECTOR D(.) TO 1'S, 2'S, AND 3'S     **
!               **  FOR THE PLOTTED VALUE, THE LOWER CONFIDENCE LINE,*
!               **  AND THE UPPER CONFIDENCE LINE.                  **
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).   **
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).   **
!               ******************************************************
!
      ISTEPN='28'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCRP2(Y1,Z1,Z2,X1,X2,NLOCAL,NUMV2,ISTANR,ICASPL,ISIZE,ICONT,   &
                  TEMP,TEMP2,TEMP3,TEMP4,   &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,XTEMP6,MAXNXT,   &
                  ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  ICTBDI,ISTARA,   &
                  Y,X,D,X3D,NPLOTP,NPLOTV,ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'COUN')THEN
        ICASPL='CTCO'
      ELSE
        IF(ICTBDI.EQ.'2')THEN
          ICASPL='CTA2'
        ELSE
          ICASPL='CTAB'
        ENDIF
      ENDIF
!
!
!               *************************************************
!               **  STEP 29--                                  **
!               **  SAVE DIFFERENCE BETWEEN HIGHEST VALUE AND  **
!               **  LOWEST VALUE OF STATISTIC IN INTERNAL      **
!               **  PARAMETER ALOWHIGH                         **
!               *************************************************
      AMINS=CPUMAX
      AMAXS=CPUMIN
      DO 2910 I=1,NPLOTP
        IF(D(I).NE.1.0)GO TO 2910
        IF(Y(I).GT.AMAXS)AMAXS=Y(I)
        IF(Y(I).LT.AMINS)AMINS=Y(I)
 2910 CONTINUE
      ADIFF=0.0
      IF(AMINS.NE.CPUMAX.AND.AMAXS.NE.CPUMIN)ADIFF=AMAXS-AMINS
!
      ISUBN0='DPCR'
      IH='ALOW'
      IH2='HIGH'
      VALUE0=ADIFF
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGG3,IERROR)
!
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CRPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICONT,ISUBRO,IBUGG2,IBUGG3,IBUGQ
 9012   FORMAT('ICONT,ISUBRO,IBUGG2,IBUGG3,IBUGQ  = ',   &
               A4,2X,A4,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR
 9013   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9014   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ISIZE,NUMV2
 9015   FORMAT('ISIZE,NUMV2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)IHLEFT,IHLEF2,ICOLL,NLEFT
 9017   FORMAT('IHLEFT,IHLEF2,ICOLL,NLEFT = ',A4,2X,A4,I8,I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMV2.GE.2)THEN
          WRITE(ICOUT,9018)IHHOR,IHHOR2,ICOLH,NHOR
 9018     FORMAT('IHHOR,IHHOR2,ICOLH,NHOR = ',A4,2X,A4,I8,I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IF(NUMV2.GE.3)THEN
          WRITE(ICOUT,9019)IHX,IHX2,ICOLX,NX
 9019     FORMAT('IHX,IHX2,ICOLX,NX = ',A4,2X,A4,I8,I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!CCCC   THE FOLLOWING LINE WAS CHANGED SEPTEMBER 1992
!CCCC   IF(NPLOTP.LE.0)GO TO 9090
        IF(IFOUND.EQ.'YES'.AND.NPLOTP.GT.0)THEN
          DO 9025 I=1,NPLOTP
            WRITE(ICOUT,9026)I,Y(I),X(I),D(I)
 9026       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9025     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRPL
      SUBROUTINE DPCRP2(Y,Z,Z2,TAG1,TAG2,N,NUMV2,ISTANR,ICASPL,   &
                        ISIZE,ICONT,   &
                        TEMP,TEMPZ,TEMPZ2,XIDTEM,XIDTE2,   &
                        XTEMP1,XTEMP2,XTEMP4,XTEMP5,XTEMP6,MAXNXT,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ICTBDI,ISTARA,   &
                        Y2,X2,D2,X3D,N2,NPLOTV,ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE
!              A PLOT FOR ONE OF DATAPLOT'S SUPPORTED STATISTICS
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/11
!     ORIGINAL VERSION--NOVEMBER  1999.
!     UPDATED         --JULY      2002. WINSORIZED VARIANCE
!     UPDATED         --JULY      2002. WINSORIZED SD
!     UPDATED         --JULY      2002. ADD WINSORIZED COVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD WINSORIZED CORRELATION PLOT
!     UPDATED         --JULY      2002. ADD BIWEIGHT MIDVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD BIWEIGHT MIDCOVARIANCE PLOT
!     UPDATED         --JULY      2002. ADD PERCENTAGE BEND MIDVARIANCE
!                                           PLOT
!     UPDATED         --JULY      2002. ADD HODGES LEHMAN PLOT
!     UPDATED         --JULY      2002. ADD QUANTILE PLOT
!     UPDATED         --JULY      2002. ADD QUANTILE STANDARD ERROR PLOT
!     UPDATED         --JULY      2002. ADD TRIMMED MEAN STANDARD ERROR
!                                       PLOT
!     UPDATED         --APRIL     2003. ADD SN AND QN
!     UPDATED         --JUNE      2010. ADD Z2/TEMPZ2 TO CALL LIST
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 ICONT
      CHARACTER*4 ICTBDI
      CHARACTER*4 ISTARA
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION X3D(*)
!
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP4(*)
      DIMENSION XTEMP5(*)
      DIMENSION XTEMP6(*)
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='P2  '
      IWRITE='OFF'
!
      I2=0
      ISIZE2=0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CRP2')THEN
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF DPCRP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)IBUGG3,ISUBRO,ICASPL,ICONT,N
   71   FORMAT('IBUGG3,ISUBRO,ICASPL,ICONT,N = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y(I),Z(I),Z2(I),TAG1(I),TAG2(I)
   74     FORMAT('I, Y(I),Z(I),Z2(I),TAG1(I)TAG2(I) = ',I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
        WRITE(ICOUT,75)ISIZE,NUMV2
   75   FORMAT('ISIZE,NUMV2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN CROSS TABULATE PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 1;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES         **
!               **  FOR THE GROUP VARIABLES (TAG1, TAG2)            **
!               **  IF ALL VALUES ARE DISTINCT, THEN THIS           **
!               **  IMPLIES WE HAVE THE NO REPLICATION CASE         **
!               **  WHICH IS AN ERROR CONDITION FOR A PLOT.         **
!               ******************************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CRP2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(TAG1,N,IWRITE,XIDTEM,NUMSE1,IBUGG3,IERROR)
      CALL SORT(XIDTEM,NUMSE1,XIDTEM)
      CALL DISTIN(TAG2,N,IWRITE,XIDTE2,NUMSE2,IBUGG3,IERROR)
      CALL SORT(XIDTE2,NUMSE2,XIDTE2)
!
      IF(NUMSE1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      NUMBER OF SETS    NUMSE1 = 0 ')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMSE2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,194)
  194   FORMAT('      NUMBER OF SETS    NUMSE2 = 0 ')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMSE1.EQ.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,196)NUMSE1
  196   FORMAT('      NUMBER OF SETS FOR GROUP 1 VARIABLE ',I8,   &
               ' IDENTICAL TO ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,197)N
  197   FORMAT('      NUMBER OF OBSERVATIONS ',I8,' .')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMSE2.EQ.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,206)NUMSE2
  206   FORMAT('      NUMBER OF SETS FOR GROUP 2 VARIABLE ',I8,   &
               ' IDENTICAL TO ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,197)N
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      ANUMS1=NUMSE1
      ANUMS2=NUMSE2
!
!               ****************************************************
!               **  STEP 11--                                     **
!               **  COMPUTE THE SPECIFIED STATISTIC               **
!               **  FOR EACH CROSS-TAB CATEGORY OF THE DATA, AND  **
!               **  THEN FOR THE FULL DATA SET                    **
!               ****************************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CRP2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      J=0
      ATAG=1.0
!
      AINC=0.4/REAL(NUMSE2)
      ICASP2=ICASPL
      IF(ICASPL.EQ.'COUN')ICASP2='NUMB'
      DO 11000 ISET1=1,NUMSE1
!CCCC ATAG=ATAG+1.0
      DO 12000 ISET2=1,NUMSE2
!
        K=0
        ASTRT=XIDTEM(ISET1)-0.2
        DO 11011 I=1,N
        IF(TAG1(I).EQ.XIDTEM(ISET1).AND.TAG2(I).EQ.XIDTE2(ISET2))THEN
          K=K+1
          TEMP(K)=Y(I)
          TEMPZ(K)=Z(I)
          TEMPZ2(K)=Z2(I)
        ENDIF
11011   CONTINUE
        NS2=K
        IF(NS2.LT.1)GO TO 12000
        CALL DPCRP3(ICASP2,TEMP,TEMPZ,TEMPZ2,NS2,XTEMP1,XTEMP2,XTEMP4,   &
                    XTEMP5,XTEMP6,MAXNXT,RIGHT,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISTANR,ISTARA,   &
                    ISUBRO,IBUGG3,IERROR)
        J=J+1
        IF(ICASPL.NE.'COUN'.AND.ICTBDI.EQ.'1')THEN
          Y2(J)=RIGHT
          X2(J)=ASTRT + REAL(ISET2-1)*AINC
          D2(J)=ATAG
        ELSE
          Y2(J)=REAL(XIDTE2(ISET2))
          X2(J)=REAL(XIDTEM(ISET1))
          X3D(J)=RIGHT
!CCCC     D2(J)=RIGHT
          D2(J)=1.0
        ENDIF
12000 CONTINUE
11000 CONTINUE
!
      IF(ICASPL.EQ.'COUN')GO TO 13000
      IF(ICTBDI.EQ.'2')GO TO 13000
      ATAG=2.0
      DO 10500 ISET1=1,NUMSE1
        K=0
        DO 10550 I=1,N
          IF(TAG1(I).EQ.XIDTEM(ISET1))THEN
            K=K+1
            TEMP(K)=Y(I)
            TEMPZ(K)=Z(I)
            TEMPZ2(K)=Z2(I)
          ENDIF
10550   CONTINUE
        NS2=K
        IF(NS2.LT.1)GO TO 10500
        CALL DPCRP3(ICASPL,TEMP,TEMPZ,TEMPZ2,NS2,XTEMP1,XTEMP2,XTEMP4,   &
                    XTEMP5,XTEMP6,MAXNXT,RIGHT,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISTANR,ISTARA,   &
                    ISUBRO,IBUGG3,IERROR)
        J=J+1
        ATAG=ATAG+1.0
        Y2(J)=RIGHT
        X2(J)=XIDTEM(ISET1)-0.2
        D2(J)=ATAG
        J=J+1
        Y2(J)=RIGHT
        X2(J)=XIDTEM(ISET1)+0.2
        D2(J)=ATAG
10500 CONTINUE
!
      DO 10100 I=1,N
        TEMP(I)=Y(I)
        TEMPZ(I)=Z(I)
        TEMPZ2(I)=Z2(I)
10100 CONTINUE
      NS2=N
      CALL DPCRP3(ICASPL,TEMP,TEMPZ,TEMPZ2,NS2,XTEMP1,XTEMP2,XTEMP4,   &
                  XTEMP5,XTEMP6,MAXNXT,RIGHT,   &
                  ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  ISTANR,ISTARA,   &
                  ISUBRO,IBUGG3,IERROR)
      ATAG=2.0
      J=J+1
      Y2(J)=RIGHT
      X2(J)=XIDTEM(1)-0.2
      D2(J)=ATAG
      J=J+1
      Y2(J)=RIGHT
      X2(J)=XIDTEM(NUMSE1)+0.2
      D2(J)=ATAG
!
13000 CONTINUE
      N2=J
      NPLOTV=3
      GO TO 9000
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CRP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGG3,ISUBRO
 9012   FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ICASPL,N,NUMSE1,NUMSE2,N2,IERROR
 9013   FORMAT('ICASPL,N,NUMSE1,NUMSE2,N2,IERROR = ',A4,4I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,2E15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRP2
      SUBROUTINE DPCRP3(ICASPL,TEMP,TEMPZ,TEMPZ3,NS2,   &
                        XTEMP1,XTEMP2,XTEMP3,   &
                        XTEMP5,XTEMP6,MAXNXT,RIGHT,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISTANR,ISTARA,   &
                        ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--FOR CROSS-TABULATE PLOT, GENERATE VALUE OF
!              STATISTIC.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/11
!     ORIGINAL VERSION--NOVEMBER  1999.
!     UPDATED         --AUGUST    2002. USE "CMPSTA" TO COMPUTE THE
!                                       DESIRED STATISTIC
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISTARA
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ3(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XTEMP5(*)
      DIMENSION XTEMP6(*)
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='P3  '
!
      IWRITE='OFF'
!
      CALL CMPSTA(TEMP,TEMPZ,TEMPZ3,XTEMP1,XTEMP2,XTEMP3,   &
                  XTEMP5,XTEMP6,MAXNXT,   &
                  NS2,NS2,NS2,ISTANR,ICASPL,ISTARA,   &
                  ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                  DTEMP1,DTEMP2,DTEMP3,   &
                  RIGHT,   &
                  ISUBRO,IBUGG3,IERROR)
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CRP3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRP3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGG3,ISUBRO
 9012   FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ICASPL,NS2,IERROR
 9013   FORMAT('ICASPL,NS2,IERROR = ',A4,I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NS2
          WRITE(ICOUT,9021)I,TEMP(I),TEMPZ(I)
 9021     FORMAT('I,TEMP(I),TEMPZ(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRP3
      SUBROUTINE DPCRTA(Y1,ISEED,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A CROSS-TABULATION FOR ONE OF DATAPLOT'S
!              SUPPORTED STATISTICS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/12
!     ORIGINAL VERSION--NOVEMBER  1989.
!     UPDATED         --JUNE      1990.  TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --OCTOBER   1992. ADD SUMS AND CHI-SQUARE
!     UPDATED         --AUGUST    2002. EXPAND LIST OF SUPPORTED
!                                       STATISTICS
!     UPDATED         --MARCH     2003. WEIGHTED MEAN, WEIGHTED SD,
!                                       WEIGHTED VARIANCE
!     UPDATED         --MARCH     2003. 35 "DIFFERENCE OF" STATISTICS
!     UPDATED         --APRIL     2003. SN AND QN (AND DIFFERENCE OF)
!                                       REQUIRED ADDITION OF
!                                       ADDITIONAL SCRATCH ARRAYS
!     UPDATED         --MAY       2003. WEIGHTED TRIMMED MEAN
!     UPDATED         --OCTOBER   2004. KENDELLS TAU
!     UPDATED         --SEPTEMBER 2005. RATIO
!     UPDATED         --MARCH     2007. RELATIVE RISK
!     UPDATED         --MARCH     2007. CRAMER CONTINGENCY COEFFICIENT
!     UPDATED         --MARCH     2007. PEARSON CONTINGENCY COEFFICIENT
!     UPDATED         --MARCH     2007. FALSE POSITIVE
!     UPDATED         --MARCH     2007. FALSE NEGATIVE
!     UPDATED         --MARCH     2007. TRUE POSITIVE
!     UPDATED         --MARCH     2007. TRUE NEGATIVE
!     UPDATED         --MARCH     2007. TEST SENSITIVITY
!     UPDATED         --MARCH     2007. TEST SPECIFICITY
!     UPDATED         --APRIL     2007. POSITIVE PREDICTIVE VALUE
!     UPDATED         --APRIL     2007. NEGATIVE PREDICTIVE VALUE
!     UPDATED         --APRIL     2007. ODDS RATIO
!     UPDATED         --APRIL     2007. STANDARD ERROR ODDS RATIO
!     UPDATED         --APRIL     2007. LOG ODDS RATIO
!     UPDATED         --APRIL     2007. LOG STANDARD ERROR ODDS RATIO
!     UPDATED         --NOVEMBER  2007. DOUBLE PRECISION ARRAYS FOR
!                                       CMPSTA
!     UPDATED         --NOVEMBER  2007. LP LOCATION
!     UPDATED         --NOVEMBER  2007. VARIANCE OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. SD OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF VARI OF LP LOCATION
!     UPDATED         --NOVEMBER  2007. DIFFERENCE OF SD OF LP LOCATION
!     UPDATED         --APRIL     2008. SUPPORT FOR 3, 4, 5, OR 6
!                                       CROSS-TABULATION VARIABLES
!     UPDATED         --APRIL     2008. SUPPORT FOR RTF
!     UPDATED         --APRIL     2008. SINCE THERE IS NOW A SEPARATE
!                                       "CHI-SQUARE INDEPENDENCE" TEST
!                                       REMOVE IT FROM HERE
!     UPDATED         --APRIL     2008. "BINOMIAL PROBABILITY" OPTION
!                                       (THIS RECIEVES SPECIAL
!                                       HANDLING)
!     UPDATED         --FEBRUARY  2009. INDEX MINIMUM
!     UPDATED         --FEBRUARY  2009. INDEX MAXIMUM
!     UPDATED         --FEBRUARY  2009. INDEX EXTREME
!     UPDATED         --FEBRUARY  2009. GRUBB
!                                       GRUBB CDF
!                                       GRUBB DIRECTION
!                                       GRUBB INDEX
!     UPDATED         --FEBRUARY  2009. ONE SAMPLE T TEST
!                                       ONE SAMPLE T TEST CDF
!     UPDATED         --FEBRUARY  2009. CHI-SQUARE SD TEST
!                                       CHI-SQUARE SD TEST CDF
!     UPDATED         --FEBRUARY  2009. FREQUENCY TEST
!                                       FREQUENCY TEST CDF
!     UPDATED         --FEBRUARY  2009. FREQUENCY WITHIN A BLOCK TEST
!                                       FREQUENCY WITHIN A BLOCK TEST CDF
!     UPDATED         --MARCH     2009. PARSE WITH "EXTSTA"
!     UPDATED         --FEBRUARY  2010. USE DPPARS
!     UPDATED         --FEBRUARY  2010. HANDLE ONE GROUP-ID VARIABLE
!                                       CASE
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --MAY       2014. SUPPORT UP TO 8 CROSS-TAB
!                                       VARIABLES
!     UPDATED         --APRIL     2018. CROSS TABULATE LIMITS OPTION
!     UPDATED         --JULY      2019. TWEAK USE OF SCRATCH SPACE
!     UPDATED         --AUGUST    2023. CALL LIST TO EXTSTA, CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*40 ICTNAM
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IFLAGL
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=12)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
      CHARACTER*8 IX6NAM
      CHARACTER*8 IX7NAM
      CHARACTER*8 IX8NAM
!
      CHARACTER*4 ISTADF
      CHARACTER*4 ISTARA
      CHARACTER*60 ISTANM
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZD.INC'
!
      DIMENSION Y1(*)
!
      PARAMETER (MAXGR9=8)
      DIMENSION XH1DIS(MAXOBV,MAXGR9)
      DIMENSION XDESGN(MAXOBV,MAXGR9)
      DIMENSION TEMP(MAXOBV)
      DIMENSION TEMPZ(MAXOBV)
      DIMENSION TEMPZ2(MAXOBV)
      DIMENSION XTEMP1(MAXOBV)
      DIMENSION Z1(MAXOBV)
      DIMENSION Z2(MAXOBV)
      DIMENSION XTEMP2(MAXOBV)
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP6(MAXOBV)
      DIMENSION XTEMP7(MAXOBV)
      DIMENSION XNTRIA(MAXOBV)
      DIMENSION XACLOW(MAXOBV)
      DIMENSION XACUPP(MAXOBV)
      DIMENSION XTEMP8(MAXOBV)
      DIMENSION XTEMP9(MAXOBV)
!
      DIMENSION ITEMP1(MAXOBV)
      DIMENSION ITEMP2(MAXOBV)
      DIMENSION ITEMP3(MAXOBV)
      DIMENSION ITEMP4(MAXOBV)
      DIMENSION ITEMP5(MAXOBV)
      DIMENSION ITEMP6(MAXOBV)
!
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),TEMP(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMPZ(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB4),XTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB5),Z1(1))
      EQUIVALENCE (GARBAG(IGARB6),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB7),XNTRIA(1))
      EQUIVALENCE (GARBAG(IGARB8),XACLOW(1))
      EQUIVALENCE (GARBAG(IGARB9),XACUPP(1))
      EQUIVALENCE (GARBAG(IGAR10),Z2(1))
      EQUIVALENCE (GARBAG(JGAR11),TEMPZ2(1))
      EQUIVALENCE (GARBAG(JGAR12),XTEMP6(1))
      EQUIVALENCE (GARBAG(JGAR13),XTEMP7(1))
      EQUIVALENCE (GARBAG(JGAR14),XH1DIS(1,1))
      EQUIVALENCE (GARBAG(IGAR13),XTEMP8(1))
      EQUIVALENCE (GARBAG(IGAR14),XTEMP9(1))
      EQUIVALENCE (GARBAG(IGAR15),XDESGN(1,1))
!
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR2),ITEMP2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP3(1))
      EQUIVALENCE (IGARBG(IIGAR4),ITEMP4(1))
      EQUIVALENCE (IGARBG(IIGAR5),ITEMP5(1))
      EQUIVALENCE (IGARBG(IIGAR6),ITEMP6(1))
!
      EQUIVALENCE (DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR2),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR3),DTEMP3(1))
!
!CCCC END CHANGE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPCR'
      ISUBN2='TA  '
!
      IYNAM=' '
      IXNAM=' '
      IXNAM2=' '
      IX1NAM=' '
      IX2NAM=' '
      IX3NAM=' '
      IX4NAM=' '
      IX5NAM=' '
      IX6NAM=' '
      IX7NAM=' '
      IX8NAM=' '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MINN2=1
!
!               ******************************************
!               **  TREAT THE CROSS-TABULATION    CASE  **
!               ******************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRTA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCRTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASCT,IBUGA2,IBUGA3,IBUGQ
   53   FORMAT('ICASCT,IBUGA2,IBUGA3,IBUGQ = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *******************************************************
!               **  STEP 1.5--                                       **
!               **  SEARCH FOR CROSS-TABULATE CHI-SQUARE             **
!               *******************************************************
!
      ICASCT='CSCT'
      IYVAR='ON'
      IXVAR='OFF'
      IX2VAR='OFF'
      IFLAGL='OFF'
!
      IF(ICOM.EQ.'CROS' .AND. IHARG(1).EQ.'TABU')THEN
        JMIN=2
        IF(IHARG(2).EQ.'LIMI')THEN
          JMIN=3
          IFLAGL='ON'
        ENDIF
      ELSEIF(ICOM.EQ.'TABU')THEN
        JMIN=1
        IF(IHARG(1).EQ.'LIMI')THEN
          JMIN=2
          IFLAGL='ON'
        ENDIF
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
      JMAX=MIN(NUMARG,JMIN+6)
!
!CCCC MARCH 2009: USE "EXTSTA" TO PARSE.  NOTE THAT IF NO
!CCCC             STATISTIC IS GIVEN, WE ASSUME THE "COUNTS"
!CCCC             CASE.
!
      CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,   &
                  JMIN,JMAX,   &
                  ICASCT,ISTANM,ISTANR,ISTADF,ISTARA,   &
                  IFOUND,ILOCV,ISUBRO,IBUGA3,IERROR)
!
      IF(IFOUND.EQ.'YES')THEN
        ICTNAM(1:40)=ISTANM(1:40)
        IYVAR='ON'
        IXVAR='OFF'
        IX2VAR='OFF'
        IF(ISTANR.GE.2)IXVAR='ON'
        IF(ISTANR.GE.3)IX2VAR='ON'
        IF(ICASCT.EQ.'NUMB')THEN
          IYVAR='OFF'
          ISTANR=0
        ENDIF
      ELSE
        ICASCT='NUMB'
        ICTNAM='NUMBER'
        IYVAR='OFF'
        IXVAR='OFF'
        IX2VAR='OFF'
        ISTANR=0
        IFOUND='YES'
        ILOCV=JMIN
      ENDIF
!
      ILASTC=ILOCV-1
      IF(ILASTC.GE.1)THEN
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CROSS TABULATE'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=8 + ISTANR
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ****************************************
!               **  STEP 3--                          **
!               **  EXTRACT THE DATA                  **
!               ****************************************
!
      NRESP=ISTANR
      NCRTV=NUMVAR-NRESP
      IF(NCRTV.LT.1 .OR. NCRTV.GT.8)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
  301   FORMAT('****** ERROR IN CROSS TABULATE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,302)
  302   FORMAT('       THE NUMBER OF GROUP-ID VARIABLES IS LESS THAN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)
  303   FORMAT('       OR GREATER THAN EIGHT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,304)NGROUP
  304   FORMAT('       THE NUMBER OF GROUP-ID VARIABLES   = ',I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,305)NRESP
  305   FORMAT('       THE NUMBER OF RESPONSE VARIABLES   = ',I5)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      J=0
      DO 2660 I=1,NRIGHT(1)
        ICOLH=0
        IF(ISUB(I).EQ.0)GO TO 2660
        J=J+1
!
        IF(NRESP.GE.1)THEN
          ICOLH=ICOLH+1
          IJ=MAXN*(ICOLR(ICOLH)-1)+I
          IF(ICOLR(ICOLH).LE.MAXCOL)Y1(J)=V(IJ)
          IF(ICOLR(ICOLH).EQ.MAXCP1)Y1(J)=PRED(I)
          IF(ICOLR(ICOLH).EQ.MAXCP2)Y1(J)=RES(I)
          IF(ICOLR(ICOLH).EQ.MAXCP3)Y1(J)=YPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP4)Y1(J)=XPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP5)Y1(J)=X2PLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP6)Y1(J)=TAGPLO(I)
        ELSE
          Y1(J)=0.0
        ENDIF
!
        IF(NRESP.GE.2)THEN
          ICOLH=ICOLH+1
          IJ=MAXN*(ICOLR(ICOLH)-1)+I
          IF(ICOLR(ICOLH).LE.MAXCOL)Z1(J)=V(IJ)
          IF(ICOLR(ICOLH).EQ.MAXCP1)Z1(J)=PRED(I)
          IF(ICOLR(ICOLH).EQ.MAXCP2)Z1(J)=RES(I)
          IF(ICOLR(ICOLH).EQ.MAXCP3)Z1(J)=YPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP4)Z1(J)=XPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP5)Z1(J)=X2PLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP6)Z1(J)=TAGPLO(I)
        ELSE
          Z1(J)=0.0
        ENDIF
!
        IF(NRESP.GE.3)THEN
          ICOLH=ICOLH+1
          IJ=MAXN*(ICOLR(ICOLH)-1)+I
          IF(ICOLR(ICOLH).LE.MAXCOL)Z2(J)=V(IJ)
          IF(ICOLR(ICOLH).EQ.MAXCP1)Z2(J)=PRED(I)
          IF(ICOLR(ICOLH).EQ.MAXCP2)Z2(J)=RES(I)
          IF(ICOLR(ICOLH).EQ.MAXCP3)Z2(J)=YPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP4)Z2(J)=XPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP5)Z2(J)=X2PLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP6)Z2(J)=TAGPLO(I)
        ELSE
          Z2(J)=0.0
        ENDIF
!
        DO 2670 K=1,NCRTV
          ICOLH=ICOLH+1
          IJ=MAXN*(ICOLR(ICOLH)-1)+I
          IF(ICOLR(ICOLH).LE.MAXCOL)XDESGN(J,K)=V(IJ)
          IF(ICOLR(ICOLH).EQ.MAXCP1)XDESGN(J,K)=PRED(I)
          IF(ICOLR(ICOLH).EQ.MAXCP2)XDESGN(J,K)=RES(I)
          IF(ICOLR(ICOLH).EQ.MAXCP3)XDESGN(J,K)=YPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP4)XDESGN(J,K)=XPLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP5)XDESGN(J,K)=X2PLOT(I)
          IF(ICOLR(ICOLH).EQ.MAXCP6)XDESGN(J,K)=TAGPLO(I)
 2670   CONTINUE
!
 2660 CONTINUE
      NLOCAL=J
!
      ICNT=0
      IF(NRESP.GE.1)THEN
        ICNT=ICNT+1
        IYNAM(1:4)=IVARN1(ICNT)(1:4)
        IYNAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NRESP.GE.2)THEN
        ICNT=ICNT+1
        IXNAM(1:4)=IVARN1(ICNT)(1:4)
        IXNAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NRESP.GE.3)THEN
        ICNT=ICNT+1
        IXNAM2(1:4)=IVARN1(ICNT)(1:4)
        IXNAM2(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.1)THEN
        ICNT=ICNT+1
        IX1NAM(1:4)=IVARN1(ICNT)(1:4)
        IX1NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.2)THEN
        ICNT=ICNT+1
        IX2NAM(1:4)=IVARN1(ICNT)(1:4)
        IX2NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.3)THEN
        ICNT=ICNT+1
        IX3NAM(1:4)=IVARN1(ICNT)(1:4)
        IX3NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.4)THEN
        ICNT=ICNT+1
        IX4NAM(1:4)=IVARN1(ICNT)(1:4)
        IX4NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.5)THEN
        ICNT=ICNT+1
        IX5NAM(1:4)=IVARN1(ICNT)(1:4)
        IX5NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.6)THEN
        ICNT=ICNT+1
        IX6NAM(1:4)=IVARN1(ICNT)(1:4)
        IX6NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.7)THEN
        ICNT=ICNT+1
        IX7NAM(1:4)=IVARN1(ICNT)(1:4)
        IX7NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
      IF(NCRTV.GE.8)THEN
        ICNT=ICNT+1
        IX8NAM(1:4)=IVARN1(ICNT)(1:4)
        IX8NAM(5:8)=IVARN2(ICNT)(1:4)
      ENDIF
!
      IF(NLOCAL.LE.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2710)
 2710   FORMAT('      AFTER EXTRACTING THE SUBSET, THERE ARE NO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2712)
 2712   FORMAT('      OBSERVATIONS REMAINING ON WHICH TO PERFORM')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2714)
 2714   FORMAT('      THE RELEVANT CROSS-TABULATION.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  STEP 8--                                       **
!               **  COMPUTE THE APPROPRIATE CROSS-TABULATION       **
!               **  STATISTIC--                                    **
!               **  (MEAN, STANDARD DEVIATION, RANGE, OR COUNT).   **
!               *****************************************************
!
      ISTEPN='8'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CRTA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL' .OR. ICASCT.EQ.'BRAT')THEN
        IHP='ALPH'
        IHP2='A   '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                    NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,   &
                    ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ALPHA=0.95
        ELSE
          ALPHA=VALUE(ILOCP)
          IF(ALPHA.GE.1.0 .AND. ALPHA.LE.100.0)ALPHA=ALPHA/100.
          IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)ALPHA=0.95
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
          IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')THEN
            ATEMP=1.0 - ALPHA
            ATEMP=2.0*ATEMP
            ALPHA=1.0 - ATEMP
          ENDIF
        ENDIF
      ELSE
        ALPHA=0.05
      ENDIF
!
      IF(IFLAGL.EQ.'ON')THEN
      ELSE
        CALL DPCRT2(Y1,Z1,Z2,XDESGN,NLOCAL,MAXGR9,   &
                    NUMVAR,ICASCT,ICTNAM,ISTARA,   &
                    XH1DIS,   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    XNTRIA,XACLOW,XACUPP,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,IQUAME,IQUASE,PSTAMV,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,IX6NAM,   &
                    IX7NAM,IX8NAM,   &
                    ICAPSW,ICAPTY,IFORSW,NCRTV,MAXOBV,   &
                    Y,X,D,DSIZE,DFILL,DCOLOR,DSYMB,   &
                    XTEMP6,XTEMP7,NPLOTP,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CRTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,ICASCT
 9012   FORMAT('IFOUND,IERROR,ICASCT = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTP,NS,NCRTV
 9013   FORMAT('NPLOTP,NS,ICASCT = ',3I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GT.0)THEN
          DO 9015 I=1,MIN(200,NPLOTP)
          WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016     FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
          CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRTA
      SUBROUTINE DPCRT2(Y,Z,Z2,TAG,N,MAXGRP,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,   &
                        XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,IQUAME,IQUASE,PSTAMV,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,IX6NAM,   &
                        IX7NAM,IX8NAM,   &
                        ICAPSW,ICAPTY,IFORSW,NCRTV,MAXNXT,   &
                        Y2,X2,D2,DSIZE,DFILL,DCOLOR,DSYMB,   &
                        XPLOT,YPLOT,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE A CROSS-TABULATION
!              OF THE FOLLOWING TYPES--
!                 1) MEAN CROSS-TABULATION;
!                 2) STANDARD DEVIATION CROSS-TABULATION;
!                 3) RANGE CROSS-TABULATION;
!                 4) COUNT CROSS-TABULATION.
!                 5) SUM CROSS-TABULATION`
!                 6) CHI-SQUARE ANALYSIS CROSS_TABULATION
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --APRIL     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  1989.  COMMENT OUT CHECK OF NUMSET=N
!     UPDATED         --DECEMBEDR 1989.  FIX CROSS-TAB X1 X2
!     UPDATED         --OCTOBER   1992.  SUPPRESS ERROR MESSAGE FOR
!                                        ZERO COUNT CELLS.
!                                        ADD SUM AND CHI-SQUARE OPTIONS
!     UPDATED         --MARCH     1994.  FIX CROSS TABU SUM CASE
!     UPDATED         --MARCH     1994.  MODIFY CROSS TABU CHI-SQUARE
!                                        OUTPUT
!     UPDATED         --DECEMBER  1998.  WRITE OUTPUT TO FILE
!     UPDATED         --AUGUST    2002.  USE CMPSTA TO COMPUTE THE
!                                        STATISTICS
!     UPDATED         --AUGUST    2002.  GREATLY EXPAND LIST OF
!                                        SUPPORTED STATISICS
!     UPDATED         --AUGUST    2002.  SUPPORT FOR HTML OUTPUT
!     UPDATED         --APRIL     2003.  ADD SN AND QN (AND DIFFERENCE
!                                        OF), REQUIRED ADDITIONAL
!                                        SCRATCH ARAYS
!     UPDATED         --OCTOBER   2003.  SUPPORT FOR LATEX OUTPUT
!     UPDATED         --APRIL     2008.  SUPPORT FOR RTF OUTPUT
!     UPDATED         --APRIL     2008.  SUPPORT FOR 3, 4, 5, OR 6
!                                        CROSS-TABULATION VARIABLES
!     UPDATED         --APRIL     2008.  "BINOMIAL PROBABILITY" OPTION
!                                        (THIS RECIEVES SPECIAL
!                                        HANDLING)
!     UPDATED         --AUGUST    2008.  FIXED SOME BUGS
!     UPDATED         --JUNE      2010.  CALL LIST TO CMPSTA
!     UPDATED         --MAY       2014.  SUPPORT UP TO 8 CROSS-TAB
!                                        VARIABLES
!     UPDATED         --AUGUST    2023.  CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*40 ICTNAM
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 IQUAME
      CHARACTER*4 IQUASE
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
      CHARACTER*8 IX6NAM
      CHARACTER*8 IX7NAM
      CHARACTER*8 IX8NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(MAXNXT,MAXGRP)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DFILL(*)
      DIMENSION DCOLOR(*)
      DIMENSION DSYMB(*)
      DIMENSION XPLOT(*)
      DIMENSION YPLOT(*)
!
      DIMENSION TAG(MAXNXT,MAXGRP)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      INTEGER NUMSET(8)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T2  '
!
      I2=0
!
      AN=0.0
      YUPPER=0.0
      YLOWER=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN CROSS-TABULATE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!CCCC MAY 2008: DO NOT TREAT FOLLOWING AS AN ERROR.
!CCCC           PRINT A WARNING, BUT CONTINUE TO PROCESS.
!CCCC
!CCCC           WHEN CROSS-TABBING MULTIPLE VARIABLES, CAN
!CCCC           GET A LOT OF ERROR MESSAGES DUE TO CLASSES
!CCCC           WITH SMALL NUMBER OF ELEMENTS.  SO DO NOT
!CCCC           PRINT WARNING MESSAGE.
!
!CCCC IF(IYVAR.EQ.'ON')THEN
!CCCC   HOLD=Y(1)
!CCCC   DO60I=1,N
!CCCC     IF(Y(I).NE.HOLD)GO TO 69
!CC60   CONTINUE
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,61)
!CC61   FORMAT('***** WARNING IN CROSS-TABULATE--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,62)
!CC62   FORMAT('      ALL RESPONSE VARIABLE ELEMENTS')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,63)HOLD
!CC63   FORMAT('      ARE IDENTICALLY EQUAL TO ',G15.7)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CC69   CONTINUE
!CCCC ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT2')THEN
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF DPCRT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)N,ICASCT,NUMV2,NCRTV
   71   FORMAT('N,ICASCT,NUMV2,NCRTV = ',I8,2X,A4,I8,2X,I5)
        CALL DPWRST('XXX','BUG ')
        DO 72 I=1,N
          WRITE(ICOUT,73)I,Y(I),Z(I),Z2(I),(TAG(I,J),J=1,MAXGRP)
   73     FORMAT('I,Y(I),Z(I),Z2(I),TAG1-6(I) = ',I8,12F10.3)
          CALL DPWRST('XXX','BUG ')
   72   CONTINUE
        WRITE(ICOUT,74)IQUAME,IQUASE,PSTAMV
   74   FORMAT('IQUAME,IQUASE,PSTAMV = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT VALUES         **
!               **  FOR THE GROUP VARIABLES (TAG1, TAG2)            **
!               **  IF ALL VALUES ARE DISTINCT, THEN THIS           **
!               **  IMPLIES WE HAVE THE NO REPLICATION CASE         **
!               **  WHICH IS AN ERROR CONDITION FOR A PLOT.         **
!               ******************************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 100 J=1,MAXGRP
        NUMSET(J)=0
  100 CONTINUE
!
      DO 110 J=1,NCRTV
        CALL DISTIN(TAG(1,J),N,IWRITE,XIDTEM(1,J),NUMSET(J),   &
                    IBUGA3,IERROR)
        CALL SORT(XIDTEM(1,J),NUMSET(J),TEMP)
        DO 120 I=1,NUMSET(J)
          XIDTEM(I,J)=TEMP(I)
  120   CONTINUE
        IF(NUMSET(J).LT.1 .OR. NUMSET(J).GT.N)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)J,NUMSET(J)
  111     FORMAT('      THE NUMBER OF SETS FOR THE GROUP ',I1,   &
                 ' VARIABLE, ',I8,',')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,113)
  113     FORMAT('      IS EITHER LESS THAN ONE OR GREATER THAN THE ',   &
                 'NUMBER')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,115)N
  115     FORMAT('      OF OBSERVATIONS, ',I8,'.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  110 CONTINUE
!
      AN=N
      ANUMS1=NUMSET(1)
      ANUMS2=NUMSET(2)
      ANUMS3=NUMSET(3)
      ANUMS4=NUMSET(4)
      ANUMS5=NUMSET(5)
      ANUMS6=NUMSET(6)
      ANUMS7=NUMSET(7)
      ANUMS8=NUMSET(8)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
      IF(NCRTV.EQ.1)THEN
        CALL DPCRT0(Y,Z,Z2,TAG,N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),   &
                    NUMSET(1),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,   &
                    XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,IX1NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,N2,ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.2)THEN
        CALL DPCRT3(Y,Z,Z2,TAG(1,1),TAG(1,2),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),   &
                    NUMSET(1),NUMSET(2),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,N2,ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.3)THEN
        CALL DPCRT4(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,N2,ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.4)THEN
        CALL DPCRT5(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),TAG(1,4),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),XIDTEM(1,4),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),NUMSET(4),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,DCOLOR,N2,ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.5)THEN
        CALL DPCRT6(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),   &
                    TAG(1,4),TAG(1,5),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),   &
                    XIDTEM(1,4),XIDTEM(1,5),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),   &
                    NUMSET(4),NUMSET(5),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,DCOLOR,DFILL,N2,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.6)THEN
        CALL DPCRT7(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),TAG(1,4),   &
                    TAG(1,5),TAG(1,6),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),   &
                    XIDTEM(1,4),XIDTEM(1,5),XIDTEM(1,6),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),   &
                    NUMSET(4),NUMSET(5),NUMSET(6),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,   &
                    IX6NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,N2,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.7)THEN
        CALL DPCRT8(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),TAG(1,4),   &
                    TAG(1,5),TAG(1,6),TAG(1,7),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),   &
                    XIDTEM(1,4),XIDTEM(1,5),XIDTEM(1,6),   &
                    XIDTEM(1,7),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),NUMSET(4),   &
                    NUMSET(5),NUMSET(6),NUMSET(7),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,   &
                    IX6NAM,IX7NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,XPLOT,N2,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSEIF(NCRTV.EQ.8)THEN
        CALL DPCRT9(Y,Z,Z2,TAG(1,1),TAG(1,2),TAG(1,3),TAG(1,4),   &
                    TAG(1,5),TAG(1,6),TAG(1,7),TAG(1,8),N,   &
                    NUMV2,ICASCT,ICTNAM,ISTARA,   &
                    XIDTEM(1,1),XIDTEM(1,2),XIDTEM(1,3),   &
                    XIDTEM(1,4),XIDTEM(1,5),XIDTEM(1,6),   &
                    XIDTEM(1,7),XIDTEM(1,8),   &
                    NUMSET(1),NUMSET(2),NUMSET(3),NUMSET(4),   &
                    NUMSET(5),NUMSET(6),NUMSET(7),NUMSET(8),   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ISEED,ALPHA,   &
                    IXVAR,IX2VAR,IYVAR,   &
                    IYNAM,IXNAM,IXNAM2,   &
                    IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,   &
                    IX6NAM,IX7NAM,IX8NAM,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    MAXNXT,   &
                    Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,XPLOT,YPLOT,N2,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,NUMV2,IERROR
 9012   FORMAT('ICASCT,N,N2,NUMV2,IERROR = ',A4,3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSET(1),NUMSET(2),N2
 9015   FORMAT('NUMSET(1),NUMSET(2),N2 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2
 9016   FORMAT('ANUMS1,ANUMS2 = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I)
 9021     FORMAT('I,Y2(I),X2(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT2
      SUBROUTINE DPCRT3(Y,Z,Z2,TAG1,TAG2,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,   &
                        NUMSE1,NUMSE2,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,N2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A TWO-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL     2008. SPLIT OFF FROM DPCRT2 ROUTINE
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. TREAT BINOMIAL RATIO IN A
!                                       SIMILAR FASHION TO BINOMIAL
!                                       PROBABILITY
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. USE DPDTA5 TO PRINT TABLE
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=7)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IBFLAG
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T3  '
!
      I2=0
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-2
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
!
          K=0
          NTEMP2=0
          DO 1130 I=1,N
            IF(XIDTEM(ISET1).EQ.TAG1(I).AND.XIDTE2(ISET2).EQ.TAG2(I))   &
              GO TO 1131
            GO TO 1130
 1131       CONTINUE
!
            NTEMP2=NTEMP2+1
            IF(IYVAR.EQ.'OFF')THEN
              K=K+1
              TEMP(K)=0.0
            ELSE
              IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                K=K+1
                TEMP(K)=Y(I)
                IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
              ENDIF
            ENDIF
 1130     CONTINUE
          NTEMP=K
!
!         AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!         NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!         NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
          IF(NTEMP2.EQ.0)GO TO 1129
!
          IF(NTEMP.EQ.0)THEN
            IF(ICTAMV.EQ.'ZERO')THEN
              STAT=0.0
              IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                 ICASCT.EQ.'MDCL')THEN
                NTRIAL=0
                ALOWLM=0.0
                AUPPLM=0.0
              ENDIF
            ELSEIF(ICTAMV.EQ.'MV  ')THEN
              STAT=PCTAMV
              IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                 ICASCT.EQ.'MDCL')THEN
                NTRIAL=0
                ALOWLM=PCTAMV
                AUPPLM=PCTAMV
              ENDIF
            ELSE
              GO TO 1129
            ENDIF
          ELSE
            CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
            IF(IBFLAG.EQ.'BPRO')THEN
              PTEMP=STAT
              NTRIAL=NTEMP
              IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
              IF(STAT.EQ.PSTAMV)THEN
                ALOWLM=PSTAMV
                AUPPLM=PSTAMV
              ELSE
                ALPHAT=ALPHA
                CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                            ALOWLM,AUPPLM,IBUGA3,IERROR)
              ENDIF
            ELSEIF(ICASCT.EQ.'MECL')THEN
              XMEAN=STAT
              NTRIAL=NTEMP
              IF(STAT.EQ.PSTAMV)THEN
                ALOWLM=PSTAMV
                AUPPLM=PSTAMV
              ELSE
                CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                ALPHAT=ALPHA
                CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                            ALOWLM,AUPPLM,IBUGA3,IERROR)
              ENDIF
            ELSEIF(ICASCT.EQ.'MDCL')THEN
              XMED=STAT
              NTRIAL=NTEMP
              IF(STAT.EQ.PSTAMV)THEN
                ALOWLM=PSTAMV
                AUPPLM=PSTAMV
              ELSE
                XQ=0.5
                CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                            QUASE,IBUGA3,IERROR)
                ALPHAT=ALPHA
                CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                            ALOWLM,AUPPLM,IBUGA3,IERROR)
              ENDIF
            ENDIF
          ENDIF
!
          J=J+1
          Y2(J)=STAT
          X2(J)=XIDTEM(ISET1)
          D2(J)=XIDTE2(ISET2)
          IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
             ICASCT.EQ.'MDCL')THEN
            XNTRIA(J)=REAL(NTRIAL)
            XACLOW(J)=ALOWLM
            XACUPP(J)=AUPPLM
          ENDIF
!
 1129   CONTINUE
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT3')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1140)ISET1,ISET2,NTEMP,NTEMP2,STAT
 1140       FORMAT('DPCRT3: ISET1,ISET2,NTEMP,NTEMP2,STAT = ',   &
                   2I5,2I8,G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1141)XIDTEM(ISET1),XIDTE2(ISET2)
 1141       FORMAT('XIDTEM(ISET1),XIDTE2(ISET2) = ',2G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1142)J,Y2(J),X2(J),D2(J)
 1142       FORMAT('J,Y2(J),X2(J),D2(J) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2           ',A40)
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),Y2(I),XNTRIA(I),XACLOW(I)
 2171       FORMAT(5E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(6E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),Y2(I),XNTRIA(I),   &
                            XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),Y2(I)
 2161     FORMAT(3E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,3)='  $|$  '
      ENDIF
      NCTIT2(1,3)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=7
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=6
        ITITL2(1,4)='P'
        NCTIT2(1,4)=1
        ITITL2(1,5)='N'
        NCTIT2(1,5)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,6)(1:40)='Lower AC'
          NCTIT2(1,6)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,6)(1:40)='Upper AC'
          NCTIT2(1,6)=8
        ELSE
          ITITL2(1,6)(1:40)='Lower AC'
          NCTIT2(1,6)=8
          ITITL2(1,7)(1:40)='Upper AC'
          NCTIT2(1,7)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=7
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,4)='Mean'
          NCTIT2(1,4)=4
        ELSE
          ITITL2(1,4)='Median'
          NCTIT2(1,4)=6
        ENDIF
        ITITL2(1,5)='N'
        NCTIT2(1,5)=1
        ITITL2(1,6)='Lower Limit'
        ITITL2(1,7)='Upper Limit'
        NCTIT2(1,6)=11
        NCTIT2(1,7)=11
      ELSE
        NUMCOL=4
        ITITL2(1,4)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,4)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,4)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.5)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.3)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=25
      IWHTML(4)=125
      IWHTML(5)=75
      IWHTML(6)=125
      IWHTML(7)=125
      IJUNK=1400
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+200
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+800
      IWRTF(6)=IWRTF(5)+IJUNK
      IWRTF(7)=IWRTF(6)+IJUNK
      IFRST=.TRUE.
      IFLAGS=.TRUE.
      ILAST=.TRUE.
      IFLAGE=.FALSE.
!
      ICALL=0
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=0.0
        AMAT(ICNT,4)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,5)=XNTRIA(I)
          AMAT(ICNT,6)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,5)=XNTRIA(I)
          AMAT(ICNT,6)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,5)=XNTRIA(I)
          AMAT(ICNT,6)=XACLOW(I)
          AMAT(ICNT,7)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,5)=XNTRIA(I)
          AMAT(ICNT,6)=XACLOW(I)
          AMAT(ICNT,7)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.3)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,NUMSE1,N2,IERROR
 9012   FORMAT('ICASCT,N,NUMSE1,N2,IERROR = ',A4,3I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMV2,NUMSE1,NUMSE2,N2
 9015   FORMAT('NUMV2,NUMSE1,NUMSE2,N2 = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2
 9016   FORMAT('ANUMS1,ANUMS2 = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),D2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT3
      SUBROUTINE DPCRT4(Y,Z,Z2,TAG1,TAG2,TAG3,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,   &
                        NUMSE1,NUMSE2,NUMSE3,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,N2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A THREE-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL     2008.
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. TREAT BINOMIAL RATIO IN A
!                                       SIMILAR FASHION TO BINOMIAL
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. PRINT TABLES USING DPDTA5
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=8)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T4  '
!
      I2=0
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-3
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
!
            K=0
            NTEMP2=0
            DO 1140 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I).AND.XIDTE2(ISET2).EQ.TAG2(I)   &
                 .AND.XIDTE3(ISET3).EQ.TAG3(I))   &
                 GO TO 1141
              GO TO 1140
 1141         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1140       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!         NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!         NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
          IF(NTEMP2.EQ.0)GO TO 1130
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1130
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3           ',A40)
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I)
 2171       FORMAT(6E17.8)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),   &
                              Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),   &
                              Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(7E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),Y2(I),XNTRIA(I),   &
                            XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),Y2(I)
 2161     FORMAT(4E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,4)='  $|$  '
      ENDIF
      NCTIT2(1,4)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=8
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=7
        ITITL2(1,5)='P'
        NCTIT2(1,5)=1
        ITITL2(1,6)='N'
        NCTIT2(1,6)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,7)(1:40)='Lower AC'
          NCTIT2(1,7)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,7)(1:40)='Upper AC'
          NCTIT2(1,7)=8
        ELSE
          ITITL2(1,7)(1:40)='Lower AC'
          NCTIT2(1,7)=8
          ITITL2(1,8)(1:40)='Upper AC'
          NCTIT2(1,8)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=8
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,5)='Mean'
          NCTIT2(1,5)=4
        ELSE
          ITITL2(1,5)='Median'
          NCTIT2(1,5)=6
        ENDIF
        ITITL2(1,6)='N'
        NCTIT2(1,6)=1
        ITITL2(1,7)='Lower Limit'
        ITITL2(1,7)='Upper Limit'
        NCTIT2(1,8)=11
        NCTIT2(1,8)=11
      ELSE
        NUMCOL=5
        ITITL2(1,5)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,5)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,5)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.6)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.4)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.5)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=25
      IWHTML(5)=125
      IWHTML(6)=75
      IWHTML(7)=125
      IWHTML(8)=125
      IJUNK=1400
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+200
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+800
      IWRTF(7)=IWRTF(6)+IJUNK
      IWRTF(8)=IWRTF(7)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
!
      ICNT=0
      ICALL=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=0.0
        AMAT(ICNT,5)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,6)=XNTRIA(I)
          AMAT(ICNT,7)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,6)=XNTRIA(I)
          AMAT(ICNT,7)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,6)=XNTRIA(I)
          AMAT(ICNT,7)=XACLOW(I)
          AMAT(ICNT,8)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,6)=XNTRIA(I)
          AMAT(ICNT,7)=XACLOW(I)
          AMAT(ICNT,8)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.4)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3 = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT4
      SUBROUTINE DPCRT5(Y,Z,Z2,TAG1,TAG2,TAG3,TAG4,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,XIDTE4,   &
                        NUMSE1,NUMSE2,NUMSE3,NUMSE4,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,DCOLOR,N2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A FOUR-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL     2008.
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. TREAT BINOMIAL RATIO IN A
!                                       SIMILAR FASHION TO BINOMIAL
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. USE DPDTA5 TO PRINT TABLE
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=9)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DCOLOR(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T5  '
!
      I2=0
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
      ANUMS4=INT(NUMSE4+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-4
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
          DO 1140 ISET4=1,NUMSE4
!
            K=0
            NTEMP2=0
            DO 1180 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I) .AND.   &
                 XIDTE2(ISET2).EQ.TAG2(I) .AND.   &
                 XIDTE3(ISET3).EQ.TAG3(I) .AND.   &
                 XIDTE4(ISET4).EQ.TAG4(I))   &
                 GO TO 1181
              GO TO 1180
 1181         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1180       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!           NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!           NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
            IF(NTEMP2.EQ.0)GO TO 1140
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1140
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            DCOLOR(J)=XIDTE4(ISET4)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1140     CONTINUE
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3   GROUP-ID 4',   &
             '           ',A40)
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I)
 2171       FORMAT(7E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),   &
                              Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),   &
                              Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(8E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),   &
                            Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),DCOLOR(I),Y2(I)
 2161     FORMAT(5E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)='-'
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)(1:8)=IX4NAM
      NCTIT2(1,4)=8
      ITITL2(1,5)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,5)='  $|$  '
      ENDIF
      NCTIT2(1,5)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=9
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=8
        ITITL2(1,6)='P'
        NCTIT2(1,6)=1
        ITITL2(1,7)='N'
        NCTIT2(1,7)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,8)(1:40)='Lower AC'
          NCTIT2(1,8)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,8)(1:40)='Upper AC'
          NCTIT2(1,8)=8
        ELSE
          ITITL2(1,8)(1:40)='Lower AC'
          NCTIT2(1,8)=8
          ITITL2(1,9)(1:40)='Upper AC'
          NCTIT2(1,9)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=9
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,6)='Mean'
          NCTIT2(1,6)=4
        ELSE
          ITITL2(1,6)='Median'
          NCTIT2(1,6)=6
        ENDIF
        ITITL2(1,7)='N'
        NCTIT2(1,7)=1
        ITITL2(1,8)='Lower Limit'
        ITITL2(1,8)='Upper Limit'
        NCTIT2(1,9)=11
        NCTIT2(1,9)=11
      ELSE
        NUMCOL=6
        ITITL2(1,6)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,6)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,6)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.7)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.5)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.6)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=125
      IWHTML(3)=125
      IWHTML(4)=125
      IWHTML(5)=25
      IWHTML(6)=125
      IWHTML(7)=75
      IWHTML(8)=125
      IWHTML(9)=125
      IJUNK=1300
      IF(ICASCT.EQ.'BPRO')IJUNK=1100
      IF(ICASCT.EQ.'MECL')IJUNK=1100
      IF(ICASCT.EQ.'MDCL')IJUNK=1100
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+200
      IWRTF(6)=IWRTF(5)+IJUNK
      IWRTF(7)=IWRTF(6)+800
      IWRTF(8)=IWRTF(7)+IJUNK
      IWRTF(9)=IWRTF(8)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
      ICALL=0
!
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=DCOLOR(I)
        AMAT(ICNT,5)=0.0
        AMAT(ICNT,6)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,7)=XNTRIA(I)
          AMAT(ICNT,8)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,7)=XNTRIA(I)
          AMAT(ICNT,8)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,7)=XNTRIA(I)
          AMAT(ICNT,8)=XACLOW(I)
          AMAT(ICNT,9)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,7)=XNTRIA(I)
          AMAT(ICNT,8)=XACLOW(I)
          AMAT(ICNT,9)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.5)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3,NUMSE4
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4 = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3,ANUMS4
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3,ANUMS4 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT5
      SUBROUTINE DPCRT6(Y,Z,Z2,TAG1,TAG2,TAG3,TAG4,TAG5,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,   &
                        NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,DCOLOR,DFILL,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A FIVE-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL     2008.
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. TREAT BINOMIAL RATIO IN A
!                                       SIMILAR FASHION TO BINOMIAL
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. USE DPDTA5 TO PRINT TABLE
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=10)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
      CHARACTER*1 IBASLC
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION XIDTE5(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TAG5(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T6  '
!
      I2=0
      IPTSAV=IRTFPS
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
      ANUMS4=INT(NUMSE4+0.01)
      ANUMS5=INT(NUMSE5+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT6')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-5
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
          DO 1140 ISET4=1,NUMSE4
          DO 1150 ISET5=1,NUMSE5
!
            K=0
            NTEMP2=0
            DO 1180 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I) .AND.   &
                 XIDTE2(ISET2).EQ.TAG2(I) .AND.   &
                 XIDTE3(ISET3).EQ.TAG3(I) .AND.   &
                 XIDTE4(ISET4).EQ.TAG4(I) .AND.   &
                 XIDTE5(ISET5).EQ.TAG5(I))   &
                 GO TO 1181
              GO TO 1180
 1181         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1180       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!           NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!           NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
            IF(NTEMP2.EQ.0)GO TO 1150
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1150
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            DCOLOR(J)=XIDTE4(ISET4)
            DFILL(J)=XIDTE5(ISET5)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1150     CONTINUE
 1140     CONTINUE
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3   GROUP-ID 4',   &
             '   GROUP-ID 5           ',A40)
!
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I)
 2171       FORMAT(8E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(9E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            Y2(I)
 2161     FORMAT(6E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT6')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)(1:8)=IX4NAM
      NCTIT2(1,4)=8
      ITITL2(1,5)(1:8)=IX5NAM
      NCTIT2(1,5)=8
      ITITL2(1,6)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,6)='  $|$  '
      ENDIF
      NCTIT2(1,6)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=10
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=9
        ITITL2(1,7)='P'
        NCTIT2(1,7)=1
        ITITL2(1,8)='N'
        NCTIT2(1,8)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,9)(1:40)='Lower AC'
          NCTIT2(1,9)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,9)(1:40)='Upper AC'
          NCTIT2(1,9)=8
        ELSE
          ITITL2(1,9)(1:40)='Lower AC'
          NCTIT2(1,9)=8
          ITITL2(1,10)(1:40)='Upper AC'
          NCTIT2(1,10)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=10
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,7)='Mean'
          NCTIT2(1,7)=4
        ELSE
          ITITL2(1,7)='Median'
          NCTIT2(1,7)=6
        ENDIF
        ITITL2(1,8)='N'
        NCTIT2(1,8)=1
        ITITL2(1,9)='Lower Limit'
        ITITL2(1,9)='Upper Limit'
        NCTIT2(1,10)=11
        NCTIT2(1,10)=11
      ELSE
        NUMCOL=7
        ITITL2(1,7)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,7)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,7)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.8)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.6)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.6)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=100
      IWHTML(2)=100
      IWHTML(3)=100
      IWHTML(4)=100
      IWHTML(5)=100
      IWHTML(6)=25
      IWHTML(7)=100
      IWHTML(8)=75
      IWHTML(9)=100
      IWHTML(10)=100
      IJUNK=1300
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IJUNK=1000
        IPTSAV=IRTFPS
        IRTFPS=16
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,7003)IBASLC,IRTFPS
 7003   FORMAT(A1,'fs',I2)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+200
      IWRTF(7)=IWRTF(6)+IJUNK
      IWRTF(8)=IWRTF(7)+800
      IWRTF(9)=IWRTF(8)+IJUNK
      IWRTF(10)=IWRTF(9)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
      ICALL=0
!
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=DCOLOR(I)
        AMAT(ICNT,5)=DFILL(I)
        AMAT(ICNT,6)=0.0
        AMAT(ICNT,7)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,8)=XNTRIA(I)
          AMAT(ICNT,9)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,8)=XNTRIA(I)
          AMAT(ICNT,9)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,8)=XNTRIA(I)
          AMAT(ICNT,9)=XACLOW(I)
          AMAT(ICNT,10)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,8)=XNTRIA(I)
          AMAT(ICNT,9)=XACLOW(I)
          AMAT(ICNT,10)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.6)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IJUNK=1000
        IRTFPS=IPTSAV
        WRITE(ICOUT,7003)IBASLC,IRTFPS
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT6')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5 = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT6
      SUBROUTINE DPCRT7(Y,Z,Z2,TAG1,TAG2,TAG3,TAG4,TAG5,TAG6,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                        NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,IX6NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A SIX-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/4
!     ORIGINAL VERSION--APRIL     2008.
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. TREAT BINOMIAL RATIO IN A
!                                       SIMILAR FASHION TO BINOMIAL
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. USE DPDTA5 TO PRINT TABLE
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=11)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
      CHARACTER*1 IBASLC
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
      CHARACTER*8 IX6NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION XIDTE5(*)
      DIMENSION XIDTE6(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
      DIMENSION DSYMB(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TAG5(*)
      DIMENSION TAG6(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T7  '
!
      I2=0
      IPTSAV=IRTFPS
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
      ANUMS4=INT(NUMSE4+0.01)
      ANUMS5=INT(NUMSE5+0.01)
      ANUMS6=INT(NUMSE6+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT7')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-6
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
          DO 1140 ISET4=1,NUMSE4
          DO 1150 ISET5=1,NUMSE5
          DO 1160 ISET6=1,NUMSE6
!
            K=0
            NTEMP2=0
            DO 1180 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I) .AND.   &
                 XIDTE2(ISET2).EQ.TAG2(I) .AND.   &
                 XIDTE3(ISET3).EQ.TAG3(I) .AND.   &
                 XIDTE4(ISET4).EQ.TAG4(I) .AND.   &
                 XIDTE5(ISET5).EQ.TAG5(I) .AND.   &
                 XIDTE6(ISET6).EQ.TAG6(I))   &
                 GO TO 1181
              GO TO 1180
 1181         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1180       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!           NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!           NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
            IF(NTEMP2.EQ.0)GO TO 1160
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1160
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            DCOLOR(J)=XIDTE4(ISET4)
            DFILL(J)=XIDTE5(ISET5)
            DSYMB(J)=XIDTE6(ISET6)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1160     CONTINUE
 1150     CONTINUE
 1140     CONTINUE
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3   GROUP-ID 4',   &
             '   GROUP-ID 5   GROUP-ID 6           ',A40)
!
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),Y2(I),XNTRIA(I),XACLOW(I)
                                                                                                                                  
 2171       FORMAT(9E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(10E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),Y2(I)
 2161     FORMAT(7E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT7')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)(1:8)=IX4NAM
      NCTIT2(1,4)=8
      ITITL2(1,5)(1:8)=IX5NAM
      NCTIT2(1,5)=8
      ITITL2(1,6)(1:8)=IX6NAM
      NCTIT2(1,6)=8
      ITITL2(1,7)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,7)='  $|$  '
      ENDIF
      NCTIT2(1,7)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=11
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=10
        ITITL2(1,8)='P'
        NCTIT2(1,8)=1
        ITITL2(1,9)='N'
        NCTIT2(1,9)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,10)(1:40)='Lower AC'
          NCTIT2(1,10)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,10)(1:40)='Upper AC'
          NCTIT2(1,10)=8
        ELSE
          ITITL2(1,10)(1:40)='Lower AC'
          NCTIT2(1,10)=8
          ITITL2(1,11)(1:40)='Upper AC'
          NCTIT2(1,11)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=11
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,8)='Mean'
          NCTIT2(1,8)=4
        ELSE
          ITITL2(1,8)='Median'
          NCTIT2(1,8)=6
        ENDIF
        ITITL2(1,9)='N'
        NCTIT2(1,9)=1
        ITITL2(1,10)='Lower Limit'
        ITITL2(1,10)='Upper Limit'
        NCTIT2(1,11)=11
        NCTIT2(1,11)=11
      ELSE
        NUMCOL=8
        ITITL2(1,8)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,8)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,8)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.9)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.7)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.6)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=100
      IWHTML(2)=100
      IWHTML(3)=100
      IWHTML(4)=100
      IWHTML(5)=100
      IWHTML(6)=100
      IWHTML(7)=25
      IWHTML(8)=100
      IWHTML(9)=75
      IWHTML(10)=100
      IWHTML(11)=100
      IJUNK=1300
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IJUNK=900
        IPTSAV=IRTFPS
        IRTFPS=14
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,7003)IBASLC,IRTFPS
 7003   FORMAT(A1,'fs',I2)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+IJUNK
      IWRTF(7)=IWRTF(6)+200
      IWRTF(8)=IWRTF(7)+IJUNK
      IWRTF(9)=IWRTF(8)+800
      IWRTF(10)=IWRTF(9)+IJUNK
      IWRTF(11)=IWRTF(10)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
      ICALL=0
!
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=DCOLOR(I)
        AMAT(ICNT,5)=DFILL(I)
        AMAT(ICNT,6)=DSYMB(I)
        AMAT(ICNT,7)=0.0
        AMAT(ICNT,8)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,9)=XNTRIA(I)
          AMAT(ICNT,10)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,9)=XNTRIA(I)
          AMAT(ICNT,10)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,9)=XNTRIA(I)
          AMAT(ICNT,10)=XACLOW(I)
          AMAT(ICNT,11)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,9)=XNTRIA(I)
          AMAT(ICNT,10)=XACLOW(I)
          AMAT(ICNT,11)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.7)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IRTFPS=IPTSAV
        WRITE(ICOUT,7003)IBASLC,IRTFPS
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT7')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT7--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6 = ',6I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,ANUMSE6
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,ANUMSE6 = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT7
      SUBROUTINE DPCRT8(Y,Z,Z2,TAG1,TAG2,TAG3,TAG4,TAG5,TAG6,TAG7,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,XIDTE4,   &
                        XIDTE5,XIDTE6,XIDTE7,   &
                        NUMSE1,NUMSE2,NUMSE3,NUMSE4,   &
                        NUMSE5,NUMSE6,NUMSE7,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,IX6NAM,   &
                        IX7NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,XPLOT,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A SEVEN-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/5
!     ORIGINAL VERSION--MAY       2014.
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=12)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
      CHARACTER*1 IBASLC
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
      CHARACTER*8 IX6NAM
      CHARACTER*8 IX7NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION XIDTE5(*)
      DIMENSION XIDTE6(*)
      DIMENSION XIDTE7(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
      DIMENSION DSYMB(*)
      DIMENSION XPLOT(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TAG5(*)
      DIMENSION TAG6(*)
      DIMENSION TAG7(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T8  '
!
      I2=0
      IPTSAV=IRTFPS
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
      ANUMS4=INT(NUMSE4+0.01)
      ANUMS5=INT(NUMSE5+0.01)
      ANUMS6=INT(NUMSE6+0.01)
      ANUMS7=INT(NUMSE7+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-6
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
          DO 1140 ISET4=1,NUMSE4
          DO 1150 ISET5=1,NUMSE5
          DO 1160 ISET6=1,NUMSE6
          DO 1170 ISET7=1,NUMSE7
!
            K=0
            NTEMP2=0
            DO 1180 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I) .AND.   &
                 XIDTE2(ISET2).EQ.TAG2(I) .AND.   &
                 XIDTE3(ISET3).EQ.TAG3(I) .AND.   &
                 XIDTE4(ISET4).EQ.TAG4(I) .AND.   &
                 XIDTE5(ISET5).EQ.TAG5(I) .AND.   &
                 XIDTE6(ISET6).EQ.TAG6(I) .AND.   &
                 XIDTE7(ISET7).EQ.TAG7(I))   &
                 GO TO 1181
              GO TO 1180
 1181         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1180       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!           NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!           NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
            IF(NTEMP2.EQ.0)GO TO 1170
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1160
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            DCOLOR(J)=XIDTE4(ISET4)
            DFILL(J)=XIDTE5(ISET5)
            DSYMB(J)=XIDTE6(ISET6)
            XPLOT(J)=XIDTE7(ISET7)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1170     CONTINUE
 1160     CONTINUE
 1150     CONTINUE
 1140     CONTINUE
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3   GROUP-ID 4',   &
             '   GROUP-ID 5   GROUP-ID 6  GROUP-ID 7         ',A40)
!
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I)
                                                                                                                                  
 2171       FORMAT(10E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),   &
                              Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(11E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),XPLOT(I),   &
                            Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),XPLOT(I),Y2(I)
 2161     FORMAT(8E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)(1:8)=IX4NAM
      NCTIT2(1,4)=8
      ITITL2(1,5)(1:8)=IX5NAM
      NCTIT2(1,5)=8
      ITITL2(1,6)(1:8)=IX6NAM
      NCTIT2(1,6)=8
      ITITL2(1,7)(1:8)=IX7NAM
      NCTIT2(1,7)=8
      ITITL2(1,8)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,8)='  $|$  '
      ENDIF
      NCTIT2(1,8)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=12
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=11
        ITITL2(1,9)='P'
        NCTIT2(1,9)=1
        ITITL2(1,10)='N'
        NCTIT2(1,10)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,11)(1:40)='Lower AC'
          NCTIT2(1,11)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,11)(1:40)='Upper AC'
          NCTIT2(1,11)=8
        ELSE
          ITITL2(1,11)(1:40)='Lower AC'
          NCTIT2(1,11)=8
          ITITL2(1,12)(1:40)='Upper AC'
          NCTIT2(1,12)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=12
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,9)='Mean'
          NCTIT2(1,9)=4
        ELSE
          ITITL2(1,9)='Median'
          NCTIT2(1,9)=6
        ENDIF
        ITITL2(1,10)='N'
        NCTIT2(1,10)=1
        ITITL2(1,11)='Lower Limit'
        ITITL2(1,11)='Upper Limit'
        NCTIT2(1,12)=11
        NCTIT2(1,12)=11
      ELSE
        NUMCOL=9
        ITITL2(1,9)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,9)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,9)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.10)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.8)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.6)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
        NMAX=NMAX+NTOT(I)
 4210 CONTINUE
!
      IWHTML(1)=100
      IWHTML(2)=100
      IWHTML(3)=100
      IWHTML(4)=100
      IWHTML(5)=100
      IWHTML(6)=100
      IWHTML(7)=100
      IWHTML(8)=25
      IWHTML(9)=100
      IWHTML(10)=75
      IWHTML(11)=100
      IWHTML(12)=100
      IJUNK=1300
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IJUNK=900
        IPTSAV=IRTFPS
        IRTFPS=14
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,7003)IBASLC,IRTFPS
 7003   FORMAT(A1,'fs',I2)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+IJUNK
      IWRTF(7)=IWRTF(6)+IJUNK
      IWRTF(8)=IWRTF(7)+200
      IWRTF(9)=IWRTF(8)+IJUNK
      IWRTF(10)=IWRTF(9)+800
      IWRTF(11)=IWRTF(10)+IJUNK
      IWRTF(12)=IWRTF(11)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
      ICALL=0
!
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=DCOLOR(I)
        AMAT(ICNT,5)=DFILL(I)
        AMAT(ICNT,6)=DSYMB(I)
        AMAT(ICNT,7)=XPLOT(I)
        AMAT(ICNT,8)=0.0
        AMAT(ICNT,9)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,10)=XNTRIA(I)
          AMAT(ICNT,11)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,10)=XNTRIA(I)
          AMAT(ICNT,11)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,10)=XNTRIA(I)
          AMAT(ICNT,11)=XACLOW(I)
          AMAT(ICNT,12)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,10)=XNTRIA(I)
          AMAT(ICNT,11)=XACLOW(I)
          AMAT(ICNT,12)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.8)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IRTFPS=IPTSAV
        WRITE(ICOUT,7003)IBASLC,IRTFPS
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT8')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT8--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,   &
                         NUMSE6,NUSE7
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,NUMSE7 = ',   &
               7I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,   &
                         ANUMSE6,ANUMSE7
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,ANUMSE6,ANUMSE7 = ',   &
               7G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT8
      SUBROUTINE DPCRT9(Y,Z,Z2,TAG1,TAG2,TAG3,TAG4,TAG5,TAG6,   &
                        TAG7,TAG8,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,XIDTE2,XIDTE3,XIDTE4,   &
                        XIDTE5,XIDTE6,XIDTE7,XIDTE8,   &
                        NUMSE1,NUMSE2,NUMSE3,NUMSE4,   &
                        NUMSE5,NUMSE6,NUMSE7,NUMSE8,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,   &
                        IX1NAM,IX2NAM,IX3NAM,IX4NAM,IX5NAM,IX6NAM,   &
                        IX7NAM,IX8NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,D2,DSIZE,DCOLOR,DFILL,DSYMB,   &
                        XPLOT,YPLOT,N2,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE AN EIGHT-WAY CROSS-TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/5
!     ORIGINAL VERSION--MAY       2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*4 ISTARA
      CHARACTER*40 ICTNAM
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=13)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
      CHARACTER*1 IBASLC
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
      CHARACTER*8 IX2NAM
      CHARACTER*8 IX3NAM
      CHARACTER*8 IX4NAM
      CHARACTER*8 IX5NAM
      CHARACTER*8 IX6NAM
      CHARACTER*8 IX7NAM
      CHARACTER*8 IX8NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION XIDTE3(*)
      DIMENSION XIDTE4(*)
      DIMENSION XIDTE5(*)
      DIMENSION XIDTE6(*)
      DIMENSION XIDTE7(*)
      DIMENSION XIDTE8(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DSIZE(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
      DIMENSION DSYMB(*)
      DIMENSION XPLOT(*)
      DIMENSION YPLOT(*)
!
      DIMENSION TAG1(*)
      DIMENSION TAG2(*)
      DIMENSION TAG3(*)
      DIMENSION TAG4(*)
      DIMENSION TAG5(*)
      DIMENSION TAG6(*)
      DIMENSION TAG7(*)
      DIMENSION TAG8(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT9')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPCRT9')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,   &
                         NUMSE6,NUSE7,NUMSE8
   55   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,',   &
               'NUMSE7,NUMSE8 = ',8I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ISUBN1='DPCR'
      ISUBN2='T9  '
!
      I2=0
      IPTSAV=IRTFPS
!
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
      ANUMS2=INT(NUMSE2+0.01)
      ANUMS3=INT(NUMSE3+0.01)
      ANUMS4=INT(NUMSE4+0.01)
      ANUMS5=INT(NUMSE5+0.01)
      ANUMS6=INT(NUMSE6+0.01)
      ANUMS7=INT(NUMSE7+0.01)
      ANUMS8=INT(NUMSE8+0.01)
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT9')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
!
      EPS=0.1E-7
      J=0
      NRESP=NUMV2-6
      DO 1110 ISET1=1,NUMSE1
        DO 1120 ISET2=1,NUMSE2
          DO 1130 ISET3=1,NUMSE3
          DO 1140 ISET4=1,NUMSE4
          DO 1150 ISET5=1,NUMSE5
          DO 1160 ISET6=1,NUMSE6
          DO 1170 ISET7=1,NUMSE7
          DO 1180 ISET8=1,NUMSE8
!
            K=0
            NTEMP2=0
            DO 1190 I=1,N
              IF(XIDTEM(ISET1).EQ.TAG1(I) .AND.   &
                 XIDTE2(ISET2).EQ.TAG2(I) .AND.   &
                 XIDTE3(ISET3).EQ.TAG3(I) .AND.   &
                 XIDTE4(ISET4).EQ.TAG4(I) .AND.   &
                 XIDTE5(ISET5).EQ.TAG5(I) .AND.   &
                 XIDTE6(ISET6).EQ.TAG6(I) .AND.   &
                 XIDTE7(ISET7).EQ.TAG7(I) .AND.   &
                 XIDTE8(ISET8).EQ.TAG8(I))   &
                 GO TO 1191
              GO TO 1190
 1191         CONTINUE
!
              NTEMP2=NTEMP2+1
              IF(IYVAR.EQ.'OFF')THEN
                K=K+1
                TEMP(K)=0.0
              ELSE
                IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
                  K=K+1
                  TEMP(K)=Y(I)
                  IF(IXVAR.EQ.'ON')TEMPZ(K)=Z(I)
                  IF(IX2VAR.EQ.'ON')TEMPZ2(K)=Z2(I)
                ENDIF
              ENDIF
 1190       CONTINUE
            NTEMP=K
!
!           AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!           NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!           NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
            IF(NTEMP2.EQ.0)GO TO 1180
!
            IF(NTEMP.EQ.0)THEN
              IF(ICTAMV.EQ.'ZERO')THEN
                STAT=0.0
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=0.0
                  AUPPLM=0.0
                ENDIF
              ELSEIF(ICTAMV.EQ.'MV  ')THEN
                STAT=PCTAMV
                IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
                   ICASCT.EQ.'MDCL')THEN
                  NTRIAL=0
                  ALOWLM=PCTAMV
                  AUPPLM=PCTAMV
                ENDIF
              ELSE
                GO TO 1180
              ENDIF
            ELSE
              CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
              IF(IERROR.EQ.'YES')GO TO 9000
              IF(IBFLAG.EQ.'BPRO')THEN
                PTEMP=STAT
                NTRIAL=NTEMP
                IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  ALPHAT=ALPHA
                  CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MECL')THEN
                XMEAN=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ELSEIF(ICASCT.EQ.'MDCL')THEN
                XMED=STAT
                NTRIAL=NTEMP
                IF(STAT.EQ.PSTAMV)THEN
                  ALOWLM=PSTAMV
                  AUPPLM=PSTAMV
                ELSE
                  XQ=0.5
                  CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                              QUASE,IBUGA3,IERROR)
                  ALPHAT=ALPHA
                  CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                              ALOWLM,AUPPLM,IBUGA3,IERROR)
                ENDIF
              ENDIF
            ENDIF
!
            J=J+1
            Y2(J)=STAT
            X2(J)=XIDTEM(ISET1)
            D2(J)=XIDTE2(ISET2)
            DSIZE(J)=XIDTE3(ISET3)
            DCOLOR(J)=XIDTE4(ISET4)
            DFILL(J)=XIDTE5(ISET5)
            DSYMB(J)=XIDTE6(ISET6)
            XPLOT(J)=XIDTE7(ISET7)
            YPLOT(J)=XIDTE8(ISET8)
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              XNTRIA(J)=REAL(NTRIAL)
              XACLOW(J)=ALOWLM
              XACUPP(J)=AUPPLM
            ENDIF
!
 1180     CONTINUE
 1170     CONTINUE
 1160     CONTINUE
 1150     CONTINUE
 1140     CONTINUE
 1130     CONTINUE
 1120   CONTINUE
 1110 CONTINUE
      N2=J
!
      IF(ICASCT.EQ.'BRAT')THEN
        IBFLAG='BRAT'
        ICASCT='BPRO'
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1   GROUP-ID 2   GROUP-ID 3   GROUP-ID 4',   &
             '   GROUP-ID 5   GROUP-ID 6  GROUP-ID 7   GROUP-ID 8',   &
             '      ',A40)
!
      IF(ICASCT.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),YPLOT(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I)
                                                                                                                                  
 2171       FORMAT(11E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),YPLOT(I),   &
                              Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                              DSYMB(I),XPLOT(I),YPLOT(I),   &
                              Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2173       FORMAT(12E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),XPLOT(I),YPLOT(I),   &
                            Y2(I),XNTRIA(I),XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),D2(I),DSIZE(I),DCOLOR(I),DFILL(I),   &
                            DSYMB(I),XPLOT(I),YPLOT(I),Y2(I)
 2161     FORMAT(9E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT9')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)(1:8)=IX2NAM
      NCTIT2(1,2)=8
      ITITL2(1,3)(1:8)=IX3NAM
      NCTIT2(1,3)=8
      ITITL2(1,4)(1:8)=IX4NAM
      NCTIT2(1,4)=8
      ITITL2(1,5)(1:8)=IX5NAM
      NCTIT2(1,5)=8
      ITITL2(1,6)(1:8)=IX6NAM
      NCTIT2(1,6)=8
      ITITL2(1,7)(1:8)=IX7NAM
      NCTIT2(1,7)=8
      ITITL2(1,8)(1:8)=IX8NAM
      NCTIT2(1,8)=8
      ITITL2(1,9)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,9)='  $|$  '
      ENDIF
      NCTIT2(1,9)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=13
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=12
        ITITL2(1,10)='P'
        NCTIT2(1,10)=1
        ITITL2(1,11)='N'
        NCTIT2(1,11)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,12)(1:40)='Lower AC'
          NCTIT2(1,12)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,12)(1:40)='Upper AC'
          NCTIT2(1,12)=8
        ELSE
          ITITL2(1,12)(1:40)='Lower AC'
          NCTIT2(1,12)=8
          ITITL2(1,13)(1:40)='Upper AC'
          NCTIT2(1,13)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=13
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,10)='Mean'
          NCTIT2(1,10)=4
        ELSE
          ITITL2(1,10)='Median'
          NCTIT2(1,10)=6
        ENDIF
        ITITL2(1,11)='N'
        NCTIT2(1,11)=1
        ITITL2(1,12)='Lower Limit'
        ITITL2(1,12)='Upper Limit'
        NCTIT2(1,13)=11
        NCTIT2(1,13)=11
      ELSE
        NUMCOL=10
        ITITL2(1,10)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,9)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,10)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.11)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.9)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
!CCCC   ELSEIF(I.EQ.6)THEN
!CCCC     IF(ICASCT.NE.'BPRO' .AND. ICASCT.NE.'MECL' .AND.
!CCCC1       ICASCT.NE.'MDCL')THEN
!CCCC        ALIGN(I)='l'
!CCCC     ENDIF
        ENDIF
        NMAX=NMAX+NTOT(I)
 4210 CONTINUE
!
      IWHTML(1)=100
      IWHTML(2)=100
      IWHTML(3)=100
      IWHTML(4)=100
      IWHTML(5)=100
      IWHTML(6)=100
      IWHTML(7)=100
      IWHTML(8)=100
      IWHTML(9)=25
      IWHTML(10)=100
      IWHTML(11)=75
      IWHTML(12)=100
      IWHTML(13)=100
      IJUNK=1300
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IJUNK=900
        IPTSAV=IRTFPS
        IRTFPS=14
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,7003)IBASLC,IRTFPS
 7003   FORMAT(A1,'fs',I2)
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+IJUNK
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+IJUNK
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+IJUNK
      IWRTF(7)=IWRTF(6)+IJUNK
      IWRTF(8)=IWRTF(7)+IJUNK
      IWRTF(9)=IWRTF(8)+200
      IWRTF(10)=IWRTF(9)+IJUNK
      IWRTF(11)=IWRTF(10)+800
      IWRTF(12)=IWRTF(11)+IJUNK
      IWRTF(13)=IWRTF(10)+IJUNK
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.FALSE.
      ICALL=0
!
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=D2(I)
        AMAT(ICNT,3)=DSIZE(I)
        AMAT(ICNT,4)=DCOLOR(I)
        AMAT(ICNT,5)=DFILL(I)
        AMAT(ICNT,6)=DSYMB(I)
        AMAT(ICNT,7)=XPLOT(I)
        AMAT(ICNT,8)=YPLOT(I)
        AMAT(ICNT,9)=0.0
        AMAT(ICNT,10)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,11)=XNTRIA(I)
          AMAT(ICNT,12)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,11)=XNTRIA(I)
          AMAT(ICNT,12)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,11)=XNTRIA(I)
          AMAT(ICNT,12)=XACLOW(I)
          AMAT(ICNT,13)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,11)=XNTRIA(I)
          AMAT(ICNT,12)=XACLOW(I)
          AMAT(ICNT,13)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.9)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASCT.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
         ICASCT.EQ.'MDCL')THEN
        IRTFPS=IPTSAV
        WRITE(ICOUT,7003)IBASLC,IRTFPS
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
!
      IF(IBFLAG.EQ.'BRAT')THEN
        ICASCT='BRAT'
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT9')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT9--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,N2,IERROR
 9012   FORMAT('ICASCT,N,N2,IERROR = ',A4,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NUMV2
 9013   FORMAT('NUMV2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,   &
                         NUMSE6,NUSE7,NUMSE8
 9015   FORMAT('NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,',   &
               'NUMSE7,NUMSE8 = ',8I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,   &
                         ANUMSE6,ANUMSE7,ANUMSE8
 9016   FORMAT('ANUMS1,ANUMS2,ANUMS3,ANUMS4,ANUMSE5,ANUMSE6,',   &
               'ANUMSE7,ANUMSE8 = ',8G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I),DSIZE(I),D2(I)
 9021     FORMAT('I,Y2(I),X2(I),DSIZE(I),D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT9
      SUBROUTINE DPCRT0(Y,Z,Z2,TAG1,N,   &
                        NUMV2,ICASCT,ICTNAM,ISTARA,   &
                        XIDTEM,   &
                        NUMSE1,   &
                        TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                        XNTRIA,XACLOW,XACUPP,XTEMP8,XTEMP9,   &
                        ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        ISEED,ALPHA,   &
                        IXVAR,IX2VAR,IYVAR,   &
                        IYNAM,IXNAM,IXNAM2,IX1NAM,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        MAXNXT,   &
                        Y2,X2,N2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A ONE-WAY TABULATION AND
!              OPTIONALLY PRINT THE RESULTS TO AN ASCII,
!              HTML, LATEX, OR RTF TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCE--ASTM MANUAL STP-15D, PAGES 78-84, 100-105
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/6
!     ORIGINAL VERSION--JUNE      2008. SPLIT OFF FROM DPTAB2 ROUTINE
!     UPDATED         --SEPTEMBER 2008. ACCOMODATE "MISSING" DATA
!     UPDATED         --JANUARY   2010. "BINOMIAL RATIO" HANDLED
!                                       SAME AS "BINOMIAL PROB"
!     UPDATED         --JUNE      2010. CALL LIST TO CMPSTA
!     UPDATED         --JUNE      2010. USE DPDTA5 TO PRINT TABLE
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASCT
      CHARACTER*40 ICTNAM
      CHARACTER*4 ISTARA
      CHARACTER*4 IXVAR
      CHARACTER*4 IX2VAR
      CHARACTER*4 IYVAR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      PARAMETER(NUMCLI=6)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
      CHARACTER*8 IYNAM
      CHARACTER*8 IXNAM
      CHARACTER*8 IXNAM2
      CHARACTER*8 IX1NAM
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Z(*)
      DIMENSION Z2(*)
      DIMENSION XIDTEM(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
!
      DIMENSION TAG1(*)
      DIMENSION TEMP(*)
      DIMENSION TEMPZ(*)
      DIMENSION TEMPZ2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION XTEMP3(*)
      DIMENSION XNTRIA(*)
      DIMENSION XACLOW(*)
      DIMENSION XACUPP(*)
      DIMENSION XTEMP8(*)
      DIMENSION XTEMP9(*)
!
      INTEGER ITEMP1(*)
      INTEGER ITEMP2(*)
      INTEGER ITEMP3(*)
      INTEGER ITEMP4(*)
      INTEGER ITEMP5(*)
      INTEGER ITEMP6(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION DTEMP2(*)
      DOUBLE PRECISION DTEMP3(*)
!
      CHARACTER*4 IOP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCR'
      ISUBN2='T0  '
!
      IBFLAG=ICASCT
      IF(IBFLAG.EQ.'BRAT')IBFLAG='BPRO'
      I2=0
      AN=INT(N+0.01)
      ANUMS1=INT(NUMSE1+0.01)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT0')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,11)
   11   FORMAT('***** AT THE BEGINNING OF DPCRT0--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)ICASCT,N,NUMSE1
   12   FORMAT('ICASCT,N,NUMSE1 = ',A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)IYVAR,IXVAR,IX2VAR
   13   FORMAT('IYVAR,IXVAR,IX2VAR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,14)IYNAM,IXNAM,IXNAM2
   14   FORMAT('IYNAM,IXNAM,IXNAM2 = ',A8,2X,A8,2X,A8)
        CALL DPWRST('XXX','BUG ')
        DO 20 I=1,N
          WRITE(ICOUT,16)I,Y(I),Z(I),Z2(I),TAG1(I)
   16     FORMAT('I,Y(I),Z(I),Z2(I),TAG1(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   20   CONTINUE
      ENDIF
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  COMPUTE THE VARIOUS CROSS-TAB STATISTICS **
!               ***********************************************
!
      ISTEPN='5.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ALLOW THE   SET WRITE DECIMALS COMMAND    TO BE USED TO
!     DETERMINE HOW MANY DIGITS PRINTED IN TABLE.
!
      NUMDIG=-7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
!     NOTE 9/2008: IN FOLLOWING, WE NEED TO DISTINGUISH BETWEEN
!                  EMPTY SETS DUE TO NO POINTS FALLING IN THE
!                  PARTICULAR CROSS TABULATION (IN WHICH CASE,
!                  WE WANT TO SKIP IN THE OUTPUT FILE) AND EMPTY
!                  SETS DUE TO ALL POINTS IN THE PARTICULAR
!                  CROSS TABULATION BEING MISSING (IN WHICH CASE,
!                  WE MAY WANT TO WRITE A 0 OR A MISSING VALUE).
!
!                  THERE ARE 2 MISSING VALUES:
!
!                  PSTAMV   - SPECIFIES WHETHER THE INPUT DATA
!                             VALUE IS TO BE INCLUDED IN THE
!                             COMPUTATION OF THE STATISTIC
!
!                  PCTAMV    - IF ALL THE DATA IS MISSING, THIS
!                              IS THE VALUE TO USE IN WRITING THE
!                              CROSS TABULATE OUTPUT.
!
      IWRITE='OFF'
!
      EPS=0.1E-7
      J=0
      K=0
      NRESP=NUMV2-1
!
      ISTEPN='5.2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1110 ISET1=1,NUMSE1
!
        K=0
        NTEMP2=0
        NTEMP=0
!
        ISTEPN='5.2'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        DO 1130 I=1,N
          IF(XIDTEM(ISET1).EQ.TAG1(I))GO TO 1131
          GO TO 1130
 1131     CONTINUE
!
          NTEMP2=NTEMP2+1
          IF(IYVAR.EQ.'OFF')THEN
            NTEMP=NTEMP+1
            TEMP(NTEMP)=0.0
          ELSE
            IF(ABS(Y(I)-PSTAMV).GT.EPS)THEN
              NTEMP=NTEMP+1
              TEMP(NTEMP)=Y(I)
              IF(IXVAR.EQ.'ON')TEMPZ(NTEMP)=Z(I)
              IF(IX2VAR.EQ.'ON')TEMPZ2(NTEMP)=Z2(I)
            ENDIF
          ENDIF
 1130   CONTINUE
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')THEN
          ISTEPN='5.3'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1133)NTEMP,NTEMP2
 1133     FORMAT('DPCRT0: NTEMP,NTEMP2=',2I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       AUGUST 2002.  CALL CMPSTA (EXCEPT FOR CHI-SQUARE CASE)
!
!       NTEMP2 IS THE NUMBER OF POINTS IN THE SUBSET AND
!       NTEMP IS THE NUMBER OF NON-MISSING POINTS IN THE SUBSET.
!
        IF(NTEMP2.EQ.0)GO TO 1110
!
        IF(NTEMP.EQ.0)THEN
          IF(ICTAMV.EQ.'ZERO')THEN
            STAT=0.0
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              NTRIAL=0
              ALOWLM=0.0
              AUPPLM=0.0
            ENDIF
          ELSEIF(ICTAMV.EQ.'MV  ')THEN
            STAT=PCTAMV
            IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
               ICASCT.EQ.'MDCL')THEN
              NTRIAL=0
              ALOWLM=PCTAMV
              AUPPLM=PCTAMV
            ENDIF
          ELSE
            GO TO 1110
          ENDIF
        ELSE
          CALL CMPSTA(   &
                    TEMP,TEMPZ,TEMPZ2,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP8,XTEMP9,   &
                    MAXNXT,NTEMP,NTEMP,NTEMP,   &
                    NRESP,ICASCT,ISTARA,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    STAT,   &
                    ISUBRO,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          IF(IBFLAG.EQ.'BPRO')THEN
            PTEMP=STAT
            NTRIAL=NTEMP
            IF(ICASCT.EQ.'BRAT')NTRIAL=ITEMP1(1)
            IF(STAT.EQ.PSTAMV)THEN
              ALOWLM=PSTAMV
              AUPPLM=PSTAMV
            ELSE
              ALPHAT=ALPHA
              CALL DPAGCO(PTEMP,NTRIAL,ALPHAT,IWRITE,   &
                          ALOWLM,AUPPLM,IBUGA3,IERROR)
            ENDIF
          ELSEIF(ICASCT.EQ.'MECL')THEN
            XMEAN=STAT
            NTRIAL=NTEMP
            IF(STAT.EQ.PSTAMV)THEN
              ALOWLM=PSTAMV
              AUPPLM=PSTAMV
            ELSE
              CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
              ALPHAT=ALPHA
              CALL DPMECL(XMEAN,XSD,NTEMP,ALPHAT,IWRITE,   &
                          ALOWLM,AUPPLM,IBUGA3,IERROR)
            ENDIF
          ELSEIF(ICASCT.EQ.'MDCL')THEN
            XMED=STAT
            NTRIAL=NTEMP
            IF(STAT.EQ.PSTAMV)THEN
              ALOWLM=PSTAMV
              AUPPLM=PSTAMV
            ELSE
              XQ=0.5
              CALL QUANSE(XQ,TEMP,NTEMP,IWRITE,XTEMP1,MAXNXT,IQUASE,   &
                          QUASE,IBUGA3,IERROR)
              ALPHAT=ALPHA
              CALL DPMECL(XMED,QUASE,NTEMP,ALPHAT,IWRITE,   &
                          ALOWLM,AUPPLM,IBUGA3,IERROR)
            ENDIF
          ENDIF
        ENDIF
!
        J=J+1
        Y2(J)=STAT
        X2(J)=XIDTEM(ISET1)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1136)J
 1136     FORMAT('DPCRT0: J=',I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IBFLAG.EQ.'BPRO' .OR. ICASCT.EQ.'MECL' .OR.   &
           ICASCT.EQ.'MDCL')THEN
          XNTRIA(J)=REAL(NTRIAL)
          XACLOW(J)=ALOWLM
          XACUPP(J)=AUPPLM
        ENDIF
!
 1110 CONTINUE
!
      N2=J
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1191)J,N2
 1191   FORMAT('DPCRT0: J,N2=',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=0
      IFLG31=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!CCCC WRITE OUT TO DPST1F.DAT
!
      WRITE(IOUNI1,2111)ICTNAM
 2111 FORMAT(' GROUP-ID 1          ',A40)
      IF(IBFLAG.EQ.'BPRO')THEN
        DO 2170 I=1,N2
          IF(IBINTA.EQ.'LOWE')THEN
            WRITE(IOUNI1,2171)X2(I),Y2(I),XNTRIA(I),XACLOW(I)
 2171       FORMAT(4E17.9)
          ELSEIF(IBINTA.EQ.'UPPE')THEN
            WRITE(IOUNI1,2171)X2(I),Y2(I),XNTRIA(I),XACUPP(I)
          ELSE
            WRITE(IOUNI1,2173)X2(I),Y2(I),XNTRIA(I),   &
                              XACLOW(I),XACUPP(I)
 2173       FORMAT(5E17.9)
          ENDIF
 2170   CONTINUE
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        DO 2175 I=1,N2
          WRITE(IOUNI1,2173)X2(I),Y2(I),XNTRIA(I),   &
                            XACLOW(I),XACUPP(I)
 2175   CONTINUE
      ELSE
        DO 2160 I=1,N2
          WRITE(IOUNI1,2161)X2(I),Y2(I)
 2161     FORMAT(2E17.9)
 2160   CONTINUE
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************
!               **   STEP 6--              **
!               **   WRITE OUT THE TABLE   **
!               *****************************
!
      ISTEPN='6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CRT0')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
!
      IF(IPRINT.EQ.'OFF')GO TO 8000
!
      ITITLE(1:15)='Cross Tabulate '
      IF(ICASCT.EQ.'BPRO')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Binomial Probabilities'
      ELSEIF(ICASCT.EQ.'MECL')THEN
        NCTITL=37
        ITITLE(16:NCTITL)='Mean Confidence Limits'
      ELSEIF(ICASCT.EQ.'MDCL')THEN
        NCTITL=39
        ITITLE(16:NCTITL)='Median Confidence Limits'
      ELSE
        ITITLE(16:55)=ICTNAM(1:40)
        NCTITL=55
        DO 4010 I=55,1,-1
          IF(ITITLE(I:I).NE.' ')THEN
            NCTITL=I
            GO TO 4019
          ENDIF
 4010   CONTINUE
 4019   CONTINUE
      ENDIF
!
      IF(IYVAR.EQ.'ON')THEN
        ITITL9(1:21)='(Response Variables: '
        NTEMP=21
        ITITL9(22:30)=IYNAM(1:8)
        NTEMP=30
        IF(IXVAR.EQ.'ON')THEN
          ITITL9(30:30)=' '
          ITITL9(31:38)=IXNAM(1:8)
          NTEMP=38
        ENDIF
        IF(IX2VAR.EQ.'ON')THEN
          ITITL9(39:39)=' '
          ITITL9(40:47)=IXNAM2(1:8)
          NTEMP=47
        ENDIF
        NTEMP=NTEMP+1
        ITITL9(NTEMP:NTEMP)=')'
        NCTIT9=NTEMP
      ELSE
        ITITL9=' '
        NCTIT9=0
      ENDIF
!
      ITITL2(1,1)(1:8)=IX1NAM
      NCTIT2(1,1)=8
      ITITL2(1,2)='   |   '
      IF(ICAPTY.EQ.'LATE')THEN
        ITITL2(1,2)='  $|$  '
      ENDIF
      NCTIT2(1,2)=7
!
      NUMLIN=1
      IF(ICASCT.EQ.'BPRO')THEN
        NUMCOL=6
        IF(IBINTA.EQ.'LOWE' .OR. IBINTA.EQ.'UPPE')NUMCOL=5
        ITITL2(1,3)='P'
        NCTIT2(1,3)=1
        ITITL2(1,4)='N'
        NCTIT2(1,4)=1
        IF(IBINTA.EQ.'LOWE')THEN
          ITITL2(1,5)(1:40)='Lower AC'
          NCTIT2(1,5)=8
        ELSEIF(IBINTA.EQ.'UPPE')THEN
          ITITL2(1,5)(1:40)='Upper AC'
          NCTIT2(1,5)=8
        ELSE
          ITITL2(1,5)(1:40)='Lower AC'
          NCTIT2(1,5)=8
          ITITL2(1,6)(1:40)='Upper AC'
          NCTIT2(1,6)=8
        ENDIF
      ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
        NUMCOL=6
        IF(ICASCT.EQ.'MECL')THEN
          ITITL2(1,3)='Mean'
          NCTIT2(1,3)=4
        ELSE
          ITITL2(1,3)='Median'
          NCTIT2(1,3)=6
        ENDIF
        ITITL2(1,4)='N'
        NCTIT2(1,4)=1
        ITITL2(1,5)='Lower Limit'
        ITITL2(1,6)='Upper Limit'
        NCTIT2(1,5)=11
        NCTIT2(1,6)=11
      ELSE
        NUMCOL=3
        ITITL2(1,3)(1:15)=ICTNAM(1:15)
        NTEMP=15
        DO 4070 I=15,1,-1
          IF(ITITL2(1,3)(I:I).NE.' ')THEN
            NTEMP=I
            GO TO 4079
          ENDIF
 4070   CONTINUE
 4079   CONTINUE
        NCTIT2(1,3)=NTEMP
      ENDIF
!
      NMAX=0
      DO 4210 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(NCTIT2(1,I).GT.NTOT(I))NTOT(I)=NCTIT2(1,I)
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.4)THEN
          NTOT(I)=8
          IDIGIT(I)=0
        ELSEIF(I.EQ.2)THEN
          ITYPCO(I)='ALPH'
          NTOT(I)=7
          IDIGIT(I)=-1
        ENDIF
 4210 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=25
      IWHTML(3)=125
      IWHTML(4)=75
      IWHTML(5)=125
      IWHTML(6)=125
      IJUNK=1400
      IWRTF(1)=IJUNK
      IWRTF(2)=IWRTF(1)+200
      IWRTF(3)=IWRTF(2)+IJUNK
      IWRTF(4)=IWRTF(3)+800
      IWRTF(5)=IWRTF(4)+IJUNK
      IWRTF(6)=IWRTF(5)+IJUNK
      IFRST=.TRUE.
      IFLAGS=.TRUE.
      ILAST=.TRUE.
      IFLAGE=.FALSE.
!
      ICALL=0
      ICNT=0
      DO 4310 I=1,N2
        IF(ICNT.GE.30)THEN
          IF(I.EQ.N2)IFLAGE=.TRUE.
          CALL DPDTA5(ITITLE,NCTITL,   &
                      ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                      MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                      IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                      IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                      ICAPSW,ICAPTY,IFRST,ILAST,   &
                      IFLAGS,IFLAGE,   &
                      ISUBRO,IBUGA3,IERROR)
          IFRST=.FALSE.
          IFLAGS=.FALSE.
          ICALL=1
          ICNT=0
        ENDIF
        ICNT=ICNT+1
        NCTEXT(ICNT)=0
        AMAT(ICNT,1)=X2(I)
        AMAT(ICNT,2)=0.0
        AMAT(ICNT,3)=Y2(I)
        IF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'LOWE')THEN
          AMAT(ICNT,4)=XNTRIA(I)
          AMAT(ICNT,5)=XACLOW(I)
        ELSEIF(ICASCT.EQ.'BPRO' .AND. IBINTA.EQ.'UPPE')THEN
          AMAT(ICNT,4)=XNTRIA(I)
          AMAT(ICNT,5)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'BPRO')THEN
          AMAT(ICNT,4)=XNTRIA(I)
          AMAT(ICNT,5)=XACLOW(I)
          AMAT(ICNT,6)=XACUPP(I)
        ELSEIF(ICASCT.EQ.'MECL' .OR. ICASCT.EQ.'MDCL')THEN
          AMAT(ICNT,4)=XNTRIA(I)
          AMAT(ICNT,5)=XACLOW(I)
          AMAT(ICNT,6)=XACUPP(I)
        ENDIF
        DO 4320 J=1,NUMCOL
          IF(J.EQ.2)THEN
            NCVALU(ICNT,J)=7
            IVALUE(ICNT,J)='   |   '
            IF(ICAPTY.EQ.'LATE')THEN
              IVALUE(ICNT,J)='  $|$  '
            ENDIF
          ELSE
            NCVALU(ICNT,J)=0
            IVALUE(ICNT,J)=' '
          ENDIF
 4320   CONTINUE
 4310 CONTINUE
!
      IF(ICNT.GE.1)THEN
        IFLAGE=.TRUE.
        ILAST=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,9212)
 9212   FORMAT(6X,'GROUP-IDs AND STATISTIC WRITTEN TO FILE ',   &
               'DPST1F.DAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CRT0')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCRT0--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASCT,N,NUMV2,NUMSE1,N2,IERROR
 9012   FORMAT('ICASCT,N,NUMV2,NUMSE1,N2,IERROR = ',A4,4I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANUMS1
 9016   FORMAT('ANUMS1 = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N2
          WRITE(ICOUT,9021)I,Y2(I),X2(I)
 9021     FORMAT('I,Y2(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCRT0
      SUBROUTINE DPCSPL(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE A
!              CANDLESTICK PLOT OR AN OPEN-CLOSE-LOW-HIGH PLOT
!     REFERENCE--Nison, Steve (2001), "Japanese Candlestick Charting Techniques (2nd ed.),"
!                Prentice Hall Press, ISBN 9780735201811.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2025/07
!     ORIGINAL VERSION--JULY      2025.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION YOPEN(MAXOBV)
      DIMENSION YCLOSE(MAXOBV)
      DIMENSION YMIN(MAXOBV)
      DIMENSION YMAX(MAXOBV)
      DIMENSION X1(MAXOBV)
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),YOPEN(1))
      EQUIVALENCE (GARBAG(IGARB2),YCLOSE(1))
      EQUIVALENCE (GARBAG(IGARB3),YMIN(1))
      EQUIVALENCE (GARBAG(IGARB4),YMAX(1))
      EQUIVALENCE (GARBAG(IGARB5),X1(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPCS'
      ISUBN2='PL  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ************************************
!               **  TREAT THE CANDLESTICK PLOT    **
!               ************************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'CSPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2,NS
   52   FORMAT('ICASPL,IAND1,IAND2,NS = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CSPL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOM.EQ.'CAND' .AND. IHARG(1).EQ.'PLOT')THEN
        IFOUND='YES'
        ILASTC=1
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        ICASPL='CSPL'
      ELSEIF(ICOM.EQ.'OCLH' .AND. IHARG(1).EQ.'PLOT')THEN
        IFOUND='YES'
        ILASTC=1
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        ICASPL='OCLH'
      ELSEIF(ICOM.EQ.'OPEN' .AND. IHARG(1).EQ.'CLOS' .AND.       &
             IHARG(2).EQ.'LOW ' .AND. IHARG(3).EQ.'HIGH' .AND.   &
             IHARG(4).EQ.'PLOT')THEN
        IFOUND='YES'
        ILASTC=4
        CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
        ICASPL='OCLH'
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CSPL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CANDLESTICK PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=4
      MAXNVA=5
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,                                   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,       &
                  IVARN1,IVARN2,IVARTY,PVAR,                   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,      &
                  MINNVA,MAXNVA,                               &
                  IFLAGM,IFLAGP,                               &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CSPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',         &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *********************************************
!               **  STEP 7A--                              **
!               **  EXTRACT THE DATA                       **
!               *********************************************
!
      ISTEPN='7A'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'CSPL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      NUMVA2=3
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,            &
                  INAME,IVARN1,IVARN2,IVARTY,                   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,             &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,                  &
                  MAXCP4,MAXCP5,MAXCP6,                         &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,         &
                  YOPEN,YCLOSE,YMIN,NLOCAL,NLOCA2,NLOCA3,ICASE, &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ICOL=4
      NUMVA2=1
      IF(NUMVAR.EQ.5)NUMVA2=2
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,            &
                  INAME,IVARN1,IVARN2,IVARTY,                   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,             &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,                  &
                  MAXCP4,MAXCP5,MAXCP6,                         &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,         &
                  YMAX,X1,X1,NLOCA2,NLOCA2,NLOCA3,ICASE,        &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.EQ.4)THEN
        DO II=1,NLOCAL
           X1(II)=REAL(II)
        ENDDO
      ENDIF
!
!       *****************************************************
!       **  STEP 7B--                                      **
!       **  FORM THE VERTICAL AND HORIZONTAL AXIS          **
!       **  VALUES Y(.) AND X(.) FOR THE PLOT.             **
!       **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).  **
!       **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).  **
!       *****************************************************
!
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'CSPL')THEN
        ISTEPN='7B'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,731)
  731   FORMAT('***** FROM THE MIDDLE  OF DPCSPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,732)ICASPL,NUMVAR,NLOCAL
  732   FORMAT('ICASPL,NUMVAR,NLOCAL = ',A4,2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NLOCAL.GE.1)THEN
          DO I=1,NLOCAL
             WRITE(ICOUT,736)I,YOPEN(I),YCLOSE(I),YMIN(I),YMAX(I),X1(I)
  736        FORMAT('I,YOPEN(I),YCLOSE(I),YMIN(I),YMAX(I),X1(I) = ',  &
                    I8,5F12.5)
             CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
      ENDIF
!
      NPLOTP=0
      NS=NLOCAL
      CALL DPCSP2(YOPEN,YCLOSE,YMIN,YMAX,X1,NLOCAL,PCSPBW,ICASPL,   &
                  Y,X,D,X3D,NPLOTP,NPLOTV,                          &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'CSPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,NPLOTV,NPLOTP
 9012   FORMAT('IFOUND,IERROR,NPLOTV,NPLOTP = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I),X3D(I)
 9016       FORMAT('I,Y(I),X(I),D(I),X3D(I) = ',I8,4G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDDO
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSPL
      SUBROUTINE DPCSP2(YOPEN,YCLOSE,YMIN,YMAX,X,N,PCSPBW,ICASPL,  &
                        Y2,X2,D2,X3D2,NPLOTP,NPLOTV,               &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS THAT WILL DEFINE A
!              CANDLESTICK PLOT OR AN OPEN-CLOSE-LOW-HIGH PLOT
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1990)
!     VERSION NUMBER--2025/07
!     ORIGINAL VERSION--JULY      2025.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION YOPEN(*)
      DIMENSION YCLOSE(*)
      DIMENSION YMIN(*)
      DIMENSION YMAX(*)
      DIMENSION X(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION X3D2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='P2  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,40)
   40   FORMAT('***** AT THE BEGINNING OF DPCSP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,41)N,NUMVAR
   41   FORMAT('N,NUMVAR = ',2(A4,2X),G15.7,2I10)
        CALL DPWRST('XXX','BUG ')
        DO I=1,N
          WRITE(ICOUT,44)I,YOPEN(I),YCLOSE(I),YMIN(I),YMAX(I),X(I)
   44     FORMAT('I,YOPEN(I),YCLOSE(I),YMIN(I),YMAX(I),X(I) = ',   &
                 I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')    &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN CANDLESTICK CHART (DPCSP2)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO II=1,N
         IF(YMIN(II).GT.YOPEN(II) .OR. YMIN(II).GT.YCLOSE(II))THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,31)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,132)II
  132      FORMAT('      FOR ROW ',I8,' THE MINIMUM VALUE IS GREATER THAN')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,134)
  134      FORMAT('      EITHER THE OPEN OR CLOSE VALUE.')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,136)YMIN(II)
  136      FORMAT('THE MINIMUM VALUE IS:     ',G15.7)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,137)YOPEN(II)
  137      FORMAT('THE OPENING VALUE IS:     ',G15.7)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,138)YCLOSE(II)
  138      FORMAT('THE CLOSING VALUE IS:     ',G15.7)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           IERROR='YES'
           GO TO 9000
         ELSEIF(YMAX(II).LT.YOPEN(II) .OR. YMAX(II).LT.YCLOSE(II))THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,31)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,142)II
  142      FORMAT('      FOR ROW ',I8,' THE MAXIMUM VALUE IS LESS THAN')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,144)
  144      FORMAT('      EITHER THE OPEN OR CLOSE VALUE.')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,146)YMAX(II)
  146      FORMAT('THE MAXIMUM VALUE IS:     ',G15.7)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,137)YOPEN(II)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,138)YCLOSE(II)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           IERROR='YES'
           GO TO 9000
         ENDIF
      ENDDO
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  GENERATE THE CANDLESTICK PLOT              **
!               *************************************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')    &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(PCSPBW.GT.0.0)THEN
        BARWIDTH=PCSPBW
      ELSE
        IF(N.EQ.1)THEN
          BARWIDTH=1.0
        ELSE
          BARWIDTH=ABS(X(2) - X(1))/2.0
        ENDIF
      ENDIF
!
      IF(ICASPL.EQ.'OCLH')GO TO 2000
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')THEN
        WRITE(ICOUT,201)PCSPBW,BARWIDTH
  201   FORMAT('PCSPBW,BARWIDTH = ',2F10.5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
      ENDIF
!
!               *************************************************
!               **  STEP 3--                                   **
!               **  GENERATE THE CANDLESTICK PLOT              **
!               *************************************************
!
      ISTEPN='3'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')    &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      N2=0
      DO II=1,N
         XCOOR1=X(II) - (BARWIDTH/2.0)
         XCOOR2=X(II) + (BARWIDTH/2.0)
         IF(YOPEN(II).LT.YCLOSE(II))THEN
           ATAG=1.0
           YCOOR1=YOPEN(II)
           YCOOR2=YCLOSE(II)
         ELSE
           ATAG=2.0
           YCOOR1=YCLOSE(II)
           YCOOR2=YOPEN(II)
         ENDIF
!
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR1
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR2
         Y2(N2)=YCOOR1
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR2
         Y2(N2)=YCOOR2
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR2
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR1
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
!
         YCOOR3=YMIN(II)
         N2=N2+1
         X2(N2)=X(II)
         Y2(N2)=YCOOR1
         D2(N2)=3.0
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=X(II)
         Y2(N2)=YCOOR3
         D2(N2)=3.0
         X3D2(N2)=REAL(II)
         YCOOR4=YMAX(II)
         N2=N2+1
         X2(N2)=X(II)
         Y2(N2)=YCOOR2
         D2(N2)=4.0
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=X(II)
         Y2(N2)=YCOOR4
         D2(N2)=4.0
         X3D2(N2)=REAL(II)
      ENDDO
!
      NPLOTP=N2
      NPLOTV=3
      GO TO 9000
!
!               *************************************************
!               **  STEP 3--                                   **
!               **  GENERATE AN OPEN-CLOSE-LOW-HIGH PLOT       **
!               *************************************************
!
 2000 CONTINUE
!
      ISTEPN='3'
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')    &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      N2=0
      DO II=1,N
         XCOOR1=X(II)
         XCOOR2=X(II) - (BARWIDTH/2.0)
         XCOOR3=X(II) + (BARWIDTH/2.0)
         YCOOR1=YOPEN(II)
         YCOOR2=YCLOSE(II)
         YCOOR3=YMIN(II)
         YCOOR4=YMAX(II)
         IF(YOPEN(II).LT.YCLOSE(II))THEN
           ATAG=1.0
           IFLAG=1
         ELSE
           ATAG=2.0
           IFLAG=2
         ENDIF
!
!        DRAW THE LINE FROM THE MINIMUM TO THE MAXIMUM
!
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR3
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR4
         D2(N2)=ATAG
         X3D2(N2)=REAL(II)
!
!        DRAW THE LINE FOR THE OPENING VALUE
!
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR1
         IF(IFLAG.EQ.1)THEN
           D2(N2)=3.0
         ELSE
           D2(N2)=4.0
         ENDIF
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR2
         Y2(N2)=YCOOR1
         IF(IFLAG.EQ.1)THEN
           D2(N2)=3.0
         ELSE
           D2(N2)=4.0
         ENDIF
         X3D2(N2)=REAL(II)
!
!        DRAW THE LINE FOR THE CLOSING VALUE
!
         N2=N2+1
         X2(N2)=XCOOR1
         Y2(N2)=YCOOR2
         IF(IFLAG.EQ.1)THEN
           D2(N2)=5.0
         ELSE
           D2(N2)=6.0
         ENDIF
         X3D2(N2)=REAL(II)
         N2=N2+1
         X2(N2)=XCOOR3
         Y2(N2)=YCOOR2
         IF(IFLAG.EQ.1)THEN
           D2(N2)=5.0
         ELSE
           D2(N2)=6.0
         ENDIF
         X3D2(N2)=REAL(II)
!
      ENDDO
!
      NPLOTP=N2
      NPLOTV=3
      GO TO 9000
!
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'CSP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)NPLOTP,NPLOTV
 9012   FORMAT('NPLOTP,NPLOTV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO I=1,NPLOTP
          WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I),X3D2(I)
 9016     FORMAT('I,Y2(I),X2(I),D2(I),X3D2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDDO
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSP2
      SUBROUTINE DPCSR2(Y,X,N,ICASAN,MAXNXT,TEMP1,TEMP2,   &
                        IVARID,IVARI2,IVARI3,IVARI4,   &
                        XMIN,XMAX,YMIN,YMAX,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        STATV1,STATV2,STATC2,PVAL2,   &
                        CV01,CV02,CV05,CV10,CV15,CV25,CV50,   &
                        CV75,CV85,CV90,CV95,CV98,CV99,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT SEVERAL TESTS FOR COMPLETE
!              SPATIAL RANDOMNESS:
!
!                 1. BIVARAITE CRAMER VON-MISES TEST (I.E., BIVARIATE
!                    UNIFORMITY.
!
!                 2. MEAN NEAREST NEIGHBORS DISTANCE TEST.
!
!                 3. POLLARD'S STATISTIC (FOR DISTANCE INDEX
!                    1, 2, 3, 4, 5)
!
!     EXAMPLE--COMPLETE SPATIAL RANDOMNESS Y X
!     REFERENCES--DALE ZIMMERMAN (1993), "A BIVARIATE CRAMER-VON MISES
!                 TYPE OF TEST FOR SPATIAL RANDONNESS", JOURNAL OF
!                 THE ROYAL STATISTICAL SOCIETY, SERIES C (APPLIED
!                 STATISTICS, VOL. 42, NO. 1, PP. 43-54.
!                 LONDON.
!               --CLARK AND EVANS (1954), "DISTANCE TO NEAREST
!                 NEIGHBOR AS A MEASURE OF SPATIAL RELATIONSHIPS
!                 IN POPULATIONS", ECOLOGY, 35, PP. 23-30.
!               --DONNELLY (1978), "SIMULATIONS TO DETERMINE THE
!                 VARIANCE AND EDGE-EFFECT OF TOTAL NEAREST-NEIGHBOR
!                 DISTANCE", IN SIMULATION STUDIES IN ARCHAEOLOGY
!                 (ED. HODDER), PP. 91-95, LONDON: CAMBRIDGE UNIVERSITY
!                 PRESS.
!               --FORTIN AND DALE (2005), "SPATIAL ANALYSIS: A GUIDE
!                 FOR ECOLOGISTS", CAMBRIDGE UNIVERSITY PRESS, PP. 34-35.
!               --POLLARD (1971), "ON DISTANCE ESTIMATORS OF DENSITY
!                 IN RANDOMLY DISTRIBUTED FORESTS", BIOMETRICS, 27,
!                 991-1002.
!               --LIU (2001), "A COMPARISON OF FIVE DISTANCE-BASED
!                 METHODS FOR PATTERN ANALYSIS", JOURNAL OF VEGETATION
!                 SCIENCE, 12, 411-416.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/1
!     ORIGINAL VERSION--JANUARY   2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IERROR
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      PARAMETER (NUMALP=7)
      REAL ALPHA(NUMALP)
      REAL ALOWER(NUMALP)
      REAL AUPPER(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=50)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
      DIMENSION STATV3(5)
      DIMENSION STATV4(5)
      DIMENSION STATC3(5)
      DIMENSION STATP3(5)
      DIMENSION STATN3(5)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       50.0, 75.0, 80.0, 90.0, 95.0, 99.0, 99.9/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='R2  '
      IERROR='NO'
      STATV1=CPUMIN
      STATV2=CPUMIN
      STATC2=CPUMIN
      PVAL2=CPUMIN
      CUTL90=CPUMIN
      CUTU90=CPUMIN
      CUTL95=CPUMIN
      CUTU95=CPUMIN
      CUTL99=CPUMIN
      CUTU99=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCSR2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,ICASAN,N,MAXNXT
   52   FORMAT('ISUBRO,IBUGA3,ICASAN,N,MAXNXT = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)XMIN,XMAX,YMIN,YMAX
   54   FORMAT('XMIN,XMAX,YMIN,YMAX = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN COMPLETE SPATIAL RANDOMNESS TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1113)
 1113   FORMAT('      THE NUMBER OF OBSERVATIONS IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1114)N
 1114   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 1135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1131)HOLD
 1131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
 1139 CONTINUE
!
!               ******************************
!               **  STEP 21--               **
!               **  CARRY OUT CALCULATIONS  **
!               ******************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      XMINZ=XMIN
      XMAXZ=XMAX
      YMINZ=YMIN
      YMAXZ=YMAX
      IWRITE='OFF'
      CALL MINIM(X,N,IWRITE,XMIND,IBUGA3,IERROR)
      CALL MAXIM(X,N,IWRITE,XMAXD,IBUGA3,IERROR)
      CALL MINIM(Y,N,IWRITE,YMIND,IBUGA3,IERROR)
      CALL MAXIM(Y,N,IWRITE,YMAXD,IBUGA3,IERROR)
!
      CALL DPCSR3(X,Y,N,TEMP1,TEMP2,   &
                  XMIN,XMAX,YMIN,YMAX,   &
                  STATV1,   &
                  CV01,CV02,CV05,CV10,CV15,CV25,CV50,   &
                  CV75,CV85,CV90,CV95,CV98,CV99,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')THEN
        WRITE(ICOUT,2111)STATV1,CV05,CV10,CV90,CV95
 2111   FORMAT('STATV1,CV05,CV10,CV90,CV95 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL DPCSR4(X,Y,N,TEMP1,TEMP2,   &
                  STATV2,STATC2,PVAL2,   &
                  ISUBRO,IBUGA3,IERROR)
!
      DO 2140 I=1,NUMALP
        PCONF=ALPHA(I)/100.0
        CDF=PCONF
        CDF=0.5+(PCONF/2.0)
        CALL NORPPF(CDF,PPF)
        ALOWER(I)=-PPF
        AUPPER(I)=PPF
 2140 CONTINUE
      CUTL50=ALOWER(1)
      CUTU50=AUPPER(1)
      CUTL75=ALOWER(2)
      CUTU75=AUPPER(2)
      CUTL80=ALOWER(3)
      CUTU80=AUPPER(3)
      CUTL90=ALOWER(4)
      CUTU90=AUPPER(4)
      CUTL95=ALOWER(5)
      CUTU95=AUPPER(5)
      CUTL99=ALOWER(6)
      CUTU99=AUPPER(6)
      CTL999=ALOWER(7)
      CTU999=AUPPER(7)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')THEN
        WRITE(ICOUT,2141)STATV2,STATC2,PVAL2
 2141   FORMAT('STATV2,STATC2,PVAL2 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2143)CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99
 2143   FORMAT('CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99=',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
!               ***************************************
!               **   STEP 42--                       **
!               **   WRITE OUT EVERYTHING FOR        **
!               **   BIVARIATE CRAMER VON-MISES TEST **
!               ***************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Bivariate Cramer Von-Mises Test'
      NCTITL=31
      ITITLZ='for Complete Spatial Randomness'
      NCTITZ=31
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable: '
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(30:35),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(31:36),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Complete Spatial Randomness'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Not Complete Spatial Randomness'
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Data Minimum for X:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=XMIND
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Data Maximum for X:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=XMAXD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Data Minimum for Y:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=YMIND
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Data Maximum for Y:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=YMAXD
      IDIGIT(ICNT)=NUMDIG
!
      IFLAGT=1
      IF(XMINZ.EQ.CPUMIN)IFLAGT=0
      IF(XMAXZ.EQ.CPUMIN)IFLAGT=0
      IF(YMINZ.EQ.CPUMIN)IFLAGT=0
      IF(YMAXZ.EQ.CPUMIN)IFLAGT=0
      IF(IFLAGT.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='User Specified Minimum for X:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=XMINZ
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='User Specified Maximum for X:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=XMAXZ
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='User Specified Minimum for Y:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=YMINZ
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='User Specified Maximum for Y:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=YMAXZ
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATV1
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:44)='Percent Points of the Reference Distribution'
      NCTITL=44
      NUMLIN=1
      NUMROW=13
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=2
      IDIGIT(3)=3
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            IF(I.EQ.1)THEN
              AMAT(I,1)=0.01
            ELSEIF(I.EQ.2)THEN
              AMAT(I,1)=0.02
            ELSEIF(I.EQ.3)THEN
              AMAT(I,1)=0.05
            ELSEIF(I.EQ.4)THEN
              AMAT(I,1)=0.10
            ELSEIF(I.EQ.5)THEN
              AMAT(I,1)=0.15
            ELSEIF(I.EQ.6)THEN
              AMAT(I,1)=0.25
            ELSEIF(I.EQ.7)THEN
              AMAT(I,1)=0.50
            ELSEIF(I.EQ.8)THEN
              AMAT(I,1)=0.75
            ELSEIF(I.EQ.9)THEN
              AMAT(I,1)=0.85
            ELSEIF(I.EQ.10)THEN
              AMAT(I,1)=0.90
            ELSEIF(I.EQ.11)THEN
              AMAT(I,1)=0.95
            ELSEIF(I.EQ.12)THEN
              AMAT(I,1)=0.98
            ELSEIF(I.EQ.13)THEN
              AMAT(I,1)=0.99
            ENDIF
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=CV01
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=CV02
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=CV05
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=CV10
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=CV15
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=CV25
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=CV50
            ELSEIF(I.EQ.8)THEN
              AMAT(I,J)=CV75
            ELSEIF(I.EQ.9)THEN
              AMAT(I,J)=CV85
            ELSEIF(I.EQ.10)THEN
              AMAT(I,J)=CV90
            ELSEIF(I.EQ.11)THEN
              AMAT(I,J)=CV95
            ELSEIF(I.EQ.12)THEN
              AMAT(I,J)=CV98
            ELSEIF(I.EQ.13)THEN
              AMAT(I,J)=CV99
            ENDIF
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Two-Tailed Test)'
      NCTITL=29
      NUMLIN=2
      NUMROW=4
      NUMCOL=4
      ITITL2(1,1)=' '
      ITITL2(2,1)='Alpha'
      NCTIT2(1,1)=0
      NCTIT2(2,1)=5
      ITITL2(1,2)='Lower'
      ITITL2(2,2)='Critical Value'
      NCTIT2(1,2)=5
      NCTIT2(2,2)=14
      ITITL2(1,3)='Upper'
      ITITL2(2,3)='Critical Value'
      NCTIT2(1,3)=5
      NCTIT2(2,3)=14
      ITITL2(1,4)=' '
      ITITL2(2,4)='Conclusion'
      NCTIT2(1,4)=0
      NCTIT2(2,4)=10
!
      NMAX=0
      DO 4321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=7
        IF(I.EQ.2 .OR. I.EQ.3)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=3
        ITYPCO(I)='ALPH'
        IF(I.EQ.2 .OR. I.EQ.3)ITYPCO(I)='NUME'
 4321 CONTINUE
      IDIGIT(1)=0
      IDIGIT(4)=0
      DO 4323 I=1,NUMROW
        DO 4325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 4325   CONTINUE
 4323 CONTINUE
      IVALUE(1,1)='20%'
      IVALUE(2,1)='10%'
      IVALUE(3,1)='4%'
      IVALUE(4,1)='2%'
      NCVALU(1,1)=3
      NCVALU(2,1)=3
      NCVALU(3,1)=2
      NCVALU(4,1)=2
      IVALUE(1,4)='Accept H0'
      IVALUE(2,4)='Accept H0'
      IVALUE(3,4)='Accept H0'
      IVALUE(4,4)='Accept H0'
      NCVALU(1,4)=9
      NCVALU(2,4)=9
      NCVALU(3,4)=9
      NCVALU(4,4)=9
      IF(STATV1.LT.CV10 .OR. STATV1.GT.CV90)IVALUE(1,4)='Reject H0'
      IF(STATV1.LT.CV05 .OR. STATV1.GT.CV95)IVALUE(2,4)='Reject H0'
      IF(STATV1.LT.CV02 .OR. STATV1.GT.CV98)IVALUE(3,4)='Reject H0'
      IF(STATV1.LT.CV01 .OR. STATV1.GT.CV99)IVALUE(4,4)='Reject H0'
      AMAT(1,2)=RND(CV10,3)
      AMAT(1,3)=RND(CV90,3)
      AMAT(2,2)=RND(CV05,3)
      AMAT(2,3)=RND(CV95,3)
      AMAT(3,2)=RND(CV02,3)
      AMAT(3,3)=RND(CV98,3)
      AMAT(4,2)=RND(CV01,3)
      AMAT(4,3)=RND(CV99,3)
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=1500
      IWRTF(2)=IWRTF(1)+2000
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='42E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42F'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Mean Nearest Neighbors Test'
      NCTITL=27
      ITITLZ='for Complete Spatial Randomness'
      NCTITZ=31
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable: '
      WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(30:35),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(31:36),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=36
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Complete Spatial Randomness'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Not Complete Spatial Randomness'
      NCTEXT(ICNT)=35
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATV2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic CDF:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=STATC2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic P-Value:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=PVAL2
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4310 I=1,NUMROW
        NTOT(I)=15
 4310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='43D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Two-Tailed Test for Complete Spatial Randomness'
      NCTITL=47
      ITITL9='H0: Complete Spatial Randomness'
      NCTIT9=31
!
      DO 4330 J=1,5
        DO 4340 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 4340   CONTINUE
 4330 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (+/-)'
      NCTIT2(3,3)=11
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 4350 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.4)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 4350 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
!
      DO 4360 J=1,NUMALP
!
        AMAT(J,2)=STATV2
        IF(J.EQ.1)THEN
          AMAT(J,3)=CUTU50
          IVALUE(J,1)='50%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.2)THEN
          AMAT(J,3)=CUTU75
          IVALUE(J,1)='75%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.3)THEN
          AMAT(J,3)=CUTU80
          IVALUE(J,1)='80%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.4)THEN
          AMAT(J,3)=CUTU90
          IVALUE(J,1)='90%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.5)THEN
          AMAT(J,3)=CUTU95
          IVALUE(J,1)='95%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.6)THEN
          AMAT(J,3)=CUTU99
          IVALUE(J,1)='99%'
          NCVALU(J,1)=3
        ELSEIF(J.EQ.7)THEN
          IVALUE(J,1)='99.9%'
          NCVALU(J,1)=5
          AMAT(J,3)=CTU999
        ENDIF
        IVALUE(J,4)(1:6)='REJECT'
        IF(ABS(STATV2).LT.AMAT(J,3))THEN
          IVALUE(J,4)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,4)=6
!
 4360 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=4
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='44'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4401 JINDX=1,5
!
        CALL DPCSR5(X,Y,N,JINDX,TEMP1,   &
                  STATZ1,STATZ2,STATCZ,PVALZ3,STATNZ,   &
                  ISUBRO,IBUGA3,IERROR)
!
        STATV3(JINDX)=STATZ1
        STATV4(JINDX)=STATZ2
        STATC3(JINDX)=STATCZ
        STATP3(JINDX)=PVALZ3
        STATN3(JINDX)=STATNZ
!
        DO 4440 I=1,NUMALP
          PCONF=ALPHA(I)/100.0
          CDF=PCONF
          CDF=0.5+(PCONF/2.0)
          IDF=N-1
          CALL CHSPPF(CDF,IDF,PPF)
          AUPPER(I)=PPF
          CDF=1.0-CDF
          CALL CHSPPF(CDF,IDF,PPF)
          ALOWER(I)=PPF
 4440   CONTINUE
!
        CL50=ALOWER(1)
        CU50=AUPPER(1)
        CL75=ALOWER(2)
        CU75=AUPPER(2)
        CL80=ALOWER(3)
        CU80=AUPPER(3)
        CL90=ALOWER(4)
        CU90=AUPPER(4)
        CL95=ALOWER(5)
        CU95=AUPPER(5)
        CL99=ALOWER(6)
        CU99=AUPPER(6)
        CL999=ALOWER(7)
        CU999=AUPPER(7)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')THEN
          WRITE(ICOUT,4441)STATZ1,STATZ2,STATCZ,PVALZ3,STATNZ
 4441     FORMAT('STATZ1,STATZ2,STATCZ,PVALZ3,STATNZ = ',5G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,4443)CL90,CU90,CL95,CU95,CL99,CU99
 4443     FORMAT('CL90,CU90,CL95,CU95,CL99,CU99=',6G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ITITLE='Pollard Statistic Test (index =  )'
        WRITE(ITITLE(33:33),'(I1)')JINDX
        NCTITL=34
        ITITLZ='for Complete Spatial Randomness'
        NCTITZ=31
!
        ICNT=1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='First Response Variable: '
        WRITE(ITEXT(ICNT)(26:29),'(A4)')IVARID(1:4)
        WRITE(ITEXT(ICNT)(30:35),'(A4)')IVARI2(1:4)
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Second Response Variable: '
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
        WRITE(ITEXT(ICNT)(31:36),'(A4)')IVARI4(1:4)
        NCTEXT(ICNT)=36
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Complete Spatial Randomness'
        NCTEXT(ICNT)=31
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: Not Complete Spatial Randomness'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Observations:'
        NCTEXT(ICNT)=23
        AVALUE(ICNT)=REAL(N)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Nearest Neighbor Index:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=REAL(JINDX)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Test Statistic Value:'
        NCTEXT(ICNT)=21
        AVALUE(ICNT)=STATZ1
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Adjusted Test Statistic Value:'
        NCTEXT(ICNT)=30
        AVALUE(ICNT)=STATZ2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test Statistic CDF:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=STATC2
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Test Statistic P-Value:'
        NCTEXT(ICNT)=23
        AVALUE(ICNT)=PVAL2
        IDIGIT(ICNT)=NUMDIG
!
        NUMROW=ICNT
        DO 4410 I=1,NUMROW
          NTOT(I)=15
 4410   CONTINUE
!
        IFRST=.TRUE.
        ILAST=.TRUE.
!
        ISTEPN='44A'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,   &
                    NTOT,NUMROW,   &
                    ICAPSW,ICAPTY,ILAST,IFRST,   &
                    ISUBRO,IBUGA3,IERROR)
!
        ISTEPN='44B'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ITITLE='Two-Tailed Test for Complete Spatial Randomness'
        NCTITL=47
        ITITL9='H0: Complete Spatial Randomness'
        NCTIT9=31
!
        DO 4450 J=1,5
          DO 4460 I=1,3
            ITITL2(I,J)=' '
            NCTIT2(I,J)=0
 4460     CONTINUE
 4450   CONTINUE
!
        ITITL2(2,1)='Significance'
        NCTIT2(2,1)=12
        ITITL2(3,1)='Level'
        NCTIT2(3,1)=5
!
        ITITL2(2,2)='Test '
        NCTIT2(2,2)=4
        ITITL2(3,2)='Statistic'
        NCTIT2(3,2)=9
!
        ITITL2(1,3)='Lower'
        NCTIT2(1,3)=5
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (+/-)'
        NCTIT2(3,3)=11
!
        ITITL2(1,4)='Upper'
        NCTIT2(1,4)=5
        ITITL2(2,4)='Critical'
        NCTIT2(2,4)=8
        ITITL2(3,4)='Value (+/-)'
        NCTIT2(3,4)=11
!
        ITITL2(1,5)='Null'
        NCTIT2(1,5)=4
        ITITL2(2,5)='Hypothesis'
        NCTIT2(2,5)=10
        ITITL2(3,5)='Conclusion'
        NCTIT2(3,5)=10
!
        NMAX=0
        NUMCOL=5
        DO 4470 I=1,NUMCOL
          VALIGN(I)='b'
          ALIGN(I)='r'
          NTOT(I)=15
          NMAX=NMAX+NTOT(I)
          ITYPCO(I)='NUME'
          IDIGIT(I)=NUMDIG
          IF(I.EQ.1 .OR. I.EQ.5)THEN
            ITYPCO(I)='ALPH'
          ENDIF
 4470   CONTINUE
!
        IWHTML(1)=125
        IWHTML(2)=175
        IWHTML(3)=175
        IWHTML(4)=175
        IWHTML(5)=175
        IINC=1800
        IINC2=1400
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC
        IWRTF(4)=IWRTF(3)+IINC
        IWRTF(5)=IWRTF(4)+IINC
!
        DO 4480 J=1,NUMALP
!
          AMAT(J,2)=STATZ2
          IF(J.EQ.1)THEN
            IVALUE(J,1)='50%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL50
            AMAT(J,4)=CU50
          ELSEIF(J.EQ.2)THEN
            IVALUE(J,1)='75%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL75
            AMAT(J,4)=CU75
          ELSEIF(J.EQ.3)THEN
            IVALUE(J,1)='80%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL80
            AMAT(J,4)=CU80
          ELSEIF(J.EQ.4)THEN
            IVALUE(J,1)='90%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL90
            AMAT(J,4)=CU90
          ELSEIF(J.EQ.5)THEN
            IVALUE(J,1)='95%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL95
            AMAT(J,4)=CU95
          ELSEIF(J.EQ.6)THEN
            IVALUE(J,1)='99%'
            NCVALU(J,1)=3
            AMAT(J,3)=CL99
            AMAT(J,4)=CU99
          ELSEIF(J.EQ.7)THEN
            IVALUE(J,1)='99.9%'
            NCVALU(J,1)=5
            AMAT(J,3)=CL999
            AMAT(J,4)=CU999
          ENDIF
          IVALUE(J,5)(1:6)='ACCEPT'
          IF(STATZ2.LT.AMAT(J,3) .OR. STATZ2.GT.AMAT(J,4))THEN
            IVALUE(J,5)(1:6)='REJECT'
          ENDIF
          NCVALU(J,5)=6
!
 4480   CONTINUE
!
        ICNT=NUMALP
        NUMLIN=3
        NUMCOL=5
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
 4401   CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CSR2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSR2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IERROR
 9012   FORMAT('N,IERROR = ',I8,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATCD,PVAL
 9013   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSR2
      SUBROUTINE DPCSRA(XTEMP1,XTEMP2,MAXNXT,   &
                        ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--PERFORM SEVERAL TESTS FOR COMPLETE SPATIAL RANDOMNESS.
!              CURRENTLY SUPPORTED TESTS ARE:
!
!                 1) BIVARIATE CRAMER VON MISES TEST
!                 2) MEAN NEAREST NEIGHBORS DISTANCE TEST
!                 3) POLLARD'S STATISTIC (FOR DISTANCE INDEX
!                    1, 2, 3, 4, 5)
!
!     EXAMPLE--COMPLETE SPATIAL RANDOMNESS TEST X Y
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/01
!     ORIGINAL VERSION--JANUARY   2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='RA  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='YES'
      IERROR='NO'
!
!               *******************************************************
!               **  TREAT THE COMPLETE SPATIAL RANDOMNESS TEST CASE  **
!               *******************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSRA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSRA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COMPLETE SPATIAL RANDOMNESS TEST'
      MINNA=1
      MAXNA=100
      MINN2=5
      IFLAGE=1
      IFLAGM=0
      MINNVA=2
      MAXNVA=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSRA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      IH='XMIN'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        XMIN=VALUE(ILOCP)
      ELSE
        XMIN=CPUMIN
      ENDIF
!
      IH='XMAX'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        XMAX=VALUE(ILOCP)
      ELSE
        XMAX=CPUMIN
      ENDIF
!
      IH='YMIN'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        YMIN=VALUE(ILOCP)
      ELSE
        YMIN=CPUMIN
      ENDIF
!
      IH='YMAX'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        YMAX=VALUE(ILOCP)
      ELSE
        YMAX=CPUMIN
      ENDIF
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               *****************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSRA')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=2
      ICOL=1
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y,X,Y,NS1,NS1,NS1,ICASE,   &
                  IBUGA3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 52--                          **
!               **  PERFORM TEST                       **
!               *****************************************
!
      ISTEPN='52'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSRA')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5211)
 5211   FORMAT('***** FROM DPCSRA, BEFORE CALL DPFTES--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5212)I,J,NS1,NS2,MAXN
 5212   FORMAT('I,J,NS1,NS2,MAXN = ',5I8)
        CALL DPWRST('XXX','BUG ')
        DO 5215 II=1,MAX(NS1,NS2)
          WRITE(ICOUT,5216)II,Y(II),X(II)
 5216     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 5215   CONTINUE
      ENDIF
!
      IVARID=IVARN1(1)
      IVARI2=IVARN2(1)
      IVARI3=IVARN1(2)
      IVARI4=IVARN2(2)
!
      CALL DPCSR2(Y,X,NS1,ICASAN,MAXNXT,XTEMP1,XTEMP2,   &
                  IVARID,IVARI2,IVARI3,IVARI4,   &
                  XMIN,XMAX,YMIN,YMAX,   &
                  ICAPSW,ICAPTY,IFORSW,   &
                  STATV1,STATV2,STATC2,PVAL2,   &
                  CV01,CV02,CV05,CV10,CV15,CV25,CV50,   &
                  CV75,CV85,CV90,CV95,CV98,CV99,   &
                  CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='8C'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'FTE2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IH='STAT'
      IH2='VAL1'
      VALUE0=STATV1
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='VAL2'
      VALUE0=STATV2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF2'
      VALUE0=STATC2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PVAL'
      IH2='UE2 '
      VALUE0=PVAL2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV01'
      IH2='    '
      VALUE0=CV01
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV02'
      IH2='    '
      VALUE0=CV02
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV05'
      IH2='    '
      VALUE0=CV05
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV10'
      IH2='    '
      VALUE0=CV10
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV15'
      IH2='    '
      VALUE0=CV15
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV25'
      IH2='    '
      VALUE0=CV25
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV50'
      IH2='    '
      VALUE0=CV50
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV75'
      IH2='    '
      VALUE0=CV75
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV85'
      IH2='    '
      VALUE0=CV85
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV90'
      IH2='    '
      VALUE0=CV90
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV95'
      IH2='    '
      VALUE0=CV95
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV98'
      IH2='    '
      VALUE0=CV98
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CV99'
      IH2='    '
      VALUE0=CV99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                  IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                  IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSRA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSRA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSRA
      SUBROUTINE DPCSR3(X,Y,N,U,V,   &
                        XMIN,XMAX,YMIN,YMAX,   &
                        STATVA,   &
                        CV01,CV02,CV05,CV10,CV15,CV25,CV50,   &
                        CV75,CV85,CV90,CV95,CV98,CV99,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE BIVARIATE CRAMER
!              VON-MISES TEST (DESCRIBED BY DALE ZIMMERMAN)
!              FOR COMPLETE SPATIAL RANDOMNESS.
!
!              FOR THIS TEST, WE HAVE A SET OF N POINTS (X,Y).  WE
!              ALSO NEED TO DEFINE THE COORDINATES OF THE ENCLOSING
!              RECTANGLE (IF THESE NOT GIVEN, THEY WILL BE BASED ON
!              THE DATA MINIMUM AND MAXIMUMS).
!
!              THE TEST STATISTIC IS
!
!                    WBAR^2 = (1/(4*N))*SUM[i=1 to N]
!                             [SUM[j=1 to N][(1 - |u(i) - u(j)|)*
!                             (1 - |v(i) - v(j)|)]] -
!                             0.5*SUM[i=1 to N][(u(i)**2 - u(i) - 0.5)*
!                             (v(i)**2 - v(i) - 0.5)] + N/9
!
!                 WHERE
!
!                    u(i) = X(i)/XMAX
!                    v(i) = Y(i)/YMAX
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE FIRST RESPONSE
!                                VARIABLE.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE SECOND RESPONSE
!                                VARIABLE.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --ICASE  = A CHARACTER VARIABLE THAT SPECIFIES
!                                WHETHER GROUPED OR UNGROUPED DATA IS
!                                BEING GIVEN.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!     REFERENCE--DALE ZIMMERMAN (1993), "A BIVARIATE CRAMER-VON MISES
!                TYPE OF TEST FOR SPATIAL RANDONNESS", JOURNAL OF
!                THE ROYAL STATISTICAL SOCIETY, SERIES C (APPLIED
!                STATISTICS, VOL. 42, NO. 1, PP. 43-54.
!                LONDON.
!     OTHER DATAPAC   SUBROUTINES NEEDED--LININ3
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013.12
!     ORIGINAL VERSION--DECEMBER  2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION U(*)
      DIMENSION V(*)
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DUI
      DOUBLE PRECISION DUJ
      DOUBLE PRECISION DVI
      DOUBLE PRECISION DVJ
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSTAT
!
      REAL CRAMCV(13,5)
      REAL LININ3
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ((CRAMCV(I,J),J=1,5),I=1,13)/   &
       0.052,  0.049,  0.047,  0.046,  0.043,   &
       0.056,  0.053,  0.052,  0.051,  0.049,   &
       0.063,  0.061,  0.060,  0.059,  0.057,   &
       0.071,  0.069,  0.068,  0.067,  0.066,   &
       0.078,  0.077,  0.076,  0.075,  0.075,   &
       0.091,  0.090,  0.089,  0.088,  0.088,   &
       0.122,  0.121,  0.122,  0.121,  0.122,   &
       0.170,  0.169,  0.171,  0.170,  0.171,   &
       0.203,  0.204,  0.204,  0.204,  0.206,   &
       0.229,  0.229,  0.232,  0.232,  0.234,   &
       0.273,  0.273,  0.281,  0.280,  0.281,   &
       0.326,  0.332,  0.341,  0.338,  0.342,   &
       0.360,  0.372,  0.385,  0.392,  0.389/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='R3  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSR3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      STATVA=CPUMIN
!
!               *******************************************
!               **  CRAMER-VON MISES TEST                **
!               *******************************************
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPLETE SPATIAL RANDOMNESS TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN FOUR.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  CHECK THAT THE POINTS LIE IN THE      **
!               **  RECTANGLE AND DEFINE LOWER LEFT       **
!               **  CORNER AT (0,0).                      **
!               ********************************************
!
      CALL MINIM(Y,N,IWRITE,YMIND,IBUGA3,IERROR)
      CALL MAXIM(Y,N,IWRITE,YMAXD,IBUGA3,IERROR)
      CALL MINIM(X,N,IWRITE,XMIND,IBUGA3,IERROR)
      CALL MAXIM(X,N,IWRITE,XMAXD,IBUGA3,IERROR)
!
      IF(YMIN.EQ.CPUMIN)THEN
        IF(YMIND.GE.0.0)THEN
          YMIN=0.0
        ELSE
          YMIN=YMIND
        ENDIF
      ELSE
        IF(YMIND.LT.YMIN)THEN
          YMIN=YMIND
        ENDIF
      ENDIF
!
      IF(YMAX.EQ.CPUMIN)THEN
        YMAX=YMAXD
      ELSE
        IF(YMAXD.GT.YMAX)THEN
          YMAX=YMAXD
        ENDIF
      ENDIF
!
      IF(XMIN.EQ.CPUMIN)THEN
        IF(XMIND.GE.0.0)THEN
          XMIN=0.0
        ELSE
          XMIN=XMIND
        ENDIF
      ELSE
        IF(XMIND.LT.XMIN)THEN
          XMIN=XMIND
        ENDIF
      ENDIF
!
      IF(XMAX.EQ.CPUMIN)THEN
        XMAX=XMAXD
      ELSE
        IF(XMAXD.GT.XMAX)THEN
          XMAX=XMAXD
        ENDIF
      ENDIF
!
      IF(XMIN.NE.0.0)XMAX=XMAX-XMIN
      IF(YMIN.NE.0.0)YMAX=YMAX-YMIN
      DO 200 I=1,N
        U(I)=(X(I) - XMIN)/XMAX
        V(I)=(Y(I) - YMIN)/YMAX
  200 CONTINUE
!
      DN=DBLE(N)
      DTERM1=1.0D0/(4.0D0*DN)
      DTERM2=DN/9.0D0
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 210 I=1,N
        DU=DBLE(U(I))
        DV=DBLE(V(I))
        DTERM3=DU**2 - DU - 0.5D0
        DTERM4=DV**2 - DV - 0.5D0
        DSUM1=DSUM1 + DTERM3*DTERM4
  210 CONTINUE
!
      DO 220 I=1,N
        DUI=DBLE(U(I))
        DVI=DBLE(V(I))
        DO 230 J=1,N
          DUJ=DBLE(U(J))
          DVJ=DBLE(V(J))
          DTERM3=1.0D0 - DABS(DUI - DUJ)
          DTERM4=1.0D0 - DABS(DVI - DVJ)
          DSUM2=DSUM2 + DTERM3*DTERM4
  230   CONTINUE
  220 CONTINUE
!
      DSTAT=DTERM1*DSUM2 - 0.5D0*DSUM1 + DTERM2
      STATVA=REAL(DSTAT)
!
      IF(N.EQ.5)THEN
        CV01=CRAMCV(1,1)
        CV02=CRAMCV(2,1)
        CV05=CRAMCV(3,1)
        CV10=CRAMCV(4,1)
        CV15=CRAMCV(5,1)
        CV25=CRAMCV(6,1)
        CV50=CRAMCV(7,1)
        CV75=CRAMCV(8,1)
        CV85=CRAMCV(9,1)
        CV90=CRAMCV(10,1)
        CV95=CRAMCV(11,1)
        CV98=CRAMCV(12,1)
        CV99=CRAMCV(13,1)
      ELSEIF(N.GE.6 .AND. N.LE.9)THEN
        AN1=5.0
        AN2=10.0
        AN=REAL(N)
        CV01=LININ3(AN1,CRAMCV(1,1),AN2,CRAMCV(1,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV02=LININ3(AN1,CRAMCV(2,1),AN2,CRAMCV(2,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV05=LININ3(AN1,CRAMCV(3,1),AN2,CRAMCV(3,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV10=LININ3(AN1,CRAMCV(4,1),AN2,CRAMCV(4,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV15=LININ3(AN1,CRAMCV(5,1),AN2,CRAMCV(5,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV25=LININ3(AN1,CRAMCV(6,1),AN2,CRAMCV(6,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV50=LININ3(AN1,CRAMCV(7,1),AN2,CRAMCV(7,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV75=LININ3(AN1,CRAMCV(8,1),AN2,CRAMCV(8,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV85=LININ3(AN1,CRAMCV(9,1),AN2,CRAMCV(9,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV90=LININ3(AN1,CRAMCV(10,1),AN2,CRAMCV(10,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV95=LININ3(AN1,CRAMCV(11,1),AN2,CRAMCV(11,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV98=LININ3(AN1,CRAMCV(12,1),AN2,CRAMCV(12,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV99=LININ3(AN1,CRAMCV(13,1),AN2,CRAMCV(13,2),AN,   &
             IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.10)THEN
        CV01=CRAMCV(1,2)
        CV02=CRAMCV(2,2)
        CV05=CRAMCV(3,2)
        CV10=CRAMCV(4,2)
        CV15=CRAMCV(5,2)
        CV25=CRAMCV(6,2)
        CV50=CRAMCV(7,2)
        CV75=CRAMCV(8,2)
        CV85=CRAMCV(9,2)
        CV90=CRAMCV(10,2)
        CV95=CRAMCV(11,2)
        CV98=CRAMCV(12,2)
        CV99=CRAMCV(13,2)
      ELSEIF(N.GE.11 .AND. N.LE.14)THEN
        AN1=10.0
        AN2=15.0
        AN=REAL(N)
        CV01=LININ3(AN1,CRAMCV(1,2),AN2,CRAMCV(1,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV02=LININ3(AN1,CRAMCV(2,2),AN2,CRAMCV(2,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV05=LININ3(AN1,CRAMCV(3,2),AN2,CRAMCV(3,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV10=LININ3(AN1,CRAMCV(4,2),AN2,CRAMCV(4,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV15=LININ3(AN1,CRAMCV(5,2),AN2,CRAMCV(5,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV25=LININ3(AN1,CRAMCV(6,2),AN2,CRAMCV(6,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV50=LININ3(AN1,CRAMCV(7,2),AN2,CRAMCV(7,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV75=LININ3(AN1,CRAMCV(8,2),AN2,CRAMCV(8,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV85=LININ3(AN1,CRAMCV(9,2),AN2,CRAMCV(9,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV90=LININ3(AN1,CRAMCV(10,2),AN2,CRAMCV(10,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV95=LININ3(AN1,CRAMCV(11,2),AN2,CRAMCV(11,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV98=LININ3(AN1,CRAMCV(12,2),AN2,CRAMCV(12,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV99=LININ3(AN1,CRAMCV(13,2),AN2,CRAMCV(13,3),AN,   &
             IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.15)THEN
        CV01=CRAMCV(1,3)
        CV02=CRAMCV(2,3)
        CV05=CRAMCV(3,3)
        CV10=CRAMCV(4,3)
        CV15=CRAMCV(5,3)
        CV25=CRAMCV(6,3)
        CV50=CRAMCV(7,3)
        CV75=CRAMCV(8,3)
        CV85=CRAMCV(9,3)
        CV90=CRAMCV(10,3)
        CV95=CRAMCV(11,3)
        CV98=CRAMCV(12,3)
        CV99=CRAMCV(13,3)
      ELSEIF(N.GE.16 .AND. N.LE.19)THEN
        AN1=15.0
        AN2=20.0
        AN=REAL(N)
        CV01=LININ3(AN1,CRAMCV(1,3),AN2,CRAMCV(1,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV02=LININ3(AN1,CRAMCV(2,3),AN2,CRAMCV(2,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV05=LININ3(AN1,CRAMCV(3,3),AN2,CRAMCV(3,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV10=LININ3(AN1,CRAMCV(4,3),AN2,CRAMCV(4,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV15=LININ3(AN1,CRAMCV(5,3),AN2,CRAMCV(5,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV25=LININ3(AN1,CRAMCV(6,3),AN2,CRAMCV(6,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV50=LININ3(AN1,CRAMCV(7,3),AN2,CRAMCV(7,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV75=LININ3(AN1,CRAMCV(8,3),AN2,CRAMCV(8,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV85=LININ3(AN1,CRAMCV(9,3),AN2,CRAMCV(9,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV90=LININ3(AN1,CRAMCV(10,3),AN2,CRAMCV(10,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV95=LININ3(AN1,CRAMCV(11,3),AN2,CRAMCV(11,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV98=LININ3(AN1,CRAMCV(12,3),AN2,CRAMCV(12,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
        CV99=LININ3(AN1,CRAMCV(13,3),AN2,CRAMCV(13,4),AN,   &
             IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.20)THEN
        CV01=CRAMCV(1,4)
        CV02=CRAMCV(2,4)
        CV05=CRAMCV(3,4)
        CV10=CRAMCV(4,4)
        CV15=CRAMCV(5,4)
        CV25=CRAMCV(6,4)
        CV50=CRAMCV(7,4)
        CV75=CRAMCV(8,4)
        CV85=CRAMCV(9,4)
        CV90=CRAMCV(10,4)
        CV95=CRAMCV(11,4)
        CV98=CRAMCV(12,4)
        CV99=CRAMCV(13,4)
      ELSE
        CV01=CRAMCV(1,5)
        CV02=CRAMCV(2,5)
        CV05=CRAMCV(3,5)
        CV10=CRAMCV(4,5)
        CV15=CRAMCV(5,5)
        CV25=CRAMCV(6,5)
        CV50=CRAMCV(7,5)
        CV75=CRAMCV(8,5)
        CV85=CRAMCV(9,5)
        CV90=CRAMCV(10,5)
        CV95=CRAMCV(11,5)
        CV98=CRAMCV(12,5)
        CV99=CRAMCV(13,5)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSR3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,IERROR
 9015   FORMAT('STATVA,IERROR = ',G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)CV01,CV05,CV10,CV90,CV95,CV99
 9016   FORMAT('CV01,CV05,CV10,CV90,CV95,CV99=',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSR3
      SUBROUTINE DPCSR4(X,Y,N,YTEMP,DIST,   &
                        STATVA,STATCD,PVALUE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE MEAN NEAREST NEIGHBOR
!              DISTANCE TEST FOR COMPLETE SPATIAL RANDOMNESS FOR
!              BIVARIATE DATA.  WE HAVE A SET OF N POINTS (X,Y).
!
!              THE TEST STATISTIC IS
!
!                  T = (ZBAR - MU(ZBAR))/SIGMA(ZBAR)
!
!                  ZBAR = (1/N)*SUM[i=1 to N][Z(i)]
!
!              WHERE
!
!                  Z(i) IS THE DISTANCE FROM THE i-TH EVENT
!                  TO IT'S NEAREST NEIGHBOR
!
!                  MU(ZBAR) = 0.5*N**(-1/2)  + 0.206*N**(-1) +
!                             0.164*N**(-3/2)
!
!                  SIGMA(ZBAR) = 0.070*N**(-2) + 0.148*N**(-5/2)
!
!               THIS IS A MODIFIED VERSION OF THE CLARK-EVANS TEST
!               (GIVEN BY DONNELLY).
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE FIRST RESPONSE
!                                VARIABLE.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE SECOND RESPONSE
!                                VARIABLE.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!                     --STATNU = THE SINGLE PRECISION VALUE OF THE
!                                CHI-SQUARE DEGREES OF FREEDOM.
!                     --PVALUE = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED P-VALUE.
!     REFERENCE--DALE ZIMMERMAN (1993), "A BIVARIATE CRAMER-VON MISES
!                TYPE OF TEST FOR SPATIAL RANDONNESS", JOURNAL OF
!                THE ROYAL STATISTICAL SOCIETY, SERIES C (APPLIED
!                STATISTICS, VOL. 42, NO. 1, PP. 43-54.
!                LONDON.
!              --CLARK AND EVANS (1954), "DISTANCE TO NEAREST
!                NEIGHBOR AS A MEASURE OF SPATIAL RELATIONSHIPS
!                IN POPULATIONS", ECOLOGY, 35, PP. 23-30.
!              --DONNELLY (1978), "SIMULATIONS TO DETERMINE THE
!                VARIANCE AND EDGE-EFFECT OF TOTAL NEAREST-NEIGHBOR
!                DISTANCE", IN SIMULATION STUDIES IN ARCHAEOLOGY
!                (ED. HODDER), PP. 91-95, LONDON: CAMBRIDGE UNIVERSITY
!                PRESS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013.12
!     ORIGINAL VERSION--DECEMBER  2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION YTEMP(*)
      DIMENSION DIST(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='R4  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSR4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      STATVA=CPUMIN
      STATCD=CPUMIN
      STATNU=CPUMIN
      PVALUE=CPUMIN
!
!               *******************************************
!               **  MEAN NEAREST NEIGHBORS TEST          **
!               *******************************************
!
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MEAN NEAREST NEIGHBORS TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN FOUR.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL NEARNE(Y,X,N,YTEMP,DIST,   &
                  IBUGA3,ISUBRO,IERROR)
      CALL MEAN(DIST,N,IWRITE,ZMEAN,IBUGA3,IERROR)
      AN=REAL(N)
      AMUZ=(0.5/SQRT(AN)) + (0.206/AN) + (0.164/AN**(-1.5))
      VARZ=(0.070/AN**2) + (0.148/AN**(-2.5))
      STATVA=(ZMEAN - AMUZ)/VARZ
      CALL NORCDF(STATVA,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(STATVA.LE.0.0)THEN
        PVALUE=2.0*PVALLT
      ELSE
        PVALUE=2.0*PVALUT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSR4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATCD,PVALUE,IERROR
 9015   FORMAT('STATVA,STATCD,PVALUE,IERROR = ',3G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)AMUZ,VARZ
 9016   FORMAT('AMUZ,VARZ = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSR4
      SUBROUTINE DPCSR5(X,Y,N,JINDX,DIST,   &
                        STATVA,STATV2,STATCD,PVALUE,STATNU,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES POLLARD'S TEST FOR
!              COMPLETE SPATIAL RANDOMNESS FOR BIVARIATE DATA.
!              WE HAVE A SET OF N POINTS (X,Y).
!
!              THE TEST STATISTIC IS
!
!                  P(j) = C1*[N*LN(C2) - C3]/C4
!
!              WHERE
!
!                  C1 = 12*j**2*N
!                  C2 = SUM[i=1 to N][X(ij)**2/N]
!                  C3 = SUM[i=1 to N][LOG(X(ij)**2)]
!                  C4 = (6*j*N + N + 1)*(N-1)
!
!              AND WHERE
!
!                  j DENOTES THE j-TH NEAREST NEIGHBOR
!                  X(ij) IS THE DISTANCE FROM THE i-TH POINT TO
!                        IT'S J-TH NEAREST NEIGHBOR
!
!               J IS 1, 2, 3, 4, 5
!
!               (N-1)*P(j) HAS A CHI-SQUARE DISTRIBUTION WITH
!               (N-1) DEGREES OF FREEDOM.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE FIRST RESPONSE
!                                VARIABLE.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS FOR THE SECOND RESPONSE
!                                VARIABLE.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!                     --STATNU = THE SINGLE PRECISION VALUE OF THE
!                                CHI-SQUARE DEGREES OF FREEDOM.
!                     --PVALUE = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED P-VALUE.
!     REFERENCE--FORTIN AND DALE (2005), "SPATIAL ANALYSIS: A GUIDE
!                FOR ECOLOGISTS", CAMBRIDGE UNIVERSITY PRESS, PP. 34-35.
!              --POLLARD (1971), "ON DISTANCE ESTIMATORS OF DENSITY
!                IN RANDOMLY DISTRIBUTED FORESTS", BIOMETRICS, 27,
!                991-1002.
!              --LIU (2001), "A COMPARISON OF FIVE DISTANCE-BASED METHODS
!                FOR PATTERN ANALYSIS", JOURNAL OF VEGETATION SCIENCE,
!                12, 411-416.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014.01
!     ORIGINAL VERSION--JANUARY   2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION DIST(*)
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DJ
      DOUBLE PRECISION DSTAT
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='R5  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR5')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSR5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      STATVA=CPUMIN
      STATCD=CPUMIN
      STATNU=CPUMIN
      PVALUE=CPUMIN
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS. **
!               **  FIRST FILTER OUT ANY DUPLICATE POINTS.**
!               ********************************************
!
      IF(JINDX.LT.1 .OR. JINDX.GT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,92)JINDX
   92   FORMAT('      THE DISTANCE INDEX (',I8,') IS LESS THAN ',   &
               '1 OR GREATER THAN 5.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      ICNT=0
      DO 101 I=1,N-1
        DO 103 J=I+1,N
          IF(X(I).EQ.X(J) .AND. Y(I).EQ.Y(J))GO TO 101
  103   CONTINUE
        ICNT=ICNT+1
        X(ICNT)=X(I)
        Y(ICNT)=Y(I)
  101 CONTINUE
      ICNT=ICNT+1
      X(ICNT)=X(N)
      Y(ICNT)=Y(N)
!
      N=ICNT
      IF(N.LT.10)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN POLLARD TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF UNIQUE OBSERVATIONS FOR THE ',   &
               'RESPONSE VARIABLE IS LESS THAN TEN.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  COMPUTE POLLARDS STATISTIC            **
!               ********************************************
!
      DN=DBLE(N)
      DJ=DBLE(JINDX)
      DC1=12.0D0*(DJ**2)*DN
      DC2=(6.0D0*DJ*DN + DN + 1.0D0)*(DN - 1.0D0)
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,N
        X2=X(I)
        Y2=Y(I)
        CALL NEARN3(Y,X,N,Y2,X2,DIST,   &
                    IBUGA3,ISUBRO,IERROR)
        DX=DBLE(DIST(JINDX))
        DSUM1=DSUM1 + DX**2/DN
        DSUM2=DSUM2 + DLOG(DX**2)
  200 CONTINUE
!
      DSTAT=DC1*(DN*DLOG(DSUM1) - DSUM2)/DC2
!
      STATVA=REAL(DSTAT)
      STATV2=REAL(N-1)*STATVA
      IDF=N-1
      STATNU=REAL(IDF)
      CALL CHSCDF(STATV2,IDF,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(STATCD.LE.0.5)THEN
        PVALUE=2.0*PVALLT
      ELSE
        PVALUE=2.0*PVALUT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CSR5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSR5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATV2,STATCD,PVALUE,IERROR
 9015   FORMAT('STATVA,STATV2,STATCD,PVALUE,IERROR = ',4G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)AMUZ,VARZ
 9016   FORMAT('AMUZ,VARZ = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSR5
      SUBROUTINE DPCSTE(MAXNXT,ICAPSW,IFORSW,ICASAN,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A ONE-SAMPLE CHI-SQUARED TEST
!     EXAMPLE--CHI-SQUARED TEST Y SIGMA
!              CHI-SQUARED TEST SIGMA Y
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/2
!     ORIGINAL VERSION--FEBRUARY  1994.
!     UPDATED         --DECEMBER  1994.  COPY CHI-SQUARED TEST PARAM.
!     UPDATED         --MAY       1995.  BUG FIX
!     UPDATED         --JANUARY   2004.  SUPPORT FOR HTML, LATEX
!     UPDATED         --APRIL     2011.  USE DPPARS AND DPPAR3
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
!
      CHARACTER*4 IREPL
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='TE  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='YES'
      IERROR='NO'
!
      ICASA2='BOTH'
      IF(ICASAN.EQ.'CSLT')THEN
        ICASAN='CSTE'
        ICASA2='LOWE'
      ELSEIF(ICASAN.EQ.'CSUT')THEN
        ICASAN='CSTE'
        ICASA2='UPPE'
      ELSEIF(ICASAN.EQ.'CS2T')THEN
        ICASAN='CSTE'
        ICASA2='TWOT'
      ENDIF
!
!               ***************************************
!               **  TREAT THE CHI-SQUARED TEST CASE  **
!               ***************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSTE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCSTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSTE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CHI-SQUARE TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      MINNVA=2
      MAXNVA=MAXSPN
      IFLAGP=29
      IF(IREPL.EQ.'ON')THEN
        IFLAGE=1
        IFLAGM=0
      ENDIF
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!     EITHER THE FIRST OR LAST ARGUMENT SHOULD BE A PARAMETER.
!
      IF(IVARTY(1).NE.'PARA' .AND. IVARTY(NUMVAR).NE.'PARA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN CHI-SQUARE TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,292)
  292   FORMAT('      EITHER THE FIRST OR THE LAST ARGUMENT MUST BE ',   &
               'A PARAMETER.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IVARTY(1).EQ.'PARA')THEN
        ISTART=2
        ISTOP=NUMVAR
        SIGMA0=PVAR(1)
      ELSEIF(IVARTY(NUMVAR).EQ.'PARA')THEN
        ISTART=1
        ISTOP=NUMVAR-1
        SIGMA0=PVAR(NUMVAR)
      ENDIF
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: NO REPLICATION CASE        **
!               *****************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSTE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=1
      DO 5210 I=ISTART,ISTOP
        ICOL=I
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,Y,Y,NS1,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 52--                          **
!               **  PERFORM CHI-SQUARE TEST            **
!               *****************************************
!
        ISTEPN='52'
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSTE')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5211)
 5211     FORMAT('***** FROM DPCSTE, BEFORE CALL DPCST2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5212)I,J,NS1,MAXN
 5212     FORMAT('I,J,NS1,MAXN = ',4I8)
          CALL DPWRST('XXX','BUG ')
          DO 5215 II=1,NS1
            WRITE(ICOUT,5216)II,Y(II)
 5216       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 5215     CONTINUE
        ENDIF
!
        IVARID=IVARN1(I)
        IVARI2=IVARN2(I)
        CALL DPCST2(Y,NS1,SIGMA0,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    IVARID,IVARI2,ICASA2,   &
                    STATVA,STATCD,STATNU,PVAL2T,PVALLT,PVALUT,   &
                    CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                    CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
        ISTEPN='8C'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CSTE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(ISTOP-ISTART.GT.0)THEN
          IFLAGU='FILE'
        ELSE
          IFLAGU='ON'
        ENDIF
        IFRST=.FALSE.
        ILAST=.FALSE.
        IF(I.EQ.ISTART)IFRST=.TRUE.
        IF(I.EQ.ISTOP)ILAST=.TRUE.
        STATV2=CPUMIN
        STATC2=CPUMIN
        STATN2=CPUMIN
        ICASA3='ONES'
        CALL DPTTE5(ICASA3,STATVA,STATCD,STATNU,   &
                    STATV2,STATC2,STATN2,   &
                    PVAL2T,PVALLT,PVALUT,   &
                    CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                    CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                    IFLAGU,IFRST,ILAST,   &
                    IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 5210 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CSTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCSTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)STATVA,STATCD,PVAL
 9018   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCSTE
      SUBROUTINE DPCST2(Y1,N1,SIGMA0,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IVARID,IVARI2,ICASA2,   &
                        STATVA,STATCD,STATNU,PVAL2T,PVALLT,PVALUT,   &
                        CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                        CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A ONE-SAMPLE CHI-SQUARED TEST
!     EXAMPLE--CHI-SQUARED TEST Y SIGMA0
!              CHI-SQUARED TEST SIGMA0 Y
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MAY       1984.
!     UPDATED         --APRIL     1987.  (LARRY KNAB CORRECTION--
!                                        BROWNLEE, P. 225)
!     UPDATED         --FEBRUARY  1994.  REFORMAT OUTPUT
!     UPDATED         --FEBRUARY  1994.  DPWRST: 'BUG ' => 'WRIT'
!     UPDATED         --DECEMBER  1994.  COPY CHI-SQUARED TEST PARAM.
!     UPDATED         --OCTOBER   2001.  MODIFY SOME OF THE
!                                        PRINT OUT FOR BETTER
!                                        CLARITY
!     UPDATED         --JANUARY   2004.  SUPPORT FOR HTML, LATEX
!     UPDATED         --APRIL     2011.  USE DPDTA1 AND DPDTA5 TO
!                                        PRINT OUTPUT.  REFORMAT OUTPUT
!                                        SOMEWHAT AS WELL.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 ICASA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='T2  '
      IERROR='NO'
      IWRITE='OFF'
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CST2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCST2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,SIGMA0,N1
   52   FORMAT('IBUGA3,ISUBRO,SIGMA0,N1 = ',2(A4,2X),G15.7,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N1
          WRITE(ICOUT,57)I,Y1(I)
   57     FORMAT('I,Y1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************
!               **  STEP 31--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR A CHI-SQUARED TEST  **
!               ******************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CST2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCST3(Y1,N1,SIGMA0,IWRITE,   &
                  STATVA,STATCD,STATNU,   &
                  YMEAN,YSD,RATIO,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IDF=INT(STATNU+0.1)
      CALL CHSPPF(.0005,IDF,CTL999)
      CALL CHSPPF(.005,IDF,CUTL99)
      CALL CHSPPF(.025,IDF,CUTL95)
      CALL CHSPPF(.05,IDF,CUTL90)
      CALL CHSPPF(.1,IDF,CUTL80)
      CALL CHSPPF(.25,IDF,CUTL50)
      CALL CHSPPF(.75,IDF,CUTU50)
      CALL CHSPPF(.90,IDF,CUTU80)
      CALL CHSPPF(.95,IDF,CUTU90)
      CALL CHSPPF(.975,IDF,CUTU95)
      CALL CHSPPF(.995,IDF,CUTU99)
      CALL CHSPPF(.9995,IDF,CTU999)
!
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(YSD.LE.SIGMA0)THEN
        PVAL2T=2.0*STATCD
      ELSE
        PVAL2T=2.0*(1.0 - STATCD)
      ENDIF
!
!               *******************************
!               **   STEP 32--               **
!               **   WRITE OUT EVERYTHING    **
!               **   FOR A CHI-SQUARED TEST  **
!               *******************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CST2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE='One Sample Chi-Square Standard Deviation Test'
      NCTITL=45
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Standard Deviation Equal'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=SIGMA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Standard Deviation Not Equal'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=SIGMA0
      IDIGIT(ICNT)=NUMDIG
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=YMEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=YSD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='s/sigma0'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=RATIO
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Chi-Square Test Statistic Value:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Degrees of Freedom:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=INT(STATNU+0.1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 2110 I=1,NUMROW
        NTOT(I)=15
 2110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='21A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CST2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='21B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CST2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Two-Tailed Test'
      NCTITL=15
      ITITL9='H0: sigma = sigma0; Ha: sigma <> sigma0'
      NCTIT9=39
!
      DO 2130 J=1,5
        DO 2140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 2140   CONTINUE
 2130 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (<)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Upper'
      NCTIT2(1,4)=5
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value (>)'
      NCTIT2(3,4)=9
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 2150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 2150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=150
      IINC=1600
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 2160 J=1,NUMALP
!
        AMAT(J,2)=STATVA
        ALPHAT=(1.0 - ALPHA(J))/2.0
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,3)=ATEMP
        ALPHAT=1.0 - ALPHAT
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,4)=ATEMP
        IVALUE(J,5)(1:6)='ACCEPT'
        IF(STATVA.LT.AMAT(J,3))IVALUE(J,5)(1:6)='REJECT'
        IF(STATVA.GT.AMAT(J,4))IVALUE(J,5)(1:6)='REJECT'
        NCVALU(J,5)=6
!
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
 2160 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA2.NE.'LOWE' .AND. ICASA2.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASA2.EQ.'TWOT')GO TO 9000
!
      ITITLE='Lower-Tailed Test'
      NCTITL=17
      ITITL9='H0: sigma = sigma0; Ha: sigma < sigma0'
      NCTIT9=38
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (<)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 2250 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.4)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 2250 CONTINUE
!
      DO 2260 J=1,NUMALP
!
        AMAT(J,2)=STATVA
        ALPHAT=(1.0 - ALPHA(J))
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='ACCEPT'
        IF(STATVA.LT.AMAT(J,3))IVALUE(J,4)(1:6)='REJECT'
        NCVALU(J,4)=6
!
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
 2260 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA2.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASA2.EQ.'LOWE')GO TO 9000
!
      ITITLE='Upper-Tailed Test'
      NCTITL=17
      ITITL9='H0: sigma = sigma0; Ha: sigma > sigma0'
      NCTIT9=38
!
      ITITL2(1,3)='Upper'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (>)'
      NCTIT2(3,3)=9
!
      NMAX=0
      NUMCOL=4
      DO 2350 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
 2350 CONTINUE
!
      DO 2360 J=1,NUMALP
!
        ALPHAT=ALPHA(J)
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='ACCEPT'
        IF(STATVA.GT.AMAT(J,3))IVALUE(J,4)(1:6)='REJECT'
        NCVALU(J,4)=6
 2360 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA2.NE.'LOWE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CST2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCST2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)IERROR,STATVA,STATCD,STATNU
 9013   FORMAT('IERROR,STATVA,STATCD,STATNU = ',A4,3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCST2
      SUBROUTINE DPCST3(X,N,SIGMA0,IWRITE,   &
                        STATVA,STATCD,STATNU,   &
                        XMEAN,XSD,RATIO,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE ONE SAMPLE CHI-SQUARE TEST
!              (AND ALTERNATIVELY THE CDF VALUE).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --SIGMA0 = THE SINGLE PRECISION VALUE FOR WHICH
!                                THE TEST IS PERFORMED (I.E.,
!                                H0: SIGMA = SIGMA0).
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             TEST STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--CHSCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.2
!     ORIGINAL VERSION--FEBRUARY  2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IWRTSV
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCS'
      ISUBN2='T3  '
      IWRTSV=IWRITE
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CST3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCST3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,SIGMA0
   53   FORMAT('N,SIGMA0 = ',I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  COMPUTE ONE SAMPLE CHI-SQUARE TEST  **
!               ******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      STATVA=-99.0
      STATCD=-99.0
      IWRITE='OFF'
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN CHI-SQUARE SD TEST--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS FOR THE ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
               '.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(SIGMA0.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1101)
 1101   FORMAT('      THE SPECIFIED SIGMA0 IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1102)SIGMA0
 1102   FORMAT('SIGMA0 = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 1135 I=2,N
        IF(X(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1131)HOLD
 1131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
 1139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE ONE SAMPLE CHI-SQUARE TEST.  **
!               ***********************************************
!
      CALL MEAN(X,N,IWRITE,XMEAN,IBUGA3,IERROR)
      CALL SD(X,N,IWRITE,XSD,IBUGA3,IERROR)
      AN=N
      RATIO=XSD/SIGMA0
      STATVA=(AN-1.0)*RATIO**2
      IDF=N-1
      STATNU=REAL(IDF)
      CALL CHSCDF(STATVA,IDF,STATCD)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,STATVA
  811   FORMAT('THE VALUE OF THE CHI-SQUARE SD TEST OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IWRITE=IWRTSV
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CST3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCST3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATCD
 9015   FORMAT('STATVA,STATCD = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)XMEAN,XSD
 9016   FORMAT('XMEAN,XSD = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCST3
      SUBROUTINE DPCVCI(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,IMULT,IREPL,ISEED,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--GENERATE A CONFIDENCE INTERVAL FOR THE COEFFICIENT OF
!              VARIATION FOR NORMALLY DISTRIBUTED DATA.  THE FOLLOWING
!              ARE SUPPORTED:
!
!                  COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!                  LOGNORMAL COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!                  COMMON COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y X
!
!              THE REPLICATION AND MULTIPLE KEYWORDS ARE SUPPORTED FOR
!              THE SINGLE VARIABLE CASE.  THE MULTIPLE OPTION IS
!              SUPPORTED FOR THE TWO VARIABLE (COMMON) CASE.
!
!              THE ONE SIDED <LOWER/UPPER> OPTIONS ARE ALSO SUPPORTED.
!
!              IN ADDITION, SUPPORT
!
!                 CONFIDENCE INTERVAL FOR COEFFICIENT OF DISPERSION
!                 CONFIDENCE INTERVAL FOR COEFFICIENT OF QUARTILE DISPERSION
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016/12
!     REFERENCES--MARK VANGEL (1996), "CONFIDENCE INTERVALS FOR A NORMAL
!                 COEFFICIENT OF VARIATION", AMERICAN STATISTICIAN,
!                 VOL. 15, NO. 1, PP. 21-26.
!                 GUIDE FOR PRACTIONERS", WILEY, PP. 55-56.
!               --MCKAY (1932), "DISTRIBUTIONS OF THE COEFFICIENT OF
!                 VARIATION AND THE EXTENDED 't' DISTRIBUTION", JOURNAL
!                 OF THE ROYAL STATISTICAL SOCIETY, VOL. 95, PP. 695-698.
!               --Steve Verrill, Confidence Bounds for Normal and
!                 Lognormal Distribution Coefficients of Variation, 2003,
!                 Research Paper 609, USDA Forest Products Laboratory,
!                 Madison, Wisconsin.
!               --Verrill, S. and Johnson, R.A. (2007). "Confidence
!                 Bounds and Hypothesis Tests for Normal Distribution
!                 Coefficients of Variation." Communications in Statistics
!                 Theory and Methods, Volume 36, Number 12, pages 2187-2206.
!               --JOHANNES FORKMAN (xxxx), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS",
!               --BONETT AND SEIER (2006), "CONFIDENCE INTERVAL FOR A
!                 COEFFICIENT OF DISPERSION", BIOMETRICAL JOURNAL,
!                 VOL. 48, NO. 1, PP. 144-148.
!     ORIGINAL VERSION--JANUARY   2017.
!     UPDATED         --NOVEMBER  2017. SUPPORT FOR COEFFICIENT OF
!                                       DISPERSION CONFIDENCE INTERVAL
!     UPDATED         --DECEMBER  2017. SUPPORT FOR COEFFICIENT OF
!                                       QUARTILE DISPERSION CONFIDENCE
!                                       INTERVAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFLAGU
!
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ICOMM
      CHARACTER*4 IDIST
      CHARACTER*4 ICTMP0
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICTMP5
      CHARACTER*4 ICTMP6
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(MAXSPN)
      CHARACTER*4 IVARI2(MAXSPN)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
!
      DIMENSION XDESGN(MAXOBV,6)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
!
      INTEGER ITEMP1(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      EQUIVALENCE (GARBAG(IGARB1),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB2),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB3),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB4),XIDTE4(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTE5(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE6(1))
      EQUIVALENCE (GARBAG(IGARB7),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB9),TEMP3(1))
      EQUIVALENCE (GARBAG(IGAR10),TEMP4(1))
      EQUIVALENCE (GARBAG(JGAR11),XDESGN(1,1))
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='CI  '
      IFOUND='YES'
      IERROR='NO'
      IREPL='OFF'
      IMULT='OFF'
      ICOMM='OFF'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
      MAXNXT=MAXOBV
!
!               ****************************************************
!               **  TREAT THE COEFFICIENT OF VARIATION CONFIDENCE **
!               **  LIMITS CASE                                   **
!               ****************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVCI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVCI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE COMMAND        **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     THE FOLLOWING COMMANDS ARE ACCEPTED:
!
!         COEFFICIENT OF VARIATION CONFIDENCE LIMITS Y        (TWO SIDED)
!         LOWER COEFFICIENT OF VARIATION CONFIDENCE LIMITS Y  (ONE SIDED)
!         UPPER COEFFICIENT OF VARIATION CONFIDENCE LIMITS Y  (ONE SIDED)
!         LOGNORMAL COEFFICIENT OF VARIATION CONFIDENCE
!                   LIMITS Y                                  (TWO SIDED)
!         LOWER LOGNORMAL COEFFICIENT OF VARIATION
!               CONFIDENCE LIMITS Y                           (ONE SIDED)
!         UPPER LOGNORMAL COEFFICIENTOF VARIATION
!               CONFIDENCE LIMITS Y                           (ONE SIDED)
!         COMMON COEFFICIENT OF VARIATION CONFIDENCE LIMITS Y X (TWO SIDED)
!         COEFFICIENT OF DISPERSION CONFIDENCE LIMITS Y       (TWO SIDED)
!         LOWER COEFFICIENT OF DISPERSION CONFIDENCE LIMITS Y (ONE SIDED)
!         UPPER COEFFICIENT OF DISPERSION CONFIDENCE LIMITS Y (ONE SIDED)
!         COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMITS Y       (TWO SIDED)
!         LOWER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMITS Y (ONE SIDED)
!         UPPER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMITS Y (ONE SIDED)
!
!     IN ADDITION, CHECK FOR THE "MULTIPLE" AND "REPLICATION" OPTIONS.
!
      ILASTZ=9999
      IFOUND='NO'
      ICASAN='CVLI'
      ICASA2='UPPE'
      ICASA3='RAW'
      ICASA4='TWOS'
      IDIST='NORM'
!
      DO 100 I=0,NUMARG-1
!
        ICTMP0='XXXX'
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
          ICTMP5=IHARG(I+4)
          ICTMP6=IHARG(I+5)
        ELSE
          IF(I.GE.2)ICTMP0=IHARG(I-1)
          ICTMP1=IHARG(I)
          ICTMP2=IHARG(I+1)
          ICTMP3=IHARG(I+2)
          ICTMP4=IHARG(I+3)
          ICTMP5=IHARG(I+4)
          ICTMP6=IHARG(I+5)
        ENDIF
!
        IF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
           ICTMP3.EQ.'VARI' .AND. ICTMP4.EQ.'CONF' .AND.   &
           ICTMP5.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+4
          ICASAN='CVLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'VARI' .AND. ICTMP4.EQ.'CONF' .AND.   &
               ICTMP5.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+4
          ICASAN='CVLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'DISP' .AND. ICTMP4.EQ.'CONF' .AND.   &
               ICTMP5.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+4
          ICASAN='CDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'DISP' .AND. ICTMP4.EQ.'CONF' .AND.   &
               ICTMP5.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+4
          ICASAN='CDLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'DISP' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'DISP' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
               ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'DISP' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
               ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'DISP' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'VARI' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'COEF' .AND. ICTMP2.EQ.'OF  ' .AND.   &
               ICTMP3.EQ.'QUAR' .AND. ICTMP4.EQ.'VARI' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
               ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'VARI' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'LIMI')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'QUAR' .AND. ICTMP2.EQ.'COEF' .AND.   &
               ICTMP3.EQ.'OF  ' .AND. ICTMP4.EQ.'VARI' .AND.   &
               ICTMP5.EQ.'CONF' .AND. ICTMP6.EQ.'INTE')THEN
          IFOUND='YES'
          ILASTZ=I+5
          ICASAN='CQLI'
          GO TO 109
        ELSEIF(ICTMP1.EQ.'LOWE')THEN
          ICASA4='ONES'
          ICASA2='LOWE'
        ELSEIF(ICTMP1.EQ.'UPPE')THEN
          ICASA4='ONES'
          ICASA2='UPPE'
        ELSEIF(ICTMP1.EQ.'ONE ' .AND. ICTMP2.EQ.'SIDE')THEN
          ICASA4='ONES'
        ELSEIF(ICTMP1.EQ.'REPL')THEN
          IREPL='ON'
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
        ELSEIF(ICTMP1.EQ.'COMM')THEN
          ICOMM='ON'
        ELSEIF(ICTMP1.EQ.'LOGN')THEN
          IDIST='LOGN'
        ENDIF
  100 CONTINUE
  109 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN COEFFICIENT OF VARIATION CONFIDENCE ',   &
                 'LIMITS--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)
  102     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION" FOR THIS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(ICOMM.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,112)
  112     FORMAT('      YOU CANNOT SPECIFY BOTH "COMMON" AND ',   &
                 '"REPLICATION" FOR THIS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSEIF(IDIST.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,114)
  114     FORMAT('      YOU CANNOT SPECIFY BOTH "COMMON" AND ',   &
                 '"LOGNORMAL" FOR THIS COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COEFFICIENT OF VARIATION CONFIDENCE LIMI'
      IF(ICASAN.EQ.'CDLI')INAME=   &
         'COEFFICIENT OF DISPERSION CONF LIMI'
      IF(ICASAN.EQ.'CQLI')INAME=   &
         'COEFF OF QUARTILE DISPERSION CONF LIMI'
      MAXNA=100
      MINNVA=1
      MAXNVA=100
      MINNA=1
      IFLAGE=1
      IFLAGM=1
      IF(IREPL.EQ.'ON')THEN
        MAXNVA=7
        IFLAGM=0
      ELSE
        MAXNVA=30
        IFLAGE=0
      ENDIF
      IF(ICOMM.EQ.'ON')THEN
        MINNVA=2
        IF(IMULT.EQ.'OFF')MAXNVA=2
      ENDIF
      MINN2=4
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(NUMVAR.GT.1 .AND. IREPL.EQ.'OFF' .AND. ICOMM.EQ.'OFF')   &
         IMULT='ON'
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT,IREPL,ICOMM
  182   FORMAT('NQ,NUMVAR,IMULT,IREPL,ICOMM = ',2I8,3(2X,A4))
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
!
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,212)
  212     FORMAT('      MUST BE BETWEEN ONE AND SIX.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,213)NREPL
  213     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSEIF(ICOMM.EQ.'ON')THEN
        NRESP=2
      ELSE
        NRESP=1
      ENDIF
!
      IH='NNEW'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'YES')THEN
        NNEW=1
      ELSE
        NNEW=INT(VALUE(ILOCV)+0.5)
        IF(NNEW.LT.1)NNEW=1
      ENDIF
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')THEN
        WRITE(ICOUT,221)NRESP,NREPL,NNEW
  221   FORMAT('NRESP,NREPL,NNEW = ',3I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  GENERATE THE PREDICTION LIMITS FOR THE VARIOUS  **
!               **  CASES                                           **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: NO REPLICATION             **
!               *****************************************
!
      IF(NREPL.EQ.0)THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       COMMON COEFFICIENT OF VARIATION CASE
!
        IF(ICOMM.EQ.'ON')THEN
          IF(IMULT.EQ.'OFF')THEN
!
!           CASE WHERE RESPONSE AND GROUP-ID VARIABLE GIVEN
!
            IINDX=ICOLR(1)
            PID(1)=CPUMIN
            IVARID(1)=IVARN1(1)
            IVARI2(1)=IVARN2(1)
            IINDX2=ICOLR(2)
            PID(2)=CPUMIN
            IVARID(2)=IVARN1(2)
            IVARI2(2)=IVARN2(2)
!
            ICOL=1
            NUMVA2=2
            CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        Y,TEMP1,TEMP1,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
!           *****************************************************
!           **  STEP 4B--                                      **
!           *****************************************************
!
            ISTEPN='4B'
            IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
            IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVCI')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,422)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,463)ICASAN,NUMVAR,NLOCAL
  463         FORMAT('ICASAN,NUMVAR,NLOCAL = ',A4,2I8)
              CALL DPWRST('XXX','BUG ')
              IF(NLOCAL.GE.1)THEN
                DO 465 I=1,NLOCAL
                  WRITE(ICOUT,466)I,Y(I),TEMP1(I)
  466             FORMAT('I,Y(I),TEMP1(I) = ',I8,2G15.7)
                  CALL DPWRST('XXX','BUG ')
  465           CONTINUE
              ENDIF
            ENDIF
!
            CALL DPCVC2(Y,TEMP1,NLOCAL,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                        ISEED,MAXNXT,IQUAME,   &
                        ISUBRO,IBUGA3,IERROR)
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(IRESP.EQ.1)IFRST=.TRUE.
            IF(IRESP.EQ.NRESP)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
          ELSE
!
!           CASE WHERE EACH GROUP AS SEPARATE VARIABLE
!
            PID(1)=CPUMIN
            IVARID(1)='NULL'
            IVARI2(1)='    '
            PID(2)=CPUMIN
            IVARID(2)='NULL'
            IVARI2(2)='    '
!
            ICOL=1
            NUMVA2=NUMVAR
            CALL DPPAR8(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        XTEMP1,Y,TEMP1,NLOCAL,ICASE,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
            NUMVAR=2
            IMULT='OFF'
!
!               *****************************************************
!               **  STEP 4C--                                      **
!               *****************************************************
!
            CALL DPCVC2(Y,TEMP1,NLOCAL,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                        ISEED,MAXNXT,IQUAME,   &
                        ISUBRO,IBUGA3,IERROR)
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(IRESP.EQ.1)IFRST=.TRUE.
            IF(IRESP.EQ.NRESP)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
          ENDIF
        ELSE
!
!         LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
          NCURVE=0
          DO 410 IRESP=1,NRESP
            NCURVE=NCURVE+1
!
            IINDX=ICOLR(IRESP)
            PID(1)=CPUMIN
            IVARID(1)=IVARN1(IRESP)
            IVARI2(1)=IVARN2(IRESP)
!
            IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,411)IRESP,NCURVE
  411         FORMAT('IRESP,NCURVE = ',2I5)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
            ICOL=IRESP
            NUMVA2=1
            CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                        INAME,IVARN1,IVARN2,IVARTY,   &
                        ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                        MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                        MAXCP4,MAXCP5,MAXCP6,   &
                        V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                        Y,XTEMP1,XTEMP2,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                        IBUGA3,ISUBRO,IFOUND,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
!
!           *****************************************************
!           **  STEP 4B--                                      **
!           *****************************************************
!
            ISTEPN='4B'
            IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
            IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVCI')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,422)
  422         FORMAT('***** FROM THE MIDDLE  OF DPCVCI--')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,423)ICASAN,NUMVAR,NLOCAL,IRESP
  423         FORMAT('ICASAN,NUMVAR,NLOCAL,IRESP = ',A4,3I8)
              CALL DPWRST('XXX','BUG ')
              IF(NLOCAL.GE.1)THEN
                DO 425 I=1,NLOCAL
                  WRITE(ICOUT,426)I,Y(I)
  426             FORMAT('I,Y(I) = ',I8,F12.5)
                  CALL DPWRST('XXX','BUG ')
  425           CONTINUE
              ENDIF
            ENDIF
!
            CALL DPCVC2(Y,Y,NLOCAL,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                        ISEED,MAXNXT,IQUAME,   &
                        ISUBRO,IBUGA3,IERROR)
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(IRESP.EQ.1)IFRST=.TRUE.
            IF(IRESP.EQ.NRESP)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
  410     CONTINUE
        ENDIF
!
!               ****************************************************
!               **  STEP 5A--                                     **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.    **
!               **          FOR THIS CASE, ALL VARIABLES MUST     **
!               **          HAVE THE SAME LENGTH.                 **
!               ****************************************************
!
      ELSEIF(IREPL.EQ.'ON')THEN
        ISTEPN='5A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 510 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 510
          J=J+1
!
!         RESPONSE VARIABLE IN Y
!
          ICOLC=1
          IJ=MAXN*(ICOLR(ICOLC)-1)+I
          IF(ICOLR(ICOLC).LE.MAXCOL)Y(J)=V(IJ)
          IF(ICOLR(ICOLC).EQ.MAXCP1)Y(J)=PRED(I)
          IF(ICOLR(ICOLC).EQ.MAXCP2)Y(J)=RES(I)
          IF(ICOLR(ICOLC).EQ.MAXCP3)Y(J)=YPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP4)Y(J)=XPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP5)Y(J)=X2PLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
          IF(NREPL.GE.1)THEN
            DO 520 IR=1,MIN(NREPL,6)
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  520       CONTINUE
          ENDIF
!
  510   CONTINUE
        NLOCAL=J
!
        ISTEPN='5B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        PID(1)=CPUMIN
        IVARID(1)=IVARN1(1)
        IVARI2(1)=IVARN2(1)
        IADD=1
        DO 540 II=1,NREPL
          IVARID(II+IADD)=IVARN1(II+IADD)
          IVARI2(II+IADD)=IVARN2(II+IADD)
  540   CONTINUE
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS.                          **
!       *****************************************************
!
        ISTEPN='5C'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVCI')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVCI')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,541)
  541     FORMAT('***** FROM THE MIDDLE  OF DPSDCL--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,542)ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL
  542     FORMAT('ICASAN,NUMVAR,NLOCAL,NLOCA2,NREPL = ',A4,2X,4I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 545 I=1,NLOCAL
              WRITE(ICOUT,546)I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2)
  546         FORMAT('I,Y(I),X(I),XDESGN(I,1),XDESGN(I,2) = ',   &
                     I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  545       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 5C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,XTEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 5D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(IADD+1)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
!
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            NPLOT2=NPLOTP
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            PID(6+IADD)=XIDTE6(ISET4)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
                TEMP2(K)=X(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCVC2(TEMP1,TEMP1,NTEMP,ICASAN,ICASA2,ICASA3,ICASA4,   &
                          PID,IVARID,IVARI2,NREPL,TEMP3,TEMP4,ITEMP1,   &
                          CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                          CTL999,CTU999,   &
                          ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                          ISEED,MAXNXT,IQUAME,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
            CALL DPCNF3(CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        IFLAGU,IFRST,ILAST,ICASAN,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVCI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPSDCL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVCI
      SUBROUTINE DPCVC2(Y,X,N,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        PID,IVARID,IVARI2,NREPL,TEMP1,TEMP2,ITEMP1,   &
                        CUTL90,CUTU90,CUTL95,CUTU95,CUTL99,CUTU99,   &
                        CTL999,CTU999,   &
                        ICAPSW,ICAPTY,IFORSW,ICVACI,IDIST,ICOMM,   &
                        ISEED,MAXNXT,IQUAME,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--GENERATE A CONFIDENCE INTERVAL FOR THE COEFFICIENT
!              OF VARIATION FOR NORMALLY DISTRIBUTED DATA.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                ORIGINAL OBSERVATIONS.
!                       N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     REFERENCES--MARK VANGEL (1996), "CONFIDENCE INTERVALS FOR A NORMAL
!                 COEFFICIENT OF VARIATION", AMERICAN STATISTICIAN,
!                 VOL. 15, NO. 1, PP. 21-26.
!                 GUIDE FOR PRACTIONERS", WILEY, PP. 55-56.
!               --MCKAY (1932), "DISTRIBUTIONS OF THE COEFFICIENT OF
!                 VARIATION AND THE EXTENDED 't' DISTRIBUTION", JOURNAL
!                 OF THE ROYAL STATISTICAL SOCIETY, VOL. 95, PP. 695-698.
!               --JOHANNES FORKMAN (xxxx), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS",
!               --BONETT AND SEIER (2006), "CONFIDENCE INTERVAL FOR A
!                 COEFFICIENT OF DISPERSION", BIOMETRICAL JOURNAL,
!                 VOL. 48, NO. 1, PP. 144-148.
!               --BONETT (2006), "CONFIDENCE INTERVAL FOR A
!                 COEFFICIENT OF QUARTILE VARIATIOIN", COMPUTATIONAL
!                 STATISTICS AND DATA ANALYSIS, VOL. 50, PP. 2953-2957.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016/12
!     ORIGINAL VERSION--DECEMBER  2016.
!     UPDATED         --NOVEMBER  2017. SUPPORT COEFFICIENT OF DISPERSION
!                                       CONFIDENCE LIMITS
!     UPDATED         --DECEMBER  2017. SUPPORT FOR COEFFICIENT OF
!                                       QUARTILE DISPERSION CONFIDENCE
!                                       INTERVAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICVACI
      CHARACTER*4 IDIST
      CHARACTER*4 ICOMM
      CHARACTER*4 IQUAME
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*20 ISTR
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION PID(*)
!
      INTEGER ITEMP1(*)
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
      REAL CONF(NUMALP)
!
      DIMENSION ALOWLM(NUMALP)
      DIMENSION AUPPLM(NUMALP)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*40 ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      CHARACTER*20 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*4  IVALUE(MAXROW,NUMCLI)
      REAL         AVALUE(MAXROW)
      REAL         AMAT(MAXROW,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA /0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
!
      ISUBN1='DPCV'
      ISUBN2='C2  '
      IERROR='NO'
      IWRITE='OFF'
      ISTR='VARIATION'
      IF(ICASAN.EQ.'CDLI')ISTR='DISPERSION'
      IF(ICASAN.EQ.'CQLI')ISTR='QUARTILE DISPERSION'
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCVC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4 = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)N
   54   FORMAT('N = ',I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)ISTR
  101   FORMAT('***** ERROR IN COEFFICIENT OF ',A20,' CONFIDENCE ',   &
               'LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)
  103   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,105)N
  105   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)ISTR
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,131)HOLD
  131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
!               ***************************************
!               **  STEP 3--                         **
!               **  COMPUTE CONFIDENCE LIMITS        **
!               **  FOR VARIOUS PROBABILITY VALUES.  **
!               ***************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ICASAN - LIMI   => CONFIDENCE LIMIT FOR THE SD
!     ICASA2:  LOWE   => LOWER LIMIT
!              UPPE   => UPPER LIMIT
!     ICASA3:  RAW    => RAW DATA
!              SUMM   => SUMMARY DATA
!     ICASA4:  ONES   => ONE-SIDED LIMIT
!              TWOS   => TWO-SIDED LIMIT
!
!     NOTE THAT THE NON-CENTRAL T COMPUTATION CAN GET A LITTLE IFFY
!     FOR LARGE VALUES OF ALPHA AND LARGE VALUES OF THE NON-CENTRALITY
!     PARAMETER.  SO FOR THE EXACT METHOD, DO NOT USE THE HIGHEST
!     LEVEL OF ALPHA (99.9 CONFIDENCE).
!
      AN=N
      ICASA3='RAW'
      NUMAL2=NUMALP
      IF(ICOMM.EQ.'ON')THEN
        CALL DPCVC4(Y,X,N,ITEMP1,TEMP1,TEMP2,   &
                    ICASAN,ICASA2,ICASA3,ICASA4,   &
                    ALPHA,NUMAL2,ALOWLM,AUPPLM,   &
                    YCV,YCVBC,NDIST,NGROUP,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICASAN.EQ.'CDLI')THEN
        CALL DPCDC3(Y,N,ICASA2,ICASA4,ISEED,MAXNXT,   &
                    TEMP1,ALPHA,NUMAL2,ALOWLM,AUPPLM,   &
                    YCD,YMED,YAAD,   &
                    ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICASAN.EQ.'CQLI')THEN
        CALL DPCQD3(Y,N,ICASA2,ICASA4,ISEED,MAXNXT,IQUAME,   &
                    TEMP1,ALPHA,NUMAL2,ALOWLM,AUPPLM,   &
                    CQV,Q1,Q3,   &
                    ISUBRO,IBUGA3,IERROR)
!
!       OMIT THE 50% INTERVAL FOR THIS CASE
!
        ALOWLM(1)=CPUMIN
        AUPPLM(1)=CPUMIN
        IF(IERROR.EQ.'YES')GO TO 9000
      ELSE
        YMEAN=CPUMIN
        YSD=CPUMIN
        IF(N.LE.3000 .AND. ICVACI.EQ.'EXAC')NUMAL2=NUMALP-1
!
        CALL DPCVC3(Y,N,YMEAN,YSD,ICASAN,ICASA2,ICASA3,ICASA4,   &
                    ISEED,MAXNXT,IDIST,   &
                    TEMP1,TEMP2,   &
                    ICVACI,ALPHA,NUMAL2,ALOWLM,AUPPLM,YCV,   &
                    ISUBRO,IBUGA3,IERROR)
!
        IF(YSD.LE.0.0)THEN
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      CUTL90=ALOWLM(3)
      CUTU90=AUPPLM(3)
      CUTL95=ALOWLM(4)
      CUTU95=AUPPLM(4)
      CUTL99=ALOWLM(5)
      CUTU99=AUPPLM(5)
      CTL999=ALOWLM(6)
      CTU999=AUPPLM(6)
      NALP=NUMAL2
      DO 420 I=1,NUMAL2
        CONF(I)=100.0*ALPHA(I) + 0.0001
  420 CONTINUE
!
!               ****************************
!               **  STEP 5--              **
!               **  WRITE EVERYTHING OUT  **
!               ****************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      IF(ICASA4.EQ.'TWOS')THEN
        IF(ICOMM.EQ.'ON')THEN
          ITITLE=   &
          'Two-Sided Confidence Limits for the Common Coefficient'
          NCTITL=54
          ITITLZ='of Variation for Normally Distributed Data'
          NCTITZ=42
        ELSEIF(ICASAN.EQ.'CDLI')THEN
          ITITLE=   &
        'Two-Sided Confidence Limit for the Coefficient of Dispersion'
          NCTITL=60
          ITITLZ=' '
          NCTITZ=0
        ELSEIF(ICASAN.EQ.'CQLI')THEN
          ITITLE='Two-Sided Confidence Limit for the Coefficient of'
          NCTITL=49
          ITITLZ='Quartile Dispersion'
          NCTITZ=19
        ELSE
          ITITLE=   &
        'Two-Sided Confidence Limits for the Coefficient of Variation'
          NCTITL=60
          ITITLZ=' '
          NCTITZ=0
          IF(IDIST.EQ.'LOGN')THEN
            ITITLZ='for Lognormally Distributed Data'
            NCTITZ=32
          ELSE
            ITITLZ='for Normally Distributed Data'
            NCTITZ=29
          ENDIF
        ENDIF
      ELSEIF(ICASA4.EQ.'ONES')THEN
        IF(ICOMM.EQ.'ON')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            ITITLE=   &
       'One-Sided Lower Confidence Limits for the Common Coefficient'
            NCTITL=60
            ITITLZ='of Variation for Normally Distributed Data'
            NCTITZ=42
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            ITITLE=   &
       'One-Sided Upper Confidence Limits for the Common Coefficient'
            NCTITL=60
            ITITLZ='of Variation for Normally Distributed Data'
            NCTITZ=42
          ENDIF
        ELSEIF(ICASAN.EQ.'CDLI')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            ITITLE='One-Sided Lower Confidence Limits for the'
            NCTITL=41
            ITITLZ='Coefficient of Dispersion'
            NCTITZ=25
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            ITITLE='One-Sided Upper Confidence Limits for the'
            NCTITL=41
            ITITLZ='Coefficient of Dispersion'
            NCTITZ=25
          ENDIF
        ELSEIF(ICASAN.EQ.'CQLI')THEN
          IF(ICASA2.EQ.'LOWE')THEN
            ITITLE='One-Sided Lower Confidence Limits for the'
            NCTITL=41
            ITITLZ='Coefficient of Quartile Dispersion'
            NCTITZ=34
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            ITITLE='One-Sided Upper Confidence Limits for the'
            NCTITL=41
            ITITLZ='Coefficient of Quartile Dispersion'
            NCTITZ=34
          ENDIF
        ELSE
          IF(ICASA2.EQ.'LOWE')THEN
            ITITLE=   &
            'One-Sided Lower Confidence Limits for the Coefficient'
            NCTITL=53
            IF(IDIST.EQ.'LOGN')THEN
              ITITLZ='of Variation (for Lognormally Distributed Data)'
              NCTITZ=47
            ELSE
              ITITLZ='of Variation (for Normally Distributed Data)'
              NCTITZ=44
            ENDIF
          ELSEIF(ICASA2.EQ.'UPPE')THEN
            ITITLE=   &
            'One-Sided Upper Confidence Limits for the Coefficient'
            NCTITL=53
            IF(IDIST.EQ.'LOGN')THEN
              ITITLZ='of Variation (for Lognormally Distributed Data)'
              NCTITZ=47
            ELSE
              ITITLZ='of Variation (for Normally Distributed Data)'
              NCTITZ=44
            ENDIF
          ENDIF
        ENDIF
      ENDIF
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(ICOMM.EQ.'OFF')THEN
        ICNT=ICNT+1
        IF(ICASAN.EQ.'CDLI' .OR. ICASAN.EQ.'CQLI')THEN
          CONTINUE
        ELSEIF(IDIST.EQ.'LOGN')THEN
          ITEXT(ICNT)='Method: Koopmans, Owen, and Rosenblatt'
          NCTEXT(ICNT)=38
        ELSEIF(ICVACI.EQ.'VANG')THEN
          ITEXT(ICNT)='Method: Vangel (Modified McKay)'
          NCTEXT(ICNT)=31
        ELSEIF(ICVACI.EQ.'MCKA')THEN
          ITEXT(ICNT)='Method: McKay'
          NCTEXT(ICNT)=13
        ELSEIF(ICVACI.EQ.'NAIV')THEN
          ITEXT(ICNT)='Method: Naive'
          NCTEXT(ICNT)=13
        ELSEIF(ICVACI.EQ.'EXAC')THEN
          IF(N.GT.3000)THEN
            ITEXT(ICNT)='Method: Vangel (Modified McKay)'
            NCTEXT(ICNT)=31
          ELSE
            ITEXT(ICNT)='Method: Exact'
            NCTEXT(ICNT)=13
          ENDIF
        ELSEIF(ICVACI.EQ.'GPQ ')THEN
          ITEXT(ICNT)='Method: GPQ'
          NCTEXT(ICNT)=11
        ENDIF
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Method: Forkman'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
      IF(ICOMM.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSEIF(ICOMM.EQ.'ON' .AND. IVARID(1).NE.'NULL')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        IDIGIT(ICNT)=-1
        NCTEXT(ICNT)=27
      ENDIF
!
      IF(NREPL.GT.0)THEN
        NRESP=1
        DO 4101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+NRESP
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 4101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICOMM.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Summary Statistics:'
        NCTEXT(ICNT)=19
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Observations:'
        NCTEXT(ICNT)=23
        AVALUE(ICNT)=REAL(N)
        IDIGIT(ICNT)=0
        IF(ICASAN.EQ.'CDLI')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Median:'
          NCTEXT(ICNT)=14
          AVALUE(ICNT)=YMED
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Average Absolute Deviation:'
          NCTEXT(ICNT)=34
          AVALUE(ICNT)=YAAD
          IDIGIT(ICNT)=NUMDIG
        ELSEIF(ICASAN.EQ.'CQLI')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Lower Quartile:'
          NCTEXT(ICNT)=22
          AVALUE(ICNT)=Q1
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Upper Quartile:'
          NCTEXT(ICNT)=22
          AVALUE(ICNT)=Q3
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          IF(IQUAME.EQ.'AVER')THEN
            ITEXT(ICNT)='Quantile Method: Average'
            NCTEXT(ICNT)=24
          ELSEIF(IQUAME.EQ.'R6')THEN
            ITEXT(ICNT)='Quantile Method: R6'
            NCTEXT(ICNT)=19
          ELSEIF(IQUAME.EQ.'R7')THEN
            ITEXT(ICNT)='Quantile Method: R7'
            NCTEXT(ICNT)=19
          ELSEIF(IQUAME.EQ.'R8')THEN
            ITEXT(ICNT)='Quantile Method: R8'
            NCTEXT(ICNT)=19
          ENDIF
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
        ELSEIF(IDIST.EQ.'NORM')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Mean:'
          NCTEXT(ICNT)=12
          AVALUE(ICNT)=YMEAN
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Standard Deviation:'
          NCTEXT(ICNT)=26
          AVALUE(ICNT)=YSD
          IDIGIT(ICNT)=NUMDIG
        ELSE
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Mean (Log of Data):'
          NCTEXT(ICNT)=26
          AVALUE(ICNT)=YMEAN
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Standard Deviation (Log of Data):'
          NCTEXT(ICNT)=40
          AVALUE(ICNT)=YSD
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        IF(ICASAN.EQ.'CDLI')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Coefficient of Dispersion:'
          NCTEXT(ICNT)=33
          AVALUE(ICNT)=YCD
          IDIGIT(ICNT)=NUMDIG
        ELSEIF(ICASAN.EQ.'CQLI')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Coefficient of Quartile Disp:'
          NCTEXT(ICNT)=36
          AVALUE(ICNT)=CQV
          IDIGIT(ICNT)=NUMDIG
        ELSE
          ICNT=ICNT+1
          ITEXT(ICNT)='Sample Coefficient of Variation:'
          NCTEXT(ICNT)=32
          AVALUE(ICNT)=YCV
          IDIGIT(ICNT)=NUMDIG
        ENDIF
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Distinct Groups:'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=NDIST
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Number of Groups Included in Analysis:'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=NGROUP
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Common Coefficient of Variation:'
        NCTEXT(ICNT)=32
        AVALUE(ICNT)=YCV
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Bias Corrected Estimate:'
        NCTEXT(ICNT)=24
        AVALUE(ICNT)=YCVBC
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='5A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITL2(1,1)='Confidence'
      NCTIT2(1,1)=10
      ITITL2(2,1)='Value (%)'
      NCTIT2(2,1)=9
!
      IF(ICASAN.EQ.'CDLI')THEN
        ITITL2(1,2)='Coefficient'
        NCTIT2(1,2)=11
        ITITL2(2,2)='of Dispersion'
        NCTIT2(2,2)=13
      ELSEIF(ICASAN.EQ.'CQLI')THEN
        ITITL2(1,2)='Coefficient of'
        NCTIT2(1,2)=14
        ITITL2(2,2)='Quartile Dispersion'
        NCTIT2(2,2)=19
      ELSE
        ITITL2(1,2)='Coefficient'
        NCTIT2(1,2)=11
        ITITL2(2,2)='of Variation'
        NCTIT2(2,2)=12
      ENDIF
      ICOL=2
!
      IF(ICASA4.EQ.'TWOS' .OR.   &
        (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'LOWE'))THEN
        ICOL=ICOL+1
        ITITL2(1,ICOL)='Lower'
        NCTIT2(1,ICOL)=5
        ITITL2(2,ICOL)='Limit'
        NCTIT2(2,ICOL)=5
      ENDIF
!
      IF(ICASA4.EQ.'TWOS' .OR.   &
        (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'UPPE'))THEN
        ICOL=ICOL+1
        ITITL2(1,ICOL)='Upper'
        NCTIT2(1,ICOL)=5
        ITITL2(2,ICOL)='Limit'
        NCTIT2(2,ICOL)=5
      ENDIF
!
      NUMLIN=2
      NUMCOL=ICOL
      NUMROW=NUMAL2
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2 .AND. ICASAN.EQ.'CQLI')NTOT(I)=21
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
        IF(I.EQ.1)THEN
          NTOT(I)=12
          IDIGIT(I)=1
          IWHTML(1)=75
        ENDIF
        NMAX=NMAX+NTOT(I)
 4221 CONTINUE
      NUMRO2=NUMROW
      ICNT=0
      DO 4223 I=1,NUMROW
        IF(ALOWLM(I).EQ.CPUMIN .OR. AUPPLM(I).EQ.CPUMIN)THEN
          NUMRO2=NUMRO2-1
          GO TO 4223
        ENDIF
        ICNT=ICNT+1
        DO 4225 J=1,NUMCOL
          NCVALU(ICNT,J)=0
          IVALUE(ICNT,J)=' '
          AMAT(ICNT,J)=0.0
 4225   CONTINUE
        AMAT(ICNT,1)=CONF(I)
        IF(ICASAN.EQ.'CDLI')THEN
          AMAT(ICNT,2)=YCD
        ELSEIF(ICASAN.EQ.'CQLI')THEN
          AMAT(ICNT,2)=CQV
        ELSE
          AMAT(ICNT,2)=YCV
        ENDIF
        JCNT=2
        IF(ICASA4.EQ.'TWOS' .OR.   &
          (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'LOWE'))THEN
          JCNT=JCNT+1
          AMAT(ICNT,JCNT)=ALOWLM(I)
        ENDIF
        IF(ICASA4.EQ.'TWOS' .OR.   &
          (ICASA4.EQ.'ONES' .AND. ICASA2.EQ.'UPPE'))THEN
          JCNT=JCNT+1
          AMAT(ICNT,JCNT)=AUPPLM(I)
        ENDIF
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=150
      IF(ICASAN.EQ.'CQLI')IWHTML(2)=250
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+2000
      IF(ICASAN.EQ.'CQLI')IWRTF(2)=IWRTF(1)+3000
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.TRUE.
      ILAST=.TRUE.
      NCTIT9=0
      NCTITL=0
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMRO2,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVC2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVC2
      SUBROUTINE DPCVC3(Y,N,YMEAN,YSD,ICASAN,ICASA2,ICASA3,ICASA4,   &
                        ISEED,MAXNXT,IDIST,   &
                        TEMP1,TEMP2,   &
                        IMETHD,ALPHA,NALPHA,ALOWLM,AUPPLM,CV,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES CONFIDENCE LIMITS FOR THE
!              COEFFIENT OF VARIATION ASSUMING A NORMAL DISTRIBUTION
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!                 LET A = LOWER COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!                 LET A = UPPER COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!                 LET A = ONE SIDED LOWER COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!                 LET A = ONE SIDED UPPER COEFFICIENT OF VARIATION CONFIDENCE LIMIT Y
!
!              THE DATA CONSISTS OF N OBSERVATIONS IN Y.
!
!              WE IMPLEMENT THE FOLLOWING METHODS:
!
!
!              THE COEFFICIENT OF VARIATION IS DEFINED AS:
!
!                  C = STANDARD DEVIATION/MEAN
!
!                 1. MARK VANGEL'S MODIFIED MCKAY METHOD:
!
!                    Clow  = C*[(u1+2)/N - 1)*c**2 + u1/(N + 1)]**(-1/2)
!                    Chigh = C*[(u2+2)/N - 1)*c**2 + u1/(N + 1)]**(-1/2)
!
!                    WHERE
!
!                    u1 = CHSPPF((1-(ALPHA/2)),N-1)
!                    u2 = CHSPPF((ALPHA/2),N-1)
!
!                    WITH CHSPPF DENOTING THE CHI-SQUARE PERCENT POINT
!                    FUNCTION WITH SIGNFICANCE LEVEL ALPHA (E.G.,
!                    ALPHA=0.05) AND N - 1 DEGREES OF FREEDOM.
!
!                 2. MARK VANGEL'S MODIFIED MCKAY METHOD:
!
!     INPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS.
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR Y.
!                    --ALPHA  = THE SINGLE PRECISION VECTOR OF CONFIDENCE
!                               LEVELS
!                      NALPHA = THE INTEGER NUMBER OF ALPHA VALUES
!     OUTPUT ARGUMENTS-YLOWLM = THE SINGLE PRECISION VECTOR OF LOWER
!                               CONFIDENCE LIMIT VALUES
!                     -YUPPLM = THE SINGLE PRECISION VECTOR OF UPPER
!                               CONFIDENCE LIMIT VALUES
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--MARK VANGEL (1996), "CONFIDENCE INTERVALS FOR A NORMAL
!                 COEFFICIENT OF VARIATION", AMERICAN STATISTICIAN,
!                 VOL. 15, NO. 1, PP. 21-26.
!                 GUIDE FOR PRACTIONERS", WILEY, PP. 55-56.
!               --MCKAY (1932), "DISTRIBUTIONS OF THE COEFFICIENT OF
!                 VARIATION AND THE EXTENDED 't' DISTRIBUTION", JOURNAL
!                 OF THE ROYAL STATISTICAL SOCIETY, VOL. 95, PP. 695-698.
!               --CODE FOR EXACT METHOD BASED ON STEVE VERRILL'S FORTRAN
!                 CODE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     ORIGINAL VERSION--DECEMBER  2016.
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION ALOWLM(*)
      DIMENSION AUPPLM(*)
      DIMENSION ALPHA(*)
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 IMETHD
      CHARACTER*4 IDIST
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IMTHD2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IQUAME
!
      DOUBLE PRECISION CVFLOW
      EXTERNAL CVFLOW
      DOUBLE PRECISION CVFUP
      EXTERNAL CVFUP
!
      DOUBLE PRECISION B1
      DOUBLE PRECISION C
      DOUBLE PRECISION R
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION ESTCV
      DOUBLE PRECISION DSQRTN
      DOUBLE PRECISION DNU1
      DOUBLE PRECISION RATIO
      DOUBLE PRECISION ALPHAD2
      DOUBLE PRECISION OMAD2
      COMMON/CVC/ESTCV,DSQRTN,DNU1,RATIO,ALPHAD2,OMAD2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CVC3'
      ISUBN2='    '
      IWRITE='OFF'
      IERROR='NO'
      IMTHD2=IMETHD
      IQUAME='ORDE'
!
      CVSQ=0.0
      ANUP1=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCVC3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4,IMETHD
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4,IMETHD = ',   &
               6(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,NALPHA,YMEAN,YSD,ALPHA(1)
   53   FORMAT('N,NALPHA,YMEAN,YSD,ALPHA(1) = ',2I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(ICASA3.EQ.'RAW')THEN
          DO 56 I=1,N
            WRITE(ICOUT,57)I,Y(I)
   57       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
        DO 76 I=1,NALPHA
          WRITE(ICOUT,77)I,ALPHA(I)
   77     FORMAT('I,ALPHA(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   76   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 110 I=1,NALPHA
        ALOWLM(I)=CPUMIN
        AUPPLM(I)=CPUMIN
  110 CONTINUE
!
      IF(ICASA3.EQ.'RAW' .AND. N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COEFFICIENT OF VARIANCE CONFIDENCE ',   &
               'LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF ORIGINAL OBSERVATIONS  IS LESS ',   &
               'THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IDIST.EQ.'LOGN')THEN
        DO 130 I=1,N
          IF(Y(I).GT.0.0)THEN
            Y(I)=LOG(Y(I))
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,131)I
  131       FORMAT('      FOR LOG-NORMAL DATA, ROW ',I8,   &
                   'IS NON-POSITIVE.')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
  130   CONTINUE
        CALL MEAN(Y,N,IWRITE,YMEAN,IBUGA3,IERROR)
        CALL SD(Y,N,IWRITE,YSD,IBUGA3,IERROR)
        CV=SQRT(EXP(YSD*YSD) - 1.0)
        GO TO 399
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CARRY OUT CALCULATIONS FOR PREDICTION **
!               **  LIMITS.                               **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.AND.ISUBRO.EQ.'CVC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     ICASAN:  CVLI     => CONFIDENCE LIMIT FOR COEFFICIENT OF
!                          VARIATION
!     ICASA2:  LOWE     => LOWER LIMIT
!              UPPE     => UPPER LIMIT
!     ICASA3:  RAW      => RAW DATA IN Y1
!              SUMM     => SUMMARY DATA IN YMEAN AND YSD
!     ICASA4:  ONES     => ONE-SIDED LIMIT
!              TWOS     => TWO-SIDED LIMIT
!
!
!     COMPUTE STANDARD DEVIATION
!
      IF(ICASA3.EQ.'RAW')THEN
        CALL MEAN(Y,N,IWRITE,YMEAN,IBUGA3,IERROR)
        IF(IMETHD.EQ.'MLE')THEN
          CALL SDMLE(Y,N,IWRITE,YSD,IBUGA3,IERROR)
          IMTHD2='VANG'
        ELSE
          CALL SD(Y,N,IWRITE,YSD,IBUGA3,IERROR)
        ENDIF
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC3')THEN
        WRITE(ICOUT,201)YMEAN,YSD
  201   FORMAT('YMEAN,YSD = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4,IMETHD
      ENDIF
!
      IF(YSD.LT.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      THE STANDARD DEVIATION OF THE ORIGINAL ',   &
               'OBSERVATIONS IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(YSD.EQ.0.0)THEN
        ALOWLM(I)=0.0
        AUPPLM(I)=0.0
        GO TO 9000
      ELSEIF(YMEAN.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,217)
  217   FORMAT('      THE MEAN OF THE ORIGINAL OBSERVATIONS IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,219)
  219   FORMAT('      THE COEFFICIENT OF VARIATION CONFIDENCE LIMIT ',   &
               'IS NOT COMPUTED IN THIS CASE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CV=YSD/YMEAN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC3')THEN
        WRITE(ICOUT,220)CV
  220   FORMAT('CV = ',G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(CV.GT.0.33)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,221)
  221   FORMAT('***** WARNING: COEFFICIENT OF VARIANCE CONFIDENCE ',   &
               'LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,223)CV
  223   FORMAT('      THE COEFFICIENT OF VARIATION ',G15.7,' IS ',   &
               '> 0.33.  THE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,224)
  224   FORMAT('      THE CONFIDENCE LIMITS APPROXIMATION MAY NOT BE ',   &
               'ACCURATE.')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     2016/07: ISSUE WITH CHSPPF WHEN DEGREES OF FREEDOM IS LARGE.
!              FOR NOW, TRUNCATE DEGREES OF FREEDOM AT 150,000.
!
      NU1=N-1
      IF(NU1.GT.150000)NU1=150000
      ANU=REAL(NU1)
      AN=REAL(N)
      ANUP1=ANU+1.0
      CVSQ=CV**2
      AFACT=2.0
      IF(IMTHD2.EQ.'MCKA')THEN
        AFACT=0.0
      ELSEIF(IMTHD2.EQ.'GPQ')THEN
        AN=REAL(N)
        NTEMP=10000
        CALL NORRAN(NTEMP,ISEED,TEMP1)
        ANU=REAL(N-1)
        CALL CHSRAN(NTEMP,ANU,ISEED,TEMP2)
        YVAR=YSD**2
        DO 310 II=1,NTEMP
          TERM1=ANU*YVAR/TEMP2(II)
          TERM3=SQRT(TERM1/AN)
          TERM2=YMEAN - SQRT(TERM1/AN)*TEMP1(II)
          TEMP1(II)=SQRT(TERM1)/TERM2
  310   CONTINUE
        CALL SORT(TEMP1,NTEMP,TEMP1)
      ELSEIF(IMTHD2.EQ.'EXAC')THEN
        IF(N.GT.3000)THEN
          IMTHD2='VANG'
        ELSE
          AN=REAL(N)
          ANSQRT=SQRT(AN)
          DSQRTN=DBLE(ANSQRT)
          ESTCV=DBLE(CV)
          RATIO=DSQRTN/ESTCV
        ENDIF
      ENDIF
!
  399 CONTINUE
!
      IF(ICASA4.EQ.'ONES')THEN
        IF(IDIST.EQ.'LOGN')THEN
          NU1=N-1
          ANU1=REAL(NU1)
          DO 400 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT
            CALL CHSPPF(ALPHAT,NU1TMP,PPFU)
            AU=YSD*SQRT(ANU/PPFU)
            AU=AU**2
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1TMP,PPFL)
            AL=YSD*SQRT(ANU/PPFL)
            AL=AL**2
            IF(AL.GE.1.0)THEN
              ALOWLM(I)=SQRT(EXP(AL) - 1.0)
            ELSE
              ALOWLM(I)=CPUMIN
            ENDIF
            IF(AU.GE.1.0)THEN
              AUPPLM(I)=SQRT(EXP(AU) - 1.0)
            ELSE
              AUPPLM(I)=CPUMAX
            ENDIF
  400     CONTINUE
        ELSEIF(IMTHD2.EQ.'VANG' .OR. IMTHD2.EQ.'MCKA')THEN
          DO 410 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFL)
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFU)
            TERM1=((PPFL + AFACT)/ANUP1) - 1.0
            TERM2=TERM1*CVSQ
            TERM3=PPFL/ANU
            TERM4=TERM2 + TERM3
            IF(TERM4.LE.0.0)THEN
              AUPPLM(I)=CPUMAX
              GO TO 410
            ENDIF
            AUPPLM(I)=CV/SQRT(TERM4)
            TERM1=((PPFU + AFACT)/ANUP1) - 1.0
            TERM2=TERM1*CVSQ
            TERM3=PPFU/ANU
            TERM4=TERM2 + TERM3
            IF(TERM4.LE.0.0)THEN
              ALOWLM(I)=CPUMIN
              GO TO 410
            ENDIF
            ALOWLM(I)=CV/SQRT(TERM4)
  410     CONTINUE
        ELSEIF(IMTHD2.EQ.'NAIV')THEN
          DO 420 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFL)
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFU)
            AUPPLM(I)=CV/SQRT(PPFL/ANU)
            ALOWLM(I)=CV/SQRT(PPFU/ANU)
  420     CONTINUE
        ELSEIF(IMTHD2.EQ.'EXAC')THEN
          DO 430 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT
            ALPHAT=1.0 - ALPHAT
!
!           COMPUTE UPPER CONFIDENCE LIMIT
!
            ALPHAD2=ALPHAT
            OMAD2=1.0 - ALPHAT
            ANU1=REAL(NU1)
            DNU1=DBLE(ANU1)
            CALL TPPF(ALPHAT,ANU1,TPPFT)
            IF(TPPFT.LT.0.0 .OR. TPPFT.GT.100.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,101)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,431)
  431         FORMAT('      THE T PERCENT POINT VALUE IS OUTSIDE THE ',   &
                     '(0,100) INTERVAL.')
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,433)ALPHA(I)
  433         FORMAT('      ALPHA = ',F10.3)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,435)ANU1
  435         FORMAT('      DEGREES OF FREEDOM = ',F10.3)
              CALL DPWRST('XXX','WRIT')
              GO TO 430
            ENDIF
            B1=0.001D0
            C=10.0D0
            R=CV
            RE=0.000001D0
            AE = 0.00001D0
            CALL DFZERO(CVFLOW,B1,C,R,RE,AE,IFLAG1)
             IF(IFLAG1 .EQ. 4)THEN
               IF(B1 .LT. 5.0)THEN
!CCCC            WRITE(6,35)
!35              FORMAT(/,1X,'tHE LOWER CONFIDENCE BOUND ON THE cov',
!CCCC1                  /,1X,'LIES BETWEEN 0 AND .001.',/)
                 AUPPLM(I)=0.001
               ELSEIF(B1 .GT. 5.0)THEN
                 B2 = 10.0D0
                 C = 100.0D0
                 R = ESTCV
                 RE = .000001D0
                 AE = .001D0
                 CALL DFZERO(CVFLOW,B2,C,R,RE,AE,IFLAG2)
                 IF(IFLAG2 .EQ. 4 .AND. B2 .GT. 50.0D0)THEN
!CCCC              WRITE(6,45)
!45                FORMAT(/,1X,'tHE LOWER CONFIDENCE BOUND ON THE cov',
!CCCCX                    /,1X,'IS GREATER THAN 100.',/)
                   ALOWLM(I)=100.0
                   AUPPLM(I)=CPUMAX
                   GO TO 430
                 ELSE
                   AUPPLM(I)=REAL(B2)
                 ENDIF
               ELSE
                 AUPPLM(I)=REAL(B2)
               ENDIF
             ELSE
               AUPPLM(I)=REAL(B1)
             ENDIF
!
!           COMPUTE LOWER CONFIDENCE LIMIT
!
            IF(TPPFT.GE.RATIO)THEN
              ALOWLM(I)=0.0
              GO TO 430
            ENDIF
!
            B1 = .001D0
            C = 10.0D0
            R = ESTCV
            RE = .000001D0
            AE = .00001D0
            CALL DFZERO(CVFUP,B1,C,R,RE,AE,IFLAG1)
            IF(IFLAG1 .EQ. 4)THEN
              IF(B1 .LT. 5.0)THEN
!CCCC           WRITE(6,135)
!135            FORMAT(/,1X,'tHE UPPER CONFIDENCE BOUND ON THE cov',
!CCCC1                 /,1X,'LIES BETWEEN 0 AND .001.',/)
                ALOWLM(I)=0.0
                GO TO 430
              ELSEIF(B1 .GT. 5.0) THEN
                B2 = 10.0D0
                C = 100.0D0
                R = ESTCV
                RE = .000001D0
                AE = .001D0
                CALL DFZERO(CVFUP,B2,C,R,RE,AE,IFLAG2)
                IF(IFLAG2 .EQ. 4 .AND. B2 .GT. 50.0D0)THEN
!CCCC             WRITE(6,145)
!145              FORMAT(/,1X,'tHE UPPER CONFIDENCE BOUND ON THE cov',
!CCCCX                   /,1X,'IS GREATER THAN 100.',/)
                  ALOWLM(I)=100.
                  GO TO 430
                ELSE
                  ALOWLM(I)=REAL(B2)
                ENDIF
              ENDIF
            ELSE
              ALOWLM(I)=REAL(B1)
            ENDIF
!
  430     CONTINUE
        ELSEIF(IMTHD2.EQ.'GPQ')THEN
          DO 440 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT
            CALL QUANT(ALPHAT,TEMP1,NTEMP,IWRITE,TEMP2,MAXNXT,   &
                       IQUAME,XQUANT,IBUGA3,IERROR)
            ALOWLM(I)=XQUANT
            ALPHAT=1.0 - ALPHAT
            CALL QUANT(ALPHAT,TEMP1,NTEMP,IWRITE,TEMP2,MAXNXT,   &
                       IQUAME,XQUANT,IBUGA3,IERROR)
            AUPPLM(I)=XQUANT
  440     CONTINUE
        ENDIF
      ELSEIF(ICASA4.EQ.'TWOS')THEN
        IF(IDIST.EQ.'LOGN')THEN
          NU1TMP=N-1
          ANU=REAL(NU1TMP)
          DO 450 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT/2.0
            CALL CHSPPF(ALPHAT,NU1TMP,PPFU)
            AU=YSD*SQRT(ANU/PPFU)
            AU=AU**2
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1TMP,PPFL)
            AL=YSD*SQRT(ANU/PPFL)
            AL=AL**2
            IF(AL.GE.1.0)THEN
              ALOWLM(I)=SQRT(EXP(AL) - 1.0)
            ELSE
              ALOWLM(I)=CPUMIN
            ENDIF
            IF(AU.GE.1.0)THEN
              AUPPLM(I)=SQRT(EXP(AU) - 1.0)
            ELSE
              AUPPLM(I)=CPUMAX
            ENDIF
  450     CONTINUE
        ELSEIF(IMTHD2.EQ.'VANG' .OR. IMETHD.EQ.'MCKA')THEN
          DO 460 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT/2.0
            CALL CHSPPF(ALPHAT,NU1,PPFL)
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFU)
            TERM1=((PPFL + AFACT)/ANUP1) - 1.0
            TERM2=TERM1*CVSQ
            TERM3=PPFL/ANU
            TERM4=TERM2 + TERM3
            IF(TERM4.LE.0.0)THEN
              AUPPLM(I)=CPUMAX
              GO TO 460
            ENDIF
            AUPPLM(I)=CV/SQRT(TERM4)
            TERM1=((PPFU + AFACT)/ANUP1) - 1.0
            TERM2=TERM1*CVSQ
            TERM3=PPFU/ANU
            TERM4=TERM2 + TERM3
            IF(TERM4.LE.0.0)THEN
              ALOWLM(I)=CPUMIN
              GO TO 460
            ENDIF
            ALOWLM(I)=CV/SQRT(TERM4)
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC3')THEN
              WRITE(ICOUT,462)I,ALPHA(I),PPFL,PPFU,AFACT
  462         FORMAT('I,ALPHA(I),PPFL,PPFU,AFACT = ',I5,4G15.7)
              CALL DPWRST('XXX','WRIT')
            ENDIF
!
  460     CONTINUE
        ELSEIF(IMTHD2.EQ.'NAIV')THEN
          DO 470 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT/2.0
            CALL CHSPPF(ALPHAT,NU1,PPFL)
            ALPHAT=1.0 - ALPHAT
            CALL CHSPPF(ALPHAT,NU1,PPFU)
            AUPPLM(I)=CV/SQRT(PPFL/ANU)
            ALOWLM(I)=CV/SQRT(PPFU/ANU)
  470     CONTINUE
        ELSEIF(IMTHD2.EQ.'EXAC')THEN
          DO 480 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=1.0 - (ALPHAT/2.0)
!
!           COMPUTE UPPER CONFIDENCE LIMIT
!
            ALPHAD2=ALPHAT
            OMAD2=1.0 - ALPHAT
            ANU1=REAL(NU1)
            DNU1=DBLE(ANU1)
            CALL TPPF(ALPHAT,ANU1,TPPFT)
            IF(TPPFT.LT.0.0 .OR. TPPFT.GT.100.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,101)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,481)
  481         FORMAT('      THE T PERCENT POINT VALUE IS OUTSIDE THE ',   &
                     '(0,100) INTERVAL.')
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,483)ALPHA(I)
  483         FORMAT('      ALPHA = ',F10.3)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,485)ANU1
  485         FORMAT('      DEGREES OF FREEDOM = ',F10.3)
              CALL DPWRST('XXX','WRIT')
              GO TO 480
            ENDIF
            B1=0.001D0
            C=10.0D0
            R=CV
            RE=0.000001D0
            AE = 0.00001D0
            CALL DFZERO(CVFLOW,B1,C,R,RE,AE,IFLAG1)
             IF(IFLAG1 .EQ. 4)THEN
               IF(B1 .LT. 5.0)THEN
!CCCC            WRITE(6,35)
!35              FORMAT(/,1X,'tHE LOWER CONFIDENCE BOUND ON THE cov',
!CCCC1                  /,1X,'LIES BETWEEN 0 AND .001.',/)
                 AUPPLM(I)=0.001
               ELSEIF(B1 .GT. 5.0)THEN
                 B2 = 10.0D0
                 C = 100.0D0
                 R = ESTCV
                 RE = .000001D0
                 AE = .001D0
                 CALL DFZERO(CVFLOW,B2,C,R,RE,AE,IFLAG2)
                 IF(IFLAG2 .EQ. 4 .AND. B2 .GT. 50.0D0)THEN
!CCCC              WRITE(6,45)
!45                FORMAT(/,1X,'tHE LOWER CONFIDENCE BOUND ON THE cov',
!CCCCX                    /,1X,'IS GREATER THAN 100.',/)
                   ALOWLM(I)=100.0
                   AUPPLM(I)=CPUMAX
                   GO TO 480
                 ELSE
                   AUPPLM(I)=REAL(B2)
                 ENDIF
               ELSE
                 AUPPLM(I)=REAL(B2)
               ENDIF
             ELSE
               AUPPLM(I)=REAL(B1)
             ENDIF
!
!           COMPUTE LOWER CONFIDENCE LIMIT
!
            IF(TPPFT.GE.RATIO)THEN
              ALOWLM(I)=0.0
              GO TO 480
            ENDIF
!
            B1 = .001D0
            C = 10.0D0
            R = ESTCV
            RE = .000001D0
            AE = .00001D0
            CALL DFZERO(CVFUP,B1,C,R,RE,AE,IFLAG1)
            IF(IFLAG1 .EQ. 4)THEN
              IF(B1 .LT. 5.0)THEN
!CCCC           WRITE(6,135)
!135            FORMAT(/,1X,'tHE UPPER CONFIDENCE BOUND ON THE cov',
!CCCC1                 /,1X,'LIES BETWEEN 0 AND .001.',/)
                ALOWLM(I)=0.0
                GO TO 480
              ELSEIF(B1 .GT. 5.0) THEN
                B2 = 10.0D0
                C = 100.0D0
                R = ESTCV
                RE = .000001D0
                AE = .001D0
                CALL DFZERO(CVFUP,B2,C,R,RE,AE,IFLAG2)
                IF(IFLAG2 .EQ. 4 .AND. B2 .GT. 50.0D0)THEN
!CCCC             WRITE(6,145)
!145              FORMAT(/,1X,'tHE UPPER CONFIDENCE BOUND ON THE cov',
!CCCCX                   /,1X,'IS GREATER THAN 100.',/)
                  ALOWLM(I)=100.
                  GO TO 480
                ELSE
                  ALOWLM(I)=REAL(B2)
                ENDIF
              ENDIF
            ELSE
              ALOWLM(I)=REAL(B1)
            ENDIF
!
  480     CONTINUE
        ELSEIF(IMTHD2.EQ.'GPQ')THEN
          DO 490 I=1,NALPHA
            ALPHAT=ALPHA(I)
            IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
            IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
            IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
            ALPHAT=ALPHAT/2.0
            CALL QUANT(ALPHAT,TEMP1,NTEMP,IWRITE,TEMP2,MAXNXT,   &
                       IQUAME,XQUANT,IBUGA3,IERROR)
            ALOWLM(I)=XQUANT
            ALPHAT=1.0 - ALPHAT
            CALL QUANT(ALPHAT,TEMP1,NTEMP,IWRITE,TEMP2,MAXNXT,   &
                       IQUAME,XQUANT,IBUGA3,IERROR)
            AUPPLM(I)=XQUANT
  490     CONTINUE
        ENDIF
      ENDIF
!
      GO TO 9000
!
 8000 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8001)I
 8001 FORMAT('      ROW ',I8,' OF ALPHA VALUES IS OUT OF RANGE.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8003)ALPHA(I)
 8003 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9051)
 9051   FORMAT('**** AT THE END OF DPCVC3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9052)YSD,PPF,ALPHA(NALPHA),ALPHAT,ANU,PPF
 9052   FORMAT('YSD,PPF,ALPHA(NALPHA),ALPHAT,ANU,PPF = ',6G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVC3
      SUBROUTINE DPCVC4(Y,X,N,NSIZE,XIDTEM,TEMP1,   &
                        ICASAN,ICASA2,ICASA3,ICASA4,   &
                        ALPHA,NALPHA,ALOWLM,AUPPLM,   &
                        CV,CVBC,NDIST,NGROUP,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES A COMMON COEFFICIENT OF
!              VARIATION AND, OPTIONALLY, CONFIDENCE LIMITS FOR THE
!              COMMON COEFFIENT OF VARIATION.  IT IS ASSUMED THAT THE
!              DATA FOR EACH GROUP IS NORMALLY DISTRIBUTED.
!
!              THE FOLLOWING CASES ARE SUPPORTED:
!
!                 LET A = LOWER COMMON COEFFICIENT OF VARIATION CONFIDENCE
!                         LIMIT Y X
!                 LET A = UPPER COMMON COEFFICIENT OF VARIATION CONFIDENCE
!                         LIMIT Y X
!                 LET A = ONE SIDED LOWER COMMON COEFFICIENT OF VARIATION
!                         CONFIDENCE LIMIT Y X
!                 LET A = ONE SIDED UPPER COMMON COEFFICIENT OF VARIATION
!                         CONFIDENCE LIMIT Y X
!
!              THE DATA CONSISTS OF N OBSERVATIONS IN Y WITH X
!              DEFINING THE K GROUPS.
!
!              WE IMPLEMENT THE METHOD OF PANICHKITKOSOLKUL (SEE
!              REFERENCE BELOW).
!
!              THE (BIASED) COMMON COEFFICIENT OF VARIATION IS:
!
!                 GAMMA = SQRT[SUM{I=1 to k}{(N(i)-1)*C(i)**2}/
!                              SUM{i=1 to k}{N(i)-1)}]
!
!              THE BIAS CORRECTED COMMON COEFFICIENT OF VARIATION IS:
!
!                 GAMMABC = GAMMA/[1 - 1/(4*SUM{i=1 to k}{N(i) -1)}]
!
!              WHERE
!
!                 k     = NUMBER OF GROUPS
!                 N(i)  = SAMPLE SIZE OF THE i-TH GROUP
!                 C(i)  = SAMPLE COEFFICIENT OF VARIATION OF THE i-TH GROUP
!
!              THE CONFIDENCE LIMITS ARE COMPUTED AS
!
!                 LOWER LIMIT = SQRT[SUM{I=1 to k}{(N(i)-1)*U(i)}/
!                               (CHSPPF(1-ALPHA/2,DF) - SUM{i=1 to k}{(N(i)-1)*U(i)}]
!                 UPPER LIMIT = SQRT[SUM{I=1 to k}{(N(i)-1)*U(i)}/
!                               (CHSPPF(ALPHA/2,DF) - SUM{i=1 to k}{(N(i)-1)*U(i)}]
!
!              WHERE
!
!                 U(i)  = C(i)**2/(1 + C(i)**2*(N(i)-1)/N(i)
!                 DF    = SUM[i=1 to k][N(i) - 1]
!
!              NOTE THAT THE ALGORITHM CAN BE COMPUTED FROM SUMMARY
!              STATISTICS (THE MEAN AND STANDARD DEVIATION IN THIS
!              CASE).  BOTH THE RAW DATA AND SUMMARY STATISTIC CASES
!              ARE SUPPORTED.
!
!              IF THE NUMBER OF ALPHA VALUES IS ZERO, THEN ONLY COMPUTE
!              THE COMMON CV STATISTIC AND OMIT THE CONFIDENCE INTERVAL.
!
!     INPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                               (UNSORTED OR SORTED) OBSERVATIONS.
!                    --X      = THE SINGLE PRECISION VECTOR THAT
!                               SPECIFIES THE GROUP ID VARIABLE
!                    --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                               IN THE VECTOR Y.
!                    --ALPHA  = THE SINGLE PRECISION VECTOR OF CONFIDENCE
!                               LEVELS
!                      NALPHA = THE INTEGER NUMBER OF ALPHA VALUES
!     OUTPUT ARGUMENTS-YLOWLM = THE SINGLE PRECISION VECTOR OF LOWER
!                               CONFIDENCE LIMIT VALUES
!                     -YUPPLM = THE SINGLE PRECISION VECTOR OF UPPER
!                               CONFIDENCE LIMIT VALUES
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", XCOMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, Vol. 38, No. 2, pp. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     ORIGINAL VERSION--JANUARY   2017.
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP1(*)
      DIMENSION ALOWLM(*)
      DIMENSION AUPPLM(*)
      DIMENSION ALPHA(*)
!
      INTEGER NSIZE(*)
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 ICASA4
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 IOP
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     ICASAN:  CCVA     => CONFIDENCE LIMIT FOR COMMON COEFFICIENT OF
!                          VARIATION
!     ICASA2:  LOWE     => LOWER LIMIT
!              UPPE     => UPPER LIMIT
!     ICASA3:  RAW      => RAW DATA IN Y (AND X IS GROUP-ID VARIABLE)
!              SUMM     => SUMMARY DATA (Y CONTAINS MEANS AND X CONTAINS
!                          STANDARD DEVIATIONS)
!     ICASA4:  ONES     => ONE-SIDED LIMIT
!              TWOS     => TWO-SIDED LIMIT
!
      ISUBN1='CVC4'
      ISUBN2='    '
      IWRITE='OFF'
      IERROR='NO'
      NDIST=0
      NGROUP=0
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=0
      IFLAG3=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      WRITE(IOUNI1,41)
   41 FORMAT(4X,'N(I)',11X,'MEAN',13X,'SD',3X,'COEF OF VARI')
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCCVC4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,ICASA2,ICASA3,ICASA4 = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,53)N,NALPHA,ALPHA(1)
   53   FORMAT('N,NALPHA,ALPHA(1) = ',2I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
        DO 76 I=1,NALPHA
          WRITE(ICOUT,77)I,ALPHA(I)
   77     FORMAT('I,ALPHA(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   76   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 110 I=1,NALPHA
        ALOWLM(I)=CPUMIN
        AUPPLM(I)=CPUMIN
  110 CONTINUE
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COMMON COEFFICIENT OF VARIATION ',   &
               'CONFIDENCE LIMITS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS  IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  DETERMINE THE NUMBER OF GROUPS        **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASA3.EQ.'RAW')THEN
        CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(NDIST.LT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,201)
  201     FORMAT('      THE NUMBER OF GROUPS  IS LESS THAN TWO.')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  COMPUTE THE GROUP STATISTICS          **
!               ********************************************
!
        ISTEPN='22'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
           CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        NGROUP=0
        DSUM1=0.0D0
        DSUM2=0.0D0
        DSUM3=0.0D0
!
        DO 210 II=1,NDIST
          K=0
!
          YMEANT=CPUMIN
          YSDT=CPUMIN
          CT=CPUMIN
!
          HOLD=XIDTEM(II)
          DO 220 JJ=1,N
            IF(X(JJ).EQ.HOLD)THEN
              K=K+1
              TEMP1(K)=Y(JJ)
            ENDIF
  220     CONTINUE
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
            WRITE(ICOUT,211)II,K
  211       FORMAT('GROUP ',I8,' HAS ',I8,' OBSERVATIONS.')
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          IF(K.GT.1)THEN
            CALL MEAN(TEMP1,K,IWRITE,YMEANT,IBUGA3,IERROR)
            CALL SD(TEMP1,K,IWRITE,YSDT,IBUGA3,IERROR)
!
!           CHECK FOR:
!
!               1) POSITIVE MEAN
!                  (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE MEAN)
!               2) POSITIVE SD
!                  (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE SD)
!               3) COEFFICIENT OF VARIATION < 0.33
!                  (THIS WILL BE WARNING, BUT INCLUDE IN THE COMPUTATIONS)
!
            IF(YMEANT.LT.0.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,203)
  203         FORMAT('***** WARNING COMMON COEFFICIENT OF VARIANCE ',   &
                     'CONFIDENCE LIMITS--')
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,204)II
  204         FORMAT('      GROUP ',I5,' HAS A NON-POSITIVE MEAN.')
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,205)
  205         FORMAT('      IT WILL BE OMITTED FROM THE COMPUTATION.')
              CALL DPWRST('XXX','WRIT')
              GO TO 219
            ELSEIF(YSDT.LE.0.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,203)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,206)II
  206         FORMAT('      GROUP ',I5,' HAS A NON-POSITIVE STANDARD ',   &
                     'DEVIATION.')
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,205)
              CALL DPWRST('XXX','WRIT')
              GO TO 219
            ENDIF
            NGROUP=NGROUP+1
            CT=YSDT/YMEANT
            ANT=REAL(K)
            ANTM1=REAL(K) - 1.0
            UT=CT**2/(1.0 + (CT**2*ANTM1/ANT))
            DSUM1=DSUM1 + DBLE(ANTM1)
            DSUM2=DSUM2 + DBLE(ANTM1*CT**2)
            DSUM3=DSUM3 + DBLE(ANTM1*UT)
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
              WRITE(ICOUT,213)NGROUP,YMEANT,YSDT,CT,UT
  213         FORMAT('NGROUP,YMEANT,YSDT,CT,UT = ',I8,4G15.7)
              CALL DPWRST('XXX','WRIT')
            ENDIF
!
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,203)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,207)II
  207       FORMAT('      GROUP ',I5,' HAS FEWER THAN TWO ',   &
                   'OBSERVATIONS.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,205)
            CALL DPWRST('XXX','WRIT')
          ENDIF
  219   CONTINUE
        WRITE(IOUNI1,'(I8,3E15.7)')K,YMEANT,YSDT,CT
  210   CONTINUE
!
      ELSE
!
!       SUMMARY DATA CASE
!
        NGROUP=0
        DSUM1=0.0D0
        DSUM2=0.0D0
        DSUM3=0.0D0
!
        DO 260 II=1,N
          K=NSIZE(II)
          IF(K.LT.2)THEN
            WRITE(ICOUT,207)II
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,205)
            CALL DPWRST('XXX','WRIT')
            GO TO 260
          ENDIF
!
!         CHECK FOR:
!
!             1) POSITIVE MEAN
!                (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE MEAN)
!             2) POSITIVE SD
!                (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE SD)
!             3) COEFFICIENT OF VARIATION < 0.33
!                (THIS WILL BE WARNING, BUT INCLUDE IN THE COMPUTATIONS)
!
            YMEANT=Y(II)
            YSDT=X(II)
            IF(YMEANT.LT.0.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,203)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,204)II
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,205)
              CALL DPWRST('XXX','WRIT')
              GO TO 260
            ELSEIF(YSDT.LE.0.0)THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,203)
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,206)II
              CALL DPWRST('XXX','WRIT')
              WRITE(ICOUT,205)
              CALL DPWRST('XXX','WRIT')
              GO TO 260
            ENDIF
            NGROUP=NGROUP+1
            CT=YSDT/YMEANT
            ANT=REAL(K)
            ANTM1=REAL(K) - 1.0
            UT=CT**2/(1.0 + (CT**2*ANTM1/ANT))
            DSUM1=DSUM1 + DBLE(ANTM1)
            DSUM2=DSUM2 + DBLE(ANTM1*CT**2)
            DSUM3=DSUM3 + DBLE(ANTM1*UT)
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
              WRITE(ICOUT,213)NGROUP,YMEANT,YSDT,CT,UT
              CALL DPWRST('XXX','WRIT')
            ENDIF
  260   CONTINUE
      ENDIF
!
      IF(NGROUP.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,281)
  281   FORMAT('      AFTER REMOVING GROUPS, LESS THAN TWO GROUPS ',   &
               'REMAIN.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DTERM1=DSQRT(DSUM2/DSUM1)
      DTERM2=1.0D0 - (1.0D0/(4.0D0*DSUM1))
      CV=REAL(DTERM1)
      CVBC=REAL(DTERM1/DTERM2)
!
!               ********************************************
!               **  STEP 31--                             **
!               **  GENERATE CONFIDENCE LIMITS FOR        **
!               **  VARIOUS VALUES OF ALPHA               **
!               ********************************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.AND.ISUBRO.EQ.'CVC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ANU1=REAL(DSUM1)
      IF(ANU1.GE.150000)THEN
        NU1=150000
      ELSE
        NU1=INT(ANU1+0.1)
      ENDIF
!
      IF(ICASA4.EQ.'ONES')THEN
        DO 420 I=1,NALPHA
          ALPHAT=ALPHA(I)
          IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
          IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
          IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
          ALPHAT=ALPHAT
          CALL CHSPPF(ALPHAT,NU1,PPFU)
          ALPHAT=1.0 - ALPHAT
          CALL CHSPPF(ALPHAT,NU1,PPFL)
          DTERM3=DSQRT(DSUM3/(DBLE(PPFL) - DSUM3))
          DTERM4=DSQRT(DSUM3/(DBLE(PPFU) - DSUM3))
          ALOWLM(I)=REAL(DTERM3)
          AUPPLM(I)=REAL(DTERM4)
  420   CONTINUE
      ELSEIF(ICASA4.EQ.'TWOS')THEN
        DO 470 I=1,NALPHA
          ALPHAT=ALPHA(I)
          IF(ALPHAT.GE.1.0 .AND. ALPHAT.LT.100.0)ALPHAT=ALPHAT/100.
          IF(ALPHAT.LE.0.0 .OR. ALPHAT.GE.1.0)GO TO 8000
          IF(ALPHAT.GT.0.5)ALPHAT=1.0 - ALPHAT
          ALPHAT=ALPHAT/2.0
          CALL CHSPPF(ALPHAT,NU1,PPFU)
          ALPHAT=1.0 - ALPHAT
          CALL CHSPPF(ALPHAT,NU1,PPFL)
          DTERM3=DSQRT(DSUM3/(DBLE(PPFL) - DSUM3))
          DTERM4=DSQRT(DSUM3/(DBLE(PPFU) - DSUM3))
          ALOWLM(I)=REAL(DTERM3)
          AUPPLM(I)=REAL(DTERM4)
  470   CONTINUE
      ENDIF
!
      GO TO 9000
!
 8000 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8001)I
 8001 FORMAT('      ROW ',I8,' OF ALPHA VALUES IS OUT OF RANGE.')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,8003)ALPHA(I)
 8003 FORMAT('      THE VALUE OF ALPHA IS ',G15.7)
      CALL DPWRST('XXX','WRIT')
      IERROR='YES'
      GO TO 9000
!
 9000 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVC4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9051)
 9051   FORMAT('**** AT THE END OF DPCCVC4--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9053)DTERM1,DTERM2,CV,CVBC
 9053   FORMAT('DTERM1,DTERM2,CV,CVBC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVC4
      SUBROUTINE DPCVOT(YTEMP,XTEMP,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT COCHRAN VARIANCE OUTLIER TEST
!     EXAMPLE--COCHRAN VARIANCE OUTLIER TEST Y X
!     REFERENCES--RUBEN U.E. 't LAM (2010), "SCRUTINY OF VARIANCE RESULTS
!                 FOR OUTLIERS: COCHRAN'S TEST OPTIMIZED", ANALYTICA
!                 CHIMICA ACTA, VOL. 659, NO. 1-2, PP. 68-84.
!               --KANJI (2006), "100 STATISTICAL TESTS", SAGE
!                 PUBLICATIONS, P. 75.
!               --W.G. Cochran, The distribution of the largest of a set
!                 of estimated variances as a fraction of their total,
!                 Annals of Human Genetics (London) 11(1), 47–52 (January
!                 1941).
!               --ISO Standard 5725–2:1994, “Accuracy (trueness and
!                 precision) of measurement methods and results – Part 2:
!                 Basic method for the determination of repeatability and
!                 reproducibility of a standard measurement method”,
!                 International Organization for Standardization,
!                 Geneva, Switzerland, 1994;
!                 http://www.iso.org/iso/iso_catalogue/catalogue_tc/
!                 catalogue_detail.htm?csnumber=11834
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015/3
!     ORIGINAL VERSION--MARCH     2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
!
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION NU(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      EQUIVALENCE(GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB2),TEMP2(1))
      EQUIVALENCE(GARBAG(IGARB3),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB4),TEMP4(1))
      EQUIVALENCE(IGARBG(IIGAR1),NU(1))
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='OT '
      IERROR='NO'
      IFOUND='YES'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ****************************************************
!               **  TREAT THE COCHRAN VARIANCE OUTLIER TEST CASE  **
!               ****************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVOT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,IFORSW
   55   FORMAT('MAXNXT,IFORSW = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE COMMAND        **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
!     CHECK FOR FOLLOWING COMMAND:
!
!        <MULTIPLE> COCHRAN <MINIMUM/MAXIMUM/TWO-SIDED> VARIANCE OUTLIER TEST
!
      ICASAN='CVOT'
      ICASA2='UPPE'
      IMULT='OFF'
      IFOUND='NO'
      ISTRT=0
!
!     FIRST CHECK FOR WORD "MULTIPLE"
!
      IF(ICOM.EQ.'MULT')THEN
        ISTRT=1
        IMULT='ON'
      ENDIF
!
!     NEXT CHECK FOR WORD "COCHRAN"
!
      IF(ISTRT.EQ.0)THEN
        IF(ICOM.EQ.'COCH')THEN
          ISTRT=1
        ELSE
          GO TO 9000
        ENDIF
      ELSE
        IF(IHARG(ISTRT+1).EQ.'COCH')THEN
          ISTRT=ISTRT+1
        ELSE
          GO TO 9000
        ENDIF
      ENDIF
!
!     NEXT CHECK FOR MINIMUM (LOWER), MAXIMUM (UPPER), OR TWO-SIDED
!
      IF(IHARG(ISTRT).EQ.'LOWE' .OR. IHARG(ISTRT).EQ.'MINI')THEN
        ISTRT=ISTRT+1
        ICASA2='LOWE'
      ELSEIF(IHARG(ISTRT).EQ.'UPPE' .OR. IHARG(ISTRT).EQ.'MAXI')THEN
        ISTRT=ISTRT+1
        ICASA2='UPPE'
      ELSEIF(IHARG(ISTRT).EQ.'TWOS')THEN
        ISTRT=ISTRT+1
        ICASA2='TWOS'
      ELSEIF(IHARG(ISTRT).EQ.'TWO ' .AND.   &
             IHARG(ISTRT+1).EQ.'SIDE')THEN
        ISTRT=ISTRT+2
        ICASA2='TWOS'
      ENDIF
!
!     CHECK FOR "VARIANCE OUTLIER TEST"
!
      IF(IHARG(ISTRT).EQ.'VARI' .AND. IHARG(ISTRT+1).EQ.'OUTL' .AND.   &
         IHARG(ISTRT+2).EQ.'TEST')THEN
         IFOUND='YES'
         ISTRT=ISTRT+2
      ELSEIF(IHARG(ISTRT).EQ.'VARI' .AND. IHARG(ISTRT+1).EQ.'OUTL')THEN
         IFOUND='YES'
         ISTRT=ISTRT+1
      ELSEIF(IHARG(ISTRT).EQ.'VARI' .AND. IHARG(ISTRT+1).EQ.'TEST')THEN
         IFOUND='YES'
         ISTRT=ISTRT+1
      ELSEIF(IHARG(ISTRT).EQ.'VARI')THEN
         IFOUND='YES'
      ENDIF
!
      IF(IFOUND.EQ.'NO')GO TO 9000
      IF(ISTRT.GT.0)THEN
        CALL ADJUST(ISTRT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ENDIF
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COCHRAN VARIANCE OUTLIER TEST'
      MINNA=1
      MAXNA=100
      MINNVA=2
      MAXNVA=2
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
        MINNVA=2
        MAXNVA=30
      ENDIF
      MINN2=2
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                       **
!               **  GENERATE THE COCHRAN VARIANCE OUTLIER TEST FOR **
!               **  THE VARIOUS  CASES                             **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
!     NOTE: ONLY ALLOW MATRIX ARGUMENTS FOR "MULTIPLE" CASE.
!           FOR CASE WHERE SECOND VARIABLE IS A GROUP-ID VARIABLE,
!           MATRIX ARGUMENTS DON'T MAKE SENSE.
!
      IF(IMULT.EQ.'OFF')THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=2
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    YTEMP,XTEMP,YTEMP,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************************************
!               **  STEP 3B--                                       **
!               **  PREPARE FOR ENTRANCE INTO DPCVO2--              **
!               ******************************************************
!
        ISTEPN='3B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,331)
  331     FORMAT('***** FROM DPCVOT, AS WE ARE ABOUT TO CALL DPCVO2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,332)NLOCAL
  332     FORMAT('NLOCAL = ',I8)
          CALL DPWRST('XXX','BUG ')
          DO 335 I=1,NLOCAL
            WRITE(ICOUT,336)I,YTEMP(I),XTEMP(I)
  336       FORMAT('I,YTEMP(I),XTEMP(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
  335     CONTINUE
        ENDIF
!
        CALL DPCVO2(YTEMP,XTEMP,NLOCAL,ICASA2,   &
                    IVARN1,IVARN2,   &
                    TEMP1,TEMP2,TEMP3,TEMP4,NU,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,   &
                    STATVA,STATV2,STATCU,STATCL,PVALU,PVALL,   &
                    CUT001,CUT005,CUT01,CUT025,CUT05,CUT10,CUT25,   &
                    CUT50,   &
                    CUT75,CUT90,CUT95,CUT975,CUT99,CUT995,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
!
!               *******************************************************
!               **  STEP 4A--                                        **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES.  NOTE THAT  **
!               **          FOR THE COCHRAN TEST, THE MULTIPLE LABS  **
!               **          ARE CONVERTED INTO A "Y X" STACKED PAIR  **
!               **          WHERE "X" IS THE LAB-ID VARIABLE.        **
!               *******************************************************
!
      ELSEIF(IMULT.EQ.'ON')THEN
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=NUMVAR
        CALL DPPAR8(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    TEMP1,YTEMP,XTEMP,NLOCAL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NUMVAR=2
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVOT')THEN
          ISTEPN='4B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,442)
  442     FORMAT('***** FROM THE MIDDLE  OF DPCVOT--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,443)ICASAN,NUMVAR,NLOCAL
  443     FORMAT('ICASAN,NUMVAR,NLOCAL = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 445 I=1,NLOCAL
              WRITE(ICOUT,446)I,YTEMP(I),XTEMP(I)
  446         FORMAT('I,YTEMP(I),XTEMP(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
  445       CONTINUE
          ENDIF
        ENDIF
!
        CALL DPCVO2(YTEMP,XTEMP,NLOCAL,ICASA2,   &
                    IVARN1,IVARN2,   &
                    TEMP1,TEMP2,TEMP3,TEMP4,NU,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,   &
                    STATVA,STATV2,STATCU,STATCL,PVALU,PVALL,   &
                    CUT001,CUT005,CUT01,CUT025,CUT05,CUT10,CUT25,   &
                    CUT50,   &
                    CUT75,CUT90,CUT95,CUT975,CUT99,CUT995,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
!
      ENDIF
!
!               ***************************************
!               **  STEP 61--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVOT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='DPLT'
!
      IF(ICASA2.EQ.'UPPE')THEN
        IH='STAT'
        IH2='VAL '
        VALUE0=STATVA
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
        IH='STAT'
        IH2='CDF '
        VALUE0=STATCU
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
        IH='PVAL'
        IH2='UE  '
        VALUE0=PVALU
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
      ELSEIF(ICASA2.EQ.'LOWE')THEN
        IH='STAT'
        IH2='VAL '
        VALUE0=STATV2
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
        IH='STAT'
        IH2='CDF '
        VALUE0=STATCL
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
        IH='PVAL'
        IH2='UE  '
        VALUE0=PVALL
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
      ELSE
        IH='STAT'
        IH2='VALU'
        VALUE0=STATVA
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
!
        IH='STAT'
        IH2='VALL'
        VALUE0=STATV2
        CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                    IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                    IANS,IWIDTH,IBUGA3,IERROR)
      ENDIF
!
      IH='CUTO'
      IH2='FF50'
      VALUE0=CUT50
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF75'
      VALUE0=CUT75
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF90'
      VALUE0=CUT90
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF95'
      VALUE0=CUT95
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F975'
      VALUE0=CUT975
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF99'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F995'
      VALUE0=CUT995
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F999'
      VALUE0=CUT999
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF25'
      VALUE0=CUT25
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF10'
      VALUE0=CUT10
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF05'
      VALUE0=CUT05
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F025'
      VALUE0=CUT025
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF01'
      VALUE0=CUT01
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F005'
      VALUE0=CUT005
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F001'
      VALUE0=CUT001
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVOT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NLOCAL,STATVA,STATCD
 9014   FORMAT('NLOCAL,STATVA,STATCD = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVOT
      SUBROUTINE DPCVO2(Y,TAG,N,ICASA2,IVARID,IVARI2,   &
                        TEMP1,TEMP2,G,V,NU,   &
                        ICAPSW,ICAPTY,IFORSW,IMULT,   &
                        STATVA,STATV2,STATCU,STATCL,PVALU,PVALL,   &
                        CUT001,CUT005,CUT01,CUT025,CUT05,CUT10,CUT25,   &
                        CUT50,   &
                        CUT75,CUT90,CUT95,CUT975,CUT99,CUT995,CUT999,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT COCHRAN'S TEST FOR VARIANCE
!              OUTLIERS (I.E., IS LARGEST VARIANCE FROM K TREATEMENTS
!              SIGNIFICANCTLY LARGER THAN THE VARIANCES FROM THE OTHER
!              GROUPS).
!
!              THE TEST STATISTIC IS RATIO OF THE LARGEST VARIANCE TO
!              THE SUM OF ALL THE VARIANCES.
!
!              IT IS ASSUMED THAT THE DATA ARE APPROXIMATELY NORMAL AND
!              AT LEAST 3 GROUPS ARE REQUIRED.
!
!              NOTE THAT COCHRAN'S ORIGINAL TEST REQUIRED EQUAL GROUP
!              SIZES AND WAS FOR THE MAXIMUM VARIANCE ONLY.  WE HAVE
!              INCORPORATED LAM'S UPDATES TO THE TEST WHICH ALLOW
!              THE MINIMUM VARIANCE (OR A TWO-SIDED TEST) TO BE
!              TESTED AND ALSO ALLOW FOR UNEQUAL GROUP SIZES.
!
!              NOTE THAT THE LEVENE AND BARTLETT TESTS ARE USED TO
!              TEST FOR THE HOMOGENEITY OF VARIANCES.  THE COCHRAN
!              TEST HAS A SOMEWHAT SIMILAR PURPOSE.  HOWEVER, IT IS
!              SPECIFICALLY AN "OUTLIER" TEST WHEREAS THE LEVENE AND
!              BARTLETT TEST FOR OVERALL HOMOGENEITY.  THE COCHRAN TEST
!              MAY BE MORE RELEVANT IN THE CONTEXT OF PROFICIENCY TEST
!              WHERE WE ARE TRYING TO IDENTIFY SPECIFICE LABORATORIES
!              THAT ARE "DIFFERENT" THAN THE OTHERS RATHER THAN JUST
!              TESTING FOR GENERAL HOMOGENEITY.
!
!     EXAMPLE--COCHRAN VARIANCE OUTLIER TEST Y TAG
!     REFERENCES--RUBEM U.E. 't LAM (2010), "SCRUTINY OF VARIANCE RESULTS
!                 FOR OUTLIERS: COCHRAN'S TEST OPTIMIZED", ANALYTICA
!                 CHIMICA ACTA, VOL. 659, NO. 1-2, PP. 68-84.
!               --KANJI (2006), "100 STATISTICAL TESTS", SAGE
!                 PUBLICATIONS, P. 75.
!               --W.G. Cochran, The distribution of the largest of a set
!                 of estimated variances as a fraction of their total,
!                 Annals of Human Genetics (London) 11(1), 47–52 (January
!                 1941).
!               --ISO Standard 5725–2:1994, “Accuracy (trueness and
!                 precision) of measurement methods and results – Part 2:
!                 Basic method for the determination of repeatability and
!                 reproducibility of a standard measurement method”,
!                 International Organization for Standardization,
!                 Geneva, Switzerland, 1994;
!                 http://www.iso.org/iso/iso_catalogue/catalogue_tc/
!                 catalogue_detail.htm?csnumber=11834
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015/04
!     ORIGINAL VERSION--APRIL     2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IOP
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION G(*)
      DIMENSION V(*)
!
      INTEGER NU(*)
!
      PARAMETER (NUMALP=15)
      REAL ALPHA(NUMALP)
      REAL CV(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=25)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       0.1, 0.5, 1.0, 2.5, 5.0, 10.0, 25.0,   &
       50.0,   &
       75.0, 90.0, 95.0, 97.5, 99.0, 99.5, 99.9/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='O2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVO2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCVO2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IMULT,ICASA2,N
   52   FORMAT('IBUGA3,ISUBRO,IMULT,ICASA2,N = ',4(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ***************************************
!               **  STEP 1--                         **
!               **  CARRY OUT CALCULATIONS  FOR      **
!               **  COCHRAN'S VARIANCE OUTLIER TEST  **
!               ***************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL DPCVO3(Y,TAG,N,ICASA2,   &
                  TEMP1,TEMP2,G,V,NU,   &
                  STATVA,STATV2,STATCU,STATCL,PVALU,PVALL,   &
                  ALPHA,CV,NUMALP,   &
                  IDF1,IDF2,ILABMX,ILABMN,NUMDIS,NGROUP,   &
                  DTOTVA,VARMAX,VARMIN,   &
                  IBUGA3,ISUBRO,IERROR)
!
!     WRITE FOLLOWING TO DPST1F.DAT
!
!       1. GROUP NUMBER
!       2. VARIANCE
!       3. VALUE OF G-STATISTIC
!
      IOP='OPEN'
      IFLG11=1
      IFLG21=1
      IFLG31=0
      IFLG41=0
      IFLG51=0
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLA41,IFLG51,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
      WRITE(IOUNI1,110)
  110 FORMAT(3X,'GROUP',7X,'VARIANCE',4X,'G-STATISTIC')
      DO 120 I=1,NUMDIS
        WRITE(IOUNI1,125)NU(I)+1,V(I),G(I)
  125   FORMAT(I8,2E15.7)
  120 CONTINUE
!
      WRITE(IOUNI2,130)
  130 FORMAT(10X,'ALPHA',1X,'CRITICAL VALUE')
      DO 140 I=1,NUMALP
        WRITE(IOUNI2,145)ALPHA(I),CV(I)
  145   FORMAT(2E15.7)
  140 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG11,IFLG21,IFLG31,IFLA41,IFLG51,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               **********************************************
!               **   STEP 42--                              **
!               **   WRITE OUT EVERYTHING                   **
!               **   FOR COCHRAN'S VARIANCE OUTLIER TEST    **
!               **********************************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Cochran Variance Outlier Test'
      NCTITL=29
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(IMULT.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASA2.EQ.'UPPE')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Largest Variance is Not an Outlier'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: Largest Variance is an Outlier'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSEIF(ICASA2.EQ.'LOWE')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Smallest Variance is Not an Outlier'
        NCTEXT(ICNT)=39
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: Smallest Variance is an Outlier'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='H0: Extreme Variance is Not an Outlier'
        NCTEXT(ICNT)=38
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Ha: Extreme Variance is an Outlier'
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NUMDIS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups with Positive Variance:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=REAL(NGROUP)
      IDIGIT(ICNT)=0
      IF(ICASA2.EQ.'UPPE' .OR. ICASA2.EQ.'TWOS')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Group with Largest Variance:'
        NCTEXT(ICNT)=28
        AVALUE(ICNT)=REAL(ILABMX)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Largest Variance:'
        NCTEXT(ICNT)=17
        AVALUE(ICNT)=VARMAX
        IDIGIT(ICNT)=NUMDIG
      ELSEIF(ICASA2.EQ.'LOWE' .OR. ICASA2.EQ.'TWOS')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Group with Smallest Variance:'
        NCTEXT(ICNT)=29
        AVALUE(ICNT)=REAL(ILABMN)
        IDIGIT(ICNT)=0
        ICNT=ICNT+1
        ITEXT(ICNT)='Smallest Variance:'
        NCTEXT(ICNT)=18
        AVALUE(ICNT)=VARMIN
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)='Sum of Variance:'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=DTOTVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(ICASA2.EQ.'TWOS')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Cochran Test Statistic Value (upper):'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=STATVA
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Cochran Test Statistic Value (lower):'
        NCTEXT(ICNT)=37
        AVALUE(ICNT)=STATV2
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Cochran Test Statistic Value:'
        NCTEXT(ICNT)=29
        IF(ICASA2.EQ.'UPPE')THEN
          AVALUE(ICNT)=STATVA
        ELSE
          AVALUE(ICNT)=STATV2
        ENDIF
        IDIGIT(ICNT)=NUMDIG
        IF(ICASA2.EQ.'UPPE')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='CDF of Test Statistic:'
          NCTEXT(ICNT)=22
          AVALUE(ICNT)=STATCU
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='P-Value:'
          NCTEXT(ICNT)=8
          AVALUE(ICNT)=PVALU
          IDIGIT(ICNT)=NUMDIG
        ELSEIF(ICASA2.EQ.'LOWE')THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='CDF of Test Statistic:'
          NCTEXT(ICNT)=22
          AVALUE(ICNT)=STATCL
          IDIGIT(ICNT)=NUMDIG
          ICNT=ICNT+1
          ITEXT(ICNT)='P-Value:'
          NCTEXT(ICNT)=8
          AVALUE(ICNT)=PVALL
          IDIGIT(ICNT)=NUMDIG
        ENDIF
      ENDIF
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
!
!     DON'T PRINT REFERENCE DISTRIBUTION FOR TWO-TAILED TEST SINCE
!     IT IS DIFFERENT FOR MINIMUM AND MAXIMUM TESTS.
!
      IF(ICASA2.EQ.'TWOS')GO TO 4299
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:44)='Percent Points of the Reference Distribution'
      NCTITL=44
      NUMLIN=1
      NUMROW=NUMALP
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      DO 4223 I=1,NUMALP
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            AMAT(I,J)=CV(I)
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMALP,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
 4299 CONTINUE
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CUT0=0.0
      CUT001=CV(1)
      CUT005=CV(2)
      CUT01=CV(3)
      CUT025=CV(4)
      CUT05=CV(5)
      CUT10=CV(6)
      CUT25=CV(7)
      CUT50=CV(8)
      CUT75=CV(9)
      CUT90=CV(10)
      CUT95=CV(11)
      CUT975=CV(12)
      CUT99=CV(13)
      CUT995=CV(14)
      CUT999=CV(15)
      IF(ICASA2.EQ.'UPPE')THEN
        CDF1=CUT90
        CDF2=CUT95
        CDF3=CUT975
        CDF4=CUT99
      ELSEIF(ICASA2.EQ.'LOWE')THEN
        CDF1=CUT10
        CDF2=CUT05
        CDF3=CUT025
        CDF4=CUT01
      ELSE
        CDF1=CUT95
        CDF2=CUT975
        CDF3=CUT995
        CDF4=CUT05
        CDF5=CUT025
        CDF6=CUT005
      ENDIF
!
      ITITL9=' '
      NCTIT9=0
      IF(ICASA2.EQ.'UPPE')THEN
        ITITLE='Conclusions (Upper 1-Tailed Test)'
        NCTITL=33
      ELSEIF(ICASA2.EQ.'LOWE')THEN
        ITITLE='Conclusions (Lower 1-Tailed Test)'
        NCTITL=33
      ELSEIF(ICASA2.EQ.'TWOS')THEN
        ITITLE='Conclusions (Two-Tailed Test)'
        NCTITL=29
      ENDIF
      IF(ICASA2.EQ.'TWOS')THEN
        NUMLIN=2
        NUMROW=3
        NUMCOL=5
        ITITL2(1,1)=' '
        ITITL2(2,1)='Alpha'
        NCTIT2(1,1)=0
        NCTIT2(2,1)=5
        ITITL2(1,2)='Significance'
        ITITL2(2,2)='Level'
        NCTIT2(1,2)=12
        NCTIT2(2,2)=5
        ITITL2(1,3)='Lower'
        ITITL2(2,3)='Critical Value'
        NCTIT2(1,3)=5
        NCTIT2(2,3)=14
        ITITL2(1,4)='Upper'
        ITITL2(2,4)='Critical Value'
        NCTIT2(1,4)=5
        NCTIT2(2,4)=14
        ITITL2(1,5)=' '
        ITITL2(2,5)='Conclusion'
        NCTIT2(1,5)=0
        NCTIT2(2,5)=10
      ELSE
        NUMLIN=1
        NUMROW=4
        NUMCOL=4
        ITITL2(1,1)='Alpha'
        NCTIT2(1,1)=5
        ITITL2(1,2)='CDF'
        NCTIT2(1,2)=3
        ITITL2(1,3)='Critical Value'
        NCTIT2(1,3)=14
        ITITL2(1,4)='Conclusion'
        NCTIT2(1,4)=10
      ENDIF
!
      NMAX=0
      DO 4321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=7
        IF(ICASA2.NE.'TWOS' .AND. I.EQ.2)NTOT(I)=7
        IF(I.EQ.3)NTOT(I)=17
        IF(ICASA2.EQ.'TWOS' .AND. I.EQ.4)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='ALPH'
 4321 CONTINUE
      ITYPCO(3)='NUME'
      IF(ICASA2.EQ.'TWOS')ITYPCO(4)='NUME'
      IDIGIT(1)=0
      IDIGIT(2)=0
      DO 4323 I=1,NUMROW
        DO 4325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 4325   CONTINUE
 4323 CONTINUE
      IF(ICASA2.EQ.'UPPE')THEN
        IVALUE(1,1)='10%'
        IVALUE(2,1)='5%'
        IVALUE(3,1)='2.5%'
        IVALUE(4,1)='1%'
        IVALUE(1,2)='90%'
        IVALUE(2,2)='95%'
        IVALUE(3,2)='97.5%'
        IVALUE(4,2)='99%'
        NCVALU(1,1)=3
        NCVALU(2,1)=2
        NCVALU(3,1)=4
        NCVALU(4,1)=2
        NCVALU(1,2)=3
        NCVALU(2,2)=3
        NCVALU(3,2)=5
        NCVALU(4,2)=3
        IVALUE(1,4)='Accept H0'
        IVALUE(2,4)='Accept H0'
        IVALUE(3,4)='Accept H0'
        IVALUE(4,4)='Accept H0'
        NCVALU(1,4)=9
        NCVALU(2,4)=9
        NCVALU(3,4)=9
        NCVALU(4,4)=9
        IF(STATVA.GT.CUT90)IVALUE(1,4)='Reject H0'
        IF(STATVA.GT.CUT95)IVALUE(2,4)='Reject H0'
        IF(STATVA.GT.CUT975)IVALUE(3,4)='Reject H0'
        IF(STATVA.GT.CUT99)IVALUE(4,4)='Reject H0'
        AMAT(1,3)=RND(CUT90,IDIGIT(3))
        AMAT(2,3)=RND(CUT95,IDIGIT(3))
        AMAT(3,3)=RND(CUT975,IDIGIT(3))
        AMAT(4,3)=RND(CUT99,IDIGIT(3))
      ELSEIF(ICASA2.EQ.'LOWE')THEN
        IVALUE(4,1)='10%'
        IVALUE(3,1)='5%'
        IVALUE(2,1)='2.5%'
        IVALUE(1,1)='1%'
        IVALUE(4,2)='10%'
        IVALUE(3,2)='5%'
        IVALUE(2,2)='2.5%'
        IVALUE(1,2)='1%'
        NCVALU(4,1)=3
        NCVALU(3,1)=2
        NCVALU(2,1)=4
        NCVALU(1,1)=2
        NCVALU(4,2)=3
        NCVALU(3,2)=2
        NCVALU(2,2)=4
        NCVALU(1,2)=2
        IVALUE(4,4)='Accept H0'
        IVALUE(3,4)='Accept H0'
        IVALUE(2,4)='Accept H0'
        IVALUE(1,4)='Accept H0'
        NCVALU(4,4)=9
        NCVALU(3,4)=9
        NCVALU(2,4)=9
        NCVALU(1,4)=9
        IF(STATVA.LT.CUT10)IVALUE(4,4)='Reject H0'
        IF(STATVA.LT.CUT05)IVALUE(3,4)='Reject H0'
        IF(STATVA.LT.CUT025)IVALUE(2,4)='Reject H0'
        IF(STATVA.LT.CUT01)IVALUE(1,4)='Reject H0'
        AMAT(4,3)=RND(CUT10,IDIGIT(3))
        AMAT(3,3)=RND(CUT05,IDIGIT(3))
        AMAT(2,3)=RND(CUT025,IDIGIT(3))
        AMAT(1,3)=RND(CUT01,IDIGIT(3))
      ELSE
        IVALUE(1,1)='10%'
        IVALUE(2,1)='5%'
        IVALUE(3,1)='1%'
        IVALUE(1,2)='90%'
        IVALUE(2,2)='95%'
        IVALUE(3,2)='99%'
        NCVALU(1,1)=3
        NCVALU(2,1)=2
        NCVALU(3,1)=2
        NCVALU(1,2)=3
        NCVALU(2,2)=3
        NCVALU(3,2)=3
        IVALUE(1,5)='Accept H0'
        IVALUE(2,5)='Accept H0'
        IVALUE(3,5)='Accept H0'
        NCVALU(1,5)=9
        NCVALU(2,5)=9
        NCVALU(3,5)=9
        IF(STATVA.GT.CUT95.OR.STATV2.LT.CUT05)IVALUE(1,5)='Reject H0'
        IF(STATVA.GT.CUT975.OR.STATV2.LT.CUT025)IVALUE(2,5)='Reject H0'
        IF(STATVA.GT.CUT995.OR.STATV2.LT.CUT005)IVALUE(3,5)='Reject H0'
        AMAT(1,3)=RND(CUT05,IDIGIT(3))
        AMAT(2,3)=RND(CUT025,IDIGIT(3))
        AMAT(3,3)=RND(CUT005,IDIGIT(3))
        AMAT(1,4)=RND(CUT95,IDIGIT(3))
        AMAT(2,4)=RND(CUT975,IDIGIT(3))
        AMAT(3,4)=RND(CUT995,IDIGIT(3))
      ENDIF
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=1500
      IWRTF(2)=IWRTF(1)+1500
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='42E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVO2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVO2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)STATVA,STATCD,PVAL
 9014   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVO2
      SUBROUTINE DPCVO3(Y,TAG,N,ICASAN,   &
                        DTAG,YTEMP,G,V,NU,   &
                        STATVA,STATV2,STATCU,STATCL,PVALU,PVALL,   &
                        ALPHAV,CV,NALPHA,   &
                        IDF1,IDF2,ILABMX,ILABMN,NUMDIS,NGROUP,   &
                        DVARTO,VARMAX,VARMIN,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT COCHRAN'S TEST FOR VARIANCE
!              OUTLIERS (I.E., IS LARGEST VARIANCE FROM K TREATEMENTS
!              SIGNIFICANCTLY LARGER THAN THE VARIANCES FROM THE OTHER
!              GROUPS).
!
!              THE TEST STATISTIC IS RATIO OF THE LARGEST VARIANCE TO
!              THE SUM OF ALL THE VARIANCES.
!
!              IT IS ASSUMED THAT THE DATA ARE APPROXIMATELY NORMAL,
!              AT LEAST 3 GROUPS ARE REQUIRED, AND ALL SAMPLE SIZES
!              ARE EQUAL.
!
!              THE TEST STATISITC IS:
!
!                 C = MAX(S(i)**2)/SUM[i=1 to k][S(i)]
!
!              WHERE THE S(i) ARE THE VARIANCES FROM THE K GROUPS.
!
!              THIS IS AN UPPER ONE-SIDED TEST AND THE CRITICAL VALUE
!              CAN BE COMPUTED AS
!
!                 CUL(ALPHA,NI,K) = 1/[1 +
!                 (K-1)/Fc(ALPHA/K,(NI-1),(K-1)*(NI-1))}
!
!              NOTE THAT 't LAM HAS EXTENDED THIS TEST TO HANDLE UNEQUAL
!              SAMPLE SIZES AND TO TEST FOR THE SMALLEST AS WELL AS THE
!              LARGEST VARIANCE (AND TO PERFORM TWO-SIDED TESTS AS
!              WELL).  SEE  DPGVT3 FOR THIS VERSION OF THE TEST.
!
!     EXAMPLE--COCHRAN VARIANCE OUTLIER TEST Y TAG
!     REFERENCES--RUBEM U.E. 't LAM (2010), "SCRUTINY OF VARIANCE RESULTS
!                 FOR OUTLIERS: COCHRAN'S TEST OPTIMIZED", ANALYTICA
!                 CHIMICA ACTA, VOL. 659, NO. 1-2, PP. 68-84.
!               --KANJI (2006), "100 STATISTICAL TESTS", SAGE
!                 PUBLICATIONS, P. 75.
!               --W.G. Cochran, The distribution of the largest of a set
!                 of estimated variances as a fraction of their total,
!                 Annals of Human Genetics (London) 11(1), 47–52 (January
!                 1941).
!               --ISO Standard 5725–2:1994, “Accuracy (trueness and
!                 precision) of measurement methods and results – Part 2:
!                 Basic method for the determination of repeatability and
!                 reproducibility of a standard measurement method”,
!                 International Organization for Standardization,
!                 Geneva, Switzerland, 1994;
!                 http://www.iso.org/iso/iso_catalogue/catalogue_tc/
!                 catalogue_detail.htm?csnumber=11834
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015/3
!     ORIGINAL VERSION--MARCH     2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION DTAG(*)
      DIMENSION YTEMP(*)
      DIMENSION V(*)
      DIMENSION G(*)
      DIMENSION ALPHAV(*)
      DIMENSION CV(*)
      INTEGER NU(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='O3  '
      ISUBN0='    '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=CPUMIN
      STATV2=CPUMIN
      STATCU=CPUMIN
      STATCL=CPUMIN
      PVALU=CPUMIN
      PVALL=CPUMIN
      XL=CPUMIN
      XLF=CPUMIN
      XR=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVO3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCOV3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,NALPHA,IDF1,IDF2
   52   FORMAT('IBUGA3,ISUBRO,N,NALPHA,IDF1,IDF2 = ',2(A4,2X),4I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN COCHRANS VARIANCE OUTLIER TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1113)
 1113   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        WRITE(ICOUT,1115)N
 1115   FORMAT('      THE SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 1135 I=2,N
        IF(Y(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1133)HOLD
 1133 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
 1139 CONTINUE
!
      HOLD=TAG(1)
      DO 1235 I=2,N
        IF(TAG(I).NE.HOLD)GO TO 1239
 1235 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,1231)HOLD
 1231 FORMAT('      THE GROUP-ID VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','WRIT')
      GO TO 9000
 1239 CONTINUE
!
!               ********************************************
!               **  STEP 41--                            **
!               **  CARRY OUT CALCULATIONS               **
!               **  FOR COCHRAN'S VARIANCE OUTLIER TEST  **
!               *******************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     COMPUTE THE VARIANCE FOR EACH GROUP
!
      CALL DISTIN(TAG,N,IWRITE,DTAG,NUMDIS,IBUGA3,IERROR)
!
      DVARTO=0.0
      VARMAX=CPUMIN
      VARMIN=CPUMAX
      NNOVAR=0
      ILABMX=0
      NUPOOL=0
      DO 2105 II=1,NUMDIS
        NU(II)=0
        V(II)=0.0
        G(II)=0.0
 2105 CONTINUE
!
      DO 2110 II=1,NUMDIS
        NTEMP=0
        HOLD=DTAG(II)
        DO 2120 J=1,N
          IF(TAG(J).EQ.HOLD)THEN
            NTEMP=NTEMP+1
            YTEMP(NTEMP)=Y(J)
          ENDIF
 2120   CONTINUE
        NU(II)=NTEMP-1
        NUPOOL=NUPOOL + NU(II)
        IF(NU(II).GE.1)THEN
          CALL VAR(YTEMP,NTEMP,IWRITE,AVAR,IBUGA3,IERROR)
          V(II)=AVAR
          DVARTO=DVARTO + REAL(NU(II))*V(II)
          IF(AVAR.LE.0)THEN
            NNOVAR=NNOVAR + 1
          ENDIF
        ELSE
          NNOVAR=NNOVAR + 1
        ENDIF
!
 2110 CONTINUE
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUPOOL.GT.0)THEN
        GMAX=CPUMIN
        GMIN=CPUMAX
        DO 2115 II=1,NUMDIS
          ANUM=REAL(NU(II))*V(II)
          G(II)=ANUM/DVARTO
          IF(G(II).GT.GMAX)THEN
            GMAX=G(II)
            G(II)=GMAX
            ILABMX=II
            VARMAX=V(II)
          ENDIF
          IF(G(II).LT.GMIN .AND. G(II).GT.0.0)THEN
            GMIN=G(II)
            ILABMN=II
            VARMIN=V(II)
          ENDIF
 2115   CONTINUE
      ENDIF
!
!     CHECK: AT LEAST 3 POSITIVE VARIANCES
!
      ISTEPN='23'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NGROUP=NUMDIS - NNOVAR
      IF(NGROUP.LT.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('      AT LEAST 3 GROUPS WITH NON-ZERO VARIANCE ',   &
               'REQUIRED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)NGROUP
 2133   FORMAT('      THE NUMBER OF GROUPS WITH NON-ZERO VARIANCE = ',   &
               I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FOR CRITICAL VALUES:
!
!        1. ICASAN = UPPE  => AN UPPER TAILED TEST (LARGEST VARIANCE)
!        2. ICASAN = LOWE  => A  LOWER TAILED TEST (SMALLEST VARIANCE)
!        3. ICASAN = TWOS  => A  TWO   TAILED TEST (LARGEST/SMALLEST VARIANCE)
!
!
!       FOR TWO-SIDED TEST, TEST BOTH THE MAXIMUM AND THE MINIMUM
!       VARIANCE.
!
!CCCC IF(ICASAN.EQ.'TWOS')THEN
!
!CCCC   VPOOL=REAL(NUPOOL)
!
!       MAXIMUM VARIANCE FIRST
!
!CCCC   ANUM=(VPOOL/REAL(NU(ILABMX))) - 1.0
!CCCC   DENOM=(1.0/G(ILABMX)) - 1.0
!CCCC   FJMX=ANUM/DENOM
!CCCC   IDF1MX=NU(ILABMX)
!CCCC   IDF2MX=NUPOOL-IDF1
!CCCC   CALL FCDF(FJMX,IDF1MX,IDF2MX,PHIMX)
!CCCC   PHIMX=MIN(PHIMX,1.0-PHIMX)
!
!       NOW MINIMUM VARIANCE
!
!CCCC   ANUM=(VPOOL/REAL(NU(ILABMN))) - 1.0
!CCCC   DENOM=(1.0/G(ILABMN)) - 1.0
!CCCC   FJMN=ANUM/DENOM
!CCCC   IDF1MN=NU(ILABMN)
!CCCC   IDF2MN=NUPOOL-IDF1
!CCCC   CALL FCDF(FJMN,IDF1MN,IDF2MN,PHIMN)
!CCCC   PHIMN=MIN(PHIMN,1.0-PHIMN)
!
!CCCC   IF(PHIMX.LE.PHIMN)THEN
!CCCC     STATVA=G(ILABMX)
!CCCC     IDF1=IDF1MX
!CCCC     IDF2=IDFMN
!CCCC   ELSE
!CCCC     STATVA=G(ILABMN)
!CCCC     IDF1=IDF1MN
!CCCC     IDF2=IDF2MN
!CCCC   ENDIF
!
!CCCC   DO3010I=1,NALPHA
!CCCC     CV(I)=CPUMIN
!CCCC     ALPHA=ALPHAV(I)
!CCCC     IF(ALPHA.GE.1.0 .AND. ALPHA.LT.100.0)ALPHA=ALPHA/100.
!CCCC     IF(ALPHA.GT.0.5 .AND. ALPHA.LT.1.0)THEN
!CCCC       ALPHA=1.0 - ALPHA
!CCCC     ELSEIF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
!CCCC       GO TO 3010
!CCCC     ENDIF
!CCCC     TERM9=2.0*REAL(NGROUP)
!CCCC     ALPHA1=1.0-(ALPHA/TERM9)
!CCCC     CALL FPPF(ALPHA1,IDF1,IDF2,FC)
!CCCC     TERM1=1.0 + (REAL(NGROUP-1)/FC)
!CCCC     CV(I)=1.0/TERM1
!3010   CONTINUE
!
!CCCC ELSE
!
        ISTEPN='24'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IDF1MX=NU(ILABMX)
        STATVA=G(ILABMX)
        IDF1MN=NU(ILABMN)
        STATV2=G(ILABMN)
        IDF2MX=NUPOOL - IDF1MX
        IDF2MN=NUPOOL - IDF1MN
        AFACT=1.0
        DO 3019 I=1,NALPHA
          IF(ALPHAV(I).GE.1.0 .AND. ALPHAV(I).LT.100.0)AFACT=100.
 3019   CONTINUE
!
        DO 3020 I=1,NALPHA
          CV(I)=CPUMIN
          ALPHA=ALPHAV(I)/AFACT
          IF(ICASAN.EQ.'UPPE' .OR.   &
             (ICASAN.EQ.'TWOS' .AND. ALPHA.GE.0.5))THEN
            ALPHAT=(1.0 - ALPHA)
            ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
            TERM1=(REAL(NUPOOL)/REAL(NU(ILABMX))) - 1.0
            CALL FPPF(ALPHA1,IDF1MX,IDF2MX,FC)
            TERM2=1.0 + (TERM1/FC)
            CV(I)=1.0/TERM2
          ELSEIF(ICASAN.EQ.'LOWE' .OR.   &
                (ICASAN.EQ.'TWOS' .AND. ALPHA.LT.0.5))THEN
            ALPHAT=ALPHA
            ALPHA1=ALPHAT/REAL(NUMDIS)
            TERM1=(REAL(NUPOOL)/REAL(NU(ILABMN))) - 1.0
            CALL FPPF(ALPHA1,IDF1MN,IDF2MN,FC)
            TERM2=1.0 + (TERM1/FC)
            CV(I)=1.0/TERM2
          ENDIF
 3020   CONTINUE
!CCCC ENDIF
!
!     COMPUTE THE CDF/P-VALUE FOR THE ONE-TAILED TESTS.  USE
!     THE CV ARRAY TO FIND THE BRACKETING INTERVAL.
!
      ISTEPN='25'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVO3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      SIG=1.0E-5
      EPS=1.0E-5
      MAXIT=100
!
      IF(ICASAN.EQ.'UPPE')THEN
        IF(STATVA.EQ.0.0)THEN
          STATCU=0.0
          PVALU=1.0
          GO TO 9000
        ELSEIF(STATVA.LT.CV(1))THEN
          XR=ALPHAV(1)/AFACT
          XRF=CV(1)
          XL=XR/100.
          ALPHAT=(1.0 - XL)
          ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
          TERM1=(REAL(NUPOOL)/REAL(NU(ILABMX))) - 1.0
          CALL FPPF(ALPHA1,IDF1MX,IDF2MX,FC)
          TERM2=1.0 + (TERM1/FC)
          XLF=1.0/TERM2
          IF(STATVA.LT.XLF)THEN
            STATCU=XL
            PVALU=1.0 - STATCU
            GO TO 9000
          ENDIF
        ELSEIF(STATVA.GT.CV(NALPHA))THEN
          XL=ALPHAV(NALPHA)/AFACT
          XLF=CV(NALPHA)
          IF(XL.LE.0.999)THEN
            XR=0.99999
          ELSE
            XR=MAX(0.99999,XL)
          ENDIF
          ALPHAT=(1.0 - XR)
          ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
          TERM1=(REAL(NUPOOL)/REAL(NU(ILABMX))) - 1.0
          CALL FPPF(ALPHA1,IDF1MX,IDF2MX,FC)
          TERM2=1.0 + (TERM1/FC)
          XRF=1.0/TERM2
          IF(STATVA.GT.XRF)THEN
            STATCU=XR
            PVALU=1.0 - STATCU
            GO TO 9000
          ENDIF
        ELSE
          DO 4010 I=2,NALPHA
            IF(STATVA.GE.CV(I-1) .AND. STATVA.LE.CV(I))THEN
              XL=ALPHAV(I-1)/AFACT
              XLF=CV(I-1)
              XR=ALPHAV(I)/AFACT
              XRF=CV(I)
              GO TO 4019
            ENDIF
 4010     CONTINUE
 4019     CONTINUE
        ENDIF
!
!       NOW THAT WE HAVE BRACKETING INTERVAL, USE BISECTION
!       TO DETERMINE CDF VALUE.
!
        IF(STATVA.EQ.XL)THEN
          STATCU=XL
          PVALU=1.0 - STATCU
          GO TO 9000
        ELSEIF(STATVA.EQ.XR)THEN
          STATCU=XR
          PVALU=1.0 - STATCU
          GO TO 9000
        ENDIF
!
        FXL=XLF-STATVA
        FXR=XRF-STATVA
        IC=0
 4025   CONTINUE
        XMID=(XL+XR)/2.0
        ALPHAT=(1.0 - XMID)
        ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
        TERM1=(REAL(NUPOOL)/REAL(NU(ILABMX))) - 1.0
        CALL FPPF(ALPHA1,IDF1MX,IDF2MX,FC)
        TERM2=1.0 + (TERM1/FC)
        XMIDF=1.0/TERM2
        FCS=XMIDF-STATVA
        IF(FCS*FXL.GT.0.0)THEN
          XL=XMID
          XLF=XMIDF
          FXL=FCS
        ELSE
          XR=XMID
          XRF=XMIDF
          FXR=FCS
        ENDIF
        XRML=XR-XL
        IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)THEN
          STATCU=XMID
          PVALU=1.0 - STATCU
          GO TO 9000
        ENDIF
        IC=IC+1
        IF(IC.LE.MAXIT)GO TO 4025
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,4031)
 4031   FORMAT('***** WARNING FROM COCHRAN VARIANCE OUTLIER TEST')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,4033)
 4033   FORMAT('      THE P-VALUE COMPUTATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','WRIT')
        STATCU=XMID
        PVALU=1.0 - STATCU
        GO TO 9000
!
      ELSEIF(ICASAN.EQ.'LOWE')THEN
        IF(STATV2.LT.CV(1))THEN
          XR=ALPHAV(1)/AFACT
          XRF=CV(1)
          XL=XR/100.
          ALPHAT=XL
          ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
          TERM1=(REAL(NUPOOL)/REAL(NU(ILABMN))) - 1.0
          CALL FPPF(ALPHA1,IDF1MN,IDF2MN,FC)
          TERM2=1.0 + (TERM1/FC)
          XLF=1.0/TERM2
          IF(STATVA.LT.XLF)THEN
            STATCL=XL
            PVALL=STATCL
            GO TO 9000
          ENDIF
        ELSEIF(STATV2.GT.CV(NALPHA))THEN
          XL=ALPHAV(NALPHA)/AFACT
          XLF=CV(NALPHA)
          XR=XL*100.
          ALPHAT=XR
          ALPHA1=1.0-(ALPHAT/REAL(NUMDIS))
          TERM1=(REAL(NUPOOL)/REAL(NU(ILABMN))) - 1.0
          CALL FPPF(ALPHA1,IDF1MN,IDF2MN,FC)
          TERM2=1.0 + (TERM1/FC)
          XRF=1.0/TERM2
          IF(STATV2.GT.XRF)THEN
            STATCL=XR
            PVALL=STATCL
            GO TO 9000
          ENDIF
        ELSE
          DO 4110 I=2,NALPHA
            IF(STATV2.GE.CV(I-1) .AND. STATV2.LE.CV(I))THEN
              XL=ALPHAV(I-1)/AFACT
              XLF=CV(I-1)
              XR=ALPHAV(I)/AFACT
              XRF=CV(I)
              GO TO 4119
            ENDIF
 4110     CONTINUE
 4119     CONTINUE
        ENDIF
!
!       NOW THAT WE HAVE BRACKETING INTERVAL, USE BISECTION
!       TO DETERMINE CDF VALUE.
!
        IF(STATV2.EQ.XL)THEN
          STATCL=XL
          PVALU=STATCU
          GO TO 9000
        ELSEIF(STATV2.EQ.XR)THEN
          STATCL=XR
          PVALL=STATCL
          GO TO 9000
        ENDIF
!
        FXL=XLF-STATV2
        FXR=XRF-STATV2
        IC=0
 4125   CONTINUE
        XMID=(XL+XR)/2.0
        ALPHAT=XMID
        ALPHA1=ALPHAT/REAL(NUMDIS)
        TERM1=(REAL(NUPOOL)/REAL(NU(ILABMN))) - 1.0
        CALL FPPF(ALPHA1,IDF1MN,IDF2MN,FC)
        TERM2=1.0 + (TERM1/FC)
        XMIDF=1.0/TERM2
        FCS=XMIDF-STATV2
        IF(FCS*FXL.GT.0.0)THEN
          XL=XMID
          XLF=XMIDF
          FXL=FCS
        ELSE
          XR=XMID
          XRF=XMIDF
          FXR=FCS
        ENDIF
        XRML=XR-XL
        IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)THEN
          STATCL=XMID
          PVALL=STATCL
          GO TO 9000
        ENDIF
        IC=IC+1
        IF(IC.LE.MAXIT)GO TO 4125
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,4031)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,4033)
        CALL DPWRST('XXX','WRIT')
        STATCL=XMID
        PVALL=STATCL
        GO TO 9000
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVO3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOV3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9025)STATVA,STATV2
 9025   FORMAT('STATVA,STATV2 = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 9031 I=1,NALPHA
          WRITE(ICOUT,9033)I,ALPHAV(I),CV(I)
 9033     FORMAT('I,ALPHAV(I),CV(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
 9031   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVO3
      SUBROUTINE DPCUBE(IHARG,IARGT,ARG,NUMARG,   &
                        PXSTAR,PYSTAR,PXEND,PYEND,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                        IBACCO,IBACC2,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DRAW ONE OR MORE CUBES (DEPENDING ON HOW MANY NUMBERS ARE
!              PROVIDED).  THE COORDINATES ARE IN STANDARDIZED UNITS
!              OF 0 TO 100.
!     NOTE--THE INPUT COORDINATES DEFINE THE OPPOSING CORNERS
!           OF (THE FRONT FACE OF) THE CUBE.
!     NOTE-THE USUAL INPUT NUMBER OF COORDINATES IS 2
!          AND THEREFORE THE USUAL INPUT NUMBER OF NUMBERS IS 2*2 = 4.
!     NOTE--IF 2 NUMBERS ARE PROVIDED, THEN THE DRAWN CUBE WILL GO FROM THE
!           LAST CURSOR POSITION TO THE (X,Y) POINT (EITHER ABSOLUTE OR
!           RELATIVE) AS DEFINED BY THE 2 NUMBERS.
!     NOTE--IF 4 NUMBERS ARE PROVIDED, THEN THE DRAWN CUBE WILL GO FROM THE
!           ABSOLUTE (X,Y) POSITION AS DEFINED BY THE FIRST 2 NUMBERS TO THE
!           (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS DEFINED BY THE THIRD
!           AND FOURTH NUMBERS.
!     NOTE--IF 6 NUMBERS ARE PROVIDED, THEN THE DRAWN CUBE WILL GO FROM THE
!           (X,Y) POSITION AS RESULTING FROM THE THIRD AND FOURTH NUMBERS TO
!           THE (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS DEFINED BY THE
!           FIFTH AND SIXTH NUMBERS.
!     NOTE--AND SO FORTH FOR 8, 10, 12, ... NUMBERS.
!     INPUT  ARGUMENTS--IHARG
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PXSTAR
!                     --PYSTAR
!     OUTPUT ARGUMENTS--PXEND
!                     --PYEND
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1987.
!     UPDATED         --JANUARY   1989. CALL LIST FOR OFFSET VAR (ALAN)
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!     UPDATED         --JULY      1997. SUPPORT FOR "DATA" UNITS (ALAN)
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLORS
!
!-----NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
!CCCC ADD FOLLOWING LINE MARCH 1997.
      CHARACTER*4 IDFONT
!CCCC ADD FOLLOWING LINE JULY 1997.
      CHARACTER*4 UNITSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IFIG
      CHARACTER*4 IBELSW
      CHARACTER*4 IERASW
      CHARACTER*4 IBACCO
      CHARACTER*4 ICOPSW
      CHARACTER*4 ITYPEO
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
      DIMENSION PDSCAL(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
!CCCC ADD FOLLOWING LINE MARCH 1997.
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
!
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION IBACC2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IERRG4=IERROR
!CCCC IBUGG4=IBUGD2
!CCCC ISUBG4=ISUBRO
!
      ILOCFN=0
      NUMNUM=0
!
      X1=0.0
      Y1=0.0
      X2=0.0
      Y2=0.0
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CUBE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCUBE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMARG,NUMDEV
   53   FORMAT('NUMARG,NUMDEV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56     FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2(2X,A4),G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,57)PXSTAR,PYSTAR,PXEND,PYEND
   57   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1)
   63   FORMAT('IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1) = ',   &
               2(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG= ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,76)IGRASW,IDIASW
   76   FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77   FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78   FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 81 I=1,NUMDEV
          WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82     FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
                 3(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83     FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',2(A4,2X),A4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84     FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',3I8)
          CALL DPWRST('XXX','BUG ')
   81   CONTINUE
        WRITE(ICOUT,88)IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR
   88   FORMAT('IBUGG4,ISUBG4,IERRG4,IBUGD2,IFOUND,IERROR = ',   &
              5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFIG='CUBE'
      NUMPT=2
      NUMPT2=2*NUMPT
!
!               ********************************
!               **  STEP 0--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
      DO 8000 IDEVIC=1,NUMDEV
!
      IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'OFF')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NULL')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'NONE')GO TO 8000
      IF(IDMANU(IDEVIC).EQ.'DISC')GO TO 8000
!
      IMANUF=IDMANU(IDEVIC)
      IMODEL=IDMODE(IDEVIC)
      IMODE2=IDMOD2(IDEVIC)
      IMODE3=IDMOD3(IDEVIC)
      IGCONT=IDCONT(IDEVIC)
      IGCOLO=IDCOLO(IDEVIC)
      IGFONT=IDFONT(IDEVIC)
      NUMVPP=IDNVPP(IDEVIC)
      NUMHPP=IDNHPP(IDEVIC)
      ANUMVP=NUMVPP
      ANUMHP=NUMHPP
      IOFFSV=IDNVOF(IDEVIC)
      IOFFSH=IDNHOF(IDEVIC)
      IGUNIT=IDUNIT(IDEVIC)
      PCHSCA=PDSCAL(IDEVIC)
!
!               ************************************
!               **  STEP 1--                      **
!               **  CARRY OUT OPENING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      CALL DPOPDE
!
      IBELSW='OFF'
      NUMRIN=0
      IERASW='OFF'
!
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  SEARCH FOR COMMAND SPECIFICATIONS  **
!               *****************************************
!
      IF(NUMARG.GE.2.AND.   &
      IARGT(1).EQ.'NUMB'.AND.IARGT(2).EQ.'NUMB')   &
      GO TO 1111
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ABSO'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1112
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'RELA'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1113
      GO TO 1130
!
 1111 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=1
      GO TO 1119
!
 1112 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=2
      GO TO 1119
!
 1113 CONTINUE
      ITYPEO='RELA'
      ILOCFN=2
      GO TO 1119
 1119 CONTINUE
!
      IF(ILOCFN.GT.NUMARG)GO TO 1129
      DO 1120 I=ILOCFN,NUMARG
      IF(IARGT(I).EQ.'NUMB')GO TO 1120
      GO TO 1129
 1120 CONTINUE
      IFOUND='YES'
      GO TO 1149
 1129 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,1131)
 1131 FORMAT('***** ERROR IN DPCUBE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      ILLEGAL FORM FOR DRAW ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      SUPPOSE IT IS DESIRED TO DRAW A CUBE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('      WITH ONE FRONT FACE CORNER AT THE POINT 20 20 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1137)
 1137 FORMAT('      AND THE FRONT FACE OPPOSITE CORNER AT 40 60')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('      THEN THE ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      CUBE 20 20 40 60 ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      CUBE ABSOLUTE 20 20 40 60 ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1149 CONTINUE
!
!               ****************************
!               **  STEP 3--              **
!               **  DRAW OUT THE LINE(S)  **
!               ****************************
!
      NUMNUM=NUMARG-ILOCFN+1
      IF(NUMNUM.LT.NUMPT2)GO TO 1151
      GO TO 1152
!
 1151 CONTINUE
      J=ILOCFN-1
      X1=PXSTAR
      Y1=PYSTAR
      GO TO 1159
!
 1152 CONTINUE
      J=ILOCFN
      IF(J.GT.NUMARG)GO TO 1190
      X1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X1,X1,IBUGD2,ISUBRO,IERROR)
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y1,Y1,IBUGD2,ISUBRO,IERROR)
      GO TO 1159
 1159 CONTINUE
!
 1160 CONTINUE
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      X2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X2,X2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')X2=X1+X2
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y2,Y2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')Y2=Y1+Y2
!
      CALL DPCUB2(X1,Y1,X2,Y2,   &
                  IFIG,   &
                  ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                  AREGBA,   &
                  IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
      X1=X2
      Y1=Y2
!
      GO TO 1160
 1190 CONTINUE
!
      PXEND=X2
      PYEND=Y2
!
!               ************************************
!               **  STEP 4--                      **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      ICOPSW='OFF'
      NUMCOP=0
      CALL DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
      CALL DPCLDE
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CUBE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCUBE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IFIG,IFOUND,ILOCFN,NUMNUM
 9012   FORMAT('IERROR,IFIG,IFOUND,ILOCFN,NUMNUM = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)X1,Y1,X2,Y2
 9013   FORMAT('X1,Y1,X2,Y2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)PXSTAR,PYSTAR,PXEND,PYEND
 9015   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUBE
      SUBROUTINE DPCUB2(X1,Y1,X2,Y2,   &
                        IFIG,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
!     PURPOSE--DRAW A CUBE WITH ONE FRONT FACE CORNER AT (X1,Y1)
!              AND THE FRONT FACE OPPOSITE CORNER AT (X2,Y2).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/5
!     ORIGINAL VERSION--APRIL     1987.
!     UPDATED         --JANUARY   1989. MODIFY CALLS TO DPDRPL (ALAN)
!     UPDATED         --JANUARY   1989. MODIFY CALL  TO DPFIRE (ALAN)
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----NON-COMMON VARIABLES-------------------------------------
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT2
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IPATT
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION PX(20)
      DIMENSION PY(20)
!CCCC DIMENSION PX3(20)
!CCCC DIMENSION PY3(20)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CUB2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCUB2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2
   53   FORMAT('X1,Y1,X2,Y2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4,IFIG
   59   FORMAT('IBUGG4,ISUBG4,IERRG4,IFIG = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',2(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)PREBTH(1),AREGBA(1)
   62   FORMAT('PREBTH(1),AREGBA(1) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),IREBC2(1,1),IREBC2(1,2),   &
                       IREBC2(1,3)
   63   FORMAT('IREBLI(1),IREBCO(1),IREBC2(1,1),IREBC2(1,2),',   &
               'IREBC2(1,3) = ',2(A4,2X),3I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  SET THE SPECS              **
!               **  WHICH CONTROL THE          **
!               **  APPEARANCE OF THE          **
!               **  RESULTING CUBE.            **
!               *********************************
!
      DELX=ABS(X2-X1)
      DELY=ABS(Y2-Y1)
      DELMIN=DELX
!CCCC IF(DELY.LT.DELX)DELMIN=DELY
      P3D=0.3
      DEL3D=P3D*DELMIN
!
!               *************************
!               **  STEP 2--           **
!               **  FILL THE FIGURE    **
!               **  (IF CALLED FOR)    **
!               *************************
!
      IF(IREFSW(1).EQ.'OFF')GO TO 2190
!
      IPATT=IREPTY(1)
      PTHICK=PREPTH(1)
      PXGAP=PREPSP(1)
      PYGAP=PREPSP(1)
      ICOLF=IREFCO(1)
      ICOLFR=IREFC2(1,1)
      ICOLFG=IREFC2(1,2)
      ICOLFB=IREFC2(1,3)
      ICOLP=IREPCO(1)
      ICOLPR=IREPC2(1,1)
      ICOLPG=IREPC2(1,2)
      ICOLPB=IREPC2(1,3)
!
      IF(IREFSW(1).EQ.'ON')GO TO 2110
      IF(IREFSW(1).EQ.'ONF')GO TO 2110
      IF(IREFSW(1).EQ.'ONS')GO TO 2120
      IF(IREFSW(1).EQ.'ONT')GO TO 2130
      IF(IREFSW(1).EQ.'ONFS')GO TO 2110
      IF(IREFSW(1).EQ.'ONSF')GO TO 2110
      IF(IREFSW(1).EQ.'ONFT')GO TO 2110
      IF(IREFSW(1).EQ.'ONTF')GO TO 2110
      IF(IREFSW(1).EQ.'ONST')GO TO 2120
      IF(IREFSW(1).EQ.'ONTS')GO TO 2120
!
!               ********************************
!               **  STEP 2.1--                **
!               **  FRONT FACE ONLY           **
!               ********************************
!
 2110 CONTINUE
      PX(1)=X1
      PY(1)=Y1
!
      PX(2)=X2
      PY(2)=Y1
!
      PX(3)=X2
      PY(3)=Y2
!
      PX(4)=X1
      PY(4)=Y2
!
      PX(5)=X1
      PY(5)=Y1
!
      NP=5
!
      IPATT2='SOLI'
      CALL DPFIRE(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
!
      IF(IREFSW(1).EQ.'ON')GO TO 2120
      IF(IREFSW(1).EQ.'ONF')GO TO 2190
      IF(IREFSW(1).EQ.'ONS')GO TO 2120
      IF(IREFSW(1).EQ.'ONT')GO TO 2130
      IF(IREFSW(1).EQ.'ONFS')GO TO 2120
      IF(IREFSW(1).EQ.'ONSF')GO TO 2120
      IF(IREFSW(1).EQ.'ONFT')GO TO 2130
      IF(IREFSW(1).EQ.'ONTF')GO TO 2130
      IF(IREFSW(1).EQ.'ONST')GO TO 2120
      IF(IREFSW(1).EQ.'ONTS')GO TO 2120
!
!               ********************************
!               **  STEP 2.2--                **
!               **  SIDE (= RIGHT) FACE ONLY  **
!               ********************************
!
!
 2120 CONTINUE
      PX(1)=X2
      PY(1)=Y2
!
      PX(2)=X2+DEL3D
      PY(2)=Y2+DEL3D
!
      PX(3)=X2+DEL3D
      PY(3)=Y1+DEL3D
!
      PX(4)=X2
      PY(4)=Y1
!
      PX(5)=X2
      PY(5)=Y2
!
      NP=5
!
      IPATT2='SOLI'
      CALL DPFIRE(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
!
      IF(IREFSW(1).EQ.'ON')GO TO 2130
      IF(IREFSW(1).EQ.'ONF')GO TO 2190
      IF(IREFSW(1).EQ.'ONS')GO TO 2190
      IF(IREFSW(1).EQ.'ONT')GO TO 2130
      IF(IREFSW(1).EQ.'ONFS')GO TO 2190
      IF(IREFSW(1).EQ.'ONSF')GO TO 2190
      IF(IREFSW(1).EQ.'ONFT')GO TO 2130
      IF(IREFSW(1).EQ.'ONTF')GO TO 2130
      IF(IREFSW(1).EQ.'ONST')GO TO 2130
      IF(IREFSW(1).EQ.'ONTS')GO TO 2130
!
!               ********************************
!               **  STEP 2.3--                **
!               **  TOP FACE ONLY             **
!               ********************************
!
 2130 CONTINUE
      PX(1)=X1
      PY(1)=Y2
!
      PX(2)=X1+DEL3D
      PY(2)=Y2+DEL3D
!
      PX(3)=X2+DEL3D
      PY(3)=Y2+DEL3D
!
      PX(4)=X2
      PY(4)=Y2
!
      PX(5)=X1
      PY(5)=Y2
!
      NP=5
!
      IPATT2='SOLI'
      CALL DPFIRE(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
!
 2190 CONTINUE
!
!               ***************************
!               **  STEP 3--             **
!               **  DRAW OUT THE FIGURE  **
!               ***************************
!
      IPATT=ILINPA(1)
      PTHICK=PLINTH(1)
      ICOL=ILINCO(1)
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
!
      PX(1)=X1
      PY(1)=Y1
!
      PX(2)=X2
      PY(2)=Y1
!
      PX(3)=X2
      PY(3)=Y2
!
      PX(4)=X1
      PY(4)=Y2
!
      PX(5)=X1
      PY(5)=Y1
!
      NP=5
!
      IFLAG='ON'
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
      PX(1)=X1
      PY(1)=Y2
!
      PX(2)=X1+DEL3D
      PY(2)=Y2+DEL3D
!
      PX(3)=X2+DEL3D
      PY(3)=Y2+DEL3D
!
      PX(4)=X2
      PY(4)=Y2
!
      NP=4
!
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
      PX(1)=X2+DEL3D
      PY(1)=Y2+DEL3D
!
      PX(2)=X2+DEL3D
      PY(2)=Y1+DEL3D
!
      PX(3)=X2
      PY(3)=Y1
!
      NP=3
!
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'CUB2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCUB2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9022)DELX,DELY,DELMIN,P3D,DEL3D
 9022   FORMAT('DELX,DELY,DELMIN,P3D,DEL3D = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9039)IERRG4
 9039   FORMAT('IERRG4 = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUB2
      SUBROUTINE DPCUCO(IHARG,IARGT,ARG,NUMARG,PDIAYC,   &
                        PDIAY2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE (VERTICAL) COORDINATE FOR THE CURSOR
!              THE COORDINATE FOR THE CURSOR WILL BE PLACED
!              IN THE FLOATING POINT VARIABLE PDIAY2.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --PDIAYC
!     OUTPUT ARGUMENTS--PDIAY2
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/7
!     ORIGINAL VERSION--APRIL     1986.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.1)GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      GO TO 1110
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
!
      IERROR='YES'
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN DPCUCO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      ILLEGAL FORM FOR CURSOR COORDINATES ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)
 1124 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('      SUPPOSE IT IS DESIRED TO HAVE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('      THE CURSOR COORDINATE TO BE 20 PERCENT ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)
 1127 FORMAT('      OF THE WAY UP THE SCREEN (FROM THE BOTTOM), ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1128)
 1128 FORMAT('      THEN THE ALLOWABLE FORM IS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('      CURSOR COORDINATE 20')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      PDIAY2=PDIAYC
      GO TO 1180
!
 1160 CONTINUE
      PDIAY2=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)PDIAY2
 1181 FORMAT('THE CURSOR COORDINATE HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPCUCO
