      END SUBROUTINE DPCUSP
      SUBROUTINE DPCUSU(XTEMP1,MAXNXT,   &
                        ICASAN,ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--PERFORM A CUMULATIVE SUM TEST FOR RANDOMNESS
!     EXAMPLE--CUMULATIVE SUM TEST Y
!     REFERENCE--A STATISTICAL TEST SUITE FOR RANDOM AND PSUEDORANDOM
!                NUMBER GENERATORS FOR CRYPTOGRAPHIC APPLICATIONS,
!                ANDREW RUKHIN, JUAN SOTO, JAMES NECHVATAL, MILES SMID,
!                ELAINE BARKER, STEFAN LEIGH, MARK LEVENSON,
!                MARK VANGEL, DAVID BANKS, ALAN HECKERT, JAMES DRAY,
!                SAN VO.  NIST SPECIAL PUBLICATION 800-22,
!                OCTOBER 2000, PP. 14-16.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/12
!     ORIGINAL VERSION--DECEMBER  2003.
!     UPDATED         --MARCH     2011. USE DPPARS ROUTINE
!     UPATED          --MARCH     2011. REWRITTEN TO HANDLE MULTIPLE
!                                       RESPONSE VARIABLES, GROUP-ID
!                                       VARIABLES, OR A LAB-ID VARIABLE
!     UPATED          --JUNE      2019. TWEAK TO SCRATCH STORAGE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFLAGU
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
      CHARACTER*4 ICTMP4
      CHARACTER*4 ICASE
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(1)
      CHARACTER*4 IVARI2(1)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      DIMENSION XTEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION YTEMP1(MAXOBV)
      DIMENSION YTEMP2(MAXOBV)
      DIMENSION YTEMP3(MAXOBV)
      DIMENSION XDESGN(MAXOBV,7)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
      DIMENSION XIDTE3(MAXOBV)
      DIMENSION XIDTE4(MAXOBV)
      DIMENSION XIDTE5(MAXOBV)
      DIMENSION XIDTE6(MAXOBV)
!
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),YTEMP1(1))
      EQUIVALENCE (GARBAG(IGARB2),YTEMP2(1))
      EQUIVALENCE (GARBAG(IGARB3),YTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB4),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB5),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGARB6),XIDTE2(1))
      EQUIVALENCE (GARBAG(IGARB7),XIDTE3(1))
      EQUIVALENCE (GARBAG(IGARB8),XIDTE4(1))
      EQUIVALENCE (GARBAG(IGARB9),XIDTE5(1))
      EQUIVALENCE (GARBAG(IGAR10),XIDTE6(1))
      EQUIVALENCE (GARBAG(JGAR11),TEMP2(1))
      EQUIVALENCE (GARBAG(JGAR12),XDESGN(1,1))
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IREPL='OFF'
      IMULT='OFF'
      ISUBN1='DPCU'
      ISUBN2='SU  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='NO'
      IERROR='NO'
!
!               ********************************************
!               **  TREAT THE CUMULATIVE SUM   TEST CASE  **
!               ********************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCUSU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)IFORSW,ICAPSW,ICAPTY,MAXNXT
   55   FORMAT('IFORSW,ICAPSW,ICAPTY,MAXNXT = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************************************************
!               **  STEP 1--                                       **
!               **  EXTRACT THE COMMAND                            **
!               **  LOOK FOR ONE OF THE FOLLOWING COMMANDS:        **
!               **    1) CUMULATIVE SUM TEST Y                     **
!               **    2) MULTIPLE CUMULATIVE SUM TEST   Y1 ... YK  **
!               **    3) REPLICATED CUMULATIVE SUM TEST            **
!               **       Y X1 ... XK                               **
!               *****************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTC=9999
      ILASTZ=9999
      ICASAN='CUSU'
!
!     LOOK FOR:
!
!          CUMULATIVE SUM TEST
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
        ICTMP4=IHARG(I+3)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'CUMU' .AND. ICTMP2.EQ.'SUM ' .AND.   &
               ICTMP3.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='CUSU'
          ILASTC=I
          ILASTZ=I+2
        ELSEIF(ICTMP1.EQ.'REPL')THEN
          IREPL='ON'
          ILASTC=MIN(ILASTC,I)
          ILASTZ=MAX(ILASTZ,I)
        ELSEIF(ICTMP1.EQ.'MULT')THEN
          IMULT='ON'
          ILASTC=MIN(ILASTC,I)
          ILASTZ=MAX(ILASTZ,I)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
        WRITE(ICOUT,91)ICASAN,IMULT,IREPL,ISHIFT
   91   FORMAT('DPCUSU: ICASAN,IMULT,IREPL,ISHIFT = ',3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IMULT.EQ.'ON')THEN
        IF(IREPL.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR IN CUMULATIVE SUM TEST--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,103)
  103     FORMAT('      YOU CANNOT SPECIFY BOTH "MULTIPLE" AND ',   &
                 '"REPLICATION"')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,104)
  104     FORMAT('      FOR THE CUMULATIVE SUM TEST COMMAND.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************
!               **  STEP 4--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CUMULATIVE SUM TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      IF(IREPL.EQ.'ON')THEN
        IFLAGM=0
        IFLAGE=1
      ENDIF
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=MAXSPN
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ***********************************************
!               **  STEP 5--                                 **
!               **  DETERMINE:                               **
!               **  1) NUMBER OF REPLICATION VARIABLES (0-6) **
!               **  2) NUMBER OF RESPONSE    VARIABLES (>= 1)**
!               ***********************************************
!
      ISTEPN='5'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NRESP=0
      NREPL=0
      IF(IMULT.EQ.'ON')THEN
        NRESP=NUMVAR
      ELSEIF(IREPL.EQ.'ON')THEN
        NRESP=1
        NREPL=NUMVAR-NRESP
        IF(NREPL.LT.1 .OR. NREPL.GT.6)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,511)
  511     FORMAT('      FOR THE REPLICATION CASE, THE NUMBER OF ',   &
                 'REPLICATION VARIABLES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,512)
  512     FORMAT('      MUST BE BETWEEN ONE AND SIX.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,513)NREPL
  513     FORMAT('      THE NUMBER OF REPLICATION VARIABLES = ',I5)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ELSE
        NRESP=NUMVAR
        IMULT='ON'
      ENDIF
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
        WRITE(ICOUT,521)NRESP,NREPL
  521   FORMAT('NRESP,NREPL = ',2I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ******************************************************
!               **  STEP 6--                                        **
!               **  GENERATE THE CUMULATIVE SUM   TEST FOR THE      **
!               **  VARIOUS CASES                                   **
!               ******************************************************
!
      ISTEPN='6'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               ******************************************
!               **  STEP 8A--                           **
!               **  CASE 1: NO REPLICATION VARIABLES    **
!               ******************************************
!
      IF(NREPL.LT.1)THEN
        ISTEPN='8A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
        NCURVE=0
        DO 810 IRESP=1,NRESP
          NCURVE=NCURVE+1
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,811)IRESP,NCURVE
  811       FORMAT('IRESP,NCURVE = ',2I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y,XTEMP1,XTEMP1,NS1,NLOCA2,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!         *****************************************************
!         **  STEP 8B--                                      **
!         *****************************************************
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CUSU')THEN
            ISTEPN='8B'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,822)
  822       FORMAT('***** FROM THE MIDDLE  OF DPFRTE--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,823)ICASAN,NUMVAR,NS1
  823       FORMAT('ICASAN,NUMVAR,NS1 = ',A4,2I8)
            CALL DPWRST('XXX','BUG ')
            IF(NS1.GE.1)THEN
              DO 825 I=1,NS1
                WRITE(ICOUT,826)I,Y(I)
  826           FORMAT('I,Y(I) = ',I8,G15.7)
                CALL DPWRST('XXX','BUG ')
  825         CONTINUE
            ENDIF
          ENDIF
!
          CALL DPCUS2(Y,NS1,   &
                      XTEMP1,MAXNXT,   &
                      ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                      PID,IVARID,IVARI2,NREPL,   &
                      STATVA,STATV2,PVAL1,PVAL2,   &
                      YTEMP1,   &
                      ISUBRO,IBUGA3,IERROR)
!
!               ***************************************
!               **  STEP 61--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
          ISTEPN='8C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(NRESP.GT.1)THEN
            IFLAGU='FILE'
          ELSE
            IFLAGU='ON'
          ENDIF
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(IRESP.EQ.1)IFRST=.TRUE.
          IF(IRESP.EQ.NRESP)ILAST=.TRUE.
          CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                      IFLAGU,IFRST,ILAST,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
  810   CONTINUE
!
!               ****************************************************
!               **  STEP 9A--                                     **
!               **  CASE 3: ONE OR MORE REPLICATION VARIABLES.    **
!               **          FOR THIS CASE, THE NUMBER OF RESPONSE **
!               **          VARIABLES MUST BE EXACTLY 1.          **
!               **          FOR THIS CASE, ALL VARIABLES MUST     **
!               **          HAVE THE SAME LENGTH.                 **
!               ****************************************************
!
      ELSEIF(NREPL.GE.1)THEN
        ISTEPN='9A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        J=0
        IMAX=NRIGHT(1)
        IF(NQ.LT.NRIGHT(1))IMAX=NQ
        DO 910 I=1,IMAX
          IF(ISUB(I).EQ.0)GO TO 910
          J=J+1
!
!         RESPONSE VARIABLE IN Y
!
          ICOLC=1
          IJ=MAXN*(ICOLR(ICOLC)-1)+I
          IF(ICOLR(ICOLC).LE.MAXCOL)Y(J)=V(IJ)
          IF(ICOLR(ICOLC).EQ.MAXCP1)Y(J)=PRED(I)
          IF(ICOLR(ICOLC).EQ.MAXCP2)Y(J)=RES(I)
          IF(ICOLR(ICOLC).EQ.MAXCP3)Y(J)=YPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP4)Y(J)=XPLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP5)Y(J)=X2PLOT(I)
          IF(ICOLR(ICOLC).EQ.MAXCP6)Y(J)=TAGPLO(I)
!
          IF(NREPL.GE.1)THEN
            DO 920 IR=1,MIN(NREPL,6)
              ICOLC=ICOLC+1
              ICOLT=ICOLR(ICOLC)
              IJ=MAXN*(ICOLT-1)+I
              IF(ICOLT.LE.MAXCOL)XDESGN(J,IR)=V(IJ)
              IF(ICOLT.EQ.MAXCP1)XDESGN(J,IR)=PRED(I)
              IF(ICOLT.EQ.MAXCP2)XDESGN(J,IR)=RES(I)
              IF(ICOLT.EQ.MAXCP3)XDESGN(J,IR)=YPLOT(I)
              IF(ICOLT.EQ.MAXCP4)XDESGN(J,IR)=XPLOT(I)
              IF(ICOLT.EQ.MAXCP5)XDESGN(J,IR)=X2PLOT(I)
              IF(ICOLT.EQ.MAXCP6)XDESGN(J,IR)=TAGPLO(I)
  920       CONTINUE
          ENDIF
!
  910   CONTINUE
        NLOCAL=J
!
!       *****************************************************
!       **  STEP 9B--                                      **
!       **  CALL DPCUS2 TO PERFORM CUMULATIVE SUM TEST.    **
!       *****************************************************
!
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CUSU')THEN
          ISTEPN='9C'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,941)
  941     FORMAT('***** FROM THE MIDDLE  OF DPCUSU--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,942)ICASAN,NUMVAR,NLOCAL,NREPL
  942     FORMAT('ICASAN,NUMVAR,NLOCAL,NREPL = ',   &
                 A4,3I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 945 I=1,NLOCAL
              WRITE(ICOUT,946)I,Y(I),XDESGN(I,1),XDESGN(I,2)
  946         FORMAT('I,Y(I),XDESGN(I,1),XDESGN(I,2) = ',   &
                     I8,4F12.5)
              CALL DPWRST('XXX','BUG ')
  945       CONTINUE
          ENDIF
        ENDIF
!
!       *****************************************************
!       **  STEP 9C--                                      **
!       **  FIND THE DISTINCT VALUES IN EACH OF THE        **
!       **  REPLICATION VARIABLES.                         **
!       *****************************************************
!
        CALL DPPP5(XDESGN(1,1),XDESGN(1,2),XDESGN(1,3),   &
                   XDESGN(1,4),XDESGN(1,5),XDESGN(1,6),   &
                   NREPL,NLOCAL,MAXOBV,   &
                   XIDTEM,XIDTE2,XIDTE3,XIDTE4,XIDTE5,XIDTE6,   &
                   XTEMP1,TEMP2,   &
                   NUMSE1,NUMSE2,NUMSE3,NUMSE4,NUMSE5,NUMSE6,   &
                   IBUGA3,ISUBRO,IERROR)
!
!       *****************************************************
!       **  STEP 9D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NCURVE=0
        IADD=1
!
        IF(NREPL.EQ.1)THEN
          J=0
          DO 1110 ISET1=1,NUMSE1
            K=0
            PID(IADD+1)=XIDTEM(ISET1)
            DO 1130 I=1,NLOCAL
              IF(XIDTEM(ISET1).EQ.XDESGN(I,1))THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1130       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
            ENDIF
            IFLAGU='FILE'
            IFRST=.FALSE.
            ILAST=.FALSE.
            IF(NCURVE.EQ.1)IFRST=.TRUE.
            IF(NCURVE.EQ.NUMSE1)ILAST=.TRUE.
            CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110     CONTINUE
        ELSEIF(NREPL.EQ.2)THEN
          J=0
          NTOT=NUMSE1*NUMSE2
          DO 1210 ISET1=1,NUMSE1
          DO 1220 ISET2=1,NUMSE2
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            DO 1290 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1290       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1220     CONTINUE
 1210     CONTINUE
        ELSEIF(NREPL.EQ.3)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3
          DO 1310 ISET1=1,NUMSE1
          DO 1320 ISET2=1,NUMSE2
          DO 1330 ISET3=1,NUMSE3
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            DO 1390 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1390       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1330     CONTINUE
 1320     CONTINUE
 1310     CONTINUE
        ELSEIF(NREPL.EQ.4)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4
          DO 1410 ISET1=1,NUMSE1
          DO 1420 ISET2=1,NUMSE2
          DO 1430 ISET3=1,NUMSE3
          DO 1440 ISET4=1,NUMSE4
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            DO 1490 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1490       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1440     CONTINUE
 1430     CONTINUE
 1420     CONTINUE
 1410     CONTINUE
        ELSEIF(NREPL.EQ.5)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5
          DO 1510 ISET1=1,NUMSE1
          DO 1520 ISET2=1,NUMSE2
          DO 1530 ISET3=1,NUMSE3
          DO 1540 ISET4=1,NUMSE4
          DO 1550 ISET5=1,NUMSE5
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            DO 1590 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1590       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1550     CONTINUE
 1540     CONTINUE
 1530     CONTINUE
 1520     CONTINUE
 1510     CONTINUE
        ELSEIF(NREPL.EQ.6)THEN
          J=0
          NTOT=NUMSE1*NUMSE2*NUMSE3*NUMSE4*NUMSE5*NUMSE6
          DO 1610 ISET1=1,NUMSE1
          DO 1620 ISET2=1,NUMSE2
          DO 1630 ISET3=1,NUMSE3
          DO 1640 ISET4=1,NUMSE4
          DO 1650 ISET5=1,NUMSE5
          DO 1660 ISET6=1,NUMSE6
            K=0
            PID(1+IADD)=XIDTEM(ISET1)
            PID(2+IADD)=XIDTE2(ISET2)
            PID(3+IADD)=XIDTE3(ISET3)
            PID(4+IADD)=XIDTE4(ISET4)
            PID(5+IADD)=XIDTE5(ISET4)
            PID(6+IADD)=XIDTE6(ISET4)
            DO 1690 I=1,NLOCAL
              IF(   &
                 XIDTEM(ISET1).EQ.XDESGN(I,1) .AND.   &
                 XIDTE2(ISET2).EQ.XDESGN(I,2) .AND.   &
                 XIDTE3(ISET3).EQ.XDESGN(I,3) .AND.   &
                 XIDTE4(ISET4).EQ.XDESGN(I,4) .AND.   &
                 XIDTE5(ISET5).EQ.XDESGN(I,5) .AND.   &
                 XIDTE6(ISET6).EQ.XDESGN(I,6)   &
                )THEN
                K=K+1
                TEMP1(K)=Y(I)
              ENDIF
 1690       CONTINUE
            NTEMP=K
            NCURVE=NCURVE+1
            IF(NTEMP.GT.0)THEN
              CALL DPCUS2(TEMP1,NTEMP,   &
                          XTEMP1,MAXNXT,   &
                          ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                          PID,IVARID,IVARI2,NREPL,   &
                          STATVA,STATV2,PVAL1,PVAL2,   &
                          YTEMP1,   &
                          ISUBRO,IBUGA3,IERROR)
              IFLAGU='FILE'
              IFRST=.FALSE.
              ILAST=.FALSE.
              IF(NCURVE.EQ.1)IFRST=.TRUE.
              IF(NCURVE.EQ.NTOT)ILAST=.TRUE.
              CALL DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                          IFLAGU,IFRST,ILAST,   &
                          IBUGA2,IBUGA3,ISUBRO,IERROR)
            ENDIF
 1660     CONTINUE
 1650     CONTINUE
 1640     CONTINUE
 1630     CONTINUE
 1620     CONTINUE
 1610     CONTINUE
        ENDIF
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CUSU')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCUSU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUSU
      SUBROUTINE DPCUS2(Y,N,   &
                        XTEMP,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,ICASAN,M,   &
                        PID,IVARID,IVARI2,NREPL,   &
                        STATVA,STATV2,PVAL1,PVAL2,   &
                        YTEMP1,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT THE CUMULATIVE SUM TEST
!              FOR RANDOMNESS.
!     EXAMPLE--CUMULATIVE SUM TEST Y
!     REFERENCE--A STATISTICAL TEST SUITE FOR RANDOM AND PSUEDORANDOM
!                NUMBER GENERATORS FOR CRYPTOGRAPHIC APPLICATIONS,
!                ANDREW RUKHIN, JUAN SOTO, JAMES NECHVATAL, MILES SMID,
!                ELAINE BARKER, STEFAN LEIGH, MARK LEVENSON,
!                MARK VANGEL, DAVID BANKS, ALAN HECKERT, JAMES DRAY,
!                SAN VO.  NIST SPECIAL PUBLICATION 800-22,
!                OCTOBER 2000, PP. 14-18.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/12
!     ORIGINAL VERSION--DECEMBER  2003.
!     UPDATED         --MARCH     2011. USE DPDTA1 AND DPDTA5 TO PRINT
!                                       TABLES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION XTEMP(*)
      DIMENSION YTEMP1(*)
      DIMENSION PID(*)
!
      PARAMETER (NUMALP=7)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=20)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCU'
      ISUBN2='S2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCUS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASAN,IBUGA3,ISUBRO,N,M,MAXNXT
   52   FORMAT('ICASAN,IBUGA3,ISUBRO,N,M,MAXNXT = ',3(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   56   CONTINUE
      ENDIF
!
      CALL DPCUS3(Y,N,   &
                  STATVA,STATV2,STATCD,STATC2,PVAL1,PVAL2,   &
                  YTEMP1,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *********************************
!               **   STEP 52--                 **
!               **   WRITE OUT EVERYTHING      **
!               **   FOR CUMULATIVE SUM TEST   **
!               *********************************
!
      ISTEPN='52'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Cumulative Sum Test for Randomness'
      NCTITL=34
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NREPL.GT.0)THEN
        IADD=1
        DO 6101 I=1,NREPL
          ICNT=ICNT+1
          ITEMP=I+IADD
          ITEXT(ICNT)='Factor Variable  : '
          WRITE(ITEXT(ICNT)(17:17),'(I1)')I
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(ITEMP)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(ITEMP)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(ITEMP)
          IDIGIT(ICNT)=NUMDIG
 6101   CONTINUE
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: The Data Are Random'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: The Data Are Not Random'
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Forward Direction Cumulative Sum Test Statistic:'
      NCTEXT(ICNT)=48
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Forward Direction P-Value:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=PVAL1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Backward Direction Cumulative Sum Test Statistic:'
      NCTEXT(ICNT)=49
      AVALUE(ICNT)=STATV2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Backward Direction P-Value:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVAL2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      NUMROW=ICNT
      DO 6110 I=1,NUMROW
        NTOT(I)=15
 6110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions for Forward Direction Test'
      NCTITL=38
!
      DO 6130 J=1,4
        DO 6140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 6140   CONTINUE
 6130 CONTINUE
!
      ITITL2(2,1)='Null'
      NCTIT2(2,1)=4
      ITITL2(3,1)='Hypothesis'
      NCTIT2(3,1)=10
!
      ITITL2(2,2)='Confidence'
      NCTIT2(2,2)=10
      ITITL2(3,2)='Level'
      NCTIT2(3,2)=5
!
      ITITL2(3,3)='P-Value'
      NCTIT2(3,3)=7
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 6150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=12
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='ALPH'
        IF(I.EQ.3)ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IWHTML(1)=150
        IWHTML(2)=125
        IWHTML(3)=150
        IWHTML(4)=150
        IINC=1600
        IINC2=1400
        IINC3=2200
        IWRTF(1)=IINC
        IWRTF(2)=IWRTF(1)+IINC
        IWRTF(3)=IWRTF(2)+IINC2
        IWRTF(4)=IWRTF(3)+IINC
!
        DO 6160 J=1,NUMALP
!
          AMAT(J,I)=0.0
          AMAT(J,3)=PVAL1
          IVALUE(J,1)='Random'
          NCVALU(J,1)=6
          IVALUE(J,4)(1:6)='REJECT'
          IF(J.EQ.1)THEN
            IVALUE(J,2)(1:5)='50.0%'
            IF(PVAL1.GE.0.50)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.2)THEN
            IVALUE(J,2)(1:5)='75.0%'
            IF(PVAL1.GE.0.25)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.3)THEN
            IVALUE(J,2)(1:5)='90.0%'
            IF(PVAL1.GE.0.10)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.4)THEN
            IVALUE(J,2)(1:5)='95.0%'
            IF(PVAL1.GE.0.05)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.5)THEN
            IVALUE(J,2)(1:5)='97.5%'
            IF(PVAL1.GE.0.025)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.6)THEN
            IVALUE(J,2)(1:5)='99.0%'
            IF(PVAL1.GE.0.01)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.7)THEN
            IVALUE(J,2)(1:5)='99.9%'
            IF(PVAL1.GE.0.001)IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
          NCVALU(J,2)=5
          NCVALU(J,4)=6
!
 6160   CONTINUE
 6150 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=4
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions for Backward Direction Test'
      NCTITL=40
!
      NMAX=0
      NUMCOL=4
      DO 7150 I=1,NUMCOL
        NTOT(I)=15
        IF(I.EQ.1)NTOT(I)=12
        NMAX=NMAX+NTOT(I)
!
        DO 7160 J=1,NUMALP
!
          AMAT(J,I)=0.0
          AMAT(J,3)=PVAL2
          IVALUE(J,4)(1:6)='REJECT'
          IF(J.EQ.1)THEN
            IVALUE(J,2)(1:5)='50.0%'
            IF(PVAL2.GE.0.50)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.2)THEN
            IVALUE(J,2)(1:5)='75.0%'
            IF(PVAL2.GE.0.25)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.3)THEN
            IVALUE(J,2)(1:5)='90.0%'
            IF(PVAL2.GE.0.10)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.4)THEN
            IVALUE(J,2)(1:5)='95.0%'
            IF(PVAL2.GE.0.05)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.5)THEN
            IVALUE(J,2)(1:5)='97.5%'
            IF(PVAL2.GE.0.025)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.6)THEN
            IVALUE(J,2)(1:5)='99.0%'
            IF(PVAL2.GE.0.01)IVALUE(J,4)(1:6)='ACCEPT'
          ELSEIF(J.EQ.7)THEN
            IVALUE(J,2)(1:5)='99.9%'
            IF(PVAL2.GE.0.001)IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
          NCVALU(J,2)=5
          NCVALU(J,4)=6
!
 7160   CONTINUE
 7150 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=4
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCUS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 9016 I=1,N
          WRITE(ICOUT,9017)I,Y(I),XTEMP(I)
 9017     FORMAT('I,Y(I),XTEMP(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
 9016   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUS2
      SUBROUTINE DPCUS3(Y,N,   &
                        STATVA,STATV2,STATCD,STATC2,PVAL1,PVAL2,   &
                        YTEMP1,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT THE CUMULATIVE SUM TEST
!              FOR RANDOMNESS (EITHER FORWARD DIRECTION OR
!              BACKWARD DIRECTION).  THIS IS EXTRACTED FROM DPCUS2
!              IN ORDER TO MAKE IT CALLABLE FROM CMPSTA (I.E.,
!              MAKE A SUPPORTED STATISTIC).
!     EXAMPLE--LET A = CUMULATIVE SUM FORWARD TEST Y
!     REFERENCE--A STATISTICAL TEST SUITE FOR RANDOM AND PSUEDORANDOM
!                NUMBER GENERATORS FOR CRYPTOGRAPHIC APPLICATIONS,
!                ANDREW RUKHIN, JUAN SOTO, JAMES NECHVATAL, MILES SMID,
!                ELAINE BARKER, STEFAN LEIGH, MARK LEVENSON,
!                MARK VANGEL, DAVID BANKS, ALAN HECKERT, JAMES DRAY,
!                SAN VO.  NIST SPECIAL PUBLICATION 800-22,
!                OCTOBER 2000, PP. 14-18.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/3
!     ORIGINAL VERSION--MARCH     2011. EXTRACTED FROM DPCUS2
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION YTEMP1(*)
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DZ1
      DOUBLE PRECISION DZ2
      DOUBLE PRECISION DCDF1
      DOUBLE PRECISION DCDF2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCU'
      ISUBN2='S3  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCUS3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASAN,IBUGA3,ISUBRO,N
   52   FORMAT('ICASAN,IBUGA3,ISUBRO,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CUS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN CUMULATIVE SUM RANDOMNESS TEST.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1113)
 1113   FORMAT('      AT LEAST SIX OBSERVATIONS REQUIRED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1115)N
 1115   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 1135 I=2,N
      IF(Y(I).NE.HOLD)GO TO 1139
 1135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)HOLD
 1131 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1139 CONTINUE
!
!               *******************************
!               **  STEP 2--                 **
!               **  COMPUTE THE NUMBER OF    **
!               **  DISTINCT VALUES.         **
!               *******************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='NO'
      CALL DISTIN(Y,N,IWRITE,YTEMP1,NDIST,IBUGA3,IERROR)
!
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(NDIST.NE.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2003)
 2003   FORMAT('      FOR CUMULATIVE SUM TEST, EXACTLY TWO DISTINCT ',   &
               'VALUES ARE ALLOWED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2005)NDIST
 2005   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************
!               **  STEP 21--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR CUSUM         TEST  **
!               ******************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
      ALOW=MIN(YTEMP1(1),YTEMP1(2))
      AHIGH=MAX(YTEMP1(1),YTEMP1(2))
      DZ1=0.0D0
      DZ2=0.0D0
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
!
      DO 2120 I=1,N
        IF(Y(I).EQ.ALOW)THEN
          DSUM1=DSUM1 - 1.0
        ELSE
          DSUM1=DSUM1 + 1.0
        ENDIF
        DZ1=MAX(DZ1,ABS(DSUM1))
 2120 CONTINUE
!
      DO 2130 I=N,1,-1
        IF(Y(I).EQ.ALOW)THEN
          DSUM2=DSUM2 - 1.0
        ELSE
          DSUM2=DSUM2 + 1.0
        ENDIF
        DZ2=MAX(DZ2,ABS(DSUM2))
 2130 CONTINUE
!
      AN=REAL(N)
      Z1=REAL(DZ1)/SQRT(AN)
      Z2=REAL(DZ2)/SQRT(AN)
      STATVA=Z1
      STATV2=Z2
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      ATEMP=((AN/Z1)-1.0)/4.0
      IUPP=INT(ATEMP)
      ATEMP=((-AN/Z1)+1.0)/4.0
      ILOW=INT(ATEMP)
      DSUM1=0.0D0
      DO 2140 K=ILOW,IUPP
        AK=REAL(K)
        ATEMP=(4.0*AK+1.0)*Z1
        CALL NODCDF(DBLE(ATEMP),DCDF1)
        ATEMP=((4.0*AK - 1.0)*Z1)
        CALL NODCDF(DBLE(ATEMP),DCDF2)
        DSUM1=DSUM1 + (DCDF1 - DCDF2)
 2140 CONTINUE
!
      ATEMP=((AN/Z1)-3.0)/4.0
      IUPP=INT(ATEMP)
      ATEMP=((-AN/Z1)-1.0)/4.0
      ILOW=INT(ATEMP)
      DO 2150 K=ILOW,IUPP
        AK=REAL(K)
        ATEMP=(4.0*AK+3.0)*Z1
        CALL NODCDF(DBLE(ATEMP),DCDF1)
        ATEMP=((4.0*AK + 1.0)*Z1)
        CALL NODCDF(DBLE(ATEMP),DCDF2)
        DSUM2=DSUM2 + (DCDF1 - DCDF2)
 2150 CONTINUE
!
      ATEMP=((AN/Z2)-1.0)/4.0
      IUPP=INT(ATEMP)
      ATEMP=((-AN/Z2)+1.0)/4.0
      ILOW=INT(ATEMP)
      DSUM3=0.0D0
      DO 2180 K=ILOW,IUPP
        ATEMP=(4.0*REAL(K)+1.0)*Z2
        CALL NODCDF(DBLE(ATEMP),DCDF1)
        ATEMP=((4.0*REAL(K) - 1.0)*Z2)
        CALL NODCDF(DBLE(ATEMP),DCDF2)
        DSUM3=DSUM3 + (DCDF1 - DCDF2)
 2180 CONTINUE
!
      ATEMP=((AN/Z2)-3.0)/4.0
      IUPP=INT(ATEMP)
      ATEMP=((-AN/Z2)-1.0)/4.0
      ILOW=INT(ATEMP)
      DSUM4=0.0D0
      DO 2190 K=ILOW,IUPP
        ATEMP=(4.0*REAL(K)+3.0)*Z2
        CALL NODCDF(DBLE(ATEMP),DCDF1)
        ATEMP=((4.0*REAL(K) + 1.0)*Z2)
        CALL NODCDF(DBLE(ATEMP),DCDF2)
        DSUM4=DSUM4 + (DCDF1 - DCDF2)
 2190 CONTINUE
!
      STATCD=REAL(1.0D0 - DSUM1 + DSUM2)
      STATC2=REAL(1.0D0 - DSUM3 + DSUM4)
      PVAL1=STATCD
      PVAL2=STATC2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CUS3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCUS3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUS3
      SUBROUTINE DPCUS5(STATVA,STATV2,PVAL1,PVAL2,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPCUSU.  THIS ROUTINE
!              UPDATES THE PARAMETERS "STATVAL" AND
!              "PVALUE".  NOTE THAT THERE ARE "FORWARD" AND "BACKWARD"
!              VERSIONS OF THE STATISTIC.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/3
!     ORIGINAL VERSION--MARCH     2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      SAVE IOUNI1
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CUS5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCUS5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)STATVA,STATV2,PVAL1,PVAL2
   53   FORMAT('STATVA,STATV2,PVAL1,PVAL2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,295)
  295     FORMAT(11X,'STATVAL',8X,'PVALUE',   &
                 6X,'STATVAL2',7X,'PVALUE2')
        ENDIF
        WRITE(IOUNI1,299)STATVA,STATV2,PVAL1,PVAL2
  299   FORMAT(4E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
        IF(STATVA.NE.CPUMIN)THEN
          IH='STAT'
          IH2='VAL '
          VALUE0=STATVA
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(STATV2.NE.CPUMIN)THEN
          IH='STAT'
          IH2='VAL2'
          VALUE0=STATV2
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(PVAL1.NE.CPUMIN)THEN
          IH='PVAL'
          IH2='UE  '
          VALUE0=PVAL1
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(PVAL2.NE.CPUMIN)THEN
          IH='PVAL'
          IH2='UE2 '
          VALUE0=PVAL2
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CUS5')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI, IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CUS5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPCUS5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCUS5
      SUBROUTINE DPCUSZ(IHARG,IARGT,ARG,NUMARG,DEFCSZ,   &
                        ACURSZ,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE SIZE FOR THE CURSOR (THE HORIZONTAL STRING
!              ABOVE THE UPPER HORIZONTAL FRAME).  THE SIZE FOR THE
!              CURSOR WILL BE PLACED IN THE FLOATING POINT VARIABLE
!              ACURSZ.  (NOTE THAT THE IMPORTANT VARIABLE PDIAHE IS
!              USUALLY SET EQUAL TO ACURSZ IN THE CALLING ROUTINE
!              AFTER THE CALL TO THIS SUBROUTINE).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --DEFCSZ
!     OUTPUT ARGUMENTS--ACURSZ
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JANUARY   1980.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1199
      IF(IHARG(1).NE.'SIZE')GO TO 1199
      IF(NUMARG.EQ.1)GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      GO TO 1110
!
 1110 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
!
      IERROR='YES'
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN DPCUSZ--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      ILLEGAL FORM FOR CURSOR SIZE ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)
 1124 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1125)
 1125 FORMAT('      SUPPOSE IT IS DESIRED TO HAVE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1126)
 1126 FORMAT('      THE CURSOR ONE AND ONE HALF TIMES AS BIG ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1127)
 1127 FORMAT('      AS THE DEFAULT SIZE (WHICH IS SIZE 1), ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1128)
 1128 FORMAT('      THEN THE ALLOWABLE FORM IS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1131)
 1131 FORMAT('      CURSOR SIZE 1.5 ')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      ACURSZ=DEFCSZ
      GO TO 1180
!
 1160 CONTINUE
      ACURSZ=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)ACURSZ
 1181 FORMAT('THE CURSOR SIZE HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPCUSZ
      SUBROUTINE DPCVTE(XTEMP1,XTEMP2,MAXNXT,   &
                        ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A COEFFICIENT OF VARIATION TEST
!              (1-SAMPLE OR 2-SAMPLE) BASED ON THE FORKMAN METHOD.
!
!              NOTE THAT THIS HANDLES THE GENERAL CASE WHERE WE HAVE
!              MULTIPLE GROUPS. THAT IS, FOR THE ONE SAMPLE CASE WE ARE
!              TESTING WHETHER THE COMMON COEFFICIENT OF VARIATION FOR
!              MULTIPLE GROUPS IS EQUAL TO A GIVEN VALUE.  FOR THE TWO
!              SAMPLE CASE, WE ARE TESTING WHETHER THE COMMON
!              COEFFICIENT OF VARIATION FOR ONE SET OF GROUPS OF DATA
!              IS EQUAL TO THE COMMON COEFFICIENT OF VARIATION FOR A
!              SECOND SET OF GROUPS OF DATA.
!
!              THE MORE COMMON CASE WHERE THERE IS A SINGLE GROUP IS A
!              SPECIAL CASE OF THE MORE GENERAL MULTIPLE GROUPS CASE.
!
!     EXAMPLE--COEFFICIENT OF VARIATION TEST Y X GAMMA0
!              COEFFICIENT OF VARIATION TWO SAMPLE TEST Y1 Y2
!              COEFFICIENT OF VARIATION TWO SAMPLE TEST Y1 X1 Y2 X2
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", COMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, Vol. 38, No. 2, pp. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IH
      CHARACTER*4 IH2
!
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 IVARI5
      CHARACTER*4 IVARI6
      CHARACTER*4 IVARI7
      CHARACTER*4 IVARI8
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION X1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION X2(MAXOBV)
!
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),X1(1))
      EQUIVALENCE (GARBAG(IGARB3),Y2(1))
      EQUIVALENCE (GARBAG(IGARB4),X2(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='TE  '
      IFOUND='NO'
      IERROR='NO'
      ICASAN='CVTE'
      ICASA2='UNKN'
      ICASA3='TWOT'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ****************************************************
!               **  TREAT THE COEFFICIENT OF VARIATION TEST CASE  **
!               ****************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVTE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               *********************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVTE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
!     NOTE THAT SINCE THESE TESTS CAN OPTIONALLY SUPPORT GROUP-ID
!     VARIABLES, THE "MULTIPLE" AND "REPLICATION" OPTIONS WILL NOT
!     BE SUPPORTED.
!
!          ONE SAMPLE COEFFICIENT OF VARIATION TEST (OR 1 SAMPLE)
!          TWO SAMPLE COEFFICIENT OF VARIATION TEST (OR 2 SAMPLE)
!
      IF((ICOM.EQ.'ONE ' .OR. ICOM.EQ.'1   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI' .AND.   &
          IHARG(5).EQ.'UPPE' .AND. IHARG(6).EQ.'TAIL' .AND.   &
          IHARG(7).EQ.'TEST')THEN
        ILASTZ=7
        ICASA2='ONES'
        ICASA3='UPPE'
      ELSEIF((ICOM.EQ.'ONE ' .OR. ICOM.EQ.'1   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI' .AND.   &
          IHARG(5).EQ.'LOWE' .AND. IHARG(6).EQ.'TAIL' .AND.   &
          IHARG(7).EQ.'TEST')THEN
        ILASTZ=7
        ICASA2='ONES'
        ICASA3='LOWE'
      ELSEIF((ICOM.EQ.'TWO ' .OR. ICOM.EQ.'2   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI' .AND.   &
          IHARG(5).EQ.'UPPE' .AND. IHARG(6).EQ.'TAIL' .AND.   &
          IHARG(7).EQ.'TEST')THEN
        ILASTZ=7
        ICASA2='TWOS'
        ICASA3='UPPE'
      ELSEIF((ICOM.EQ.'TWO ' .OR. ICOM.EQ.'2   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI' .AND.   &
          IHARG(5).EQ.'LOWE' .AND. IHARG(6).EQ.'TAIL' .AND.   &
          IHARG(7).EQ.'TEST')THEN
        ILASTZ=7
        ICASA2='TWOS'
        ICASA3='LOWE'
      ELSEIF((ICOM.EQ.'ONE ' .OR. ICOM.EQ.'1   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI')THEN
        ILASTZ=4
        IF(IHARG(5).EQ.'TEST')ILASTZ=5
        ICASA2='ONES'
      ELSEIF((ICOM.EQ.'TWO ' .OR. ICOM.EQ.'2   ') .AND.   &
          IHARG(1).EQ.'SAMP' .AND. IHARG(2).EQ.'COEF' .AND.   &
          IHARG(3).EQ.'OF  ' .AND. IHARG(4).EQ.'VARI')THEN
        ILASTZ=4
        IF(IHARG(5).EQ.'TEST')ILASTZ=5
        ICASA2='TWOS'
      ELSE
        GO TO 9000
      ENDIF
!
      IFOUND='YES'
      CALL SHIFTL(ILASTZ,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVTE')THEN
        WRITE(ICOUT,91)ICASAN,ICASA2,ICASA3,ILASTZ
   91   FORMAT('DPCVTE: ICASAN,ICASA2,ICASA3,ILASTZ = ',3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVTE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COEFFICIENT OF VARIATION TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGM=0
      IF(ICASA2.EQ.'ONES')THEN
        MINNVA=1
        MAXNVA=3
        IFLAGP=29
        IFLAGE=1
      ELSE
        MINNVA=2
        MAXNVA=4
        IFLAGP=0
        IFLAGE=0
      ENDIF
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
  201   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,202)NQ,NUMVAR
  202   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 205 I=1,NUMVAR
            WRITE(ICOUT,207)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  207       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  205     CONTINUE
        ENDIF
      ENDIF
!
!     FOR THE ONE-SAMPLE TEST, CHECK TO SEE IF THE LAST ARGUMENT IS
!     A PARAMETER (AT LEAST ONE VARIABLE MUST BE ENTERED).  IF IT IS
!     NOT, CHECK TO SEE IF THE "GAMMA0" PARAMETER EXISTS.
!
      IF(ICASA2.EQ.'ONES')THEN
        IF(IVARTY(NUMVAR).EQ.'PARA')THEN
          IF(NUMVAR.EQ.1)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)
  101       FORMAT('***** ERROR IN COEFFICIENT OF VARIATION TEST--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,282)
  282       FORMAT('      FOR THE ONE-SAMPLE TEST, IF ONLY ONE NAME ',   &
                   'IS GIVEN')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,284)
  284       FORMAT('      IT MUST BE A VARIABLE NAME RATHER THAN A ',   &
                   'PARAMETER NAME')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSEIF(NUMVAR.EQ.2)THEN
            NVAR=1
          ELSEIF(NUMVAR.EQ.3)THEN
            NVAR=2
          ENDIF
          GAMMA0=PVAR(NUMVAR)
        ELSE
          IH='GAMM'
          IH2='A0  '
          IHWUSE='P'
          MESSAG='YES'
          CALL CHECKN(IH,IH2,IHWUSE,   &
                      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
          IF(IERROR.EQ.'YES')THEN
            GO TO 9000
          ELSE
           GAMMA0=VALUE(ILOCP)
          ENDIF
          NVAR=NUMVAR
        ENDIF
      ELSE
        NVAR=NUMVAR
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  EXTRACT THE DATA.                               **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CVTE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASA2.EQ.'ONES')THEN
        ICOL=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,X1,Y1,NS1,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(NVAR.EQ.1)THEN
          DO 310 II=1,NS1
            X1(II)=1.0
  310     CONTINUE
        ENDIF
      ELSE
        IF(NVAR.EQ.2)THEN
          ICOL=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NVAR,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,Y2,Y1,NS1,NS2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          DO 321 II=1,NS1
            X1(II)=1.0
  321     CONTINUE
          DO 322 II=1,NS2
            X2(II)=1.0
  322     CONTINUE
        ELSEIF(NVAR.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,324)
  324     FORMAT('      FOR THE TWO-SAMPLE TEST, EITHER TWO OR FOUR ',   &
                 'VARAIBLES SHOULD BE GIVEN.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,326)
  326     FORMAT('      THREE VARIABLE WERE GIVEN HERE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(NVAR.EQ.4)THEN
          IF(NRIGHT(1).NE.NRIGHT(2))THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,332)
  332       FORMAT('      FOR THE TWO-SAMPLE TEST WITH FOUR VARIABLES ',   &
                   'CASE,')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,334)
  334       FORMAT('      VARIABLES ONE AND TWO MUST HAVE THE SAME ',   &
                  'LENGTH.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,336)IVARN1(1),IVARN2(1),NRIGHT(1)
  336       FORMAT('      VARIABLE ',2A4,' HAS ',I8,' ROWS.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,336)IVARN1(2),IVARN2(2),NRIGHT(2)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSEIF(NRIGHT(3).NE.NRIGHT(4))THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,332)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,338)
  338       FORMAT('      VARIABLES THREE AND FOUR MUST HAVE THE SAME ',   &
                  'LENGTH.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,336)IVARN1(3),IVARN2(3),NRIGHT(3)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,336)IVARN1(4),IVARN2(4),NRIGHT(4)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
          ICOL=1
          NVAR2=2
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NVAR2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,X1,Y1,NS1,NS1,NLOCA3,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
          ICOL=3
          NVAR2=2
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NVAR2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y2,X2,Y1,NS2,NS2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               ************************************************
!               **  STEP 4--                                  **
!               **  PERFORM THE COEFFICIENT OF VARIATION TEST **
!               ************************************************
!
      ISTEPN='4'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVTE')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,411)
  411   FORMAT('***** FROM DPCVTE, BEFORE CALL DPCVT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,412)NS1,NS2,MAXN,NVAR,GAMMA0
  412   FORMAT('NS1,NS2,MAXN,NVAR,GAMMA0 = ',4I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        IF(ICASA2.EQ.'ONES')THEN
          NTEMP=NS1
        ELSE
          NTEMP=MAX(NS1,NS2)
        ENDIF
        DO 415 II=1,NTEMP
          WRITE(ICOUT,416)II,Y1(II),X1(II),Y2(II),X2(II)
  416     FORMAT('I,Y(I),X(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
  415   CONTINUE
      ENDIF
!
      IVARID=IVARN1(1)
      IVARI2=IVARN2(1)
      IVARI3=IVARN1(2)
      IVARI4=IVARN2(2)
      IVARI5=IVARN1(3)
      IVARI6=IVARN2(3)
      IVARI7=IVARN1(4)
      IVARI8=IVARN2(4)
!
      CALL DPCVT2(Y1,X1,NS1,Y2,X2,NS2,GAMMA0,ICASA2,ICASA3,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  ICAPSW,ICAPTY,IFORSW,ICVTTE,   &
                  IVARID,IVARI2,IVARI3,IVARI4,   &
                  IVARI5,IVARI6,IVARI7,IVARI7,   &
                  STATVA,STATCD,STATN1,STATN2,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                  CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 6--                         **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='6'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'TTE2')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFLAGU='ON'
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPCVT5(STATVA,STATCD,PVAL,STANU1,STANU2,   &
                  CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                  CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                  IFLAGU,IFRST,ILAST,   &
                  IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVTE
      SUBROUTINE DPCVT2(Y1,X1,N1,Y2,X2,N2,GAMMA0,ICASA2,ICASA3,   &
                        TEMP1,TEMP2,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,ICVTTE,   &
                        IVARID,IVARI2,IVARI3,IVARI4,   &
                        IVARI5,IVARI6,IVARI7,IVARI8,   &
                        STATVA,STATCD,STATN1,STATN2,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                        CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT A COEFFICIENT OF VARIATION TEST
!              (1-SAMPLE OR 2-SAMPLE) BASED ON THE FORKMAN METHOD.
!
!              NOTE THAT THIS HANDLES THE GENERAL CASE WHERE WE HAVE
!              MULTIPLE GROUPS. THAT IS, FOR THE ONE SAMPLE CASE WE ARE
!              TESTING WHETHER THE COMMON COEFFICIENT OF VARIATION FOR
!              MULTIPLE GROUPS IS EQUAL TO A GIVEN VALUE.  FOR THE TWO
!              SAMPLE CASE, WE ARE TESTING WHETHER THE COMMON
!              COEFFICIENT OF VARIATION FOR ONE SET OF GROUPS OF DATA
!              IS EQUAL TO THE COMMON COEFFICIENT OF VARIATION FOR A
!              SECOND SET OF GROUPS OF DATA.
!
!              THE MORE COMMON CASE WHERE THERE IS A SINGLE GROUP IS A
!              SPECIAL CASE OF THE MORE GENERAL MULTIPLE GROUPS CASE.
!
!     EXAMPLE--COEFFICIENT OF VARIATION TEST Y X GAMMA0
!              COEFFICIENT OF VARIATION TWO SAMPLE TEST Y1 Y2
!              COEFFICIENT OF VARIATION TWO SAMPLE TEST Y1 X1 Y2 X2
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", COMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, Vol. 38, No. 2, pp. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 IVARI3
      CHARACTER*4 IVARI4
      CHARACTER*4 IVARI5
      CHARACTER*4 IVARI6
      CHARACTER*4 IVARI7
      CHARACTER*4 IVARI8
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 ICVTTE
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASA5
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
      INTEGER ITEMP1(1)
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=40)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='T2  '
      IERROR='NO'
      IWRITE='OFF'
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCVT2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASA2
   52   FORMAT('IBUGA3,ISUBRO = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N1,N2,NUMDIG,MAXNXT,GAMMA0
   55   FORMAT('N1,N2,NUMDIG,MAXNXT,GAMMA0 = ',4I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        IF(N1.GE.1)THEN
          DO 56 I=1,N1
            WRITE(ICOUT,57)I,X1(I),Y1(I)
   57       FORMAT('I,Y1(I),X1(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   56     CONTINUE
        ENDIF
        IF(N2.GE.1 .AND. ICASA2.EQ.'TWOS')THEN
          DO 66 I=1,N2
            WRITE(ICOUT,67)I,X2(I),Y2(I)
   67       FORMAT('I,X2(I),Y2(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','WRIT')
   66     CONTINUE
        ENDIF
      ENDIF
!
!               ************************************
!               **   STEP 1--                     **
!               **   BRANCH DEPENDING ON WHETHER  **
!               **   1-SAMPLE TEST OR             **
!               **   2-SAMPLE TEST.               **
!               ************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASA2.EQ.'ONES')THEN
        GO TO 2100
      ELSEIF(ICASA2.EQ.'TWOS')THEN
        IF(ICVTTE.EQ.'MILL')THEN
          GO TO 4100
        ELSE
          GO TO 3100
        ENDIF
      ELSE
        GO TO 9000
      ENDIF
!
!               ******************************
!               **  STEP 21--               **
!               **  CARRY OUT CALCULATIONS  **
!               **  FOR A 1-SAMPLE TEST     **
!               ******************************
!
 2100 CONTINUE
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASA5='RAW'
      CALL DPCVT3(Y1,X1,ITEMP1,N1,GAMMA0,IWRITE,ICASA5,   &
                  TEMP1,TEMP2,   &
                  NDIST,NGROUP,YMEANT,YSDT,YCVT,   &
                  STATVA,STATCD,STATNU,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IDF=INT(STATNU+0.5)
      CALL CHSPPF(.0005,IDF,CTL999)
      CALL CHSPPF(.005,IDF,CUTL99)
      CALL CHSPPF(.025,IDF,CUTL95)
      CALL CHSPPF(.05,IDF,CUTL90)
      CALL CHSPPF(.1,IDF,CUTL80)
      CALL CHSPPF(.25,IDF,CUTL50)
      CALL CHSPPF(.75,IDF,CUTU50)
      CALL CHSPPF(.90,IDF,CUTU80)
      CALL CHSPPF(.95,IDF,CUTU90)
      CALL CHSPPF(.975,IDF,CUTU95)
      CALL CHSPPF(.995,IDF,CUTU99)
      CALL CHSPPF(.9995,IDF,CTU999)
!
!               ******************************
!               **   STEP 22--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR A 1-SAMPLE TEST    **
!               ******************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE='Forkman One Sample Coefficient of Variation Test'
      NCTITL=48
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable: '
      WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=27
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      IF(NDIST.GT.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARI3(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI4(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Coefficient of Variation Equal'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=GAMMA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      IF(ICASA3.EQ.'TWOT')THEN
        ITEXT(ICNT)='Ha: Coefficient of Variation Not Equal'
        NCTEXT(ICNT)=38
      ELSEIF(ICASA3.EQ.'UPPE')THEN
        ITEXT(ICNT)='Ha: Coefficient of Variation >'
        NCTEXT(ICNT)=30
      ELSEIF(ICASA3.EQ.'LOWE')THEN
        ITEXT(ICNT)='Ha: Coefficient of Variation <'
        NCTEXT(ICNT)=30
      ENDIF
      AVALUE(ICNT)=GAMMA0
      IDIGIT(ICNT)=NUMDIG
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(NDIST)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups Included in Test:'
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=REAL(NGROUP)
      IDIGIT(ICNT)=0
      IF(NDIST.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Mean:'
        NCTEXT(ICNT)=12
        AVALUE(ICNT)=YMEANT
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Standard Deviation:'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=YSDT
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Coefficient of Variation:'
        NCTEXT(ICNT)=32
        AVALUE(ICNT)=YCVT
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Common Coefficient of Variation:'
        NCTEXT(ICNT)=39
        AVALUE(ICNT)=YCVT
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Gamma0:'
      NCTEXT(ICNT)=7
      AVALUE(ICNT)=GAMMA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Degrees of Freedom:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=INT(STATNU+0.1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 2110 I=1,NUMROW
        NTOT(I)=15
 2110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='21A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='21B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Two-Tailed Test'
      NCTITL=15
      ITITL9='H0: Gamma = Gamma0; Ha: Gamma <> Gamma0'
      NCTIT9=39
!
      DO 2130 J=1,5
        DO 2140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 2140   CONTINUE
 2130 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value'
      NCTIT2(3,3)=5
!
      ITITL2(1,4)='Upper'
      NCTIT2(1,4)=5
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value'
      NCTIT2(3,4)=5
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 2150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 2150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IWHTML(5)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 2160 J=1,NUMALP
!
        ALPHAT=(1.0 - ALPHA(J))/2.0
        CALL CHSPPF(ALPHAT,IDF,ALOWCV)
        ALPHT2=1.0 - ALPHAT
        CALL CHSPPF(ALPHT2,IDF,AUPPCV)
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
!
        AMAT(J,2)=STATVA
        AMAT(J,3)=ALOWCV
        AMAT(J,4)=AUPPCV
        IVALUE(J,5)(1:6)='REJECT'
        IF(STATVA.GE.AMAT(J,3).AND.STATVA.LE.AMAT(J,4))THEN
          IVALUE(J,5)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,5)=6
!
 2160 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA3.EQ.'TWOT')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASA3.EQ.'TWOT')GO TO 9000
!
      ITITLE='Lower One-Tailed Test'
      NCTITL=21
      ITITL9='H0: Gamma = Gamma0; Ha: Gamma < Gamma0'
      NCTIT9=38
!
      ITITL2(1,3)=' '
      NCTIT2(1,3)=0
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (<)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 2250 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        IF(I.EQ.1 .OR. I.EQ.4)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 2250 CONTINUE
!
      IDF=INT(STATNU+0.5)
      DO 2260 J=1,NUMALP
        ALPHAT=1.0 - ALPHA(J)
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='REJECT'
        IF(STATVA.GE.AMAT(J,3))THEN
          IVALUE(J,4)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,4)=6
 2260 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA3.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASA3.EQ.'LOWE')GO TO 9000
!
      ITITLE='Upper One-Tailed Test'
      NCTITL=21
      ITITL9='H0: Gamma = Gamma0; Ha: Gamma > Gamma0'
      NCTIT9=38
!
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (>)'
      NCTIT2(3,3)=9
!
      NMAX=0
      NUMCOL=4
      DO 2350 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
 2350 CONTINUE
!
      IDF=INT(STATNU+0.5)
      DO 2360 J=1,NUMALP
        ALPHAT=ALPHA(J)
        CALL CHSPPF(ALPHAT,IDF,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='REJECT'
        IF(STATVA.LE.AMAT(J,3))THEN
          IVALUE(J,4)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,4)=6
 2360 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
      GO TO 9000
!
!               ****************************************
!               **  STEP 31--                         **
!               **  CARRY OUT CALCULATIONS            **
!               **  FOR A 2-SAMPLE TEST               **
!               **  (FORKMAN TEST)                    **
!               ****************************************
!
 3100 CONTINUE
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCVT4(Y1,X1,N1,Y2,X2,N2,IWRITE,   &
                  TEMP1,TEMP2,NGROU1,NGROU2,   &
                  Y1MEAN,Y1SD,Y1CV,Y2MEAN,Y2SD,Y2CV,   &
                  STATVA,STATCD,STATN1,STATN2,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************
!               **   STEP 32--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR A 2-SAMPLE TEST    **
!               ******************************
!
      ISTEPN='32'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=   &
        'Forkman Two Sample Test for Equal Coefficient of Variations'
      NCTITL=59
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable:  '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(NGROU1.GT.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='First Group-ID Variable:  '
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
        WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI4(1:4)
        NCTEXT(ICNT)=34
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      IF(NGROU1.GT.1)THEN
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI5(1:4)
        WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI6(1:4)
      ELSE
        WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
        WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI4(1:4)
      ENDIF
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(NGROU2.GT.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Second Group-ID Variable:  '
        IF(NGROU1.GT.1)THEN
          WRITE(ITEXT(ICNT)(28:31),'(A4)')IVARI7(1:4)
          WRITE(ITEXT(ICNT)(32:35),'(A4)')IVARI8(1:4)
        ELSE
          WRITE(ITEXT(ICNT)(28:31),'(A4)')IVARI5(1:4)
          WRITE(ITEXT(ICNT)(32:35),'(A4)')IVARI6(1:4)
        ENDIF
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Population Coefficients of Variation'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='    Are Equal (gamma1 = gamma2)'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      IF(ICASA3.EQ.'TWOT')THEN
        ITEXT(ICNT)='Ha: gamma1 <> gamma2'
        NCTEXT(ICNT)=20
      ELSEIF(ICASA3.EQ.'UPPE')THEN
        ITEXT(ICNT)='Ha: gamma1 > gamma2'
        NCTEXT(ICNT)=19
      ELSEIF(ICASA3.EQ.'LOWE')THEN
        ITEXT(ICNT)='Ha: gamma1 < gamma2'
        NCTEXT(ICNT)=19
      ENDIF
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample One Summary Statistics:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups Included:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=REAL(NGROU1)
      IDIGIT(ICNT)=0
      IF(NGROU1.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Mean:'
        NCTEXT(ICNT)=12
        AVALUE(ICNT)=Y1MEAN
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Standard Deviation:'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=Y1SD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Coefficient of Variation:'
        NCTEXT(ICNT)=32
        AVALUE(ICNT)=Y1CV
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Common Coefficient of Variation:'
        NCTEXT(ICNT)=39
        AVALUE(ICNT)=Y1CV
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Two Summary Statistics:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Included Groups:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=REAL(NGROU2)
      IDIGIT(ICNT)=0
      IF(NGROU2.EQ.1)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Mean:'
        NCTEXT(ICNT)=12
        AVALUE(ICNT)=Y2MEAN
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Standard Deviation:'
        NCTEXT(ICNT)=26
        AVALUE(ICNT)=Y2SD
        IDIGIT(ICNT)=NUMDIG
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Coefficient of Variation:'
        NCTEXT(ICNT)=32
        AVALUE(ICNT)=Y2CV
        IDIGIT(ICNT)=NUMDIG
      ELSE
        ICNT=ICNT+1
        ITEXT(ICNT)='Sample Common Coefficient of Variation:'
        NCTEXT(ICNT)=39
        AVALUE(ICNT)=Y2CV
        IDIGIT(ICNT)=NUMDIG
      ENDIF
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Forkman Test Statistic Value:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Degrees of Freedom 1:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=STATN1
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Degrees of Freedom 2:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=STATN2
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 3110 I=1,NUMROW
        NTOT(I)=15
 3110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='31A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='31B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDF1=INT(STATN1+0.5)
      IDF2=INT(STATN2+0.5)
!
      CALL FPPF(.0005,IDF1,IDF2,CTL999)
      CALL FPPF(.005,IDF1,IDF2,CUTL99)
      CALL FPPF(.025,IDF1,IDF2,CUTL95)
      CALL FPPF(.05,IDF1,IDF2,CUTL90)
      CALL FPPF(.1,IDF1,IDF2,CUTL80)
      CALL FPPF(.25,IDF1,IDF2,CUTL50)
      CALL FPPF(.75,IDF1,IDF2,CUTU50)
      CALL FPPF(.90,IDF1,IDF2,CUTU80)
      CALL FPPF(.95,IDF1,IDF2,CUTU90)
      CALL FPPF(.975,IDF1,IDF2,CUTU95)
      CALL FPPF(.995,IDF1,IDF2,CUTU99)
      CALL FPPF(.9995,IDF1,IDF2,CTU999)
!
      ITITL9='H0: gamma1 = gamma2; Ha: gamma1 <> gamma2'
      NCTIT9=41
!
      DO 3130 J=1,5
        DO 3140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 3140   CONTINUE
 3130 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value'
      NCTIT2(3,3)=5
!
      ITITL2(1,4)='Upper'
      NCTIT2(1,4)=5
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value'
      NCTIT2(3,4)=5
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 3150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 3150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IWHTML(5)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 3160 J=1,NUMALP
!
        ALPHAT=(1.0 - ALPHA(J))/2.0
        CALL FPPF(ALPHAT,IDF1,IDF2,ALOWCV)
        ALPHT2=1.0 - ALPHAT
        CALL FPPF(ALPHT2,IDF1,IDF2,AUPPCV)
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
!
        AMAT(J,2)=STATVA
        AMAT(J,3)=ALOWCV
        AMAT(J,4)=AUPPCV
        IVALUE(J,5)(1:6)='REJECT'
        IF(STATVA.GE.AMAT(J,3).AND.STATVA.LE.AMAT(J,4))THEN
          IVALUE(J,5)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,5)=6
!
 3160 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA3.NE.'LOWE' .AND. ICASA3.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASA3.EQ.'TWOT')GO TO 3199
!
      IF(ICASA3.EQ.'LOWE')THEN
        ITITLE='Lower One-Tailed Test'
        NCTITL=21
        ITITL9='H0: gamma1 = gamma2; Ha: gamma1 < gamma2'
        NCTIT9=40
        ITITL2(1,3)=' '
        NCTIT2(1,3)=0
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (<)'
        NCTIT2(3,3)=9
      ELSEIF(ICASA3.EQ.'UPPE')THEN
        ITITLE='Upper One-Tailed Test'
        NCTITL=21
        ITITL9='H0: gamma1 = gamma2; Ha: gamma1 > gamma2'
        NCTIT9=40
        NCTIT2(1,3)=0
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (>)'
        NCTIT2(3,3)=9
      ENDIF
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 3250 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        IF(I.EQ.1 .OR. I.EQ.4)ITYPCO(I)='ALPH'
 3250 CONTINUE
!
      DO 3260 J=1,NUMALP
        IF(ICASA3.EQ.'UPPE')THEN
          ALPHAT=ALPHA(J)
        ELSE
          ALPHAT=1.0 - ALPHA(J)
        ENDIF
        CALL FPPF(ALPHAT,IDF1,IDF2,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='REJECT'
        IF(ICASA3.EQ.'UPPE')THEN
          IF(STATVA.GE.AMAT(J,3))THEN
            IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
        ELSE
          IF(STATVA.LE.AMAT(J,3))THEN
            IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
        ENDIF
        NCVALU(J,4)=6
 3260 CONTINUE
!
        ICNT=NUMALP
        NUMLIN=3
        NUMCOL=4
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
!
 3199 CONTINUE
      GO TO 9000
!
!               ****************************************
!               **  STEP 41--                         **
!               **  CARRY OUT CALCULATIONS            **
!               **  FOR A 2-SAMPLE TEST               **
!               **  (MILLER TEST)                     **
!               ****************************************
!
 4100 CONTINUE
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCVT6(Y1,N1,Y2,N2,IWRITE,   &
                  Y1MEAN,Y1SD,Y1CV,Y2MEAN,Y2SD,Y2CV,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************
!               **   STEP 42--              **
!               **   WRITE OUT EVERYTHING   **
!               **   FOR A 2-SAMPLE TEST    **
!               ******************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=   &
        'Miller Two Sample Test for Equal Coefficient of Variations'
      NCTITL=58
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='First Response Variable:  '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Second Response Variable: '
      WRITE(ITEXT(ICNT)(27:30),'(A4)')IVARI3(1:4)
      WRITE(ITEXT(ICNT)(31:34),'(A4)')IVARI4(1:4)
      NCTEXT(ICNT)=34
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Population Coefficients of Variation'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='    Are Equal (gamma1 = gamma2)'
      NCTEXT(ICNT)=41
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      IF(ICASA3.EQ.'TWOT')THEN
        ITEXT(ICNT)='Ha: gamma1 <> gamma2'
        NCTEXT(ICNT)=20
      ELSEIF(ICASA3.EQ.'UPPE')THEN
        ITEXT(ICNT)='Ha: gamma1 > gamma2'
        NCTEXT(ICNT)=19
      ELSEIF(ICASA3.EQ.'LOWE')THEN
        ITEXT(ICNT)='Ha: gamma1 < gamma2'
        NCTEXT(ICNT)=19
      ENDIF
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample One Summary Statistics:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N1)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=Y1MEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=Y1SD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Coefficient of Variation:'
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=Y1CV
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Two Summary Statistics:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N2)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=Y2MEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=Y2SD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Coefficient of Variation:'
      NCTEXT(ICNT)=42
      AVALUE(ICNT)=Y2CV
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Miller Test Statistic Value:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value:'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4110 I=1,NUMROW
        NTOT(I)=15
 4110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='41A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='41B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL NORPPF(.0005,CTL999)
      CALL NORPPF(.005,CUTL99)
      CALL NORPPF(.025,CUTL95)
      CALL NORPPF(.05,CUTL90)
      CALL NORPPF(.1,CUTL80)
      CALL NORPPF(.25,CUTL50)
      CALL NORPPF(.75,CUTU50)
      CALL NORPPF(.90,CUTU80)
      CALL NORPPF(.95,CUTU90)
      CALL NORPPF(.975,CUTU95)
      CALL NORPPF(.995,CUTU99)
      CALL NORPPF(.9995,CTU999)
!
      ITITL9='H0: gamma1 = gamma2; Ha: gamma1 <> gamma2'
      NCTIT9=41
!
      DO 4130 J=1,5
        DO 4140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 4140   CONTINUE
 4130 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value'
      NCTIT2(3,3)=5
!
      ITITL2(1,4)='Upper'
      NCTIT2(1,4)=5
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value'
      NCTIT2(3,4)=5
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 4150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=NUMDIG
        IF(I.EQ.1 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 4150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(3)=175
      IWHTML(4)=175
      IWHTML(5)=175
      IINC=1800
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 4160 J=1,NUMALP
!
        ALPHAT=(1.0 - ALPHA(J))/2.0
        CALL NORPPF(ALPHAT,ALOWCV)
        ALPHT2=1.0 - ALPHAT
        CALL NORPPF(ALPHT2,AUPPCV)
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
!
        AMAT(J,2)=STATVA
        AMAT(J,3)=ALOWCV
        AMAT(J,4)=AUPPCV
        IVALUE(J,5)(1:6)='REJECT'
        IF(STATVA.GE.AMAT(J,3).AND.STATVA.LE.AMAT(J,4))THEN
          IVALUE(J,5)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,5)=6
!
 4160 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      NUMCOL=5
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASA3.NE.'LOWE' .AND. ICASA3.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASA3.EQ.'TWOT')GO TO 4199
!
      IF(ICASA3.EQ.'LOWE')THEN
        ITITLE='Lower One-Tailed Test'
        NCTITL=21
        ITITL9='H0: gamma1 = gamma2; Ha: gamma1 < gamma2'
        NCTIT9=40
        ITITL2(1,3)=' '
        NCTIT2(1,3)=0
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (<)'
        NCTIT2(3,3)=9
      ELSEIF(ICASA3.EQ.'UPPE')THEN
        ITITLE='Upper One-Tailed Test'
        NCTITL=21
        ITITL9='H0: gamma1 = gamma2; Ha: gamma1 > gamma2'
        NCTIT9=40
        NCTIT2(1,3)=0
        ITITL2(2,3)='Critical'
        NCTIT2(2,3)=8
        ITITL2(3,3)='Value (>)'
        NCTIT2(3,3)=9
      ENDIF
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
!
      NMAX=0
      NUMCOL=4
      DO 4250 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        IF(I.EQ.1 .OR. I.EQ.4)ITYPCO(I)='ALPH'
 4250 CONTINUE
!
      DO 4260 J=1,NUMALP
        IF(ICASA3.EQ.'UPPE')THEN
          ALPHAT=ALPHA(J)
        ELSE
          ALPHAT=1.0 - ALPHA(J)
        ENDIF
        CALL NORPPF(ALPHAT,ATEMP)
        AMAT(J,3)=ATEMP
        IVALUE(J,4)(1:6)='REJECT'
        IF(ICASA3.EQ.'UPPE')THEN
          IF(STATVA.GE.AMAT(J,3))THEN
            IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
        ELSE
          IF(STATVA.LE.AMAT(J,3))THEN
            IVALUE(J,4)(1:6)='ACCEPT'
          ENDIF
        ENDIF
        NCVALU(J,4)=6
 4260 CONTINUE
!
        ICNT=NUMALP
        NUMLIN=3
        NUMCOL=4
        IFRST=.TRUE.
        ILAST=.TRUE.
        IFLAGS=.TRUE.
        IFLAGE=.TRUE.
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
!
 4199 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVT2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)STATVA,STATCD,PVAL2T,PVALLT,PVALUT
 9013   FORMAT('STATVA,STATCD,PVAL2T,PVALLT,PVALUT = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVT2
      SUBROUTINE DPCVT3(Y,X,NI,N,GAMMA0,IWRITE,ICASA3,   &
                        TEMP1,XIDTEM,   &
                        NDIST,NGROUP,YMEAN,YSD,YCV,   &
                        STATVA,STATCD,STATNU,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE FOLLOWING TESTS FOR A
!              COMMON COEFFICIENT OF VARIATION:
!
!                 H0: GAMMA = GAMMA0
!
!              THE TEST STATISTIC IS
!
!                 SUM[i=1 to k][(n(i) - 1)*u(i)/THETA0]
!
!              WHERE
!
!                 k     = NUMBER OF GROUPS
!                 u(i)  = c(i)**2/[1 + c(i)**2*(n(i) - 1)/n(i)]
!                 c(i)  = COEFFICIENT OF VARIATION FOR i-TH GROUP
!                 n(i)  = SAMPLE SIZE FOR i-THE GROUP
!                 THETA0 = GAMMA0**2/(1 + GAMMA0**2)
!
!              WHERE GAMMA IS THE COMMON COEFFICIENT OF VARIATION
!              AND GAMMA0 IS THE HYPOTHESIZED VALUE.
!
!              THIS STATISTIC IS COMPARED TO A CHI-SQUARE WITH
!              SUM[i=1 to k][n(i)- 1] DEGREES OF FREEDOM.
!
!              FOR THE RAW DATA CASE, Y IS THE RESPONSE VARIABLE.  FOR
!              THE SUMMARY DATA CASE, Y IS THE MEAN VALUES, X IS THE
!              STANDARD DEVIATIONS, AND NI IS THE SAMPLE SIZES.
!
!              THE (BIASED) COMMON COEFFICIENT OF VARIATION IS:
!
!                 CVCOMM = SQRT[SUM{I=1 to k}{(N(i)-1)*C(i)**2}/
!                               SUM{i=1 to k}{N(i)-1)}]
!
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                RESPONSE VALUES.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP-ID VALUES.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --GAMMA0 = THE SINGLE PRECISION VALUE FOR WHICH
!                                THE TEST IS PERFORMED (I.E.,
!                                H0: GAMMA = GAMMA0).
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!                     --STATNU = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED DEGREES OF FREDDOM
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             TEST STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", COMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, Vol. 38, No. 2, pp. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017.06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASA3
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION XIDTEM(*)
!
      INTEGER NI(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='T3  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=-99.0
      STATCD=-99.0
      STATNU=-99.0
      PVAL2T=-99.0
      PVALLT=-99.0
      PVALUT=-99.0
      YMEAN=-99.0
      YSD=-99.0
      YCV=-99.0
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=0
      IFLAG3=0
      IFLAG4=0
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      WRITE(IOUNI1,41)
   41 FORMAT(4X,'N(I)',8X,'MEAN(I)',10X,'SD(I)',10X,'CV(I)')
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASA3,N
   52   FORMAT('IBUGA3,ISUBRO,ICASA3,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COMMON COEFFICIENT OF VARIATION ',   &
               'ONE SAMPLE TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS  IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(GAMMA0.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)GAMMA0
  107   FORMAT('      THE HYPOTHESIZED VALUE, (',G15.7,') IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  DETERMINE THE NUMBER OF GROUPS        **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASA3.EQ.'RAW')THEN
        CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT3')THEN
          DO 201 I=1,NDIST
            WRITE(ICOUT,203)I,XIDTEM(I)
  203       FORMAT('I,XIDTEM(I) = ',I8,G15.7)
            CALL DPWRST('XXX','WRIT')
  201     CONTINUE
        ENDIF
!
!       NOTE: ALLOW SINGLE GROUP
!
!CCCC   IF(NDIST.LT.2)THEN
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,101)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,201)
!C201     FORMAT('      THE NUMBER OF GROUPS  IS LESS THAN TWO.')
!CCCC     IERROR='YES'
!CCCC     GO TO 9000
!CCCC   ENDIF
      ELSE
        NDIST=N
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  COMPUTE THE GROUP STATISTICS          **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      AN=N
      THETA0=GAMMA0**2/(1.0 + GAMMA0**2)
      NGROUP=0
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 210 II=1,NDIST
        K=0
!
        YMEANT=CPUMIN
        YSDT=CPUMIN
        CT=CPUMIN
!
        IF(ICASA3.EQ.'SUMM')THEN
          YMEANT=Y(II)
          YSDT=X(II)
          NT=NI(II)
        ELSE
          HOLD=XIDTEM(II)
          DO 220 JJ=1,N
            IF(X(JJ).EQ.HOLD)THEN
              K=K+1
              TEMP1(K)=Y(JJ)
            ENDIF
  220     CONTINUE
          NT=K
!
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT3')THEN
            WRITE(ICOUT,211)II,HOLD,NT
  211       FORMAT('GROUP ',I8,' (',G15.7,') HAS ',I8,' OBSERVATIONS.')
            CALL DPWRST('XXX','WRIT')
          ENDIF
!
          IF(NT.GT.1)THEN
            CALL MEAN(TEMP1,NT,IWRITE,YMEANT,IBUGA3,IERROR)
            CALL SD(TEMP1,NT,IWRITE,YSDT,IBUGA3,IERROR)
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,203)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,207)II
  207       FORMAT('      GROUP ',I5,' HAS FEWER THAN TWO ',   &
                   'OBSERVATIONS.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,225)
            CALL DPWRST('XXX','WRIT')
            GO TO 219
          ENDIF
        ENDIF
!
!       CHECK FOR:
!
!           1) POSITIVE MEAN
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE MEAN)
!           2) POSITIVE SD
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE SD)
!           3) COEFFICIENT OF VARIATION < 0.33
!              (THIS WILL BE WARNING, BUT INCLUDE IN THE COMPUTATIONS)
!
        IF(YMEANT.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,223)
  223     FORMAT('***** WARNING COMMON COEFFICIENT OF VARIATION ',   &
                 'ONE SAMPLE TEST--')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,224)II
  224     FORMAT('      GROUP ',I5,' HAS A NON-POSITIVE MEAN.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,225)
  225     FORMAT('      IT WILL BE OMITTED FROM THE COMPUTATION.')
          CALL DPWRST('XXX','WRIT')
          GO TO 219
        ELSEIF(YSDT.LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,223)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,226)II
  226     FORMAT('      GROUP ',I5,' HAS A NON-POSITIVE STANDARD ',   &
                 'DEVIATION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,225)
          CALL DPWRST('XXX','WRIT')
          GO TO 219
        ENDIF
!
        NGROUP=NGROUP+1
        CT=YSDT/YMEANT
        ANT=REAL(NT)
        ANTM1=ANT - 1.0
        UT=CT**2/(1.0 + (CT**2*ANTM1/ANT))
        DSUM1=DSUM1 + DBLE(ANTM1)
        DSUM2=DSUM2 + DBLE(ANTM1*UT)
        DSUM3=DSUM3 + DBLE(ANTM1*CT**2)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVT3')THEN
          WRITE(ICOUT,233)NGROUP,YMEANT,YSDT,CT,UT
  233     FORMAT('NGROUP,YMEANT,YSDT,CT,UT = ',I8,4G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
  219   CONTINUE
        WRITE(IOUNI1,'(I8,3E15.7)')NT,YMEANT,YSDT,CT
        IF(NDIST.EQ.1 .AND. II.EQ.1)THEN
          YMEAN=YMEANT
          YSD=YSDT
          YCV=CT
        ENDIF
!
  210 CONTINUE
!
!CCCC IF(NGROUP.LT.2)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,101)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,281)
!C281   FORMAT('      AFTER REMOVING GROUPS, LESS THAN TWO GROUPS ',
!CCCC1         'REMAIN.')
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
!CCCC ENDIF
!
      DTERM1=DSUM2/DBLE(THETA0)
      DTERM2=DSQRT(DSUM3/DSUM1)
      YCV=REAL(DTERM2)
      STATVA=REAL(DTERM1)
      IDF=INT(DSUM1+0.5D0)
      STATNU=REAL(IDF)
      CALL CHSCDF(STATVA,IDF,STATCD)
!
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(YCV.LE.GAMMA0)THEN
        PVAL2T=2.0*STATCD
      ELSE
        PVAL2T=2.0*(1.0 - STATCD)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVT3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,NDIST,NGROUP
 9012   FORMAT('IBUGA3,IERROR,NDIST,NGROUP = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATNU,STATCD,YCV
 9015   FORMAT('STATVA,STATNU,STATCD,YCV = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)DSUM1,DSUM2,DSUM3,THETA0
 9016   FORMAT('DSUM1,DSUM2,DSUM3,THETA0 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVT3
      SUBROUTINE DPCVT4(Y1,X1,N1,Y2,X2,N2,IWRITE,   &
                        TEMP1,XIDTEM,NGROU1,NGROU2,   &
                        YMEAN1,YSD1,CV1,YMEAN2,YSD2,CV2,   &
                        STATVA,STATCD,STATN1,STATN2,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES AN APPROXIMATE F TEST FOR THE
!              EQUALITY OF THE COEFFIIENTS OF VARIATION FROM TWO
!              SAMPLES.  NOTE THAT THE MOST GENERAL FORM OF THIS TEST
!              CAN BE USED FOR THE CASE WHERE EACH SAMPLE IS COMPRISED
!              OF MULTIPLE GROUPS (I.E., WE ARE COMPARING THE COMMON
!              COEFFICIENT OF VARIATION FOR SAMPLE 1 WITH K1 GROUPS WITH
!              THE COMMON COEFFICIENT OF VARIATION FOR SAMPLE 2 WITH K2
!              GROUPS.
!
!                 H0: GAMMA1 = GAMMA2
!
!              THE TEST STATISTIC IS
!
!                 F = NUM/DENOM
!
!                 NUM   = SUM[i=1 to k1][(n1(i) - 1)*u1(i)]/
!                         SUM[i=1 to k1][n1(i) - 1]
!                 DENOM = SUM[i=1 to k2][(n2(i) - 1)*u2(i)]/
!                         SUM[i=1 to k2][n2(i) - 1]
!
!              WHEN k1 = k2 = 1, THE TEST SIMPLIFIES TO
!
!                  F = [c1**2/(1 + c1**2*(n1-1)/n1)]/
!                      [c2**2/(1 + c2**2*(n2-1)/n2)]
!              WHERE
!
!                 k1     = NUMBER OF GROUPS FOR SAMPLE ONE
!                 k2     = NUMBER OF GROUPS FOR SAMPLE TWO
!                 ur(i)  = cr(i)**2/[1 + cr(i)**2*(nr(i) - 1)/nr(i)]
!                 cr(i)  = COEFFICIENT OF VARIATION FOR i-TH GROUP AND
!                          r-TH SAMPLE
!                 nr(i)  = SAMPLE SIZE FOR i-THE GROUP AND r-TH SAMPLE
!                 r      = 1, 2 (I.E., TWO SAMPLES)
!
!              THIS STATISTIC IS COMPARED TO THE F DISTRIBUTION WITH
!              SUM[i=1 to k1][n1(i)- 1] AND SUM[i=1 to k2][n2(i) - 1]
!              DEGREES OF FREEDOM.
!
!              CURRENTLY, ONLY THE RAW DATA CASE IS SUPPORTED.  ALSO,
!              THE CASE WHERE THERE IS ONE GROUP FOR EACH SAMPLE IS THE
!              MOST COMMONLY USED IN PRACTICE.
!
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                RESPONSE VALUES FOR SAMPLE ONE.
!                     --X1     = THE SINGLE PRECISION VECTOR OF
!                                GROUP-ID VALUES FOR SAMPLE ONE.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                FOR SAMPLE ONE.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                RESPONSE VALUES FOR SAMPLE TWO.
!                     --X2     = THE SINGLE PRECISION VECTOR OF
!                                GROUP-ID VALUES FOR SAMPLE TWO.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                FOR SAMPLE TWO.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!                     --STATN1 = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED DEGREES OF FREDDOM
!                     --STATN2 = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED DEGREES OF FREDDOM
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             TEST STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", COMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, VOL. 38, NO. 2, PP. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017.06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DTERM1
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION X1(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION XIDTEM(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='T4  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=-99.0
      STATCD=-99.0
      STATNU=-99.0
      PVAL2T=-99.0
      PVALLT=-99.0
      PVALUT=-99.0
      YMEAN1=-99.0
      YSD1=-99.0
      CV1=-99.0
      YMEAN2=-99.0
      YSD2=-99.0
      CV2=-99.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT4')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVT4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I),X1(I)
   56     FORMAT('I,Y1(I),X1(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I),X2(I)
   66     FORMAT('I,Y2(I),X2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COMMON COEFFICIENT OF VARIANCE ',   &
               'TWO SAMPLE TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR SAMPLE ONE ',   &
                'IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N1
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR SAMPLE TWO ',   &
                'IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  DETERMINE THE NUMBER OF GROUPS        **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(X1,N1,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ********************************************
!               **  STEP 2--                              **
!               **  COMPUTE THE NUMERATOR OF THE F TEST   **
!               ********************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NGROUP=0
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 210 II=1,NDIST
        K=0
!
        YMEANT=CPUMIN
        YSDT=CPUMIN
        CT=CPUMIN
!
        HOLD=XIDTEM(II)
        DO 220 JJ=1,N1
          IF(X1(JJ).EQ.HOLD)THEN
            K=K+1
            TEMP1(K)=Y1(JJ)
          ENDIF
  220   CONTINUE
        NT=K
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
          WRITE(ICOUT,211)II,NT
  211     FORMAT('GROUP ',I8,' HAS ',I8,' OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(NT.GT.1)THEN
          CALL MEAN(TEMP1,NT,IWRITE,YMEANT,IBUGA3,IERROR)
          CALL SD(TEMP1,NT,IWRITE,YSDT,IBUGA3,IERROR)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,207)II
  207     FORMAT('      GROUP ',I5,' HAS FEWER THAN TWO ',   &
                 'OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
          CALL DPWRST('XXX','WRIT')
          GO TO 219
        ENDIF
!
!       CHECK FOR:
!
!           1) POSITIVE MEAN
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE MEAN)
!           2) POSITIVE SD
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE SD)
!           3) COEFFICIENT OF VARIATION < 0.33
!              (THIS WILL BE WARNING, BUT INCLUDE IN THE COMPUTATIONS)
!
        IF(YMEANT.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
  203     FORMAT('***** WARNING COEFFICIENT OF VARIATION ',   &
                 'TWO SAMPLE TEST--')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,204)II
  204     FORMAT('      GROUP ',I5,' OF SAMPLE ONE HAS A NON-POSITIVE ',   &
                 'MEAN.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
  205     FORMAT('      IT WILL BE OMITTED FROM THE COMPUTATION.')
          CALL DPWRST('XXX','WRIT')
          GO TO 219
        ELSEIF(YSDT.LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,206)II
  206     FORMAT('      GROUP ',I5,' OF SAMPLE ONE HAS A NON-POSITIVE ',   &
                 'STANDARD DEVIATION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
          CALL DPWRST('XXX','WRIT')
          GO TO 219
        ENDIF
!
        NGROUP=NGROUP+1
        CT=YSDT/YMEANT
        IF(NGROUP.EQ.1)THEN
          YMEAN1=YMEANT
          YSD1=YSDT
          CV1=CT
        ENDIF
        ANT=REAL(NT)
        ANTM1=ANT - 1.0
        UT=CT**2/(1.0 + (CT**2*ANTM1/ANT))
        DSUM1=DSUM1 + DBLE(ANTM1)
        DSUM2=DSUM2 + DBLE(ANTM1*UT)
        DSUM3=DSUM3 + DBLE(ANTM1)*DBLE(CT**2)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
          WRITE(ICOUT,213)NGROUP,YMEANT,YSDT,CT,UT
  213     FORMAT('NGROUP,YMEANT,YSDT,CT,UT = ',I8,4G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
  219   CONTINUE
  210 CONTINUE
!
      IF(NGROUP.GT.1)THEN
        DTERM1=DSQRT(DSUM3/DSUM1)
        CV1=REAL(DTERM1)
      ENDIF
!
      IF(NGROUP.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,281)
  281   FORMAT('      AFTER REMOVING GROUPS, LESS THAN ONE GROUP ',   &
               'REMAIN FOR SAMPLE ONE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NGROU1=NGROUP
      IDF1=INT(DSUM1+0.5D0)
      DNUM=DSUM2/DSUM1
!
!               **********************************************
!               **  STEP 3--                                **
!               **  COMPUTE THE DENOMINATOR OF THE F TEST   **
!               **********************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(X2,N2,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      NGROUP=0
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 310 II=1,NDIST
        K=0
!
        YMEANT=CPUMIN
        YSDT=CPUMIN
        CT=CPUMIN
!
        HOLD=XIDTEM(II)
        DO 320 JJ=1,N2
          IF(X2(JJ).EQ.HOLD)THEN
            K=K+1
            TEMP1(K)=Y2(JJ)
          ENDIF
  320   CONTINUE
        NT=K
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
          WRITE(ICOUT,211)II,NT
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(NT.GT.1)THEN
          CALL MEAN(TEMP1,NT,IWRITE,YMEANT,IBUGA3,IERROR)
          CALL SD(TEMP1,NT,IWRITE,YSDT,IBUGA3,IERROR)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,207)II
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
          CALL DPWRST('XXX','WRIT')
          GO TO 319
        ENDIF
!
!       CHECK FOR:
!
!           1) POSITIVE MEAN
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE MEAN)
!           2) POSITIVE SD
!              (OMIT GROUP FROM COMPUTATIONS FOR NON-POSITIVE SD)
!           3) COEFFICIENT OF VARIATION < 0.33
!              (THIS WILL BE WARNING, BUT INCLUDE IN THE COMPUTATIONS)
!
        IF(YMEANT.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,204)II
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
          CALL DPWRST('XXX','WRIT')
          GO TO 319
        ELSEIF(YSDT.LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,203)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,206)II
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,205)
          CALL DPWRST('XXX','WRIT')
          GO TO 319
        ENDIF
!
        NGROUP=NGROUP+1
        CT=YSDT/YMEANT
        IF(NGROUP.EQ.1)THEN
          YMEAN2=YMEANT
          YSD2=YSDT
          CV2=CT
        ENDIF
        ANT=REAL(NT)
        ANTM1=ANT - 1.0
        UT=CT**2/(1.0 + (CT**2*ANTM1/ANT))
        DSUM1=DSUM1 + DBLE(ANTM1)
        DSUM2=DSUM2 + DBLE(ANTM1*UT)
        DSUM3=DSUM3 + DBLE(ANTM1)*DBLE(CT**2)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')THEN
          WRITE(ICOUT,213)NGROUP,YMEANT,YSDT,CT,UT
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
  319   CONTINUE
  310 CONTINUE
!
      IF(NGROUP.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,381)
  381   FORMAT('      AFTER REMOVING GROUPS, LESS THAN ONE GROUP ',   &
               'REMAIN FOR SAMPLE TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NGROUP.GT.1)THEN
        DTERM1=DSQRT(DSUM3/DSUM1)
        CV2=REAL(DTERM1)
      ENDIF
!
      IDF2=INT(DSUM1+0.5D0)
      NGROU2=NGROUP
      DENOM=DSUM2/DSUM1
!
      IF(DENOM.NE.0.0D0)THEN
        STATVA=REAL(DNUM/DENOM)
      ELSE
        IERROR='YES'
        GO TO 9000
      ENDIF
      CALL FCDF(STATVA,IDF1,IDF2,STATCD)
      CALL FPPF(0.50,IDF1,IDF2,FCV50)
      STATN1=REAL(IDF1)
      STATN2=REAL(IDF2)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(STATVA.LE.FCV50)THEN
        PVAL2T=2.0*PVALLT
      ELSE
        PVAL2T=2.0*PVALUT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT4')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVT4--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATN1,STATN2,STATCD
 9015   FORMAT('STATVA,STATN1,STATN2,STATCD = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)NGROU1,NGROU2,DNUM,DENOM
 9016   FORMAT('NGROU1,NGROU2,DNUM,DENOM = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)CV1,CV2
 9017   FORMAT('CV1,CV2 = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVT4
      SUBROUTINE DPCVT5(STATVA,STATCD,PVAL,STANU1,STANU2,   &
                        CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                        CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                        IFLAGU,IFRST,ILAST,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPCVTE.  THIS ROUTINE UPDATES THE
!              PARAMETERS "STATVAL", "STATCDF", "PVALUE", "STANU1",
!              "STANU2", AND VARIOUS CUTOFF POINTS AFTER A COEFFICIENT
!              OF VARIATION TEST.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      SAVE IOUNI1
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVT5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVT5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)STATVA,STATCD,PVAL,STANU1,STANU2
   53   FORMAT('STATVA,STATCD,PVAL,STANU1,STANU2 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)CUTL95,CUTU95,CUTL99,CUTU99
   54   FORMAT('CUTL95,CUTU95,CUTL99,CUTU99 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
!
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          WRITE(IOUNI1,295)
  295     FORMAT(11X,'STATVAL',8X,'STATCDF',8X,'PVALUE',   &
                  8X,'STATNU1',8X,'STATNU2',   &
                  7X,'0.0005  ',7X,'0.005   ',   &
                  7X,'0.025   ',7X,'0.1     ',7X,'0.25    ',   &
                  7X,'0.75    ',7X,'0.90    ',   &
                  7X,'0.95    ',7X,'0.975   ',   &
                  7X,'0.995   ',7X,'0.9995  ')
        ENDIF
        WRITE(IOUNI1,299)STATVA,STATCD,PVAL,STANU1,STANU2,   &
                         CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                         CUTU50,CUTU80,CUTU90,CUTU95,CUTU99,CTU999
  299   FORMAT(12E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
        IF(STATVA.NE.CPUMIN)THEN
          IH='STAT'
          IH2='VAL '
          VALUE0=STATVA
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(STATCD.NE.CPUMIN)THEN
          IH='STAT'
          IH2='CDF '
          VALUE0=STATCD
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(PVAL.NE.CPUMIN)THEN
          IH='PVAL'
          IH2='UE  '
          VALUE0=PVAL
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(STANU1.NE.CPUMIN)THEN
          IH='STAT'
          IH2='NU1 '
          VALUE0=STANU1
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(STANU2.NE.CPUMIN)THEN
          IH='STAT'
          IH2='NU2 '
          VALUE0=STANU2
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU50.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP50'
          VALUE0=CUTU50
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU80.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP80'
          VALUE0=CUTU80
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU90.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP90'
          VALUE0=CUTU95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU95.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP95'
          VALUE0=CUTU95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTU99.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='PP99'
          VALUE0=CUTU99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CTU999.NE.CPUMIN)THEN
          IH='CUTU'
          IH2='P999'
          VALUE0=CTU999
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL50.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW50'
          VALUE0=CUTL50
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL80.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW80'
          VALUE0=CUTL80
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL90.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='PP90'
          VALUE0=CUTL90
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL95.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW95'
          VALUE0=CUTL95
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CUTL99.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='OW99'
          VALUE0=CUTL99
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CTL999.NE.CPUMIN)THEN
          IH='CUTL'
          IH2='P999'
          VALUE0=CTL999
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVT5')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI, IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CVT5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPCVT5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVT5
      SUBROUTINE DPCVT6(Y1,N1,Y2,N2,IWRITE,   &
                        YMEAN1,YSD1,C1,YMEAN2,YSD2,C2,   &
                        STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES MILLER'S TEST FOR THE EQUALITY
!              OF THE COEFFICIENTS OF VARIATION FROM TWO SAMPLES.
!
!                 H0: GAMMA1 = GAMMA2
!
!              THE TEST STATISTIC IS
!
!                 (C1-C2)/SQRT{C**2/(2*(N1-1)) + C**4/(N1-1) +
!                              C**2/(2*(N2-1)) + C**4/(N2-1)}
!
!              WHERE
!
!                 N1     = THE SAMPLE SIZE FOR SAMPLE ONE
!                 C1     = THE SAMPLE COEFFICIENT OF VARIATION FOR
!                          SAMPLE ONE
!                 N2     = THE SAMPLE SIZE FOR SAMPLE TWO
!                 C2     = THE SAMPLE COEFFICIENT OF VARIATION FOR
!                          SAMPLE TWO
!                 C      = ((N1-1)*C1 + (N2-1)*C2)/(N1+N2-2)
!
!              THIS STATISTIC IS COMPARED TO THE STANDARD NORMAL
!              DISTRIBUTION.
!
!              CURRENTLY, ONLY THE RAW DATA CASE IS SUPPORTED.
!
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                RESPONSE VALUES FOR SAMPLE ONE.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                FOR SAMPLE ONE.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                RESPONSE VALUES FOR SAMPLE TWO.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                FOR SAMPLE TWO.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STATISTIC.
!                     --STATCD = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CDF OF THE TEST STATISTIC.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             TEST STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHANNES FORKMAN (2009)), "ESTIMATOR AND TESTS FOR
!                 COMMON COEFFICIENTS OF VARIATION IN NORMAL
!                 DISTRIBUTIONS", COMMUNICATIONS IN STATISTICS -
!                 THEROY AND METHODS, VOL. 38, NO. 2, PP. 233-251.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017.06
!     ORIGINAL VERSION--JUNE      2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCV'
      ISUBN2='T6  '
      IERROR='NO'
      IWRITE='OFF'
!
      STATVA=-99.0
      STATCD=-99.0
      PVAL2T=-99.0
      PVALLT=-99.0
      PVALUT=-99.0
      YMEAN1=-99.0
      YSD1=-99.0
      C1=-99.0
      YMEAN2=-99.0
      YSD2=-99.0
      C2=-99.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT6')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCVT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I)
   56     FORMAT('I,Y1(I),X1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I)
   66     FORMAT('I,Y2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR: COMMON COEFFICIENT OF VARIANCE ',   &
               'TWO SAMPLE TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR SAMPLE ONE ',   &
                'IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N1
  103   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR SAMPLE TWO ',   &
                'IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 2--                              **
!               **  COMPUTE THE TWO SAMPLE COEFICIENT OF  **
!               **  VARIATION TEST.                       **
!               ********************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CVC4')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y1,N1,IWRITE,YMEAN1,IBUGA3,IERROR)
      CALL SD(Y1,N1,IWRITE,YSD1,IBUGA3,IERROR)
      IF(YMEAN1.GT.0.0)THEN
         C1=YSD1/YMEAN1
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,201)YMEAN1
  201   FORMAT('      THE MEAN FOR SAMPLE ONE IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL MEAN(Y2,N2,IWRITE,YMEAN2,IBUGA3,IERROR)
      CALL SD(Y2,N2,IWRITE,YSD2,IBUGA3,IERROR)
      IF(YMEAN2.GT.0.0)THEN
         C2=YSD2/YMEAN2
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,211)YMEAN2
  211   FORMAT('      THE MEAN FOR SAMPLE TWO IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN1=REAL(N1)
      AN2=REAL(N2)
      C=((AN1-1.0)*C1 + (AN2-1.0)*C2)/(AN1 + AN2 - 2.0)
      CC=C*C
      C4=C**4
      TERM1=C1 - C2
      TERM2=CC/(2.0*(AN1-1.0))
      TERM3=C4/(AN1-1.0)
      TERM4=CC/(2.0*(AN2-1.0))
      TERM5=C4/(AN2-1.0)
      STATVA=TERM1/SQRT(TERM2 + TERM3 + TERM4 + TERM5)
      CALL NORCDF(STATVA,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      IF(STATVA.LE.0.0)THEN
        PVAL2T=2.0*PVALLT
      ELSE
        PVAL2T=2.0*PVALUT
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CVT6')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCVT6--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STATVA,STATCD,PVAL2T
 9015   FORMAT('STATVA,STATCD,PVAL2T = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)TERM1,TERM2,TERM3,TERM4,TERM5
 9016   FORMAT('TERM1,TERM2,TERM3,TERM4,TERM5 = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)CV1,CV2
 9017   FORMAT('CV1,CV2 = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCVT6
      SUBROUTINE DPCWSH(YTEMP,XTEMP,MAXNXT,ICASAN,   &
                        ICAPSW,IFORSW,IMULT,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT COMMON WEIBULL SHAPE TEST
!              (K-SAMPLE HOMOGENEITY OF SHAPE PARAMETERS FOR TWO
!              PARAMETER WEIBULL)
!     EXAMPLE--COMMON WEIBULL SHAPE TEST Y X
!     REFERENCES--MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY, PP.
!                 236-238.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014.
!     UPDATED         --DECEMBER  2016. CONVERT TEMP2 TO DOUBLE
!                                       PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
!
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHOST1
      CHARACTER*4 ISUBN0
      CHARACTER*4 IWRITE
!
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!---------------------------------------------------------------------
!
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION TEMP1(MAXOBV)
!CCCC DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION TEMP5(MAXOBV)
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
      EQUIVALENCE(GARBAG(IGARB1),TEMP1(1))
      EQUIVALENCE(GARBAG(IGARB2),TEMP3(1))
      EQUIVALENCE(GARBAG(IGARB3),TEMP4(1))
      EQUIVALENCE(GARBAG(IGARB4),TEMP5(1))
      EQUIVALENCE(DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE(DGARBG(IDGAR2),DTEMP2(1))
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOS2.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCW'
      ISUBN2='SH  '
      IERROR='NO'
      IFOUND='YES'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               ************************************************
!               **  TREAT THE COMMON WEIBULL SHAPE TEST CASE  **
!               ************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CWSH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCWSH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)MAXNXT,IMULT,IFORSW
   55   FORMAT('MAXNXT,IMULT,IFORSW = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COMMON WEIBULL SHAPE TEST'
      MINNA=1
      MAXNA=100
      MINNVA=2
      MAXNVA=2
      IFLAGE=1
      IFLAGM=0
      IF(IMULT.EQ.'ON')THEN
        IFLAGE=0
        IFLAGM=1
        MINNVA=2
        MAXNVA=30
      ENDIF
      MINN2=5
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,182)NQ,NUMVAR,IMULT
  182   FORMAT('NQ,NUMVAR,IMULT = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 185 I=1,NUMVAR
            WRITE(ICOUT,187)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  187       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  185     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3--                                        **
!               **  GENERATE THE COMMON WEIBULL SHAPE TEST FOR THE  **
!               **  VARIOUS CASES                                   **
!               ******************************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     DEFINE CUT-OFF FOR "ACCEPTABLE" AGREEMENT.  LIMIT THIS
!     TO 0.90, 0.95, OR 0.99.  IF SHAPE PARAMETERS ARE JUDGED
!     EQUAL, THEN WE WILL ESTIMATE THE COMMON SHAPE PARAMETER.
!
      IH='ALPH'
      IH2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      ALPHA=0.95
      IF(IERROR.EQ.'NO')ALPHA=VALUE(ILOCP)
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)THEN
        ALPHA=0.95
      ELSEIF(ALPHA.LT.0.50)THEN
        ALPHA=1.0-ALPHA
      ENDIF
      IF(ALPHA.LE.0.925)THEN
        ALPHA=0.90
      ELSEIF(ALPHA.GT.0.925 .AND. ALPHA.LT.0.975)THEN
        ALPHA=0.95
      ELSE
        ALPHA=0.99
      ENDIF
!
!               *****************************************
!               **  STEP 3A--                          **
!               **  CASE 1: TWO RESPONSE VARIABLES     **
!               **          WITH NO REPLICATION        **
!               *****************************************
!
!     NOTE: ONLY ALLOW MATRIX ARGUMENTS FOR "MULTIPLE" CASE.
!           FOR CASE WHERE SECOND VARIABLE IS A GROUP-ID VARIABLE,
!           MATRIX ARGUMENTS DON'T MAKE SENSE.
!
      IF(IMULT.EQ.'OFF')THEN
        ISTEPN='3A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=2
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,X,YTEMP,NLOCAL,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!       PUT GROUP-ID AND CENSORING VARIABLES IN "DPCOZD" SCRATCH SPACE
!       FOR USE BY THE WEIFU8 ROUTINE.
!
        IWRITE='OFF'
        CALL DISTIN(X,NLOCAL,IWRITE,TEMP1,NTEMP,IBUGA3,IERROR)
        DO 311 I=1,NLOCAL
          DGARBG(IDGAR2+I-1)=DBLE(X(I))
          DGARBG(IDGAR3+I-1)=1.0D0
  311   CONTINUE
        DO 313 I=1,NTEMP
          DGARBG(IDGAR4+I-1)=DBLE(TEMP1(I))
  313   CONTINUE
!
!               *********************************************
!               **  STEP 3B--                              **
!               **  PREPARE FOR ENTRANCE INTO DPCWS2--     **
!               *********************************************
!
        ISTEPN='3B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,331)
  331     FORMAT('***** FROM DPCWSH, AS WE ARE ABOUT TO CALL DPCWS2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,332)NLOCAL
  332     FORMAT('NLOCAL = ',I8)
          CALL DPWRST('XXX','BUG ')
          DO 335 I=1,NLOCAL
            WRITE(ICOUT,336)I,Y(I),X(I)
  336       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
  335     CONTINUE
        ENDIF
!
        CALL DPCWS2(Y,X,NLOCAL,MAXOBV,IVARN1,IVARN2,   &
                    TEMP1,DTEMP2,TEMP3,TEMP4,TEMP5,DTEMP1,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,MINMAX,ALPHA,   &
                    STATVA,STATCD,PVALUE,   &
                    CUT0,CUT50,CUT75,CUT90,CUT95,CUT99,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
!
!               *******************************************************
!               **  STEP 4A--                                        **
!               **  CASE 2: MULTIPLE RESPONSE VARIABLES.             **
!               *******************************************************
!
      ELSEIF(IMULT.EQ.'ON')THEN
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        NUMVA2=NUMVAR
        CALL DPPAR8(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    XTEMP,Y,X,NLOCAL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        NUMVAR=2
!
!       PUT GROUP-ID AND CENSORING VARIABLES IN "DPCOZD" SCRATCH SPACE
!       FOR USE BY THE WEIFU8 ROUTINE.
!
        IWRITE='OFF'
        CALL DISTIN(X,NLOCAL,IWRITE,TEMP1,NTEMP,IBUGA3,IERROR)
        DO 411 I=1,NLOCAL
          DGARBG(IDGAR2+I-1)=DBLE(X(I))
          DGARBG(IDGAR3+I-1)=1.0D0
  411   CONTINUE
        DO 413 I=1,NTEMP
          DGARBG(IDGAR4+I-1)=DBLE(TEMP1(I))
  413   CONTINUE
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CWSH')THEN
          ISTEPN='4B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,442)
  442     FORMAT('***** FROM THE MIDDLE  OF DPCWSH--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,443)ICASAN,NUMVAR,NLOCAL
  443     FORMAT('ICASAN,NUMVAR,NLOCAL = ',A4,2I8)
          CALL DPWRST('XXX','BUG ')
          IF(NLOCAL.GE.1)THEN
            DO 445 I=1,NLOCAL
              WRITE(ICOUT,446)I,Y(I),X(I)
  446         FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
              CALL DPWRST('XXX','BUG ')
  445       CONTINUE
          ENDIF
        ENDIF
!
        CALL DPCWS2(Y,X,NLOCAL,MAXOBV,IVARN1,IVARN2,   &
                    TEMP1,DTEMP2,TEMP3,TEMP4,TEMP5,DTEMP1,   &
                    ICAPSW,ICAPTY,IFORSW,IMULT,MINMAX,ALPHA,   &
                    STATVA,STATCD,PVALUE,   &
                    CUT0,CUT50,CUT975,CUT90,CUT95,CUT99,CUT999,   &
                    IBUGA3,ISUBRO,IERROR)
      ENDIF
!
!               ***************************************
!               **  STEP 61--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='61'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CWSH')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN0='DPCW'
!
      IH='STAT'
      IH2='VAL '
      VALUE0=STATVA
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='STAT'
      IH2='CDF '
      VALUE0=STATCD
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PVAL'
      IH2='UE  '
      VALUE0=PVALUE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF0 '
      VALUE0=CUT0
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF50'
      VALUE0=CUT50
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF75'
      VALUE0=CUT75
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF90'
      VALUE0=CUT90
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF95'
      VALUE0=CUT95
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='FF99'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F975'
      VALUE0=CUT975
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='CUTO'
      IH2='F999'
      VALUE0=CUT99
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CWSH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCWSH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NLOCAL,STATVA,STATCD
 9014   FORMAT('NLOCAL,STATVA,STATCD = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCWSH
      SUBROUTINE DPCWS2(Y,TAG,N,MAXOBV,IVARID,IVARI2,   &
                        YTEMP,YTEMP2,XTEMP1,XIDTEM,YSTAT,DTEMP1,   &
                        ICAPSW,ICAPTY,IFORSW,IMULT,MINMAX,ALPHAT,   &
                        STATVA,STATCD,PVALUE,   &
                        CUT0,CUT50,CUT75,CUT90,CUT95,CUT99,CUT999,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT COMMON WEIBULL SHAPE TEST
!              (K-SAMPLE HOMOGENEITY OF SHAPE PARAMETERS FOR TWO
!              PARAMETER WEIBULL)
!     EXAMPLE--COMMON WEIBULL SHAPE TEST Y X
!     REFERENCES--MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY, PP.
!                 236-238.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 Gaithersburg, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IMULT
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ILIKFL
      CHARACTER*4 IOP
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION YTEMP(*)
      DIMENSION XTEMP1(*)
      DIMENSION YSTAT(*)
      DIMENSION XIDTEM(*)
!
      DOUBLE PRECISION YTEMP2(*)
      DOUBLE PRECISION DTEMP1(*)
!
      PARAMETER (NUMALP=8)
      PARAMETER (NUMAL2=6)
      REAL ALPHA(NUMALP)
      REAL ALPHA2(NUMAL2)
      REAL ALOWLM(NUMAL2)
      REAL AUPPLM(NUMAL2)
!
      PARAMETER(NUMCLI=4)
      PARAMETER(MAXLIN=2)
      PARAMETER (MAXROW=30)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*1  ITITL9
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INTEGER   NSIZE(50)
      INTEGER   NR(50)
      REAL      SCALE(50)
      COMMON/CWSHAP/IN,NDIST2,NSIZE,NR,SCALE,BETAMN,BETAMX,BETAMD
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ALPHA/   &
       0.0, 50.0, 75.0, 90.0, 95.0, 97.5, 99.0, 99.9/
      DATA ALPHA2 /0.50, 0.20, 0.10, 0.05, 0.01, 0.001/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCW'
      ISUBN2='S2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCWS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IMULT,N,ALPHAT
   52   FORMAT('IBUGA3,ISUBRO,IMULT,N,ALPHAT = ',3(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               *************************************
!               **  STEP 41--                      **
!               **  CARRY OUT CALCULATIONS         **
!               **  FOR COMMON WEIBULL SHAPE TEST  **
!               *************************************
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPCWS3(Y,TAG,N,IWRITE,ISEED,MINMAX,MAXOBV,   &
                  YTEMP,YTEMP2,XTEMP1,XIDTEM,YSTAT,DTEMP1,   &
                  STATVA,STATCD,PVALUE,NDIST,NGROUP,   &
                  CV90,CV95,CV99,BETACM,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      CUT0=0.0
      CUT50=YSTAT(5000)
      CUT75=YSTAT(7500)
      CUT90=YSTAT(9000)
      CUT95=YSTAT(9500)
      CUT975=YSTAT(9750)
      CUT99=YSTAT(9900)
      CUT999=YSTAT(9990)
!
!               *****************************************
!               **  STEP 42--                          **
!               **  IF SHAPES ARE EQUAL AT SPECIFIED   **
!               **  ALPHA, THEN ESTIMATE THE COMMON    **
!               **  SHAPE PARAMETER.                   **
!               *****************************************
!
      IF(BETACM.GT.0.0)THEN
        NSIMUL=10000
        DO 4101 I=1,NSIMUL
          XTEMP1(I)=YSTAT(NSIMUL+I)
 4101   CONTINUE
!
        CALL SORT(XTEMP1,NSIMUL,XTEMP1)
        DO 4191 I=1,NUMAL2
          ALP=ALPHA2(I)
          P1=100.0*(ALP/2.0)
          P2=100.0*(1.0-(ALP/2.0))
          CALL PERCEN(P2,XTEMP1,NSIMUL,IWRITE,YTEMP,MAXOBV,   &
                      XPERC,IBUGA3,IERROR)
          ALOWLM(I)=BETACM/XPERC
          CALL PERCEN(P1,XTEMP1,NSIMUL,IWRITE,YTEMP,MAXOBV,   &
                      XPERC,IBUGA3,IERROR)
          AUPPLM(I)=BETACM/XPERC
 4191   CONTINUE
!
!       WRITE SCALE PARAMETERS BASED ON COMMON SHAPE PARAMETER TO
!       dpst1f.dat.
!
        IOP='OPEN'
        IFLG1=1
        IFLG2=0
        IFLG3=0
        IFLG4=0
        IFLG5=0
        CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        DO 4193 I=1,NDIST
          WRITE(IOUNI1,'(I8,E15.7)')I,SCALE(I)
 4193   CONTINUE
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
!
      ENDIF
!
!               ******************************
!               **   STEP 42--              **
!               **   WRITE OUT EVERYTHING   **
!               ******************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Test for Common Weibull Shape Parameter'
      NCTITL=39
      ITITLZ='(For the 2-Parameter Weibull Distribution)'
      NCTITZ=42
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      IF(IMULT.EQ.'OFF')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Group-ID Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
      ENDIF
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: Homogeneous Shape Parameters'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: Shape Parameters Are Not Homogeneous'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Total Number of Observations:'
      NCTEXT(ICNT)=29
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups:'
      NCTEXT(ICNT)=17
      AVALUE(ICNT)=REAL(NDIST)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Groups Used in Test:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=REAL(NGROUP)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Minimum Value of Shape Parameter:'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=BETAMN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Maximum Value of Shape Parameter:'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=BETAMX
      IDIGIT(ICNT)=NUMDIG
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test Statistic Value:'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=STATVA
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF of Test Statistic:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=STATCD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value:'
      NCTEXT(ICNT)=8
      AVALUE(ICNT)=PVALUE
      IDIGIT(ICNT)=NUMDIG
!
      IF(BETACM.GT.0.0)THEN
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=1
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Estimate of Common Shape Parameter:'
        NCTEXT(ICNT)=35
        AVALUE(ICNT)=BETACM
        IDIGIT(ICNT)=NUMDIG
      ENDIF
!
      NUMROW=ICNT
      DO 4210 I=1,NUMROW
        NTOT(I)=15
 4210 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      ISTEPN='42A'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE=' '
      NCTITL=0
!
      ITITL9=' '
      NCTIT9=0
      ITITLE(1:44)='Percent Points of the Reference Distribution'
      NCTITL=44
      NUMLIN=1
      NUMROW=8
      NUMCOL=3
      ITITL2(1,1)='Percent Point'
      ITITL2(1,2)=' '
      ITITL2(1,3)='Value'
      NCTIT2(1,1)=13
      NCTIT2(1,2)=1
      NCTIT2(1,3)=5
!
      NMAX=0
      DO 4221 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.2)NTOT(I)=5
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
        ITYPCO(I)='NUME'
 4221 CONTINUE
      ITYPCO(2)='ALPH'
      IDIGIT(1)=1
      IDIGIT(3)=3
      DO 4223 I=1,NUMROW
        DO 4225 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
          IF(J.EQ.1)THEN
            AMAT(I,J)=ALPHA(I)
          ELSEIF(J.EQ.2)THEN
            IVALUE(I,J)='='
            NCVALU(I,J)=1
          ELSEIF(J.EQ.3)THEN
            IF(I.EQ.1)THEN
              AMAT(I,J)=RND(CUT0,IDIGIT(J))
            ELSEIF(I.EQ.2)THEN
              AMAT(I,J)=RND(CUT50,IDIGIT(J))
            ELSEIF(I.EQ.3)THEN
              AMAT(I,J)=RND(CUT75,IDIGIT(J))
            ELSEIF(I.EQ.4)THEN
              AMAT(I,J)=RND(CUT90,IDIGIT(J))
            ELSEIF(I.EQ.5)THEN
              AMAT(I,J)=RND(CUT95,IDIGIT(J))
            ELSEIF(I.EQ.6)THEN
              AMAT(I,J)=RND(CUT975,IDIGIT(J))
            ELSEIF(I.EQ.7)THEN
              AMAT(I,J)=RND(CUT99,IDIGIT(J))
            ELSEIF(I.EQ.8)THEN
              AMAT(I,J)=RND(CUT999,IDIGIT(J))
            ENDIF
          ENDIF
 4225   CONTINUE
 4223 CONTINUE
!
      IWHTML(1)=150
      IWHTML(2)=50
      IWHTML(3)=150
      IWRTF(1)=2000
      IWRTF(2)=IWRTF(1)+500
      IWRTF(3)=IWRTF(2)+2000
      IFRST=.TRUE.
      ILAST=.FALSE.
!
      ISTEPN='42C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='42D'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CDF1=CUT90
      CDF2=CUT95
      CDF3=CUT975
      CDF4=CUT99
!
      ITITL9=' '
      NCTIT9=0
      ITITLE='Conclusions (Upper 1-Tailed Test)'
      NCTITL=33
      NUMLIN=1
      NUMROW=4
      NUMCOL=4
      ITITL2(1,1)='Alpha'
      ITITL2(1,2)='CDF'
      ITITL2(1,3)='Critical Value'
      ITITL2(1,4)='Conclusion'
      NCTIT2(1,1)=5
      NCTIT2(1,2)=3
      NCTIT2(1,3)=14
      NCTIT2(1,4)=10
!
      NMAX=0
      DO 4321 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1 .OR. I.EQ.2)NTOT(I)=7
        IF(I.EQ.3)NTOT(I)=17
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=3
        ITYPCO(I)='ALPH'
 4321 CONTINUE
      ITYPCO(3)='NUME'
      IDIGIT(1)=0
      IDIGIT(2)=0
      DO 4323 I=1,NUMROW
        DO 4325 J=1,NUMCOL
          NCVALU(I,J)=0
          IVALUE(I,J)=' '
          NCVALU(I,J)=0
          AMAT(I,J)=0.0
 4325   CONTINUE
 4323 CONTINUE
      IVALUE(1,1)='10%'
      IVALUE(2,1)='5%'
      IVALUE(3,1)='2.5%'
      IVALUE(4,1)='1%'
      IVALUE(1,2)='90%'
      IVALUE(2,2)='95%'
      IVALUE(3,2)='97.5%'
      IVALUE(4,2)='99%'
      NCVALU(1,1)=3
      NCVALU(2,1)=2
      NCVALU(3,1)=4
      NCVALU(4,1)=2
      NCVALU(1,2)=3
      NCVALU(2,2)=3
      NCVALU(3,2)=5
      NCVALU(4,2)=3
      IVALUE(1,4)='Accept H0'
      IVALUE(2,4)='Accept H0'
      IVALUE(3,4)='Accept H0'
      IVALUE(4,4)='Accept H0'
      NCVALU(1,4)=9
      NCVALU(2,4)=9
      NCVALU(3,4)=9
      NCVALU(4,4)=9
      IF(STATVA.GT.CUT90)IVALUE(1,4)='Reject H0'
      IF(STATVA.GT.CUT95)IVALUE(2,4)='Reject H0'
      IF(STATVA.GT.CUT975)IVALUE(3,4)='Reject H0'
      IF(STATVA.GT.CUT99)IVALUE(4,4)='Reject H0'
      AMAT(1,3)=RND(CUT90,IDIGIT(3))
      AMAT(2,3)=RND(CUT95,IDIGIT(3))
      AMAT(3,3)=RND(CUT975,IDIGIT(3))
      AMAT(4,3)=RND(CUT99,IDIGIT(3))
!
      IWHTML(1)=150
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWRTF(1)=1500
      IWRTF(2)=IWRTF(1)+1500
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IFRST=.FALSE.
      ILAST=.TRUE.
!
      ISTEPN='42E'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPDTA4(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,NUMROW,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(BETACM.GT.0.0)THEN
        ILIKFL='WCSH'
        CALL DPDTA8(ALOWLM,ALOWLM,ALOWLM,ALOWLM,   &
                    ALOWLM,AUPPLM,ALOWLM,AUPPLM,ALPHA2,NUMAL2,   &
                    ICAPSW,ICAPTY,NUMDIG,ILIKFL,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCWS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)N,IBUGA3,IERROR
 9012   FORMAT('N,IBUGA3,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)STATVA,STATCD,PVAL
 9014   FORMAT('STATVA,STATCD,PVAL = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCWS2
      SUBROUTINE DPCWS3(Y,X,N,IWRITE,ISEED,MINMAX,MAXNXT,   &
                        YTEMP,YTEMP2,XTEMP1,XIDTEM,YSTAT,DTEMP1,   &
                        STATVA,STATCD,PVALUE,NDIST,NGROUP,   &
                        CV90,CV95,CV99,BETACM,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--GIVEN K GROUPS OF DATA, THIS ROUTINE TESTS WHETHER
!              THE K SHAPE PARAMETERS FOR A 2-PARAMETER WEIBULL
!              DISTRIBUTION ARE EQUAL.  THE TEST PROCEDURE IS
!
!                 1) FOR EACH GROUP, FIT A 2-PARAMETER WEIBULL
!                    DISTRIBUTION.
!
!                 2) DETERMINE THE MINIMUM AND MAXIMUM VALUES OF
!                    THE SHAPE PARAMETER.
!
!                 3) THE TEST STATISTIC IS
!
!                        Bhat(max)/Bhat(min)
!
!                 4) CRITICAL VALUES ARE DETERMINED VIA SIMULATION.
!                    SPECIFICALLY, GENERATE K 2-PARAMETER WEIBULL
!                    SAMPLES WITH A COMMON SHAPE PARAMETER
!                    (SPECIFICALLY, WE WILL USE THE MEDIAN VALUE
!                    OF THE FITTED SHAPE PARAMETERS).  COMPUTE
!                    THIS RATIO FOR 10,000 SIMULATIONS.
!
!              WE CURRENTLY ONLY SUPPORT THIS TEST FOR UNCENSORED DATA.
!              HOWEVER, IT CAN BE EXTENDED TO SUPPORT TYPE II CENSORING.
!
!              THIS TEST IS DESCRIBED IN MCCOOL (SEE REFERENCE).
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR FOR
!                                THE GROUP-IDENTIFIER.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED TEST STATISTIC.
!     OUTPUT--NONE.
!     PRINTING--YES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--XXXXX.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MCCOOL (2012), "USING THE WEIBULL DISTRIBUTION:
!                 RELIABILITY, MODELING, AND INFERENCE", WILEY, PP.
!                 236-238.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014.4
!     ORIGINAL VERSION--APRIL     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IDIR
      CHARACTER*4 ISTEPN
      CHARACTER*4 IRANSV
      CHARACTER*4 IWEIFL
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION YTEMP(*)
      DIMENSION XIDTEM(*)
      DIMENSION XTEMP1(*)
      DIMENSION YSTAT(*)
!
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION YTEMP2(*)
!
!CCCC PARAMETER (MAXGRP=50)
      DIMENSION BETA(50)
      DIMENSION BETA2(50)
      DIMENSION SCALE(50)
      INTEGER   NSIZE(50)
      INTEGER   NR(50)
      COMMON/CWSHAP/IN,NDIST2,NSIZE,NR,SCALE,BETAMN,BETAMX,BETAMD
!
      DOUBLE PRECISION WEIFU8
      EXTERNAL WEIFU8
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DAE
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOST.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPWC'
      ISUBN2='S3  '
      IERROR='NO'
      IWRITE='OFF'
      STATVA=CPUMIN
      STATCD=CPUMIN
      PVALUE=CPUMIN
!
      IRANSV=IRANAL
      IRANAL='FIBC'
      ISEESV=ISEED
      ISEED=36243
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCWS3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN WEIBULL COMMON SHAPE PARAMETER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS FEWER THAN FIVE ',   &
               'OBSERVATIONS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,118)N
  118   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(MINMAX.EQ.2)THEN
        DO 130 I=1,N
          IF(Y(I).GE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,132)
  132       FORMAT('      ROW ',I8,' OF THE RESPONSE VARIABLE IS ',   &
                   'NON-NEGATIVE.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,134)Y(I)
  134       FORMAT('      IT HAS THE VALUE ',G15.7)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ELSE
            Y(I)=-Y(I)
          ENDIF
  130   CONTINUE
      ELSE
        DO 120 I=1,N
          IF(Y(I).LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,122)
  122       FORMAT('      ROW ',I8,' OF THE RESPONSE VARIABLE IS ',   &
                   'NON-POSITIVE.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,124)Y(I)
  124       FORMAT('      IT HAS THE VALUE ',G15.7)
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
  120   CONTINUE
      ENDIF
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      IF(NDIST.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,142)
  142   FORMAT('      NO DISTINCT GROUPS DETECTED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE TEST STATISTIC                 **
!               *************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS3')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWEIFL='WEIB'
      ICNT1=0
      DO 1000 I=1,NDIST
        HOLD=XIDTEM(I)
        ICNT2=0
        DO 1100 J=1,N
          IF(X(J).EQ.HOLD)THEN
            ICNT2=ICNT2+1
            YTEMP(ICNT2)=Y(J)
          ENDIF
 1100   CONTINUE
        IF(ICNT2.GE.3)THEN
          ICNT1=ICNT1+1
          NSIZE(ICNT1)=ICNT2
          CALL WEIML1(YTEMP,ICNT2,IWEIBC,IWEIFL,MINMAX,   &
                      XTEMP1,DTEMP1,   &
                      XMEAN,XSD,XVAR,XMIN,XMAX,   &
                      ZMEAN,ZSD,   &
                      SCALML,SCALSE,SHAPML,SHAPSE,   &
                      SHAPBC,SHABSE,COVSE,COVBSE,   &
                      ISUBRO,IBUGA3,IERROR)
          BETA(ICNT1)=SHAPML
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)
 1111     FORMAT('***** WARNING IN WEIBULL COMMON SHAPE PARAMETER--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1112)I
 1112     FORMAT('      GROUP ',I3,' HAS FEWER THAN THREE ',   &
                 'OBSERVATIONS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1113)
 1113     FORMAT('      AND WILL BE OMITTED FROM THE ANALYSIS.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS3')THEN
          WRITE(ICOUT,1191)I,ICNT1,NSIZE(ICNT1),BETA(ICNT1)
 1191     FORMAT('I,ICNT1,NSIZE(ICNT1),BETA(ICNT1) = ',3I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 1000 CONTINUE
!
      ISTEPN='2B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS3')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NGROUP=ICNT1
      IF(ICNT1.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
 1211   FORMAT('      LESS THAN TWO GROUPS HAVE AT LEAST THREE ',   &
               'OBSERVATIONS, SO TEST NOT PERFORMED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        CALL MINIM(BETA,NGROUP,IWRITE,BETAMN,IBUGA3,IERROR)
        CALL MAXIM(BETA,NGROUP,IWRITE,BETAMX,IBUGA3,IERROR)
        CALL MEDIAN(BETA,NGROUP,IWRITE,XTEMP1,MAXNXT,BETAMD,   &
                    IBUGA3,IERROR)
        IF(BETAMN.GT.0.0)THEN
          STATVA=BETAMX/BETAMN
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
!     COMPUTE THE COMMON SHAPE PARAMETER
!
      ISTEPN='2C'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS3')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 4101 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 4101 CONTINUE
      DO 4103 I=1,50
        NR(I)=NSIZE(I)
 4103 CONTINUE
      IFLAG=0
      IN=N
      NDIST2=NDIST
      DAE=1.D-7
      DRE=1.D-7
      DXLOW=DBLE(BETAMN)/2.0D0
      DXUP=DBLE(BETAMX)*2.0D0
      DXSTRT=DBLE(BETAMD)
      CALL DFZER3(WEIFU8,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
      BETACM=REAL(DXLOW)
!
!     BASED ON THE COMMON SHAPE PARAMETER, COMPUTE THE SCALE
!     PARAMETERS FOR EACH GROUP.
!
      DO 4410 I=1,NDIST
        HOLD=XIDTEM(I)
        DSUM1=0.0D0
        DO 4420 J=1,N
          IF(X(J).EQ.HOLD)THEN
            DSUM1=DSUM1 + DBLE(Y(J))**DBLE(BETACM)
          ENDIF
 4420   CONTINUE
        IF(DSUM1.GT.0.0D0 .AND. NR(I).GT.0)THEN
          DTERM1=(DSUM1/DBLE(NR(I)))**(1.0D0/DBLE(BETACM))
          SCALE(I)=REAL(DTERM1)
        ELSE
          SCALE(I)=CPUMIN
        ENDIF
 4410 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS3')THEN
        WRITE(ICOUT,1291)BETAMN,BETAMX,BETAMD,STATVA,BETACM
 1291   FORMAT('BETAMN,BETAMX,BETAMD,STATVA,BETACM = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *************************************************
!               **  STEP 3--                                   **
!               **  COMPUTE THE CRITICAL VALUES                **
!               *************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CWS3')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NSIMUL=10000
      BETATE=2.0
!
      DO 3000 I=1,NSIMUL
        ICNT=0
        DO 3100 J=1,NGROUP
          NTEMP=NSIZE(J)
!
!         GENERATE THE WEIBULL RANDOM NUMBERS FOR THE SUB-GROUP
!
!CCCC     CALL WEIRAN(NTEMP,BETAMD,MINMAX,ISEED,YTEMP)
          CALL WEIRAN(NTEMP,BETATE,MINMAX,ISEED,YTEMP)
          DO 3105 II=1,NTEMP
            ICNT=ICNT+1
            YTEMP2(ICNT)=YTEMP(II)
 3105     CONTINUE
!
!         ESTIMATE BETA FOR THIS RANDOM SAMPLE
!
          CALL WEIML1(YTEMP,NTEMP,IWEIBC,IWEIFL,MINMAX,   &
                      XTEMP1,DTEMP1,   &
                      XMEAN,XSD,XVAR,XMIN,XMAX,   &
                      ZMEAN,ZSD,   &
                      SCALML,SCALSE,SHAPML,SHAPSE,   &
                      SHAPBC,SHABSE,COVSE,COVBSE,   &
                      ISUBRO,IBUGA3,IERROR)
          BETA2(J)=SHAPML
 3100   CONTINUE
!
!       NOW COMPUTE TEST STATISTIC
!
        CALL MINIM(BETA2,NGROUP,IWRITE,BETMN2,IBUGA3,IERROR)
        CALL MAXIM(BETA2,NGROUP,IWRITE,BETMX2,IBUGA3,IERROR)
        STATV9=BETMX2/BETMN2
        YSTAT(I)=STATV9
!
!       COMPUTE COMMON SHAPE PARAMETER AND THEN COMPUTE
!       V1 = BETAHAT/BETA = COMMON BETA/BETA USED FOR SIMULATION
!
        DO 3301 II=1,N
          DTEMP1(II)=YTEMP2(II)
 3301   CONTINUE
        DO 3303 II=1,50
          NR(II)=NSIZE(II)
 3303   CONTINUE
        IFLAG=0
        IN=N
        NDIST2=NDIST
        DAE=1.D-7
        DRE=1.D-7
        DXLOW=DBLE(BETMN2)/2.0D0
        DXUP=DBLE(BETMX2)*2.0D0
        DXSTRT=DBLE((BETMN2 + BETMX2)/2.0)
        CALL DFZER3(WEIFU8,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
        BETCM2=REAL(DXLOW)
        YSTAT(NSIMUL+I)=BETCM2/BETATE
!
 3000 CONTINUE
!
!     NOW COMPUTE CDF AND PVALUE
!
      IDIR='UPPE'
      CALL DPGOF8(YSTAT,NSIMUL,STATVA,PVALUE,IDIR,   &
                  IBUGA3,ISUBRO,IERROR)
      STATCD=1.0 - PVALUE
      CV90=YSTAT(9000)
      CV95=YSTAT(9500)
      CV99=YSTAT(9900)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      ISEED=ISEESV
      IRANAL=IRANSV
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CWS3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCWS3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NGROUP,BETAMN,BETAMX,BETAMD
 9014   FORMAT('NGROUP,BETAMN,BETAMX,BETAMD = ',I8,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)STATVA,STATCD,PVALUE
 9016   FORMAT('STATVA,STATCD,PVALUE = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)CV90,CV95,CV99
 9018   FORMAT('CV90,CV95,CV99 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCWS3
      SUBROUTINE DPCXTE(XTEMP1,XTEMP2,MAXNXT,   &
                        ICAPSW,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT A COX STUART TEST FOR TREND
!     EXAMPLE--COX STUART TEST Y
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/6
!     ORIGINAL VERSION--JUNE      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASAN
      CHARACTER*4 ICASA2
      CHARACTER*4 ICASA3
      CHARACTER*4 IMULT
      CHARACTER*4 IREPL
      CHARACTER*4 ICTMP1
      CHARACTER*4 ICTMP2
      CHARACTER*4 ICTMP3
!
      CHARACTER*4 ICASE
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!---------------------------------------------------------------------
!
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
      DIMENSION Y2(MAXOBV)
      EQUIVALENCE (GARBAG(IGARB1),Y2(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCX'
      ISUBN2='TE  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IFOUND='YES'
      IERROR='NO'
      IREPL='OFF'
      IMULT='OFF'
      ICASA2='TWOT'
!
!               **************************************
!               **  TREAT THE COX STUART TEST CASE  **
!               **************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCXTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ,ISUBRO,MAXNXT
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ,ISUBRO = ',4(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************************
!               **  STEP 1--                                           **
!               **  EXTRACT THE COMMAND                                **
!               *********************************************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ILASTZ=9999
      ICASAN='COXS'
!
!     LOOK FOR:
!
!          COX STUART TEST
!          LOWER TAILED
!          UPPER TAILED
!
      DO 100 I=0,NUMARG-1
!
        IF(I.EQ.0)THEN
          ICTMP1=ICOM
        ELSE
          ICTMP1=IHARG(I)
        ENDIF
        ICTMP2=IHARG(I+1)
        ICTMP3=IHARG(I+2)
!
        IF(ICTMP1.EQ.'=')THEN
          IFOUND='NO'
          GO TO 9000
        ELSEIF(ICTMP1.EQ.'COX ' .AND. ICTMP2.EQ.'STUA' .AND.   &
               ICTMP3.EQ.'TEST')THEN
          IFOUND='YES'
          ICASAN='COXS'
          ILASTZ=I+2
        ELSEIF(ICTMP1.EQ.'COX ' .AND. ICTMP2.EQ.'STUA')THEN
          IFOUND='YES'
          ICASAN='COXS'
          ILASTZ=I+1
        ELSEIF(ICTMP1.EQ.'LOWE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='LOWE'
          ILASTZ=MAX(ILASTZ,I+1)
        ELSEIF(ICTMP1.EQ.'UPPE' .AND. ICTMP2.EQ.'TAIL')THEN
          ICASA2='UPPE'
          ILASTZ=MAX(ILASTZ,I+1)
        ENDIF
  100 CONTINUE
!
      IF(IFOUND.EQ.'NO')GO TO 9000
!
      ISHIFT=ILASTZ
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                  IBUGA2,IERROR)
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')THEN
        WRITE(ICOUT,91)ICASAN,ICASA2,ISHIFT
   91   FORMAT('DPCXTE: ICASAN,ICASA2,ISHIFT = ',   &
               2(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='COX-STUART TEST'
      MINNA=1
      MAXNA=100
      MINN2=2
      IFLAGE=0
      IFLAGM=1
      MINNVA=1
      MAXNVA=MAXSPN
      IF(IREPL.EQ.'ON')THEN
        IFLAGE=1
        IFLAGM=0
      ENDIF
      JMIN=1
      JMAX=NUMARG
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               ******************************************************
!               **  STEP 3A--                                       **
!               **  CASE 1: NO REPLICATION.                         **
!               ******************************************************
!
      ISTEPN='3A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')   &
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMVA2=1
      DO 5210 I=1,NUMVAR
        ICOL=I
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y,Y,Y,NS1,NLOCA2,NLOCA3,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 52--                          **
!               **  PERFORM COX STUART    TEST         **
!               *****************************************
!
        ISTEPN='52'
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CXTE')THEN
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5211)
 5211     FORMAT('***** FROM DPCXTE, BEFORE CALL DPCXT2--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5212)I,NS1,MAXN
 5212     FORMAT('I,NS1,MAXN = ',3I8)
          CALL DPWRST('XXX','BUG ')
          DO 5215 II=1,NS1
            WRITE(ICOUT,5216)II,Y(II)
 5216       FORMAT('I,Y(I) = ',I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 5215     CONTINUE
        ENDIF
!
        IVARID=IVARN1(I)
        IVARI2=IVARN2(I)
        CALL DPCXT2(Y,NS1,ICASA2,   &
                    Y2,XTEMP1,XTEMP2,MAXNXT,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    IVARID,IVARI2,   &
                    STATV1,STATV2,STATC1,STATC2,   &
                    PVAL2T,PVALLT,PVALUT,   &
                    CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                    CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***************************************
!               **  STEP 8C--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
        ISTEPN='8C'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'CXTE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IFLAGU='ON'
        IFRST=.FALSE.
        ILAST=.FALSE.
        IF(I.EQ.1)IFRST=.TRUE.
        IF(I.EQ.NUMVAR)ILAST=.TRUE.
        ICASA3='TWOS'
        CALL DPSIG5(ICASA3,STATV1,STATC1,   &
                    PVAL2T,PVALLT,PVALUT,   &
                    CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                    CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                    IFLAGU,IFRST,ILAST,   &
                    IBUGA2,IBUGA3,ISUBRO,IERROR)
!
 5210 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'CXTE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCXTE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCXTE
      SUBROUTINE DPCXT2(Y1,N,ICASAN,   &
                        Y2,XTEMP1,XTEMP2,MAXNXT,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        IVARID,IVARI2,   &
                        STATV1,STATV2,STATC1,STATC2,   &
                        PVAL2T,PVALLT,PVALUT,   &
                        CTL999,CUTL99,CUTL95,CUTL90,CUTL80,CUTL50,   &
                        CTU999,CUTU99,CUTU95,CUTU90,CUTU80,CUTU50,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE CARRIES OUT THE COX-STUART TREND TEST.
!              THIS IS ESSENTIALLY A TWO-SAMPLE SIGN TEST BETWEEN POINTS
!              BELOW THE MEDIAN WITH POINTS ABOVE THE MEDIAN.
!     EXAMPLE--COX STUART TEST Y
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/6
!     ORIGINAL VERSION--JUNE      2011.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IVARID
      CHARACTER*4 IVARI2
      CHARACTER*4 ICAPTY
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ICASAN
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DPAR
!
      PARAMETER (NUMALP=6)
      REAL ALPHA(NUMALP)
!
      PARAMETER(NUMCLI=5)
      PARAMETER(MAXLIN=3)
      PARAMETER (MAXROW=NUMALP)
      PARAMETER (MAXRO2=35)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITLZ
      CHARACTER*60 ITITL9
      CHARACTER*60 ITEXT(MAXRO2)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AVALUE(MAXRO2)
      INTEGER      NCTEXT(MAXRO2)
      INTEGER      IDIGIT(MAXRO2)
      INTEGER      NTOT(MAXRO2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      CHARACTER*15 IVALUE(MAXROW,NUMCLI)
      CHARACTER*4  ITYPCO(NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      NCVALU(MAXROW,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      LOGICAL IFRST
      LOGICAL ILAST
      LOGICAL IFLAGS
      LOGICAL IFLAGE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA ALPHA/0.50, 0.80, 0.90, 0.95, 0.99, 0.999/
!
      ISUBN1='DPCX'
      ISUBN2='T2  '
      IERROR='NO'
      IWRITE='OFF'
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF DPCXT2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,IVARID,IVARI2
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,IVARID,IVARI2 = ',4(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N
   55   FORMAT('N1 = ',2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,N
          WRITE(ICOUT,57)I,Y1(I)
   57     FORMAT('I,Y1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 11--                  **
!               **  SPLIT THE DATA INTO 2      **
!               **  PARTS                      **
!               *********************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IODD=MOD(N,2)
      IF(IODD.EQ.0)THEN
        IC=N/2
        DO 1110 I=1,IC
          Y2(I)=Y1(IC+I)
 1110   CONTINUE
        N1=IC
      ELSE
        IC=(N+1)/2
        N1=IC-1
        DO 1120 I=1,N1
          Y2(I)=Y1(IC+I)
 1120   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 11--                  **
!               **  CARRY OUT CALCULATIONS FOR **
!               **  THE COX-STUART      TEST   **
!               *********************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      D0=0.0
      CALL DPSIG4(Y1,N1,Y2,N1,D0,IWRITE,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  Y1MEAN,Y1MED,Y1SD,Y1MAD,   &
                  Y2MEAN,Y2MED,Y2SD,Y2MAD,   &
                  STATV1,STATC1,STATV2,STATC2,RTIES,NTEMP,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DPAR=0.5D0
      CALL BINPPF(.0005D0,DPAR,NTEMP,DPPF)
      CTL999=DPPF
      CALL BINPPF(.005D0,DPAR,NTEMP,DPPF)
      CUTL99=DPPF
      CALL BINPPF(.025D0,DPAR,NTEMP,DPPF)
      CUTL95=DPPF
      CALL BINPPF(.05D0,DPAR,NTEMP,DPPF)
      CUTL90=DPPF
      CALL BINPPF(.1D0,DPAR,NTEMP,DPPF)
      CUTL80=DPPF
      CALL BINPPF(.25D0,DPAR,NTEMP,DPPF)
      CUTL50=DPPF
      CALL BINPPF(.75D0,DPAR,NTEMP,DPPF)
      CUTU50=DPPF
      CALL BINPPF(.90D0,DPAR,NTEMP,DPPF)
      CUTU80=DPPF
      CALL BINPPF(.95D0,DPAR,NTEMP,DPPF)
      CUTU90=DPPF
      CALL BINPPF(.975D0,DPAR,NTEMP,DPPF)
      CUTU95=DPPF
      CALL BINPPF(.995D0,DPAR,NTEMP,DPPF)
      CUTU99=DPPF
      CALL BINPPF(.9995D0,DPAR,NTEMP,DPPF)
      CTU999=DPPF
!
!               *********************************
!               **   STEP 32--                 **
!               **   WRITE OUT EVERYTHING      **
!               **   FOR COX STUART      TEST  **
!               *********************************
!
      ISTEPN='42'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE='Cox Stuart Test for Trend'
      NCTITL=25
      ITITLZ='(Compare Observations < Midpoint to Those > Midpoint)'
      NCTITZ=53
!
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Response Variable:  '
      WRITE(ITEXT(ICNT)(21:24),'(A4)')IVARID(1:4)
      WRITE(ITEXT(ICNT)(25:28),'(A4)')IVARI2(1:4)
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='H0: There is No Trend'
      NCTEXT(ICNT)=21
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Ha: There is a Trend'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics:'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations for Original Sample:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(N)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations After Matching:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=REAL(NTEMP)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Points Below Midpoint:'
      NCTEXT(ICNT)=45
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=Y1MEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Median:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=Y1MED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=Y1SD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Median Absolute Deviation:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=Y1MAD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Summary Statistics for Points Above Midpoint:'
      NCTEXT(ICNT)=45
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Mean:'
      NCTEXT(ICNT)=12
      AVALUE(ICNT)=Y2MEAN
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Median:'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=Y2MED
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Standard Deviation:'
      NCTEXT(ICNT)=26
      AVALUE(ICNT)=Y2SD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Sample Median Absolute Deviation:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=Y2MAD
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=1
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='Test:'
      NCTEXT(ICNT)=5
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Positive Differences:'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=STATV1
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Negative Differences:'
      NCTEXT(ICNT)=31
      AVALUE(ICNT)=STATV2
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Ties:'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=RTIES
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value for Positive Values:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=STATC1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CDF Value for Negative Values:'
      NCTEXT(ICNT)=30
      AVALUE(ICNT)=STATC2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (2-tailed test):'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=PVAL2T
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (lower-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALLT
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='P-Value (upper-tailed test):'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=PVALUT
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 4110 I=1,NUMROW
        NTOT(I)=15
 4110 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ISTEPN='21B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ITITLE='Two-Tailed Test'
      NCTITL=15
      ITITL9='H0: P(+) = P(-); Ha: P(+) <> P(-)'
      NCTIT9=33
!
      DO 4130 J=1,NUMCLI
        DO 4140 I=1,3
          ITITL2(I,J)=' '
          NCTIT2(I,J)=0
 4140   CONTINUE
 4130 CONTINUE
!
      ITITL2(2,1)='Significance'
      NCTIT2(2,1)=12
      ITITL2(3,1)='Level'
      NCTIT2(3,1)=5
!
      ITITL2(2,2)='Test '
      NCTIT2(2,2)=4
      ITITL2(3,2)='Statistic'
      NCTIT2(3,2)=9
!
      ITITL2(1,3)='Lower'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (<)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Upper'
      NCTIT2(1,4)=5
      ITITL2(2,4)='Critical'
      NCTIT2(2,4)=8
      ITITL2(3,4)='Value (>)'
      NCTIT2(3,4)=9
!
      ITITL2(1,5)='Null'
      NCTIT2(1,5)=4
      ITITL2(2,5)='Hypothesis'
      NCTIT2(2,5)=10
      ITITL2(3,5)='Conclusion'
      NCTIT2(3,5)=10
!
      NMAX=0
      NUMCOL=5
      DO 4150 I=1,NUMCOL
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
        ITYPCO(I)='NUME'
        IDIGIT(I)=0
        IF(I.EQ.1 .OR. I.EQ.5)THEN
          ITYPCO(I)='ALPH'
        ENDIF
 4150 CONTINUE
!
      IWHTML(1)=125
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=150
      IINC=1600
      IINC2=1400
      IWRTF(1)=IINC
      IWRTF(2)=IWRTF(1)+IINC
      IWRTF(3)=IWRTF(2)+IINC
      IWRTF(4)=IWRTF(3)+IINC
      IWRTF(5)=IWRTF(4)+IINC
!
      DO 4160 J=1,NUMALP
!
        AMAT(J,2)=STATV1
        ALPHAT=(1.0 - ALPHA(J))/2.0
        CALL BINPPF(DBLE(ALPHAT),DPAR,NTEMP,DPPF)
        AMAT(J,3)=REAL(DPPF)
        ALPHAT=1.0 - ALPHAT
        CALL BINPPF(DBLE(ALPHAT),DPAR,NTEMP,DPPF)
        AMAT(J,4)=REAL(DPPF)
        IVALUE(J,5)(1:6)='ACCEPT'
        IF(STATV1.LT.AMAT(J,3))IVALUE(J,5)(1:6)='REJECT'
        IF(STATV1.GT.AMAT(J,4))IVALUE(J,5)(1:6)='REJECT'
        NCVALU(J,5)=6
!
        ALPHAT=100.0*ALPHA(J)
        WRITE(IVALUE(J,1)(1:4),'(F4.1)')ALPHAT
        IVALUE(J,1)(5:5)='%'
        NCVALU(J,1)=5
 4160 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASAN.NE.'LOWE' .AND. ICASAN.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(ICASAN.EQ.'TWOT')GO TO 9000
!
      ITITLE='Lower One-Tailed Test (decreasing trend)'
      NCTITL=40
      ITITL9='H0: P(+) = P(-); Ha: P(+) < P(-)'
      NCTIT9=32
!
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (<)'
      NCTIT2(3,3)=9
!
      ITITL2(1,4)='Null'
      NCTIT2(1,4)=4
      ITITL2(2,4)='Hypothesis'
      NCTIT2(2,4)=10
      ITITL2(3,4)='Conclusion'
      NCTIT2(3,4)=10
      ITYPCO(4)='ALPH'
!
      NMAX=0
      NUMCOL=4
      DO 4250 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
 4250 CONTINUE
!
      DO 4260 J=1,NUMALP
        ALPHAT=1.0 - ALPHA(J)
        CALL BINPPF(DBLE(ALPHAT),DPAR,NTEMP,DPPF)
        AMAT(J,3)=REAL(DPPF)
        IVALUE(J,4)(1:6)='REJECT'
        IF(AMAT(J,2).GE.AMAT(J,3))THEN
          IVALUE(J,4)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,4)=6
 4260 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      IF(ICASAN.NE.'UPPE')THEN
        CALL DPDTA5(ITITLE,NCTITL,   &
                    ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                    MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                    IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                    IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                    ICAPSW,ICAPTY,IFRST,ILAST,   &
                    IFLAGS,IFLAGE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
      IF(ICASAN.EQ.'LOWE')GO TO 9000
!
      ITITLE='Upper One-Tailed Test (increasing trend)'
      NCTITL=40
      ITITL9='H0: P(+) = P(-); Ha: P(+) > P(-)'
      NCTIT9=32
!
      ITITL2(1,3)='Upper'
      NCTIT2(1,3)=5
      ITITL2(2,3)='Critical'
      NCTIT2(2,3)=8
      ITITL2(3,3)='Value (>)'
      NCTIT2(3,3)=9
!
      NMAX=0
      NUMCOL=4
      DO 4350 I=1,NUMCOL
        NTOT(I)=15
        NMAX=NMAX+NTOT(I)
 4350 CONTINUE
!
      DO 4360 J=1,NUMALP
        ALPHAT=ALPHA(J)
        CALL BINPPF(DBLE(ALPHAT),DPAR,NTEMP,DPPF)
        AMAT(J,3)=REAL(DPPF)
        IVALUE(J,4)(1:6)='REJECT'
        IF(AMAT(J,2).LE.AMAT(J,3))THEN
          IVALUE(J,4)(1:6)='ACCEPT'
        ENDIF
        NCVALU(J,4)=6
 4360 CONTINUE
!
      ICNT=NUMALP
      NUMLIN=3
      IFRST=.TRUE.
      ILAST=.TRUE.
      IFLAGS=.TRUE.
      IFLAGE=.TRUE.
      CALL DPDTA5(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  IVALUE,NCVALU,AMAT,ITYPCO,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  IFLAGS,IFLAGE,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CXT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCXT2--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCXT2
      SUBROUTINE DPCYGR(IANSLC,IWIDTH,IHARG,IARGT,IARG,NUMARG,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CYCLE THROUGH THE CURRENTLY SAVED PIXMAPS
!
!                  CYCLE GRAPHS  (OR CYCLE PLOT, CG, CP)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/4
!     ORIGINAL VERSION--APRIL     1997.
!     UPDATED         --AUGUST    1997. MOVE SOME CODE TO A LOWER LEVEL
!                                       TO SUPPORT NON-X11 DEVICES
!                                       (SPECIFICALLY PC FOR NOW)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
      CHARACTER*4 IANSLC
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 ICODE
      CHARACTER*256 ISTRI2
      CHARACTER*128 CTEMP
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IFOUND
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!CCCC DIMENSION IADE(128)
!CCCC DIMENSION IADE2(128)
!
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPM.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='GR  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'CYGR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPCYGR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGS2,ISUBRO,IFOUND,IERROR
   52   FORMAT('IBUGS2,ISUBRO,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,IWIDTH
          WRITE(ICOUT,62)I,IANSLC(I)
   62     FORMAT('I,IANSLC(I) = ',I8,2X,A4)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
        DO 70 I=1,NUMARG
          WRITE(ICOUT,72)I,IHARG(I),IARGT(I),IARG(I)
   72     FORMAT('I,IHARG(I),IARGT(I),IARG(I) = ',   &
                 I8,2(2X,A4),I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   70   CONTINUE
      ENDIF
!
!               *******************************
!               **  STEP 12--                **
!               **  CALL XCYCLE              **
!               *******************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'CYGR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMPXM.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1203)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        IF(IFEEDB.EQ.'ON')THEN
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1213)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1215)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1217)
          CALL DPWRST('XXX','BUG ')
          IF(ICOMPI.EQ.'MS-F')THEN
            WRITE(ICOUT,1221)
          ELSE
            WRITE(ICOUT,1219)
          ENDIF
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
 1203 FORMAT('***** THERE ARE FEWER THAN TWO CURRENTLY SAVED PIMAPS.')
 1213 FORMAT('***** TO CYCLE THROUGH THE PREVIOUSLY SAVED GRAPHS:')
 1215 FORMAT('      1. CLICK THE LEFT MOUSE BUTTON TO CYCLE BACK.')
 1217 FORMAT('      2. CLICK THE RIGHT MOUSE BUTTON TO CYCLE FORWARD.')
 1219 FORMAT('      3. CLICK THE MIDDLE MOUSE BUTTON TO STOP CYCLING.')
 1221 FORMAT('      3. HOLD SHIFT OR CONTROL KEY DOWN WHILE CLICKING ',   &
      'THE LEFT OR RIGHT BUTTON TO STOP CYCLING.')
!
!  AUGUST 1997.  IN ORDER TO GENERALIZE THE CODE TO NON-X11 DEVICES,
!  MOVE FOLLOWING CODE TO LOWER LEVEL ROUTINE.
!
      ICODE='CYCL'
      ISTRI2=' '
      CTEMP=' '
      NCSTR2=0
      NCTEMP=0
      CALL GRSAGR(ICODE,ISTRI2,NCSTR2,CTEMP,NCTEMP)
!
!1000 CONTINUE
!CCCC IERR=0
!CCCC CALL XCYCLE(IERR,IBUTTN)
!CCCC IF(IERR.EQ.4)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1310)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
!CCCC ELSEIF(IERR.NE.0)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1310)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
!CCCC ENDIF
!1310 FORMAT('***** ERROR FROM DPCYGR: X11 NOT ACTIVE ON THIS ',
!CCCC1'IMPLEMENTATION.')
!1311 FORMAT('***** ERROR FROM DPCYGR: ERROR TRYING TO REDRAW PIXMAP.')
!CCCC IF(IBUTTN.EQ.1)THEN
!CCCC   ICURPM=ICURPM-1
!CCCC   IF(ICURPM.LT.1)ICURPM=1
!CCCC ELSEIF(IBUTTN.EQ.3)THEN
!CCCC   ICURPM=ICURPM+1
!CCCC   IF(ICURPM.GT.NUMPXM)ICURPM=NUMPXM
!CCCC ELSE
!CCCC   GO TO 9000
!CCCC ENDIF
!
!CCCC NCSTR2=1
!CCCC DO1405I=128,1,-1
!CCCC   NCSTR2=I
!CCCC   IF(IPXMFN(ICURPM)(I:I).NE.' ')GO TO 1409
!1405 CONTINUE
!1409 CONTINUE
!CCCC CTEMP=' '
!CCCC IF(ICURPM.LE.9)THEN
!CCCC   CTEMP(1:4)='  - '
!CCCC   WRITE(CTEMP(1:1),'(I1)')ICURPM
!CCCC   NCTEMP=4
!CCCC ELSEIF(ICURPM.LE.99)THEN
!CCCC   CTEMP(1:5)='   - '
!CCCC   WRITE(CTEMP(1:2),'(I2)')ICURPM
!CCCC   NCTEMP=5
!CCCC ELSEIF(ICURPM.LE.999)THEN
!CCCC   CTEMP(1:6)='    - '
!CCCC   WRITE(CTEMP(1:3),'(I3)')ICURPM
!CCCC   NCTEMP=6
!CCCC ENDIF
!CCCC DO1415I=1,NCTEMP
!CCCC   CALL DPCOAN(CTEMP(I:I),IADE2(I))
!1415 CONTINUE
!CCCC DO1420I=1,NCSTR2
!CCCC   CALL DPCOAN(IPXMFN(ICURPM)(I:I),IADE(I))
!CCCC   CALL DPCOAN(IPXMFN(ICURPM)(I:I),IADE2(I+NCTEMP))
!1420 CONTINUE
!CCCC IADE(NCSTR2+1)=0
!CCCC IADE2(NCSTR2+NCTEMP+1)=0
!CCCC IERR=0
!CCCC CALL XRESTG(IADE,IADE2,IERR)
!CCCC IF(IERR.NE.0)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1310)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
!CCCC ENDIF
!
!CCCC GO TO 1000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'OFF'.AND.ISUBRO.NE.'CYGR')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCYGR
